/**
 * Guest Access Service
 * 
 * Manages guest user authentication, magic link generation,
 * and permission-based access to value cases.
 */

import crypto from 'crypto';

import { logger } from './lib/logger';
import { supabase } from './lib/supabase';

// Guest user interface
export interface GuestUser {
  id: string;
  email: string;
  name: string;
  company?: string;
  role?: string;
  createdBy: string;
  organizationId: string;
  createdAt: string;
  updatedAt: string;
}

// Guest permissions interface
export interface GuestPermissions {
  can_view: boolean;
  can_comment: boolean;
  can_edit: boolean;
}

// Guest access token interface
export interface GuestAccessToken {
  id: string;
  guestUserId: string;
  valueCaseId: string;
  token: string;
  permissions: GuestPermissions;
  expiresAt: string;
  lastAccessedAt?: string;
  accessCount: number;
  ipAddress?: string;
  userAgent?: string;
  revoked: boolean;
  revokedAt?: string;
  revokedBy?: string;
  revokeReason?: string;
  createdBy: string;
  createdAt: string;
  updatedAt: string;
}

// Token validation result
export interface TokenValidationResult {
  isValid: boolean;
  guestUserId?: string;
  valueCaseId?: string;
  permissions?: GuestPermissions;
  guestName?: string;
  guestEmail?: string;
  expiresAt?: string;
  errorMessage?: string;
}

// Guest activity type
export type GuestActivityType = 
  | 'access'
  | 'view_element'
  | 'add_comment'
  | 'view_metric'
  | 'export_pdf'
  | 'export_excel'
  | 'share_email';

// Guest activity interface
export interface GuestActivity {
  id: string;
  guestUserId: string;
  guestAccessTokenId: string;
  valueCaseId: string;
  activityType: GuestActivityType;
  activityData?: Record<string, unknown>;
  ipAddress?: string;
  userAgent?: string;
  createdAt: string;
}

// Create guest user options
export interface CreateGuestUserOptions {
  email: string;
  name: string;
  company?: string;
  role?: string;
  organizationId: string;
}

// Create guest token options
export interface CreateGuestTokenOptions {
  guestUserId: string;
  valueCaseId: string;
  permissions?: Partial<GuestPermissions>;
  expiresInDays?: number;
}

class GuestAccessService {
  private readonly defaultExpirationDays = 30;
  private readonly defaultPermissions: GuestPermissions = {
    can_view: true,
    can_comment: false,
    can_edit: false,
  };

  /**
   * Create a guest user
   */
  public async createGuestUser(
    options: CreateGuestUserOptions
  ): Promise<GuestUser> {
    try {
      const { data: currentUser } = await supabase.auth.getUser();

      if (!currentUser.user) {
        throw new Error('Not authenticated');
      }

      const { data, error } = await supabase
        .from('guest_users')
        .insert({
          email: options.email.toLowerCase(),
          name: options.name,
          company: options.company,
          role: options.role,
          organization_id: options.organizationId,
          created_by: currentUser.user.id,
        })
        .select()
        .single();

      if (error) {
        // Check for unique constraint violation
        if (error.code === '23505') {
          // Guest user already exists, fetch and return
          const { data: existingUser, error: fetchError } = await supabase
            .from('guest_users')
            .select()
            .eq('email', options.email.toLowerCase())
            .eq('organization_id', options.organizationId)
            .single();

          if (fetchError) throw fetchError;
          return this.mapDatabaseToGuestUser(existingUser);
        }
        throw error;
      }

      logger.info('Guest user created', {
        guestUserId: data.id,
        recipientId: this.redactRecipient(options.email),
        organizationId: options.organizationId,
      });

      return this.mapDatabaseToGuestUser(data);
    } catch (error: unknown) {
      logger.error('Failed to create guest user', error as Error);
      throw error;
    }
  }

  /**
   * Generate a magic link token for guest access
   */
  public async createGuestToken(
    options: CreateGuestTokenOptions
  ): Promise<{ token: GuestAccessToken; magicLink: string }> {
    try {
      const { data: currentUser } = await supabase.auth.getUser();

      if (!currentUser.user) {
        throw new Error('Not authenticated');
      }

      // Generate secure token
      const token = this.generateSecureToken();

      // Calculate expiration
      const expiresInDays = options.expiresInDays || this.defaultExpirationDays;
      const expiresAt = new Date();
      expiresAt.setDate(expiresAt.getDate() + expiresInDays);

      // Merge permissions with defaults
      const permissions = {
        ...this.defaultPermissions,
        ...options.permissions,
      };

      const { data, error } = await supabase
        .from('guest_access_tokens')
        .insert({
          guest_user_id: options.guestUserId,
          value_case_id: options.valueCaseId,
          token,
          permissions,
          expires_at: expiresAt.toISOString(),
          created_by: currentUser.user.id,
        })
        .select()
        .single();

      if (error) throw error;

      const tokenData = this.mapDatabaseToToken(data);
      const magicLink = this.generateMagicLink(token);

      logger.info('Guest token created', {
        tokenId: data.id,
        guestUserId: options.guestUserId,
        valueCaseId: options.valueCaseId,
        expiresAt: expiresAt.toISOString(),
      });

      return { token: tokenData, magicLink };
    } catch (error: unknown) {
      logger.error('Failed to create guest token', error as Error);
      throw error;
    }
  }

  /**
   * Validate a guest access token
   */
  public async validateToken(
    token: string,
    ipAddress?: string,
    userAgent?: string
  ): Promise<TokenValidationResult> {
    try {
      const { data, error } = await supabase.rpc('validate_guest_token', {
        token_value: token,
      });

      if (error) throw error;

      const result = (data as Array<{
        is_valid: boolean;
        guest_user_id?: string;
        value_case_id?: string;
        permissions?: GuestPermissions;
        guest_name?: string;
        guest_email?: string;
        expires_at?: string;
        error_message?: string;
      }>)[0];

      if (!result.is_valid) {
        logger.warn('Invalid guest token', {
          tokenRef: this.describeToken(token),
          error: result.error_message,
        });

        return {
          isValid: false,
          errorMessage: result.error_message,
        };
      }

      // Update IP and user agent if provided
      if (ipAddress || userAgent) {
        await supabase
          .from('guest_access_tokens')
          .update({
            ip_address: ipAddress,
            user_agent: userAgent,
          })
          .eq('token', token);
      }

      logger.info('Guest token validated', {
        guestUserId: result.guest_user_id,
        valueCaseId: result.value_case_id,
      });

      return {
        isValid: true,
        guestUserId: result.guest_user_id,
        valueCaseId: result.value_case_id,
        permissions: result.permissions,
        guestName: result.guest_name,
        guestEmail: result.guest_email,
        expiresAt: result.expires_at,
      };
    } catch (error) {
      logger.error('Failed to validate guest token', error as Error);
      throw error;
    }
  }

  /**
   * Revoke a guest access token
   */
  public async revokeToken(
    token: string,
    reason?: string
  ): Promise<boolean> {
    try {
      const { data: currentUser } = await supabase.auth.getUser();

      if (!currentUser.user) {
        throw new Error('Not authenticated');
      }

      const { data, error } = await supabase.rpc('revoke_guest_token', {
        token_value: token,
        revoked_by_user: currentUser.user.id,
        reason: reason || 'Revoked by user',
      });

      if (error) throw error;

      logger.info('Guest token revoked', {
        tokenRef: this.describeToken(token),
        reason,
      });

      return data as boolean;
    } catch (error) {
      logger.error('Failed to revoke guest token', error as Error);
      throw error;
    }
  }

  /**
   * Get guest user by ID
   */
  public async getGuestUser(guestUserId: string): Promise<GuestUser | null> {
    try {
      const { data, error } = await supabase
        .from('guest_users')
        .select()
        .eq('id', guestUserId)
        .single();

      if (error) {
        if (error.code === 'PGRST116') return null; // Not found
        throw error;
      }

      return this.mapDatabaseToGuestUser(data);
    } catch (error) {
      logger.error('Failed to get guest user', error as Error);
      throw error;
    }
  }

  /**
   * Get guest tokens for a value case
   */
  public async getTokensForValueCase(
    valueCaseId: string
  ): Promise<GuestAccessToken[]> {
    try {
      const { data, error } = await supabase
        .from('guest_access_tokens')
        .select()
        .eq('value_case_id', valueCaseId)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data as Array<Record<string, unknown>>).map(this.mapDatabaseToToken);
    } catch (error) {
      logger.error('Failed to get guest tokens', error as Error);
      throw error;
    }
  }

  /**
   * Log guest activity
   */
  public async logActivity(
    guestUserId: string,
    tokenId: string,
    valueCaseId: string,
    activityType: GuestActivityType,
    activityData?: Record<string, unknown>,
    ipAddress?: string,
    userAgent?: string
  ): Promise<void> {
    try {
      const { error } = await supabase
        .from('guest_activity_log')
        .insert({
          guest_user_id: guestUserId,
          guest_access_token_id: tokenId,
          value_case_id: valueCaseId,
          activity_type: activityType,
          activity_data: activityData,
          ip_address: ipAddress,
          user_agent: userAgent,
        });

      if (error) throw error;

      logger.debug('Guest activity logged', {
        guestUserId,
        activityType,
      });
    } catch (error) {
      logger.error('Failed to log guest activity', error as Error);
      // Don't throw - activity logging should not break the main flow
    }
  }

  /**
   * Get guest activity for a value case
   */
  public async getActivityForValueCase(
    valueCaseId: string,
    limit: number = 100
  ): Promise<GuestActivity[]> {
    try {
      const { data, error } = await supabase
        .from('guest_activity_log')
        .select()
        .eq('value_case_id', valueCaseId)
        .order('created_at', { ascending: false })
        .limit(limit);

      if (error) throw error;

      return (data as Array<Record<string, unknown>>).map(this.mapDatabaseToActivity);
    } catch (error) {
      logger.error('Failed to get guest activity', error as Error);
      throw error;
    }
  }

  /**
   * Cleanup expired tokens
   */
  public async cleanupExpiredTokens(): Promise<number> {
    try {
      const { data, error } = await supabase.rpc('cleanup_expired_guest_tokens');

      if (error) throw error;

      logger.info('Expired guest tokens cleaned up', { count: data });

      return data as number;
    } catch (error) {
      logger.error('Failed to cleanup expired tokens', error as Error);
      throw error;
    }
  }

  /**
   * Generate a secure random token
   */
  private generateSecureToken(): string {
    // Generate 32 bytes of random data
    const buffer = crypto.randomBytes(32);

    // Convert to base64url (URL-safe)
    return buffer
      .toString('base64')
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=/g, '');
  }

  /**
   * Generate magic link URL
   */
  private generateMagicLink(token: string): string {
    const baseUrl = ((import.meta as Record<string, unknown>).env as Record<string, string>).VITE_APP_URL || 'http://localhost:5173';
    return `${baseUrl}/guest/access#token=${encodeURIComponent(token)}`;
  }

  private describeToken(token: string): string {
    return `token:${crypto.createHash('sha256').update(token).digest('hex').slice(0, 12)}`;
  }

  private redactRecipient(email: string): string {
    return `recipient:${crypto.createHash('sha256').update(email.trim().toLowerCase()).digest('hex').slice(0, 12)}`;
  }

  /**
   * Map database row to GuestUser
   */
  private mapDatabaseToGuestUser(row: Record<string, unknown>): GuestUser {
    return {
      id: String(row.id),
      email: String(row.email),
      name: String(row.name),
      company: row.company === null || row.company === undefined ? undefined : String(row.company),
      role: row.role === null || row.role === undefined ? undefined : String(row.role),
      createdBy: String(row.created_by),
      organizationId: String(row.organization_id),
      createdAt: String(row.created_at),
      updatedAt: String(row.updated_at),
    };
  }

  /**
   * Map database row to GuestAccessToken
   */
  private mapDatabaseToToken(row: Record<string, unknown>): GuestAccessToken {
    return {
      id: String(row.id),
      guestUserId: String(row.guest_user_id),
      valueCaseId: String(row.value_case_id),
      token: String(row.token),
      permissions: row.permissions as GuestPermissions,
      expiresAt: String(row.expires_at),
      lastAccessedAt: row.last_accessed_at === null || row.last_accessed_at === undefined ? undefined : String(row.last_accessed_at),
      accessCount: typeof row.access_count === 'number' ? row.access_count : Number(row.access_count),
      ipAddress: row.ip_address === null || row.ip_address === undefined ? undefined : String(row.ip_address),
      userAgent: row.user_agent === null || row.user_agent === undefined ? undefined : String(row.user_agent),
      revoked: Boolean(row.revoked),
      revokedAt: row.revoked_at === null || row.revoked_at === undefined ? undefined : String(row.revoked_at),
      revokedBy: row.revoked_by === null || row.revoked_by === undefined ? undefined : String(row.revoked_by),
      revokeReason: row.revoke_reason === null || row.revoke_reason === undefined ? undefined : String(row.revoke_reason),
      createdBy: String(row.created_by),
      createdAt: String(row.created_at),
      updatedAt: String(row.updated_at),
    };
  }

  /**
   * Map database row to GuestActivity
   */
  private mapDatabaseToActivity(row: Record<string, unknown>): GuestActivity {
    return {
      id: String(row.id),
      guestUserId: String(row.guest_user_id),
      guestAccessTokenId: String(row.guest_access_token_id),
      valueCaseId: String(row.value_case_id),
      activityType: row.activity_type as GuestActivityType,
      activityData: row.activity_data as Record<string, unknown> | undefined,
      ipAddress: row.ip_address === null || row.ip_address === undefined ? undefined : String(row.ip_address),
      userAgent: row.user_agent === null || row.user_agent === undefined ? undefined : String(row.user_agent),
      createdAt: String(row.created_at),
    };
  }
}

// Singleton instance
let guestAccessServiceInstance: GuestAccessService | null = null;

/**
 * Get guest access service instance
 */
export function getGuestAccessService(): GuestAccessService {
  if (!guestAccessServiceInstance) {
    guestAccessServiceInstance = new GuestAccessService();
  }
  return guestAccessServiceInstance;
}

// Export singleton instance getter
export default getGuestAccessService;

/**
 * Conflict Resolution Integration Tests
 * 
 * Tests various conflict scenarios in collaborative editing
 */

import { describe, expect, it } from 'vitest';

import type { CanvasElement } from '../../lib/realtime/supabaseRealtime';

describe('Conflict Resolution Integration Tests', () => {
  describe('Last-Write-Wins (LWW)', () => {
    it('should resolve concurrent updates using timestamps', () => {
      const baseTime = Date.now();

      // User 1 updates at T+0
      const user1Update: CanvasElement = {
        id: 'elem-1',
        valueCaseId: 'vc-123',
        elementType: 'text',
        positionX: 100,
        positionY: 200,
        content: { text: 'User 1 edit' },
        zIndex: 1,
        locked: false,
        createdAt: new Date(baseTime).toISOString(),
        updatedAt: new Date(baseTime).toISOString(),
      };

      // User 2 updates at T+1000 (1 second later)
      const user2Update: CanvasElement = {
        ...user1Update,
        content: { text: 'User 2 edit' },
        updatedAt: new Date(baseTime + 1000).toISOString(),
      };

      // Resolve conflict: User 2's update should win
      const winner =
        new Date(user2Update.updatedAt).getTime() >
        new Date(user1Update.updatedAt).getTime()
          ? user2Update
          : user1Update;

      expect(winner.content.text).toBe('User 2 edit');
      expect(winner.updatedAt).toBe(user2Update.updatedAt);
    });

    it('should handle simultaneous updates with same timestamp', () => {
      const timestamp = new Date().toISOString();

      const user1Update: CanvasElement = {
        id: 'elem-1',
        valueCaseId: 'vc-123',
        elementType: 'text',
        positionX: 100,
        positionY: 200,
        content: { text: 'User 1' },
        zIndex: 1,
        locked: false,
        createdBy: 'user-1',
        updatedBy: 'user-1',
        createdAt: timestamp,
        updatedAt: timestamp,
      };

      const user2Update: CanvasElement = {
        ...user1Update,
        content: { text: 'User 2' },
        updatedBy: 'user-2',
      };

      // When timestamps are equal, use user ID as tiebreaker
      const winner =
        user1Update.updatedAt === user2Update.updatedAt
          ? user1Update.updatedBy! < user2Update.updatedBy!
            ? user1Update
            : user2Update
          : user1Update;

      expect(winner.updatedBy).toBe('user-1'); // Alphabetically first
    });
  });

  describe('Element Locking', () => {
    it('should prevent edits to locked elements', () => {
      const lockedElement: CanvasElement = {
        id: 'elem-1',
        valueCaseId: 'vc-123',
        elementType: 'text',
        positionX: 100,
        positionY: 200,
        content: { text: 'Locked content' },
        zIndex: 1,
        locked: true,
        createdBy: 'user-1',
        updatedBy: 'user-1',
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };

      // User 2 tries to edit
      const canEdit = (element: CanvasElement, userId: string) => {
        if (element.locked && element.updatedBy !== userId) {
          return false;
        }
        return true;
      };

      expect(canEdit(lockedElement, 'user-2')).toBe(false);
      expect(canEdit(lockedElement, 'user-1')).toBe(true);
    });

    it('should allow unlocking by original user', () => {
      const element: CanvasElement = {
        id: 'elem-1',
        valueCaseId: 'vc-123',
        elementType: 'text',
        positionX: 100,
        positionY: 200,
        content: { text: 'Content' },
        zIndex: 1,
        locked: true,
        updatedBy: 'user-1',
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };

      const unlock = (elem: CanvasElement, userId: string) => {
        if (elem.updatedBy === userId) {
          return { ...elem, locked: false };
        }
        return elem;
      };

      const unlocked = unlock(element, 'user-1');
      expect(unlocked.locked).toBe(false);

      const notUnlocked = unlock(element, 'user-2');
      expect(notUnlocked.locked).toBe(true);
    });
  });

  describe('Position Conflicts', () => {
    it('should handle overlapping element positions', () => {
      const element1: CanvasElement = {
        id: 'elem-1',
        valueCaseId: 'vc-123',
        elementType: 'shape',
        positionX: 100,
        positionY: 100,
        width: 100,
        height: 100,
        content: {},
        zIndex: 1,
        locked: false,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };

      const element2: CanvasElement = {
        id: 'elem-2',
        valueCaseId: 'vc-123',
        elementType: 'shape',
        positionX: 150,
        positionY: 150,
        width: 100,
        height: 100,
        content: {},
        zIndex: 2,
        locked: false,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };

      // Check for overlap
      const checkOverlap = (e1: CanvasElement, e2: CanvasElement) => {
        if (!e1.width || !e1.height || !e2.width || !e2.height) return false;

        return !(
          e1.positionX + e1.width < e2.positionX ||
          e2.positionX + e2.width < e1.positionX ||
          e1.positionY + e1.height < e2.positionY ||
          e2.positionY + e2.height < e1.positionY
        );
      };

      expect(checkOverlap(element1, element2)).toBe(true);

      // Higher z-index should be on top
      expect(element2.zIndex).toBeGreaterThan(element1.zIndex);
    });

    it('should auto-adjust z-index on overlap', () => {
      const elements: CanvasElement[] = [
        {
          id: 'elem-1',
          valueCaseId: 'vc-123',
          elementType: 'shape',
          positionX: 100,
          positionY: 100,
          width: 100,
          height: 100,
          content: {},
          zIndex: 1,
          locked: false,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
        },
        {
          id: 'elem-2',
          valueCaseId: 'vc-123',
          elementType: 'shape',
          positionX: 150,
          positionY: 150,
          width: 100,
          height: 100,
          content: {},
          zIndex: 1,
          locked: false,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
        },
      ];

      // Auto-adjust z-index
      const adjustZIndex = (elems: CanvasElement[]) => {
        return elems.map((elem, index) => ({
          ...elem,
          zIndex: index + 1,
        }));
      };

      const adjusted = adjustZIndex(elements);
      expect(adjusted[0].zIndex).toBe(1);
      expect(adjusted[1].zIndex).toBe(2);
    });
  });

  describe('Content Conflicts', () => {
    it('should merge non-conflicting property changes', () => {
      const baseElement: CanvasElement = {
        id: 'elem-1',
        valueCaseId: 'vc-123',
        elementType: 'text',
        positionX: 100,
        positionY: 200,
        content: { text: 'Original', fontSize: 14 },
        style: { color: 'black' },
        zIndex: 1,
        locked: false,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };

      // User 1 changes position
      const user1Change = {
        ...baseElement,
        positionX: 150,
        positionY: 250,
      };

      // User 2 changes content
      const user2Change = {
        ...baseElement,
        content: { text: 'Updated', fontSize: 14 },
      };

      // Merge changes
      const merged: CanvasElement = {
        ...baseElement,
        positionX: user1Change.positionX,
        positionY: user1Change.positionY,
        content: user2Change.content,
      };

      expect(merged.positionX).toBe(150);
      expect(merged.content.text).toBe('Updated');
    });

    it('should detect conflicting property changes', () => {
      const baseElement: CanvasElement = {
        id: 'elem-1',
        valueCaseId: 'vc-123',
        elementType: 'text',
        positionX: 100,
        positionY: 200,
        content: { text: 'Original' },
        zIndex: 1,
        locked: false,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };

      // User 1 changes text
      const user1Change = {
        ...baseElement,
        content: { text: 'User 1 edit' },
        updatedAt: new Date(Date.now()).toISOString(),
      };

      // User 2 changes text
      const user2Change = {
        ...baseElement,
        content: { text: 'User 2 edit' },
        updatedAt: new Date(Date.now() + 1000).toISOString(),
      };

      // Detect conflict
      const hasConflict =
        user1Change.content.text !== baseElement.content.text &&
        user2Change.content.text !== baseElement.content.text &&
        user1Change.content.text !== user2Change.content.text;

      expect(hasConflict).toBe(true);

      // Resolve using LWW
      const winner =
        new Date(user2Change.updatedAt).getTime() >
        new Date(user1Change.updatedAt).getTime()
          ? user2Change
          : user1Change;

      expect(winner.content.text).toBe('User 2 edit');
    });
  });

  describe('Deletion Conflicts', () => {
    it('should handle delete vs update conflict', () => {
      const element: CanvasElement = {
        id: 'elem-1',
        valueCaseId: 'vc-123',
        elementType: 'text',
        positionX: 100,
        positionY: 200,
        content: { text: 'Content' },
        zIndex: 1,
        locked: false,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };

      // User 1 deletes at T+0
      const deleteTime = Date.now();

      // User 2 updates at T+500
      const updateTime = deleteTime + 500;

      // Delete should win if it happened after update
      const deleteWins = deleteTime > updateTime;

      expect(deleteWins).toBe(false); // Update happened later
    });

    it('should handle concurrent deletions', () => {
      const element: CanvasElement = {
        id: 'elem-1',
        valueCaseId: 'vc-123',
        elementType: 'text',
        positionX: 100,
        positionY: 200,
        content: { text: 'Content' },
        zIndex: 1,
        locked: false,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };

      // Both users delete at same time
      const user1Delete = { elementId: element.id, deletedAt: Date.now() };
      const user2Delete = { elementId: element.id, deletedAt: Date.now() };

      // Both deletions should be idempotent
      expect(user1Delete.elementId).toBe(user2Delete.elementId);
    });
  });

  describe('Undo/Redo Conflicts', () => {
    it('should handle undo during concurrent edits', () => {
      const history: CanvasElement[] = [
        {
          id: 'elem-1',
          valueCaseId: 'vc-123',
          elementType: 'text',
          positionX: 100,
          positionY: 200,
          content: { text: 'Version 1' },
          zIndex: 1,
          locked: false,
          createdAt: new Date().toISOString(),
          updatedAt: new Date(Date.now()).toISOString(),
        },
        {
          id: 'elem-1',
          valueCaseId: 'vc-123',
          elementType: 'text',
          positionX: 100,
          positionY: 200,
          content: { text: 'Version 2' },
          zIndex: 1,
          locked: false,
          createdAt: new Date().toISOString(),
          updatedAt: new Date(Date.now() + 1000).toISOString(),
        },
      ];

      // User 1 undoes to Version 1
      const undoVersion = history[0];

      // User 2 makes new edit (Version 3)
      const newEdit: CanvasElement = {
        ...history[1],
        content: { text: 'Version 3' },
        updatedAt: new Date(Date.now() + 2000).toISOString(),
      };

      // New edit should win over undo
      const winner =
        new Date(newEdit.updatedAt).getTime() >
        new Date(undoVersion.updatedAt).getTime()
          ? newEdit
          : undoVersion;

      expect(winner.content.text).toBe('Version 3');
    });
  });

  describe('Network Partition', () => {
    it('should reconcile changes after network partition', () => {
      // Offline changes from User 1
      const user1Changes: CanvasElement[] = [
        {
          id: 'elem-1',
          valueCaseId: 'vc-123',
          elementType: 'text',
          positionX: 100,
          positionY: 200,
          content: { text: 'Offline edit 1' },
          zIndex: 1,
          locked: false,
          createdAt: new Date().toISOString(),
          updatedAt: new Date(Date.now()).toISOString(),
        },
        {
          id: 'elem-2',
          valueCaseId: 'vc-123',
          elementType: 'text',
          positionX: 200,
          positionY: 300,
          content: { text: 'Offline edit 2' },
          zIndex: 1,
          locked: false,
          createdAt: new Date().toISOString(),
          updatedAt: new Date(Date.now() + 1000).toISOString(),
        },
      ];

      // Online changes from User 2
      const user2Changes: CanvasElement[] = [
        {
          id: 'elem-1',
          valueCaseId: 'vc-123',
          elementType: 'text',
          positionX: 150,
          positionY: 250,
          content: { text: 'Online edit' },
          zIndex: 1,
          locked: false,
          createdAt: new Date().toISOString(),
          updatedAt: new Date(Date.now() + 500).toISOString(),
        },
      ];

      // Reconcile: merge non-conflicting, resolve conflicts with LWW
      const reconciled = new Map<string, CanvasElement>();

      [...user1Changes, ...user2Changes].forEach((change) => {
        const existing = reconciled.get(change.id);
        if (!existing) {
          reconciled.set(change.id, change);
        } else {
          // Use LWW for conflicts
          const winner =
            new Date(change.updatedAt).getTime() >
            new Date(existing.updatedAt).getTime()
              ? change
              : existing;
          reconciled.set(change.id, winner);
        }
      });

      expect(reconciled.size).toBe(2);
      // LWW: user2's elem-1 has updatedAt +500ms vs user1's +0ms → user2 wins
      expect(reconciled.get('elem-1')?.content.text).toBe('Online edit');
      // elem-2 only exists in user1's changes → user1 wins
      expect(reconciled.get('elem-2')?.content.text).toBe('Offline edit 2');
    });
  });
});

