/**
 * Tenant API Client
 *
 * Provides typed API calls for tenant-related operations.
 * Uses feature flag to enable/disable real API calls.
 */

import { createLogger } from "../lib/logger";
import { supabase } from "../lib/supabase";
import { sanitizeInput } from "../security/InputSanitizer";

const logger = createLogger({ component: "TenantAPI" });

/**
 * Tenant information returned from API
 */
export interface TenantInfo {
  id: string;
  name: string;
  slug: string;
  color: string;
  role: string;
  status: "active" | "inactive" | "pending";
  createdAt: string;
}

/**
 * API response wrapper
 */
export interface TenantApiResponse<T> {
  data: T | null;
  error: Error | null;
}

interface TenantMembershipRecord {
  tenant_id: string;
  role: string;
  status: TenantInfo["status"];
  tenants?: {
    name?: string;
    slug?: string;
    settings?: { brandColor?: string };
    created_at?: string;
  };
}

type AuthenticatedUserId = string & { readonly __authenticatedUserId: unique symbol };

interface TenantMembershipQueryGuard {
  expectedUserId?: string;
}

/**
 * Check if tenant API is enabled via feature flag
 */
export function isTenantApiEnabled(): boolean {
  return import.meta.env.VITE_TENANTS_API_ENABLED !== "false";
}

/**
 * Fetch all tenants the current user has access to
 *
 * SECURITY: This queries user_tenants table which is RLS-protected.
 * The backend validates the user's session before returning data.
 */
async function resolveAuthenticatedUserId(
  guard?: TenantMembershipQueryGuard
): Promise<TenantApiResponse<AuthenticatedUserId>> {
  if (!supabase) {
    logger.error("Supabase client not configured");
    return {
      data: null,
      error: new Error("Database connection unavailable"),
    };
  }

  // getUser() verifies the JWT server-side but requires a network call to Supabase.
  // If that fails (e.g. transient network error or TypeError), fall back to
  // getSession() which reads the locally-stored session without a network round-trip.
  let user: { id: string } | null = null;
  try {
    const { data: getUserData, error: getUserError } = await supabase.auth.getUser();
    if (getUserError) {
      logger.warn("getUser() failed, falling back to getSession()", { error: getUserError });
      const { data: sessionData } = await supabase.auth.getSession();
      user = sessionData?.session?.user ?? null;
    } else {
      user = getUserData.user;
    }
  } catch (networkError) {
    logger.warn("getUser() threw, falling back to getSession()", { error: networkError });
    try {
      const { data: sessionData } = await supabase.auth.getSession();
      user = sessionData?.session?.user ?? null;
    } catch {
      user = null;
    }
  }

  if (!user?.id) {
    logger.warn("Tenant query rejected because session user is missing");
    return { data: null, error: new Error("Authenticated user is required") };
  }

  const sanitizedSessionUserId = sanitizeInput(user.id, { allowHtml: false, maxLength: 128 });
  const sanitizedExpectedUserId = guard?.expectedUserId
    ? sanitizeInput(guard.expectedUserId, { allowHtml: false, maxLength: 128 })
    : undefined;

  if (sanitizedExpectedUserId && sanitizedExpectedUserId !== sanitizedSessionUserId) {
    logger.warn("Tenant query rejected because caller user does not match session user", {
      expectedUserId: sanitizedExpectedUserId,
      sessionUserId: sanitizedSessionUserId,
    });
    return { data: null, error: new Error("Caller identity does not match authenticated user") };
  }

  return { data: sanitizedSessionUserId as AuthenticatedUserId, error: null };
}

export async function fetchUserTenants(
  guard?: TenantMembershipQueryGuard
): Promise<TenantApiResponse<TenantInfo[]>> {
  if (!isTenantApiEnabled()) {
    logger.warn("Tenant API disabled, returning empty list");
    return { data: [], error: null };
  }

  const { data: authenticatedUserId, error: userError } = await resolveAuthenticatedUserId(guard);
  if (userError || !authenticatedUserId) {
    return { data: null, error: userError ?? new Error("Authenticated user is required") };
  }

  try {
    const { data, error } = await supabase
      .from("user_tenants")
      .select(
        `
        tenant_id,
        role,
        status,
        tenants:tenant_id (
          id,
          name,
          slug,
          settings
        )
      `
      )
      .eq("user_id", authenticatedUserId)
      .eq("status", "active");

    if (error) {
      logger.error("Failed to fetch user tenants", error, { userId: authenticatedUserId });
      return { data: null, error };
    }

    if (!data || data.length === 0) {
      logger.info("User has no active tenants", { userId: authenticatedUserId });
      return { data: [], error: null };
    }

    const tenants: TenantInfo[] = (data as TenantMembershipRecord[]).map((row) => ({
      id: row.tenant_id,
      name: row.tenants?.name || "Unknown Tenant",
      slug: row.tenants?.slug || row.tenant_id,
      color: row.tenants?.settings?.brandColor || "#18C3A5",
      role: row.role || "member",
      status: row.status,
      createdAt: row.tenants?.created_at || new Date().toISOString(),
    }));

    logger.debug("Fetched user tenants", { userId: authenticatedUserId, count: tenants.length });
    return { data: tenants, error: null };
  } catch (err) {
    const error = err instanceof Error ? err : new Error("Unknown error fetching tenants");
    logger.error("Exception fetching user tenants", error, { userId: authenticatedUserId });
    return { data: null, error };
  }
}

/**
 * Validate that a user has access to a specific tenant
 *
 * SECURITY: This is a client-side check. The backend MUST also validate.
 */
export async function validateTenantAccess(tenantId: string, guard?: TenantMembershipQueryGuard): Promise<boolean> {
  const sanitizedTenantId = sanitizeInput(tenantId, { allowHtml: false, maxLength: 128 });
  const { data: tenants, error } = await fetchUserTenants(guard);

  if (error || !tenants) {
    logger.warn("Cannot validate tenant access", { tenantId: sanitizedTenantId, error });
    return false;
  }

  const hasAccess = tenants.some((t) => t.id === sanitizedTenantId);

  if (!hasAccess) {
    logger.warn("User does not have access to tenant", { tenantId: sanitizedTenantId });
  }

  return hasAccess;
}

/**
 * Get tenant details by ID
 */
export async function getTenantById(tenantId: string): Promise<TenantApiResponse<TenantInfo>> {
  if (!supabase) {
    return { data: null, error: new Error("Database connection unavailable") };
  }

  const sanitizedTenantId = sanitizeInput(tenantId, { allowHtml: false, maxLength: 128 });

  try {
    const { data, error } = await supabase
      .from("tenants")
      .select("id, name, slug, settings, created_at")
      .eq("id", sanitizedTenantId)
      .single();

    if (error) {
      logger.error("Failed to fetch tenant", error, { tenantId: sanitizedTenantId });
      return { data: null, error };
    }

    if (!data) {
      return { data: null, error: new Error("Tenant not found") };
    }

    const tenant: TenantInfo = {
      id: data.id,
      name: data.name,
      slug: data.slug,
      color: data.settings?.brandColor || "#18C3A5",
      role: "member",
      status: "active",
      createdAt: data.created_at,
    };

    return { data: tenant, error: null };
  } catch (err) {
    const error = err instanceof Error ? err : new Error("Unknown error");
    return { data: null, error };
  }
}

/**
 * Application Bootstrap
 * Initialization sequence for the ValyntApp application.
 */

import { logger } from "../../lib/logger";

import { getConfig, loadConfig } from "@/app/config/env";
import { trackFrontendFlow } from "@/lib/observability";

export interface BootstrapResult {
  success: boolean;
  errors: string[];
  warnings: string[];
  duration: number;
}

export interface BootstrapOptions {
  onProgress?: (message: string) => void;
  onWarning?: (warning: string) => void;
  onError?: (error: string) => void;
}

/**
 * Bootstrap the application
 */
export async function bootstrap(
  options: BootstrapOptions = {},
): Promise<BootstrapResult> {
  const startTime = Date.now();
  const errors: string[] = [];
  const warnings: string[] = [];

  const { onProgress, onWarning, onError } = options;

  logger.info("🚀 Bootstrapping ValyntApp...");

  const traceId = `bootstrap-${Date.now()}`;

  // Step 1: Load environment configuration
  onProgress?.("Loading configuration...");
  try {
    await trackFrontendFlow("bootstrap.load_config", {
      service: "valynt-app",
      env: import.meta.env.MODE || "development",
      tenant_id: "anonymous",
      trace_id: traceId,
    }, async () => {
      loadConfig();
      const config = getConfig();
      logger.info("✅ Configuration loaded", {
        environment: config.env,
        apiUrl: config.apiBaseUrl,
      });
    });
  } catch (error) {
    const errorMsg = `Failed to load configuration: ${error instanceof Error ? error.message : "Unknown error"}`;
    errors.push(errorMsg);
    onError?.(errorMsg);
    logger.error("❌", errorMsg);
  }

  // Step 2: Validate required environment variables
  onProgress?.("Validating environment...");
  const requiredVars = ["VITE_SUPABASE_URL", "VITE_SUPABASE_ANON_KEY"];
  const missingVars = requiredVars.filter((v) => !import.meta.env[v]);

  if (missingVars.length > 0) {
    const warningMsg = `Missing environment variables: ${missingVars.join(", ")}`;
    warnings.push(warningMsg);
    onWarning?.(warningMsg);
    logger.warn("⚠️", warningMsg);
  }

  // Step 3: Initialize analytics (if enabled)
  onProgress?.("Initializing analytics...");
  if (import.meta.env.VITE_ANALYTICS_ENABLED === "true") {
    try {
      await trackFrontendFlow("bootstrap.analytics", {
        service: "valynt-app",
        env: import.meta.env.MODE || "development",
        tenant_id: "anonymous",
        trace_id: traceId,
      }, async () => {
        // Analytics initialization would go here
        logger.info("✅ Analytics initialized");
      });
    } catch (error) {
      const warningMsg = `Analytics initialization failed: ${error instanceof Error ? error.message : "Unknown error"}`;
      warnings.push(warningMsg);
      onWarning?.(warningMsg);
    }
  }


  const duration = Date.now() - startTime;
  const success = errors.length === 0;

  logger.info(`🎉 Bootstrap complete in ${duration}ms`, {
    success,
    errors: errors.length,
    warnings: warnings.length,
  });

  return {
    success,
    errors,
    warnings,
    duration,
  };
}

/**
 * Bootstrap with console logging
 */
export async function bootstrapWithLogging(): Promise<BootstrapResult> {
  return bootstrap({
    onProgress: (msg) => logger.info(`⏳ ${msg}`),
    onWarning: (msg) => logger.warn(`⚠️ ${msg}`),
    onError: (msg) => logger.error(`❌ ${msg}`),
  });
}

export default bootstrap;

/**
 * Environment Configuration
 */

export type AppEnvironment = "development" | "staging" | "production" | "test";

export interface AppConfig {
  env: AppEnvironment;
  appUrl: string;
  apiBaseUrl: string;
  supabase: {
    url: string;
    anonKey: string;
  };
  features: {
    billing: boolean;
  };
}

function getEnv(key: string, defaultValue = ""): string {
  if (typeof import.meta !== "undefined" && import.meta.env) {
    return (import.meta.env as Record<string, string>)[key] || defaultValue;
  }
  if (typeof process !== "undefined" && process.env) {
    return process.env[key] || defaultValue;
  }
  return defaultValue;
}

function getBoolEnv(key: string, defaultValue = false): boolean {
  const value = getEnv(key, String(defaultValue));
  return value === "true" || value === "1";
}

function getAppEnvironment(): AppEnvironment {
  const nodeEnv = getEnv("NODE_ENV");
  if (["development", "staging", "production", "test"].includes(nodeEnv)) {
    return nodeEnv as AppEnvironment;
  }
  return "development";
}

export function loadConfig(): AppConfig {
  const env = getAppEnvironment();

  return {
    env,
    appUrl: getEnv("VITE_APP_URL", "http://localhost:5173"),
    apiBaseUrl: getEnv("VITE_API_BASE_URL", ""),
    supabase: {
      url: getEnv("VITE_SUPABASE_URL", ""),
      anonKey: getEnv("VITE_SUPABASE_ANON_KEY", ""),
    },
    features: {
      billing: getBoolEnv("VITE_BILLING_ENABLED", false),
    },
  };
}

let configInstance: AppConfig | null = null;

export function getConfig(): AppConfig {
  if (!configInstance) {
    configInstance = loadConfig();
  }
  return configInstance;
}

export function isProduction(): boolean {
  return getConfig().env === "production";
}

export function isDevelopment(): boolean {
  return getConfig().env === "development";
}

export function isTest(): boolean {
  return getConfig().env === "test";
}

export default getConfig;

import { createContext, ReactNode, useContext, useEffect, useState } from "react";

import { storage, STORAGE_KEYS } from "@/lib/storage";

type Theme = "light" | "dark" | "system";

interface ThemeContextValue {
  theme: Theme;
  setTheme: (theme: Theme) => void;
  resolvedTheme: "light" | "dark";
}

const ThemeContext = createContext<ThemeContextValue | undefined>(undefined);

interface ThemeProviderProps {
  children: ReactNode;
  defaultTheme?: Theme;
}

export function ThemeProvider({ children, defaultTheme = "system" }: ThemeProviderProps) {
  const [theme, setThemeState] = useState<Theme>(() => {
    return storage.get<Theme>(STORAGE_KEYS.THEME) || defaultTheme;
  });

  const [resolvedTheme, setResolvedTheme] = useState<"light" | "dark">("light");

  useEffect(() => {
    const root = window.document.documentElement;

    const applyTheme = (newTheme: "light" | "dark") => {
      root.classList.remove("light", "dark");
      root.classList.add(newTheme);
      setResolvedTheme(newTheme);
    };

    if (theme === "system") {
      const mediaQuery = window.matchMedia("(prefers-color-scheme: dark)");
      applyTheme(mediaQuery.matches ? "dark" : "light");

      const handler = (e: MediaQueryListEvent) => {
        applyTheme(e.matches ? "dark" : "light");
      };

      mediaQuery.addEventListener("change", handler);
      return () => mediaQuery.removeEventListener("change", handler);
    } else {
      applyTheme(theme);
    }
  }, [theme]);

  const setTheme = (newTheme: Theme) => {
    storage.set(STORAGE_KEYS.THEME, newTheme);
    setThemeState(newTheme);
  };

  return (
    <ThemeContext.Provider value={{ theme, setTheme, resolvedTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return context;
}

import * as ToastPrimitive from "@radix-ui/react-toast";
import { AlertCircle, AlertTriangle, CheckCircle, Info, X } from "lucide-react";
import { createContext, ReactNode, useCallback, useContext, useState } from "react";

import { cn } from "@/lib/utils";

type ToastVariant = "default" | "success" | "error" | "warning" | "info";

interface Toast {
  id: string;
  title: string;
  description?: string;
  variant?: ToastVariant;
  duration?: number;
}

interface ToastContextValue {
  toasts: Toast[];
  toast: (options: Omit<Toast, "id">) => void;
  dismiss: (id: string) => void;
}

const ToastContext = createContext<ToastContextValue | undefined>(undefined);

const variantStyles: Record<ToastVariant, string> = {
  default: "bg-background border",
  success: "bg-green-50 border-green-200 text-green-900",
  error: "bg-red-50 border-red-200 text-red-900",
  warning: "bg-yellow-50 border-yellow-200 text-yellow-900",
  info: "bg-blue-50 border-blue-200 text-blue-900",
};

const variantIcons: Record<ToastVariant, typeof CheckCircle> = {
  default: Info,
  success: CheckCircle,
  error: AlertCircle,
  warning: AlertTriangle,
  info: Info,
};

export function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const toast = useCallback((options: Omit<Toast, "id">) => {
    const id = Math.random().toString(36).slice(2);
    setToasts((prev) => [...prev, { ...options, id }]);
  }, []);

  const dismiss = useCallback((id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  return (
    <ToastContext.Provider value={{ toasts, toast, dismiss }}>
      <ToastPrimitive.Provider swipeDirection="right">
        {children}

        {toasts.map((t) => {
          const Icon = variantIcons[t.variant || "default"];
          return (
            <ToastPrimitive.Root
              key={t.id}
              duration={t.duration || 5000}
              onOpenChange={(open) => !open && dismiss(t.id)}
              className={cn(
                "group pointer-events-auto relative flex w-full items-center justify-between space-x-4 overflow-hidden rounded-md border p-4 shadow-lg transition-all",
                "data-[swipe=cancel]:translate-x-0 data-[swipe=end]:translate-x-[var(--radix-toast-swipe-end-x)]",
                "data-[swipe=move]:translate-x-[var(--radix-toast-swipe-move-x)] data-[swipe=move]:transition-none",
                "data-[state=open]:animate-in data-[state=closed]:animate-out",
                "data-[state=closed]:fade-out-80 data-[state=closed]:slide-out-to-right-full",
                "data-[state=open]:slide-in-from-top-full data-[state=open]:sm:slide-in-from-bottom-full",
                variantStyles[t.variant || "default"]
              )}
            >
              <div className="flex items-start gap-3">
                <Icon className="h-5 w-5 flex-shrink-0 mt-0.5" />
                <div className="grid gap-1">
                  <ToastPrimitive.Title className="text-sm font-semibold">
                    {t.title}
                  </ToastPrimitive.Title>
                  {t.description && (
                    <ToastPrimitive.Description className="text-sm opacity-90">
                      {t.description}
                    </ToastPrimitive.Description>
                  )}
                </div>
              </div>
              <ToastPrimitive.Close className="absolute right-2 top-2 rounded-md p-1 opacity-0 transition-opacity hover:opacity-100 group-hover:opacity-100 focus:opacity-100">
                <X className="h-4 w-4" />
              </ToastPrimitive.Close>
            </ToastPrimitive.Root>
          );
        })}

        <ToastPrimitive.Viewport className="fixed bottom-0 right-0 z-[100] flex max-h-screen w-full flex-col-reverse gap-2 p-4 sm:bottom-0 sm:right-0 sm:top-auto sm:flex-col sm:max-w-[420px]" />
      </ToastPrimitive.Provider>
    </ToastContext.Provider>
  );
}

export function useToast() {
  const context = useContext(ToastContext);
  if (!context) {
    throw new Error("useToast must be used within a ToastProvider");
  }
  return context;
}

/**
 * Comprehensive Audit Trail System
 *
 * Provides full traceability for all business case generation activities:
 * - Immutable audit logs
 * - Compliance tracking
 * - Data provenance
 * - Regulatory reporting
 * - Tamper-evident records
 *
 * Part of Phase 3 - Integration & Business Case Generation
 */

import { createHash, randomUUID } from 'crypto';

import { logger } from "../../../lib/logger";

// ============================================================================
// AUDIT TYPES
// ============================================================================

export type AuditLevel = 'DEBUG' | 'INFO' | 'WARN' | 'ERROR' | 'CRITICAL';
export type AuditCategory =
  | 'VALIDATION'
  | 'CALCULATION'
  | 'DECISION'
  | 'EVIDENCE'
  | 'COMPLIANCE'
  | 'ERROR'
  | 'PERFORMANCE'
  | 'SECURITY';

export interface AuditEntry {
  id: string;
  timestamp: string;
  level: AuditLevel;
  category: AuditCategory;
  component: string;
  operation: string;
  inputs: Record<string, unknown>;
  outputs: Record<string, unknown>;
  confidence: number;
  reasoning: string;
  evidence: string[];
  userId?: string;
  sessionId?: string;
  correlationId?: string;
  metadata: Record<string, unknown>;
  hash: string;
  previousHash?: string;
}

export interface AuditQuery {
  startTime?: string;
  endTime?: string;
  level?: AuditLevel[];
  category?: AuditCategory[];
  component?: string[];
  operation?: string[];
  correlationId?: string;
  sessionId?: string;
  userId?: string;
  minConfidence?: number;
}

export interface AuditStats {
  totalEntries: number;
  byLevel: Record<AuditLevel, number>;
  byCategory: Record<AuditCategory, number>;
  byComponent: Record<string, number>;
  averageConfidence: number;
  complianceScore: number;
  errorRate: number;
}

export interface ComplianceReport {
  period: { start: string; end: string };
  totalOperations: number;
  compliantOperations: number;
  violations: Violation[];
  recommendations: string[];
  signature: string;
}

export interface Violation {
  type: 'MISSING_DATA' | 'LOW_CONFIDENCE' | 'INVALID_CALCULATION' | 'COMPLIANCE_BREACH';
  severity: 'low' | 'medium' | 'high' | 'critical';
  description: string;
  entryId: string;
  timestamp: string;
  mitigation?: string;
}

// ============================================================================
// AUDIT TRAIL MANAGER
// ============================================================================

export class AuditTrailManager {
  private static instance: AuditTrailManager;
  private entries: AuditEntry[] = [];
  private maxEntries: number = 10000; // Prevent memory overflow
  private enabled: boolean = true;
  private persistentStorage: boolean = false;
  private storagePath: string = './audit-logs';

  private constructor() {
    // Singleton pattern
  }

  static getInstance(): AuditTrailManager {
    if (!AuditTrailManager.instance) {
      AuditTrailManager.instance = new AuditTrailManager();
    }
    return AuditTrailManager.instance;
  }

  /**
   * Configure audit trail settings
   */
  configure(options: {
    enabled?: boolean;
    maxEntries?: number;
    persistentStorage?: boolean;
    storagePath?: string;
  }): void {
    if (options.enabled !== undefined) this.enabled = options.enabled;
    if (options.maxEntries) this.maxEntries = options.maxEntries;
    if (options.persistentStorage !== undefined) this.persistentStorage = options.persistentStorage;
    if (options.storagePath) this.storagePath = options.storagePath;

    if (this.persistentStorage) {
      this.ensureStorageDirectory();
    }
  }

  /**
   * Log an audit entry
   */
  log(entry: {
    level: AuditLevel;
    category: AuditCategory;
    component: string;
    operation: string;
    inputs: Record<string, unknown>;
    outputs: Record<string, unknown>;
    confidence: number;
    reasoning: string;
    evidence?: string[];
    userId?: string;
    sessionId?: string;
    correlationId?: string;
    metadata?: Record<string, unknown>;
  }): AuditEntry {
    if (!this.enabled) {
      return {} as AuditEntry;
    }

    const timestamp = new Date().toISOString();
    const previousHash = this.entries.length > 0 ? this.entries[this.entries.length - 1].hash : 'GENESIS';

    const auditEntry: AuditEntry = {
      id: randomUUID(),
      timestamp,
      level: entry.level,
      category: entry.category,
      component: entry.component,
      operation: entry.operation,
      inputs: this.sanitizeData(entry.inputs) as Record<string, unknown>,
      outputs: this.sanitizeData(entry.outputs) as Record<string, unknown>,
      confidence: Math.max(0, Math.min(1, entry.confidence)),
      reasoning: entry.reasoning,
      evidence: entry.evidence || [],
      userId: entry.userId,
      sessionId: entry.sessionId,
      correlationId: entry.correlationId,
      metadata: entry.metadata || {},
      previousHash,
      hash: this.calculateHash({ timestamp, previousHash, ...entry })
    };

    this.entries.push(auditEntry);

    // Maintain max entries limit
    if (this.entries.length > this.maxEntries) {
      this.entries = this.entries.slice(-this.maxEntries);
    }

    // Persist if enabled
    if (this.persistentStorage) {
      this.persistEntry(auditEntry);
    }

    // Emit event for real-time monitoring
    this.emitAuditEvent(auditEntry);

    return auditEntry;
  }

  /**
   * Query audit trail
   */
  query(filter: AuditQuery = {}): AuditEntry[] {
    let results = [...this.entries];

    // Time range filter
    if (filter.startTime) {
      results = results.filter(e => e.timestamp >= filter.startTime);
    }
    if (filter.endTime) {
      results = results.filter(e => e.timestamp <= filter.endTime);
    }

    // Level filter
    if (filter.level && filter.level.length > 0) {
      results = results.filter(e => filter.level!.includes(e.level));
    }

    // Category filter
    if (filter.category && filter.category.length > 0) {
      results = results.filter(e => filter.category!.includes(e.category));
    }

    // Component filter
    if (filter.component && filter.component.length > 0) {
      results = results.filter(e => filter.component!.includes(e.component));
    }

    // Operation filter
    if (filter.operation && filter.operation.length > 0) {
      results = results.filter(e => filter.operation!.includes(e.operation));
    }

    // Correlation ID filter
    if (filter.correlationId) {
      results = results.filter(e => e.correlationId === filter.correlationId);
    }

    // Session ID filter
    if (filter.sessionId) {
      results = results.filter(e => e.sessionId === filter.sessionId);
    }

    // User ID filter
    if (filter.userId) {
      results = results.filter(e => e.userId === filter.userId);
    }

    // Confidence filter
    if (filter.minConfidence !== undefined) {
      results = results.filter(e => e.confidence >= filter.minConfidence);
    }

    return results;
  }

  /**
   * Get statistics
   */
  getStats(filter: AuditQuery = {}): AuditStats {
    const entries = this.query(filter);

    const stats: AuditStats = {
      totalEntries: entries.length,
      byLevel: { DEBUG: 0, INFO: 0, WARN: 0, ERROR: 0, CRITICAL: 0 },
      byCategory: {
        VALIDATION: 0, CALCULATION: 0, DECISION: 0, EVIDENCE: 0,
        COMPLIANCE: 0, ERROR: 0, PERFORMANCE: 0, SECURITY: 0
      },
      byComponent: {},
      averageConfidence: 0,
      complianceScore: 0,
      errorRate: 0
    };

    let totalConfidence = 0;
    let errorCount = 0;
    let criticalCount = 0;

    for (const entry of entries) {
      // Count by level
      stats.byLevel[entry.level]++;

      // Count by category
      stats.byCategory[entry.category]++;

      // Count by component
      stats.byComponent[entry.component] = (stats.byComponent[entry.component] || 0) + 1;

      // Accumulate confidence
      totalConfidence += entry.confidence;

      // Count errors
      if (entry.level === 'ERROR' || entry.level === 'CRITICAL') {
        errorCount++;
        if (entry.level === 'CRITICAL') criticalCount++;
      }
    }

    stats.averageConfidence = entries.length > 0 ? totalConfidence / entries.length : 0;
    stats.errorRate = entries.length > 0 ? errorCount / entries.length : 0;

    // Compliance score (0-100)
    const criticalPenalty = criticalCount * 10;
    const errorPenalty = errorCount * 2;
    const confidenceBonus = stats.averageConfidence * 10;
    stats.complianceScore = Math.max(0, Math.min(100, 100 - criticalPenalty - errorPenalty + confidenceBonus));

    return stats;
  }

  /**
   * Generate compliance report
   */
  generateComplianceReport(startTime: string, endTime: string): ComplianceReport {
    const entries = this.query({ startTime, endTime });

    const violations: Violation[] = [];
    let compliantOperations = 0;

    for (const entry of entries) {
      // Check for violations
      if (entry.confidence < 0.6 && entry.category !== 'ERROR') {
        violations.push({
          type: 'LOW_CONFIDENCE',
          severity: entry.confidence < 0.3 ? 'high' : 'medium',
          description: `Low confidence (${entry.confidence.toFixed(2)}) for ${entry.component}:${entry.operation}`,
          entryId: entry.id,
          timestamp: entry.timestamp,
          mitigation: 'Review calculation methodology and data sources'
        });
      }

      if (entry.category === 'ERROR' && entry.level === 'CRITICAL') {
        violations.push({
          type: 'INVALID_CALCULATION',
          severity: 'critical',
          description: `Critical error: ${entry.reasoning}`,
          entryId: entry.id,
          timestamp: entry.timestamp,
          mitigation: 'Immediate investigation required'
        });
      }

      if (entry.category === 'VALIDATION' && entry.outputs.valid === false) {
        violations.push({
          type: 'MISSING_DATA',
          severity: 'medium',
          description: `Validation failed: ${(Array.isArray(entry.outputs.errors) ? entry.outputs.errors : []).join(', ')}`,
          entryId: entry.id,
          timestamp: entry.timestamp,
          mitigation: 'Provide missing data or adjust constraints'
        });
      }

      // Count compliant operations
      if (entry.level !== 'ERROR' && entry.level !== 'CRITICAL' && entry.confidence >= 0.7) {
        compliantOperations++;
      }
    }

    // Generate recommendations
    const recommendations: string[] = [];

    if (violations.some(v => v.type === 'LOW_CONFIDENCE')) {
      recommendations.push('Improve data quality and source reliability');
    }

    if (violations.some(v => v.type === 'INVALID_CALCULATION')) {
      recommendations.push('Review calculation logic and validation rules');
    }

    if (violations.some(v => v.type === 'MISSING_DATA')) {
      recommendations.push('Implement data collection for missing KPIs');
    }

    if (violations.length === 0) {
      recommendations.push('All operations compliant - maintain current processes');
    }

    // Create signature
    const signature = this.createComplianceSignature(startTime, endTime, violations.length);

    return {
      period: { start: startTime, end: endTime },
      totalOperations: entries.length,
      compliantOperations,
      violations,
      recommendations,
      signature
    };
  }

  /**
   * Verify audit integrity
   */
  verifyIntegrity(): { valid: boolean; issues: string[] } {
    const issues: string[] = [];

    for (let i = 0; i < this.entries.length; i++) {
      const entry = this.entries[i];

      // Verify hash chain
      if (i > 0) {
        const expectedPreviousHash = this.entries[i - 1].hash;
        if (entry.previousHash !== expectedPreviousHash) {
          issues.push(`Hash chain broken at index ${i}`);
        }
      }

      // Verify current hash
      const expectedHash = this.calculateHash({
        timestamp: entry.timestamp,
        level: entry.level,
        category: entry.category,
        component: entry.component,
        operation: entry.operation,
        inputs: entry.inputs,
        outputs: entry.outputs,
        confidence: entry.confidence,
        reasoning: entry.reasoning,
        evidence: entry.evidence,
        userId: entry.userId,
        sessionId: entry.sessionId,
        correlationId: entry.correlationId,
        metadata: entry.metadata
      });

      if (entry.hash !== expectedHash) {
        issues.push(`Hash mismatch at entry ${entry.id}`);
      }

      // Check for tampering indicators
      if (entry.previousHash === 'GENESIS' && i > 0) {
        issues.push(`Genesis hash found at non-zero index ${i}`);
      }
    }

    return {
      valid: issues.length === 0,
      issues
    };
  }

  /**
   * Export audit trail
   */
  export(format: 'json' | 'csv' | 'xml' = 'json', filter: AuditQuery = {}): string {
    const entries = this.query(filter);

    if (format === 'json') {
      return JSON.stringify(entries, null, 2);
    }

    if (format === 'csv') {
      const headers = ['id', 'timestamp', 'level', 'category', 'component', 'operation', 'confidence', 'reasoning'];
      const rows = entries.map(e => [
        e.id,
        e.timestamp,
        e.level,
        e.category,
        e.component,
        e.operation,
        e.confidence.toFixed(3),
        `"${e.reasoning.replace(/"/g, '""')}"`
      ]);
      return [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
    }

    if (format === 'xml') {
      const xmlEntries = entries.map(e => `
        <entry id="${e.id}" timestamp="${e.timestamp}">
          <level>${e.level}</level>
          <category>${e.category}</category>
          <component>${e.component}</component>
          <operation>${e.operation}</operation>
          <confidence>${e.confidence}</confidence>
          <reasoning>${this.escapeXml(e.reasoning)}</reasoning>
          <hash>${e.hash}</hash>
        </entry>
      `).join('');
      return `<audit-trail>${xmlEntries}</audit-trail>`;
    }

    return '';
  }

  /**
   * Clear audit trail
   */
  clear(filter: AuditQuery = {}): number {
    if (Object.keys(filter).length === 0) {
      const count = this.entries.length;
      this.entries = [];
      return count;
    }

    const toRemove = this.query(filter);
    const removeIds = new Set(toRemove.map(e => e.id));
    const beforeCount = this.entries.length;
    this.entries = this.entries.filter(e => !removeIds.has(e.id));
    return beforeCount - this.entries.length;
  }

  /**
   * Get entry by ID
   */
  getEntry(id: string): AuditEntry | undefined {
    return this.entries.find(e => e.id === id);
  }

  /**
   * Get total count
   */
  getCount(): number {
    return this.entries.length;
  }

  // ============================================================================
  // PRIVATE HELPER METHODS
  // ============================================================================

  private calculateHash(data: string | Record<string, unknown>): string {
    const hash = createHash('sha256');
    if (typeof data === 'string') {
      hash.update(data);
    } else {
      hash.update(JSON.stringify(data));
    }
    return hash.digest('hex');
  }

  private sanitizeData(data: unknown): unknown {
    if (data === null || data === undefined) return {};

    // Remove sensitive data
    const sensitiveKeys = ['password', 'token', 'secret', 'apiKey', 'privateKey'];

    const sanitize = (obj: unknown): unknown => {
      if (typeof obj !== 'object' || obj === null) return obj;

      if (Array.isArray(obj)) {
        return obj.map(sanitize);
      }

      const result: Record<string, unknown> = {};
      for (const [key, value] of Object.entries(obj)) {
        if (sensitiveKeys.some(sk => key.toLowerCase().includes(sk))) {
          result[key] = '***REDACTED***';
        } else {
          result[key] = sanitize(value);
        }
      }
      return result;
    };

    return sanitize(data);
  }

  private createComplianceSignature(startTime: string, endTime: string, violationCount: number): string {
    const data = `${startTime}|${endTime}|${violationCount}|${this.entries.length}`;
    return this.calculateHash(data).substring(0, 16);
  }

  private escapeXml(text: string): string {
    return text.replace(/&/g, '&amp;')
               .replace(/</g, '&lt;')
               .replace(/>/g, '&gt;')
               .replace(/"/g, '&quot;')
               .replace(/'/g, '&#39;');
  }

  private emitAuditEvent(entry: AuditEntry): void {
    // In a real implementation, this would emit events to listeners
    // For now, we'll just log to console in development
    if (process.env.NODE_ENV === 'development') {
      logger.info(`[AUDIT] ${entry.level} ${entry.category} ${entry.component}:${entry.operation} (conf: ${entry.confidence.toFixed(2)})`);
    }
  }

  private ensureStorageDirectory(): void {
    const fs = require('fs');
    const path = require('path');

    const dir = path.resolve(this.storagePath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
  }

  private persistEntry(entry: AuditEntry): void {
    if (!this.persistentStorage) return;

    const fs = require('fs');
    const path = require('path');

    try {
      const date = new Date().toISOString().split('T')[0];
      const filename = `audit-${date}.jsonl`;
      const filepath = path.join(this.storagePath, filename);

      const line = JSON.stringify(entry) + '\n';
      fs.appendFileSync(filepath, line);
    } catch (error: unknown) {
      console.error('Failed to persist audit entry:', error);
    }
  }
}

// ============================================================================
// AUDIT TRAIL DECORATOR
// ============================================================================

/**
 * Decorator to automatically audit method calls
 */
export function AuditTrail(
  component: string,
  options: {
    level?: AuditLevel;
    category?: AuditCategory;
    includeInputs?: boolean;
    includeOutputs?: boolean;
    confidence?: (result: unknown) => number;
  } = {}
) {
  return function (_target: unknown, propertyKey: string, descriptor: PropertyDescriptor) {
    const originalMethod = descriptor.value;
    const audit = AuditTrailManager.getInstance();

    descriptor.value = async function (...args: unknown[]) {
      const startTime = Date.now();
      const inputs = options.includeInputs !== false ? args : {};

      try {
        const result = await originalMethod.apply(this, args);
        const duration = Date.now() - startTime;

        const confidence = options.confidence ? options.confidence(result) : 1.0;

        audit.log({
          level: options.level || 'INFO',
          category: options.category || 'CALCULATION',
          component,
          operation: propertyKey,
          inputs,
          outputs: options.includeOutputs !== false ? { result, duration } : {},
          confidence,
          reasoning: `Method ${propertyKey} executed successfully in ${duration}ms`,
          evidence: [],
          metadata: { duration }
        });

        return result;
      } catch (error: unknown) {
        const duration = Date.now() - startTime;

        audit.log({
          level: 'ERROR',
          category: 'ERROR',
          component,
          operation: propertyKey,
          inputs,
          outputs: { error: error instanceof Error ? error.message : 'Unknown error' },
          confidence: 0,
          reasoning: `Method ${propertyKey} failed: ${error instanceof Error ? error.message : 'Unknown error'}`,
          evidence: [],
          metadata: { duration, error: String(error) }
        });

        throw error;
      }
    };

    return descriptor;
  };
}

// ============================================================================
// COMPLIANCE MONITOR
// ============================================================================

export class ComplianceMonitor {
  private auditManager: AuditTrailManager;
  private thresholds: {
    minConfidence: number;
    maxErrorRate: number;
    maxCriticalCount: number;
  };

  constructor(thresholds?: {
    minConfidence?: number;
    maxErrorRate?: number;
    maxCriticalCount?: number;
  }) {
    this.auditManager = AuditTrailManager.getInstance();
    this.thresholds = {
      minConfidence: thresholds?.minConfidence ?? 0.7,
      maxErrorRate: thresholds?.maxErrorRate ?? 0.05,
      maxCriticalCount: thresholds?.maxCriticalCount ?? 0,
      ...thresholds
    };
  }

  /**
   * Check if system is compliant
   */
  isCompliant(filter: AuditQuery = {}): { compliant: boolean; issues: string[] } {
    const stats = this.auditManager.getStats(filter);
    const issues: string[] = [];

    if (stats.averageConfidence < this.thresholds.minConfidence) {
      issues.push(`Average confidence (${stats.averageConfidence.toFixed(2)}) below threshold (${this.thresholds.minConfidence})`);
    }

    if (stats.errorRate > this.thresholds.maxErrorRate) {
      issues.push(`Error rate (${(stats.errorRate * 100).toFixed(1)}%) exceeds threshold (${(this.thresholds.maxErrorRate * 100).toFixed(1)}%)`);
    }

    const criticalCount = stats.byLevel.CRITICAL;
    if (criticalCount > this.thresholds.maxCriticalCount) {
      issues.push(`Critical errors (${criticalCount}) exceed threshold (${this.thresholds.maxCriticalCount})`);
    }

    return {
      compliant: issues.length === 0,
      issues
    };
  }

  /**
   * Monitor for anomalies
   */
  detectAnomalies(): string[] {
    const anomalies: string[] = [];
    const recentEntries = this.auditManager.query({
      startTime: new Date(Date.now() - 3600000).toISOString() // Last hour
    });

    // Check for sudden spike in errors
    const errorCount = recentEntries.filter(e => e.level === 'ERROR' || e.level === 'CRITICAL').length;
    if (errorCount > 10) {
      anomalies.push(`Error spike detected: ${errorCount} errors in last hour`);
    }

    // Check for low confidence patterns
    const lowConfidence = recentEntries.filter(e => e.confidence < 0.5).length;
    if (lowConfidence > 5) {
      anomalies.push(`Low confidence pattern: ${lowConfidence} entries below 0.5`);
    }

    // Check for missing evidence
    const noEvidence = recentEntries.filter(e => e.evidence.length === 0).length;
    if (noEvidence > 3) {
      anomalies.push(`Evidence gap: ${noEvidence} entries without supporting evidence`);
    }

    return anomalies;
  }

  /**
   * Get compliance dashboard data
   */
  getDashboardData(): {
    complianceScore: number;
    health: 'green' | 'yellow' | 'red';
    stats: AuditStats;
    anomalies: string[];
  } {
    const stats = this.auditManager.getStats();
    const compliance = this.isCompliant();
    const anomalies = this.detectAnomalies();

    let health: 'green' | 'yellow' | 'red' = 'green';
    if (stats.complianceScore < 70) health = 'red';
    else if (stats.complianceScore < 85) health = 'yellow';

    return {
      complianceScore: stats.complianceScore,
      health,
      stats,
      anomalies
    };
  }
}

