            <Button onClick={handleSend} disabled={!inputValue.trim() || isStreaming} size="sm" aria-label="Send message">
              {isStreaming ? (
                <Loader2 className="h-4 w-4 animate-spin" aria-hidden="true" />
              ) : (
                <Send className="h-4 w-4" aria-hidden="true" />
              )}
            </Button>
