    },
  ];
}

interface SearchableCommand {
  command: CommandItem;
  label: string;
  description: string;
  keywords: string[];
}

/* ------------------------------------------------------------------ */
/*  Command Palette UI                                                 */
/* ------------------------------------------------------------------ */

function CommandPaletteDialog({
  commands,
  aiSuggestions,
  onClose,
}: {
  commands: CommandItem[];
  aiSuggestions: CommandItem[];
  onClose: () => void;
}) {
  const [query, setQuery] = useState("");
  const [selectedIndex, setSelectedIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLDivElement>(null);

  const searchableCommands = useMemo<SearchableCommand[]>(
    () => commands.map((command) => ({
      command,
      label: command.label.toLowerCase(),
      description: command.description?.toLowerCase() ?? "",
      keywords: command.keywords?.map((keyword) => keyword.toLowerCase()) ?? [],
    })),
    [commands],
  );

  const filtered = useMemo(
    () => {
      const normalizedQuery = query.toLowerCase();
      if (!normalizedQuery) {
        return searchableCommands.map(({ command }) => command);
      }

      return searchableCommands
        .filter(({ label, description, keywords }) => (
          label.includes(normalizedQuery)
          || description.includes(normalizedQuery)
          || keywords.some((keyword) => keyword.includes(normalizedQuery))
        ))
        .map(({ command }) => command);
    },
    [query, searchableCommands],
  );

  // Reset selection when query changes
  useEffect(() => {
    setSelectedIndex(0);
  }, [query]);

  // Focus input on open
  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSelect = useCallback(
    (item: CommandItem) => {
      item.onSelect();
      onClose();
    },
    [onClose],
  );

  const handleKeyDown = useCallback(
    (e: ReactKeyboardEvent) => {
      switch (e.key) {
        case "ArrowDown":
          e.preventDefault();
          setSelectedIndex((prev) => Math.min(prev + 1, filtered.length - 1));
          break;
        case "ArrowUp":
          e.preventDefault();
          setSelectedIndex((prev) => Math.max(prev - 1, 0));
          break;
        case "Enter":
          e.preventDefault();
          if (filtered[selectedIndex]) {
            handleSelect(filtered[selectedIndex]);
          }
          break;
        case "Escape":
          e.preventDefault();
          onClose();
          break;
      }
    },
    [filtered, selectedIndex, handleSelect, onClose],
  );

  // Scroll selected item into view
  useEffect(() => {
    const listEl = listRef.current;
    if (!listEl) return;
    const selectedEl = listEl.querySelector(`[data-index="${selectedIndex}"]`);
    selectedEl?.scrollIntoView({ block: "nearest" });
  }, [selectedIndex]);

  const categoryLabels: Record<string, string> = {
    navigation: "Navigation",
    action: "Actions",
    settings: "Settings",
  };

  // Group by category
  const grouped = useMemo(() => {
    const groups: Record<string, CommandItem[]> = {};
    for (const item of filtered) {
      const cat = item.category;
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(item);
    }
    return groups;
  }, [filtered]);

  let globalIndex = -1;

  return (
    <>
      {/* Backdrop */}
      <div
        className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* Dialog */}
      <div
        role="dialog"
        aria-modal="true"
        aria-label="Command palette"
        className="fixed inset-x-0 top-[20%] z-50 mx-auto max-w-lg"
        onKeyDown={handleKeyDown}
      >
        <div className="overflow-hidden rounded-xl border border-border bg-popover shadow-2xl">
          {/* Search input */}
          <div className="flex items-center gap-2 border-b border-border px-4 py-3">
            <Search className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
            <input
              ref={inputRef}
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Type a command or search..."
              className="flex-1 bg-transparent text-sm text-foreground placeholder:text-muted-foreground outline-none"
              aria-label="Search commands"
              autoComplete="off"
              role="combobox"
              aria-expanded="true"
              aria-controls="command-list"
              aria-activedescendant={
                filtered[selectedIndex]
                  ? `cmd-${filtered[selectedIndex].id}`
                  : undefined
              }
            />
            <button
              onClick={onClose}
              className="rounded p-1 text-muted-foreground hover:text-foreground"
              aria-label="Close command palette"
            >
              <X className="h-4 w-4" />
            </button>
          </div>

          {/* Screen-reader announcement for result count */}
          <div role="status" aria-live="polite" aria-atomic="true" className="sr-only">
            {filtered.length === 0
              ? "No results found"
              : `${filtered.length} command${filtered.length === 1 ? "" : "s"} available`}
          </div>

          {/* Results */}
          <div
            ref={listRef}
            id="command-list"
            role="listbox"
            className="max-h-72 overflow-y-auto p-2"
          >
            {filtered.length === 0 && (
              <p className="py-6 text-center text-sm text-muted-foreground">
                No results found.
              </p>
            )}

            {Object.entries(grouped).map(([category, items]) => (
              <div key={category}>
                <p className="px-2 py-1.5 text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">
                  {categoryLabels[category] ?? category}
                </p>
                {items.map((item) => {
                  globalIndex++;
                  const isSelected = globalIndex === selectedIndex;
                  const Icon = item.icon;
                  const idx = globalIndex;

                  return (
                    <div
                      key={item.id}
                      id={`cmd-${item.id}`}
                      role="option"
                      aria-selected={isSelected}
                      tabIndex={-1}
                      data-index={idx}
                      onClick={() => handleSelect(item)}
                      onKeyDown={(event) => {
                        if (event.key === "Enter" || event.key === " ") {
                          event.preventDefault();
                          handleSelect(item);
                        }
                      }}
                      onMouseEnter={() => setSelectedIndex(idx)}
                      className={cn(
                        "flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 text-sm transition-colors",
                        isSelected
                          ? "bg-accent text-accent-foreground"
                          : "text-foreground hover:bg-accent/50",
                      )}
                    >
                      {Icon && (
                        <Icon className="h-4 w-4 flex-shrink-0 text-muted-foreground" aria-hidden="true" />
                      )}
                      <div className="flex-1 min-w-0">
                        <p className="font-medium truncate">{item.label}</p>
                        {item.description && (
                          <p className="text-[12px] text-muted-foreground truncate">
                            {item.description}
                          </p>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            ))}

            {query.length === 0 && aiSuggestions.length > 0 && (
              <div>
                <p className="px-2 py-1.5 text-[11px] font-semibold uppercase tracking-wider text-muted-foreground">
                  AI Suggestions
                </p>
                {aiSuggestions.map((item) => (
                  <div
                    key={`ai-${item.id}`}
                    onClick={() => handleSelect(item)}
                    className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 text-sm text-foreground transition-colors hover:bg-accent/50"
                  >
                    <Zap className="h-4 w-4 text-primary" aria-hidden="true" />
                    <div className="flex-1 min-w-0">
                      <p className="font-medium truncate">{item.label}</p>
                      {item.description && (
                        <p className="text-[12px] text-muted-foreground truncate">{item.description}</p>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Footer hint */}
          <div className="border-t border-border px-4 py-2 text-[11px] text-muted-foreground flex items-center gap-4">
            <span><kbd className="rounded border border-border bg-muted px-1 py-0.5 font-mono text-[10px]">&uarr;</kbd> <kbd className="rounded border border-border bg-muted px-1 py-0.5 font-mono text-[10px]">&darr;</kbd> navigate</span>
            <span><kbd className="rounded border border-border bg-muted px-1 py-0.5 font-mono text-[10px]">Enter</kbd> select</span>
            <span><kbd className="rounded border border-border bg-muted px-1 py-0.5 font-mono text-[10px]">Esc</kbd> close</span>
          </div>
        </div>
      </div>
    </>
  );
}

/* ------------------------------------------------------------------ */
/*  Provider                                                           */
/* ------------------------------------------------------------------ */

export function CommandPaletteProvider({ children }: { children: ReactNode }) {
  const [isOpen, setIsOpen] = useState(false);
  const [extraCommands, setExtraCommands] = useState<CommandItem[]>([]);
  const previousFocusRef = useRef<HTMLElement | null>(null);

  const navigate = useCallback((path: string) => {
    safeNavigate(path, { fallback: "/dashboard" });
  }, []);

  const defaultCommands = useMemo(() => createDefaultCommands(navigate), [navigate]);
  const allCommands = useMemo(
    () => [...defaultCommands, ...extraCommands],
    [defaultCommands, extraCommands],
  );

  const openCommandPalette = useCallback(() => {
    previousFocusRef.current = document.activeElement instanceof HTMLElement ? document.activeElement : null;
    setIsOpen(true);
  }, []);
  const closeCommandPalette = useCallback(() => {
    setIsOpen(false);
    previousFocusRef.current?.focus();
  }, []);
  const registerCommands = useCallback((commands: CommandItem[]) => {
    setExtraCommands((prev) => {
      const nextById = new Map<string, CommandItem>();
      [...prev, ...commands].forEach((command) => {
        nextById.set(command.id, command);
      });
      return [...nextById.values()];
    });

    return () => {
      const commandIds = new Set(commands.map((command) => command.id));
      setExtraCommands((prev) => prev.filter((command) => !commandIds.has(command.id)));
    };
  }, []);

  // Global keyboard shortcut: Cmd+K / Ctrl+K
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      const target = e.target;
      const isEditableTarget =
        target instanceof HTMLElement
        && (target.isContentEditable
          || target.tagName === "INPUT"
          || target.tagName === "TEXTAREA"
          || target.tagName === "SELECT");

      if (isEditableTarget) {
        return;
      }

      if ((e.metaKey || e.ctrlKey) && e.key === "k") {
        e.preventDefault();
        setIsOpen((prev) => !prev);
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, []);

  const aiSuggestions = useMemo(() => allCommands.slice(0, 3), [allCommands]);

  return (
    <CommandPaletteContext.Provider
      value={{ openCommandPalette, closeCommandPalette, isOpen, registerCommands }}
    >
      {children}
      {isOpen && (
        <CommandPaletteDialog commands={allCommands} aiSuggestions={aiSuggestions} onClose={closeCommandPalette} />
      )}
    </CommandPaletteContext.Provider>
  );
}

export function useCommandPalette() {
  const context = useContext(CommandPaletteContext);
  if (!context) {
    throw new Error("useCommandPalette must be used within a CommandPaletteProvider");
  }
  return context;
}

// apps/ValyntApp/src/components/DrawerForm.tsx
import { X } from "lucide-react";
import React, { useCallback, useEffect, useRef } from "react";

import { cn } from "@/lib/utils";

interface DrawerFormProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  description?: string;
  children: React.ReactNode;
  size?: "sm" | "md" | "lg";
  showCloseButton?: boolean;
  className?: string;
}

const sizeClasses = {
  sm: "w-80",
  md: "w-96",
  lg: "w-[32rem]",
} as const;

const backdropClasses = "fixed inset-0 bg-slate-950/50 backdrop-blur-sm transition-opacity duration-300";
const drawerBaseClasses = "absolute right-0 top-0 h-full bg-[var(--vds-color-surface-2)] shadow-xl transform transition-transform duration-300 ease-out flex flex-col";
const headerClasses = "flex items-center justify-between p-4 border-b border-[var(--vds-color-border)]";
const titleClasses = "text-lg font-semibold text-[var(--vds-color-text-primary)]";
const descriptionClasses = "text-sm text-[var(--vds-color-text-muted)]";
const closeButtonClasses = "p-2 rounded-lg text-[var(--vds-color-text-muted)] hover:text-[var(--vds-color-text-primary)] hover:bg-[var(--vds-color-surface)] transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-[var(--vds-color-primary)]/30";
const contentClasses = "flex-1 p-4 overflow-auto";

const DrawerForm: React.FC<DrawerFormProps> = ({
  isOpen,
  onClose,
  title,
  description,
  children,
  size = "md",
  showCloseButton = true,
  className,
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const previousFocusRef = useRef<HTMLElement | null>(null);

  const focusFirstFocusable = useCallback((element: HTMLElement) => {
    const focusableSelectors = 'input:not([disabled]), textarea:not([disabled]), select:not([disabled]), button:not([disabled]), [href], [tabindex]:not([tabindex="-1"])';
    const firstFocusable = element.querySelector(focusableSelectors);
    if (firstFocusable instanceof HTMLElement) {
      firstFocusable.focus();
    }
  }, []);

  const handleEscape = useCallback((e: KeyboardEvent) => {
    if (e.key === "Escape") onClose();
  }, [onClose]);

  useEffect(() => {
    if (isOpen) {
      previousFocusRef.current = document.activeElement as HTMLElement;
      document.addEventListener("keydown", handleEscape);
      document.body.style.overflow = "hidden";

      const timer = setTimeout(() => {
        if (containerRef.current) {
          focusFirstFocusable(containerRef.current);
        }
      }, 100);

      return () => {
        document.removeEventListener("keydown", handleEscape);
        document.body.style.overflow = "";
        clearTimeout(timer);
      };
    }
  }, [isOpen, handleEscape, focusFirstFocusable]);

  // Restore focus on close
  useEffect(() => {
    if (!isOpen && previousFocusRef.current) {
      previousFocusRef.current.focus();
    }
  }, [isOpen]);

  return (
    <div
      className={cn("fixed inset-0 z-50", isOpen ? "visible" : "invisible")}
      aria-hidden={!isOpen}
    >
      <div
        className={cn(backdropClasses, isOpen ? "opacity-100" : "opacity-0")}
        onClick={onClose}
        aria-hidden="true"
      />
      <div
        className={cn(
          drawerBaseClasses,
          sizeClasses[size],
          isOpen ? "translate-x-0" : "translate-x-full",
          className
        )}
        role="dialog"
        aria-modal="true"
        aria-labelledby="drawer-title"
        aria-describedby={description ? "drawer-description" : undefined}
      >
        <div className={headerClasses}>
          <div>
            <h2 id="drawer-title" className={titleClasses}>{title}</h2>
            {description && (
              <p id="drawer-description" className={descriptionClasses}>{description}</p>
            )}
          </div>
          {showCloseButton && (
            <button
              onClick={onClose}
              className={closeButtonClasses}
              aria-label="Close drawer"
            >
              <X className="w-5 h-5" aria-hidden="true" />
            </button>
          )}
        </div>
        <div ref={containerRef} className={contentClasses}>
          {children}
        </div>
      </div>
    </div>
  );
};

DrawerForm.displayName = "DrawerForm";

export default DrawerForm;

// apps/ValyntApp/src/components/EntityTable.tsx
import { ChevronDown, ChevronUp, Search } from "lucide-react";
import React, { useCallback, useMemo, useState } from "react";

import { cn } from "@/lib/utils";

interface Column<T> {
  key: keyof T;
  label: string;
  sortable?: boolean;
  render?: (value: unknown, item: T) => React.ReactNode;
}

interface EntityTableProps<T> {
  data: T[];
  columns: Column<T>[];
  onRowClick?: (item: T) => void;
  filterKey?: keyof T;
  emptyMessage?: string;
  className?: string;
}

const tableContainerClasses = "bg-[var(--vds-color-surface)] border border-[var(--vds-color-border)] rounded-lg overflow-hidden";
const tableClasses = "min-w-full";
const headerRowClasses = "bg-[var(--vds-color-surface-2)] border-b border-[var(--vds-color-border)]";
const headerCellClasses = "px-4 py-3 text-left text-xs font-semibold uppercase tracking-wider text-[var(--vds-color-text-secondary)]";
const rowClasses = "border-t border-[var(--vds-color-border)] transition-colors duration-150";
const rowHoverClasses = "hover:bg-[var(--vds-color-surface-2)]/50 cursor-pointer";
const cellClasses = "px-4 py-3 text-sm text-[var(--vds-color-text-primary)]";
const filterInputClasses = "w-full px-4 py-2 bg-[var(--vds-color-surface)] border border-[var(--vds-color-border)] rounded-lg text-sm text-[var(--vds-color-text-primary)] placeholder:text-[var(--vds-color-text-muted)] focus:outline-none focus:ring-2 focus:ring-[var(--vds-color-primary)]/30";

function EntityTable<T extends Record<string, unknown>>({
  data,
  columns,
  onRowClick,
  filterKey,
  emptyMessage = "No items found",
  className,
}: EntityTableProps<T>) {
  const [filter, setFilter] = useState("");
  const [sortConfig, setSortConfig] = useState<{ key: keyof T; direction: "asc" | "desc" } | null>(null);

  const filteredData = useMemo(() => {
    let result = filterKey
      ? data.filter((item) => String(item[filterKey]).toLowerCase().includes(filter.toLowerCase()))
      : [...data];

    if (sortConfig) {
      result.sort((a, b) => {
        const aValue = a[sortConfig.key];
        const bValue = b[sortConfig.key];
        if (aValue < bValue) return sortConfig.direction === "asc" ? -1 : 1;
        if (aValue > bValue) return sortConfig.direction === "asc" ? 1 : -1;
        return 0;
      });
    }

    return result;
  }, [data, filterKey, filter, sortConfig]);

  const handleSort = useCallback((key: keyof T) => {
    setSortConfig((current) => {
      if (!current || current.key !== key) {
        return { key, direction: "asc" };
      }
      if (current.direction === "asc") {
        return { key, direction: "desc" };
      }
      return null;
    });
  }, []);

  return (
    <div className={cn("space-y-3", className)}>
      {filterKey && (
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--vds-color-text-muted)]" aria-hidden="true" />
          <input
            type="text"
            placeholder="Filter..."
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className={cn(filterInputClasses, "pl-10")}
            aria-label="Filter table"
          />
        </div>
      )}

      <div className={tableContainerClasses}>
        <table className={tableClasses} role="table" aria-label="Entity table">
          <thead>
            <tr className={headerRowClasses}>
              {columns.map((col) => (
                <th key={String(col.key)} className={headerCellClasses} scope="col">
                  {col.sortable ? (
                    <button
                      onClick={() => handleSort(col.key)}
                      className="inline-flex items-center gap-1 hover:text-[var(--vds-color-text-primary)] transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-[var(--vds-color-primary)]/30 rounded"
                      aria-label={`Sort by ${col.label}`}
                    >
                      {col.label}
                      {sortConfig?.key === col.key && (
                        sortConfig.direction === "asc"
                          ? <ChevronUp className="w-3 h-3" aria-hidden="true" />
                          : <ChevronDown className="w-3 h-3" aria-hidden="true" />
                      )}
                    </button>
                  ) : (
                    col.label
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filteredData.length === 0 ? (
              <tr>
                <td colSpan={columns.length} className={cn(cellClasses, "text-center text-[var(--vds-color-text-muted)] py-8")}>
                  {emptyMessage}
                </td>
              </tr>
            ) : (
              filteredData.map((item, index) => (
                <tr
                  key={index}
                  className={cn(rowClasses, onRowClick && rowHoverClasses)}
                  onClick={() => onRowClick?.(item)}
                  role={onRowClick ? "button" : undefined}
                  tabIndex={onRowClick ? 0 : undefined}
                  onKeyDown={onRowClick ? (e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); onRowClick(item); } } : undefined}
                >
                  {columns.map((col) => (
                    <td key={String(col.key)} className={cellClasses}>
                      {col.render ? col.render(item[col.key], item) : String(item[col.key])}
                    </td>
                  ))}
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <div className="text-xs text-[var(--vds-color-text-muted)]">
        Showing {filteredData.length} of {data.length} items
      </div>
    </div>
  );
}

export default EntityTable;

