/**
 * KPIForm
 *
 * Form for entering KPI values with inline validation, progress tracking,
 * and field-level error prevention.
 *
 * UX Principles:
 * - Error Prevention > Error Messages: disables submit until valid, shows range hints
 * - Immediate Feedback: inline validation on blur, progress bar for completion
 * - Golden Thread: carries target context alongside each field
 * - Accessibility: aria-invalid, aria-describedby for errors, proper label association
 */

import { AlertCircle, Send, Target } from "lucide-react";
import React, { useMemo } from "react";

import { cn } from "@/lib/utils";

export interface KPIDefinition {
  id: string;
  label: string;
  unit?: string;
  type: "number" | "currency" | "percentage" | "text";
  min?: number;
  max?: number;
  target?: number;
  required?: boolean;
}

export interface KPIFormProps {
  kpis: KPIDefinition[];
  values?: Record<string, number | string>;
  errors?: Record<string, string>;
  onChange?: (kpiId: string, value: number | string) => void;
  onSubmit?: (values: Record<string, number | string>) => void;
  readOnly?: boolean;
  loading?: boolean;
  className?: string;
}

const unitSuffix: Record<string, string> = {
  currency: "$",
  percentage: "%",
};

function getInputType(kpiType: KPIDefinition["type"]): string {
  return kpiType === "text" ? "text" : "number";
}

function validateField(kpi: KPIDefinition, value: number | string | undefined): string | null {
  if (kpi.required && (value === undefined || value === "")) {
    return `${kpi.label} is required`;
  }
  if (kpi.type !== "text" && value !== undefined && value !== "") {
    const num = Number(value);
    if (isNaN(num)) return "Must be a number";
    if (kpi.min !== undefined && num < kpi.min) return `Minimum is ${kpi.min}`;
    if (kpi.max !== undefined && num > kpi.max) return `Maximum is ${kpi.max}`;
  }
  return null;
}

export const KPIForm: React.FC<KPIFormProps> = ({
  kpis,
  values = {},
  errors: externalErrors = {},
  onChange,
  onSubmit,
  readOnly = false,
  loading = false,
  className = "",
}) => {
  // Compute completion progress
  const { filledCount, totalRequired, allValid } = useMemo(() => {
    let filled = 0;
    let required = 0;
    let valid = true;

    for (const kpi of kpis) {
      const val = values[kpi.id];
      const hasValue = val !== undefined && val !== "";
      if (hasValue) filled++;
      if (kpi.required) {
        required++;
        if (!hasValue) valid = false;
      }
      const err = validateField(kpi, val);
      if (err && hasValue) valid = false;
    }

    return { filledCount: filled, totalRequired: required, allValid: valid };
  }, [kpis, values]);

  const progress = kpis.length > 0 ? (filledCount / kpis.length) * 100 : 0;
  const canSubmit = allValid && !readOnly && !loading;

  const handleChange = (kpi: KPIDefinition, raw: string) => {
    if (!onChange) return;
    const value = kpi.type === "text" ? raw : (raw === "" ? "" : Number(raw));
    onChange(kpi.id, value);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (canSubmit) onSubmit?.(values);
  };

  return (
    <form
      onSubmit={handleSubmit}
      className={cn("bg-card border border-border rounded-lg p-4 space-y-4", className)}
      noValidate
    >
      {/* Completion progress */}
      {kpis.length > 1 && (
        <div className="space-y-1">
          <div className="flex items-center justify-between text-xs text-muted-foreground">
            <span>{filledCount} of {kpis.length} fields completed</span>
            <span className="tabular-nums">{Math.round(progress)}%</span>
          </div>
          <div className="h-1 w-full overflow-hidden rounded-full bg-secondary">
            <div
              className="h-full rounded-full bg-primary transition-all duration-300 ease-out"
              style={{ width: `${progress}%` }}
              role="progressbar"
              aria-valuenow={Math.round(progress)}
              aria-valuemin={0}
              aria-valuemax={100}
            />
          </div>
        </div>
      )}

      {/* KPI fields */}
      {kpis.map((kpi) => {
        const currentValue = values[kpi.id] ?? "";
        const suffix = kpi.unit ?? unitSuffix[kpi.type] ?? "";
        const hasTarget = kpi.target !== undefined;
        const inlineError = externalErrors[kpi.id] || (currentValue !== "" ? validateField(kpi, currentValue) : null);
        const errorId = `kpi-error-${kpi.id}`;
        const hintId = `kpi-hint-${kpi.id}`;

        return (
          <div key={kpi.id} className="space-y-1.5">
            <label
              htmlFor={`kpi-${kpi.id}`}
              className="flex items-center justify-between text-sm font-medium text-foreground"
            >
              <span>
                {kpi.label}
                {kpi.required && <span className="text-destructive ml-0.5">*</span>}
              </span>
              {hasTarget && (
                <span className="inline-flex items-center gap-1 text-xs text-muted-foreground">
                  <Target className="w-3 h-3" />
                  Target: {kpi.target}{suffix}
                </span>
              )}
            </label>
            <div className="relative">
              {kpi.type === "currency" && (
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-sm text-muted-foreground" aria-hidden>
                  $
                </span>
              )}
              <input
                id={`kpi-${kpi.id}`}
                type={getInputType(kpi.type)}
                value={currentValue}
                onChange={(e) => handleChange(kpi, e.target.value)}
                readOnly={readOnly}
                min={kpi.min}
                max={kpi.max}
                step={kpi.type === "percentage" ? "0.1" : undefined}
                required={kpi.required}
                aria-invalid={!!inlineError}
                aria-describedby={cn(inlineError && errorId, (kpi.min !== undefined || kpi.max !== undefined) && hintId)}
                className={cn(
                  "w-full rounded-md border bg-secondary/50 px-3 py-2 text-sm text-foreground",
                  "placeholder:text-muted-foreground transition-colors",
                  "focus:outline-none focus:ring-2 focus:ring-ring",
                  kpi.type === "currency" && "pl-7",
                  readOnly && "opacity-60 cursor-not-allowed",
                  inlineError
                    ? "border-destructive focus:ring-destructive"
                    : "border-border"
                )}
                placeholder={`Enter ${kpi.label.toLowerCase()}`}
              />
              {suffix && kpi.type !== "currency" && (
                <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-muted-foreground" aria-hidden>
                  {suffix}
                </span>
              )}
            </div>

            {/* Range hint */}
            {(kpi.min !== undefined || kpi.max !== undefined) && !inlineError && (
              <p id={hintId} className="text-xs text-muted-foreground">
                {kpi.min !== undefined && kpi.max !== undefined
                  ? `Range: ${kpi.min}–${kpi.max}`
                  : kpi.min !== undefined
                    ? `Minimum: ${kpi.min}`
                    : `Maximum: ${kpi.max}`}
              </p>
            )}

            {/* Inline error */}
            {inlineError && (
              <p id={errorId} className="flex items-center gap-1 text-xs text-destructive" role="alert">
                <AlertCircle className="h-3 w-3 shrink-0" />
                {inlineError}
              </p>
            )}
          </div>
        );
      })}

      {/* Submit */}
      {!readOnly && onSubmit && (
        <button
          type="submit"
          disabled={!canSubmit}
          className={cn(
            "inline-flex items-center gap-1.5 px-4 py-2 text-sm font-medium rounded-md transition-colors",
            "bg-primary text-primary-foreground hover:bg-primary/90",
            "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
            "disabled:opacity-50 disabled:pointer-events-none"
          )}
        >
          {loading ? (
            <>
              <span className="h-3.5 w-3.5 animate-spin rounded-full border-2 border-current border-t-transparent" />
              Submitting...
            </>
          ) : (
            <>
              <Send className="w-3.5 h-3.5" />
              Submit
            </>
          )}
        </button>
      )}
    </form>
  );
};
KPIForm.displayName = "KPIForm";

export default KPIForm;

/**
 * NarrativeBlock
 *
 * Displays narrative content (insights, recommendations, warnings, summaries)
 * with type-coded visual indicators, collapsible sources, and copy support.
 *
 * UX Principles:
 * - Progressive Disclosure: sources hidden behind toggle
 * - Immediate Feedback: copy-to-clipboard with visual confirmation
 * - Accessibility: focus management, keyboard-accessible toggle, aria roles
 * - Visual Hierarchy: left border color codes type at a glance
 */

import {
  AlertTriangle,
  ArrowUpRight,
  Check,
  ChevronDown,
  ChevronRight,
  Clock,
  Copy,
  ExternalLink,
  FileText,
  Lightbulb,
  User,
} from "lucide-react";
import React, { useCallback, useState } from "react";

import { ConfidenceDisplay } from "../Agent/ConfidenceDisplay";

import { cn } from "@/lib/utils";

export interface NarrativeBlockProps {
  content: string;
  author?: string;
  timestamp?: string;
  type?: "insight" | "recommendation" | "warning" | "summary";
  confidence?: number;
  sources?: string[];
  collapsible?: boolean;
  defaultExpanded?: boolean;
  className?: string;
}

const typeConfig: Record<
  NonNullable<NarrativeBlockProps["type"]>,
  { icon: React.FC<{ className?: string }>; borderColor: string; iconColor: string; label: string }
> = {
  insight: { icon: Lightbulb, borderColor: "border-l-primary", iconColor: "text-primary", label: "Insight" },
  recommendation: { icon: ArrowUpRight, borderColor: "border-l-success", iconColor: "text-success", label: "Recommendation" },
  warning: { icon: AlertTriangle, borderColor: "border-l-warning", iconColor: "text-warning", label: "Warning" },
  summary: { icon: FileText, borderColor: "border-l-[hsl(var(--color-primary-400))]", iconColor: "text-primary", label: "Summary" },
};

export const NarrativeBlock: React.FC<NarrativeBlockProps> = ({
  content,
  author,
  timestamp,
  type = "summary",
  confidence,
  sources,
  collapsible = false,
  defaultExpanded = true,
  className = "",
}) => {
  const [showSources, setShowSources] = useState(false);
  const [expanded, setExpanded] = useState(defaultExpanded);
  const [copied, setCopied] = useState(false);
  const config = typeConfig[type];
  const Icon = config.icon;

  const handleCopy = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(content);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Fallback: no-op if clipboard API unavailable
    }
  }, [content]);

  return (
    <article
      className={cn(
        "bg-card border border-border border-l-4 rounded-lg p-4 transition-all duration-200",
        config.borderColor,
        className
      )}
      aria-label={`${config.label}: ${content.slice(0, 60)}...`}
    >
      <div className="flex items-start gap-3">
        <Icon className={cn("w-5 h-5 shrink-0 mt-0.5", config.iconColor)} />
        <div className="flex-1 min-w-0">
          {/* Header row */}
          <div className="flex items-center gap-2 flex-wrap mb-2">
            {collapsible ? (
              <button
                onClick={() => setExpanded(!expanded)}
                className="flex items-center gap-1 text-xs font-medium uppercase tracking-wider text-muted-foreground hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring rounded"
                aria-expanded={expanded}
              >
                {expanded ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3" />}
                {config.label}
              </button>
            ) : (
              <span className="text-xs font-medium uppercase tracking-wider text-muted-foreground">
                {config.label}
              </span>
            )}
            {confidence !== undefined && (
              <ConfidenceDisplay value={confidence} size="sm" showLabel={false} />
            )}

            {/* Copy button */}
            <button
              onClick={handleCopy}
              className={cn(
                "ml-auto p-1 rounded text-muted-foreground hover:text-foreground transition-colors",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
              )}
              aria-label={copied ? "Copied" : "Copy content"}
              title="Copy to clipboard"
            >
              {copied ? (
                <Check className="w-3.5 h-3.5 text-success" />
              ) : (
                <Copy className="w-3.5 h-3.5" />
              )}
            </button>
          </div>

          {/* Content (collapsible) */}
          {(!collapsible || expanded) && (
            <div className="animate-in fade-in-0 duration-200">
              <div className="text-sm text-foreground leading-relaxed whitespace-pre-wrap">
                {content}
              </div>

              {(author || timestamp) && (
                <div className="flex items-center gap-3 mt-3 text-xs text-muted-foreground">
                  {author && (
                    <span className="inline-flex items-center gap-1">
                      <User className="w-3 h-3" />
                      {author}
                    </span>
                  )}
                  {timestamp && (
                    <span className="inline-flex items-center gap-1">
                      <Clock className="w-3 h-3" />
                      {timestamp}
                    </span>
                  )}
                </div>
              )}

              {sources && sources.length > 0 && (
                <div className="mt-3 pt-3 border-t border-border">
                  <button
                    onClick={() => setShowSources(!showSources)}
                    className={cn(
                      "flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors",
                      "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring rounded"
                    )}
                    aria-expanded={showSources}
                  >
                    {showSources ? (
                      <ChevronDown className="w-3 h-3" />
                    ) : (
                      <ChevronRight className="w-3 h-3" />
                    )}
                    {sources.length} source{sources.length !== 1 ? "s" : ""}
                  </button>
                  {showSources && (
                    <ul className="mt-2 space-y-1 animate-in fade-in-0 slide-in-from-top-1 duration-150">
                      {sources.map((source, i) => (
                        <li
                          key={i}
                          className="flex items-center gap-1.5 text-xs text-muted-foreground"
                        >
                          <ExternalLink className="w-3 h-3 shrink-0" />
                          <span className="truncate">{source}</span>
                        </li>
                      ))}
                    </ul>
                  )}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </article>
  );
};
NarrativeBlock.displayName = "NarrativeBlock";

export default NarrativeBlock;

import React, { useMemo, useState } from "react";

export interface ScenarioSelectorScenario {
  id: string;
  label?: string;
  title?: string;
  description?: string;
  category?: string;
  estimatedTime?: string;
  estimatedValue?: string;
  tags?: string[];
}

export interface ScenarioSelectorProps {
  scenarios: ScenarioSelectorScenario[];
  selectedId?: string;
  onChange?: (id: string) => void;
  onSelect?: (scenario: ScenarioSelectorScenario) => void;
  showSearch?: boolean;
  showViewToggle?: boolean;
  multiSelect?: boolean;
  onMultiSelect?: (selectedIds: string[]) => void;
}

const getScenarioLabel = (scenario: ScenarioSelectorScenario) =>
  scenario.label ?? scenario.title ?? scenario.id;

export function ScenarioSelector({
  scenarios,
  selectedId,
  onChange,
  onSelect,
  showSearch = false,
  showViewToggle = false,
  multiSelect = false,
  onMultiSelect,
}: ScenarioSelectorProps) {
  const [searchQuery, setSearchQuery] = useState("");
  const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
  const [selectedIds, setSelectedIds] = useState<string[]>(selectedId ? [selectedId] : []);

  const filteredScenarios = useMemo(() => {
    const normalizedQuery = searchQuery.trim().toLowerCase();
    if (!normalizedQuery) {
      return scenarios;
    }

    return scenarios.filter((scenario) => {
      const searchableParts = [
        getScenarioLabel(scenario),
        scenario.description,
        scenario.category,
        ...(scenario.tags ?? []),
      ]
        .filter(Boolean)
        .join(" ")
        .toLowerCase();

      return searchableParts.includes(normalizedQuery);
    });
  }, [scenarios, searchQuery]);

  const handleSingleSelect = (scenario: ScenarioSelectorScenario) => {
    onChange?.(scenario.id);
    onSelect?.(scenario);
  };

  const handleMultiSelect = (scenario: ScenarioSelectorScenario) => {
    setSelectedIds((currentSelectedIds) => {
      const nextSelectedIds = currentSelectedIds.includes(scenario.id)
        ? currentSelectedIds.filter((id) => id !== scenario.id)
        : [...currentSelectedIds, scenario.id];

      onMultiSelect?.(nextSelectedIds);
      onSelect?.(scenario);
      return nextSelectedIds;
    });
  };

  return (
    <section className="space-y-4" aria-label="Scenario selector">
      {(showSearch || showViewToggle) && (
        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          {showSearch ? (
            <input
              aria-label="Search scenarios"
              className="rounded border border-border px-3 py-2 text-sm"
              onChange={(event) => setSearchQuery(event.target.value)}
              placeholder="Search scenarios..."
              type="search"
              value={searchQuery}
            />
          ) : (
            <div />
          )}

          {showViewToggle && (
            <div className="flex items-center gap-2" aria-label="Scenario layout controls">
              <button
                aria-pressed={viewMode === "grid"}
                className="rounded border border-border px-3 py-1.5 text-sm"
                onClick={() => setViewMode("grid")}
                type="button"
              >
                Grid
              </button>
              <button
                aria-pressed={viewMode === "list"}
                className="rounded border border-border px-3 py-1.5 text-sm"
                onClick={() => setViewMode("list")}
                type="button"
              >
                List
              </button>
            </div>
          )}
        </div>
      )}

      {!multiSelect && onChange ? (
        <label className="flex flex-col gap-1 text-sm">
          Scenario
          <select
            className="rounded border border-border px-2 py-1"
            onChange={(event) => onChange(event.target.value)}
            value={selectedId}
          >
            {scenarios.map((scenario) => (
              <option key={scenario.id} value={scenario.id}>
                {getScenarioLabel(scenario)}
              </option>
            ))}
          </select>
        </label>
      ) : null}

      {multiSelect && (
        <p className="text-sm text-muted-foreground">{selectedIds.length} scenarios selected</p>
      )}

      <div
        className={
          viewMode === "grid" ? "grid gap-3 md:grid-cols-2 xl:grid-cols-3" : "flex flex-col gap-3"
        }
      >
        {filteredScenarios.map((scenario) => {
          const isSelected = multiSelect
            ? selectedIds.includes(scenario.id)
            : selectedId === scenario.id;

          return (
            <button
              aria-pressed={isSelected}
              className={`rounded-lg border px-4 py-3 text-left transition-colors ${
                isSelected
                  ? "border-primary bg-primary/5"
                  : "border-border bg-card hover:bg-secondary"
              }`}
              key={scenario.id}
              onClick={() =>
                multiSelect ? handleMultiSelect(scenario) : handleSingleSelect(scenario)
              }
              type="button"
            >
              <div className="flex items-start justify-between gap-3">
                <div className="space-y-1">
                  <h3 className="font-medium text-foreground">{getScenarioLabel(scenario)}</h3>
                  {scenario.description && (
                    <p className="text-sm text-muted-foreground">{scenario.description}</p>
                  )}
                </div>
                {scenario.category && (
                  <span className="rounded-full bg-secondary px-2 py-1 text-xs text-muted-foreground">
                    {scenario.category}
                  </span>
                )}
              </div>

              {(scenario.estimatedTime || scenario.estimatedValue) && (
                <div className="mt-3 flex flex-wrap gap-3 text-xs text-muted-foreground">
                  {scenario.estimatedTime && <span>{scenario.estimatedTime}</span>}
                  {scenario.estimatedValue && <span>{scenario.estimatedValue}</span>}
                </div>
              )}
            </button>
          );
        })}
      </div>
    </section>
  );
}

/**
 * ValueTreeCard
 *
 * Hierarchical tree view for value drivers with keyboard navigation,
 * aria-tree roles, and expand-all/collapse-all controls.
 *
 * UX Principles:
 * - Minimize Cognitive Load: progressive disclosure via expand/collapse
 * - Accessibility: aria-tree/treeitem roles, arrow key navigation
 * - Visual Hierarchy: indentation + status badges for quick scanning
 */

import { ChevronDown, ChevronRight, ChevronsUpDown, Circle } from "lucide-react";
import React, { useCallback, useRef, useState } from "react";

import { cn } from "@/lib/utils";

export interface ValueNode {
  id: string;
  label: string;
  value?: number | string;
  children?: ValueNode[];
  type?: "root" | "branch" | "leaf";
  status?: "active" | "at_risk" | "achieved";
}

export interface ValueTreeCardProps {
  nodes: ValueNode[];
  title?: string;
  expandedIds?: string[];
  onNodeClick?: (nodeId: string) => void;
  onToggle?: (nodeId: string, expanded: boolean) => void;
  showExpandAll?: boolean;
  className?: string;
}

const statusStyles: Record<string, { dot: string; badge: string }> = {
  active: { dot: "text-[var(--vds-color-primary)]", badge: "bg-[var(--vds-color-primary)]/10 text-[var(--vds-color-primary)]" },
  at_risk: { dot: "text-amber-500", badge: "bg-amber-500/10 text-amber-500" },
  achieved: { dot: "text-green-500", badge: "bg-green-500/10 text-green-500" },
};

function collectAllIds(nodes: ValueNode[]): string[] {
  const ids: string[] = [];
  function walk(n: ValueNode[]) {
    for (const node of n) {
      if (node.children && node.children.length > 0) {
        ids.push(node.id);
        walk(node.children);
      }
    }
  }
  walk(nodes);
  return ids;
}

function flattenVisible(nodes: ValueNode[], expanded: Set<string>): ValueNode[] {
  const result: ValueNode[] = [];
  function walk(n: ValueNode[]) {
    for (const node of n) {
      result.push(node);
      if (node.children && node.children.length > 0 && expanded.has(node.id)) {
        walk(node.children);
      }
    }
  }
  walk(nodes);
  return result;
}

interface TreeNodeProps {
  node: ValueNode;
  depth: number;
  expanded: Set<string>;
  toggle: (id: string) => void;
  onNodeClick?: (nodeId: string) => void;
  focusedId: string | null;
  onFocus: (id: string) => void;
}

const TreeNode: React.FC<TreeNodeProps> = ({
  node,
  depth,
  expanded,
  toggle,
  onNodeClick,
  focusedId,
  onFocus,
}) => {
  const hasChildren = node.children && node.children.length > 0;
  const isExpanded = expanded.has(node.id);
  const isFocused = focusedId === node.id;
  const style = node.status ? statusStyles[node.status] : undefined;

  return (
    // eslint-disable-next-line jsx-a11y/role-has-required-aria-props -- legacy waiver: virtualized tree semantics are parent-managed; expires=2026-09-30; owner=@valueos-frontend
    <li role="treeitem" aria-expanded={hasChildren ? isExpanded : undefined}>
      <div
        className={cn(
          "flex items-center gap-2 py-1.5 px-2 rounded transition-colors cursor-pointer",
          "hover:bg-[var(--vds-color-surface)]/50",
          isFocused && "ring-2 ring-[var(--vds-color-primary)]/30 ring-inset bg-[var(--vds-color-surface)]/30"
        )}
        style={{ paddingLeft: `${depth * 20 + 8}px` }}
        onClick={() => {
          if (hasChildren) toggle(node.id);
          onNodeClick?.(node.id);
        }}
        onFocus={() => onFocus(node.id)}
        // eslint-disable-next-line jsx-a11y/no-noninteractive-tabindex -- legacy waiver: roving tabindex for tree navigation pending full treegrid migration; expires=2026-09-30; owner=@valueos-frontend
        tabIndex={isFocused ? 0 : -1}
        data-node-id={node.id}
      >
        {hasChildren ? (
          isExpanded ? (
            <ChevronDown className="w-4 h-4 text-[var(--vds-color-text-muted)] shrink-0" aria-hidden="true" />
          ) : (
            <ChevronRight className="w-4 h-4 text-[var(--vds-color-text-muted)] shrink-0" aria-hidden="true" />
          )
        ) : (
          <Circle
            className={cn("w-2.5 h-2.5 shrink-0 ml-0.5 mr-0.5", style?.dot ?? "text-[var(--vds-color-text-muted)]")}
            fill="currentColor"
            aria-hidden="true"
          />
        )}
        <span className="text-sm text-[var(--vds-color-text-primary)] truncate flex-1">{node.label}</span>
        {node.value !== undefined && (
          <span className="text-xs text-[var(--vds-color-text-muted)] font-mono shrink-0 tabular-nums">
            {node.value}
          </span>
        )}
        {node.status && (
          <span className={cn("text-[10px] font-medium px-1.5 py-0.5 rounded", style?.badge)}>
            {node.status.replace("_", " ")}
          </span>
        )}
      </div>
      {hasChildren && isExpanded && (
        <ul role="group">
          {node.children!.map((child) => (
            <TreeNode
              key={child.id}
              node={child}
              depth={depth + 1}
              expanded={expanded}
              toggle={toggle}
              onNodeClick={onNodeClick}
              focusedId={focusedId}
              onFocus={onFocus}
            />
          ))}
        </ul>
      )}
    </li>
  );
};

export const ValueTreeCard: React.FC<ValueTreeCardProps> = ({
  nodes,
  title,
  expandedIds,
  onNodeClick,
  onToggle,
  showExpandAll = true,
  className = "",
}) => {
  const [localExpanded, setLocalExpanded] = useState<Set<string>>(
    () => new Set(expandedIds ?? [])
  );
  const [focusedId, setFocusedId] = useState<string | null>(null);
  const treeRef = useRef<HTMLUListElement>(null);

  const allBranchIds = collectAllIds(nodes);
  const allExpanded = allBranchIds.every((id) => localExpanded.has(id));

  const toggle = useCallback(
    (id: string) => {
      setLocalExpanded((prev) => {
        const next = new Set(prev);
        const willExpand = !next.has(id);
        if (willExpand) next.add(id);
        else next.delete(id);
        onToggle?.(id, willExpand);
        return next;
      });
    },
    [onToggle]
  );

  const toggleAll = useCallback(() => {
    if (allExpanded) {
      setLocalExpanded(new Set());
    } else {
      setLocalExpanded(new Set(allBranchIds));
    }
  }, [allExpanded, allBranchIds]);

  // Keyboard navigation: arrow keys to move, Enter/Space to toggle
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      const visible = flattenVisible(nodes, localExpanded);
      const currentIndex = visible.findIndex((n) => n.id === focusedId);
      if (currentIndex === -1 && visible.length > 0) {
        setFocusedId(visible[0]!.id);
        return;
      }

      const current = visible[currentIndex];
      if (!current) return;

      switch (e.key) {
        case "ArrowDown": {
          e.preventDefault();
          const next = visible[currentIndex + 1];
          if (next) {
            setFocusedId(next.id);
            const el = treeRef.current?.querySelector(`[data-node-id="${next.id}"]`) as HTMLElement;
            el?.focus();
          }
          break;
        }
        case "ArrowUp": {
          e.preventDefault();
          const prev = visible[currentIndex - 1];
          if (prev) {
            setFocusedId(prev.id);
            const el = treeRef.current?.querySelector(`[data-node-id="${prev.id}"]`) as HTMLElement;
            el?.focus();
          }
          break;
        }
        case "ArrowRight": {
          e.preventDefault();
          const hasChildren = current.children && current.children.length > 0;
          if (hasChildren && !localExpanded.has(current.id)) {
            toggle(current.id);
          }
          break;
        }
        case "ArrowLeft": {
          e.preventDefault();
          if (localExpanded.has(current.id)) {
            toggle(current.id);
          }
          break;
        }
        case "Enter":
        case " ": {
          e.preventDefault();
          const hasChildren = current.children && current.children.length > 0;
          if (hasChildren) toggle(current.id);
          onNodeClick?.(current.id);
          break;
        }
      }
    },
    [nodes, localExpanded, focusedId, toggle, onNodeClick]
  );

  return (
    <div className={cn("bg-[var(--vds-color-surface)] border border-[var(--vds-color-border)] rounded-lg p-4", className)}>
      {/* Header */}
      {(title || showExpandAll) && (
        <div className="flex items-center justify-between mb-3">
          {title && (
            <h3 className="text-sm font-semibold text-[var(--vds-color-text-primary)]">{title}</h3>
          )}
          {showExpandAll && allBranchIds.length > 0 && (
            <button
              onClick={toggleAll}
              className={cn(
                "inline-flex items-center gap-1 text-xs text-[var(--vds-color-text-muted)] hover:text-[var(--vds-color-text-primary)] transition-colors",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[var(--vds-color-primary)]/30 rounded px-1.5 py-0.5"
              )}
              aria-label={allExpanded ? "Collapse all" : "Expand all"}
            >
              <ChevronsUpDown className="h-3 w-3" aria-hidden="true" />
              {allExpanded ? "Collapse all" : "Expand all"}
            </button>
          )}
        </div>
      )}

      {/* Tree */}
      <ul
        ref={treeRef}
        role="tree"
        aria-label={title ?? "Value tree"}
        aria-multiselectable="false"
        className="space-y-0.5"
        onKeyDown={handleKeyDown}
      >
        {nodes.map((node) => (
          <TreeNode
            key={node.id}
            node={node}
            depth={0}
            expanded={localExpanded}
            toggle={toggle}
            onNodeClick={onNodeClick}
            focusedId={focusedId}
            onFocus={setFocusedId}
          />
        ))}
      </ul>
    </div>
  );
};
