import * as React from "react";
export interface AsyncFeedbackProps { children?: React.ReactNode; status?: string; message?: string; }
export function AsyncFeedback(_props: AsyncFeedbackProps): React.ReactElement {
  return React.createElement("div", null);
}
export function SuccessFeedback(_props: AsyncFeedbackProps): React.ReactElement {
  return React.createElement("div", null);
}
export function ErrorFeedback(_props: AsyncFeedbackProps): React.ReactElement {
  return React.createElement("div", null);
}
export function SettingsErrorBoundary({ children }: { children?: React.ReactNode }): React.ReactElement {
  return React.createElement(React.Fragment, null, children);
}
export interface AsyncState<T = unknown> { state: { status: "idle" | "loading" | "success" | "error"; data?: T; error?: string }; execute: (fn: () => Promise<T>) => Promise<void>; reset: () => void; }
export function useAsyncState<T = unknown>(): AsyncState<T> {
  const [status, setStatus] = React.useState<"idle" | "loading" | "success" | "error">("idle");
  const [data, setData] = React.useState<T | undefined>(undefined);
  const [error, setError] = React.useState<string | undefined>(undefined);
  return {
    state: { status, data, error },
    execute: async (fn) => { setStatus("loading"); try { setData(await fn()); setStatus("success"); } catch (e) { setError(String(e)); setStatus("error"); } },
    reset: () => { setStatus("idle"); setData(undefined); setError(undefined); },
  };
}

/**
 * StepperWizard
 *
 * Multi-step wizard with keyboard navigation, step validation states,
 * and consistent visual language.
 *
 * UX Principles:
 * - POLA: consistent step indicator styling, predictable Back/Next pattern
 * - Golden Thread: carries context forward, one task per step
 * - Accessibility: arrow key navigation, aria-current, focus management
 * - Error Prevention: disables Next when step is invalid, shows validation state
 */

import { Check, ChevronLeft, ChevronRight } from "lucide-react";
import React, { useCallback, useEffect, useRef } from "react";

import { cn } from "@/lib/utils";

export type StepValidation = "valid" | "invalid" | "pending";

export interface Step {
  label: string;
  description?: string;
  content: React.ReactNode;
  validation?: StepValidation;
  optional?: boolean;
}

export interface StepperWizardProps {
  steps: Step[];
  currentStep: number;
  onNext: () => void;
  onBack: () => void;
  onStepClick?: (index: number) => void;
  canNext: boolean;
  canBack: boolean;
  nextLabel?: string;
  backLabel?: string;
  finishLabel?: string;
  className?: string;
}

const StepperWizard: React.FC<StepperWizardProps> = ({
  steps,
  currentStep,
  onNext,
  onBack,
  onStepClick,
  canNext,
  canBack,
  nextLabel,
  backLabel = "Back",
  finishLabel = "Finish",
  className,
}) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const isLastStep = currentStep === steps.length - 1;
  const currentStepData = steps[currentStep];

  // Focus content area on step change for screen readers
  useEffect(() => {
    contentRef.current?.focus();
  }, [currentStep]);

  // Keyboard navigation
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === "ArrowRight" && canNext) {
        e.preventDefault();
        onNext();
      } else if (e.key === "ArrowLeft" && canBack) {
        e.preventDefault();
        onBack();
      }
    },
    [canNext, canBack, onNext, onBack]
  );

  return (
    <div
      className={cn("max-w-2xl mx-auto", className)}
      onKeyDown={handleKeyDown}
    >
      {/* Step indicators */}
      <nav aria-label="Wizard steps" className="mb-8">
        <ol className="flex items-center">
          {steps.map((step, index) => {
            const isCompleted = index < currentStep;
            const isCurrent = index === currentStep;
            const isClickable = onStepClick && index <= currentStep;
            const validation = step.validation ?? (isCompleted ? "valid" : "pending");

            return (
              <li
                key={index}
                className={cn("flex items-center", index < steps.length - 1 && "flex-1")}
              >
                {/* Step circle */}
                <button
                  type="button"
                  onClick={() => isClickable && onStepClick?.(index)}
                  disabled={!isClickable}
                  className={cn(
                    "flex flex-col items-center gap-1.5 group",
                    isClickable && "cursor-pointer",
                    !isClickable && "cursor-default"
                  )}
                  aria-current={isCurrent ? "step" : undefined}
                  aria-label={`Step ${index + 1}: ${step.label}${isCompleted ? " (completed)" : isCurrent ? " (current)" : ""}`}
                >
                  <div
                    className={cn(
                      "flex h-9 w-9 items-center justify-center rounded-full border-2 text-sm font-medium transition-all duration-200",
                      isCompleted
                        ? "border-green-500 bg-green-500 text-white"
                        : isCurrent
                          ? "border-[var(--vds-color-primary)] bg-[var(--vds-color-primary)] text-white shadow-sm"
                          : "border-[var(--vds-color-border)] bg-[var(--vds-color-surface)] text-[var(--vds-color-text-muted)]",
                      isClickable && !isCurrent && "group-hover:border-[var(--vds-color-primary)]/50"
                    )}
                  >
                    {isCompleted ? (
                      <Check className="h-4 w-4" aria-hidden="true" />
                    ) : (
                      <span>{index + 1}</span>
                    )}
                  </div>
                  <span
                    className={cn(
                      "text-xs font-medium text-center max-w-[90px] leading-tight",
                      isCurrent
                        ? "text-[var(--vds-color-primary)]"
                        : isCompleted
                          ? "text-[var(--vds-color-text-primary)]"
                          : "text-[var(--vds-color-text-muted)]"
                    )}
                  >
                    {step.label}
                  </span>
                </button>

                {/* Connector */}
                {index < steps.length - 1 && (
                  <div className="flex-1 mx-3 mt-[-1.25rem]">
                    <div
                      className={cn(
                        "h-0.5 w-full rounded-full transition-all duration-300",
                        isCompleted ? "bg-green-500" : "bg-[var(--vds-color-border)]"
                      )}
                    />
                  </div>
                )}
              </li>
            );
          })}
        </ol>
      </nav>

      {/* Step description */}
      {currentStepData?.description && (
        <p className="text-sm text-[var(--vds-color-text-muted)] mb-4 text-center">
          {currentStepData.description}
        </p>
      )}

      {/* Step content */}
      <div
        ref={contentRef}
        className="mb-8 focus:outline-none focus-visible:ring-2 focus-visible:ring-[var(--vds-color-primary)]/30 rounded-lg"
        tabIndex={-1}
        role="region"
        aria-label={`Step ${currentStep + 1}: ${currentStepData?.label ?? "Step"}`}
      >
        {currentStepData?.content ?? (
          <div className="text-center text-[var(--vds-color-text-muted)] py-8">
            Invalid step
          </div>
        )}
      </div>

      {/* Validation feedback */}
      {currentStepData?.validation === "invalid" && (
        <p className="text-xs text-red-500 mb-3 text-center" role="alert">
          Please complete all required fields before continuing.
        </p>
      )}

      {/* Navigation */}
      <div className="flex items-center justify-between">
        <button
          type="button"
          onClick={onBack}
          disabled={!canBack}
          className={cn(
            "inline-flex items-center gap-2 px-4 py-2.5 text-sm font-medium rounded-md transition-colors",
            "border border-[var(--vds-color-border)] text-[var(--vds-color-text-primary)] hover:bg-[var(--vds-color-surface)]",
            "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[var(--vds-color-primary)]/30",
            "disabled:opacity-50 disabled:pointer-events-none"
          )}
        >
          <ChevronLeft className="h-4 w-4" aria-hidden="true" />
          {backLabel}
        </button>

        {/* Step counter */}
        <span className="text-xs text-[var(--vds-color-text-muted)] tabular-nums">
          {currentStep + 1} of {steps.length}
        </span>

        <button
          type="button"
          onClick={onNext}
          disabled={!canNext}
          className={cn(
            "inline-flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-md transition-colors",
            "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[var(--vds-color-primary)]/30",
            "disabled:opacity-50 disabled:pointer-events-none",
            isLastStep
              ? "bg-green-500 text-white hover:bg-green-600"
              : "bg-[var(--vds-color-primary)] text-white hover:brightness-110"
          )}
        >
          {isLastStep ? finishLabel : (nextLabel ?? "Next")}
          {!isLastStep && <ChevronRight className="h-4 w-4" aria-hidden="true" />}
          {isLastStep && <Check className="h-4 w-4" aria-hidden="true" />}
        </button>
      </div>
    </div>
  );
};

StepperWizard.displayName = "StepperWizard";

export default StepperWizard;

// apps/ValyntApp/src/components/TracePanel.tsx
import { CheckCircle, ChevronDown, ChevronRight, Link2 } from "lucide-react";
import React, { useCallback, useState } from "react";

import { cn } from "@/lib/utils";

interface TraceStep {
  step: string;
  citation?: string;
  confidence?: number;
  details?: string;
}

interface TracePanelProps {
  steps: TraceStep[];
  title?: string;
  defaultExpanded?: boolean;
}

const containerClasses = "bg-[var(--vds-color-surface)] border border-[var(--vds-color-border)] rounded-lg p-4";
const titleClasses = "text-lg font-semibold text-[var(--vds-color-text-primary)] mb-4";
const stepContainerClasses = "space-y-2";
const stepClasses = "flex items-start gap-3 p-2 rounded-lg transition-colors hover:bg-[var(--vds-color-surface-2)]/50";
const stepNumberClasses = "flex-shrink-0 w-6 h-6 rounded-full bg-[var(--vds-color-primary)]/10 text-[var(--vds-color-primary)] flex items-center justify-center text-xs font-medium";
const stepContentClasses = "flex-1 min-w-0";
const stepTextClasses = "text-sm text-[var(--vds-color-text-primary)]";
const citationClasses = "text-xs text-[var(--vds-color-text-muted)] mt-1 flex items-center gap-1";
const confidenceClasses = "inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium mt-1";
const expandButtonClasses = "p-1 rounded hover:bg-[var(--vds-color-surface-2)] transition-colors text-[var(--vds-color-text-muted)]";

const getConfidenceStyle = (confidence: number): string => {
  if (confidence >= 0.8) return "bg-green-500/10 text-green-500";
  if (confidence >= 0.5) return "bg-amber-500/10 text-amber-500";
  return "bg-red-500/10 text-red-500";
};

const TracePanel: React.FC<TracePanelProps> = ({ steps, title = "Reasoning Trace", defaultExpanded = false }) => {
  const [expandedSteps, setExpandedSteps] = useState<Set<number>>(defaultExpanded ? new Set(steps.map((_, i) => i)) : new Set());

  const toggleStep = useCallback((index: number) => {
    setExpandedSteps(prev => {
      const next = new Set(prev);
      if (next.has(index)) {
        next.delete(index);
      } else {
        next.add(index);
      }
      return next;
    });
  }, []);

  return (
    <div className={containerClasses}>
      <h3 className={titleClasses}>{title}</h3>
      <div className={stepContainerClasses}>
        {steps.map((step, index) => {
          const isExpanded = expandedSteps.has(index);

          return (
            <div key={index} className={stepClasses}>
              <div className={stepNumberClasses}>
                {index + 1}
              </div>
              <div className={stepContentClasses}>
                <div className="flex items-start justify-between gap-2">
                  <p className={stepTextClasses}>{step.step}</p>
                  {step.details && (
                    <button
                      onClick={() => toggleStep(index)}
                      className={expandButtonClasses}
                      aria-label={isExpanded ? "Collapse details" : "Expand details"}
                      aria-expanded={isExpanded}
                    >
                      {isExpanded ? (
                        <ChevronDown className="w-4 h-4" aria-hidden="true" />
                      ) : (
                        <ChevronRight className="w-4 h-4" aria-hidden="true" />
                      )}
                    </button>
                  )}
                </div>

                {step.citation && (
                  <p className={citationClasses}>
                    <Link2 className="w-3 h-3" aria-hidden="true" />
                    Citation: {step.citation}
                  </p>
                )}

                {step.confidence !== undefined && (
                  <span className={cn(confidenceClasses, getConfidenceStyle(step.confidence))}>
                    {(step.confidence * 100).toFixed(0)}% confidence
                  </span>
                )}

                {isExpanded && step.details && (
                  <div className="mt-2 p-2 bg-[var(--vds-color-surface-2)] rounded text-xs text-[var(--vds-color-text-secondary)]">
                    {step.details}
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

TracePanel.displayName = "TracePanel";

export default TracePanel;

