/**
 * HumanCheckpoint
 *
 * Decision gate in the workflow where a human must approve or reject.
 * Shows context summary, clear CTA hierarchy, and optional confirmation.
 *
 * UX Principles:
 * - One Primary Task per Screen: approve or reject, nothing else
 * - Contextual Continuity: carries forward summary from previous steps
 * - Error Prevention: confirmation dialog before destructive reject
 * - 5-Second Rule: immediately clear what action is needed
 */

import { AlertTriangle, CheckCircle2, Clock, User, XCircle } from "lucide-react";
import React, { useState } from "react";

import { cn } from "@/lib/utils";

export interface CheckpointSummaryItem {
  label: string;
  value: string;
}

export interface HumanCheckpointProps {
  title?: string;
  description?: string;
  summary?: CheckpointSummaryItem[];
  assignee?: string;
  deadline?: string;
  confidence?: number;
  onApprove?: () => void;
  onReject?: (reason?: string) => void;
  approveLabel?: string;
  rejectLabel?: string;
  loading?: boolean;
  className?: string;
}

export function HumanCheckpoint({
  title = "Review Required",
  description,
  summary = [],
  assignee,
  deadline,
  confidence,
  onApprove,
  onReject,
  approveLabel = "Approve",
  rejectLabel = "Reject",
  loading = false,
  className,
}: HumanCheckpointProps) {
  const [rejectConfirm, setRejectConfirm] = useState(false);
  const [rejectReason, setRejectReason] = useState("");

  const handleReject = () => {
    onReject?.(rejectReason || undefined);
    setRejectConfirm(false);
    setRejectReason("");
  };

  return (
    <div
      className={cn(
        "rounded-lg border-2 border-primary/30 bg-primary/5 p-6",
        className
      )}
      role="region"
      aria-label={title}
    >
      {/* Header: What needs to happen */}
      <div className="flex items-start gap-3 mb-4">
        <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-primary/10">
          <User className="h-5 w-5 text-primary" />
        </div>
        <div className="flex-1 min-w-0">
          <h3 className="text-base font-semibold text-foreground">{title}</h3>
          {description && (
            <p className="text-sm text-muted-foreground mt-1">{description}</p>
          )}
        </div>
      </div>

      {/* Meta: who and when */}
      {(assignee || deadline || confidence !== undefined) && (
        <div className="flex flex-wrap items-center gap-4 mb-4 text-xs text-muted-foreground">
          {assignee && (
            <span className="inline-flex items-center gap-1">
              <User className="h-3 w-3" />
              {assignee}
            </span>
          )}
          {deadline && (
            <span className="inline-flex items-center gap-1">
              <Clock className="h-3 w-3" />
              Due: {deadline}
            </span>
          )}
          {confidence !== undefined && (
            <span className="inline-flex items-center gap-1">
              <span
                className={cn(
                  "h-2 w-2 rounded-full",
                  confidence >= 0.7 ? "bg-success" : confidence >= 0.4 ? "bg-warning" : "bg-destructive"
                )}
              />
              Confidence: {Math.round(confidence * 100)}%
            </span>
          )}
        </div>
      )}

      {/* Context summary: what was done so far */}
      {summary.length > 0 && (
        <div className="rounded-md border border-border bg-card p-4 mb-5">
          <h4 className="text-xs font-medium text-muted-foreground uppercase tracking-wider mb-2">
            Summary
          </h4>
          <dl className="grid grid-cols-2 gap-x-4 gap-y-2">
            {summary.map((item) => (
              <div key={item.label}>
                <dt className="text-xs text-muted-foreground">{item.label}</dt>
                <dd className="text-sm font-medium text-foreground">{item.value}</dd>
              </div>
            ))}
          </dl>
        </div>
      )}

      {/* Actions: clear CTA hierarchy */}
      {!rejectConfirm ? (
        <div className="flex items-center gap-3">
          {onApprove && (
            <button
              onClick={onApprove}
              disabled={loading}
              className={cn(
                "inline-flex items-center gap-2 px-5 py-2.5 text-sm font-medium rounded-md transition-colors",
                "bg-success text-success-foreground hover:bg-success/90 active:bg-success/80",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                "disabled:opacity-50 disabled:pointer-events-none"
              )}
            >
              <CheckCircle2 className="h-4 w-4" />
              {approveLabel}
            </button>
          )}
          {onReject && (
            <button
              onClick={() => setRejectConfirm(true)}
              disabled={loading}
              className={cn(
                "inline-flex items-center gap-2 px-4 py-2.5 text-sm font-medium rounded-md transition-colors",
                "border border-destructive/30 text-destructive hover:bg-destructive/10",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                "disabled:opacity-50 disabled:pointer-events-none"
              )}
            >
              <XCircle className="h-4 w-4" />
              {rejectLabel}
            </button>
          )}
        </div>
      ) : (
        <div className="space-y-3">
          <div className="flex items-center gap-2 text-sm text-destructive">
            <AlertTriangle className="h-4 w-4 shrink-0" />
            <span className="font-medium">This will send the case back for revision.</span>
          </div>
          <textarea
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
            placeholder="Reason for rejection (optional but recommended)..."
            className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring resize-none"
            rows={2}
            aria-label="Rejection reason"
          />
          <div className="flex items-center gap-2">
            <button
              onClick={handleReject}
              className="inline-flex items-center gap-1.5 px-4 py-2 text-sm font-medium bg-destructive text-destructive-foreground rounded-md hover:bg-destructive/90 transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
            >
              Confirm Rejection
            </button>
            <button
              onClick={() => { setRejectConfirm(false); setRejectReason(""); }}
              className="px-4 py-2 text-sm font-medium text-muted-foreground hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring rounded-md"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default HumanCheckpoint;

/**
 * WorkflowStatusBar
 *
 * Displays the current workflow phase with animated progress,
 * step indicators, and system status feedback.
 *
 * UX Principles:
 * - Visual Hierarchy: progress bar along F-pattern scan line
 * - Immediate Feedback: animated transitions between states, pulsing for active steps
 * - Accessibility: role="progressbar" with aria attributes, keyboard navigable steps
 */

import { CheckCircle2, Circle, Loader2, XCircle } from "lucide-react";
import React from "react";

import { cn } from "@/lib/utils";

export interface WorkflowStep {
  id: string;
  label: string;
  description?: string;
}

export type StepStatus = "pending" | "active" | "completed" | "failed" | "skipped";

export interface WorkflowStatusBarProps {
  steps?: WorkflowStep[];
  currentStepId?: string;
  stepStatuses?: Record<string, StepStatus>;
  status?: string;
  progress?: number;
  message?: string;
  className?: string;
}

const statusIcons: Record<StepStatus, React.FC<{ className?: string }>> = {
  pending: Circle,
  active: Loader2,
  completed: CheckCircle2,
  failed: XCircle,
  skipped: Circle,
};

const statusStyles: Record<StepStatus, string> = {
  pending: "text-[var(--vds-color-text-muted)] border-[var(--vds-color-border)]",
  active: "text-[var(--vds-color-primary)] border-[var(--vds-color-primary)]",
  completed: "text-green-500 border-green-500",
  failed: "text-red-500 border-red-500",
  skipped: "text-[var(--vds-color-text-muted)]/50 border-[var(--vds-color-border)]/50",
};

const connectorStyles: Record<string, string> = {
  completed: "bg-green-500",
  pending: "bg-[var(--vds-color-border)]",
};

export function WorkflowStatusBar({
  steps = [],
  currentStepId,
  stepStatuses = {},
  status,
  progress,
  message,
  className,
}: WorkflowStatusBarProps) {
  const resolvedProgress =
    progress ??
    (steps.length > 0
      ? (Object.values(stepStatuses).filter((s) => s === "completed").length /
        steps.length) *
      100
      : 0);

  const getStepStatus = (stepId: string, index: number): StepStatus => {
    if (stepStatuses[stepId]) return stepStatuses[stepId]!;
    if (!currentStepId) return "pending";
    const currentIndex = steps.findIndex((s) => s.id === currentStepId);
    if (index < currentIndex) return "completed";
    if (index === currentIndex) return "active";
    return "pending";
  };

  // Minimal mode: no steps defined, just a progress bar
  if (steps.length === 0) {
    return (
      <div
        className={cn("w-full", className)}
        role="progressbar"
        aria-valuenow={Math.round(resolvedProgress)}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={status ?? "Workflow progress"}
      >
        <div className="flex items-center justify-between mb-2">
          {status && (
            <span className="text-sm font-medium text-[var(--vds-color-text-primary)]">{status}</span>
          )}
          <span className="text-xs text-[var(--vds-color-text-muted)] tabular-nums">
            {Math.round(resolvedProgress)}%
          </span>
        </div>
        <div className="h-2 w-full overflow-hidden rounded-full bg-[var(--vds-color-surface)]">
          <div
            className="h-full rounded-full bg-[var(--vds-color-primary)] transition-all duration-500 ease-out"
            style={{ width: `${resolvedProgress}%` }}
          />
        </div>
        {message && (
          <p className="mt-1.5 text-xs text-[var(--vds-color-text-muted)]">{message}</p>
        )}
      </div>
    );
  }

  return (
    <div
      className={cn("w-full", className)}
      role="progressbar"
      aria-valuenow={Math.round(resolvedProgress)}
      aria-valuemin={0}
      aria-valuemax={100}
      aria-label={status ?? "Workflow progress"}
    >
      {(status || message) && (
        <div className="flex items-center justify-between mb-4">
          {status && (
            <span className="text-sm font-medium text-[var(--vds-color-text-primary)]">{status}</span>
          )}
          {message && (
            <span className="text-xs text-[var(--vds-color-text-muted)]">{message}</span>
          )}
        </div>
      )}

      <nav aria-label="Workflow steps">
        <ol className="flex items-center w-full">
          {steps.map((step, index) => {
            const stepStatus = getStepStatus(step.id, index);
            const Icon = statusIcons[stepStatus];
            const isLast = index === steps.length - 1;

            return (
              <li
                key={step.id}
                className={cn("flex items-center", !isLast && "flex-1")}
              >
                <div className="flex flex-col items-center gap-1.5 min-w-0">
                  <div
                    className={cn(
                      "flex h-8 w-8 shrink-0 items-center justify-center rounded-full border-2 transition-all duration-300",
                      statusStyles[stepStatus],
                      stepStatus === "completed" && "bg-green-500/10",
                      stepStatus === "active" && "bg-[var(--vds-color-primary)]/10",
                      stepStatus === "failed" && "bg-red-500/10"
                    )}
                    aria-current={stepStatus === "active" ? "step" : undefined}
                  >
                    <Icon
                      className={cn(
                        "h-4 w-4",
                        stepStatus === "active" && "animate-spin"
                      )}
                      aria-hidden="true"
                    />
                  </div>
                  <span
                    className={cn(
                      "text-xs font-medium text-center max-w-[80px] truncate",
                      stepStatus === "active"
                        ? "text-[var(--vds-color-primary)]"
                        : stepStatus === "completed"
                          ? "text-green-500"
                          : stepStatus === "failed"
                            ? "text-red-500"
                            : "text-[var(--vds-color-text-muted)]"
                    )}
                    title={step.description ?? step.label}
                  >
                    {step.label}
                  </span>
                </div>

                {!isLast && (
                  <div className="flex-1 mx-2 mt-[-1.25rem]">
                    <div
                      className={cn(
                        "h-0.5 w-full rounded-full transition-all duration-500",
                        connectorStyles[stepStatus === "completed" ? "completed" : "pending"]
                      )}
                    />
                  </div>
                )}
              </li>
            );
          })}
        </ol>
      </nav>

      <div className="mt-4 h-1.5 w-full overflow-hidden rounded-full bg-[var(--vds-color-surface)]">
        <div
          className="h-full rounded-full bg-[var(--vds-color-primary)] transition-all duration-500 ease-out"
          style={{ width: `${resolvedProgress}%` }}
        />
      </div>
    </div>
  );
}

