/**
 * Canvas Layer: CanvasHost
 * Dynamic host for SDUI-driven widgets
 * Implements the DynamicRenderer pattern for server-driven UI
 */

import { Building2 } from "lucide-react";
import React, { Component, ComponentType, ErrorInfo, LazyExoticComponent, ReactNode, Suspense } from "react";

// Widget type registry - maps component_type to eagerly or lazily loaded components
type RegisteredWidget = ComponentType<WidgetProps> | LazyExoticComponent<ComponentType<WidgetProps>>;
const widgetRegistry: Record<string, RegisteredWidget> = {};

export interface WidgetProps {
  id: string;
  data?: Record<string, unknown>;
  onAction?: (action: string, payload?: unknown) => Promise<void> | void;
}

export interface SDUIWidget {
  id: string;
  componentType: string;
  props?: Record<string, unknown>;
  children?: SDUIWidget[];
}

interface CanvasHostProps {
  widgets: SDUIWidget[];
  onWidgetAction?: (widgetId: string, action: string, payload?: unknown) => void;
  onWidgetError?: (widgetId: string, componentType: string, error: Error, errorInfo: ErrorInfo) => void;
  emptyState?: React.ReactNode;
  className?: string;
}

// Register built-in widgets
function registerWidget(type: string, component: RegisteredWidget) {
  widgetRegistry[type] = component;
}

// Lazy-load built-in widgets to keep bundle split
const AgentResponseCard = React.lazy(() => import("./widgets/AgentResponseCard"));
const ChatInputWidget = React.lazy(() => import("./widgets/ChatInput"));

// V1 Surface Widgets
const StakeholderMap = React.lazy(() => import("./widgets/StakeholderMap"));
const GapResolution = React.lazy(() => import("./widgets/GapResolution"));
const HypothesisCard = React.lazy(() => import("./widgets/HypothesisCard"));
const AssumptionRegister = React.lazy(() => import("./widgets/AssumptionRegister"));
const ScenarioComparison = React.lazy(() => import("./widgets/ScenarioComparison"));
const SensitivityTornado = React.lazy(() => import("./widgets/SensitivityTornado"));
const ReadinessGauge = React.lazy(() => import("./widgets/ReadinessGauge"));
const EvidenceGapList = React.lazy(() => import("./widgets/EvidenceGapList"));
const ArtifactPreview = React.lazy(() => import("./widgets/ArtifactPreview"));
const InlineEditor = React.lazy(() => import("./widgets/InlineEditor"));
const KPITargetCard = React.lazy(() => import("./widgets/KPITargetCard"));
const CheckpointTimeline = React.lazy(() => import("./widgets/CheckpointTimeline"));
const UsageMeter = React.lazy(() => import("./widgets/UsageMeter"));
const PlanComparison = React.lazy(() => import("./widgets/PlanComparison"));

// Register built-in SDUI widget types
registerWidget("agent-response", AgentResponseCard);
registerWidget("chat-input", ChatInputWidget);

// Register V1 Surface Widgets
registerWidget("stakeholder-map", StakeholderMap);
registerWidget("gap-resolution", GapResolution);
registerWidget("hypothesis-card", HypothesisCard);
registerWidget("assumption-register", AssumptionRegister);
registerWidget("scenario-comparison", ScenarioComparison);
registerWidget("sensitivity-tornado", SensitivityTornado);
registerWidget("readiness-gauge", ReadinessGauge);
registerWidget("evidence-gap-list", EvidenceGapList);
registerWidget("artifact-preview", ArtifactPreview);
registerWidget("inline-editor", InlineEditor);
registerWidget("kpi-target-card", KPITargetCard);
registerWidget("checkpoint-timeline", CheckpointTimeline);
registerWidget("usage-meter", UsageMeter);
registerWidget("plan-comparison", PlanComparison);

// Per-widget error boundary to isolate failures (spec 3.2.1)
interface WidgetErrorBoundaryProps {
  widgetId: string;
  componentType: string;
  onError?: (widgetId: string, componentType: string, error: Error, errorInfo: ErrorInfo) => void;
  children: ReactNode;
}

interface WidgetErrorBoundaryState {
  hasError: boolean;
}

class WidgetErrorBoundary extends Component<WidgetErrorBoundaryProps, WidgetErrorBoundaryState> {
  constructor(props: WidgetErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(_: Error): Partial<WidgetErrorBoundaryState> {
    return { hasError: true };
  }

  override componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    logger.error(
      `[CanvasHost] Widget "${this.props.componentType}" (${this.props.widgetId}) crashed:`,
      error.message,
      errorInfo.componentStack,
    );

    this.props.onError?.(this.props.widgetId, this.props.componentType, error, errorInfo);
  }

  override render() {
    if (this.state.hasError) {
      return (
        <div
          className="rounded-xl border border-destructive/30 bg-destructive/5 p-6 text-center"
          role="alert"
        >
          <p className="text-sm font-medium text-destructive mb-1">
            Widget failed to render
          </p>
          <p className="text-xs text-muted-foreground">
            {this.props.componentType} ({this.props.widgetId})
          </p>
          <button
            onClick={() => this.setState({ hasError: false })}
            className="mt-3 rounded-lg border border-border px-3 py-1.5 text-xs font-medium text-foreground hover:bg-muted transition-colors"
          >
            Retry
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

// Widget loading fallback
function WidgetSkeleton() {
  return (
    <div className="animate-pulse rounded-xl border border-border bg-card p-6">
      <div className="h-4 w-1/3 rounded bg-muted" />
      <div className="mt-4 space-y-2">
        <div className="h-3 w-full rounded bg-muted" />
        <div className="h-3 w-2/3 rounded bg-muted" />
      </div>
    </div>
  );
}

// Unknown widget fallback
function UnknownWidget({ componentType }: { componentType: string }) {
  return (
    <div className="rounded-xl border border-dashed border-border bg-card/50 p-6 text-center">
      <p className="text-sm text-muted-foreground">
        Unknown widget type: <code className="text-primary">{componentType}</code>
      </p>
    </div>
  );
}

// Default empty state
function DefaultEmptyState() {
  return (
    <div className="flex h-full items-center justify-center">
      <div className="text-center">
        <Building2 className="mx-auto h-12 w-12 text-muted-foreground/50" />
        <h2 className="mt-4 text-lg font-medium">No case selected</h2>
        <p className="mt-1 text-sm text-muted-foreground">
          Select a case from the sidebar or create a new one
        </p>
      </div>
    </div>
  );
}

export function CanvasHost({
  widgets,
  onWidgetAction,
  onWidgetError,
  emptyState,
  className = "",
}: CanvasHostProps) {
  if (widgets.length === 0) {
    return <>{emptyState ?? <DefaultEmptyState />}</>;
  }

  const renderWidget = (widget: SDUIWidget): React.ReactNode => {
    const Widget = widgetRegistry[widget.componentType];

    if (!Widget) {
      return <UnknownWidget key={widget.id} componentType={widget.componentType} />;
    }

    const handleAction = async (action: string, payload?: unknown) => {
      onWidgetAction?.(widget.id, action, payload);
    };

    return (
      <WidgetErrorBoundary
        key={widget.id}
        widgetId={widget.id}
        componentType={widget.componentType}
        onError={onWidgetError}
      >
        <Suspense fallback={<WidgetSkeleton />}>
          <Widget
            id={widget.id}
            data={widget.props}
            onAction={handleAction}
          />
        </Suspense>
      </WidgetErrorBoundary>
    );
  };

  return (
    <div className={`space-y-6 ${className}`}>
      {widgets.map(renderWidget)}
    </div>
  );
}

// Export registration function for external widgets
export { registerWidget };

/**
 * ArtifactPreview Widget
 *
 * Formatted rendering of artifact content with data-claim-id attributes on financial figures for click-to-trace.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.4
 */

import { Clock, FileText, User } from "lucide-react";
import React from "react";

import { WidgetProps } from "../CanvasHost";

export interface Artifact {
  id: string;
  type: "executive-memo" | "cfo-recommendation" | "customer-narrative" | "internal-case";
  status: "draft" | "ready" | "archived";
  title: string;
  content: string;
  claimIds: string[];
  generatedAt: string;
  modifiedAt?: string;
  modifiedBy?: string;
  readinessAtGeneration: number;
}

export interface ArtifactPreviewData {
  artifact: Artifact;
  onClaimClick?: (claimId: string) => void;
}

export function ArtifactPreview({ data, onAction }: WidgetProps) {
  const widgetData = data as unknown as ArtifactPreviewData;
  const artifact = widgetData.artifact;

  if (!artifact) {
    return (
      <div className="rounded-xl border bg-card p-6 text-center text-muted-foreground">
        <FileText className="w-12 h-12 mx-auto mb-3 opacity-50" />
        <p>No artifact selected</p>
      </div>
    );
  }

  const getTypeBadge = (type: string) => {
    switch (type) {
      case "executive-memo":
        return "bg-purple-100 text-purple-800 border-purple-200";
      case "cfo-recommendation":
        return "bg-blue-100 text-blue-800 border-blue-200";
      case "customer-narrative":
        return "bg-green-100 text-green-800 border-green-200";
      case "internal-case":
        return "bg-gray-100 text-gray-800 border-gray-200";
      default:
        return "bg-gray-100 text-gray-800 border-gray-200";
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "ready":
        return "bg-green-100 text-green-800";
      case "draft":
        return "bg-amber-100 text-amber-800";
      case "archived":
        return "bg-gray-100 text-gray-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  // Parse content to identify financial figures (simple regex-based approach)
  const renderContent = (content: string) => {
    // Guard against empty claimIds
    if (!artifact.claimIds?.length) {
      return content.split("\n").map((line, index) => (
        <p key={index} className="mb-2">{line}</p>
      ));
    }

    // Split by lines and render with claim IDs on potential financial figures
    return content.split("\n").map((line, index) => {
      // Simple heuristic: lines containing $ or % or numbers might have financial figures
      const hasFinancialFigure = /\$[\d,]+|[\d]+%?/.test(line);
      const claimId = hasFinancialFigure ? artifact.claimIds[index % artifact.claimIds.length] : null;

      return (
        <p key={index} className="mb-2">
          {claimId ? (
            <span
              data-claim-id={claimId}
              className="cursor-pointer hover:bg-primary/10 rounded px-1 transition-colors"
              onClick={() => onAction?.("showProvenance", { claimId })}
              title="Click to trace provenance"
            >
              {line}
            </span>
          ) : (
            line
          )}
        </p>
      );
    });
  };

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-start justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-primary/10 rounded-lg">
            <FileText className="w-5 h-5 text-primary" />
          </div>
          <div>
            <h3 className="font-semibold text-lg">{artifact.title}</h3>
            <div className="flex items-center gap-2 mt-1">
              <span
                className={`text-xs px-2 py-0.5 rounded-full border ${getTypeBadge(
                  artifact.type
                )}`}
              >
                {artifact.type.replace("-", " ")}
              </span>
              <span className={`text-xs px-2 py-0.5 rounded-full ${getStatusBadge(artifact.status)}`}>
                {artifact.status}
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Metadata */}
      <div className="flex items-center gap-4 mb-4 text-sm text-muted-foreground">
        <div className="flex items-center gap-1">
          <Clock className="w-4 h-4" />
          <span>Generated {new Date(artifact.generatedAt).toLocaleDateString()}</span>
        </div>
        {artifact.modifiedAt && (
          <div className="flex items-center gap-1">
            <User className="w-4 h-4" />
            <span>
              Modified {new Date(artifact.modifiedAt).toLocaleDateString()}
              {artifact.modifiedBy && ` by ${artifact.modifiedBy}`}
            </span>
          </div>
        )}
      </div>

      {/* Readiness watermark */}
      {(artifact.status === "draft" || artifact.readinessAtGeneration < 0.8) && (
        <div className="mb-4 p-3 bg-amber-50 border border-amber-200 rounded-lg">
          <p className="text-sm text-amber-800">
            <strong>DRAFT</strong> — Generated at {Math.round(artifact.readinessAtGeneration * 100)}%
            readiness. Review recommended before finalization.
          </p>
        </div>
      )}

      {/* Content */}
      <div className="prose prose-sm max-w-none text-foreground">
        {renderContent(artifact.content)}
      </div>

      {/* Claim IDs legend */}
      {artifact.claimIds?.length > 0 && (
        <div className="mt-6 pt-4 border-t">
          <p className="text-xs text-muted-foreground mb-2">
            Click highlighted text to trace provenance
          </p>
          <div className="flex flex-wrap gap-2">
            {artifact.claimIds.slice(0, 5).map((claimId) => (
              <span key={claimId} className="text-xs px-2 py-1 bg-muted rounded">
                {claimId.slice(0, 8)}...
              </span>
            ))}
            {artifact.claimIds.length > 5 && (
              <span className="text-xs px-2 py-1 bg-muted rounded">
                +{artifact.claimIds.length - 5} more
              </span>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default ArtifactPreview;

/**
 * AssumptionRegister Widget
 *
 * Sortable table with: name, value, unit, source badge, confidence badge, benchmark reference, unsupported flag highlight.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.2
 */

import { ConfidenceBadge } from "@valueos/components/components/ConfidenceBadge";
import { SourceBadge, SourceType } from "@valueos/components/components/SourceBadge";
import { AlertTriangle, ArrowDown, ArrowUp, ArrowUpDown } from "lucide-react";
import React, { useState } from "react";

import { WidgetProps } from "../CanvasHost";

type SortField = "name" | "value" | "confidence" | "source";
type SortDirection = "asc" | "desc";

export interface Assumption {
  id: string;
  name: string;
  value: number;
  unit: string;
  source: SourceType;
  confidenceScore: number;
  benchmarkReference?: string;
  unsupported: boolean;
  plausibility: "plausible" | "aggressive" | "weakly-supported";
}

export interface AssumptionRegisterData {
  assumptions: Assumption[];
}

export function AssumptionRegister({ data, onAction }: WidgetProps) {
  const widgetData = data as unknown as AssumptionRegisterData;
  const assumptions = widgetData.assumptions ?? [];

  const [sortField, setSortField] = useState<SortField>("name");
  const [sortDirection, setSortDirection] = useState<SortDirection>("asc");
  const [filterSource, setFilterSource] = useState<string>("all");

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortDirection(sortDirection === "asc" ? "desc" : "asc");
    } else {
      setSortField(field);
      setSortDirection("asc");
    }
  };

  const sortedAssumptions = [...assumptions]
    .filter((a) => filterSource === "all" || a.source === filterSource)
    .sort((a, b) => {
      let comparison = 0;
      switch (sortField) {
        case "name":
          comparison = a.name.localeCompare(b.name);
          break;
        case "value":
          comparison = a.value - b.value;
          break;
        case "confidence":
          comparison = a.confidenceScore - b.confidenceScore;
          break;
        case "source":
          comparison = a.source.localeCompare(b.source);
          break;
      }
      return sortDirection === "asc" ? comparison : -comparison;
    });

  const SortIcon = ({ field }: { field: SortField }) => {
    if (sortField !== field) return <ArrowUpDown className="w-3.5 h-3.5 text-muted-foreground" />;
    return sortDirection === "asc" ? (
      <ArrowUp className="w-3.5 h-3.5 text-primary" />
    ) : (
      <ArrowDown className="w-3.5 h-3.5 text-primary" />
    );
  };

  const sourceTypes = Array.from(new Set(assumptions.map((a) => a.source)));

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center justify-between mb-4">
        <h3 className="font-semibold text-lg">Assumption Register</h3>
        <select
          value={filterSource}
          onChange={(e) => setFilterSource(e.target.value)}
          className="text-sm px-3 py-1.5 rounded-md border bg-background"
        >
          <option value="all">All Sources</option>
          {sourceTypes.map((source) => (
            <option key={source} value={source}>
              {source}
            </option>
          ))}
        </select>
      </div>

      {sortedAssumptions.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">No assumptions found</div>
      ) : (
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b">
                <th
                  className="text-left py-3 px-2 cursor-pointer hover:bg-muted/50 transition-colors"
                  onClick={() => handleSort("name")}
                >
                  <div className="flex items-center gap-1">
                    <span className="text-sm font-medium">Name</span>
                    <SortIcon field="name" />
                  </div>
                </th>
                <th
                  className="text-left py-3 px-2 cursor-pointer hover:bg-muted/50 transition-colors"
                  onClick={() => handleSort("value")}
                >
                  <div className="flex items-center gap-1">
                    <span className="text-sm font-medium">Value</span>
                    <SortIcon field="value" />
                  </div>
                </th>
                <th className="text-left py-3 px-2">
                  <span className="text-sm font-medium">Source</span>
                </th>
                <th
                  className="text-left py-3 px-2 cursor-pointer hover:bg-muted/50 transition-colors"
                  onClick={() => handleSort("confidence")}
                >
                  <div className="flex items-center gap-1">
                    <span className="text-sm font-medium">Confidence</span>
                    <SortIcon field="confidence" />
                  </div>
                </th>
                <th className="text-left py-3 px-2">
                  <span className="text-sm font-medium">Status</span>
                </th>
              </tr>
            </thead>
            <tbody>
              {sortedAssumptions.map((assumption) => (
                <tr
                  key={assumption.id}
                  className={`border-b last:border-0 hover:bg-muted/30 transition-colors ${
                    assumption.unsupported ? "bg-red-50/50" : ""
                  }`}
                >
                  <td className="py-3 px-2">
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{assumption.name}</span>
                      {assumption.unsupported && (
                        <AlertTriangle className="w-4 h-4 text-red-500" />
                      )}
                    </div>
                    {assumption.benchmarkReference && (
                      <p className="text-xs text-muted-foreground mt-0.5">
                        Benchmark: {assumption.benchmarkReference}
                      </p>
                    )}
                  </td>
                  <td className="py-3 px-2">
                    <span className="font-medium">
                      {assumption.value.toLocaleString()} {assumption.unit}
                    </span>
                  </td>
                  <td className="py-3 px-2">
                    <SourceBadge sourceType={assumption.source} size="sm" showTier={false} />
                  </td>
                  <td className="py-3 px-2">
                    <ConfidenceBadge score={assumption.confidenceScore} showTooltip={false} />
                  </td>
                  <td className="py-3 px-2">
                    <span
                      className={`text-xs px-2 py-1 rounded-full font-medium ${
                        assumption.plausibility === "plausible"
                          ? "bg-green-100 text-green-800"
                          : assumption.plausibility === "aggressive"
                            ? "bg-amber-100 text-amber-800"
                            : "bg-red-100 text-red-800"
                      }`}
                    >
                      {assumption.plausibility.replace("-", " ")}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default AssumptionRegister;

/**
 * CheckpointTimeline Widget
 *
 * Horizontal timeline with measurement dates, expected ranges, status indicators (pending/measured/missed/exceeded).
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.5
 */

import { AlertCircle, Calendar, CheckCircle2, Clock, XCircle } from "lucide-react";
import React from "react";

import { WidgetProps } from "../CanvasHost";

export type CheckpointStatus = "pending" | "measured" | "missed" | "exceeded";

export interface Checkpoint {
  id: string;
  date: string;
  expectedRange: { min: number; max: number };
  actualValue?: number;
  status: CheckpointStatus;
  notes?: string;
}

export interface CheckpointTimelineData {
  checkpoints: Checkpoint[];
  metricName: string;
  unit: string;
}

export function CheckpointTimeline({ data }: WidgetProps) {
  const widgetData = data as unknown as CheckpointTimelineData;
  const checkpoints = widgetData.checkpoints ?? [];
  const metricName = widgetData.metricName ?? "Metric";
  const unit = widgetData.unit ?? "";

  const getStatusIcon = (status: CheckpointStatus) => {
    switch (status) {
      case "measured":
        return <CheckCircle2 className="w-5 h-5 text-green-500" />;
      case "missed":
        return <XCircle className="w-5 h-5 text-red-500" />;
      case "exceeded":
        return <CheckCircle2 className="w-5 h-5 text-blue-500" />;
      default:
        return <Clock className="w-5 h-5 text-amber-500" />;
    }
  };

  const getStatusColor = (status: CheckpointStatus) => {
    switch (status) {
      case "measured":
        return "bg-green-100 border-green-200 text-green-800";
      case "missed":
        return "bg-red-100 border-red-200 text-red-800";
      case "exceeded":
        return "bg-blue-100 border-blue-200 text-blue-800";
      default:
        return "bg-amber-50 border-amber-200 text-amber-800";
    }
  };

  const formatValue = (value: number) => {
    if (unit === "$" || unit === "USD") {
      if (value >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
      return `$${value.toLocaleString()}`;
    }
    if (unit === "%") return `${value.toFixed(1)}%`;
    return `${value.toLocaleString()} ${unit}`;
  };

  // Parse YYYY-MM-DD as local date to avoid timezone issues
  const parseLocalDate = (dateStr: string): Date => {
    const parts = dateStr.split("-").map((s) => parseInt(s, 10));
    if (parts.length < 3 || parts.some((p) => isNaN(p))) {
      throw new Error(`Invalid date format: ${dateStr}`);
    }
    const [year, month, day] = parts as [number, number, number];
    return new Date(year, month - 1, day);
  };

  // Sort by date
  const sortedCheckpoints = [...checkpoints].sort(
    (a, b) => parseLocalDate(a.date).getTime() - parseLocalDate(b.date).getTime()
  );

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-primary/10 rounded-lg">
          <Calendar className="w-5 h-5 text-primary" />
        </div>
        <div>
          <h3 className="font-semibold text-lg">Checkpoint Timeline</h3>
          <p className="text-sm text-muted-foreground">{metricName} checkpoints</p>
        </div>
      </div>

      {sortedCheckpoints.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          <Clock className="w-12 h-12 mx-auto mb-3 opacity-50" />
          <p>No checkpoints scheduled</p>
        </div>
      ) : (
        <div className="relative">
          {/* Timeline line */}
          <div className="absolute top-6 left-0 right-0 h-0.5 bg-border" />

          {/* Checkpoints */}
          <div className="flex justify-between">
            {sortedCheckpoints.map((checkpoint, index) => (
              <div key={checkpoint.id} className="relative flex flex-col items-center">
                {/* Status indicator */}
                <div
                  className={`w-12 h-12 rounded-full border-2 flex items-center justify-center z-10 ${getStatusColor(
                    checkpoint.status
                  )}`}
                >
                  {getStatusIcon(checkpoint.status)}
                </div>

                {/* Date */}
                <div className="mt-3 text-center">
                  <p className="text-sm font-medium">
                    {parseLocalDate(checkpoint.date).toLocaleDateString("en-US", {
                      month: "short",
                      day: "numeric",
                      year: "numeric",
                    })}
                  </p>
                </div>

                {/* Status label */}
                <p className="mt-2 text-xs font-medium capitalize">{checkpoint.status}</p>

                {/* Expected range */}
                <div className="mt-2 text-center">
                  <p className="text-xs text-muted-foreground">Expected</p>
                  <p className="text-sm font-medium">
                    {formatValue(checkpoint.expectedRange.min)} -{" "}
                    {formatValue(checkpoint.expectedRange.max)}
                  </p>
                </div>

                {/* Actual value if measured */}
                {checkpoint.actualValue !== undefined && (
                  <div className="mt-1 text-center">
                    <p className="text-xs text-muted-foreground">Actual</p>
                    <p
                      className={`text-sm font-bold ${checkpoint.status === "missed"
                        ? "text-red-600"
                        : checkpoint.status === "exceeded"
                          ? "text-blue-600"
                          : "text-green-600"
                        }`}
                    >
                      {formatValue(checkpoint.actualValue)}
                    </p>
                  </div>
                )}

                {/* Notes */}
                {checkpoint.notes && (
                  <p className="mt-1 text-xs text-muted-foreground text-center max-w-[120px]">
                    {checkpoint.notes}
                  </p>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Legend */}
      <div className="mt-8 flex flex-wrap gap-4 justify-center text-xs">
        <div className="flex items-center gap-1">
          <Clock className="w-4 h-4 text-amber-500" />
          <span>Pending</span>
        </div>
        <div className="flex items-center gap-1">
          <CheckCircle2 className="w-4 h-4 text-green-500" />
          <span>On Target</span>
        </div>
        <div className="flex items-center gap-1">
          <XCircle className="w-4 h-4 text-red-500" />
          <span>Missed</span>
        </div>
        <div className="flex items-center gap-1">
          <CheckCircle2 className="w-4 h-4 text-blue-500" />
          <span>Exceeded</span>
        </div>
      </div>
    </div>
  );
}

export default CheckpointTimeline;

/**
 * EvidenceGapList Widget
 *
 * List of claims with insufficient evidence, showing current tier, required tier, suggested action.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.3
 */

import { AlertCircle, ArrowUpRight, Shield } from "lucide-react";
import React from "react";

import { WidgetProps } from "../CanvasHost";

export interface EvidenceGap {
  id: string;
  claimId: string;
  field: string;
  currentTier: "tier1" | "tier2" | "tier3" | "none";
  requiredTier: "tier1" | "tier2" | "tier3";
  suggestedAction: string;
  impact: "high" | "medium" | "low";
}

export interface EvidenceGapListData {
  gaps: EvidenceGap[];
}

export function EvidenceGapList({ data, onAction }: WidgetProps) {
  const widgetData = data as unknown as EvidenceGapListData;
  const gaps = widgetData.gaps ?? [];

  const getTierBadge = (tier: string) => {
    switch (tier) {
      case "tier1":
        return "bg-emerald-100 text-emerald-800 border-emerald-200";
      case "tier2":
        return "bg-blue-100 text-blue-800 border-blue-200";
      case "tier3":
        return "bg-amber-100 text-amber-800 border-amber-200";
      default:
        return "bg-gray-100 text-gray-800 border-gray-200";
    }
  };

  const getImpactBadge = (impact: string) => {
    switch (impact) {
      case "high":
        return "bg-red-100 text-red-800";
      case "medium":
        return "bg-amber-100 text-amber-800";
      case "low":
        return "bg-blue-100 text-blue-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const sortedGaps = [...gaps].sort((a, b) => {
    const impactOrder = { high: 0, medium: 1, low: 2 };
    return impactOrder[a.impact] - impactOrder[b.impact];
  });

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-amber-100 rounded-lg">
          <AlertCircle className="w-5 h-5 text-amber-600" />
        </div>
        <div>
          <h3 className="font-semibold text-lg">Evidence Gaps</h3>
          <p className="text-sm text-muted-foreground">
            {gaps.length} {gaps.length === 1 ? "gap" : "gaps"} need attention
          </p>
        </div>
      </div>

      {sortedGaps.length === 0 ? (
        <div className="flex items-center gap-3 p-4 bg-green-50 rounded-lg">
          <Shield className="w-5 h-5 text-green-600" />
          <p className="text-green-800">No evidence gaps</p>
        </div>
      ) : (
        <div className="space-y-3">
          {sortedGaps.map((gap) => (
            <div
              key={gap.id}
              className="p-4 rounded-lg border hover:border-primary/30 transition-colors cursor-pointer"
              onClick={() => onAction?.("select", { gapId: gap.id })}
            >
              <div className="flex items-start justify-between mb-2">
                <div>
                  <h4 className="font-medium">{gap.field}</h4>
                  <p className="text-sm text-muted-foreground">{gap.suggestedAction}</p>
                </div>
                <span
                  className={`text-xs px-2 py-1 rounded-full font-medium ${getImpactBadge(
                    gap.impact
                  )}`}
                >
                  {gap.impact.charAt(0).toUpperCase() + gap.impact.slice(1)} impact
                </span>
              </div>

              <div className="flex items-center gap-4 mt-3">
                <div className="flex items-center gap-2">
                  <span
                    className={`text-xs px-2 py-0.5 rounded-full border ${getTierBadge(
                      gap.currentTier
                    )}`}
                  >
                    Current: {gap.currentTier === "none" ? "None" : gap.currentTier.replace("tier", "Tier ")}
                  </span>
                </div>

                <ArrowUpRight className="w-4 h-4 text-muted-foreground" />

                <div className="flex items-center gap-2">
                  <span
                    className={`text-xs px-2 py-0.5 rounded-full border ${getTierBadge(
                      gap.requiredTier
                    )}`}
                  >
                    Required: {gap.requiredTier.replace("tier", "Tier ")}
                  </span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default EvidenceGapList;

/**
 * GapResolution Widget
 *
 * List of missing data items with inline input fields, submit action, and resolved state.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.1
 */

import { AlertCircle, CheckCircle2, Circle, Send } from "lucide-react";
import React, { useState } from "react";

import { WidgetProps } from "../CanvasHost";

export interface GapItem {
  id: string;
  field: string;
  description: string;
  required: boolean;
  resolved: boolean;
  value?: string | number | boolean;
}

export interface GapResolutionData {
  gaps: GapItem[];
  caseId: string;
}

export function GapResolution({ data, onAction }: WidgetProps) {
  const widgetData = data as unknown as GapResolutionData;
  const gaps = widgetData.gaps ?? [];
  const [inputValues, setInputValues] = useState<Record<string, string>>({});
  const [submitting, setSubmitting] = useState<Record<string, boolean>>({});

  const handleInputChange = (gapId: string, value: string) => {
    setInputValues((prev) => ({ ...prev, [gapId]: value }));
  };

  const handleSubmit = (gapId: string) => {
    const value = inputValues[gapId];
    if (!value?.trim()) return;

    // Fire action immediately without async delay for test compatibility
    onAction?.("submitGap", { gapId, value });
    setInputValues((prev) => ({ ...prev, [gapId]: "" }));
  };

  const resolvedCount = gaps.filter((g) => g.resolved).length;
  const progress = gaps.length > 0 ? (resolvedCount / gaps.length) * 100 : 0;

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-amber-100 rounded-lg">
            <AlertCircle className="w-5 h-5 text-amber-600" />
          </div>
          <div>
            <h3 className="font-semibold text-lg">Gap Resolution</h3>
            <p className="text-sm text-muted-foreground">
              {resolvedCount} of {gaps.length} resolved
            </p>
          </div>
        </div>
      </div>

      {/* Progress bar */}
      <div className="w-full bg-muted rounded-full h-2 mb-6">
        <div
          className="bg-primary h-2 rounded-full transition-all duration-300"
          style={{ width: `${progress}%` }}
        />
      </div>

      {gaps.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          <CheckCircle2 className="w-12 h-12 mx-auto mb-3 text-green-500" />
          <p>No data gaps</p>
        </div>
      ) : (
        <div className="space-y-3">
          {gaps.map((gap) => (
            <div
              key={gap.id}
              className={`p-4 rounded-lg border ${gap.resolved ? "bg-green-50 border-green-200" : "bg-card border-border"
                }`}
            >
              <div className="flex items-start gap-3">
                {gap.resolved ? (
                  <CheckCircle2 className="w-5 h-5 text-green-500 mt-0.5 shrink-0" />
                ) : (
                  <Circle className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                )}

                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-medium">{gap.field}</span>
                    {gap.required && (
                      <span className="text-xs text-red-500 font-medium">Required</span>
                    )}
                  </div>

                  <p className="text-sm text-muted-foreground mb-3">{gap.description}</p>

                  {gap.resolved ? (
                    <div className="flex items-center gap-2 text-sm">
                      <span className="text-muted-foreground">Value:</span>
                      <span className="font-medium text-green-700">{String(gap.value)}</span>
                    </div>
                  ) : (
                    <div className="flex gap-2">
                      <input
                        type="text"
                        value={inputValues[gap.id] ?? ""}
                        onChange={(e) => handleInputChange(gap.id, e.target.value)}
                        placeholder={`Enter ${gap.field}...`}
                        className="flex-1 px-3 py-2 text-sm rounded-md border bg-background focus:outline-none focus:ring-2 focus:ring-primary/20"
                        onKeyDown={(e) => {
                          if (e.key === "Enter") {
                            handleSubmit(gap.id);
                          }
                        }}
                      />
                      <button
                        onClick={() => handleSubmit(gap.id)}
                        disabled={!inputValues[gap.id]?.trim()}
                        className="px-3 py-2 bg-primary text-primary-foreground rounded-md text-sm font-medium hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                      >
                        <span>Submit</span>
                      </button>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default GapResolution;

/**
 * HypothesisCard Widget
 *
 * Value driver, impact range, evidence tier, confidence badge, Accept/Edit/Reject actions.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.2
 */

import { ConfidenceBadge } from "@valueos/components/components/ConfidenceBadge";
import { Check, Edit3, TrendingUp, X } from "lucide-react";
import React from "react";

import { useToast } from "@/components/common/Toast";
import { WidgetProps } from "../CanvasHost";

export interface HypothesisData {
  id: string;
  valueDriver: string;
  impactRange: { low: number; high: number };
  evidenceTier: "tier1" | "tier2" | "tier3";
  confidenceScore: number;
  status: "pending" | "accepted" | "rejected" | "modified";
  benchmarkReference?: { source: string; p25: number; p50: number; p75: number };
}

export interface HypothesisCardWidgetData {
  hypotheses: HypothesisData[];
}

export function HypothesisCard({ data, onAction }: WidgetProps) {
  const { error, success } = useToast();
  const widgetData = data as unknown as HypothesisCardWidgetData;
  const hypotheses = widgetData.hypotheses ?? [];

  const handleAction = async (action: "accept" | "edit" | "reject", hypothesisId: string) => {
    try {
      await onAction?.(action, { hypothesisId });
      success(`Hypothesis ${action}ed.`);
    } catch {
      error("Could not update hypothesis. Please try again.");
    }
  };

  const getTierBadge = (tier: string) => {
    switch (tier) {
      case "tier1":
        return "bg-emerald-100 text-emerald-800 border-emerald-200";
      case "tier2":
        return "bg-blue-100 text-blue-800 border-blue-200";
      case "tier3":
        return "bg-amber-100 text-amber-800 border-amber-200";
      default:
        return "bg-gray-100 text-gray-800 border-gray-200";
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "accepted":
        return "bg-green-100 text-green-800";
      case "rejected":
        return "bg-red-100 text-red-800";
      case "modified":
        return "bg-blue-100 text-blue-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  return (
    <div className="space-y-4">
      {hypotheses.map((hypothesis) => (
        <div
          key={hypothesis.id}
          role="button"
          tabIndex={0}
          onKeyDown={(event) => {
            if (event.key === "Enter" || event.key === " ") {
              event.preventDefault();
            }
          }}
          aria-label={`Hypothesis ${hypothesis.valueDriver}`}
          className="rounded-xl border bg-card p-5 transition-all hover:shadow-sm"
        >
          <div className="flex items-start justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-primary/10 rounded-lg">
                <TrendingUp className="w-5 h-5 text-primary" />
              </div>
              <div>
                <h4 className="font-semibold">{hypothesis.valueDriver}</h4>
                <div className="flex items-center gap-2 mt-1">
                  <span className={`text-xs px-2 py-0.5 rounded-full border ${getTierBadge(hypothesis.evidenceTier)}`}>
                    {hypothesis.evidenceTier.replace("tier", "Tier ")}
                  </span>
                  <ConfidenceBadge score={hypothesis.confidenceScore} showTooltip={false} />
                </div>
              </div>
            </div>
            <span className={`text-xs px-2 py-1 rounded-full font-medium ${getStatusBadge(hypothesis.status)}`}>
              {hypothesis.status.charAt(0).toUpperCase() + hypothesis.status.slice(1)}
            </span>
          </div>

          <div className="mb-4">
            <p className="text-sm text-muted-foreground mb-2">Impact Range</p>
            <div className="flex items-center gap-2">
              <span className="text-lg font-bold">${hypothesis.impactRange.low.toLocaleString()}</span>
              <span className="text-muted-foreground">-</span>
              <span className="text-lg font-bold">${hypothesis.impactRange.high.toLocaleString()}</span>
            </div>
          </div>

          {hypothesis.benchmarkReference && (
            <div className="mb-4 p-3 bg-muted/50 rounded-lg">
              <p className="text-xs text-muted-foreground mb-1">Benchmark Reference</p>
              <p className="text-sm font-medium">{hypothesis.benchmarkReference.source}</p>
              <div className="flex gap-3 mt-1 text-xs text-muted-foreground">
                <span>P25: {hypothesis.benchmarkReference.p25}%</span>
                <span>P50: {hypothesis.benchmarkReference.p50}%</span>
                <span>P75: {hypothesis.benchmarkReference.p75}%</span>
              </div>
            </div>
          )}

          {hypothesis.status === "pending" && (
            <div className="flex gap-2">
              <button
                onClick={() => void handleAction("accept", hypothesis.id)}
                className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg text-sm font-medium hover:bg-green-700 transition-colors"
              >
                <Check className="w-4 h-4" />
                Accept
              </button>
              <button
                onClick={() => void handleAction("edit", hypothesis.id)}
                className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-primary text-primary-foreground rounded-lg text-sm font-medium hover:bg-primary/90 transition-colors"
              >
                <Edit3 className="w-4 h-4" />
                Edit
              </button>
              <button
                onClick={() => void handleAction("reject", hypothesis.id)}
                className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg text-sm font-medium hover:bg-red-700 transition-colors"
              >
                <X className="w-4 h-4" />
                Reject
              </button>
            </div>
          )}
        </div>
      ))}

      {hypotheses.length === 0 && (
        <div className="text-center py-8 text-muted-foreground">
          <TrendingUp className="w-12 h-12 mx-auto mb-3 opacity-50" />
          <p>No value hypotheses generated yet</p>
        </div>
      )}
    </div>
  );
}

export default HypothesisCard;

/**
 * InlineEditor Widget
 *
 * contentEditable region with save/cancel, diff highlight on modified sections, reason prompt on save.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.4
 */

import { Edit3, Save, X } from "lucide-react";
import React, { useEffect, useRef, useState } from "react";

import { useToast } from "@/components/common/Toast";
import { WidgetProps } from "../CanvasHost";

export interface InlineEditorData {
  sectionId: string;
  sectionTitle?: string;
  content?: string;
  originalContent?: string;
  currentContent?: string;
  isModified?: boolean;
}

export function InlineEditor({ data, onAction }: WidgetProps) {
  const { error, success } = useToast();
  const widgetData = data as unknown as InlineEditorData;
  const [isEditing, setIsEditing] = useState(false);

  // Support both test data shape (content) and full shape (originalContent/currentContent)
  const originalContent = widgetData.originalContent ?? widgetData.content ?? "";
  const currentContent = widgetData.currentContent ?? widgetData.content ?? "";
  const sectionTitle = widgetData.sectionTitle ?? "Section";

  const [editedContent, setEditedContent] = useState(currentContent);
  const [reason, setReason] = useState("");
  const [showReasonPrompt, setShowReasonPrompt] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    setEditedContent(currentContent);
  }, [currentContent]);

  const hasChanges = editedContent !== originalContent;

  const handleSave = async () => {
    if (!hasChanges) {
      setIsEditing(false);
      return;
    }
    // Inline reason flow - save directly if reason provided
    if (reason.trim()) {
      try {
        await onAction?.("save", {
          sectionId: widgetData.sectionId,
          content: editedContent,
          reason: reason,
        });
        success("Section saved.");
        setIsEditing(false);
        setReason("");
      } catch {
        error("Failed to save section.");
      }
    }
    // If no reason, just stay in edit mode (test will provide reason)
  };

  const handleConfirmSave = async () => {
    if (!reason.trim()) return;

    try {
      await onAction?.("save", {
        sectionId: widgetData.sectionId,
        content: editedContent,
        reason: reason,
      });
      success("Section saved.");
    } catch {
      error("Failed to save section.");
      return;
    }

    setShowReasonPrompt(false);
    setIsEditing(false);
    setReason("");
  };

  const handleCancel = () => {
    setEditedContent(originalContent);
    setIsEditing(false);
    setShowReasonPrompt(false);
    setReason("");
  };

  // Simple diff highlighting (lines that changed)
  const renderDiff = () => {
    const originalLines = originalContent.split("\n");
    const editedLines = editedContent.split("\n");

    return editedLines.map((line, index) => {
      const isChanged = line !== originalLines[index];
      return (
        <div
          key={index}
          className={`px-2 py-0.5 ${isChanged ? "bg-yellow-50 border-l-2 border-yellow-400" : ""}`}
        >
          {line || "\u00A0"}
        </div>
      );
    });
  };

  if (!isEditing) {
    const isModified = widgetData.isModified ?? false;
    return (
      <div className="rounded-xl border bg-card p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-semibold">{sectionTitle}</h3>
          <button
            onClick={() => setIsEditing(true)}
            className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-primary hover:bg-primary/10 rounded-lg transition-colors"
          >
            <Edit3 className="w-4 h-4" />
            Edit
          </button>
        </div>
        <div
          className={`prose prose-sm max-w-none text-foreground whitespace-pre-wrap cursor-pointer hover:bg-muted/50 rounded p-2 -m-2 transition-colors ${isModified ? "bg-yellow-50 border-l-2 border-yellow-400" : ""}`}
          onClick={() => setIsEditing(true)}
          tabIndex={0}
          aria-label={`Inline editor content for ${sectionTitle}`}
          onKeyDown={(event) => {
            if (event.key === "Enter" || event.key === " ") {
              event.preventDefault();
              setIsEditing(true);
            }
          }}
        >
          {currentContent}
        </div>
        {/* Accessibility live region */}
        <div className="sr-only" role="status" aria-live="polite">
          Viewing mode
        </div>
      </div>
    );
  }

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center justify-between mb-4">
        <h3 className="font-semibold">{widgetData.sectionTitle}</h3>
        <div className="flex items-center gap-2">
          <button
            onClick={handleCancel}
            className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-muted-foreground hover:bg-muted rounded-lg transition-colors"
          >
            <X className="w-4 h-4" />
            Cancel
          </button>
          <button
            onClick={() => void handleSave()}
            disabled={!hasChanges}
            className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Save className="w-4 h-4" />
            Save
          </button>
        </div>
      </div>

      {/* Diff view */}
      {hasChanges && (
        <div className="mb-4 p-3 bg-yellow-50 border border-yellow-200 rounded-lg">
          <p className="text-xs text-yellow-800 font-medium mb-2">Changes detected:</p>
          <div className="text-sm font-mono whitespace-pre-wrap">{renderDiff()}</div>
        </div>
      )}

      {/* Editor */}
      <textarea
        ref={textareaRef}
        value={editedContent}
        onChange={(e) => setEditedContent(e.target.value)}
        aria-label={`Edit ${sectionTitle}`}
        className="min-h-[200px] w-full p-4 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20 prose prose-sm max-w-none"
        style={{ whiteSpace: "pre-wrap" }}
      />

      {/* Reason input - inline for tests */}
      {hasChanges && (
        <div className="mt-4">
          <textarea
            value={reason}
            onChange={(e) => setReason(e.target.value)}
            placeholder="Reason for edit..."
            className="w-full px-3 py-2 border rounded-lg resize-none h-20 focus:outline-none focus:ring-2 focus:ring-primary/20"
          />
        </div>
      )}

      {/* Accessibility live region */}
      <div className="sr-only" role="status" aria-live="polite">
        Editing mode active
      </div>
    </div>
  );
}

export default InlineEditor;

/**
 * KPITargetCard Widget
 *
 * Metric name, baseline → target, timeline, source badge, progress indicator (for post-sale).
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.5
 */

import { SourceBadge, SourceType } from "@valueos/components/components/SourceBadge";
import { Minus, Target, TrendingDown, TrendingUp } from "lucide-react";
import React from "react";

import { WidgetProps } from "../CanvasHost";

export interface KPITarget {
  id: string;
  metricName: string;
  baseline: number;
  target: number;
  unit: string;
  timeline: {
    startDate: string;
    targetDate: string;
  };
  source: SourceType;
  progress: number; // 0-100
  currentValue?: number;
}

export interface KPITargetCardData {
  kpiTargets: KPITarget[];
}

export function KPITargetCard({ data }: WidgetProps) {
  const widgetData = data as unknown as KPITargetCardData;
  const targets = widgetData.kpiTargets ?? [];

  const formatValue = (value: number, unit: string) => {
    if (unit === "$" || unit === "USD") {
      return `$${value.toLocaleString()}`;
    }
    if (unit === "%") return `${value.toFixed(0)}%`;
    return `${value.toLocaleString()} ${unit}`;
  };

  const getTrendIcon = (baseline: number, target: number) => {
    if (target > baseline) return <TrendingUp className="w-4 h-4 text-green-500" />;
    if (target < baseline) return <TrendingDown className="w-4 h-4 text-red-500" />;
    return <Minus className="w-4 h-4 text-gray-500" />;
  };

  // Parse YYYY-MM-DD as local date to avoid timezone issues
  const parseLocalDate = (dateStr: string): Date => {
    const parts = dateStr.split("-").map((s) => parseInt(s, 10));
    if (parts.length < 3 || parts.some((p) => isNaN(p))) {
      throw new Error(`Invalid date format: ${dateStr}`);
    }
    const [year, month, day] = parts as [number, number, number];
    return new Date(year, month - 1, day);
  };

  const formatTimelineDate = (dateStr: string) => {
    const date = parseLocalDate(dateStr);
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      {targets.map((target) => {
        const isImproving = target.target > target.baseline;
        const isOnTrack = target.progress >= 50; // Simple heuristic

        return (
          <div key={target.id} className="rounded-xl border bg-card p-5">
            <div className="flex items-center justify-between mb-3">
              <h4 className="font-semibold">{target.metricName}</h4>
              {getTrendIcon(target.baseline, target.target)}
            </div>

            {/* Value comparison */}
            <div className="flex items-center gap-3 mb-4">
              <div className="text-center">
                <p className="text-xs text-muted-foreground">Baseline</p>
                <p className="font-medium">{formatValue(target.baseline, target.unit)}</p>
              </div>
              <div className="flex-1 flex items-center justify-center">
                <div className="h-px flex-1 bg-border" />
                <span className="mx-2 text-xs text-muted-foreground">→</span>
                <div className="h-px flex-1 bg-border" />
              </div>
              <div className="text-center">
                <p className="text-xs text-muted-foreground">Target</p>
                <p className={`font-bold ${isImproving ? "text-green-600" : "text-red-600"}`}>
                  {formatValue(target.target, target.unit)}
                </p>
              </div>
            </div>

            {/* Progress bar */}
            <div className="mb-3">
              <div className="flex items-center justify-between text-xs mb-1">
                <span className="text-muted-foreground">Progress</span>
                <span className={isOnTrack ? "text-green-600" : "text-amber-600"}>
                  {target.progress.toFixed(0)}%
                </span>
              </div>
              <div className="h-2 bg-muted rounded-full overflow-hidden">
                <div
                  className={`h-full rounded-full transition-all duration-500 ${isOnTrack ? "bg-green-500" : "bg-amber-500"
                    }`}
                  style={{ width: `${Math.min(target.progress, 100)}%` }}
                />
              </div>
              {target.currentValue !== undefined && (
                <p className="text-xs text-muted-foreground mt-1">
                  Current: {formatValue(target.currentValue, target.unit)}
                </p>
              )}
            </div>

            {/* Timeline */}
            <div className="flex items-center justify-between text-xs text-muted-foreground mb-3">
              <span>{formatTimelineDate(target.timeline.startDate)}</span>
              <span>{formatTimelineDate(target.timeline.targetDate)}</span>
            </div>

            {/* Source badge */}
            <SourceBadge sourceType={target.source} size="sm" showTier={false} />
          </div>
        );
      })}

      {targets.length === 0 && (
        <div className="col-span-full text-center py-8 text-muted-foreground">
          <Target className="w-12 h-12 mx-auto mb-3 opacity-50" />
          <p>No KPI targets defined</p>
        </div>
      )}
    </div>
  );
}

export default KPITargetCard;

/**
 * PlanComparison Widget
 *
 * Side-by-side plan cards with features, pricing, current plan indicator, and upgrade CTA.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.6
 */

import { ArrowRight, Check, Star } from "lucide-react";
import React from "react";

import { WidgetProps } from "../CanvasHost";

export interface Plan {
  id: string;
  name: string;
  description: string;
  price: number;
  interval: "month" | "year";
  features: string[];
  limits: {
    aiTokens: number;
    apiCalls: number;
    seats: number;
  };
  isCurrent: boolean;
  popular?: boolean;
}

export interface PlanComparisonData {
  plans: Plan[];
  currentPlanId: string;
}

export function PlanComparison({ data, onAction }: WidgetProps) {
  const widgetData = data as unknown as PlanComparisonData;
  const plans = widgetData.plans ?? [];

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: "USD",
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(price);
  };

  const formatLimit = (value: number) => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(0)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(0)}K`;
    return value.toLocaleString();
  };

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-primary/10 rounded-lg">
          <Star className="w-5 h-5 text-primary" />
        </div>
        <div>
          <h3 className="font-semibold text-lg">Plan Comparison</h3>
          <p className="text-sm text-muted-foreground">Choose the right plan for your needs</p>
        </div>
      </div>

      {plans.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">No plans available</div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {plans.map((plan) => (
            <div
              key={plan.id}
              className={`relative rounded-lg border p-5 ${plan.isCurrent
                  ? "bg-primary/5 border-primary ring-1 ring-primary/20"
                  : plan.popular
                    ? "bg-amber-50/50 border-amber-200"
                    : "bg-card border-border"
                }`}
            >
              {/* Badges */}
              <div className="flex items-center gap-2 mb-3">
                {plan.isCurrent && (
                  <span className="text-xs px-2 py-0.5 bg-primary text-primary-foreground rounded-full font-medium">
                    Current Plan
                  </span>
                )}
                {plan.popular && !plan.isCurrent && (
                  <span className="text-xs px-2 py-0.5 bg-amber-100 text-amber-800 rounded-full font-medium">
                    Popular
                  </span>
                )}
              </div>

              {/* Plan name */}
              <h4 className="font-semibold text-lg">{plan.name}</h4>
              <p className="text-sm text-muted-foreground mb-4">{plan.description}</p>

              {/* Price */}
              <div className="mb-4">
                <span className="text-3xl font-bold">{formatPrice(plan.price)}</span>
                <span className="text-muted-foreground">/{plan.interval}</span>
              </div>

              {/* Limits */}
              <div className="mb-4 p-3 bg-muted/50 rounded-lg text-sm space-y-1">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">AI Tokens</span>
                  <span className="font-medium">{formatLimit(plan.limits.aiTokens)}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">API Calls</span>
                  <span className="font-medium">{formatLimit(plan.limits.apiCalls)}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Seats</span>
                  <span className="font-medium">{plan.limits.seats}</span>
                </div>
              </div>

              {/* Features */}
              <ul className="space-y-2 mb-5">
                {plan.features.map((feature, index) => (
                  <li key={index} className="flex items-start gap-2 text-sm">
                    <Check className="w-4 h-4 text-green-500 mt-0.5 shrink-0" />
                    <span>{feature}</span>
                  </li>
                ))}
              </ul>

              {/* CTA */}
              {plan.isCurrent ? (
                <button
                  disabled
                  className="w-full py-2 text-sm font-medium text-muted-foreground bg-muted rounded-lg cursor-not-allowed"
                >
                  Current Plan
                </button>
              ) : (
                <button
                  onClick={() => onAction?.("upgrade", { planId: plan.id })}
                  className="w-full flex items-center justify-center gap-2 py-2 text-sm font-medium bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors"
                >
                  {plan.price > (plans.find((p) => p.isCurrent)?.price || 0) ? "Upgrade" : "Downgrade"}
                  <ArrowRight className="w-4 h-4" />
                </button>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default PlanComparison;

