/**
 * ReadinessGauge Widget
 *
 * Circular gauge for composite score + four component bars (validation rate, grounding, benchmark coverage, unsupported count).
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.3
 */

import { AlertTriangle, Anchor, BarChart3, CheckCircle2, Gauge, Loader2 } from "lucide-react";
import React, { useMemo } from "react";

import { WidgetProps } from "../CanvasHost";

export interface ReadinessComponent {
  name?: string;
  score: number;
  /** @deprecated Weight is not currently consumed by the UI */
  weight?: number;
}

export interface ReadinessGaugeData {
  compositeScore: number;
  status: "presentation-ready" | "draft" | "blocked";
  components: {
    validationRate: ReadinessComponent;
    grounding: ReadinessComponent;
    benchmarkCoverage: ReadinessComponent;
    unsupportedCount: ReadinessComponent;
  };
  blockers: string[];
}

/** Type guard for ReadinessComponent */
function isReadinessComponent(value: unknown): value is ReadinessComponent {
  return (
    typeof value === "object" &&
    value !== null &&
    "score" in value &&
    typeof (value as ReadinessComponent).score === "number"
  );
}

/** Type guard for ReadinessGaugeData */
function isReadinessGaugeData(value: unknown): value is ReadinessGaugeData {
  if (typeof value !== "object" || value === null) return false;
  const data = value as Record<string, unknown>;

  return (
    "compositeScore" in data &&
    typeof data.compositeScore === "number" &&
    "status" in data &&
    ["presentation-ready", "draft", "blocked"].includes(data.status as string) &&
    "components" in data &&
    typeof data.components === "object" &&
    data.components !== null
  );
}

/** Loading state component */
function ReadinessGaugeLoading() {
  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-primary/10 rounded-lg">
          <Loader2 className="w-5 h-5 text-primary animate-spin" />
        </div>
        <div>
          <h3 className="font-semibold text-lg">Defense Readiness</h3>
          <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium border bg-amber-100 text-amber-800 border-amber-200">
            Loading...
          </span>
        </div>
      </div>
      <div className="flex items-center justify-center py-12">
        <Loader2 className="w-8 h-8 text-muted-foreground animate-spin" />
      </div>
    </div>
  );
}

export function ReadinessGauge({ data }: WidgetProps) {
  // Validate data structure with type guard
  const gaugeData = data?.readiness;

  if (gaugeData === undefined || gaugeData === null) {
    return <ReadinessGaugeLoading />;
  }

  if (!isReadinessGaugeData(gaugeData)) {
    console.warn("ReadinessGauge: Invalid data structure received", gaugeData);
    return <ReadinessGaugeLoading />;
  }

  const widgetData = gaugeData;
  const compositeScore = widgetData.compositeScore;
  const status = widgetData.status;
  const components = widgetData.components;
  const blockers = widgetData.blockers ?? [];

  // Calculate circle properties
  const radius = 40;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (compositeScore / 100) * circumference;

  const getScoreColor = React.useCallback((score: number) => {
    if (score >= 80) return "text-green-600";
    if (score >= 50) return "text-amber-600";
    return "text-red-600";
  }, []);

  const getScoreBg = React.useCallback((score: number) => {
    if (score >= 80) return "bg-green-500";
    if (score >= 50) return "bg-amber-500";
    return "bg-red-500";
  }, []);

  const statusBadgeClass = useMemo(() =>
    status === "presentation-ready"
      ? "bg-green-100 text-green-800 border-green-200"
      : status === "blocked"
        ? "bg-red-100 text-red-800 border-red-200"
        : "bg-amber-100 text-amber-800 border-amber-200",
    [status]
  );

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-primary/10 rounded-lg">
          <Gauge className="w-5 h-5 text-primary" />
        </div>
        <div>
          <h3 className="font-semibold text-lg">Defense Readiness</h3>
          <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium border ${statusBadgeClass}`}>
            {status === "presentation-ready" ? "Ready" : status.replace("-", " ").toUpperCase()}
          </span>
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-6">
        {/* Circular gauge */}
        <div className="flex flex-col items-center">
          <div className="relative w-32 h-32">
            <svg className="w-full h-full transform -rotate-90" viewBox="0 0 100 100">
              {/* Background circle */}
              <circle
                cx="50"
                cy="50"
                r={radius}
                fill="none"
                stroke="currentColor"
                strokeWidth="8"
                className="text-muted"
                opacity="0.2"
              />
              {/* Progress circle */}
              <circle
                cx="50"
                cy="50"
                r={radius}
                fill="none"
                stroke="currentColor"
                strokeWidth="8"
                strokeLinecap="round"
                className={getScoreColor(compositeScore)}
                strokeDasharray={circumference}
                strokeDashoffset={strokeDashoffset}
                style={{ transition: "stroke-dashoffset 0.5s ease" }}
              />
            </svg>
            <div
              role="meter"
              aria-label="Defense readiness score"
              aria-valuemin={0}
              aria-valuemax={100}
              aria-valuenow={Math.round(compositeScore * 100)}
              className={`absolute inset-0 flex flex-col items-center justify-center ${getScoreColor(compositeScore)}`}
            >
              <span className="text-2xl font-bold">{Math.round(compositeScore * 100)}%</span>
              <span className="text-xs text-muted-foreground">Composite</span>
            </div>
          </div>
        </div>

        {/* Component bars */}
        <div className="flex-1 space-y-4">
          {components && isReadinessComponent(components.validationRate) && (
            <>
              <ComponentBar
                icon={<CheckCircle2 className="w-4 h-4" />}
                label="Validation Rate"
                score={components.validationRate.score}
                colorClass={getScoreBg(components.validationRate.score)}
              />
              {isReadinessComponent(components.grounding) && (
                <ComponentBar
                  icon={<Anchor className="w-4 h-4" />}
                  label="Grounding"
                  score={components.grounding.score}
                  colorClass={getScoreBg(components.grounding.score)}
                />
              )}
              {isReadinessComponent(components.benchmarkCoverage) && (
                <ComponentBar
                  icon={<BarChart3 className="w-4 h-4" />}
                  label="Benchmark Coverage"
                  score={components.benchmarkCoverage.score}
                  colorClass={getScoreBg(components.benchmarkCoverage.score)}
                />
              )}
              {isReadinessComponent(components.unsupportedCount) && (
                <ComponentBar
                  icon={<AlertTriangle className="w-4 h-4" />}
                  label="Unsupported"
                  score={components.unsupportedCount.score}
                  colorClass={getScoreBg(components.unsupportedCount.score)}
                />
              )}
            </>
          )}
        </div>
      </div>

      {blockers.length > 0 && (
        <div className="mt-6 p-3 bg-red-50 border border-red-200 rounded-lg">
          <p className="text-sm font-medium text-red-800 mb-1">
            {blockers.length} blockers
          </p>
          <ul className="text-sm text-red-700 space-y-0.5">
            {blockers.map((blocker, index) => (
              <li key={index}>• {blocker}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

function ComponentBar({
  icon,
  label,
  score,
  colorClass,
  inverted = false,
}: {
  icon: React.ReactNode;
  label: string;
  score: number;
  colorClass: string;
  inverted?: boolean;
}) {
  const displayScore = inverted ? 1 - score : score;
  const percentage = Math.round(displayScore * 100);

  return (
    <div className="flex items-center gap-3">
      <div className="text-muted-foreground w-5">{icon}</div>
      <div className="flex-1">
        <div className="flex items-center justify-between mb-1">
          <span className="text-sm font-medium">{label}</span>
          <span className="text-sm text-muted-foreground">{percentage}%</span>
        </div>
        <div className="h-2 bg-muted rounded-full overflow-hidden">
          <div
            className={`h-full rounded-full transition-all duration-500 ${colorClass}`}
            style={{ width: `${percentage}%` }}
          />
        </div>
      </div>
    </div>
  );
}

export default ReadinessGauge;

/**
 * ScenarioComparison Widget
 *
 * Three-column layout showing ROI, NPV, payback, EVF decomposition per scenario with base emphasized.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.2
 */

import { Clock, DollarSign, PieChart, TrendingUp } from "lucide-react";
import React from "react";

import { WidgetProps } from "../CanvasHost";

export interface Scenario {
  id: string;
  name: "conservative" | "base" | "upside";
  roi: number;
  npv: number;
  paybackMonths: number;
  evfDecomposition: {
    revenueUplift: number;
    costReduction: number;
    riskMitigation: number;
    efficiencyGain: number;
  };
  isBase: boolean;
}

export interface ScenarioComparisonData {
  scenarios: Scenario[];
}

export function ScenarioComparison({ data }: WidgetProps) {
  const widgetData = data as unknown as ScenarioComparisonData;
  const scenarios = widgetData.scenarios ?? [];

  const formatCurrency = (value: number) => `$${value.toLocaleString()}`;

  const formatPercent = (value: number) => `${value.toFixed(0)}%`;

  const scenarioOrder: Scenario["name"][] = ["conservative", "base", "upside"];
  const orderedScenarios = scenarioOrder
    .map((name) => scenarios.find((s) => s.name === name))
    .filter(Boolean) as Scenario[];

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-primary/10 rounded-lg">
          <PieChart className="w-5 h-5 text-primary" />
        </div>
        <div>
          <h3 className="font-semibold text-lg">Scenario Comparison</h3>
          <p className="text-sm text-muted-foreground">Financial scenarios side-by-side</p>
        </div>
      </div>

      {orderedScenarios.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">No scenarios available</div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          {orderedScenarios.map((scenario) => (
            <div
              key={scenario.id}
              role="button"
              tabIndex={0}
              aria-label={`${scenario.name} scenario`}
              onKeyDown={(event) => {
                if (event.key === "Enter" || event.key === " ") {
                  event.preventDefault();
                }
              }}
              className={`rounded-lg border p-4 ${scenario.isBase
                ? "bg-primary/5 border-primary ring-1 ring-primary/20"
                : "bg-card border-border"
                }`}
            >
              <div className="flex items-center justify-between mb-4">
                <h4 className="font-semibold">{scenario.name.charAt(0).toUpperCase() + scenario.name.slice(1)}</h4>
                {scenario.isBase && (
                  <span className="text-xs px-2 py-0.5 bg-primary text-primary-foreground rounded-full font-medium">
                    Base
                  </span>
                )}
              </div>

              <div className="space-y-4">
                <div className="flex items-center gap-3">
                  <TrendingUp className="w-4 h-4 text-muted-foreground" />
                  <div>
                    <p className="text-xs text-muted-foreground">ROI</p>
                    <p className="font-semibold">{formatPercent(scenario.roi)}</p>
                  </div>
                </div>

                <div className="flex items-center gap-3">
                  <DollarSign className="w-4 h-4 text-muted-foreground" />
                  <div>
                    <p className="text-xs text-muted-foreground">NPV</p>
                    <p className="font-semibold">{formatCurrency(scenario.npv)}</p>
                  </div>
                </div>

                <div className="flex items-center gap-3">
                  <Clock className="w-4 h-4 text-muted-foreground" />
                  <div>
                    <p className="text-xs text-muted-foreground">Payback</p>
                    <p className="font-semibold">{scenario.paybackMonths} months</p>
                  </div>
                </div>
              </div>

              <div className="mt-4 pt-4 border-t">
                <p className="text-xs text-muted-foreground mb-2">EVF Decomposition</p>
                <div className="space-y-1 text-xs">
                  <div className="flex justify-between">
                    <span>Revenue Uplift</span>
                    <span className="font-medium">{formatCurrency(scenario.evfDecomposition.revenueUplift)}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Cost Reduction</span>
                    <span className="font-medium">{formatCurrency(scenario.evfDecomposition.costReduction)}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Risk Mitigation</span>
                    <span className="font-medium">{formatCurrency(scenario.evfDecomposition.riskMitigation)}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Efficiency Gain</span>
                    <span className="font-medium">{formatCurrency(scenario.evfDecomposition.efficiencyGain)}</span>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default ScenarioComparison;

/**
 * SensitivityTornado Widget
 *
 * Horizontal bar chart showing assumption impact (positive and negative), clickable bars navigate to assumption.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.2
 */

import { ArrowRight, BarChart3 } from "lucide-react";
import React from "react";

import { WidgetProps } from "../CanvasHost";

export interface SensitivityItem {
  assumptionId: string;
  assumptionName: string;
  impactPositive: number; // +20% change
  impactNegative: number; // -20% change
  leverage: number;
}

export interface SensitivityTornadoData {
  tornadoData: SensitivityItem[];
  baseScenario: string;
}

export function SensitivityTornado({ data, onAction }: WidgetProps) {
  const widgetData = data as unknown as SensitivityTornadoData;
  const items = widgetData.tornadoData ?? [];

  // Sort by leverage (highest first)
  const sortedItems = [...items].sort((a, b) => b.leverage - a.leverage);

  // Find max value for scaling
  const maxValue = Math.max(
    ...items.map((i) => Math.max(Math.abs(i.impactPositive), Math.abs(i.impactNegative)))
  );

  const formatImpact = (value: number) => {
    const absValue = Math.abs(value);
    const formatted = `$${absValue.toLocaleString()}`;
    return value >= 0 ? `+${formatted}` : `-${formatted}`;
  };

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-primary/10 rounded-lg">
          <BarChart3 className="w-5 h-5 text-primary" />
        </div>
        <div>
          <h3 className="font-semibold text-lg">Sensitivity Analysis</h3>
          <p className="text-sm text-muted-foreground">
            Impact of ±20% assumption changes on NPV
          </p>
        </div>
      </div>

      {sortedItems.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          No sensitivity data available
        </div>
      ) : (
        <div className="space-y-3">
          {sortedItems.map((item) => {
            const positiveWidth = (Math.abs(item.impactPositive) / maxValue) * 100;
            const negativeWidth = (Math.abs(item.impactNegative) / maxValue) * 100;

            return (
              <div
                key={item.assumptionId}
                className="group cursor-pointer"
                onClick={() => onAction?.("navigate", { assumptionId: item.assumptionId })}
              >
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-sm font-medium flex-1">{item.assumptionName}</span>
                  <ArrowRight className="w-4 h-4 text-muted-foreground opacity-0 group-hover:opacity-100 transition-opacity" />
                </div>

                <div className="flex items-center gap-2">
                  {/* Negative impact bar */}
                  <div className="flex-1 flex justify-end">
                    <div
                      className="h-6 bg-red-400 rounded-l flex items-center justify-end px-2 text-xs text-white font-medium transition-all hover:bg-red-500"
                      style={{ width: `${negativeWidth}%` }}
                    >
                      {negativeWidth > 20 && formatImpact(item.impactNegative)}
                    </div>
                  </div>

                  {/* Center line */}
                  <div className="w-px h-8 bg-border" />

                  {/* Positive impact bar */}
                  <div className="flex-1">
                    <div
                      className="h-6 bg-green-400 rounded-r flex items-center px-2 text-xs text-white font-medium transition-all hover:bg-green-500"
                      style={{ width: `${positiveWidth}%` }}
                    >
                      {positiveWidth > 20 && formatImpact(item.impactPositive)}
                    </div>
                  </div>
                </div>

                {/* Leverage indicator */}
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-xs text-muted-foreground">
                    {item.leverage.toFixed(1)}x
                  </span>
                  <div className="flex-1 h-1 bg-muted rounded-full overflow-hidden">
                    <div
                      className="h-full bg-primary rounded-full"
                      style={{ width: `${Math.min(item.leverage * 10, 100)}%` }}
                    />
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

export default SensitivityTornado;

/**
 * StakeholderMap Widget
 *
 * Grid showing stakeholders with role, priority, and source badge.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.1
 */

import { SourceBadge, SourceType } from "@valueos/components/components/SourceBadge";
import { Building, User, Users } from "lucide-react";
import React from "react";

import { WidgetProps } from "../CanvasHost";

export interface Stakeholder {
  id: string;
  name: string;
  role: string;
  priority: "high" | "medium" | "low";
  source: SourceType;
  email?: string;
  department?: string;
}

export interface StakeholderMapData {
  stakeholders: Stakeholder[];
}

export function StakeholderMap({ data, onAction }: WidgetProps) {
  const widgetData = data as unknown as StakeholderMapData;
  const stakeholders = widgetData.stakeholders ?? [];

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case "high":
        return "bg-red-50 border-red-200 text-red-700";
      case "medium":
        return "bg-amber-50 border-amber-200 text-amber-700";
      case "low":
        return "bg-green-50 border-green-200 text-green-700";
      default:
        return "bg-gray-50 border-gray-200 text-gray-700";
    }
  };

  return (
    <div className="rounded-xl border bg-card p-6">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-primary/10 rounded-lg">
          <Users className="w-5 h-5 text-primary" />
        </div>
        <div>
          <h3 className="font-semibold text-lg">Stakeholder Map</h3>
          <p className="text-sm text-muted-foreground">{stakeholders.length} identified stakeholders</p>
        </div>
      </div>

      {stakeholders.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          <User className="w-12 h-12 mx-auto mb-3 opacity-50" />
          <p>No stakeholders identified yet</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {stakeholders.map((stakeholder) => (
            <div
              key={stakeholder.id}
              className={`p-4 rounded-lg border ${getPriorityColor(stakeholder.priority)} transition-all hover:shadow-sm cursor-pointer`}
              onClick={() => onAction?.("select", { stakeholderId: stakeholder.id })}
              role="button"
              tabIndex={0}
              onKeyDown={(e) => {
                if (e.key === "Enter" || e.key === " ") {
                  onAction?.("select", { stakeholderId: stakeholder.id });
                }
              }}
            >
              <div className="flex items-start justify-between mb-2">
                <div className="flex items-center gap-2">
                  <Building className="w-4 h-4 opacity-75" />
                  <span className="font-medium">{stakeholder.name}</span>
                </div>
                <span
                  className={`text-xs px-2 py-0.5 rounded-full font-medium ${stakeholder.priority === "high"
                    ? "bg-red-100 text-red-800"
                    : stakeholder.priority === "medium"
                      ? "bg-amber-100 text-amber-800"
                      : "bg-green-100 text-green-800"
                    }`}
                >
                  {stakeholder.priority}
                </span>
              </div>

              <p className="text-sm opacity-75 mb-2">{stakeholder.role}</p>

              {stakeholder.department && (
                <p className="text-xs opacity-60 mb-2">{stakeholder.department}</p>
              )}

              <div className="mt-3">
                <SourceBadge sourceType={stakeholder.source} size="sm" showTier={false} />
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default StakeholderMap;

/**
 * UsageMeter Widget
 *
 * Horizontal bar showing used/cap with percentage, color shifts at 80% and 100%, reset date.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §3.6
 */

import { Gauge, Zap } from "lucide-react";
import React from "react";

import { WidgetProps } from "../CanvasHost";

export interface UsageMeterData {
  meterName: string;
  meterKey: string;
  used: number;
  cap: number;
  unit: string;
  resetDate: string;
  trend: "up" | "down" | "flat";
  trendPercentage: number;
}

export function UsageMeter({ data }: WidgetProps) {
  const widgetData = data as unknown as UsageMeterData;
  const { meterName, used, cap, unit, resetDate, trend, trendPercentage } = widgetData;

  const percentage = Math.min((used / cap) * 100, 100);

  // Color logic: green < 80%, amber 80-100%, red > 100%
  const getBarColor = () => {
    if (percentage >= 100) return "bg-red-500";
    if (percentage >= 80) return "bg-amber-500";
    return "bg-green-500";
  };

  const getStatusText = () => {
    if (percentage >= 100) return "Over limit";
    if (percentage >= 80) return "Approaching limit";
    return "Within limit";
  };

  const getStatusColor = () => {
    if (percentage >= 100) return "text-red-600";
    if (percentage >= 80) return "text-amber-600";
    return "text-green-600";
  };

  const formatValue = (value: number) => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(0)}K`;
    return value.toLocaleString();
  };

  return (
    <div className="rounded-xl border bg-card p-5">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-primary/10 rounded-lg">
            <Gauge className="w-5 h-5 text-primary" />
          </div>
          <div>
            <h4 className="font-semibold">{meterName}</h4>
            <p className="text-xs text-muted-foreground">
              Resets {new Date(resetDate).toLocaleDateString()}
            </p>
          </div>
        </div>
        <div className="text-right">
          <p className={`text-sm font-medium ${getStatusColor()}`}>{getStatusText()}</p>
          <p className="text-xs text-muted-foreground">{percentage.toFixed(1)}% used</p>
        </div>
      </div>

      {/* Usage bar */}
      <div className="mb-3">
        <div className="h-3 bg-muted rounded-full overflow-hidden">
          <div
            className={`h-full rounded-full transition-all duration-500 ${getBarColor()}`}
            style={{ width: `${Math.min(percentage, 100)}%` }}
          />
        </div>
      </div>

      {/* Usage details */}
      <div className="flex items-center justify-between text-sm">
        <div>
          <span className="text-muted-foreground">Used: </span>
          <span className="font-medium">{formatValue(used)}</span>
          <span className="text-muted-foreground"> {unit}</span>
        </div>
        <div>
          <span className="text-muted-foreground">Cap: </span>
          <span className="font-medium">{formatValue(cap)}</span>
          <span className="text-muted-foreground"> {unit}</span>
        </div>
      </div>

      {/* Trend indicator */}
      <div className="mt-3 flex items-center gap-2 text-xs">
        <Zap className="w-3.5 h-3.5 text-muted-foreground" />
        <span className="text-muted-foreground">Trend:</span>
        <span
          className={`font-medium ${
            trend === "up" ? "text-red-600" : trend === "down" ? "text-green-600" : "text-gray-600"
          }`}
        >
          {trend === "up" ? "↑" : trend === "down" ? "↓" : "→"} {Math.abs(trendPercentage).toFixed(1)}%
        </span>
        <span className="text-muted-foreground">vs last period</span>
      </div>

      {/* Warning at 80%+ */}
      {percentage >= 80 && percentage < 100 && (
        <div className="mt-3 p-2 bg-amber-50 border border-amber-200 rounded-lg text-sm text-amber-800">
          Approaching usage limit. Consider upgrading your plan.
        </div>
      )}

      {/* Error at 100%+ */}
      {percentage >= 100 && (
        <div className="mt-3 p-2 bg-red-50 border border-red-200 rounded-lg text-sm text-red-800">
          Usage limit exceeded. Additional charges may apply.
        </div>
      )}
    </div>
  );
}

export default UsageMeter;

