import { AlertTriangle, Loader2, X } from "lucide-react";
import { useEffect, useRef, useState } from "react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { logger } from "@/lib/logger";

interface ConfirmationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void | Promise<void>;
  title: string;
  message: string;
  confirmText?: string;
  requireTypedConfirmation?: boolean;
  confirmationPhrase?: string;
  isDangerous?: boolean;
}

export function ConfirmationModal({
  isOpen,
  onClose,
  onConfirm,
  title,
  message,
  confirmText = "Confirm",
  requireTypedConfirmation = false,
  confirmationPhrase = "DELETE",
  isDangerous = false,
}: ConfirmationModalProps) {
  const [typedText, setTypedText] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
      // Store the previously focused element to restore focus on close
      const previousFocus = document.activeElement as HTMLElement | null;

      const timer = setTimeout(() => {
        if (requireTypedConfirmation && inputRef.current) {
          inputRef.current.focus();
        } else {
          // Focus the confirm button by default for keyboard accessibility
          const confirmButton = modalRef.current?.querySelector('[data-confirm-button]') as HTMLElement;
          confirmButton?.focus();
        }
      }, 100);

      return () => {
        clearTimeout(timer);
        // Restore focus when modal closes
        previousFocus?.focus();
      };
    } else {
      setTypedText("");
      setIsProcessing(false);
    }

    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === "Escape" && isOpen && !isProcessing) {
        onClose();
      }
    };

    document.addEventListener("keydown", handleEscape);
    return () => document.removeEventListener("keydown", handleEscape);
  }, [isOpen, requireTypedConfirmation, isProcessing, onClose]);

  const handleConfirm = async () => {
    setIsProcessing(true);
    try {
      await onConfirm();
      onClose();
    } catch (error) {
      logger.error("Confirmation action failed:", error);
    } finally {
      setIsProcessing(false);
    }
  };

  const canConfirm = requireTypedConfirmation
    ? typedText === confirmationPhrase
    : true;

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4"
      onClick={(e) => {
        if (e.target === e.currentTarget && !isProcessing) {
          onClose();
        }
      }}
      role="dialog"
      aria-modal="true"
      aria-labelledby="modal-title"
    >
      <div
        ref={modalRef}
        className="bg-card text-card-foreground rounded-lg shadow-lg border max-w-md w-full"
      >
        <div className="flex items-start justify-between p-6 border-b">
          <div className="flex items-start gap-3">
            {isDangerous && (
              <div className="flex-shrink-0 p-2 bg-destructive/10 rounded-lg">
                <AlertTriangle
                  className="h-6 w-6 text-destructive"
                  aria-hidden="true"
                />
              </div>
            )}
            <h3 id="modal-title" className="text-lg font-semibold">
              {title}
            </h3>
          </div>
          <button
            onClick={onClose}
            disabled={isProcessing}
            className="p-1 hover:bg-muted rounded transition-colors disabled:opacity-50"
            aria-label="Close dialog"
          >
            <X className="h-5 w-5" />
          </button>
        </div>

        <div className="p-6 space-y-4">
          <p className="text-muted-foreground">{message}</p>

          {requireTypedConfirmation && (
            <div className="space-y-2">
              <Label htmlFor="confirmation-input">
                Type{" "}
                <strong className={isDangerous ? "text-destructive" : ""}>
                  {confirmationPhrase}
                </strong>{" "}
                to confirm
              </Label>
              <Input
                ref={inputRef}
                id="confirmation-input"
                type="text"
                value={typedText}
                onChange={(e) => setTypedText(e.target.value)}
                placeholder={`Type ${confirmationPhrase}`}
                disabled={isProcessing}
              />
            </div>
          )}
        </div>

        <div className="flex justify-end gap-3 px-6 py-4 bg-muted/50 rounded-b-lg">
          <Button variant="outline" onClick={onClose} disabled={isProcessing}>
            Cancel
          </Button>
          <Button
            variant={isDangerous ? "destructive" : "default"}
            onClick={handleConfirm}
            disabled={!canConfirm || isProcessing}
            data-confirm-button
          >
            {isProcessing && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
            {isProcessing ? "Processing..." : confirmText}
          </Button>
        </div>
      </div>
    </div>
  );
}

import { AlertTriangle, Home, MessageSquare, RefreshCw, Wifi, WifiOff } from "lucide-react";
import { Component, ErrorInfo, ReactNode } from "react";

import { Alert, AlertDescription } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import { safeNavigate, safeReload, navigateToLogin } from "@/lib/safeNavigation";
import { logger } from "@/lib/logger";

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
  context?: string; // Context where the error occurred (e.g., "dashboard", "canvas")
  showDetails?: boolean; // Whether to show error details in production
}

interface State {
  hasError: boolean;
  error?: Error;
  retryCount: number;
}

export class ErrorBoundary extends Component<Props, State> {
  private maxRetries = 3;

  constructor(props: Props) {
    super(props);
    this.state = { hasError: false, retryCount: 0 };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error, retryCount: 0 };
  }

  override componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    logger.error("ErrorBoundary caught an error:", error, errorInfo);
    this.props.onError?.(error, errorInfo);
  }

  handleReset = () => {
    if (this.state.retryCount < this.maxRetries) {
      this.setState(
        (prev) =>
          ({
            hasError: false,
            retryCount: prev.retryCount + 1,
          }) as State
      );
    } else {
      // After max retries, redirect to home safely
      safeNavigate("/dashboard", { fallback: "/login" });
    }
  };

  getErrorType = (error: Error): "network" | "auth" | "data" | "unknown" => {
    const message = error.message.toLowerCase();
    if (
      message.includes("network") ||
      message.includes("fetch") ||
      message.includes("connection")
    ) {
      return "network";
    }
    if (
      message.includes("auth") ||
      message.includes("unauthorized") ||
      message.includes("forbidden")
    ) {
      return "auth";
    }
    if (message.includes("data") || message.includes("parse") || message.includes("json")) {
      return "data";
    }
    return "unknown";
  };

  getErrorMessage = (errorType: string, context?: string) => {
    const messages = {
      network: {
        title: "Connection Problem",
        description:
          "Unable to connect to our servers. Please check your internet connection and try again.",
        icon: WifiOff,
      },
      auth: {
        title: "Authentication Required",
        description: "Your session has expired. Please sign in again to continue.",
        icon: MessageSquare,
      },
      data: {
        title: "Data Loading Error",
        description: `Unable to load ${context || "content"}. The data might be temporarily unavailable.`,
        icon: AlertTriangle,
      },
      unknown: {
        title: "Something went wrong",
        description: "We encountered an unexpected error. Our team has been notified.",
        icon: AlertTriangle,
      },
    };

    return messages[errorType as keyof typeof messages] || messages.unknown;
  };

  override render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback;
      }

      const errorType = this.state.error ? this.getErrorType(this.state.error) : "unknown";
      const {
        title,
        description,
        icon: Icon,
      } = this.getErrorMessage(errorType, this.props.context);
      const showDetails = this.props.showDetails || import.meta.env.DEV;
      const canRetry = this.state.retryCount < this.maxRetries;

      return (
        <div
          className="flex items-center justify-center min-h-screen bg-background px-4"
          role="alert"
          aria-labelledby="error-title"
        >
          <div className="max-w-md w-full bg-card rounded-lg shadow-lg p-8 text-center border">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-destructive/10 rounded-full mb-4">
              <Icon className="h-8 w-8 text-destructive" aria-hidden="true" />
            </div>

            <h1 id="error-title" className="text-2xl font-bold text-foreground mb-2">
              {title}
            </h1>

            <p className="text-muted-foreground mb-6">{description}</p>

            {errorType === "network" && (
              <Alert className="mb-6 text-left">
                <Wifi className="h-4 w-4" />
                <AlertDescription>
                  <strong>Troubleshooting tips:</strong>
                  <ul className="list-disc list-inside mt-2 space-y-1 text-sm">
                    <li>Check your internet connection</li>
                    <li>Try refreshing the page</li>
                    <li>Clear your browser cache</li>
                  </ul>
                </AlertDescription>
              </Alert>
            )}

            {showDetails && this.state.error && (
              <details className="text-left mb-6 p-4 bg-muted rounded-lg">
                <summary className="cursor-pointer text-sm font-medium text-foreground mb-2">
                  Error Details{" "}
                  {this.state.retryCount > 0 && `(Attempt ${this.state.retryCount + 1})`}
                </summary>
                <pre className="text-xs text-destructive overflow-auto whitespace-pre-wrap">
                  {this.state.error.toString()}
                  {this.state.error.stack}
                </pre>
              </details>
            )}

            <div className="flex flex-col sm:flex-row gap-3 justify-center">
              {canRetry ? (
                <Button onClick={this.handleReset}>
                  <RefreshCw className="h-4 w-4 mr-2" aria-hidden="true" />
                  Try Again{" "}
                  {this.state.retryCount > 0 && `(${this.state.retryCount}/${this.maxRetries})`}
                </Button>
              ) : (
                <Button onClick={() => window.location.reload()}>
                  <RefreshCw className="h-4 w-4 mr-2" aria-hidden="true" />
                  Reload Page
                </Button>
              )}

              <Button variant="outline" onClick={() => safeNavigate("/dashboard", { fallback: "/login" })}>
                <Home className="h-4 w-4 mr-2" aria-hidden="true" />
                Go to Home
              </Button>
            </div>

            {errorType === "auth" && (
              <p className="text-xs text-muted-foreground mt-4">
                <button
                  onClick={() => navigateToLogin()}
                  className="underline hover:text-foreground bg-transparent border-none cursor-pointer p-0"
                >
                  Click here to sign in
                </button>
              </p>
            )}
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

/**
 * LoadingOverlay
 *
 * Full-area or inline loading indicator with contextual status messages.
 * Prevents the "silent interface" anti-pattern.
 *
 * UX Principles:
 * - Immediate Feedback: spinner + message tells user the system is working
 * - System Status: contextual message explains what's happening
 * - Accessibility: role="status", aria-live for screen readers
 */

import { Loader2 } from "lucide-react";
import React from "react";

import { cn } from "@/lib/utils";

export interface LoadingOverlayProps {
  /** What the system is doing (e.g., "Analyzing financial models...") */
  message?: string;
  /** Secondary detail (e.g., "Step 2 of 7") */
  detail?: string;
  /** Whether to cover the full parent area with a backdrop */
  overlay?: boolean;
  /** Size of the spinner */
  size?: "sm" | "md" | "lg";
  className?: string;
}

const sizeConfig = {
  sm: { spinner: "h-4 w-4", text: "text-xs", gap: "gap-2" },
  md: { spinner: "h-6 w-6", text: "text-sm", gap: "gap-3" },
  lg: { spinner: "h-8 w-8", text: "text-base", gap: "gap-4" },
};

export function LoadingOverlay({
  message = "Loading...",
  detail,
  overlay = false,
  size = "md",
  className,
}: LoadingOverlayProps) {
  const sizes = sizeConfig[size];

  const content = (
    <div
      className={cn(
        "flex flex-col items-center justify-center",
        sizes.gap,
        !overlay && "py-12",
        className
      )}
      role="status"
      aria-live="polite"
      aria-busy="true"
    >
      <Loader2 className={cn("animate-spin text-primary", sizes.spinner)} />
      <div className="text-center">
        <p className={cn("font-medium text-foreground", sizes.text)}>{message}</p>
        {detail && (
          <p className={cn("text-muted-foreground mt-0.5", size === "sm" ? "text-[10px]" : "text-xs")}>
            {detail}
          </p>
        )}
      </div>
    </div>
  );

  if (overlay) {
    return (
      <div className="absolute inset-0 z-10 flex items-center justify-center bg-background/80 backdrop-blur-sm rounded-lg">
        {content}
      </div>
    );
  }

  return content;
}

import { Loader2 } from "lucide-react";

interface LoadingSpinnerProps {
  size?: "sm" | "md" | "lg";
  label?: string;
  fullScreen?: boolean;
}

export function LoadingSpinner({
  size = "md",
