    if (!dealName.trim()) {
      setError('Deal name is required');
      return;
    }
    if (!company.trim()) {
      setError('Company name is required');
      return;
    }

    setIsSubmitting(true);
    setError(null);

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1000));

      // Generate a mock deal ID
      const newDealId = `deal-${Date.now()}`;

      // In a real implementation, this would:
      // 1. Create the deal in the local database
      // 2. If syncToCRM is true, also create in the selected CRM
      // 3. Return the deal ID

      onDealImported(newDealId);
      onClose();
    } catch (err) {
      setError('Failed to create deal. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  }, [dealName, company, onDealImported, onClose]);

  // Role check
  if (!isCloser) {
    return (
      <Dialog open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
        <DialogContent className="sm:max-w-[450px]">
          <DialogHeader>
            <DialogTitle>Create New Deal</DialogTitle>
          </DialogHeader>
          <div className="py-6">
            <Card className="p-4 bg-amber-50 border-amber-200">
              <div className="flex items-start gap-3">
                <AlertCircle className="w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5" />
                <div>
                  <p className="font-medium text-amber-800">Closer Role Required</p>
                  <p className="text-sm text-amber-700 mt-1">
                    Only users with the Closer role can create new deals.
                    Please contact your sales manager for assistance.
                  </p>
                </div>
              </div>
            </Card>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={onClose}>
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    );
  }

  return (
    <Dialog open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle>Create New Deal</DialogTitle>
          <DialogDescription>
            Create a new deal and optionally sync it to your CRM.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4 py-4">
          {/* Deal Name */}
          <div className="space-y-2">
            <Label htmlFor="deal-name">Deal Name *</Label>
            <Input
              id="deal-name"
              placeholder="e.g., Acme Corp Q2 Expansion"
              value={dealName}
              onChange={(e) => setDealName(e.target.value)}
            />
          </div>

          {/* Company */}
          <div className="space-y-2">
            <Label htmlFor="company">Company *</Label>
            <div className="relative">
              <Building2 className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
              <Input
                id="company"
                placeholder="Company name"
                value={company}
                onChange={(e) => setCompany(e.target.value)}
                className="pl-9"
              />
            </div>
          </div>

          {/* Amount and Stage */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="amount">Amount</Label>
              <div className="relative">
                <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input
                  id="amount"
                  type="number"
                  placeholder="0"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  className="pl-9"
                />
              </div>
              {suggestedAmount && (
                <p className="text-xs text-muted-foreground">
                  Suggested from Value Model: ${suggestedAmount.toLocaleString()}
                </p>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="stage">Stage</Label>
              <Select value={stage} onValueChange={(v) => setStage(v as Deal['stage'])}>
                <SelectTrigger>
                  <SelectValue placeholder="Select stage" />
                </SelectTrigger>
                <SelectContent>
                  {STAGE_OPTIONS.map((option) => (
                    <SelectItem key={option.value} value={option.value}>
                      {option.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          {/* Close Date */}
          <div className="space-y-2">
            <Label htmlFor="close-date">Expected Close Date</Label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
              <Input
                id="close-date"
                type="date"
                value={closeDate}
                onChange={(e) => setCloseDate(e.target.value)}
                className="pl-9"
              />
            </div>
          </div>

          {/* CRM Sync */}
          {availableCRMs.length > 0 && (
            <Card className="p-4">
              <div className="flex items-center gap-2 mb-3">
                <Checkbox
                  id="sync-crm"
                  checked={syncToCRM}
                  onCheckedChange={(checked) => setSyncToCRM(checked === true)}
                />
                <Label htmlFor="sync-crm" className="font-medium">
                  Create in CRM
                </Label>
              </div>

              {syncToCRM && (
                <div className="space-y-2 pl-6">
                  <Label htmlFor="crm-select">Select CRM</Label>
                  <Select
                    value={selectedCRM || undefined}
                    onValueChange={setSelectedCRM}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select CRM" />
                    </SelectTrigger>
                    <SelectContent>
                      {availableCRMs.map((crm) => (
                        <SelectItem key={crm} value={crm}>
                          {CRM_LABELS[crm]}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <p className="text-xs text-muted-foreground flex items-center gap-1">
                    <ExternalLink className="w-3 h-3" />
                    Deal will be created in {selectedCRM ? CRM_LABELS[selectedCRM] : 'selected CRM'}
                  </p>
                </div>
              )}
            </Card>
          )}

          {/* Error Message */}
          {error && (
            <div className="flex items-center gap-2 p-3 rounded-lg bg-red-50 border border-red-200 text-red-700">
              <AlertCircle className="w-4 h-4 flex-shrink-0" />
              <p className="text-sm">{error}</p>
            </div>
          )}
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={onClose} disabled={isSubmitting}>
            Cancel
          </Button>
          <Button onClick={handleSubmit} disabled={isSubmitting}>
            {isSubmitting ? (
              <>
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                Creating...
              </>
            ) : (
              <>
                <CheckCircle2 className="w-4 h-4 mr-2" />
                Create Deal
              </>
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

/**
 * DealLinkModal Component
 *
 * Connects an existing Value Case to a CRM Deal.
 * Workflow:
 * 1. User clicks "Link Deal" in capsule
 * 2. Searches CRM (mocked or real) for open opportunities
 * 3. Selects a deal
 * 4. System establishes deal_id on the value_case record
 */

import { Building2, Calendar, DollarSign, ExternalLink, Loader2, Search } from 'lucide-react';
import { useCallback, useEffect, useState } from 'react';

import type { Deal } from './DealStatusCapsule';

import { apiClient } from '@/api/client/unified-api-client';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { cn } from '@/lib/utils';


export interface CRMDeal extends Deal {
  company: string;
  owner?: string;
  lastActivity?: Date;
}

/** Shape returned by GET /api/crm/deals */
interface ApiCRMDeal {
  id: string;
  externalId: string;
  provider: string;
  name: string;
  amount?: number;
  stage: string;
  closeDate?: string;
  ownerName?: string;
  companyName?: string;
}

const VALID_STAGES = new Set<Deal['stage']>([
  'prospecting', 'qualification', 'proposal',
  'negotiation', 'closed_won', 'closed_lost',
]);

function toLocalStage(raw: string): Deal['stage'] {
  const normalised = raw.toLowerCase().replace(/\s+/g, '_') as Deal['stage'];
  return VALID_STAGES.has(normalised) ? normalised : 'prospecting';
}

function mapApiDeal(d: ApiCRMDeal): CRMDeal {
  return {
    id: d.id,
    name: d.name,
    stage: toLocalStage(d.stage),
    amount: d.amount,
    closeDate: d.closeDate ? new Date(d.closeDate) : undefined,
    crmId: d.externalId,
    crmSource: (d.provider === 'salesforce' || d.provider === 'hubspot' || d.provider === 'pipedrive')
      ? d.provider
      : undefined,
    company: d.companyName ?? '',
    owner: d.ownerName,
  };
}

export interface DealLinkModalProps {
  /** Whether the modal is open */
  open: boolean;
  /** Callback when modal is closed */
  onClose: () => void;
  /** Callback when a deal is selected and linked */
  onLinkDeal: (deal: CRMDeal) => void;
  /** Current value case ID for context */
  valueCaseId: string;
  /** Optional: pre-filter by company name */
  companyFilter?: string;
}

const STAGE_COLORS: Record<Deal['stage'], string> = {
  prospecting: 'bg-slate-100 text-slate-700',
  qualification: 'bg-blue-100 text-blue-700',
  proposal: 'bg-purple-100 text-purple-700',
  negotiation: 'bg-amber-100 text-amber-700',
  closed_won: 'bg-green-100 text-green-700',
  closed_lost: 'bg-red-100 text-red-700',
};

const STAGE_LABELS: Record<Deal['stage'], string> = {
  prospecting: 'Prospecting',
  qualification: 'Qualification',
  proposal: 'Proposal',
  negotiation: 'Negotiation',
  closed_won: 'Closed Won',
  closed_lost: 'Closed Lost',
};

function formatCurrency(amount: number): string {
  if (amount >= 1_000_000) {
    return `$${(amount / 1_000_000).toFixed(1)}M`;
  }
  if (amount >= 1_000) {
    return `$${(amount / 1_000).toFixed(0)}K`;
  }
  return `$${amount.toLocaleString()}`;
}

function formatDate(date: Date): string {
  return new Intl.DateTimeFormat('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  }).format(date);
}



export function DealLinkModal({
  open,
  onClose,
  onLinkDeal,
  valueCaseId,
  companyFilter,
}: DealLinkModalProps) {
  const [searchQuery, setSearchQuery] = useState(companyFilter || '');
  const [deals, setDeals] = useState<CRMDeal[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedDeal, setSelectedDeal] = useState<CRMDeal | null>(null);

  const searchDeals = useCallback(async (query: string) => {
    setIsLoading(true);
    try {
      const params = query ? { q: query } : undefined;
      const res = await apiClient.get<{ deals: ApiCRMDeal[] }>('/api/crm/deals', params);
      setDeals((res.data?.deals ?? []).map(mapApiDeal));
    } catch {
      setDeals([]);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (open) {
      searchDeals(searchQuery);
    }
  }, [open, searchQuery, searchDeals]);

  const handleLink = () => {
    if (selectedDeal) {
      onLinkDeal(selectedDeal);
      onClose();
    }
  };

  return (
    <Dialog open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
      <DialogContent className="sm:max-w-[600px]">
        <DialogHeader>
          <DialogTitle>Link to CRM Deal</DialogTitle>
          <DialogDescription>
            Search for an existing deal in your CRM to link with this Value Case.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          {/* Search Input */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <Input
              placeholder="Search deals by name or company..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-9"
            />
          </div>

          {/* Deal List */}
          <ScrollArea className="h-[300px] border rounded-lg">
            {isLoading ? (
              <div className="flex items-center justify-center h-full">
                <Loader2 className="w-6 h-6 animate-spin text-muted-foreground" />
              </div>
            ) : deals.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-muted-foreground">
                <Building2 className="w-8 h-8 mb-2 opacity-50" />
                <p className="text-sm">No deals found</p>
                <p className="text-xs">Try a different search term</p>
              </div>
            ) : (
              <div className="p-2 space-y-2">
                {deals.map((deal) => (
                  <button
                    key={deal.id}
                    onClick={() => setSelectedDeal(deal)}
                    className={cn(
                      'w-full p-3 rounded-lg border text-left transition-colors',
                      'hover:bg-accent hover:border-accent-foreground/20',
                      selectedDeal?.id === deal.id
                        ? 'bg-accent border-primary'
                        : 'bg-card border-border'
                    )}
                  >
                    <div className="flex items-start justify-between gap-2">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1">
                          <span className="font-medium truncate">{deal.name}</span>
                          <Badge className={cn('text-xs', STAGE_COLORS[deal.stage])}>
                            {STAGE_LABELS[deal.stage]}
                          </Badge>
                        </div>
                        <div className="flex items-center gap-3 text-sm text-muted-foreground">
                          <span className="flex items-center gap-1">
                            <Building2 className="w-3 h-3" />
                            {deal.company}
                          </span>
                          {deal.amount && (
                            <span className="flex items-center gap-1">
                              <DollarSign className="w-3 h-3" />
                              {formatCurrency(deal.amount)}
                            </span>
                          )}
                          {deal.closeDate && (
                            <span className="flex items-center gap-1">
                              <Calendar className="w-3 h-3" />
                              {formatDate(deal.closeDate)}
                            </span>
                          )}
                        </div>
                      </div>
                      {deal.crmSource && (
                        <Badge variant="outline" className="text-xs capitalize">
                          {deal.crmSource}
                        </Badge>
                      )}
                    </div>
                  </button>
                ))}
              </div>
            )}
          </ScrollArea>

          {/* Selected Deal Preview */}
          {selectedDeal && (
            <div className="p-3 rounded-lg bg-muted/50 border">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium">Selected Deal</p>
                  <p className="text-sm text-muted-foreground">{selectedDeal.name}</p>
                </div>
                {selectedDeal.crmId && (
                  <Button variant="ghost" size="sm" asChild>
                    <a
                      href={`#crm/${selectedDeal.crmSource}/${selectedDeal.crmId}`}
                      target="_blank"
                      rel="noopener noreferrer"
                    >
                      <ExternalLink className="w-4 h-4 mr-1" />
                      View in CRM
                    </a>
                  </Button>
                )}
              </div>
            </div>
          )}
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={onClose}>
            Cancel
          </Button>
          <Button onClick={handleLink} disabled={!selectedDeal}>
            Link Deal
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

