import { Camera, MessageSquareText, Send } from "lucide-react";
import { useEffect, useMemo, useState } from "react";

import { apiClient } from "@/api/client/unified-api-client";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { analyticsClient } from "@/lib/analyticsClient";
import { getConsoleLogs, startConsoleCapture } from "@/utils/consoleRecorder";
import { logger } from "@/lib/logger";

const FEEDBACK_TAG = "beta_cohort";

type FeedbackPayload = {
  message: string;
  screenshot: string | null;
  userAgent: string;
  consoleLogs: ReturnType<typeof getConsoleLogs>;
  tags: string[];
  createdAt: string;
};

async function captureScreenshot(): Promise<string | null> {
  if (typeof navigator === "undefined" || !navigator.mediaDevices?.getDisplayMedia) {
    return null;
  }

  const stream = await navigator.mediaDevices.getDisplayMedia({
    video: { displaySurface: "browser" },
    audio: false,
  } as DisplayMediaStreamOptions);

  const video = document.createElement("video");
  video.srcObject = stream;
  await video.play();

  await new Promise((resolve) => {
    video.onloadeddata = resolve;
  });

  const canvas = document.createElement("canvas");
  canvas.width = video.videoWidth;
  canvas.height = video.videoHeight;

  const ctx = canvas.getContext("2d");
  if (ctx) {
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
  }

  stream.getTracks().forEach((track) => track.stop());

  return canvas.toDataURL("image/png");
}

export function BetaFeedbackWidget() {
  const [open, setOpen] = useState(false);
  const [message, setMessage] = useState("");
  const [screenshot, setScreenshot] = useState<string | null>(null);
  const [isCapturing, setIsCapturing] = useState(false);
  const [captureError, setCaptureError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    startConsoleCapture();
  }, []);

  const userAgent = useMemo(
    () => (typeof navigator === "undefined" ? "unknown" : navigator.userAgent),
    []
  );

  useEffect(() => {
    if (!open) return;
    if (screenshot || isCapturing) return;

    const runCapture = async () => {
      setCaptureError(null);
      setIsCapturing(true);
      try {
        const dataUrl = await captureScreenshot();
        if (dataUrl) {
          setScreenshot(dataUrl);
        } else {
          setCaptureError("Screen capture is not available in this browser.");
        }
      } catch (error) {
        setCaptureError(
          error instanceof Error
            ? error.message
            : "Unable to capture a screenshot. Please try again."
        );
      } finally {
        setIsCapturing(false);
      }
    };

    void runCapture();
  }, [open, screenshot, isCapturing]);

  const handleSubmit = async () => {
    const logs = getConsoleLogs().slice(-100);
    const payload: FeedbackPayload = {
      message,
      screenshot,
      userAgent,
      consoleLogs: logs,
      tags: [FEEDBACK_TAG],
      createdAt: new Date().toISOString(),
    };

    setIsSubmitting(true);
    analyticsClient.trackWorkflowEvent("beta_feedback_submitted", "support", {
      has_screenshot: Boolean(screenshot),
      log_count: logs.length,
      tags: payload.tags,
    });

    try {
      await apiClient.post("/api/feedback", payload);
    } catch (error) {
      logger.warn("Feedback submission failed", error);
    } finally {
      setIsSubmitting(false);
      setMessage("");
      setScreenshot(null);
      setOpen(false);
    }
  };

  const handleRecapture = async () => {
    setCaptureError(null);
    setIsCapturing(true);
    try {
      const dataUrl = await captureScreenshot();
      if (dataUrl) {
        setScreenshot(dataUrl);
      } else {
        setCaptureError("Screen capture is not available in this browser.");
      }
    } catch (error) {
      setCaptureError(
        error instanceof Error
          ? error.message
          : "Unable to capture a screenshot. Please try again."
      );
    } finally {
      setIsCapturing(false);
    }
  };

  return (
    <>
      <Button
        className="fixed bottom-6 right-6 z-50 flex items-center gap-2 rounded-full shadow-lg"
        onClick={() => setOpen(true)}
        aria-label="Send beta feedback"
      >
        <MessageSquareText className="h-4 w-4" />
        Beta Feedback
      </Button>

      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className="sm:max-w-2xl">
          <DialogHeader>
            <DialogTitle>Send Beta Feedback</DialogTitle>
            <DialogDescription>
              Share your feedback with our beta team. We automatically attach a screenshot, browser
              details, and recent console logs.
            </DialogDescription>
          </DialogHeader>

          <div className="grid gap-4 sm:grid-cols-[1.1fr_0.9fr]">
            <div className="space-y-3">
              <div className="space-y-2">
                <Label htmlFor="feedback-message">Feedback</Label>
                <Textarea
                  id="feedback-message"
                  value={message}
                  onChange={(event) => setMessage(event.target.value)}
                  placeholder="Describe the issue or idea..."
                  className="min-h-[180px]"
                />
              </div>
              <div className="rounded-lg border border-border bg-muted/50 p-3 text-xs text-muted-foreground">
                <div className="font-medium text-foreground">Browser</div>
                <p className="mt-1 break-words">{userAgent}</p>
              </div>
            </div>

            <div className="space-y-3">
              <div className="flex items-center justify-between text-sm">
                <span className="font-medium text-foreground">Screenshot</span>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleRecapture}
                  disabled={isCapturing}
                >
                  <Camera className="mr-2 h-4 w-4" />
                  {isCapturing ? "Capturing..." : "Recapture"}
                </Button>
              </div>
              <div className="flex min-h-[180px] items-center justify-center rounded-lg border border-dashed border-border bg-muted/30">
                {screenshot ? (
                  <img
                    src={screenshot}
                    alt="Captured screenshot"
                    className="max-h-[200px] w-full rounded-lg object-contain"
                  />
                ) : (
                  <div className="text-xs text-muted-foreground">
                    {isCapturing ? "Capturing screenshot..." : "No screenshot available."}
                  </div>
                )}
              </div>
              {captureError && (
                <p className="text-xs text-red-500">{captureError}</p>
              )}
            </div>
          </div>

          <DialogFooter className="gap-2 sm:gap-0">
            <Button variant="outline" onClick={() => setOpen(false)}>
              Cancel
            </Button>
            <Button
              onClick={handleSubmit}
              disabled={!message.trim()}
              loading={isSubmitting}
            >
              {!isSubmitting && <Send className="mr-2 h-4 w-4" />}
              {isSubmitting ? "Sending..." : "Submit Feedback"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { zodResolver } from "@hookform/resolvers/zod";
import { AlertCircle, Check, CheckCircle, Loader2 } from "lucide-react";
import { ReactNode, useId } from "react";
import {
  DefaultValues,
  FieldError,
  FieldValues,
  Path,
  SubmitHandler,
  useForm,
  UseFormReturn,
} from "react-hook-form";
import type { ZodType } from "zod";

import { cn } from "@/lib/utils";

export interface FormOptions<T extends FieldValues> {
  schema?: ZodType<T>;
  defaultValues?: DefaultValues<T>;
  mode?: "onChange" | "onBlur" | "onSubmit" | "onTouched" | "all";
}

export function useFormWithValidation<T extends FieldValues>(
  options: FormOptions<T> = {}
): UseFormReturn<T> {
  const { schema, defaultValues, mode = "onChange" } = options;

  return useForm<T>({

    resolver: schema ? zodResolver(schema as Parameters<typeof zodResolver>[0]) : undefined,
    defaultValues,
    mode,
  });
}

interface FormProps<T extends FieldValues> {
  form: UseFormReturn<T>;
  onSubmit: SubmitHandler<T>;
  children: ReactNode;
  className?: string;
  loading?: boolean;
  disabled?: boolean;
  submitLabel?: string;
  cancelLabel?: string;
  onCancel?: () => void;
}

export function Form<T extends FieldValues>({
  form,
  onSubmit,
  children,
  className,
  loading = false,
  disabled = false,
  submitLabel = "Submit",
  cancelLabel = "Cancel",
  onCancel,
}: FormProps<T>) {
  const {
    handleSubmit,
    formState: { isSubmitting },
  } = form;

  return (
    <form onSubmit={handleSubmit(onSubmit)} className={className} noValidate>
      {children}

      <div className="flex justify-end gap-3 mt-6 pt-4 border-t">
        {onCancel && (
          <button
            type="button"
            onClick={onCancel}
            disabled={loading || disabled}
            className="px-4 py-2 border rounded-md text-muted-foreground hover:bg-muted disabled:opacity-50 transition-colors"
          >
            {cancelLabel}
          </button>
        )}
        <button
          type="submit"
          disabled={loading || disabled || isSubmitting}
          className="inline-flex items-center gap-2 px-4 py-2 bg-primary text-primary-foreground rounded-md hover:bg-primary/90 disabled:opacity-50 transition-colors"
        >
          {loading || isSubmitting ? (
            <>
              <Loader2 className="w-4 h-4 animate-spin" />
              Saving...
            </>
          ) : (
            <>
              <Check className="w-4 h-4" />
              {submitLabel}
            </>
          )}
        </button>
      </div>
    </form>
  );
}

interface FormFieldProps {
  label: string;
  required?: boolean;
  error?: FieldError;
  success?: boolean;
  validating?: boolean;
  helpText?: string;
  className?: string;
  children: ReactNode;
  inputId?: string;
  helpTextId?: string;
  errorId?: string;
}

export function FormField({
  label,
  required = false,
  error,
  success = false,
  validating = false,
  helpText,
  className,
  children,
  inputId,
  helpTextId,
  errorId,
}: FormFieldProps) {
  return (
    <div className={cn("space-y-2", className)}>
      <label htmlFor={inputId} className="block text-sm font-medium text-foreground">
        {label}
        {required && <span className="text-destructive ml-1">*</span>}
      </label>

      <div className="relative">
        {children}

        {/* Validation indicators */}
        <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-1">
          {validating && <Loader2 className="w-4 h-4 animate-spin text-muted-foreground" />}
          {success && !error && <CheckCircle className="w-4 h-4 text-success" />}
          {error && <AlertCircle className="w-4 h-4 text-destructive" />}
        </div>
      </div>

      {helpText && !error && (
        <p id={helpTextId} className="text-sm text-muted-foreground">
          {helpText}
        </p>
      )}

      {error && (
        <p
          id={errorId}
          className="text-sm text-destructive flex items-start gap-1 animate-in slide-in-from-top-1"
        >
          <AlertCircle className="w-4 h-4 mt-0.5 flex-shrink-0" />
          <span>{error.message}</span>
        </p>
      )}

      {success && !error && (
        <p className="text-sm text-success flex items-center gap-1 animate-in slide-in-from-top-1">
          <CheckCircle className="w-4 h-4" />
          <span>Looks good!</span>
        </p>
      )}
    </div>
  );
}

interface FormInputProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, "form"> {
  name: string;
  form: UseFormReturn<FieldValues>;
  label: string;
  required?: boolean;
  helpText?: string;
}

export function FormInput({
  name,
  form,
  label,
  required,
  helpText,
  className,
  ...props
}: FormInputProps) {
  const {
    register,
    formState: { errors, touchedFields },
    watch,
  } = form;
  const error = errors[name] as FieldError | undefined;
  const touched = touchedFields[name];
  const value = watch(name);

  // Determine validation state
  const isValid = touched && !error && value;
  const isValidating = false; // Could be enhanced with async validation

  const generatedId = useId();
  const inputId = props.id || generatedId;
  const helpTextId = helpText ? `${inputId}-help` : undefined;
  const errorId = error ? `${inputId}-error` : undefined;

  return (
    <FormField
      label={label}
      required={required}
      error={error}
      success={isValid}
      validating={isValidating}
      helpText={helpText}
      inputId={inputId}
      helpTextId={helpTextId}
      errorId={errorId}
    >
      <input
        id={inputId}
        aria-describedby={
          [(!error ? helpTextId : undefined), errorId]
            .filter(Boolean)
            .join(" ") || undefined
        }
        {...register(name)}
        {...props}
        className={cn(
          "w-full px-3 py-2 border rounded-md bg-background focus:outline-none focus:ring-2 disabled:opacity-50 transition-colors",
          "placeholder:text-muted-foreground",
          {
            "border-destructive focus:ring-destructive": error,
            "border-success focus:ring-success": isValid && !error,
            "border-input focus:ring-primary": !error && !isValid,
          },
          className
        )}
      />
    </FormField>
  );
}

