interface FormSelectProps extends Omit<React.SelectHTMLAttributes<HTMLSelectElement>, "form"> {
  name: string;
  form: UseFormReturn<FieldValues>;
  label: string;
  options: Array<{ value: string | number; label: string; disabled?: boolean }>;
  placeholder?: string;
  required?: boolean;
  helpText?: string;
}

export function FormSelect({
  name,
  form,
  label,
  options,
  placeholder,
  required,
  helpText,
  className,
  ...props
}: FormSelectProps) {
  const {
    register,
    formState: { errors, touchedFields },
    watch,
  } = form;
  const error = errors[name] as FieldError | undefined;
  const touched = touchedFields[name];
  const value = watch(name);

  // Determine validation state
  const isValid = touched && !error && value && value !== "";
  const isValidating = false; // Could be enhanced with async validation

  const generatedId = useId();
  const inputId = props.id || generatedId;
  const helpTextId = helpText ? `${inputId}-help` : undefined;
  const errorId = error ? `${inputId}-error` : undefined;

  return (
    <FormField
      label={label}
      required={required}
      error={error}
      success={isValid}
      validating={isValidating}
      helpText={helpText}
      inputId={inputId}
      helpTextId={helpTextId}
      errorId={errorId}
    >
      <select
        id={inputId}
        aria-describedby={
          [(!error ? helpTextId : undefined), errorId]
            .filter(Boolean)
            .join(" ") || undefined
        }
        {...register(name)}
        {...props}
        className={cn(
          "w-full px-3 py-2 border rounded-md bg-background focus:outline-none focus:ring-2 disabled:opacity-50 transition-colors",
          "placeholder:text-muted-foreground",
          {
            "border-destructive focus:ring-destructive": error,
            "border-success focus:ring-success": isValid && !error,
            "border-input focus:ring-primary": !error && !isValid,
          },
          className
        )}
      >
        {placeholder && (
          <option value="" disabled>
            {placeholder}
          </option>
        )}
        {options.map((option) => (
          <option key={option.value} value={option.value} disabled={option.disabled}>
            {option.label}
          </option>
        ))}
      </select>
    </FormField>
  );
}

export function getFieldError<T extends FieldValues>(
  form: UseFormReturn<T>,
  fieldName: Path<T>
): FieldError | undefined {
  return form.formState.errors[fieldName] as FieldError | undefined;
}

export function setFormError<T extends FieldValues>(
  form: UseFormReturn<T>,
  fieldName: Path<T>,
  message: string
) {
  form.setError(fieldName, { message });
}

export function resetForm<T extends FieldValues>(
  form: UseFormReturn<T>,
  values?: DefaultValues<T>
) {
  form.reset(values);
}

import { useEffect } from "react";

export function Analytics() {
  const gtmId = import.meta.env.VITE_GTM_CONTAINER_ID;

  useEffect(() => {
    if (!gtmId) return;

    // GTM Initialization
    // Refactored to avoid innerHTML usage (SEC-003)
    (function (w: Window & Record<string, unknown>, d: Document, s: string, l: string, i: string) {
      w[l] = w[l] || [];
      w[l].push({
        'gtm.start': new Date().getTime(),
        event: 'gtm.js'
      });

      const f = d.getElementsByTagName(s)[0];
      const j = d.createElement(s);
      const dl = l !== 'dataLayer' ? '&l=' + l : '';

      j.async = true;
      j.src = 'https://www.googletagmanager.com/gtm.js?id=' + i + dl;

      if (f && f.parentNode) {
        f.parentNode.insertBefore(j, f);
      } else {
        d.head.appendChild(j);
      }
    })(window, document, 'script', 'dataLayer', gtmId);

    // Noscript Iframe
    // Using DOM API instead of innerHTML for security
    const gtmNoscript = document.createElement("noscript");
    const iframe = document.createElement("iframe");
    iframe.src = `https://www.googletagmanager.com/ns.html?id=${gtmId}`;
    iframe.height = "0";
    iframe.width = "0";
    iframe.style.display = "none";
    iframe.style.visibility = "hidden";

    gtmNoscript.appendChild(iframe);
    document.body.insertBefore(gtmNoscript, document.body.firstChild);

  }, [gtmId]);

  return null;
}

import { ArrowRight, Award, BookOpen, Calendar, Clock, FileText, Search, Tag, TrendingUp } from 'lucide-react';
import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

import { SEO } from './SEO';

import { supabase } from '@/lib/supabase';
import { logger } from '@/lib/logger';


interface BlogPost {
  id: string;
  title: string;
  slug: string;
  excerpt: string;
  author: string;
  author_role: string;
  published_date: string;
  featured_image: string | null;
  tags: string[];
  read_time: number;
  content_type?: string;
  featured?: boolean;
}

export default function Blog() {
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const [selectedType, setSelectedType] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    fetchPosts();
  }, []);

  const fetchPosts = async () => {
    if (!supabase) {
      logger.error('Supabase client not initialized. Skipping blog posts fetch.');
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('blog_posts')
        .select('*')
        .eq('published', true)
        .lte('published_date', new Date().toISOString())
        .order('featured', { ascending: false })
        .order('published_date', { ascending: false });

      if (error) throw error;
      setPosts(data || []);
    } catch (error) {
      logger.error('Error fetching blog posts:', error);
    } finally {
      setLoading(false);
    }
  };

  const allTags = Array.from(new Set(posts.flatMap(post => post.tags)));
  const contentTypes = Array.from(new Set(posts.map(post => post.content_type).filter(Boolean)));

  const filteredPosts = posts.filter(post => {
    const matchesTag = !selectedTag || post.tags.includes(selectedTag);
    const matchesType = !selectedType || post.content_type === selectedType;
    const matchesSearch = !searchQuery ||
      post.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      post.excerpt.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesTag && matchesType && matchesSearch;
  });

  const featuredPost = filteredPosts.find(post => post.featured);
  const regularPosts = filteredPosts.filter(post => !post.featured);

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  const getContentTypeIcon = (type: string) => {
    switch (type) {
      case 'Guide': return BookOpen;
      case 'Case Study': return Award;
      case 'Research': return TrendingUp;
      case 'Article': return FileText;
      default: return FileText;
    }
  };

  return (
    <>
      <SEO
        title="Resources & Insights: Transform Cost Centers into Profit Engines | ValueOS"
        description="Expert guides, case studies, and frameworks for turning Customer Success, Services, and Support into revenue-generating profit centers. Reduce CAC, prove ROI, and drive measurable value outcomes."
      />

      <script type="application/ld+json">
        {JSON.stringify({
          "@context": "https://schema.org",
          "@type": "Blog",
          "name": "ValueOS Resources & Insights",
          "description": "Expert resources on transforming cost centers into profit centers through value operations",
          "url": "https://valueos.com/blog",
          "publisher": {
            "@type": "Organization",
            "name": "ValueOS",
            "logo": {
              "@type": "ImageObject",
              "url": "https://valueos.com/logo.png"
            }
          }
        })}
      </script>

      <div className="min-h-screen pt-24 pb-16" style={{ backgroundColor: '#0B0C0F' }}>
        <div className="max-w-7xl mx-auto px-6">
          <div className="max-w-4xl mx-auto text-center mb-12">
            <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full mb-6" style={{
              border: '1px solid rgba(24, 195, 165, 0.3)',
              backgroundColor: 'rgba(24, 195, 165, 0.1)'
            }}>
              <TrendingUp className="w-4 h-4" style={{ color: '#18C3A5' }} />
              <span className="text-sm font-medium" style={{ color: '#18C3A5' }}>Strategic Resources for Value Leaders</span>
            </div>

            <h1 className="text-5xl md:text-6xl font-bold text-white mb-6 leading-tight">
              Turn Knowledge Into
              <span className="block mt-2" style={{ color: '#18C3A5' }}>Revenue Advantage</span>
            </h1>

            <p className="text-xl leading-relaxed mb-8" style={{ color: '#707070' }}>
              Proven frameworks, real outcomes, and strategic insights to transform your cost centers into measurable profit engines. Join 500+ revenue leaders who are redefining value operations.
            </p>

            <div className="relative max-w-xl mx-auto mb-12">
              <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 w-5 h-5" style={{ color: '#707070' }} />
              <input
                type="text"
                placeholder="Search resources by topic, outcome, or challenge..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-12 pr-4 py-4 rounded-full text-white placeholder-gray-500 focus:outline-none transition-all"
                style={{
                  backgroundColor: '#1E1E1E',
                  border: '1px solid rgba(224, 224, 224, 0.1)'
