          </div>

          <div className="flex flex-wrap justify-center gap-3 mb-8">
            <button
              onClick={() => setSelectedType(null)}
              className={`px-5 py-2 rounded-full text-sm font-medium transition-all ${selectedType === null ? 'shadow-lg' : 'hover:bg-white/5'
