          ) : !supabase ? (
            <div className="text-center py-16">
              <p className="text-xl mb-2" style={{ color: '#707070' }}>
                Blog is temporarily unavailable.
              </p>
              <p className="mb-4" style={{ color: '#707070' }}>
                Please check back later.
              </p>
