/**
 * SuggestionCard — renders a single AI-generated suggestion with
 * Accept/Edit/Reject actions, confidence badge, and source count.
 */

import { Check, ExternalLink, Pencil, Sparkles, X } from "lucide-react";
import { useState } from "react";

import type { ResearchSuggestion } from "@/hooks/company-context/types";
import { cn } from "@/lib/utils";

interface Props {
  suggestion: ResearchSuggestion;
  onAccept: (suggestion: ResearchSuggestion) => void;
  onReject: (suggestion: ResearchSuggestion) => void;
  onEdit: (suggestion: ResearchSuggestion, editedPayload: Record<string, unknown>) => void;
  renderPayload: (payload: Record<string, unknown>, isEditing: boolean, onPayloadChange: (payload: Record<string, unknown>) => void) => React.ReactNode;
  isProcessing?: boolean;
}

function ConfidenceBadge({ score }: { score: number }) {
  const color =
    score >= 0.7
      ? "bg-emerald-50 text-emerald-700 border-emerald-200"
      : score >= 0.4
        ? "bg-amber-50 text-amber-700 border-amber-200"
        : "bg-red-50 text-red-700 border-red-200";

  return (
    <span className={cn("text-[10px] px-2 py-0.5 rounded-full font-semibold border", color)}>
      {Math.round(score * 100)}%
    </span>
  );
}

function getSourceName(url: string): string {
  if (url.startsWith("sec://edgar")) {
    const parts = url.split("/");
    const section = parts[parts.length - 1];
    return `SEC 10-K (${section.replace(/_/g, " ")})`;
  }
  if (url.includes("sec.gov")) return "SEC Filing";
  try {
    const u = new URL(url);
    return u.hostname.replace("www.", "");
  } catch {
    return "Website";
  }
}

function SourceBadge({ urls }: { urls: string[] }) {
  if (urls.length === 0) return null;
  const firstName = getSourceName(urls[0]);

  return (
    <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-zinc-100 text-zinc-600 border border-zinc-200 text-[9px] font-medium">
      <ExternalLink className="w-2.5 h-2.5" />
      {urls.length === 1 ? firstName : `${firstName} +${urls.length - 1}`}
    </div>
  );
}

export function SuggestionCard({
  suggestion,
  onAccept,
  onReject,
  onEdit,
  renderPayload,
  isProcessing = false,
}: Props) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedPayload, setEditedPayload] = useState<Record<string, unknown>>(
    suggestion.payload as Record<string, unknown>,
  );

  if (suggestion.status !== "suggested") return null;

  const handleAcceptEdit = () => {
    onEdit(suggestion, editedPayload);
    setIsEditing(false);
  };

  return (
    <div className="p-4 rounded-xl border border-blue-100 bg-blue-50/30 space-y-3 shadow-sm">
      {/* Header */}
      <div className="flex items-center gap-2">
        <Sparkles className="w-3.5 h-3.5 text-blue-500" />
        <span className="text-[10px] font-semibold uppercase tracking-[0.15em] text-blue-500">
          AI Suggested
        </span>
        <ConfidenceBadge score={suggestion.confidence_score} />
        <div className="ml-auto">
          <SourceBadge urls={suggestion.source_urls} />
        </div>
      </div>

      {/* Payload content */}
      <div>
        {renderPayload(
          isEditing ? editedPayload : (suggestion.payload as Record<string, unknown>),
          isEditing,
          setEditedPayload,
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-2 pt-1">
        {isEditing ? (
          <>
            <button
              onClick={handleAcceptEdit}
              disabled={isProcessing}
              className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-[11px] font-medium bg-emerald-600 text-white hover:bg-emerald-700 transition-colors disabled:opacity-50"
            >
              <Check className="w-3 h-3" /> Save & Accept
            </button>
            <button
              onClick={() => {
                setIsEditing(false);
                setEditedPayload(suggestion.payload as Record<string, unknown>);
              }}
              className="px-3 py-1.5 rounded-lg text-[11px] font-medium text-zinc-500 hover:bg-zinc-100 transition-colors"
            >
              Cancel
            </button>
          </>
        ) : (
          <>
            <button
              onClick={() => onAccept(suggestion)}
              disabled={isProcessing}
              className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-[11px] font-medium bg-emerald-50 text-emerald-700 border border-emerald-200 hover:bg-emerald-100 transition-colors disabled:opacity-50"
            >
              <Check className="w-3 h-3" /> Accept
            </button>
            <button
              onClick={() => setIsEditing(true)}
              disabled={isProcessing}
              className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-[11px] font-medium text-zinc-600 border border-zinc-200 hover:bg-zinc-100 transition-colors disabled:opacity-50"
            >
              <Pencil className="w-3 h-3" /> Edit
            </button>
            <button
              onClick={() => onReject(suggestion)}
              disabled={isProcessing}
              className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-[11px] font-medium text-red-600 border border-red-200 hover:bg-red-50 transition-colors disabled:opacity-50"
            >
              <X className="w-3 h-3" /> Reject
            </button>
          </>
        )}
      </div>
    </div>
  );
}

/**
 * SuggestionSection — wraps a list of suggestions for a given entity type.
 * Renders above the manual entry area.
 */
export function SuggestionSection({
  suggestions,
  onAccept,
  onReject,
  onEdit,
  renderPayload,
  isProcessing,
}: {
  suggestions: ResearchSuggestion[];
  onAccept: (s: ResearchSuggestion) => void;
  onReject: (s: ResearchSuggestion) => void;
  onEdit: (s: ResearchSuggestion, payload: Record<string, unknown>) => void;
  renderPayload: Props["renderPayload"];
  isProcessing?: boolean;
}) {
  const pending = suggestions.filter((s) => s.status === "suggested");
  if (pending.length === 0) return null;

  return (
    <div className="space-y-3 mb-6">
      <div className="flex items-center gap-2">
        <Sparkles className="w-4 h-4 text-blue-500" />
        <h3 className="text-[12px] font-semibold text-blue-600">
          AI Suggestions ({pending.length})
        </h3>
      </div>
      {pending.map((s) => (
        <SuggestionCard
          key={s.id}
          suggestion={s}
          onAccept={onAccept}
          onReject={onReject}
          onEdit={onEdit}
          renderPayload={renderPayload}
          isProcessing={isProcessing ?? false}
        />
      ))}
    </div>
  );
}

import { AlertTriangle } from "lucide-react";
import type { RuntimeFailureDetails } from "@shared/domain/RuntimeFailureTaxonomy";

interface DegradedStatusBannerProps {
  runtimeFailure: RuntimeFailureDetails;
  className?: string;
}

export function DegradedStatusBanner({ runtimeFailure, className = "" }: DegradedStatusBannerProps) {
  const isDegraded = runtimeFailure.severity === "degraded";
  const tone = isDegraded
    ? "border-amber-200 bg-amber-50 text-amber-900"
    : "border-red-200 bg-red-50 text-red-900";

  return (
    <div className={`rounded-lg border px-4 py-3 ${tone} ${className}`} role="status" aria-live="polite">
      <div className="flex items-start gap-3">
        <AlertTriangle className="mt-0.5 h-4 w-4" />
        <div className="space-y-1">
          <p className="text-sm font-semibold">
            {isDegraded ? "Execution degraded" : "Execution failed"} · {runtimeFailure.class}
          </p>
          <p className="text-sm">{runtimeFailure.diagnosis}</p>
          <div className="flex flex-wrap gap-2 text-xs">
            <span className="rounded-full bg-white/70 px-2 py-0.5 font-medium">reason: {runtimeFailure.machineReasonCode}</span>
            <span className="rounded-full bg-white/70 px-2 py-0.5 font-medium">confidence: {Math.round(runtimeFailure.confidence * 100)}%</span>
            <span className="rounded-full bg-white/70 px-2 py-0.5 font-medium">blast radius: {runtimeFailure.blastRadiusEstimate}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * PipelineStepper
 *
 * A 7-step horizontal pipeline visualization for the HypothesisLoop.
 * Each step shows real-time status, agent name, confidence badge,
 * and timing — all driven by enriched SSE LoopProgress events.
 */

import {
  AlertTriangle,
  BookOpen,
  CheckCircle2,
  ChevronRight,
  Clock,
  DollarSign,
  FileSearch,
  Lightbulb,
  Loader2,
  RefreshCw,
  Shield,
  Sparkles,
} from "lucide-react";
import type { ReactNode } from "react";

import type { PipelineStepState, PipelineStepStatus } from "@/hooks/useValueCaseStream";

// ---------------------------------------------------------------------------
// Step icon mapping
// ---------------------------------------------------------------------------

const STEP_ICONS: Record<string, ReactNode> = {
  Hypothesis: <Lightbulb className="h-4 w-4" />,
  Model: <DollarSign className="h-4 w-4" />,
  Evidence: <FileSearch className="h-4 w-4" />,
  Narrative: <BookOpen className="h-4 w-4" />,
  Objection: <Shield className="h-4 w-4" />,
  Revision: <RefreshCw className="h-4 w-4" />,
  Approval: <Sparkles className="h-4 w-4" />,
};

// ---------------------------------------------------------------------------
// Confidence badge
// ---------------------------------------------------------------------------

function ConfidenceBadge({ value }: { value: number }) {
  const pct = Math.round(value * 100);
  const color =
    pct >= 80
      ? "text-emerald-600 bg-emerald-50 border-emerald-200"
      : pct >= 60
        ? "text-amber-600 bg-amber-50 border-amber-200"
        : "text-red-500 bg-red-50 border-red-200";

  return (
    <span
      className={`inline-flex items-center rounded-full border px-1.5 py-0.5 text-[10px] font-semibold tabular-nums ${color}`}
    >
      {pct}%
    </span>
  );
}

// ---------------------------------------------------------------------------
// Duration badge
// ---------------------------------------------------------------------------

function DurationBadge({ ms }: { ms: number }) {
  const label = ms < 1000 ? `${ms}ms` : `${(ms / 1000).toFixed(1)}s`;
  return (
    <span className="inline-flex items-center gap-0.5 text-[10px] text-zinc-400 tabular-nums">
      <Clock className="h-3 w-3" />
      {label}
    </span>
  );
}

// ---------------------------------------------------------------------------
// Single step node
// ---------------------------------------------------------------------------

interface StepNodeProps {
  step: PipelineStepState;
  isLast: boolean;
}

function statusRingClass(status: PipelineStepStatus): string {
  switch (status) {
    case "completed":
      return "border-emerald-500 bg-emerald-50 text-emerald-600";
    case "running":
      return "border-brand-indigo bg-brand-indigo/10 text-brand-indigo ring-4 ring-brand-indigo/20";
    case "failed":
      return "border-red-500 bg-red-50 text-red-500";
    default:
      return "border-zinc-200 bg-zinc-50 text-zinc-400";
  }
}

function connectorClass(status: PipelineStepStatus): string {
  switch (status) {
    case "completed":
      return "bg-emerald-400";
    case "running":
      return "bg-gradient-to-r from-emerald-400 to-brand-indigo animate-pulse";
    default:
      return "bg-zinc-200";
  }
}

function StepNode({ step, isLast, stepNumber }: StepNodeProps & { stepNumber: number }) {
  const icon = STEP_ICONS[step.stepName] ?? <ChevronRight className="h-4 w-4" />;
  const stepId = `step-${step.step}`;

  return (
    <div className="flex items-start gap-0 flex-1 min-w-0" role="listitem" aria-label={`Step ${stepNumber}: ${step.stepName}, ${step.status}`}>
      {/* Step circle + label column */}
      <div className="flex flex-col items-center gap-1.5 min-w-[72px]">
        {/* Circle */}
        <div
          className={`relative flex h-10 w-10 items-center justify-center rounded-full border-2 transition-all duration-500 ${statusRingClass(step.status)}`}
          aria-current={step.status === "running" ? "step" : undefined}
        >
          {step.status === "running" ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : step.status === "completed" ? (
            <CheckCircle2 className="h-4 w-4" />
          ) : step.status === "failed" ? (
            <AlertTriangle className="h-4 w-4" />
          ) : (
            icon
          )}
        </div>

        {/* Step name */}
        <span
          className={`text-[11px] font-semibold tracking-wide text-center leading-tight ${step.status === "running"
            ? "text-brand-indigo"
            : step.status === "completed"
              ? "text-zinc-700"
              : "text-zinc-400"
            }`}
        >
          {step.stepName}
        </span>

        {/* Agent name */}
        {step.agentName && step.status !== "pending" && (
          <span className="text-[9px] text-zinc-400 font-medium truncate max-w-[80px] text-center">
            {step.agentName}
          </span>
        )}

        {/* Badges row */}
        <div className="flex items-center gap-1">
          {typeof step.confidence === "number" && step.status === "completed" && (
            <ConfidenceBadge value={step.confidence} />
          )}
          {typeof step.durationMs === "number" && step.status === "completed" && (
            <DurationBadge ms={step.durationMs} />
          )}
        </div>

        {/* Message / highlights */}
        {step.message && step.status !== "pending" && (
          <p className="text-[10px] text-zinc-500 text-center leading-snug max-w-[100px] line-clamp-2">
            {step.message}
          </p>
        )}
      </div>

      {/* Connector line */}
      {!isLast && (
        <div className="flex items-center pt-[18px] flex-1 min-w-[12px] px-0.5">
          <div
            className={`h-[2px] w-full rounded-full transition-all duration-700 ${connectorClass(step.status)}`}
          />
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// PipelineStepper
// ---------------------------------------------------------------------------

interface PipelineStepperProps {
  steps: PipelineStepState[];
  revisionCycle?: number;
  maxRevisionCycles?: number;
  className?: string;
}

export function PipelineStepper({
  steps,
  revisionCycle = 0,
  maxRevisionCycles = 3,
  className = "",
}: PipelineStepperProps) {
  const showRevisionBadge = revisionCycle > 0;

  return (
    <div className={`w-full ${className}`}>
      {/* Revision indicator */}
      {showRevisionBadge && (
        <div className="flex items-center gap-2 mb-3 px-1">
          <div className="flex items-center gap-1.5 rounded-full bg-amber-50 border border-amber-200 px-2.5 py-1">
            <RefreshCw className="h-3 w-3 text-amber-600" />
            <span className="text-[11px] font-semibold text-amber-700">
              Revision cycle {revisionCycle}/{maxRevisionCycles}
            </span>
          </div>
          <div className="flex gap-1">
            {Array.from({ length: maxRevisionCycles }).map((_, i) => (
              <div
                key={i}
                className={`h-1.5 w-6 rounded-full transition-colors ${i < revisionCycle ? "bg-amber-400" : "bg-zinc-200"
                  }`}
              />
            ))}
          </div>
        </div>
      )}

      {/* Steps row */}
      <div className="flex items-start w-full" role="list" aria-label="Pipeline progress">
        {steps.map((step, i) => (
          <StepNode key={step.step} step={step} isLast={i === steps.length - 1} stepNumber={i + 1} />
        ))}
      </div>
    </div>
  );
}

import type { RemediationAction, RuntimeFailureDetails } from "@shared/domain/RuntimeFailureTaxonomy";

const ACTION_LABELS: Record<RemediationAction, string> = {
  retry: "Retry",
  "reroute-owner": "Reroute Owner",
  "provide-missing-artifact": "Provide Artifact",
  "request-override": "Request Override",
  "escalate-approval-inbox": "Escalate to Approval Inbox",
};

interface RemediationActionPanelProps {
  runtimeFailure: RuntimeFailureDetails;
  onRetry?: () => void;
  onOpenApprovalInbox?: () => void;
}

export function RemediationActionPanel({ runtimeFailure, onRetry, onOpenApprovalInbox }: RemediationActionPanelProps) {
  const runAction = (action: RemediationAction) => {
    if (action === "retry") {
      onRetry?.();
      return;
    }

    if (action === "escalate-approval-inbox") {
      onOpenApprovalInbox?.();
    }
  };

  return (
    <div className="rounded-xl border border-zinc-200 bg-white p-4">
      <div className="mb-3">
        <p className="text-sm font-semibold text-zinc-900">Remediation playbook</p>
        <p className="text-xs text-zinc-600">{runtimeFailure.playbookTitle} · Owner: {runtimeFailure.owner}</p>
        <p className="mt-1 text-xs text-zinc-500">{runtimeFailure.playbookGuidance}</p>
      </div>
      <div className="flex flex-wrap gap-2">
        {runtimeFailure.recommendedNextActions.map((action) => (
          <button
            key={action}
            type="button"
            onClick={() => runAction(action)}
            className="rounded-md border border-zinc-300 px-2.5 py-1.5 text-xs font-medium text-zinc-700 hover:bg-zinc-50"
          >
            {ACTION_LABELS[action]}
          </button>
        ))}
      </div>
    </div>
  );
}

