  // Secondary (inverted containers)
  '--md-sys-color-on-secondary': '#0d1c2e',
  '--md-sys-color-secondary-container': '#515f74',
  '--md-sys-color-on-secondary-container': '#d5e3fc',
  // Tertiary (inverted containers)
