const AvatarFallback = React.forwardRef<
  React.ElementRef<typeof AvatarPrimitive.Fallback>,
  React.ComponentPropsWithoutRef<typeof AvatarPrimitive.Fallback>
>(({ className, ...props }, ref) => (
  <AvatarPrimitive.Fallback
    ref={ref}
    className={cn(
      "flex h-full w-full items-center justify-center rounded-full bg-muted font-medium text-muted-foreground",
      className
    )}
    {...props}
  />
));
AvatarFallback.displayName = AvatarPrimitive.Fallback.displayName;

/**
 * UserAvatar - Complete avatar with image, fallback, and optional status
 */
export interface UserAvatarProps {
  src?: string | null;
  name: string;
  email?: string;
  size?: VariantProps<typeof avatarVariants>["size"];
  status?: "online" | "offline" | "busy" | "away";
  className?: string;
}

const getInitials = (name: string): string => {
  const parts = name.trim().split(/\s+/);
  if (parts.length === 1) {
    return parts[0]?.slice(0, 2).toUpperCase() ?? "";
  }
  return (
    (parts[0]?.[0] ?? "") + (parts[parts.length - 1]?.[0] ?? "")
  ).toUpperCase();
};

const statusColors = {
  online: "bg-success",
  offline: "bg-slate-400",
  busy: "bg-destructive",
  away: "bg-warning",
};

const UserAvatar = ({
  src,
  name,
  email,
  size = "md",
  status,
  className,
}: UserAvatarProps) => {
  const initials = getInitials(name);

  return (
    <div className={cn("relative inline-block", className)}>
      <Avatar size={size}>
        {src && <AvatarImage src={src} alt={name} />}
        <AvatarFallback>{initials}</AvatarFallback>
      </Avatar>
      {status && (
        <span
          className={cn(
            "absolute bottom-0 right-0 block rounded-full ring-2 ring-background",
            statusColors[status],
            size === "xs" && "h-1.5 w-1.5",
            size === "sm" && "h-2 w-2",
            size === "md" && "h-2.5 w-2.5",
            size === "lg" && "h-3 w-3",
            size === "xl" && "h-4 w-4"
          )}
        />
      )}
    </div>
  );
};

/**
 * AvatarGroup - Stack of avatars for showing multiple users
 */
export interface AvatarGroupProps {
  users: Array<{
    src?: string | null;
    name: string;
  }>;
  max?: number;
  size?: VariantProps<typeof avatarVariants>["size"];
  className?: string;
}

const AvatarGroup = ({ users, max = 4, size = "sm", className }: AvatarGroupProps) => {
  const visibleUsers = users.slice(0, max);
  const remainingCount = users.length - max;

  return (
    <div className={cn("flex -space-x-2", className)}>
      {visibleUsers.map((user, index) => (
        <UserAvatar
          key={index}
          src={user.src}
          name={user.name}
          size={size}
          className="ring-2 ring-background"
        />
      ))}
      {remainingCount > 0 && (
        <div
          className={cn(
            avatarVariants({ size }),
            "flex items-center justify-center bg-muted text-muted-foreground ring-2 ring-background"
          )}
          role="status"
          aria-label={`${remainingCount} more users`}
        >
          +{remainingCount}
        </div>
      )}
    </div>
  );
};

export { Avatar, AvatarImage, AvatarFallback, avatarVariants, UserAvatar, AvatarGroup };

