/**
 * ValueDriverEditor - Modal for creating/editing value drivers
 *
 * Full editor with formula builder, persona tags, and narrative pitch.
 */

import {
  Calculator,
  Eye,
  MessageSquare,
  Plus,
  Sparkles,
  Target,
  Trash2,
  Users,
  X,
} from "lucide-react";
import { useState } from "react";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input, Textarea } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { SimpleSelect } from "@/components/ui/select";
import { cn } from "@/lib/utils";
import {
  FormulaVariable,
  PERSONA_TAG_LABELS,
  PersonaTag,
  SALES_MOTION_LABELS,
  SalesMotionTag,
  VALUE_DRIVER_TYPE_LABELS,
  ValueDriver,
  ValueDriverType,
} from "@/types/valueDriver";
import { evaluateFormula } from "@/utils/formulas";

interface ValueDriverEditorProps {
  driver: ValueDriver | null;
  onSave: (driver: ValueDriver) => void;
  onClose: () => void;
}

const TYPE_OPTIONS = Object.entries(VALUE_DRIVER_TYPE_LABELS).map(([value, label]) => ({
  value,
  label,
}));

const ALL_PERSONAS: PersonaTag[] = [
  "cro",
  "cmo",
  "cfo",
  "cto",
  "vp-sales",
  "se-director",
  "cs-leader",
  "procurement",
];
const ALL_MOTIONS: SalesMotionTag[] = [
  "new-logo",
  "renewal",
  "expansion",
  "land-expand",
  "competitive-displacement",
];

export function ValueDriverEditor({ driver, onSave, onClose }: ValueDriverEditorProps) {
  const isNew = !driver;

  const [formData, setFormData] = useState<Partial<ValueDriver>>({
    name: driver?.name || "",
    description: driver?.description || "",
    type: driver?.type || "cost-savings",
    personaTags: driver?.personaTags || [],
    salesMotionTags: driver?.salesMotionTags || [],
    formula: driver?.formula || {
      expression: "",
      variables: [],
      resultUnit: "currency",
    },
    narrativePitch: driver?.narrativePitch || "",
    status: driver?.status || "draft",
  });

  const [previewValue, setPreviewValue] = useState<number | null>(null);

  const handleChange = <K extends keyof ValueDriver>(key: K, value: ValueDriver[K]) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
  };

  const togglePersonaTag = (tag: PersonaTag) => {
    const current = formData.personaTags || [];
    const updated = current.includes(tag) ? current.filter((t) => t !== tag) : [...current, tag];
    handleChange("personaTags", updated);
  };

  const toggleMotionTag = (tag: SalesMotionTag) => {
    const current = formData.salesMotionTags || [];
    const updated = current.includes(tag) ? current.filter((t) => t !== tag) : [...current, tag];
    handleChange("salesMotionTags", updated);
  };

  const addVariable = () => {
    const newVar: FormulaVariable = {
      id: `var-${Date.now()}`,
      name: "",
      label: "",
      defaultValue: 0,
      unit: "",
    };
    handleChange("formula", {
      ...formData.formula!,
      variables: [...(formData.formula?.variables ?? []), newVar],
    });
  };

  const updateVariable = (id: string, updates: Partial<FormulaVariable>) => {
    handleChange("formula", {
      ...formData.formula!,
      variables: formData.formula?.variables?.map((v) => (v.id === id ? { ...v, ...updates } : v)) ?? [],
    });
  };

  const removeVariable = (id: string) => {
    handleChange("formula", {
      ...formData.formula!,
      variables: formData.formula?.variables?.filter((v) => v.id !== id) ?? [],
    });
  };

  const calculatePreview = () => {
    try {
      const vars = formData.formula?.variables || [];
      const scope: Record<string, number> = {};
      vars.forEach((v) => {
        scope[v.name] = v.defaultValue;
      });

      // Use safe evaluator instead of new Function
      const expr = formData.formula?.expression || "0";
      const result = evaluateFormula(expr, scope);
      setPreviewValue(result);
    } catch {
      setPreviewValue(null);
    }
  };

  const handleSave = () => {
    const now = new Date().toISOString();
    const savedDriver: ValueDriver = {
      id: driver?.id || "",
      name: formData.name || "",
      description: formData.description || "",
      type: formData.type as ValueDriverType,
      personaTags: formData.personaTags || [],
      salesMotionTags: formData.salesMotionTags || [],
      formula: formData.formula!,
      narrativePitch: formData.narrativePitch || "",
      status: formData.status as "draft" | "published" | "archived",
      createdAt: driver?.createdAt || now,
      updatedAt: now,
      createdBy: driver?.createdBy || "admin@acme.com",
      version: (driver?.version || 0) + 1,
      usageCount: driver?.usageCount || 0,
      winRateCorrelation: driver?.winRateCorrelation,
    };
    onSave(savedDriver);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-start justify-center pt-10 pb-10 overflow-y-auto">
      {/* Backdrop */}
      <div className="fixed inset-0 bg-black/50" onClick={onClose} />

      {/* Modal */}
      <div className="relative bg-white rounded-lg shadow-xl w-full max-w-3xl mx-4">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b">
          <div>
            <h2 className="text-xl font-semibold">
              {isNew ? "Create Value Driver" : "Edit Value Driver"}
            </h2>
            <p className="text-sm text-muted-foreground mt-1">
              Define the formula, personas, and narrative for this driver
            </p>
          </div>
          <Button variant="ghost" size="sm" onClick={onClose}>
            <X className="h-5 w-5" />
          </Button>
        </div>

        {/* Content */}
        <div className="p-6 space-y-6 max-h-[calc(100vh-200px)] overflow-y-auto">
          {/* Basic Info */}
          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-2">
              <Label>Name</Label>
              <Input
                value={formData.name}
                onChange={(e) => handleChange("name", e.target.value)}
                placeholder="e.g., Demo Prep Time Reduction"
                className="mt-1"
              />
            </div>
            <div className="col-span-2">
              <Label>Description</Label>
              <Input
                value={formData.description}
                onChange={(e) => handleChange("description", e.target.value)}
                placeholder="Brief description of this value driver"
                className="mt-1"
              />
            </div>
            <div>
              <Label>Type</Label>
              <SimpleSelect
                value={formData.type || "cost-savings"}
                onValueChange={(v) => handleChange("type", v as ValueDriverType)}
                options={TYPE_OPTIONS}
              />
            </div>
            <div>
              <Label>Status</Label>
              <SimpleSelect
                value={formData.status || "draft"}
                onValueChange={(v) =>
                  handleChange("status", v as "draft" | "published" | "archived")
                }
                options={[
                  { value: "draft", label: "Draft" },
                  { value: "published", label: "Published" },
                  { value: "archived", label: "Archived" },
                ]}
              />
            </div>
          </div>

          {/* Persona Tags */}
          <div>
            <Label className="flex items-center gap-2">
              <Users className="h-4 w-4" />
              Persona Fit
            </Label>
            <p className="text-sm text-muted-foreground mb-2">
              Which buyer personas does this driver resonate with?
            </p>
            <div className="flex flex-wrap gap-2">
              {ALL_PERSONAS.map((tag) => (
                <Badge
                  key={tag}
                  variant="outline"
                  className={cn(
                    "cursor-pointer transition-colors",
                    formData.personaTags?.includes(tag)
                      ? "bg-primary text-primary-foreground border-primary"
                      : "hover:bg-muted"
                  )}
                  onClick={() => togglePersonaTag(tag)}
                >
                  {PERSONA_TAG_LABELS[tag]}
                </Badge>
              ))}
            </div>
          </div>

          {/* Sales Motion Tags */}
          <div>
            <Label className="flex items-center gap-2">
              <Target className="h-4 w-4" />
              Sales Motion
            </Label>
            <p className="text-sm text-muted-foreground mb-2">
              Where does this driver fit in the GTM lifecycle?
            </p>
            <div className="flex flex-wrap gap-2">
              {ALL_MOTIONS.map((tag) => (
                <Badge
                  key={tag}
                  variant="outline"
                  className={cn(
                    "cursor-pointer transition-colors",
                    formData.salesMotionTags?.includes(tag)
                      ? "bg-primary text-primary-foreground border-primary"
                      : "hover:bg-muted"
                  )}
                  onClick={() => toggleMotionTag(tag)}
                >
                  {SALES_MOTION_LABELS[tag]}
                </Badge>
              ))}
            </div>
          </div>

          {/* Formula Builder */}
          <div className="border rounded-lg p-4 bg-muted/30">
            <Label className="flex items-center gap-2 mb-3">
              <Calculator className="h-4 w-4" />
              Formula & Assumptions
            </Label>

            {/* Variables */}
            <div className="space-y-3 mb-4">
              {formData.formula?.variables.map((variable, _index) => (
                <div key={variable.id} className="grid grid-cols-12 gap-2 items-end">
                  <div className="col-span-3">
                    <Label className="text-xs">Variable Name</Label>
                    <Input
                      value={variable.name}
                      onChange={(e) => updateVariable(variable.id, { name: e.target.value })}
                      placeholder="variableName"
                      className="text-sm"
                    />
                  </div>
                  <div className="col-span-3">
                    <Label className="text-xs">Label</Label>
                    <Input
                      value={variable.label}
                      onChange={(e) => updateVariable(variable.id, { label: e.target.value })}
                      placeholder="Display label"
                      className="text-sm"
                    />
                  </div>
                  <div className="col-span-2">
                    <Label className="text-xs">Default</Label>
                    <Input
                      type="number"
                      value={variable.defaultValue}
                      onChange={(e) =>
                        updateVariable(variable.id, {
                          defaultValue: parseFloat(e.target.value) || 0,
                        })
                      }
                      className="text-sm"
                    />
                  </div>
                  <div className="col-span-2">
                    <Label className="text-xs">Unit</Label>
                    <Input
                      value={variable.unit}
                      onChange={(e) => updateVariable(variable.id, { unit: e.target.value })}
                      placeholder="$, hrs, %"
                      className="text-sm"
                    />
                  </div>
                  <div className="col-span-2 flex justify-end">
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => removeVariable(variable.id)}
                      className="text-destructive hover:text-destructive"
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))}
            </div>

            <Button variant="outline" size="sm" onClick={addVariable}>
              <Plus className="h-4 w-4 mr-2" />
              Add Variable
            </Button>

            {/* Expression */}
            <div className="mt-4">
              <Label className="text-xs">Formula Expression</Label>
              <Input
                value={formData.formula?.expression}
                onChange={(e) =>
                  handleChange("formula", { ...formData.formula!, expression: e.target.value })
                }
                placeholder="e.g., demosPerMonth * timeSaved * hourlyRate * 12"
                className="font-mono text-sm mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">
                Use variable names in the expression. Supports basic math operators.
              </p>
            </div>

            {/* Preview */}
            <div className="mt-4 flex items-center gap-4">
              <Button variant="outline" size="sm" onClick={calculatePreview}>
                <Eye className="h-4 w-4 mr-2" />
                Preview Result
              </Button>
              {previewValue !== null && (
                <span className="text-lg font-semibold text-emerald-600">
                  ${previewValue.toLocaleString()}
                </span>
              )}
            </div>
          </div>

          {/* Narrative Pitch */}
          <div>
            <Label className="flex items-center gap-2">
              <MessageSquare className="h-4 w-4" />
              Narrative Pitch
            </Label>
            <p className="text-sm text-muted-foreground mb-2">
              Buyer-facing one-liner that drives urgency and relevance
            </p>
            <Textarea
              value={formData.narrativePitch}
              onChange={(e) => handleChange("narrativePitch", e.target.value)}
              placeholder="e.g., We cut demo prep time in half—freeing SEs to run more demos or focus on complex use cases."
              rows={3}
            />
            <div className="flex justify-end mt-2">
              <Button variant="ghost" size="sm">
                <Sparkles className="h-4 w-4 mr-2" />
                AI Improve
              </Button>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between p-6 border-t bg-muted/30">
          <Button variant="ghost" onClick={onClose}>
            Cancel
          </Button>
          <div className="flex gap-2">
            <Button variant="outline" onClick={() => handleChange("status", "draft")}>
              Save as Draft
            </Button>
            <Button onClick={handleSave}>
              {formData.status === "published" ? "Update & Publish" : "Save"}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ValueDriverEditor;

/**
 * ValueDriverSelector - Seller-facing component for selecting value drivers
 *
 * Shows only published drivers with persona-specific summaries and editable fields.
 */

import { Calculator, Check, ChevronRight, Sparkles, TrendingUp } from "lucide-react";
import { useState } from "react";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input, SearchInput } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import {
  PERSONA_TAG_LABELS,
  useValueDrivers,
  VALUE_DRIVER_TYPE_LABELS,
  ValueDriver,
} from "@/types/valueDriver";
import { evaluateFormula } from "@/utils/formulas";

interface SelectedDriver {
  driver: ValueDriver;
  customValues: Record<string, number>;
  calculatedValue: number;
}

interface ValueDriverSelectorProps {
  selectedDrivers: SelectedDriver[];
  onSelect: (driver: ValueDriver) => void;
  onRemove: (driverId: string) => void;
  onUpdateValues: (driverId: string, values: Record<string, number>) => void;
  personaFilter?: string;
}

const TYPE_COLORS: Record<string, string> = {
  "cost-savings": "bg-emerald-100 text-emerald-700 border-emerald-200",
  "revenue-lift": "bg-blue-100 text-blue-700 border-blue-200",
  "productivity-gain": "bg-purple-100 text-purple-700 border-purple-200",
  "risk-mitigation": "bg-amber-100 text-amber-700 border-amber-200",
};

export function ValueDriverSelector({
  selectedDrivers,
  onSelect,
  onRemove,
  onUpdateValues,
  personaFilter,
}: ValueDriverSelectorProps) {
  const [searchQuery, setSearchQuery] = useState("");
  const [expandedDriver, setExpandedDriver] = useState<string | null>(null);
  const { drivers: allDrivers, loading: driversLoading } = useValueDrivers();

  // Only show published drivers
  const availableDrivers = allDrivers.filter((d) => {
    if (d.status !== "published") return false;
    if (personaFilter && !d.personaTags.includes(personaFilter as string)) return false;
    if (searchQuery) {
      return (
        d.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        d.description.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    return true;
  });

  const selectedIds = selectedDrivers.map((s) => s.driver.id);

  const calculateValue = (driver: ValueDriver, customValues: Record<string, number>): number => {
    try {
      const scope: Record<string, number> = {};
      driver.formula.variables.forEach((v) => {
        scope[v.name] = customValues[v.name] ?? v.defaultValue;
      });
      // Use safe evaluator instead of new Function
      return evaluateFormula(driver.formula.expression, scope);
    } catch {
      return 0;
    }
  };

  const handleSelect = (driver: ValueDriver) => {
    if (selectedIds.includes(driver.id)) {
      onRemove(driver.id);
    } else {
      onSelect(driver);
    }
  };

  return (
    <div className="space-y-4">
      {/* Search */}
      <SearchInput
        value={searchQuery}
        onChange={(e) => setSearchQuery(e.target.value)}
        onClear={() => setSearchQuery("")}
        placeholder="Search value drivers..."
      />

      {/* Available Drivers */}
      <div className="space-y-2">
        {driversLoading && (
          <p className="text-sm text-muted-foreground text-center py-4">Loading drivers…</p>
        )}
        {availableDrivers.map((driver) => {
          const isSelected = selectedIds.includes(driver.id);
          const selectedData = selectedDrivers.find((s) => s.driver.id === driver.id);
          const isExpanded = expandedDriver === driver.id;

          return (
            <Card
              key={driver.id}
              className={cn(
                "transition-all cursor-pointer",
                isSelected && "border-primary bg-primary/5"
              )}
            >
              <CardContent className="p-4">
                {/* Header */}
                <div
                  className="flex items-start justify-between"
                  onClick={() => handleSelect(driver)}
                >
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="font-medium">{driver.name}</span>
                      <Badge className={cn("text-xs", TYPE_COLORS[driver.type])}>
                        {VALUE_DRIVER_TYPE_LABELS[driver.type]}
                      </Badge>
                    </div>
                    <p className="text-sm text-muted-foreground">{driver.narrativePitch}</p>
                    <div className="flex items-center gap-2 mt-2">
                      {driver.personaTags.slice(0, 3).map((tag) => (
                        <Badge key={tag} variant="outline" className="text-xs">
                          {PERSONA_TAG_LABELS[tag]}
                        </Badge>
                      ))}
                      {driver.winRateCorrelation && (
                        <span className="text-xs text-emerald-600 flex items-center gap-1">
                          <TrendingUp className="h-3 w-3" />
                          {(driver.winRateCorrelation * 100).toFixed(0)}% win rate
                        </span>
                      )}
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    {isSelected && (
                      <div className="w-6 h-6 rounded-full bg-primary flex items-center justify-center">
                        <Check className="h-4 w-4 text-white" />
                      </div>
                    )}
                  </div>
                </div>

                {/* Expanded: Customize Values */}
                {isSelected && (
                  <div className="mt-4 pt-4 border-t">
                    <div className="flex items-center justify-between mb-3">
                      <span className="text-sm font-medium flex items-center gap-2">
                        <Calculator className="h-4 w-4" />
                        Customize Assumptions
                      </span>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={(e) => {
                          e.stopPropagation();
                          setExpandedDriver(isExpanded ? null : driver.id);
                        }}
                      >
                        {isExpanded ? "Collapse" : "Expand"}
                        <ChevronRight
                          className={cn(
                            "h-4 w-4 ml-1 transition-transform",
                            isExpanded && "rotate-90"
                          )}
                        />
                      </Button>
                    </div>

                    {isExpanded && (
                      <div className="grid grid-cols-2 gap-3 mb-4">
                        {driver.formula.variables.map((variable) => (
                          <div key={variable.id}>
                            <label className="text-xs text-muted-foreground">
                              {variable.label} ({variable.unit})
                            </label>
                            <Input
                              type="number"
                              value={
                                selectedData?.customValues[variable.name] ?? variable.defaultValue
                              }
                              onChange={(e) => {
                                const newValues = {
                                  ...selectedData?.customValues,
                                  [variable.name]: parseFloat(e.target.value) || 0,
                                };
                                onUpdateValues(driver.id, newValues);
                              }}
                              onClick={(e) => e.stopPropagation()}
                              className="mt-1"
                            />
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Calculated Value */}
                    <div className="flex items-center justify-between p-3 bg-emerald-50 rounded-lg">
                      <span className="text-sm font-medium text-emerald-800">
                        Estimated Annual Value
                      </span>
                      <span className="text-xl font-bold text-emerald-700">
                        ${calculateValue(driver, selectedData?.customValues || {}).toLocaleString()}
                      </span>
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* Empty State */}
      {availableDrivers.length === 0 && (
        <div className="text-center py-8">
          <p className="text-muted-foreground">No value drivers match your search</p>
        </div>
      )}

      {/* AI Suggestion */}
      <Card className="border-dashed">
        <CardContent className="p-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center">
                <Sparkles className="h-5 w-5 text-primary" />
              </div>
              <div>
                <p className="font-medium">AI-Suggested Drivers</p>
                <p className="text-sm text-muted-foreground">
                  Get recommendations based on your prospect's industry and role
                </p>
              </div>
            </div>
            <Button variant="outline" size="sm">
              Get Suggestions
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

export default ValueDriverSelector;

