/**
 * Validate required environment variables
 */
export function validateEnvironmentConfig(config: EnvironmentConfig): string[] {
  const errors: string[] = [];

  // Production-specific validations
  if (config.app.env === 'production') {
    if (!config.database.url) {
      errors.push('VITE_SUPABASE_URL is required in production');
    }
    if (!config.database.anonKey) {
      errors.push('VITE_SUPABASE_ANON_KEY is required in production');
    }
    if (!config.agents.apiUrl || config.agents.apiUrl.includes('localhost')) {
      errors.push('VITE_AGENT_API_URL must be set to production URL');
    }
    if (config.security.httpsOnly && !config.app.url.startsWith('https://')) {
      errors.push('VITE_APP_URL must use HTTPS in production');
    }
    // Block mocks in production — the env var must be absent or explicitly false.
    if (config.dev.mocksEnabled) {
      errors.push('DEV_MOCKS_ENABLED must be false (or unset) in production');
    }
  }

  // Agent Fabric validations
  if (config.features.agentFabric) {
    if (!config.agents.apiUrl) {
      errors.push('VITE_AGENT_API_URL is required when Agent Fabric is enabled');
    }
  }

  // Vault validations
  if (config.vault.enabled && !config.vault.address) {
    errors.push('VAULT_ADDR is required when Vault is enabled');
  }

  return errors;
}

/**
 * Global configuration instance
 */
let configInstance: EnvironmentConfig | null = null;

/**
 * Get the current environment configuration
 * Loads and validates on first access
 */
export function getConfig(): EnvironmentConfig {
  if (!configInstance) {
    configInstance = loadEnvironmentConfig();

    // Validate configuration
    const errors = validateEnvironmentConfig(configInstance);
    if (errors.length > 0) {
      // Emit minimal detail to avoid leaking configuration values
      writeStderr(`[Environment] Configuration errors detected: ${errors.length}`);
      if (configInstance.app.env === 'production') {
        throw new Error(`Invalid environment configuration: ${errors.length} errors found`);
      }
    }

    // Log minimal configuration in development only
    if (configInstance.app.env === 'development') {
      writeStdout('[Environment] Configuration loaded for development (redacted)');
    }
  }

  // TypeScript null check - configInstance is guaranteed to be set above
  if (!configInstance) {
    throw new Error('Failed to initialize configuration');
  }

  return configInstance;
}

/**
 * Reset configuration (useful for testing)
 */
export function resetConfig(): void {
  configInstance = null;
}

/**
 * Check if running in production
 */
export function isProduction(): boolean {
  return getConfig().app.env === 'production';
}

/**
 * Check if running in development
 */
export function isDevelopment(): boolean {
  return getConfig().app.env === 'development';
}

/**
 * Check if running in test mode
 */
export function isTest(): boolean {
  return getConfig().test.mode;
}

/**
 * Get feature flag value
 */
export function isFeatureEnabled(feature: keyof EnvironmentConfig['features']): boolean {
  return getConfig().features[feature];
}

/**
 * Export default configuration
 */
export default getConfig();

/**
 * Feature Flags Configuration
 *
 * Usage:
 *   import { featureFlags } from '@/config/featureFlags';
 *   if (featureFlags.ENABLE_UNIFIED_ORCHESTRATION) { ... }
 */

import { logger } from '../lib/logger';

/**
 * Feature flag configuration
 */
export interface FeatureFlags {
  /**
   * Enable unified orchestration (consolidates all orchestrators).
   * Retained for backward compatibility; runtime now uses ExecutionRuntime unconditionally.
   */
  ENABLE_UNIFIED_ORCHESTRATION: boolean;

  /** 
   * @deprecated Use ENABLE_UNIFIED_ORCHESTRATION instead
   * Enable stateless orchestration (fixes singleton state bug) 
   */
  ENABLE_STATELESS_ORCHESTRATION: boolean;

  /** Enable SafeJSON parser (fixes fragile JSON parsing) */
  ENABLE_SAFE_JSON_PARSER: boolean;

  /** Enable input sanitization at entry points */
  ENABLE_INPUT_SANITIZATION: boolean;

  /** Enable trace ID logging for observability */
  ENABLE_TRACE_LOGGING: boolean;

  /** Enable circuit breaker for agent execution */
  ENABLE_CIRCUIT_BREAKER: boolean;

  /** Enable rate limiting */
  ENABLE_RATE_LIMITING: boolean;

  /** Enable audit logging */
  ENABLE_AUDIT_LOGGING: boolean;

  /**
   * Enable Value Commitment Service
   * Sprint 0: Disabled until fully implemented
   */
  ENABLE_VALUE_COMMITMENT_SERVICE: boolean;

  /**
   * Enable Agent placeholder/mock mode
   * Sprint 0: Must be false in production
   */
  ENABLE_AGENT_PLACEHOLDER_MODE: boolean;

  /**
   * Enable client-side LLM streaming
   * Sprint 0: Disabled in production until breaker integration complete
   */
  ENABLE_CLIENT_LLM_STREAMING: boolean;

  /**
   * Enable usage-based metering and Stripe submission.
   * Billing deployment: gradual rollout via percentage.
   */
  ENABLE_BILLING_USAGE_METERING: boolean;

  /**
   * Enable automatic overage billing beyond plan quotas.
   * Billing deployment: enable after metering is stable.
   */
  ENABLE_BILLING_OVERAGE_CHARGING: boolean;

