/**
 * Validate similarity score meets threshold
 */
export function meetsThreshold(
  similarity: number,
  memoryType?: keyof SemanticSearchConfig["typeThresholds"]
): boolean {
  const threshold = memoryType
    ? getSemanticThreshold(memoryType)
    : semanticMemoryConfig.defaultThreshold;
  return similarity >= threshold;
}

/**
 * Calculate adjusted threshold based on context
 *
 * Use for dynamic threshold adjustment based on:
 * - Query specificity (more specific = higher threshold)
 * - Result count (fewer results = lower threshold to ensure recall)
 * - User preference (power users may want precision)
 */
export function calculateAdjustedThreshold(
  baseThreshold: number,
  options: {
    querySpecificity?: "low" | "medium" | "high";
    resultCount?: number;
    userPreference?: "precision" | "balanced" | "recall";
  }
): number {
  let adjusted = baseThreshold;

  // Adjust for query specificity
  if (options.querySpecificity === "high") {
    adjusted += 0.05; // More precise query = higher threshold
  } else if (options.querySpecificity === "low") {
    adjusted -= 0.05; // Broader query = lower threshold
  }

  // Adjust for result count
  if (options.resultCount !== undefined && options.resultCount < 3) {
    adjusted = Math.max(0.5, adjusted - 0.1); // Ensure some results
  }

  // Adjust for user preference
  if (options.userPreference === "precision") {
    adjusted += 0.1;
  } else if (options.userPreference === "recall") {
    adjusted -= 0.1;
  }

  // Clamp to valid range
  return Math.max(0.3, Math.min(0.95, adjusted));
}

/**
 * Progressive Feature Rollout System
 * 
 * Enables gradual feature rollout with automatic rollback on errors
 * 
 * Usage:
 *   const rollout = new ProgressiveRollout('new-ui-redesign');
 *   if (await rollout.isEnabledForUser(userId)) {
 *     // Show new feature
 *   }
 */

import { logger } from '../lib/logger';
import { supabase } from '../lib/supabase';

export interface RolloutConfig {
  featureName: string;
  percentage: number;
  targetGroups?: string[];
  excludeGroups?: string[];
  startDate?: Date;
  endDate?: Date;
  autoRollback?: boolean;
  errorThreshold?: number; // Percentage of errors before rollback
}

export interface RolloutMetrics {
  totalUsers: number;
  enabledUsers: number;
  errors: number;
  errorRate: number;
  lastUpdated: Date;
}

export class ProgressiveRollout {
  private featureName: string;
  private config: RolloutConfig | null = null;
  private metrics: RolloutMetrics | null = null;

  constructor(featureName: string) {
    this.featureName = featureName;
  }

  /**
   * Load rollout configuration from database
   */
  async loadConfig(): Promise<RolloutConfig | null> {
    try {
      const { data, error } = await supabase
        .from('feature_rollouts')
        .select('*')
        .eq('feature_name', this.featureName)
        .eq('active', true)
        .single();

      if (error) {
        logger.warn('Failed to load rollout config', { feature: this.featureName, error });
        return null;
      }

      this.config = {
        featureName: data.feature_name,
        percentage: data.percentage,
        targetGroups: data.target_groups,
        excludeGroups: data.exclude_groups,
        startDate: data.start_date ? new Date(data.start_date) : undefined,
        endDate: data.end_date ? new Date(data.end_date) : undefined,
        autoRollback: data.auto_rollback ?? true,
        errorThreshold: data.error_threshold ?? 5.0,
      };

      return this.config;
    } catch (error) {
      logger.error('Error loading rollout config', { feature: this.featureName, error });
      return null;
    }
  }

  /**
   * Check if feature is enabled for a specific user
   */
  async isEnabledForUser(userId: string, userGroups?: string[]): Promise<boolean> {
    // Load config if not already loaded
    if (!this.config) {
      await this.loadConfig();
    }

    // If no config, feature is disabled
    if (!this.config) {
      return false;
    }

    // Check date range
    const now = new Date();
    if (this.config.startDate && now < this.config.startDate) {
      return false;
    }
    if (this.config.endDate && now > this.config.endDate) {
      return false;
    }

    // Check exclude groups
    if (this.config.excludeGroups && userGroups) {
      const hasExcludedGroup = userGroups.some(group => 
        this.config!.excludeGroups!.includes(group)
      );
      if (hasExcludedGroup) {
        return false;
      }
    }

    // Check target groups (if specified, user must be in one)
    if (this.config.targetGroups && this.config.targetGroups.length > 0) {
      if (!userGroups) {
        return false;
      }
      const hasTargetGroup = userGroups.some(group => 
        this.config!.targetGroups!.includes(group)
      );
      if (!hasTargetGroup) {
        return false;
      }
    }

    // Check percentage rollout (deterministic hash-based)
    const isInRollout = this.isUserInPercentage(userId, this.config.percentage);

    // Track usage
    await this.trackUsage(userId, isInRollout);

    return isInRollout;
  }

  /**
   * Deterministic hash-based percentage check
   */
  private isUserInPercentage(userId: string, percentage: number): boolean {
    if (percentage >= 100) return true;
    if (percentage <= 0) return false;

    // Hash user ID to get consistent result
    const hash = this.hashString(userId + this.featureName);
    return (hash % 100) < percentage;
  }

  /**
   * Simple hash function for deterministic rollout
   */
  private hashString(str: string): number {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash; // Convert to 32-bit integer
    }
    return Math.abs(hash);
  }

  /**
   * Track feature usage
   */
  private async trackUsage(userId: string, enabled: boolean): Promise<void> {
    try {
      await supabase.from('feature_usage').insert({
        feature_name: this.featureName,
        user_id: userId,
        enabled,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      // Don't fail if tracking fails
      logger.warn('Failed to track feature usage', { feature: this.featureName, error });
    }
  }

  /**
   * Track feature error
   */
  async trackError(userId: string, error: Error): Promise<void> {
    try {
      await supabase.from('feature_errors').insert({
        feature_name: this.featureName,
        user_id: userId,
        error_message: error.message,
        error_stack: error.stack,
        timestamp: new Date().toISOString(),
      });

      // Check if we should auto-rollback
      await this.checkAutoRollback();
    } catch (err) {
      logger.error('Failed to track feature error', { feature: this.featureName, error: err });
    }
  }

  /**
   * Get current rollout metrics
   */
  async getMetrics(): Promise<RolloutMetrics> {
    try {
      // Get usage stats
      const { data: usageData, error: usageError } = await supabase
        .from('feature_usage')
        .select('enabled')
        .eq('feature_name', this.featureName)
        .gte('timestamp', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString()); // Last 24 hours

      if (usageError) throw usageError;

      const totalUsers = usageData.length;
      const enabledUsers = usageData.filter(u => u.enabled).length;

      // Get error stats
      const { data: errorData, error: errorError } = await supabase
        .from('feature_errors')
        .select('id')
        .eq('feature_name', this.featureName)
        .gte('timestamp', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString());

      if (errorError) throw errorError;

      const errors = errorData.length;
      const errorRate = enabledUsers > 0 ? (errors / enabledUsers) * 100 : 0;

      this.metrics = {
        totalUsers,
        enabledUsers,
        errors,
        errorRate,
        lastUpdated: new Date(),
      };

      return this.metrics;
    } catch (error) {
      logger.error('Failed to get rollout metrics', { feature: this.featureName, error });
      throw error;
    }
  }

  /**
   * Check if auto-rollback should be triggered
   */
  private async checkAutoRollback(): Promise<void> {
    if (!this.config?.autoRollback) {
      return;
    }

    const metrics = await this.getMetrics();

    if (metrics.errorRate > (this.config.errorThreshold ?? 5.0)) {
      logger.error('Auto-rollback triggered', {
        feature: this.featureName,
        errorRate: metrics.errorRate,
        threshold: this.config.errorThreshold,
      });

      await this.rollback('Auto-rollback due to high error rate');
    }
  }

  /**
   * Manually rollback feature
   */
  async rollback(reason: string): Promise<void> {
    try {
      await supabase
        .from('feature_rollouts')
        .update({
          active: false,
          rollback_reason: reason,
          rollback_at: new Date().toISOString(),
        })
        .eq('feature_name', this.featureName);

      logger.info('Feature rolled back', { feature: this.featureName, reason });

      // Send alert
      await this.sendRollbackAlert(reason);
    } catch (error) {
      logger.error('Failed to rollback feature', { feature: this.featureName, error });
      throw error;
    }
  }

  /**
   * Gradually increase rollout percentage
   */
  async increasePercentage(newPercentage: number): Promise<void> {
    if (newPercentage < 0 || newPercentage > 100) {
      throw new Error('Percentage must be between 0 and 100');
    }

    try {
      await supabase
        .from('feature_rollouts')
        .update({
          percentage: newPercentage,
          updated_at: new Date().toISOString(),
        })
        .eq('feature_name', this.featureName);

      logger.info('Rollout percentage increased', {
        feature: this.featureName,
        percentage: newPercentage,
      });

      // Reload config
      await this.loadConfig();
    } catch (error) {
      logger.error('Failed to increase rollout percentage', {
        feature: this.featureName,
        error,
      });
      throw error;
    }
  }

  /**
   * Send rollback alert
   */
  private async sendRollbackAlert(reason: string): Promise<void> {
    const webhookUrl = import.meta.env.VITE_WEBHOOK_URL as string | undefined;
    if (!webhookUrl) {
      logger.warn('VITE_WEBHOOK_URL not configured; rollback alert not sent', {
        feature: this.featureName,
      });
      return;
    }

    try {
      // eslint-disable-next-line no-restricted-globals
      await fetch(webhookUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          type: 'feature_rollback',
          feature: this.featureName,
          reason,
          metrics: this.metrics,
          timestamp: new Date().toISOString(),
        }),
      });
    } catch (error) {
      logger.error('Failed to send rollback alert', { feature: this.featureName, error });
    }
  }
}

/**
 * Progressive rollout manager
 */
export class RolloutManager {
  private rollouts: Map<string, ProgressiveRollout> = new Map();

  /**
   * Get or create rollout instance
   */
  getRollout(featureName: string): ProgressiveRollout {
    if (!this.rollouts.has(featureName)) {
      this.rollouts.set(featureName, new ProgressiveRollout(featureName));
    }
    return this.rollouts.get(featureName)!;
  }

  /**
   * Check if feature is enabled for user
   */
  async isEnabled(
    featureName: string,
    userId: string,
    userGroups?: string[]
  ): Promise<boolean> {
    const rollout = this.getRollout(featureName);
    return rollout.isEnabledForUser(userId, userGroups);
  }

  /**
   * Track error for feature
   */
  async trackError(featureName: string, userId: string, error: Error): Promise<void> {
    const rollout = this.getRollout(featureName);
    await rollout.trackError(userId, error);
  }

  /**
   * Get metrics for all active rollouts
   */
  async getAllMetrics(): Promise<Map<string, RolloutMetrics>> {
    const metrics = new Map<string, RolloutMetrics>();

    for (const [featureName, rollout] of this.rollouts) {
      try {
        const rolloutMetrics = await rollout.getMetrics();
        metrics.set(featureName, rolloutMetrics);
      } catch (error) {
        logger.error('Failed to get metrics for rollout', { featureName, error });
      }
    }

    return metrics;
  }
}

/**
 * Global rollout manager instance
 */
export const rolloutManager = new RolloutManager();

/**
 * React hook for feature flags with progressive rollout
 */
export function useFeatureRollout(featureName: string, userId: string, userGroups?: string[]) {
  const [enabled, setEnabled] = React.useState(false);
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    let mounted = true;

    async function checkFeature() {
      try {
        const isEnabled = await rolloutManager.isEnabled(featureName, userId, userGroups);
        if (mounted) {
          setEnabled(isEnabled);
          setLoading(false);
        }
      } catch (error) {
        logger.error('Failed to check feature rollout', { featureName, error });
        if (mounted) {
          setEnabled(false);
          setLoading(false);
        }
      }
    }

    checkFeature();

    return () => {
      mounted = false;
    };
  }, [featureName, userId, userGroups]);

  return { enabled, loading };
}

/**
 * AWS Secrets Manager Provider
 * 
 * Implementation of ISecretProvider for AWS Secrets Manager
 * Refactored from secretsManager.v2.ts to use provider interface
 * 
 * Sprint 2: Provider Abstraction
 * Created: 2024-11-29
 */

import { CreateSecretCommand, GetSecretValueCommand, SecretsManagerClient } from '@aws-sdk/client-secrets-manager';
import type { DeleteSecretCommandInput } from '@aws-sdk/client-secrets-manager/dist-types/commands/DeleteSecretCommand';
import type { DescribeSecretCommandInput } from '@aws-sdk/client-secrets-manager/dist-types/commands/DescribeSecretCommand';
import type { ListSecretsCommandInput } from '@aws-sdk/client-secrets-manager/dist-types/commands/ListSecretsCommand';
import type { PutSecretValueCommandInput } from '@aws-sdk/client-secrets-manager/dist-types/commands/PutSecretValueCommand';
import type { RotateSecretCommandInput } from '@aws-sdk/client-secrets-manager/dist-types/commands/RotateSecretCommand';

// AWS SDK v3 bundles all commands into a single CJS entry point. Under
// moduleResolution:"bundler" the TypeScript barrel does not re-export these
// five commands, so we import their constructors from the CJS bundle directly.
// The input types above are imported from the stable dist-types declarations.
const {
  DeleteSecretCommand,
  DescribeSecretCommand,
  ListSecretsCommand,
  PutSecretValueCommand,
  RotateSecretCommand,
} = require('@aws-sdk/client-secrets-manager') as {
  DeleteSecretCommand: new (input: DeleteSecretCommandInput) => InstanceType<typeof import('@aws-sdk/client-secrets-manager/dist-types/commands/DeleteSecretCommand').DeleteSecretCommand>;
  DescribeSecretCommand: new (input: DescribeSecretCommandInput) => InstanceType<typeof import('@aws-sdk/client-secrets-manager/dist-types/commands/DescribeSecretCommand').DescribeSecretCommand>;
  ListSecretsCommand: new (input: ListSecretsCommandInput) => InstanceType<typeof import('@aws-sdk/client-secrets-manager/dist-types/commands/ListSecretsCommand').ListSecretsCommand>;
  PutSecretValueCommand: new (input: PutSecretValueCommandInput) => InstanceType<typeof import('@aws-sdk/client-secrets-manager/dist-types/commands/PutSecretValueCommand').PutSecretValueCommand>;
  RotateSecretCommand: new (input: RotateSecretCommandInput) => InstanceType<typeof import('@aws-sdk/client-secrets-manager/dist-types/commands/RotateSecretCommand').RotateSecretCommand>;
};

import { logger } from '../../lib/logger';

import type {
  AuditAction,
  AuditResult,
  ISecretProvider,
  SecretMetadata,
  SecretValue
} from './ISecretProvider';
import { SecretAuditEvent, StructuredSecretAuditLogger } from './SecretAuditLogger';

/**
 * AWS Secrets Manager provider implementation
 */
export class AWSSecretProvider implements ISecretProvider {
  private client: SecretsManagerClient;
  private environment: string;
  private cache: Map<string, { value: SecretValue; expiresAt: number }> = new Map();
  private cacheTTL: number;
  private auditLogger: StructuredSecretAuditLogger;

  constructor(
    region: string = 'us-east-1',
    cacheTTL: number = 300000 // 5 minutes
  ) {
    this.client = new SecretsManagerClient({ region });
    this.environment = process.env.NODE_ENV || 'development';
    this.cacheTTL = cacheTTL;
    this.auditLogger = new StructuredSecretAuditLogger();

    logger.info('AWS Secret Provider initialized', {
      provider: 'aws',
      region,
      environment: this.environment
    });
  }

  /**
   * Generate tenant-isolated AWS secret path
   */
  private getTenantSecretPath(tenantId: string, secretKey: string): string {
    if (!tenantId || !secretKey) {
      throw new Error('Tenant ID and secret key are required');
    }

    // Validate format
    if (!/^[a-zA-Z0-9-_]+$/.test(tenantId)) {
      throw new Error('Invalid tenant ID format');
    }

    return `valuecanvas/${this.environment}/tenants/${tenantId}/${secretKey}`;
  }

  /**
   * Get cache key
   */
  private getCacheKey(tenantId: string, secretKey: string): string {
    return `${tenantId}:${secretKey}`;
  }

  async getSecret(
    tenantId: string,
    secretKey: string,
    version?: string,
    userId?: string
  ): Promise<SecretValue> {
    const startTime = Date.now();
    const secretPath = this.getTenantSecretPath(tenantId, secretKey);

    // Check cache
    const cacheKey = this.getCacheKey(tenantId, secretKey);
    const cached = this.cache.get(cacheKey);

    if (cached && cached.expiresAt > Date.now()) {
      await this.auditAccess(tenantId, secretKey, 'READ', 'SUCCESS', userId, undefined, {
        source: 'cache',
        latency_ms: Date.now() - startTime
      });
      return cached.value;
    }

    try {
      const command = new GetSecretValueCommand({
        SecretId: secretPath,
        VersionId: version
      });

      const response = await this.client.send(command);

      if (!response.SecretString) {
        throw new Error('Secret value is empty');
      }

      const secretValue = JSON.parse(response.SecretString) as SecretValue;

      // Cache the secret
      this.cache.set(cacheKey, {
        value: secretValue,
        expiresAt: Date.now() + this.cacheTTL
      });

      await this.auditAccess(tenantId, secretKey, 'READ', 'SUCCESS', userId, undefined, {
        source: 'aws',
        latency_ms: Date.now() - startTime,
        version
      });

      return secretValue;
    } catch (error) {
      await this.auditAccess(
        tenantId,
        secretKey,
        'READ',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error),
        { latency_ms: Date.now() - startTime }
      );

      logger.error('Failed to get secret from AWS', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretPath
      });

      throw error;
    }
  }

  async setSecret(
    tenantId: string,
    secretKey: string,
    value: SecretValue,
    metadata: SecretMetadata,
    userId?: string
  ): Promise<boolean> {
    const secretPath = this.getTenantSecretPath(tenantId, secretKey);

    try {
      // Add metadata to secret
      const secretWithMetadata = {
        ...value,
        _metadata: {
          tenantId: metadata.tenantId,
          sensitivityLevel: metadata.sensitivityLevel,
          createdAt: metadata.createdAt,
          version: metadata.version,
          rotationPolicy: metadata.rotationPolicy,
          tags: metadata.tags
        }
      };

      const command = new PutSecretValueCommand({
        SecretId: secretPath,
        SecretString: JSON.stringify(secretWithMetadata)
      });

      await this.client.send(command);

      // Invalidate cache
      const cacheKey = this.getCacheKey(tenantId, secretKey);
      this.cache.delete(cacheKey);

      await this.auditAccess(tenantId, secretKey, 'WRITE', 'SUCCESS', userId);

      logger.info('Secret set successfully in AWS', {
        tenantId,
        secretKey,
        sensitivityLevel: metadata.sensitivityLevel
      });

      return true;
    } catch (error) {
      await this.auditAccess(
        tenantId,
        secretKey,
        'WRITE',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error)
      );

      logger.error('Failed to set secret in AWS', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretPath
      });

      throw error;
    }
  }

  async rotateSecret(
    tenantId: string,
    secretKey: string,
    userId?: string
  ): Promise<boolean> {
    const secretPath = this.getTenantSecretPath(tenantId, secretKey);

    try {
      const command = new RotateSecretCommand({
        SecretId: secretPath
      });

      await this.client.send(command);

      // Invalidate cache
      const cacheKey = this.getCacheKey(tenantId, secretKey);
      this.cache.delete(cacheKey);

      await this.auditAccess(tenantId, secretKey, 'ROTATE', 'SUCCESS', userId);

      logger.info('Secret rotation initiated in AWS', {
        tenantId,
        secretKey
      });

      return true;
    } catch (error) {
      await this.auditAccess(
        tenantId,
        secretKey,
        'ROTATE',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error)
      );

      logger.error('Failed to rotate secret in AWS', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretPath
      });

      throw error;
    }
  }

  async deleteSecret(
    tenantId: string,
    secretKey: string,
    userId?: string
  ): Promise<boolean> {
    const secretPath = this.getTenantSecretPath(tenantId, secretKey);

    try {
      const command = new DeleteSecretCommand({
        SecretId: secretPath,
        ForceDeleteWithoutRecovery: false, // Allow recovery window
        RecoveryWindowInDays: 30
      });

      await this.client.send(command);

      // Invalidate cache
      const cacheKey = this.getCacheKey(tenantId, secretKey);
      this.cache.delete(cacheKey);

      await this.auditAccess(tenantId, secretKey, 'DELETE', 'SUCCESS', userId);

      logger.info('Secret deleted from AWS', {
        tenantId,
        secretKey,
        recoveryWindowDays: 30
      });

      return true;
    } catch (error) {
      await this.auditAccess(
        tenantId,
        secretKey,
        'DELETE',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error)
      );

      logger.error('Failed to delete secret from AWS', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretPath
      });

      throw error;
    }
  }

  async listSecrets(tenantId: string, userId?: string): Promise<string[]> {
    const prefix = `valuecanvas/${this.environment}/tenants/${tenantId}/`;

    try {
      const command = new ListSecretsCommand({
        Filters: [
          {
            Key: 'name',
            Values: [prefix]
          }
        ]
      });

      const response = await this.client.send(command);
      const secrets = response.SecretList || [];

      // Extract secret keys from full paths
      const secretKeys = secrets
        .map(s => s.Name?.replace(prefix, '') || '')
        .filter(Boolean);

      await this.auditAccess(tenantId, 'ALL', 'LIST', 'SUCCESS', userId, undefined, {
        count: secretKeys.length
      });

      return secretKeys;
    } catch (error) {
      await this.auditAccess(
        tenantId,
        'ALL',
        'LIST',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error)
      );

      logger.error('Failed to list secrets from AWS', error instanceof Error ? error : new Error(String(error)), {
        tenantId
      });

      throw error;
    }
  }

  async getSecretMetadata(
    tenantId: string,
    secretKey: string,
    userId?: string
  ): Promise<SecretMetadata | null> {
    const secretPath = this.getTenantSecretPath(tenantId, secretKey);

    try {
      const command = new DescribeSecretCommand({
        SecretId: secretPath
      });

      const response = await this.client.send(command);

      if (!response.Name) {
        return null;
      }

      // Extract metadata from AWS response
      const metadata: SecretMetadata = {
        tenantId,
        secretPath: response.Name,
        version: response.VersionIdsToStages ? Object.keys(response.VersionIdsToStages)[0] : 'latest',
        createdAt: response.CreatedDate?.toISOString() || new Date().toISOString(),
        lastAccessed: response.LastAccessedDate?.toISOString() || new Date().toISOString(),
        sensitivityLevel: 'high', // Default, should be in tags
        tags: response.Tags?.reduce((acc, tag) => {
          if (tag.Key && tag.Value) {
            acc[tag.Key] = tag.Value;
          }
          return acc;
        }, {} as Record<string, string>)
      };

      return metadata;
    } catch (error) {
      logger.error('Failed to get secret metadata from AWS', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretPath
      });

      return null;
    }
  }

  async secretExists(
    tenantId: string,
    secretKey: string,
    userId?: string
  ): Promise<boolean> {
    try {
      const metadata = await this.getSecretMetadata(tenantId, secretKey, userId);
      return metadata !== null;
    } catch (error) {
      return false;
    }
  }

  async auditAccess(
    tenantId: string,
    secretKey: string,
    action: AuditAction,
    result: AuditResult,
    userId?: string,
    error?: string,
    metadata?: Record<string, any>
  ): Promise<void> {
    const event: SecretAuditEvent = {
      tenantId,
      userId,
      secretKey,
      action,
      result,
      error,
      metadata
    };

    if (result === 'SUCCESS') {
      if (action === 'ROTATE') {
        await this.auditLogger.logRotation(event);
      } else {
        await this.auditLogger.logAccess(event);
      }
    } else {
      await this.auditLogger.logDenied({ ...event, reason: error || 'Unknown error' });
    }
  }

  private maskSecretKey(key: string): string {
    if (key === 'ALL' || key.length <= 8) {
      return key;
    }
    return `${key.substring(0, 4)}...${key.substring(key.length - 4)}`;
  }

  getProviderName(): string {
    return 'aws';
  }

  async healthCheck(): Promise<boolean> {
    try {
      // Simple check - list secrets with limit 1
      const command = new ListSecretsCommand({ MaxResults: 1 });
      await this.client.send(command);
      return true;
    } catch (error) {
      logger.error('AWS provider health check failed', error instanceof Error ? error : new Error(String(error)));
      return false;
    }
  }

  /**
   * Clear cache for testing/maintenance
   */
  clearCache(tenantId?: string): void {
    if (tenantId) {
      // Clear cache for specific tenant
      for (const [key] of this.cache.entries()) {
        if (key.startsWith(`${tenantId}:`)) {
          this.cache.delete(key);
        }
      }
    } else {
      this.cache.clear();
    }
  }
}

/**
 * Cache Encryption
 * 
 * Encrypts cached secrets at rest using AES-256-GCM
 * Protects against memory dumps and process inspection
 * 
 * Sprint 4: Advanced Features
 * Created: 2024-11-29
 */

import { createCipheriv, createDecipheriv, createHash, randomBytes } from 'crypto';

import { logger } from '../../lib/logger';

/**
 * Encrypted cache entry
 */
export interface EncryptedCacheEntry {
  encrypted: Buffer;
  iv: Buffer;
  authTag: Buffer;
  expiresAt: number;
}

/**
 * Cache encryption configuration
 */
export interface EncryptionConfig {
  algorithm: string;
  keyDerivation: 'pbkdf2' | 'scrypt';
  cacheTTL: number;
}

/**
 * Cache encryption manager
 * 
 * Encrypts secrets in memory using AES-256-GCM
 * Keys derived from KMS or environment
 */
export class CacheEncryption {
  private algorithm: string = 'aes-256-gcm';
  private encryptionKey: Buffer;
  private cacheTTL: number;
  private encryptionEnabled: boolean;

  constructor(config?: Partial<EncryptionConfig>) {
    this.algorithm = config?.algorithm || 'aes-256-gcm';
    this.cacheTTL = config?.cacheTTL || 300000; // 5 minutes

    // Initialize encryption key
    this.encryptionKey = this.deriveEncryptionKey();

    // Check if encryption is enabled
    this.encryptionEnabled = process.env.CACHE_ENCRYPTION_ENABLED !== 'false';

    if (this.encryptionEnabled) {
      logger.info('Cache encryption initialized', {
        algorithm: this.algorithm,
        cacheTTL: this.cacheTTL
      });
    } else {
      logger.warn('Cache encryption is DISABLED - not recommended for production');
    }
  }

  /**
   * Derive encryption key from environment or KMS
   */
  private deriveEncryptionKey(): Buffer {
    // In production, this should fetch from KMS (AWS KMS, GCP KMS, etc.)
    // For now, derive from environment variable or generate

    const masterKey = process.env.CACHE_ENCRYPTION_KEY;

    if (masterKey) {
      // Derive key using SHA-256
      return createHash('sha256')
        .update(masterKey)
        .digest();
    }

    // Generate random key (WARNING: not persistent across restarts)
    logger.warn('No CACHE_ENCRYPTION_KEY set - generating random key (not persistent)');
    return randomBytes(32);
  }

  /**
   * Encrypt cache entry
   */
  encrypt(data: unknown, tenantId: string): EncryptedCacheEntry {
    if (!this.encryptionEnabled) {
      // Return unencrypted (for development only)
      return {
        encrypted: Buffer.from(JSON.stringify(data)),
        iv: Buffer.alloc(0),
        authTag: Buffer.alloc(0),
        expiresAt: Date.now() + this.cacheTTL
      };
    }

    const startTime = Date.now();

    try {
      // Generate random IV
      const iv = randomBytes(16);

      // Create cipher
      const cipher = createCipheriv(this.algorithm, this.encryptionKey, iv);

      // Add tenant ID as additional authenticated data (AAD)
      cipher.setAAD(Buffer.from(tenantId));

      // Encrypt
      const plaintext = JSON.stringify(data);
      let encrypted = cipher.update(plaintext, 'utf8');
      encrypted = Buffer.concat([encrypted, cipher.final()]);

      // Get auth tag
      const authTag = cipher.getAuthTag();

      const duration = Date.now() - startTime;

      logger.debug('Cache entry encrypted', {
        tenantId,
        size: encrypted.length,
        duration
      });

      return {
        encrypted,
        iv,
        authTag,
        expiresAt: Date.now() + this.cacheTTL
      };
    } catch (error) {
      logger.error('Encryption failed', error instanceof Error ? error : new Error(String(error)), {
        tenantId
      });
      throw error;
    }
  }

  /**
   * Decrypt cache entry
   */
  decrypt(entry: EncryptedCacheEntry, tenantId: string): unknown {
    if (!this.encryptionEnabled) {
      // Return unencrypted (for development only)
      return JSON.parse(entry.encrypted.toString());
    }

    const startTime = Date.now();

    // Check if expired
    if (entry.expiresAt < Date.now()) {
      throw new Error('Cache entry expired');
    }

    try {
      // Create decipher
      const decipher = createDecipheriv(this.algorithm, this.encryptionKey, entry.iv);

      // Set AAD
      decipher.setAAD(Buffer.from(tenantId));

      // Set auth tag
      decipher.setAuthTag(entry.authTag);

      // Decrypt
      let decrypted = decipher.update(entry.encrypted);
      decrypted = Buffer.concat([decrypted, decipher.final()]);

      const duration = Date.now() - startTime;

      logger.debug('Cache entry decrypted', {
        tenantId,
        duration
      });

      return JSON.parse(decrypted.toString('utf8'));
    } catch (error) {
      logger.error('Decryption failed', error instanceof Error ? error : new Error(String(error)), {
        tenantId
      });
      throw error;
    }
  }

  /**
   * Check if entry is expired
   */
  isExpired(entry: EncryptedCacheEntry): boolean {
    return entry.expiresAt < Date.now();
  }

  /**
   * Rotate encryption key (for key rotation)
   */
  rotateKey(newMasterKey: string): void {
    logger.info('Rotating cache encryption key');

    this.encryptionKey = createHash('sha256')
      .update(newMasterKey)
      .digest();

    logger.info('Cache encryption key rotated successfully');
  }

  /**
   * Get encryption statistics
   */
  getStatistics(): {
    enabled: boolean;
    algorithm: string;
    keySize: number;
  } {
    return {
      enabled: this.encryptionEnabled,
      algorithm: this.algorithm,
      keySize: this.encryptionKey.length * 8 // bits
    };
  }

  /**
   * Benchmark encryption performance
   */
  async benchmark(iterations: number = 1000): Promise<{
    averageEncryptionMs: number;
    averageDecryptionMs: number;
    throughputMBps: number;
  }> {
    const testData = { test: 'A'.repeat(1000) }; // 1KB test data
    const tenantId = 'benchmark-tenant';

    let totalEncryptMs = 0;
    let totalDecryptMs = 0;

    for (let i = 0; i < iterations; i++) {
      // Encrypt
      const encStart = Date.now();
      const encrypted = this.encrypt(testData, tenantId);
      totalEncryptMs += Date.now() - encStart;

      // Decrypt
      const decStart = Date.now();
      this.decrypt(encrypted, tenantId);
      totalDecryptMs += Date.now() - decStart;
    }

    const averageEncryptionMs = totalEncryptMs / iterations;
    const averageDecryptionMs = totalDecryptMs / iterations;

    // Calculate throughput (MB/s)
    const totalMs = totalEncryptMs + totalDecryptMs;
    const totalMB = (1 / 1024) * iterations * 2; // 1KB * iterations * 2 operations
    const throughputMBps = (totalMB / totalMs) * 1000;

    logger.info('Cache encryption benchmark complete', {
      iterations,
      averageEncryptionMs,
      averageDecryptionMs,
      throughputMBps
    });

    return {
      averageEncryptionMs,
      averageDecryptionMs,
      throughputMBps
    };
  }
}

/**
 * Encrypted cache store
 * 
 * Wrapper around Map with automatic encryption/decryption
 */
export class EncryptedCacheStore<T = any> {
  private store: Map<string, EncryptedCacheEntry> = new Map();
  private encryption: CacheEncryption;

  constructor(encryption: CacheEncryption) {
    this.encryption = encryption;
  }

  /**
   * Set value in cache
   */
  set(key: string, value: T, tenantId: string): void {
    const encrypted = this.encryption.encrypt(value, tenantId);
    this.store.set(key, encrypted);
  }

  /**
   * Get value from cache
   */
  get(key: string, tenantId: string): T | null {
    const entry = this.store.get(key);

    if (!entry) {
      return null;
    }

    // Check expiration
    if (this.encryption.isExpired(entry)) {
      this.store.delete(key);
      return null;
    }

    try {
      return this.encryption.decrypt(entry, tenantId) as T;
    } catch (error) {
      logger.error('Failed to decrypt cache entry', error instanceof Error ? error : new Error(String(error)), {
        key,
        tenantId
      });
      this.store.delete(key);
      return null;
    }
  }

  /**
   * Check if key exists and is not expired
   */
  has(key: string): boolean {
    const entry = this.store.get(key);

    if (!entry) {
      return false;
    }

    if (this.encryption.isExpired(entry)) {
      this.store.delete(key);
      return false;
    }

    return true;
  }

  /**
   * Delete key
   */
  delete(key: string): boolean {
    return this.store.delete(key);
  }

  /**
   * Clear all entries
   */
  clear(): void {
    this.store.clear();
  }

  /**
   * Get cache size
   */
  size(): number {
    return this.store.size;
  }

  /**
   * Prune expired entries
   */
  pruneExpired(): number {
    let pruned = 0;

    for (const [key, entry] of this.store.entries()) {
      if (this.encryption.isExpired(entry)) {
        this.store.delete(key);
        pruned++;
      }
    }

    if (pruned > 0) {
      logger.info('Pruned expired cache entries', { pruned });
    }

    return pruned;
  }
}

/**
 * Create cache encryption from environment
 */
export function createCacheEncryption(): CacheEncryption {
  return new CacheEncryption({
    algorithm: process.env.CACHE_ENCRYPTION_ALGORITHM || 'aes-256-gcm',
    cacheTTL: parseInt(process.env.CACHE_TTL || '300000', 10)
  });
}

/**
 * Global cache encryption instance
 */
export const cacheEncryption = createCacheEncryption();

/**
 * Secret Dependency Tracking
 * 
 * Tracks which services/components depend on which secrets
 * Enables impact analysis for secret rotation
 * 
 * Sprint 4: Advanced Features
 * Created: 2024-11-29
 */

import { logger } from '../../lib/logger';

/**
 * Service that depends on a secret
 */
export interface SecretDependency {
  serviceId: string;
  serviceName: string;
  serviceType: 'api' | 'worker' | 'cron' | 'function';
  environment: 'production' | 'staging' | 'development';
  lastAccess: Date;
  accessCount: number;
}

/**
 * Impact analysis result
 */
export interface ImpactAnalysis {
  tenantId: string;
  secretKey: string;
  affectedServices: SecretDependency[];
  estimatedDowntime: number; // minutes
  criticalityLevel: 'low' | 'medium' | 'high' | 'critical';
  rotationWindow: string;
}

/**
 * Dependency graph node
 */
export interface DependencyNode {
  id: string;
  type: 'secret' | 'service';
  label: string;
  connections: string[];
}

/**
 * Secret dependency tracking system
 * 
 * Maintains registry of secret-to-service dependencies
 */
export class DependencyTracking {
  private dependencies: Map<string, Set<SecretDependency>> = new Map();

  constructor() {
    logger.info('Dependency tracking initialized');
  }

  /**
   * Get dependency key
   */
  private getDependencyKey(tenantId: string, secretKey: string): string {
    return `${tenantId}:${secretKey}`;
  }

  /**
   * Register a dependency
   */
  registerDependency(
    tenantId: string,
    secretKey: string,
    service: Omit<SecretDependency, 'lastAccess' | 'accessCount'>
  ): void {
    const key = this.getDependencyKey(tenantId, secretKey);

    if (!this.dependencies.has(key)) {
      this.dependencies.set(key, new Set());
    }

    const deps = this.dependencies.get(key)!;

    // Find existing or create new
    let existing: SecretDependency | undefined;
    for (const dep of deps) {
      if (dep.serviceId === service.serviceId) {
        existing = dep;
        break;
      }
    }

    if (existing) {
      // Update existing
      existing.lastAccess = new Date();
      existing.accessCount++;
    } else {
      // Add new
      deps.add({
        ...service,
        lastAccess: new Date(),
        accessCount: 1
      });
    }

    logger.debug('Dependency registered', {
      tenantId,
      secretKey,
      serviceId: service.serviceId
    });
  }

  /**
   * Record secret access by a service
   */
  recordAccess(
    tenantId: string,
    secretKey: string,
    serviceId: string
  ): void {
    const key = this.getDependencyKey(tenantId, secretKey);
    const deps = this.dependencies.get(key);

    if (!deps) {
      return;
    }

    for (const dep of deps) {
      if (dep.serviceId === serviceId) {
        dep.lastAccess = new Date();
        dep.accessCount++;
        break;
      }
    }
  }

  /**
   * Get all dependencies for a secret
   */
  getDependencies(
    tenantId: string,
    secretKey: string
  ): SecretDependency[] {
    const key = this.getDependencyKey(tenantId, secretKey);
    const deps = this.dependencies.get(key);

    if (!deps) {
      return [];
    }

    return Array.from(deps);
  }

  /**
   * Analyze impact of rotating a secret
   */
  analyzeImpact(
    tenantId: string,
    secretKey: string
  ): ImpactAnalysis {
    const dependencies = this.getDependencies(tenantId, secretKey);

    // Calculate criticality based on number and type of services
    let criticalityLevel: ImpactAnalysis['criticalityLevel'] = 'low';

    const hasProduction = dependencies.some(d => d.environment === 'production');
    const hasApi = dependencies.some(d => d.serviceType === 'api');

    if (hasProduction && hasApi && dependencies.length > 5) {
      criticalityLevel = 'critical';
    } else if (hasProduction && dependencies.length > 3) {
      criticalityLevel = 'high';
    } else if (dependencies.length > 1) {
      criticalityLevel = 'medium';
    }

    // Estimate downtime (in minutes)
    // API services: 5 min per service
    // Workers: 2 min per service
    // Others: 1 min per service
    let estimatedDowntime = 0;
    for (const dep of dependencies) {
      switch (dep.serviceType) {
        case 'api':
          estimatedDowntime += 5;
          break;
        case 'worker':
          estimatedDowntime += 2;
          break;
        default:
          estimatedDowntime += 1;
      }
    }

    // Recommend rotation window based on criticality
    let rotationWindow = '';
    switch (criticalityLevel) {
      case 'critical':
        rotationWindow = 'Saturday 2:00 AM - 4:00 AM (low traffic period)';
        break;
      case 'high':
        rotationWindow = 'Sunday 1:00 AM - 3:00 AM';
        break;
      case 'medium':
        rotationWindow = 'Any night 2:00 AM - 4:00 AM';
        break;
      case 'low':
        rotationWindow = 'Anytime';
        break;
    }

    logger.info('Impact analysis complete', {
      tenantId,
      secretKey,
      affectedServices: dependencies.length,
      criticalityLevel,
      estimatedDowntime
    });

    return {
      tenantId,
      secretKey,
      affectedServices: dependencies,
      estimatedDowntime,
      criticalityLevel,
      rotationWindow
    };
  }

  /**
   * Generate dependency graph
   */
  generateDependencyGraph(tenantId: string): DependencyNode[] {
    const nodes: DependencyNode[] = [];
    const serviceNodes = new Map<string, DependencyNode>();

    // Create nodes for all secrets and services
    for (const [key, deps] of this.dependencies.entries()) {
      const [tid, secretKey] = key.split(':');

      if (tid !== tenantId) {
        continue;
      }

      // Secret node
      const secretNode: DependencyNode = {
        id: `secret:${secretKey}`,
        type: 'secret',
        label: secretKey,
        connections: []
      };

      // Service nodes
      for (const dep of deps) {
        if (!serviceNodes.has(dep.serviceId)) {
          serviceNodes.set(dep.serviceId, {
            id: `service:${dep.serviceId}`,
            type: 'service',
            label: dep.serviceName,
            connections: []
          });
        }

        // Add connection
        secretNode.connections.push(`service:${dep.serviceId}`);
        serviceNodes.get(dep.serviceId)!.connections.push(`secret:${secretKey}`);
      }

      nodes.push(secretNode);
    }

    // Add all service nodes
    nodes.push(...Array.from(serviceNodes.values()));

    logger.info('Generated dependency graph', {
      tenantId,
      totalNodes: nodes.length,
      secretNodes: nodes.filter(n => n.type === 'secret').length,
      serviceNodes: nodes.filter(n => n.type === 'service').length
    });

    return nodes;
  }

  /**
   * Find secrets used by a service
   */
  getServiceDependencies(serviceId: string): Array<{
    tenantId: string;
    secretKey: string;
  }> {
    const result: Array<{ tenantId: string; secretKey: string }> = [];

    for (const [key, deps] of this.dependencies.entries()) {
      const [tenantId, secretKey] = key.split(':');

      for (const dep of deps) {
        if (dep.serviceId === serviceId) {
          result.push({ tenantId, secretKey });
          break;
        }
      }
    }

    return result;
  }

  /**
   * Remove a dependency
   */
  removeDependency(
    tenantId: string,
    secretKey: string,
    serviceId: string
  ): boolean {
    const key = this.getDependencyKey(tenantId, secretKey);
    const deps = this.dependencies.get(key);

    if (!deps) {
      return false;
    }

    for (const dep of deps) {
      if (dep.serviceId === serviceId) {
        deps.delete(dep);
        logger.info('Dependency removed', {
          tenantId,
          secretKey,
          serviceId
        });
        return true;
      }
    }

    return false;
  }

  /**
   * Get statistics
   */
  getStatistics(): {
    totalSecrets: number;
    totalDependencies: number;
    averageDependenciesPerSecret: number;
    mostUsedSecrets: Array<{ secretKey: string; count: number }>;
  } {
    let totalDependencies = 0;
    const secretCounts: Map<string, number> = new Map();

    for (const [key, deps] of this.dependencies.entries()) {
      const count = deps.size;
      totalDependencies += count;

      const [, secretKey] = key.split(':');
      secretCounts.set(secretKey, count);
    }

    const mostUsedSecrets = Array.from(secretCounts.entries())
      .map(([secretKey, count]) => ({ secretKey, count }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 10);

    return {
      totalSecrets: this.dependencies.size,
      totalDependencies,
      averageDependenciesPerSecret: 
        this.dependencies.size > 0 ? totalDependencies / this.dependencies.size : 0,
      mostUsedSecrets
    };
  }

  /**
   * Export dependencies (for backup)
   */
  exportDependencies(): string {
    const data: Record<string, SecretDependency[]> = {};

    for (const [key, deps] of this.dependencies.entries()) {
      data[key] = Array.from(deps);
    }

    return JSON.stringify(data, null, 2);
  }

  /**
   * Import dependencies (from backup)
   */
  importDependencies(json: string): void {
    try {
      const data: Record<string, Array<Record<string, unknown>>> = JSON.parse(json);

      for (const [key, deps] of Object.entries(data)) {
        const depSet = new Set<SecretDependency>();

        for (const dep of deps) {
          const depTyped: SecretDependency = {
            serviceId: typeof dep.serviceId === 'string' ? dep.serviceId : '',
            serviceName: typeof dep.serviceName === 'string' ? dep.serviceName : '',
            serviceType: dep.serviceType === 'api' || dep.serviceType === 'worker' || dep.serviceType === 'cron' || dep.serviceType === 'function' ? dep.serviceType : 'api',
            environment: dep.environment === 'production' || dep.environment === 'staging' || dep.environment === 'development' ? dep.environment : 'development',
            lastAccess: dep.lastAccess instanceof Date ? dep.lastAccess : new Date(String(dep.lastAccess)),
            accessCount: typeof dep.accessCount === 'number' ? dep.accessCount : 0
          };
          depSet.add(depTyped);
        }

        this.dependencies.set(key, depSet);
      }

      logger.info('Dependencies imported', {
        count: this.dependencies.size
      });
    } catch (error: unknown) {
      logger.error('Failed to import dependencies', error instanceof Error ? error : new Error(String(error)));
      throw error;
    }
  }
}

/**
 * Global dependency tracking instance
 */
export const dependencyTracking = new DependencyTracking();

/**
 * Middleware to automatically track secret dependencies
 */
export function createDependencyTrackingMiddleware(
  tenantId: string,
  serviceId: string,
  serviceName: string,
  serviceType: SecretDependency['serviceType']
) {
  return {
    beforeGetSecret(secretKey: string) {
      // Register dependency
      dependencyTracking.registerDependency(tenantId, secretKey, {
        serviceId,
        serviceName,
        serviceType,
        environment: (process.env.NODE_ENV as unknown as 'production' | 'staging' | 'development') || 'development'
      });

      // Record access
      dependencyTracking.recordAccess(tenantId, secretKey, serviceId);
    }
  };
}

import { getEnvVar, setEnvVar } from '../../lib/env';
import { logger } from '../../lib/logger';

import type { SecretValue } from './ISecretProvider';
import { defaultProvider } from './ProviderFactory';

const isServer = typeof window === 'undefined';

const SECRET_KEY_MAPPING: Record<string, string> = {
  SUPABASE_SERVICE_KEY:
    getEnvVar('SUPABASE_SERVICE_KEY_SECRET_NAME') || 'supabase-service-key',
  REDIS_URL: getEnvVar('REDIS_URL_SECRET_NAME') || 'redis-url',
  DATABASE_URL: getEnvVar('DATABASE_URL_SECRET_NAME') || 'database-url',
};

function normalizeSecret(secret: SecretValue, envKey: string): string | undefined {
  const preferredOrder = ['value', 'secret', envKey.toLowerCase()];
  for (const candidate of preferredOrder) {
    const value = secret[candidate];
    if (typeof value === 'string' && value.trim().length > 0) {
      return value;
    }
  }
  return undefined;
}

export async function hydrateServerSecretsFromManager(): Promise<Record<string, string>> {
  if (!isServer) {
    return {};
  }

  if (getEnvVar('SECRETS_MANAGER_ENABLED') !== 'true') {
    logger.info('Secrets manager hydration skipped (SECRETS_MANAGER_ENABLED not true)');
    return {};
  }

  const tenantId = getEnvVar('SECRETS_TENANT_ID') || 'platform';
  const hydrated: Record<string, string> = {};

  for (const [envVar, secretKey] of Object.entries(SECRET_KEY_MAPPING)) {
    if (getEnvVar(envVar)) {
      continue;
    }

    try {
      const secretValue = await defaultProvider.getSecret(tenantId, secretKey, undefined, 'system-ci');
      const normalized = normalizeSecret(secretValue, envVar);

      if (!normalized) {
        logger.warn('Secret found but empty; skipping hydration', { envVar, secretKey, tenantId });
        continue;
      }

      setEnvVar(envVar, normalized);
      hydrated[envVar] = normalized;
      logger.info('Hydrated secret from manager', {
        envVar,
        tenantId,
        provider: getEnvVar('SECRETS_PROVIDER') || 'aws',
      });
    } catch (error) {
      logger.error('Failed to hydrate secret from manager', { envVar, tenantId, error });
    }
  }

  return hydrated;
}

/**
 * Secret Versioning System
 * 
 * Manages secret versions with rollback capability
 * Stores last 10 versions, enables version comparison and restoration
 * 
 * Sprint 4: Advanced Features
 * Created: 2024-11-29
 */

import { logger } from '../../lib/logger';

import type { ISecretProvider, SecretMetadata, SecretValue } from './ISecretProvider';

/**
 * Secret version entry
 */
export interface SecretVersion {
  version: string;
  value: SecretValue;
  metadata: SecretMetadata;
  createdAt: Date;
  createdBy: string;
  description?: string;
  deprecated?: boolean;
}

/**
 * Version comparison result
 */
export interface VersionComparison {
  version1: string;
  version2: string;
  differences: Array<{
    key: string;
    oldValue?: string;
    newValue?: string;
    changeType: 'added' | 'removed' | 'modified';
  }>;
}

/**
 * Secret versioning manager
 * 
 * Maintains version history and enables rollback
 */
export class SecretVersioning {
  private provider: ISecretProvider;
  private maxVersions: number = 10;
  private versionStore: Map<string, SecretVersion[]> = new Map();

  constructor(provider: ISecretProvider, maxVersions: number = 10) {
    this.provider = provider;
    this.maxVersions = maxVersions;

    logger.info('Secret versioning initialized', {
      provider: provider.getProviderName(),
      maxVersions
    });
  }

  /**
   * Get version key for storage
   */
  private getVersionKey(tenantId: string, secretKey: string): string {
    return `${tenantId}:${secretKey}`;
  }

  /**
   * Generate version ID
   */
  private generateVersionId(): string {
    const timestamp = Date.now();
    const random = Math.random().toString(36).substring(2, 8);
    return `v${timestamp}-${random}`;
  }

  /**
   * Store a new version
   */
  async storeVersion(
    tenantId: string,
    secretKey: string,
    value: SecretValue,
    metadata: SecretMetadata,
    userId: string,
    description?: string
  ): Promise<string> {
    const versionKey = this.getVersionKey(tenantId, secretKey);
    const versionId = this.generateVersionId();

    // Get existing versions
    const versions = this.versionStore.get(versionKey) || [];

    // Create new version entry
    const newVersion: SecretVersion = {
      version: versionId,
      value,
      metadata,
      createdAt: new Date(),
      createdBy: userId,
      description
    };

    // Add to beginning of array
    versions.unshift(newVersion);

    // Keep only last N versions
    if (versions.length > this.maxVersions) {
      const removed = versions.splice(this.maxVersions);
      logger.info('Pruned old versions', {
        tenantId,
        secretKey,
        removed: removed.length
      });
    }

    // Update store
    this.versionStore.set(versionKey, versions);

    logger.info('Stored secret version', {
      tenantId,
      secretKey,
      version: versionId,
      totalVersions: versions.length
    });

    return versionId;
  }

  /**
   * Get all versions for a secret
   */
  async getVersions(
    tenantId: string,
    secretKey: string,
    _userId?: string
  ): Promise<SecretVersion[]> {
    const versionKey = this.getVersionKey(tenantId, secretKey);
    const versions = this.versionStore.get(versionKey) || [];

    logger.info('Retrieved secret versions', {
      tenantId,
      secretKey,
      count: versions.length
    });

    // Return copies without actual secret values (security)
    return versions.map(v => ({
      ...v,
      value: {} // Don't expose values in list
    }));
  }

  /**
   * Get a specific version
   */
  async getVersion(
    tenantId: string,
    secretKey: string,
    versionId: string,
    _userId?: string
  ): Promise<SecretVersion | null> {
    const versionKey = this.getVersionKey(tenantId, secretKey);
    const versions = this.versionStore.get(versionKey) || [];

    const version = versions.find(v => v.version === versionId);

    if (!version) {
      logger.warn('Version not found', {
        tenantId,
        secretKey,
        versionId
      });
      return null;
    }

    logger.info('Retrieved specific version', {
      tenantId,
      secretKey,
      versionId
    });

    return version;
  }

  /**
   * Rollback to a previous version
   */
  async rollbackSecret(
    tenantId: string,
    secretKey: string,
    targetVersion: string,
    userId: string
  ): Promise<boolean> {
    logger.info('Starting secret rollback', {
      tenantId,
      secretKey,
      targetVersion,
      userId
    });

    try {
      // Get the target version
      const version = await this.getVersion(tenantId, secretKey, targetVersion, userId);

      if (!version) {
        throw new Error(`Version ${targetVersion} not found`);
      }

      // Set the secret to the old value (this creates a new version)
      const success = await this.provider.setSecret(
        tenantId,
        secretKey,
        version.value,
        {
          ...version.metadata,
          version: 'rollback',
          lastAccessed: new Date().toISOString()
        },
        userId
      );

      if (success) {
        // Store this rollback as a new version
        await this.storeVersion(
          tenantId,
          secretKey,
          version.value,
          version.metadata,
          userId,
          `Rollback to version ${targetVersion}`
        );

        logger.info('Secret rollback successful', {
          tenantId,
          secretKey,
          targetVersion
        });

        return true;
      }

      return false;
    } catch (error) {
      logger.error('Secret rollback failed', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretKey,
        targetVersion
      });
      throw error;
    }
  }

  /**
   * Compare two versions
   */
  async compareVersions(
    tenantId: string,
    secretKey: string,
    version1Id: string,
    version2Id: string
  ): Promise<VersionComparison> {
    const v1 = await this.getVersion(tenantId, secretKey, version1Id);
    const v2 = await this.getVersion(tenantId, secretKey, version2Id);

    if (!v1 || !v2) {
      throw new Error('One or both versions not found');
    }

    const differences: VersionComparison['differences'] = [];

    // Get all keys from both versions
    const allKeys = new Set([
      ...Object.keys(v1.value),
      ...Object.keys(v2.value)
    ]);

    // Compare each key
    for (const key of allKeys) {
      const val1 = v1.value[key];
      const val2 = v2.value[key];

      if (val1 === undefined && val2 !== undefined) {
        differences.push({
          key,
          newValue: this.maskValue(val2),
          changeType: 'added'
        });
      } else if (val1 !== undefined && val2 === undefined) {
        differences.push({
          key,
          oldValue: this.maskValue(val1),
          changeType: 'removed'
        });
      } else if (val1 !== val2) {
        differences.push({
          key,
          oldValue: this.maskValue(val1),
          newValue: this.maskValue(val2),
          changeType: 'modified'
        });
      }
    }

    return {
      version1: version1Id,
      version2: version2Id,
      differences
    };
  }

  /**
   * Mask secret value for logging
   */
  private maskValue(value: string | undefined): string {
    if (!value) return '(empty)';
    if (value.length <= 8) return '***';
    return `${value.substring(0, 4)}...${value.substring(value.length - 4)}`;
  }

  /**
   * Deprecate a version (mark as obsolete)
   */
  async deprecateVersion(
    tenantId: string,
    secretKey: string,
    versionId: string,
    userId: string
  ): Promise<boolean> {
    const versionKey = this.getVersionKey(tenantId, secretKey);
    const versions = this.versionStore.get(versionKey) || [];

    const version = versions.find(v => v.version === versionId);

    if (!version) {
      return false;
    }

    version.deprecated = true;

    logger.info('Version deprecated', {
      tenantId,
      secretKey,
      versionId,
      userId
    });

    return true;
  }

  /**
   * Delete old versions (cleanup)
   */
  async pruneVersions(
    tenantId: string,
    secretKey: string,
    keepCount: number = 5
  ): Promise<number> {
    const versionKey = this.getVersionKey(tenantId, secretKey);
    const versions = this.versionStore.get(versionKey) || [];

    if (versions.length <= keepCount) {
      return 0;
    }

    const toRemove = versions.length - keepCount;
    versions.splice(keepCount);

    this.versionStore.set(versionKey, versions);

    logger.info('Pruned versions', {
      tenantId,
      secretKey,
      removed: toRemove,
      remaining: keepCount
    });

    return toRemove;
  }

  /**
   * Get version statistics
   */
  getStatistics(): {
    totalSecrets: number;
    totalVersions: number;
    averageVersionsPerSecret: number;
  } {
    let totalVersions = 0;

    for (const versions of this.versionStore.values()) {
      totalVersions += versions.length;
    }

    const totalSecrets = this.versionStore.size;
    const averageVersionsPerSecret = totalSecrets > 0 ? totalVersions / totalSecrets : 0;

    return {
      totalSecrets,
      totalVersions,
      averageVersionsPerSecret
    };
  }

  /**
   * Export version history (for backup)
   */
  exportVersionHistory(tenantId: string, secretKey: string): string {
    const versionKey = this.getVersionKey(tenantId, secretKey);
    const versions = this.versionStore.get(versionKey) || [];

    // Remove sensitive values
    const sanitized = versions.map(v => ({
      ...v,
      value: Object.keys(v.value) // Only export keys, not values
    }));

    return JSON.stringify(sanitized, null, 2);
  }
}

/**
 * Create versioning manager from environment
 */
export function createSecretVersioning(provider: ISecretProvider): SecretVersioning {
  const maxVersions = parseInt(process.env.SECRET_MAX_VERSIONS || '10', 10);
  return new SecretVersioning(provider, maxVersions);
}

/**
 * HashiCorp Vault Provider
 * 
 * Implementation of ISecretProvider for HashiCorp Vault
 * Supports Kubernetes authentication and KV v2 secrets engine
 * 
 * Sprint 2: Provider Abstraction
 * Created: 2024-11-29
 */

import * as fs from 'fs';

import { logger } from '../../lib/logger';

import type {
  AuditAction,
  AuditResult,
  ISecretProvider,
  SecretMetadata,
  SecretValue
} from './ISecretProvider';
import { SecretAuditEvent, StructuredSecretAuditLogger } from './SecretAuditLogger';

// Type definitions for node-vault (simplified)
interface VaultClient {
  kubernetesLogin(options: { role: string; jwt: string }): Promise<{ auth: { client_token: string } }>;
  read(path: string): Promise<{ data: { data: Record<string, unknown>; metadata: Record<string, unknown> } }>;
  write(path: string, data: Record<string, unknown>): Promise<unknown>;
  delete(path: string): Promise<unknown>;
  list(path: string): Promise<{ data: { keys: string[] } }>;
  health(): Promise<unknown>;
}

/**
 * HashiCorp Vault provider implementation
 */
export class VaultSecretProvider implements ISecretProvider {
  private client: VaultClient | null = null;
  private vaultAddress: string;
  private vaultNamespace: string;
  private environment: string;
  private cache: Map<string, { value: SecretValue; expiresAt: number }> = new Map();
  private cacheTTL: number;
  private kubernetesRole?: string;
  private auditLogger: StructuredSecretAuditLogger;

  constructor(
    vaultAddress: string,
    vaultNamespace: string = 'valuecanvas',
    kubernetesRole?: string,
    cacheTTL: number = 300000 // 5 minutes
  ) {
    this.vaultAddress = vaultAddress;
    this.vaultNamespace = vaultNamespace;
    this.environment = process.env.NODE_ENV || 'development';
    this.cacheTTL = cacheTTL;
    this.kubernetesRole = kubernetesRole;
    this.auditLogger = new StructuredSecretAuditLogger();

    logger.info('Vault Secret Provider initialized', {
      provider: 'vault',
      address: vaultAddress,
      namespace: vaultNamespace,
      environment: this.environment
    });
  }

  /**
   * Initialize Vault client with Kubernetes authentication
   */
  async initialize(): Promise<void> {
    try {
      // Dynamic import of node-vault
      const vault = await import('node-vault');

      this.client = vault.default({
        apiVersion: 'v1',
        endpoint: this.vaultAddress,
        namespace: this.vaultNamespace
      }) as unknown as VaultClient;

      // Authenticate with Kubernetes if role provided
      if (this.kubernetesRole) {
        await this.authenticateKubernetes(this.kubernetesRole);
      }

      logger.info('Vault client initialized and authenticated');
    } catch (error: unknown) {
      logger.error('Failed to initialize Vault client', error instanceof Error ? error : new Error(String(error)));
      throw error;
    }
  }

  /**
   * Authenticate using Kubernetes service account
   */
  private async authenticateKubernetes(role: string): Promise<void> {
    try {
      const jwtPath = '/var/run/secrets/kubernetes.io/serviceaccount/token';
      const jwt = await fs.promises.readFile(jwtPath, 'utf8');

      if (!this.client) {
        throw new Error('Vault client not initialized');
      }

      const response = await this.client.kubernetesLogin({ role, jwt });

      // Store the client token for subsequent requests
      (this.client as unknown as Record<string, unknown>).token = response.auth.client_token;

      logger.info('Kubernetes authentication successful', { role });
    } catch (error: unknown) {
      logger.error('Kubernetes authentication failed', error instanceof Error ? error : new Error(String(error)));
      throw error;
    }
  }

  /**
   * Generate tenant-isolated Vault secret path
   * 
   * Format: secret/data/tenants/{tenantId}/{secretKey}
   * (KV v2 requires /data/ in path)
   */
  private getTenantSecretPath(tenantId: string, secretKey: string): string {
    if (!tenantId || !secretKey) {
      throw new Error('Tenant ID and secret key are required');
    }

    // Validate format
    if (!/^[a-zA-Z0-9-_]+$/.test(tenantId)) {
      throw new Error('Invalid tenant ID format');
    }

    return `secret/data/${this.environment}/tenants/${tenantId}/${secretKey}`;
  }

  /**
   * Get metadata path (for KV v2)
   */
  private getMetadataPath(tenantId: string, secretKey: string): string {
    return `secret/metadata/${this.environment}/tenants/${tenantId}/${secretKey}`;
  }

  /**
   * Get cache key
   */
  private getCacheKey(tenantId: string, secretKey: string): string {
    return `${tenantId}:${secretKey}`;
  }

  /**
   * Ensure client is initialized
   */
  private ensureClient(): VaultClient {
    if (!this.client) {
      throw new Error('Vault client not initialized. Call initialize() first.');
    }
    return this.client;
  }

  async getSecret(
    tenantId: string,
    secretKey: string,
    version?: string,
    userId?: string
  ): Promise<SecretValue> {
    const startTime = Date.now();
    const client = this.ensureClient();

    // Check cache
    const cacheKey = this.getCacheKey(tenantId, secretKey);
    const cached = this.cache.get(cacheKey);

    if (cached && cached.expiresAt > Date.now()) {
      await this.auditAccess(tenantId, secretKey, 'READ', 'SUCCESS', userId, undefined, {
        source: 'cache',
        latency_ms: Date.now() - startTime
      });
      return cached.value;
    }

    try {
      let path = this.getTenantSecretPath(tenantId, secretKey);

      // Add version if specified
      if (version) {
        path += `?version=${version}`;
      }

      const response = await client.read(path);
      const secretValue = response.data.data as SecretValue;

      // Remove internal metadata if present
      const { _metadata, ...cleanValue } = secretValue as Record<string, unknown>;

      // Cache the secret
      this.cache.set(cacheKey, {
        value: cleanValue as SecretValue,
        expiresAt: Date.now() + this.cacheTTL
      });

      await this.auditAccess(tenantId, secretKey, 'READ', 'SUCCESS', userId, undefined, {
        source: 'vault',
        latency_ms: Date.now() - startTime,
        version: (response.data.metadata as Record<string, unknown>)?.version
      });

      return cleanValue as SecretValue;
    } catch (error: unknown) {
      await this.auditAccess(
        tenantId,
        secretKey,
        'READ',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error),
        { latency_ms: Date.now() - startTime }
      );

      logger.error('Failed to get secret from Vault', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretKey
      });

      throw error;
    }
  }

  async setSecret(
    tenantId: string,
    secretKey: string,
    value: SecretValue,
    metadata: SecretMetadata,
    userId?: string
  ): Promise<boolean> {
    const client = this.ensureClient();
    const path = this.getTenantSecretPath(tenantId, secretKey);

    try {
      // Add metadata to secret
      const secretWithMetadata: Record<string, unknown> = {
        data: {
          ...value,
          _metadata: {
            tenantId: metadata.tenantId,
            sensitivityLevel: metadata.sensitivityLevel,
            createdAt: metadata.createdAt,
            version: metadata.version,
            rotationPolicy: metadata.rotationPolicy,
            tags: metadata.tags
          }
        },
        options: {
          cas: 0 // Check-And-Set version (0 = create only if doesn't exist)
        }
      };

      await client.write(path, secretWithMetadata);

      // Invalidate cache
      const cacheKey = this.getCacheKey(tenantId, secretKey);
      this.cache.delete(cacheKey);

      await this.auditAccess(tenantId, secretKey, 'WRITE', 'SUCCESS', userId);

      logger.info('Secret set successfully in Vault', {
        tenantId,
        secretKey,
        sensitivityLevel: metadata.sensitivityLevel
      });

      return true;
    } catch (error: unknown) {
      await this.auditAccess(
        tenantId,
        secretKey,
        'WRITE',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error)
      );

      logger.error('Failed to set secret in Vault', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretKey
      });

      throw error;
    }
  }

  async rotateSecret(
    tenantId: string,
    secretKey: string,
    userId?: string
  ): Promise<boolean> {
    const client = this.ensureClient();

    try {
      // Read current secret
      const currentSecret = await this.getSecret(tenantId, secretKey, undefined, userId);

      // Generate new value (implementation depends on secret type)
      const newValue = this.generateNewSecretValue(secretKey, currentSecret);

      // Get current metadata
      const currentMetadata = await this.getSecretMetadata(tenantId, secretKey, userId);

      // Write new version
      await this.setSecret(
        tenantId,
        secretKey,
        newValue,
        {
          ...currentMetadata!,
          version: 'auto',
          lastAccessed: new Date().toISOString()
        },
        userId
      );

      // Invalidate cache
      const cacheKey = this.getCacheKey(tenantId, secretKey);
      this.cache.delete(cacheKey);

      await this.auditAccess(tenantId, secretKey, 'ROTATE', 'SUCCESS', userId);

      logger.info('Secret rotation completed in Vault', {
        tenantId,
        secretKey
      });

      return true;
    } catch (error: unknown) {
      await this.auditAccess(
        tenantId,
        secretKey,
        'ROTATE',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error)
      );

      logger.error('Failed to rotate secret in Vault', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretKey
      });

      throw error;
    }
  }

  /**
   * Generate new secret value for rotation
   */
  private generateNewSecretValue(secretKey: string, currentValue: SecretValue): SecretValue {
    // This is a simplified implementation
    // In production, this should generate appropriate values based on secret type
    const crypto = require('crypto');

    return {
      value: crypto.randomBytes(32).toString('hex'),
      rotated_at: new Date().toISOString(),
      previous_version: 'rotated'
    };
  }

  async deleteSecret(
    tenantId: string,
    secretKey: string,
    userId?: string
  ): Promise<boolean> {
    const client = this.ensureClient();
    const metadataPath = this.getMetadataPath(tenantId, secretKey);

    try {
      // Delete all versions and metadata
      await client.delete(metadataPath);

      // Invalidate cache
      const cacheKey = this.getCacheKey(tenantId, secretKey);
      this.cache.delete(cacheKey);

      await this.auditAccess(tenantId, secretKey, 'DELETE', 'SUCCESS', userId);

      logger.info('Secret deleted from Vault', {
        tenantId,
        secretKey
      });

      return true;
    } catch (error: unknown) {
      await this.auditAccess(
        tenantId,
        secretKey,
        'DELETE',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error)
      );

      logger.error('Failed to delete secret from Vault', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretKey
      });

      throw error;
    }
  }

  async listSecrets(tenantId: string, userId?: string): Promise<string[]> {
    const client = this.ensureClient();
    const listPath = `secret/metadata/${this.environment}/tenants/${tenantId}`;

    try {
      const response = await client.list(listPath);
      const secretKeys = response.data.keys || [];

      await this.auditAccess(tenantId, 'ALL', 'LIST', 'SUCCESS', userId, undefined, {
        count: secretKeys.length
      });

      return secretKeys;
    } catch (error: unknown) {
      await this.auditAccess(
        tenantId,
        'ALL',
        'LIST',
        'FAILURE',
        userId,
        error instanceof Error ? error.message : String(error)
      );

      logger.error('Failed to list secrets from Vault', error instanceof Error ? error : new Error(String(error)), {
        tenantId
      });

      throw error;
    }
  }

  async getSecretMetadata(
    tenantId: string,
    secretKey: string,
    userId?: string
  ): Promise<SecretMetadata | null> {
    const client = this.ensureClient();
    const metadataPath = this.getMetadataPath(tenantId, secretKey);

    try {
      const response = await client.read(metadataPath);
      const vaultMetadata = response.data;

      const metadata: SecretMetadata = {
        tenantId,
        secretPath: metadataPath,
        version: String((vaultMetadata as Record<string, unknown>).current_version || 'latest'),
        createdAt: (vaultMetadata as Record<string, unknown>).created_time || new Date().toISOString(),
        lastAccessed: new Date().toISOString(),
        sensitivityLevel: 'high', // Default, should be in tags
        tags: (vaultMetadata as Record<string, Record<string, unknown>>).custom_metadata || {}
      };

      return metadata;
    } catch (error: unknown) {
      logger.error('Failed to get secret metadata from Vault', error instanceof Error ? error : new Error(String(error)), {
        tenantId,
        secretKey
      });

      return null;
    }
  }

  async secretExists(
    tenantId: string,
    secretKey: string,
    userId?: string
  ): Promise<boolean> {
    try {
      const metadata = await this.getSecretMetadata(tenantId, secretKey, userId);
      return metadata !== null;
    } catch {
      return false;
    }
  }

  async auditAccess(
    tenantId: string,
    secretKey: string,
    action: AuditAction,
    result: AuditResult,
    userId?: string,
    error?: string,
    metadata?: Record<string, unknown>
  ): Promise<void> {
    const event: SecretAuditEvent = {
      tenantId,
      userId,
      secretKey,
      action,
      result,
      error,
      metadata
    };

    if (result === 'SUCCESS') {
      if (action === 'ROTATE') {
        await this.auditLogger.logRotation(event);
      } else {
        await this.auditLogger.logAccess(event);
      }
    } else {
      await this.auditLogger.logDenied({ ...event, reason: error || 'Unknown error' });
    }
  }

  private maskSecretKey(key: string): string {
    if (key === 'ALL' || key.length <= 8) {
      return key;
    }
    return `${key.substring(0, 4)}...${key.substring(key.length - 4)}`;
  }

  getProviderName(): string {
    return 'vault';
  }

  async healthCheck(): Promise<boolean> {
    try {
      const client = this.ensureClient();
      await client.health();
      return true;
    } catch (error: unknown) {
      logger.error('Vault provider health check failed', error instanceof Error ? error : new Error(String(error)));
      return false;
    }
  }

  /**
   * Clear cache for testing/maintenance
   */
  clearCache(tenantId?: string): void {
    if (tenantId) {
      // Clear cache for specific tenant
      for (const key of this.cache.keys()) {
        if (key.startsWith(`${tenantId}:`)) {
          this.cache.delete(key);
        }
      }
    } else {
      this.cache.clear();
    }
  }
}

/**
 * Server-only application settings.
 *
 * Managed secrets, service-role credentials, and `_FILE` environment fallbacks
 * are intentionally isolated from browser-safe modules.
 */
import fs from "node:fs";

import { z } from "zod";

import { getEnvVar, env as runtimeEnv } from "../lib/env";

import { validateRedisUrlForProduction } from "./settings";

const DEFAULT_API_PORT = 3000;
const DEFAULT_SHUTDOWN_TIMEOUT_MS = 120_000;

const ServerSettingsSchema = z.object({
  VITE_SUPABASE_URL: z.string().url().optional(),
  VITE_SUPABASE_ANON_KEY: z.string().min(1).optional(),
  VITE_APP_URL: z.string().url().optional(),
  NODE_ENV: z
    .enum(["development", "staging", "production", "test"])
    .default("development"),
  API_PORT: z.string().optional().default("3000"),
  SUPABASE_SERVICE_KEY: z.string().optional(),
  SUPABASE_SERVICE_ROLE_KEY: z.string().optional(),
  SUPABASE_JWT_SECRET: z.string().optional(),
  REDIS_URL: z.string().url().optional(),
  CORS_ALLOWED_ORIGINS: z.string().optional(),
  ALERT_WEBHOOK_URL: z.string().url().optional(),
  ALERT_EMAIL_RECIPIENT: z.string().email().optional(),
  DATABASE_URL: z.string().url().optional(),
  SHUTDOWN_TIMEOUT_MS: z
    .string()
    .optional()
    .default(String(DEFAULT_SHUTDOWN_TIMEOUT_MS)),
});

let managedSecrets: Record<string, string> = {};
const isServer = typeof window === "undefined";
const isViteSsrBuild = import.meta.env?.SSR;

if ((isViteSsrBuild || isServer) && !runtimeEnv.isDevelopment) {
  try {
    const hydratorPath = "./secrets/SecretHydrator";
    const { hydrateServerSecretsFromManager } =
      await import(/* @vite-ignore */ hydratorPath);
    managedSecrets = await hydrateServerSecretsFromManager();
  } catch {
    managedSecrets = {};
  }
}

const readServerEnv = (key: string, fallback?: string) => {
  if (managedSecrets[key]) {
    return managedSecrets[key];
  }

  const filePath = getEnvVar(`${key}_FILE`);
  if (filePath) {
    try {
      return fs.readFileSync(filePath, "utf8").trim();
    } catch (error) {
      console.warn(`Failed to read secret from file ${filePath} for ${key}:`, error);
    }
  }

  return getEnvVar(key, { defaultValue: fallback });
};

const resolvedServerEnv = {
  VITE_SUPABASE_URL:
    readServerEnv("VITE_SUPABASE_URL") ||
    readServerEnv("SUPABASE_PUBLIC_URL") ||
    readServerEnv("SUPABASE_URL") ||
    readServerEnv("SUPABASE_INTERNAL_URL"),
  VITE_SUPABASE_ANON_KEY:
    readServerEnv("VITE_SUPABASE_ANON_KEY") || readServerEnv("SUPABASE_ANON_KEY"),
  VITE_APP_URL: readServerEnv("VITE_APP_URL"),
  NODE_ENV: readServerEnv("NODE_ENV"),
  API_PORT: readServerEnv("API_PORT", "3000"),
  SUPABASE_SERVICE_KEY: readServerEnv("SUPABASE_SERVICE_KEY"),
  SUPABASE_SERVICE_ROLE_KEY: readServerEnv("SUPABASE_SERVICE_ROLE_KEY"),
  SUPABASE_JWT_SECRET: readServerEnv("SUPABASE_JWT_SECRET"),
  REDIS_URL: readServerEnv("REDIS_URL"),
  CORS_ALLOWED_ORIGINS: readServerEnv("CORS_ALLOWED_ORIGINS"),
  ALERT_WEBHOOK_URL: readServerEnv("ALERT_WEBHOOK_URL"),
  ALERT_EMAIL_RECIPIENT: readServerEnv("ALERT_EMAIL_RECIPIENT"),
  DATABASE_URL: readServerEnv("DATABASE_URL"),
  SHUTDOWN_TIMEOUT_MS: readServerEnv(
    "SHUTDOWN_TIMEOUT_MS",
    String(DEFAULT_SHUTDOWN_TIMEOUT_MS),
  ),
};

const parsedServerSettings = ServerSettingsSchema.parse(resolvedServerEnv);

validateRedisUrlForProduction(parsedServerSettings.NODE_ENV, parsedServerSettings.REDIS_URL);

const defaultCorsOrigins = [
  "http://localhost:8080",
  "http://localhost:5173",
  "http://localhost:3000",
];

const parseCorsOrigins = (value?: string) =>
  (value ? value.split(",") : defaultCorsOrigins)
    .map((origin) => origin.trim())
    .filter(Boolean);

export const serverSettings = {
  ...parsedServerSettings,
  API_PORT: Number(parsedServerSettings.API_PORT) || DEFAULT_API_PORT,
  SHUTDOWN_TIMEOUT_MS:
    Number(parsedServerSettings.SHUTDOWN_TIMEOUT_MS) || DEFAULT_SHUTDOWN_TIMEOUT_MS,
  security: {
    corsOrigins: parseCorsOrigins(parsedServerSettings.CORS_ALLOWED_ORIGINS),
  },
};

export const settings = serverSettings;

const SECRET_PLACEHOLDERS = ["", "your-", "placeholder", "changeme"];

function isPlaceholder(value: string): boolean {
  const normalized = value.trim().toLowerCase();
  return SECRET_PLACEHOLDERS.some((marker) =>
    marker === "" ? normalized.length === 0 : normalized.includes(marker)
  );
}

function buildErrorMessage(scope: string, missing: string[], placeholders: string[]): string {
  const lines = [`${scope} startup configuration is invalid.`];

  if (missing.length > 0) {
    lines.push("Missing required environment variables:");
    missing.forEach((key) => lines.push(`  - ${key}`));
  }

  if (placeholders.length > 0) {
    lines.push("Environment variables still contain placeholder values:");
    placeholders.forEach((key) => lines.push(`  - ${key}`));
  }

  lines.push("Expected ownership:");
  lines.push("  - .env.example: non-secret defaults");
  lines.push("  - .env.ports: generated port mappings");
  lines.push("  - .env.local: secrets only");

  return lines.join("\n");
}

function validateRequired(scope: string, source: Record<string, string | undefined>, required: string[]) {
  const missing = required.filter((key) => !source[key]?.trim());
  const placeholders = required.filter((key) => {
    const value = source[key];
    return typeof value === "string" && isPlaceholder(value);
  });

  if (missing.length > 0 || placeholders.length > 0) {
    throw new Error(buildErrorMessage(scope, missing, placeholders));
  }
}

export function validateBackendStartupEnv(env: NodeJS.ProcessEnv = process.env): void {
  validateRequired("Backend", env, [
    "DATABASE_URL",
    "SUPABASE_URL",
    "SUPABASE_ANON_KEY",
    "SUPABASE_SERVICE_ROLE_KEY",
  ]);
}

export function validateFrontendStartupEnv(viteEnv: Record<string, string | undefined>): void {
  validateRequired("Frontend", viteEnv, [
    "VITE_API_BASE_URL",
    "VITE_SUPABASE_URL",
    "VITE_SUPABASE_ANON_KEY",
  ]);
}

/**
 * Browser-compatible OpenTelemetry Configuration
 * 
 * Provides distributed tracing and metrics for client-side operations.
 * Falls back to no-op implementations when OpenTelemetry is not available.
 */

import { Span, SpanStatusCode, trace } from '@opentelemetry/api';

// Service configuration
const SERVICE_NAME = 'valuecanvas-frontend';
const SERVICE_VERSION = '1.0.0';
const ENVIRONMENT = process.env.NODE_ENV || 'development';

// No-op implementations for browser environment
const noopSpan = {
  setAttributes: () => {},
  setStatus: () => {},
  recordException: () => {},
  addEvent: () => {},
  end: () => {},
  spanContext: () => ({ traceId: '', spanId: '' })
};

const noopTracer = {
  startSpan: () => noopSpan,
  startActiveSpan: (_name: string, _options: unknown, fn: (span: Span) => unknown) => fn(noopSpan)
};

/**
 * Get tracer instance (browser-compatible)
 */
export function getTracer() {
  try {
    return trace.getTracer(SERVICE_NAME, SERVICE_VERSION);
  } catch {
    return noopTracer;
  }
}

/**
 * Create a span for LLM operations
 */
export async function traceLLMOperation<T>(
  operationName: string,
  attributes: {
    provider: 'together_ai' | 'openai' | 'cache';
    model: string;
    userId?: string;
    promptLength?: number;
  },
  operation: (span: Span) => Promise<T>
): Promise<T> {
  const tracer = getTracer();

  return tracer.startActiveSpan(
    `llm.${operationName}`,
    {
      attributes: {
        'llm.provider': attributes.provider,
        'llm.model': attributes.model,
        'llm.user_id': attributes.userId || 'anonymous',
        'llm.prompt_length': attributes.promptLength || 0
      }
    },
    async (span) => {
      const startTime = Date.now();

      try {
        const result = await operation(span);

        const duration = Date.now() - startTime;

        span.setAttributes({
          'llm.duration_ms': duration,
          'llm.success': true
        });

        span.setStatus({ code: SpanStatusCode.OK });

        return result;
      } catch (error) {
        const duration = Date.now() - startTime;

        span.setAttributes({
          'llm.duration_ms': duration,
          'llm.success': false,
          'llm.error': error instanceof Error ? error.message : 'Unknown error'
        });

        span.setStatus({
          code: SpanStatusCode.ERROR,
          message: error instanceof Error ? error.message : 'Unknown error'
        });

        span.recordException(error as Error);

        throw error;
      } finally {
        span.end();
      }
    }
  );
}

/**
 * Create a span for database operations
 */
export async function traceDatabaseOperation<T>(
  operationName: string,
  attributes: {
    table?: string;
    operation?: 'select' | 'insert' | 'update' | 'delete';
  },
  operation: (span: Span) => Promise<T>
): Promise<T> {
  const tracer = getTracer();

  return tracer.startActiveSpan(
    `db.${operationName}`,
    {
      attributes: {
        'db.system': 'postgresql',
        'db.table': attributes.table || 'unknown',
        'db.operation': attributes.operation || 'unknown'
      }
    },
    async (span) => {
      try {
        const result = await operation(span);
        span.setStatus({ code: SpanStatusCode.OK });
        return result;
      } catch (error) {
        span.setStatus({
          code: SpanStatusCode.ERROR,
          message: error instanceof Error ? error.message : 'Unknown error'
        });
        span.recordException(error as Error);
        throw error;
      } finally {
        span.end();
      }
    }
  );
}

/**
 * Create a span for cache operations
 */
export async function traceCacheOperation<T>(
  operationName: string,
  attributes: {
    cacheKey?: string;
    hit?: boolean;
  },
  operation: (span: Span) => Promise<T>
): Promise<T> {
  const tracer = getTracer();

  return tracer.startActiveSpan(
    `cache.${operationName}`,
    {
      attributes: {
        'cache.system': 'redis',
        'cache.key': attributes.cacheKey || 'unknown',
        'cache.hit': attributes.hit !== undefined ? attributes.hit : false
      }
    },
    async (span) => {
      try {
        const result = await operation(span);
        span.setStatus({ code: SpanStatusCode.OK });
        return result;
      } catch (error) {
        span.setStatus({
          code: SpanStatusCode.ERROR,
          message: error instanceof Error ? error.message : 'Unknown error'
        });
        span.recordException(error as Error);
        throw error;
      } finally {
        span.end();
      }
    }
  );
}

