import React, { createContext, useCallback, useContext, useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";

import { SettingsContextType, SettingsPermission, UserPermissions } from "../legacy-migrated/types";
import { settingsRegistry } from "../lib/settingsRegistry";

const SettingsContext = createContext<SettingsContextType | undefined>(undefined);

interface SettingsProviderProps {
  children: React.ReactNode;
  defaultRoute?: string;
  permissions?: UserPermissions;
}

export const SettingsProvider: React.FC<SettingsProviderProps> = ({
  children,
  defaultRoute = "/user/profile",
  permissions = {
    permissions: ["team.view", "team.manage"],
    role: "Member",
  },
}) => {
  const navigate = useNavigate();
  const [currentRoute, setCurrentRoute] = useState<string>(defaultRoute);
  const [searchQuery, setSearchQuery] = useState<string>("");

  useEffect(() => {
    const hash = window.location.hash.replace("#/settings", "");
    if (hash && hash !== currentRoute) {
      setCurrentRoute(hash);
    }
  }, []);

  const navigateTo = useCallback(
    (path: string) => {
      if (!path || typeof path !== "string" || !path.startsWith("/")) {
        return;
      }
      setCurrentRoute(path);
      navigate(path);

      window.dispatchEvent(new CustomEvent("settings-navigate", { detail: { path } }));
    },
    [navigate]
  );

  const hasPermission = useCallback(
    (permission: SettingsPermission): boolean => {
      return permissions.permissions.includes(permission);
    },
    [permissions]
  );

  // Memoize breadcrumbs to prevent unnecessary recalculations
  const breadcrumbs = useMemo(() => settingsRegistry.getBreadcrumbs(currentRoute), [currentRoute]);

  // Memoize context value to prevent infinite re-render loops
  // This is critical: object literal instantiation on every render causes
  // consumers to re-render even when values haven't changed
  const contextValue: SettingsContextType = useMemo(
    () => ({
      currentRoute,
      navigateTo,
      searchQuery,
      setSearchQuery,
      permissions,
      hasPermission,
      breadcrumbs,
    }),
    [currentRoute, navigateTo, searchQuery, setSearchQuery, permissions, hasPermission, breadcrumbs]
  );

  return <SettingsContext.Provider value={contextValue}>{children}</SettingsContext.Provider>;
};

export const useSettings = (): SettingsContextType => {
  const context = useContext(SettingsContext);
  if (!context) {
    throw new Error("useSettings must be used within a SettingsProvider");
  }
  return context;
};

/**
 * Tenant Context Provider
 *
 * Provides multi-tenant context throughout the application.
 * Ensures tenant isolation by validating user access to tenants.
 *
 * SECURITY: Tenant ID is derived from server-provided tenant list,
 * never trusted from URL/browser without validation.
 */

import {
  createContext,
  ReactNode,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { useLocation } from "react-router-dom";

import { fetchUserTenants, isTenantApiEnabled, TenantInfo } from "../api/tenant";
import { analyticsClient } from "../lib/analyticsClient";
import { createLogger } from "../lib/logger";
import { clearAndBroadcastTenantCacheReset } from "../lib/tenantCacheIsolation";

import { useAuth } from "./AuthContext";

const logger = createLogger({ component: "TenantContext" });



/**
 * Tenant context state
 */
export interface TenantContextState {
  currentTenant: TenantInfo | null;
  tenants: TenantInfo[];
  isLoading: boolean;
  error: Error | null;
  isApiEnabled: boolean;
}

/**
 * Tenant context value (state + actions)
 */
export interface TenantContextValue extends TenantContextState {
  switchTenant: (tenantId: string) => Promise<boolean>;
  refreshTenants: () => Promise<void>;
  validateTenantAccess: (tenantId: string) => boolean;
  getTenantById: (tenantId: string) => TenantInfo | undefined;
}

const TenantContext = createContext<TenantContextValue | undefined>(undefined);

/**
 * Storage key for persisting selected tenant
 */
const TENANT_STORAGE_KEY = "vros_current_tenant_id";

/**
 * Get stored tenant ID from localStorage
 */
function getStoredTenantId(): string | null {
  try {
    return localStorage.getItem(TENANT_STORAGE_KEY);
  } catch {
    return null;
  }
}

/**
 * Store tenant ID in localStorage
 */
function setStoredTenantId(tenantId: string): void {
  try {
    localStorage.setItem(TENANT_STORAGE_KEY, tenantId);
  } catch {
    logger.warn("Failed to persist tenant ID to localStorage");
  }
}

/**
 * Clear stored tenant ID
 */
function clearStoredTenantId(): void {
  try {
    localStorage.removeItem(TENANT_STORAGE_KEY);
  } catch {
    // Ignore
  }
}

interface TenantProviderProps {
  children: ReactNode;
  onTenantSwitch?: (fromTenant: TenantInfo | null, toTenant: TenantInfo) => void;
}

export function TenantProvider({ children, onTenantSwitch }: TenantProviderProps) {
  const { user, isAuthenticated } = useAuth();
  const location = useLocation();

  const [tenants, setTenants] = useState<TenantInfo[]>([]);
  const [currentTenant, setCurrentTenant] = useState<TenantInfo | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  const isApiEnabled = useMemo(() => isTenantApiEnabled(), []);

  /**
   * Fetch tenants for the current user
   */
  const refreshTenants = useCallback(async () => {
    if (!user?.id) {
      setTenants([]);
      setCurrentTenant(null);
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const { data, error: fetchError } = await fetchUserTenants({ expectedUserId: user.id });

      if (fetchError) {
        setError(fetchError);
        setTenants([]);
        setCurrentTenant(null);
        logger.error("Failed to fetch tenants", fetchError);
        return;
      }

      const fetchedTenants = data || [];
      setTenants(fetchedTenants);

      if (fetchedTenants.length === 0) {
        setCurrentTenant(null);
        clearStoredTenantId();
        return;
      }

      const storedTenantId = getStoredTenantId();
      const urlTenantId = validateTenantId(extractTenantIdFromUrl(location.pathname));

      let selectedTenant: TenantInfo | null = null;

      if (urlTenantId) {
        selectedTenant =
          fetchedTenants.find((t) => t.id === urlTenantId || t.slug === urlTenantId) || null;
        if (!selectedTenant) {
          logger.warn("URL tenant not in user tenant list", { urlTenantId });
        }
      }

      if (!selectedTenant && storedTenantId) {
        selectedTenant = fetchedTenants.find((t) => t.id === storedTenantId) || null;
      }

      if (!selectedTenant && fetchedTenants.length > 0) {
        selectedTenant = fetchedTenants[0] ?? null;
      }

      if (selectedTenant) {
        setCurrentTenant(selectedTenant);
        setStoredTenantId(selectedTenant.id);

        analyticsClient.track("tenant_context_loaded", {
          tenantId: selectedTenant.id,
          tenantCount: fetchedTenants.length,
        });

        logger.info("Tenant context initialized", {
          currentTenant: selectedTenant.id,
          tenantCount: fetchedTenants.length,
        });
      }
    } catch (err) {
      const fetchError = err instanceof Error ? err : new Error("Failed to load tenants");
      setError(fetchError);
      logger.error("Exception loading tenants", fetchError);
    } finally {
      setIsLoading(false);
    }
  }, [user?.id, location.pathname]);

  /**
   * Switch to a different tenant
   */
  const switchTenant = useCallback(
    async (tenantId: string): Promise<boolean> => {
      const targetTenant = tenants.find((t) => t.id === tenantId);

      if (!targetTenant) {
        logger.error("Cannot switch to tenant - not in allowed list", { tenantId });
        setError(new Error(`You do not have access to tenant: ${tenantId}`));
        return false;
      }

      if (currentTenant?.id === tenantId) {
        return true;
      }

      const previousTenant = currentTenant;

      clearAndBroadcastTenantCacheReset();
      setCurrentTenant(targetTenant);
      setStoredTenantId(targetTenant.id);

      analyticsClient.track("tenant_switched", {
        fromTenantId: previousTenant?.id,
        toTenantId: targetTenant.id,
      });

      logger.info("Tenant switched", {
        from: previousTenant?.id,
        to: targetTenant.id,
      });

      if (onTenantSwitch) {
        onTenantSwitch(previousTenant, targetTenant);
      }

      return true;
    },
    [tenants, currentTenant, onTenantSwitch]
  );

  /**
   * Validate if user has access to a tenant
   */
  const validateTenantAccess = useCallback(
    (tenantId: string): boolean => {
      return tenants.some((t) => t.id === tenantId);
    },
    [tenants]
  );

  /**
   * Get tenant by ID
   */
  const getTenantById = useCallback(
    (tenantId: string): TenantInfo | undefined => {
      return tenants.find((t) => t.id === tenantId);
    },
    [tenants]
  );

  // Grace period for background auth to settle after page load.
  // secureTokenManager.getStoredSession() always returns null (security design),
  // so AuthContext sets loading=false before the real session resolves via
  // initializeBackgroundAuth(). Without this grace period, TenantGate would
  // redirect to /create-org before the session has a chance to resolve.
  const AUTH_SETTLE_MS = 2000;

  useEffect(() => {
    if (isAuthenticated && user?.id) {
      refreshTenants();
      return;
    }

    // Delay clearing tenants to allow background auth to settle
    const timer = setTimeout(() => {
      clearAndBroadcastTenantCacheReset();
      setTenants([]);
      setCurrentTenant(null);
      setIsLoading(false);
      clearStoredTenantId();
    }, AUTH_SETTLE_MS);

    return () => clearTimeout(timer);
  }, [isAuthenticated, user?.id, refreshTenants]);

  useEffect(() => {
    if (!isAuthenticated) {
      clearStoredTenantId();
    }
  }, [isAuthenticated]);

  const value: TenantContextValue = useMemo(
    () => ({
      currentTenant,
      tenants,
      isLoading,
      error,
      isApiEnabled,
      switchTenant,
      refreshTenants,
      validateTenantAccess,
      getTenantById,
    }),
    [
      currentTenant,
      tenants,
      isLoading,
      error,
      isApiEnabled,
      switchTenant,
      refreshTenants,
      validateTenantAccess,
      getTenantById,
    ]
  );

  return <TenantContext.Provider value={value}>{children}</TenantContext.Provider>;
}

function validateTenantId(id: string | null): string | null {
  if (!id || typeof id !== "string" || id.length === 0 || !/^[a-zA-Z0-9-_]+$/.test(id)) {
    return null;
  }
  return id;
}

/**
 * Extract tenant ID from URL path
 * Supports patterns like /org/:orgId/... or /tenant/:tenantId/...
 */
function extractTenantIdFromUrl(pathname: string): string | null {
  const orgMatch = pathname.match(/^\/org\/([^/]+)/);
  if (orgMatch && orgMatch[1]) return orgMatch[1];

  const tenantMatch = pathname.match(/^\/tenant\/([^/]+)/);
  if (tenantMatch && tenantMatch[1]) return tenantMatch[1];

  return null;
}

/**
 * Hook to access tenant context
 */
export function useTenant(): TenantContextValue {
  const context = useContext(TenantContext);
  if (context === undefined) {
    throw new Error("useTenant must be used within a TenantProvider");
  }
  return context;
}

/**
 * Hook to get current tenant (convenience)
 */
export function useCurrentTenant(): TenantInfo | null {
  const { currentTenant } = useTenant();
  return currentTenant;
}

/**
 * Hook to check if user has access to a specific tenant
 */
export function useHasTenantAccess(tenantId: string): boolean {
  const { validateTenantAccess } = useTenant();
  return validateTenantAccess(tenantId);
}

export { TenantContext };

/**
 * Agent Performance Monitoring Dashboard
 * 
 * Real-time performance metrics from agent_metrics table
 * Source: supabase/migrations/20241127_agent_predictions.sql
 */

import { useEffect, useMemo, useState } from 'react';
import { Bar, BarChart, CartesianGrid, Legend, Line, LineChart, ResponsiveContainer, Tooltip, XAxis, YAxis } from 'recharts';

import { Alert, AlertDescription } from '@/components/ui/alert';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { supabase } from '@/lib/supabase';


interface AgentMetrics {
  agent_type: string;
  avg_tokens: number;
  avg_latency_ms: number;
  total_cost: number;
  invocation_count: number;
  avg_confidence: number;
  error_rate: number;
}

interface PerformanceTrend {
  timestamp: string;
  agent_type: string;
  avg_latency: number;
  invocation_count: number;
}

interface RawAgentMetricRecord {
  agent_type: string;
  total_tokens?: number;
  latency_ms?: number;
  cost?: string | number;
  confidence_score?: number;
  error?: unknown;
  created_at: string;
}

export function AgentPerformanceDashboard() {
  const [metrics, setMetrics] = useState<AgentMetrics[]>([]);
  const [trends, setTrends] = useState<PerformanceTrend[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [timeRange, setTimeRange] = useState<'1h' | '24h' | '7d'>('24h');

  useEffect(() => {
    fetchMetrics();
    const interval = setInterval(fetchMetrics, 60000); // Refresh every minute
    return () => clearInterval(interval);
  }, [timeRange]);

  const fetchMetrics = async () => {
    try {
      setLoading(true);

      // Fetch aggregate metrics
      const { data: metricsData, error: metricsError } = await supabase
        .from<RawAgentMetricRecord>('agent_metrics')
        .select('*')
        .gte('created_at', getTimeRangeStart())
        .order('created_at', { ascending: false });

      if (metricsError) throw metricsError;

      // Aggregate by agent type
      const aggregated = aggregateMetrics(metricsData || []);
      setMetrics(aggregated);

      // Fetch trends
      const { data: trendsData, error: trendsError } = await supabase
        .from<RawAgentMetricRecord>('agent_metrics')
        .select('agent_type, created_at, latency_ms')
        .gte('created_at', getTimeRangeStart())
        .order('created_at', { ascending: true });

      if (trendsError) throw trendsError;

      const trendsByHour = aggregateTrends(trendsData || []);
      setTrends(trendsByHour);

      setError(null);
    } catch (err: unknown) {
      console.error('Error fetching agent metrics:', err);
      setError(err instanceof Error ? err.message : 'Unknown error');
    } finally {
      setLoading(false);
    }
  };

  const getTimeRangeStart = (): string => {
    const now = new Date();
    switch (timeRange) {
      case '1h':
        return new Date(now.getTime() - 60 * 60 * 1000).toISOString();
      case '24h':
        return new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
      case '7d':
        return new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();
    }
  };

  interface AggregatedMetrics {
    agent_type: string;
    total_tokens: number;
    total_latency: number;
    total_cost: number;
    count: number;
    total_confidence: number;
    errors: number;
  }

  const aggregateMetrics = (data: RawAgentMetricRecord[]): AgentMetrics[] => {
    const grouped = data.reduce<Record<string, AggregatedMetrics>>((acc, record) => {
      const agent = record.agent_type;
      if (!acc[agent]) {
        acc[agent] = {
          agent_type: agent,
          total_tokens: 0,
          total_latency: 0,
          total_cost: 0,
          count: 0,
          total_confidence: 0,
          errors: 0
        };
      }

      acc[agent].total_tokens += record.total_tokens ?? 0;
      acc[agent].total_latency += record.latency_ms ?? 0;
      acc[agent].total_cost += typeof record.cost === 'string' ? parseFloat(record.cost) : (record.cost ?? 0);
      acc[agent].total_confidence += record.confidence_score ?? 0;
      acc[agent].count += 1;
      if (record.error) acc[agent].errors += 1;

      return acc;
    }, {});

    return Object.values(grouped).map((g) => ({
      agent_type: g.agent_type,
      avg_tokens: Math.round(g.total_tokens / g.count),
      avg_latency_ms: Math.round(g.total_latency / g.count),
      total_cost: g.total_cost,
      invocation_count: g.count,
      avg_confidence: g.total_confidence / g.count,
      error_rate: (g.errors / g.count) * 100
    }));
  };

  interface AggregatedTrend {
    timestamp: string;
    agent_type: string;
    total_latency: number;
    count: number;
  }

  const aggregateTrends = (data: RawAgentMetricRecord[]): PerformanceTrend[] => {
    const grouped = data.reduce<Record<string, AggregatedTrend>>((acc, record) => {
      const hour = new Date(record.created_at).toISOString().slice(0, 13);
      const key = `${hour}-${record.agent_type}`;

      if (!acc[key]) {
        acc[key] = {
          timestamp: hour,
          agent_type: record.agent_type,
          total_latency: 0,
          count: 0
        };
      }

      acc[key].total_latency += record.latency_ms ?? 0;
      acc[key].count += 1;

      return acc;
    }, {});

    return Object.values(grouped).map((g) => ({
      timestamp: g.timestamp,
      agent_type: g.agent_type,
      avg_latency: Math.round(g.total_latency / g.count),
      invocation_count: g.count
    }));
  };

  const formatCost = (cost: number) => `$${cost.toFixed(4)}`;
  const formatLatency = (ms: number) => `${ms}ms`;

  const alertsByCategory = useMemo(() => {
    const highLatency: AgentMetrics[] = [];
    const lowConfidence: AgentMetrics[] = [];
    const highError: AgentMetrics[] = [];

    for (const metric of metrics) {
      if (metric.avg_latency_ms > 2000) {
        highLatency.push(metric);
      }

      if (metric.avg_confidence < 0.7) {
        lowConfidence.push(metric);
      }

      if (metric.error_rate > 5) {
        highError.push(metric);
      }
    }

    return {
      highLatency,
      lowConfidence,
      highError
    };
  }, [metrics]);

  if (loading && metrics.length === 0) {
    return <div className="p-4">Loading agent metrics...</div>;
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">Agent Performance Dashboard</h1>
        <div className="flex gap-2">
          <button
            onClick={() => setTimeRange('1h')}
            className={`px-4 py-2 rounded ${timeRange === '1h' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}
          >
            1 Hour
          </button>
          <button
            onClick={() => setTimeRange('24h')}
            className={`px-4 py-2 rounded ${timeRange === '24h' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}
          >
            24 Hours
          </button>
          <button
            onClick={() => setTimeRange('7d')}
            className={`px-4 py-2 rounded ${timeRange === '7d' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}
          >
            7 Days
          </button>
        </div>
      </div>

      {error && (
        <Alert variant="destructive">
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      )}

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {metrics.map((metric) => (
          <Card key={metric.agent_type}>
            <CardHeader>
              <CardTitle className="text-sm font-medium">{metric.agent_type}</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span>Invocations:</span>
                  <span className="font-bold">{metric.invocation_count}</span>
                </div>
                <div className="flex justify-between">
                  <span>Avg Latency:</span>
                  <span className={metric.avg_latency_ms > 2000 ? 'text-red-600 font-bold' : ''}>
                    {formatLatency(metric.avg_latency_ms)}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span>Avg Tokens:</span>
                  <span>{metric.avg_tokens.toLocaleString()}</span>
                </div>
                <div className="flex justify-between">
                  <span>Total Cost:</span>
                  <span>{formatCost(metric.total_cost)}</span>
                </div>
                <div className="flex justify-between">
                  <span>Confidence:</span>
                  <span className={metric.avg_confidence < 0.7 ? 'text-yellow-600 font-bold' : 'text-green-600'}>
                    {(metric.avg_confidence * 100).toFixed(1)}%
                  </span>
                </div>
                <div className="flex justify-between">
                  <span>Error Rate:</span>
                  <span className={metric.error_rate > 5 ? 'text-red-600 font-bold' : ''}>
                    {metric.error_rate.toFixed(1)}%
                  </span>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Latency Trends */}
      <Card>
        <CardHeader>
          <CardTitle>Latency Trends</CardTitle>
        </CardHeader>
        <CardContent>
          <ResponsiveContainer width="100%" height={300}>
            <LineChart data={trends}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis 
                dataKey="timestamp" 
                tickFormatter={(ts) => new Date(ts).toLocaleTimeString()}
              />
              <YAxis label={{ value: 'Latency (ms)', angle: -90, position: 'insideLeft' }} />
              <Tooltip />
              <Legend />
              {[...new Set(trends.map(t => t.agent_type))].map((agent, idx) => (
                <Line
                  key={agent}
                  type="monotone"
                  dataKey="avg_latency"
                  data={trends.filter(t => t.agent_type === agent)}
                  stroke={`hsl(${idx * 60}, 70%, 50%)`}
                  name={agent}
                />
              ))}
            </LineChart>
          </ResponsiveContainer>
        </CardContent>
      </Card>

      {/* Invocation Volume */}
      <Card>
        <CardHeader>
          <CardTitle>Invocation Volume by Agent</CardTitle>
        </CardHeader>
        <CardContent>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={metrics}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="agent_type" />
              <YAxis label={{ value: 'Count', angle: -90, position: 'insideLeft' }} />
              <Tooltip />
              <Legend />
              <Bar dataKey="invocation_count" fill="#8884d8" name="Invocations" />
            </BarChart>
          </ResponsiveContainer>
        </CardContent>
      </Card>

      {/* Cost Analysis */}
