/**
 * Get templates by category
 */
export function getTemplatesByCategory(category: PromptTemplate['category']): PromptTemplate[] {
  return promptTemplates.filter((t) => t.category === category);
}

/**
 * Get template by ID
 */
export function getTemplateById(id: string): PromptTemplate | undefined {
  return promptTemplates.find((t) => t.id === id);
}

/**
 * Search templates by tags or name
 */
export function searchTemplates(query: string): PromptTemplate[] {
  const lowerQuery = query.toLowerCase();
  return promptTemplates.filter(
    (t) =>
      t.name.toLowerCase().includes(lowerQuery) ||
      t.description.toLowerCase().includes(lowerQuery) ||
      t.tags.some((tag) => tag.toLowerCase().includes(lowerQuery))
  );
}

/**
 * Interpolate template with variables
 */
export function interpolateTemplate(template: PromptTemplate, variables: Record<string, string>): string {
  let result = template.prompt;

  for (const [key, value] of Object.entries(variables)) {

    // eslint-disable-next-line security/detect-non-literal-regexp
    result = result.replace(new RegExp(`{{${key}}}`, 'g'), value);
  }

  return result;
}

import React, { createContext, useContext, useEffect, useReducer } from 'react';
import { z } from 'zod';

import * as fixtures from './fixtures';
import {
  Artifact,
  AuditEvent,
  Benchmark,
  Deal,
  Hypothesis,
  ROIModel,
  Stakeholder,
  User,
  ValueDriver,
  ValueRealization,
} from './types';

/**
 * -----------------------------
 * STATE
 * -----------------------------
 */
interface State {
  users: User[];
  deals: Deal[];
  stakeholders: Stakeholder[];
  valueDrivers: ValueDriver[];
  benchmarks: Benchmark[];
  hypotheses: Hypothesis[];
  roiModels: ROIModel[];
  artifacts: Artifact[];
  valueRealizations: ValueRealization[];
  auditEvents: AuditEvent[];
  currentUser: User | null;
}

/**
 * -----------------------------
 * ACTIONS
 * -----------------------------
 */
type Action =
  | { type: 'SET_CURRENT_USER'; payload: User }
  | { type: 'ADD_DEAL'; payload: Deal }
  | { type: 'UPDATE_DEAL'; payload: Deal }
  | { type: 'ADD_STAKEHOLDER'; payload: Stakeholder }
  | { type: 'UPDATE_STAKEHOLDER'; payload: Stakeholder }
  | { type: 'ADD_VALUE_DRIVER'; payload: ValueDriver }
  | { type: 'UPDATE_VALUE_DRIVER'; payload: ValueDriver }
  | { type: 'PUBLISH_VALUE_DRIVER'; payload: string }
  | { type: 'ADD_HYPOTHESIS'; payload: Hypothesis }
  | { type: 'UPDATE_HYPOTHESIS'; payload: Hypothesis }
  | { type: 'ADD_ROI_MODEL'; payload: ROIModel }
  | { type: 'UPDATE_ROI_MODEL'; payload: ROIModel }
  | { type: 'ADD_ARTIFACT'; payload: Artifact }
  | { type: 'UPDATE_ARTIFACT'; payload: Artifact }
  | { type: 'ADD_VALUE_REALIZATION'; payload: ValueRealization }
  | { type: 'UPDATE_VALUE_REALIZATION'; payload: ValueRealization }
  | { type: 'ADD_AUDIT_EVENT'; payload: AuditEvent };

/**
 * -----------------------------
 * CONSTANTS
 * -----------------------------
 */
export const STORAGE_KEY = 'valueos-state';
export const SAVE_DELAY_MS = 200;

/**
 * Only persist safe slices
 */
type PersistedStateKey =
  | 'deals'
  | 'stakeholders'
  | 'valueDrivers'
  | 'hypotheses'
  | 'roiModels'
  | 'artifacts'
  | 'valueRealizations'
  | 'auditEvents';

const PERSISTED_STATE_KEYS: PersistedStateKey[] = [
  'deals',
  'stakeholders',
  'valueDrivers',
  'hypotheses',
  'roiModels',
  'artifacts',
  'valueRealizations',
  'auditEvents',
];

/**
 * -----------------------------
 * ZOD VALIDATION (from main)
 * -----------------------------
 */

const dealSchema = z.object({
  id: z.string(),
  name: z.string(),
  stage: z.string(),
  amount: z.number(),
  closeDate: z.string(),
  contacts: z.array(z.string()),
