  personaTags: z.array(z.string()),
  motionTags: z.array(z.string()),
  formula: z.string(),
  defaultAssumptions: z.record(z.string(), z.number()),
  narrativePitch: z.string(),
  status: z.enum(['draft', 'published', 'archived']),
  version: z.number(),
});

const hypothesisSchema = z.object({
  id: z.string(),
  dealId: z.string(),
  driverId: z.string(),
  inputs: z.record(z.string(), z.number()),
  outputs: z.record(z.string(), z.number()),
});

const roiModelSchema = z.object({
  id: z.string(),
  dealId: z.string(),
  components: z.object({
    revenueUplift: z.number(),
    costSavings: z.number(),
    riskReduction: z.number(),
  }),
  paybackMonths: z.number(),
});

const artifactSchema = z.object({
  id: z.string(),
  dealId: z.string(),
  type: z.enum(['exec-summary', 'one-page', 'qbr-report']),
  content: z.string(),
});

const valueRealizationSchema = z.object({
  id: z.string(),
  dealId: z.string(),
  committed: z.record(z.string(), z.number()),
  actual: z.record(z.string(), z.number()),
  variance: z.record(z.string(), z.number()),
  rootCause: z.string(),
  actions: z.array(z.string()),
});

const auditEventSchema = z.object({
  id: z.string(),
  userId: z.string(),
  action: z.string(),
  entity: z.string(),
  entityId: z.string(),
  timestamp: z.string(),
  before: z.unknown(),
  after: z.unknown(),
});

const persistedStateSchemas: Record<PersistedStateKey, z.ZodTypeAny> = {
  deals: z.array(dealSchema),
  stakeholders: z.array(stakeholderSchema),
  valueDrivers: z.array(valueDriverSchema),
  hypotheses: z.array(hypothesisSchema),
  roiModels: z.array(roiModelSchema),
  artifacts: z.array(artifactSchema),
  valueRealizations: z.array(valueRealizationSchema),
  auditEvents: z.array(auditEventSchema),
};

/**
 * -----------------------------
 * INITIAL STATE
 * -----------------------------
 */
const createInitialState = (): State => ({
  users: fixtures.users,
  deals: fixtures.deals,
  stakeholders: fixtures.stakeholders,
  valueDrivers: fixtures.valueDrivers,
  benchmarks: fixtures.benchmarks,
  hypotheses: fixtures.hypotheses,
  roiModels: fixtures.roiModels,
  artifacts: fixtures.artifacts,
  valueRealizations: fixtures.valueRealizations,
  auditEvents: fixtures.auditEvents,
  currentUser: fixtures.users[0],
});

export const initialState = createInitialState();

/**
 * -----------------------------
 * REDUCER
 * -----------------------------
 */
function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'SET_CURRENT_USER':
      return { ...state, currentUser: action.payload };

    case 'ADD_DEAL':
      return { ...state, deals: [...state.deals, action.payload] };

    case 'UPDATE_DEAL':
      return {
        ...state,
        deals: state.deals.map(d =>
          d.id === action.payload.id ? action.payload : d
        ),
      };

    case 'ADD_AUDIT_EVENT':
      return { ...state, auditEvents: [...state.auditEvents, action.payload] };

    default:
      return state;
  }
}

/**
 * -----------------------------
 * HYDRATION (secure)
 * -----------------------------
 */
const sanitizePersistedState = (
  parsed: unknown
): Partial<Pick<State, PersistedStateKey>> => {
  if (!parsed || typeof parsed !== 'object') return {};

  const record = parsed as Record<string, unknown>;

  return PERSISTED_STATE_KEYS.reduce((acc, key) => {
    const result = persistedStateSchemas[key].safeParse(record[key]);
    if (result.success) acc[key] = result.data;
    return acc;
  }, {} as Partial<Pick<State, PersistedStateKey>>);
};

export const hydrateInitialState = (
  baseState: State,
  serialized: string | null
): State => {
  if (!serialized) return baseState;

  try {
    const parsed = JSON.parse(serialized);
    const safe = sanitizePersistedState(parsed);
    return { ...baseState, ...safe };
  } catch {
    return baseState;
  }
};

function initState(baseState: State): State {
  return hydrateInitialState(baseState, localStorage.getItem(STORAGE_KEY));
}

/**
 * -----------------------------
 * PERSISTENCE (debounced)
 * -----------------------------
 */
function buildPersistedState(state: State): Partial<State> {
  return PERSISTED_STATE_KEYS.reduce((acc, key) => {
    acc[key] = state[key];
    return acc;
  }, {} as Partial<State>);
}

/**
 * -----------------------------
 * CONTEXT
 * -----------------------------
 */
const DataContext = createContext<
  { state: State; dispatch: React.Dispatch<Action> } | undefined
>(undefined);

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, dispatch] = useReducer(reducer, initialState, initState);

  useEffect(() => {
    const timer = setTimeout(() => {
      localStorage.setItem(
        STORAGE_KEY,
        JSON.stringify(buildPersistedState(state))
      );
    }, SAVE_DELAY_MS);

    return () => clearTimeout(timer);
  }, [state]);

  return (
    <DataContext.Provider value={{ state, dispatch }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error('useData must be used within DataProvider');
  return context;
};

/**
 * -----------------------------
 * TEST EXPORTS
 * -----------------------------
 */
export const __testing = {
  buildPersistedState,
  initState,
  initialState,
  reducer,
  SAVE_DELAY_MS,
  STORAGE_KEY,
};

/**
 * Wouter to React Router Adapter
 * Provides wouter-compatible hooks that use react-router-dom underneath
 */
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import {
  matchPath,
  Link as RouterLink,
  type LinkProps as RouterLinkProps,
  useNavigate,
  useLocation as useRouterLocation,
  useParams as useRouterParams,
} from "react-router-dom";

// ============================================================================
// useLocation hook - maps to react-router's useLocation
// ============================================================================

export type LocationTuple = [string, (to: string, options?: { replace?: boolean }) => void];

export function useLocation(): LocationTuple {
  const location = useRouterLocation();
  const navigate = useNavigate();

  const navigateFn = useCallback(
    (to: string, options?: { replace?: boolean }) => {
      navigate(to, { replace: options?.replace });
    },
    [navigate]
  );

  return [location.pathname + location.search + location.hash, navigateFn];
}

// ============================================================================
// useRoute hook - pattern matching for routes
// ============================================================================

export type RouteMatch = { params: Record<string, string> } | null;

export function useRoute(pattern: string): RouteMatch {
  const location = useRouterLocation();
  const match = matchPath(pattern, location.pathname);

  if (!match) {
    return null;
  }

  return { params: match.params as Record<string, string> };
}

// ============================================================================
// Link component - maps to react-router's Link
// ============================================================================

interface LinkProps extends Omit<RouterLinkProps, "to"> {
  href?: string;
  to?: string;
  children: React.ReactNode;
  className?: string;
}

export function Link({ href, to, children, className, ...props }: LinkProps) {
  const target = to || href || "";
  return (
    <RouterLink to={target} className={className} {...props}>
      {children}
    </RouterLink>
  );
}

// ============================================================================
// Switch component - maps routes to the first match
// ============================================================================

interface RouteProps {
  path?: string;
  component?: React.ComponentType;
  children?: React.ReactNode;
}

interface SwitchProps {
  children: React.ReactElement<RouteProps>[];
}

export function Switch({ children }: SwitchProps) {
  const location = useRouterLocation();

  for (const child of children) {
    const { path, component: Component, children: routeChildren } = child.props;

    if (!path) {
      // Catch-all route
      return Component ? <Component /> : routeChildren;
    }

    const match = matchPath(path, location.pathname);
    if (match) {
      return Component ? <Component /> : routeChildren;
    }
  }

  return null;
}

export function Route(_props: RouteProps) {
  // This is just a marker component - Switch handles the rendering
  return null;
}

// ============================================================================
// useParams hook - maps to react-router's useParams
// ============================================================================

export function useParams(): Record<string, string> {
  const params = useRouterParams();
  return params as Record<string, string>;
}

// ============================================================================
// useSearch hook - provides access to search params
// ============================================================================

export function useSearch(): string {
  const location = useRouterLocation();
  return location.search;
}

// ============================================================================
// Redirect component - maps to react-router's Navigate
// ============================================================================

interface RedirectProps {
  to: string;
  replace?: boolean;
}

export function Redirect({ to, replace }: RedirectProps) {
  const navigate = useNavigate();
  const hasRedirected = useRef(false);

  useEffect(() => {
    if (!hasRedirected.current) {
      hasRedirected.current = true;
      navigate(to, { replace: replace ?? true });
    }
  }, [navigate, to, replace]);

  return null;
}

// ============================================================================
// Router component - wrapper that provides the adapter context
// ============================================================================

interface RouterProps {
  children: React.ReactNode;
}

export function Router({ children }: RouterProps) {
  // The adapter doesn't need additional context since we're using react-router directly
  return <>{children}</>;
}

import { ArrowLeft, ArrowRight, BookCheck, CheckCircle2, XCircle } from "lucide-react";
import { useState } from "react";
import { Link, useParams } from "react-router-dom";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Progress } from "@/components/ui/progress";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { logger } from "@/lib/logger";

interface Question {
  id: number;
  question: string;
  options: string[];
  correctAnswer: number;
  explanation: string;
}

interface QuizResult {
  score: number;
  totalQuestions: number;
  percentage: number;
  passed: boolean;
  feedback: string;
}

export function Quiz() {
  const { pillarNumber } = useParams<{ pillarNumber: string }>();

  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedAnswers, setSelectedAnswers] = useState<Record<number, string>>({});
  const [quizSubmitted, setQuizSubmitted] = useState(false);
  const [quizResult, setQuizResult] = useState<QuizResult | null>(null);

  const pillarNum = parseInt(pillarNumber || "1");

  // Mock quiz data - replace with real data from backend
  const mockQuestions: Question[] = [
    {
      id: 1,
      question: "What is the primary goal of Value Discovery in VOS?",
      options: [
        "To maximize revenue generation",
        "To identify and articulate value in any context",
        "To reduce operational costs",
        "To improve customer satisfaction scores"
      ],
      correctAnswer: 1,
      explanation: "Value Discovery focuses on identifying and articulating value in any context, which is the foundation of the VOS framework."
    },
    {
      id: 2,
      question: "Which VOS pillar deals with measuring and optimizing value realization?",
      options: [
        "Value Discovery",
        "Value Creation",
        "Value Capture",
        "Value Distribution"
      ],
      correctAnswer: 2,
      explanation: "Value Capture is the pillar that focuses on measuring and optimizing how value is actually realized and captured."
    },
    {
      id: 3,
      question: "What is a key principle of Value Distribution?",
      options: [
        "Maximizing individual profit",
        "Fair allocation across stakeholders",
        "Centralizing all value",
        "Minimizing distribution costs"
      ],
      correctAnswer: 1,
      explanation: "Value Distribution emphasizes fair allocation and communication of value across all stakeholders involved."
    }
  ];

  const questions = mockQuestions;

  const handleAnswerSelect = (questionId: number, answer: string) => {
    setSelectedAnswers(prev => ({
      ...prev,
      [questionId]: answer
    }));
  };

  const handleNext = () => {
    if (currentQuestionIndex < questions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
    }
  };

  const handlePrevious = () => {
    if (currentQuestionIndex > 0) {
      setCurrentQuestionIndex(prev => prev - 1);
    }
  };

  const calculateScore = () => {
    let correct = 0;
    questions.forEach(question => {
      const userAnswer = selectedAnswers[question.id];
      const correctAnswer = question.options[question.correctAnswer];
      if (userAnswer === correctAnswer) {
        correct++;
      }
    });
    return correct;
  };

  const handleSubmitQuiz = () => {
    const score = calculateScore();
    const percentage = Math.round((score / questions.length) * 100);
    const passed = percentage >= 70; // 70% passing threshold

    const result: QuizResult = {
      score,
      totalQuestions: questions.length,
      percentage,
      passed,
      feedback: passed
        ? "Congratulations! You've passed the quiz and can move to the next pillar."
        : "Keep studying! Review the material and try again when you're ready."
    };

    setQuizResult(result);
    setQuizSubmitted(true);
    logger.info("Quiz completed!");
  };

  const handleRetakeQuiz = () => {
    setCurrentQuestionIndex(0);
    setSelectedAnswers({});
    setQuizSubmitted(false);
    setQuizResult(null);
  };

  const currentQuestion = questions[currentQuestionIndex]!;
  const progress = ((currentQuestionIndex + 1) / questions.length) * 100;

  if (quizSubmitted && quizResult) {
    return (
      <div className="min-h-screen bg-background">
        <div className="container max-w-4xl mx-auto p-6">
          <Card>
            <CardHeader className="text-center">
              <div className="mx-auto mb-4">
                {quizResult.passed ? (
                  <CheckCircle2 className="h-16 w-16 text-green-500" />
                ) : (
                  <XCircle className="h-16 w-16 text-red-500" />
                )}
              </div>
              <CardTitle className="text-2xl">
                {quizResult.passed ? "Quiz Passed!" : "Quiz Not Passed"}
              </CardTitle>
              <CardDescription>
                You scored {quizResult.score} out of {quizResult.totalQuestions} ({quizResult.percentage}%)
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="text-center">
                <p className="text-muted-foreground">{quizResult.feedback}</p>
              </div>

              {/* Question Review */}
              <div className="space-y-4">
                <h3 className="font-semibold">Review Your Answers</h3>
                {questions.map((question, index) => {
                  const userAnswer = selectedAnswers[question.id];
                  const correctAnswer = question.options[question.correctAnswer];
                  const isCorrect = userAnswer === correctAnswer;

                  return (
                    <div key={question.id} className="border rounded-lg p-4">
                      <div className="flex items-start gap-3">
                        <div className={`mt-1 ${isCorrect ? 'text-green-500' : 'text-red-500'}`}>
                          {isCorrect ? <CheckCircle2 className="h-5 w-5" /> : <XCircle className="h-5 w-5" />}
                        </div>
                        <div className="flex-1">
                          <h4 className="font-medium mb-2">Question {index + 1}: {question.question}</h4>
                          <div className="space-y-2 text-sm">
                            <div>
                              <span className="font-medium">Your answer: </span>
                              <span className={isCorrect ? 'text-green-600' : 'text-red-600'}>
                                {userAnswer || "Not answered"}
                              </span>
                            </div>
                            {!isCorrect && (
                              <div>
                                <span className="font-medium">Correct answer: </span>
                                <span className="text-green-600">{correctAnswer}</span>
                              </div>
                            )}
                            <div className="text-muted-foreground">
                              <span className="font-medium">Explanation: </span>
                              {question.explanation}
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>

              <div className="flex gap-4">
                {!quizResult.passed && (
                  <Button onClick={handleRetakeQuiz} variant="outline">
                    Retake Quiz
                  </Button>
                )}
                <Button asChild>
                  <Link to="/academy/dashboard">
                    {quizResult.passed ? 'Continue Learning' : 'Back to Dashboard'}
                  </Link>
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="container max-w-4xl mx-auto p-6">
        {/* Header */}
        <div className="mb-8">
          <div className="flex items-center gap-4 mb-4">
            <Button variant="ghost" asChild>
              <Link to="/academy/dashboard">
                <ArrowLeft className="h-4 w-4 mr-2" />
                Back to Dashboard
              </Link>
            </Button>
            <Badge variant="outline">Pillar {pillarNum}</Badge>
          </div>
          <h1 className="text-3xl font-bold mb-2">VOS Pillar {pillarNum} Quiz</h1>
          <p className="text-muted-foreground">Test your knowledge of VOS concepts</p>
        </div>

        {/* Progress */}
        <div className="mb-8">
          <div className="flex justify-between text-sm mb-2">
            <span>Question {currentQuestionIndex + 1} of {questions.length}</span>
            <span>{Math.round(progress)}% complete</span>
          </div>
          <Progress value={progress} />
        </div>

        {/* Question */}
        <Card>
          <CardHeader>
            <CardTitle className="text-xl">
              Question {currentQuestionIndex + 1}
            </CardTitle>
            <CardDescription className="text-lg">
              {currentQuestion.question}
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-6">
            <RadioGroup
              value={selectedAnswers[currentQuestion?.id ?? ""] || ""}
              onValueChange={(value: string) => handleAnswerSelect(currentQuestion?.id ?? "", value)}
            >
              {currentQuestion?.options?.map((option, index) => (
                <div key={index} className="flex items-center space-x-2">
                  <RadioGroupItem value={option} id={`option-${index}`} />
                  <Label htmlFor={`option-${index}`} className="text-base">
                    {option}
                  </Label>
                </div>
              ))}
            </RadioGroup>

            <div className="flex justify-between pt-4">
              <Button
                variant="outline"
                onClick={handlePrevious}
                disabled={currentQuestionIndex === 0}
              >
                Previous
              </Button>

              {currentQuestionIndex === questions.length - 1 ? (
                <Button
                  onClick={handleSubmitQuiz}
                  disabled={!selectedAnswers[currentQuestion?.id ?? ""]}
                >
                  <BookCheck className="mr-2 h-4 w-4" />
                  Submit Quiz
                </Button>
              ) : (
                <Button
                  onClick={handleNext}
                  disabled={!selectedAnswers[currentQuestion?.id ?? ""]}
                >
                  Next
                  <ArrowRight className="ml-2 h-4 w-4" />
                </Button>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

export default Quiz;

