interface AuditLogResponse {
  logs: Array<{
    id: string;
    action: AuditLogEntry["action"];
    resource_type: AuditLogEntry["resource"];
    resource_id: string;
    user_id: string;
    user_email: string;
    timestamp: string;
    ip_address?: string;
    user_agent?: string;
    details?: Record<string, unknown>;
    status?: "success" | "failed";
  }>;
}

interface AuditExportResponse {
  downloadUrl?: string;
  fileName?: string;
}

function createFilterQueryParams(filter?: AuditFilter): Record<string, string> {
  const params = new URLSearchParams();

  if (filter?.userId) params.set("userId", filter.userId);
  if (filter?.search) params.set("search", filter.search);
  if (filter?.startDate) params.set("startDate", filter.startDate);
  if (filter?.endDate) params.set("endDate", filter.endDate);

  filter?.action?.forEach((action) => params.append("action", action));
  filter?.resource?.forEach((resource) => params.append("resourceType", resource));

  return Object.fromEntries(params.entries());
}

function downloadFromBlob(blob: Blob, fileName: string): void {
  const blobUrl = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = blobUrl;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(blobUrl);
}

function downloadFromUrl(downloadUrl: string): void {
  const link = document.createElement("a");
  link.href = downloadUrl;
  link.rel = "noopener";
  link.target = "_blank";
  document.body.appendChild(link);
  link.click();
  link.remove();
}

export function useAuditLog() {
  const [entries, setEntries] = useState<AuditLogEntry[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [exportError, setExportError] = useState<string | null>(null);
  const [hasMore, setHasMore] = useState(true);
  const [currentFilter, setCurrentFilter] = useState<AuditFilter | undefined>();

  const fetchLogs = useCallback(async (filter?: AuditFilter, cursor?: string) => {
    setIsLoading(true);
    setError(null);

    if (!cursor) {
      setCurrentFilter(filter);
    }

    try {
      const queryParams = {
        ...createFilterQueryParams(filter),
        offset: String(cursor ? Number(cursor) : 0),
        limit: "50",
      };

      const response = await apiClient.get<AuditLogResponse>("/api/admin/audit-logs", queryParams);

      if (response.success && response.data) {
        const logs: AuditLogEntry[] = response.data.logs.map((log) => ({
          id: log.id,
          action: log.action,
          resource: log.resource_type,
          resourceId: log.resource_id,
          userId: log.user_id,
          userEmail: log.user_email,
          timestamp: log.timestamp,
          ipAddress: log.ip_address,
          userAgent: log.user_agent,
          status: log.status,
          metadata: log.details,
          changes: (log.details?.changes as AuditLogEntry["changes"]) ?? undefined,
        }));

        setEntries((prev) => (cursor && Number(cursor) > 0 ? [...prev, ...logs] : logs));
        setHasMore(logs.length >= 50);
      } else {
        throw new Error(response.error?.message || "Failed to fetch audit logs");
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to fetch audit logs");
    } finally {
      setIsLoading(false);
    }
  }, []);

  const exportLogs = useCallback(async (filter?: AuditFilter, format: "csv" | "json" = "csv") => {
    setIsExporting(true);
    setExportError(null);

    try {
      const activeFilter = filter ?? currentFilter;
      const queryParams = new URLSearchParams({
        ...createFilterQueryParams(activeFilter),
        format,
      });

      const response = await apiClient.fetchRaw(
        `/api/admin/audit-logs/export?${queryParams.toString()}`,
        { method: "GET", headers: { Accept: format === "json" ? "application/json" : "text/csv" } },
      );

      if (!response.ok) {
        throw new Error(`Export failed with status ${response.status}`);
      }

      const contentType = response.headers.get("content-type") ?? "";
      const disposition = response.headers.get("content-disposition") ?? "";
      const fileNameMatch = disposition.match(/filename="?([^";]+)"?/i);
      const defaultFileName = `audit-logs.${format}`;

      if (contentType.includes("application/json")) {
        const payload = (await response.json()) as AuditExportResponse | Record<string, unknown>;
        if ("downloadUrl" in payload && typeof payload.downloadUrl === "string") {
          downloadFromUrl(payload.downloadUrl);
          return payload.downloadUrl;
        }

        const blob = new Blob([JSON.stringify(payload, null, 2)], {
          type: "application/json;charset=utf-8",
        });
        downloadFromBlob(blob, fileNameMatch?.[1] ?? defaultFileName);
        return null;
      }

      const blob = await response.blob();
      downloadFromBlob(blob, fileNameMatch?.[1] ?? defaultFileName);
      return null;
    } catch (_err) {
      const message =
        "Unable to export audit logs right now. Please try again in a moment or contact support if the issue persists.";
      setExportError(message);
      throw new Error(message);
    } finally {
      setIsExporting(false);
    }
  }, [currentFilter]);

  return {
    entries,
    isLoading,
    isExporting,
    error,
    exportError,
    hasMore,
    fetchLogs,
    exportLogs,
  };
}

import { useQuery } from "@tanstack/react-query";
import { InvoicesResponseSchema } from "@valueos/shared";
import type { BackendInvoice } from "@valueos/shared";

import type { Invoice } from "../types";

import { apiClient } from "@/api/client/unified-api-client";


// ---------------------------------------------------------------------------
// Shape translation
// ---------------------------------------------------------------------------

export function mapInvoiceStatus(status: string): Invoice["status"] {
  if (status === "paid") return "paid";
  if (status === "open" || status === "draft") return "pending";
  return "failed";
}

export function mapInvoice(raw: BackendInvoice): Invoice {
  return {
    // Use || not ?? so empty strings fall through to the next candidate.
    id: raw.invoice_number || raw.stripe_invoice_id || raw.id,
    amount: raw.amount_due,
    status: mapInvoiceStatus(raw.status),
    // Format as "Mon D, YYYY" to match the existing display style.
    date: new Date(raw.created_at).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    }),
    pdfUrl: raw.invoice_pdf ?? raw.hosted_invoice_url,
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useInvoices(limit = 10) {
  return useQuery<Invoice[]>({
    queryKey: ["billing", "invoices", limit],
    queryFn: async () => {
      const res = await apiClient.get<unknown>(`/api/billing/invoices?limit=${limit}`);
      if (!res.success) {
        if (res.error?.code === "404" || res.error?.message?.includes("404")) return [];
        throw new Error(res.error?.message ?? "Failed to fetch invoices");
      }
      if (!res.data) return [];
      const parsed = InvoicesResponseSchema.parse(res.data);
      return parsed.invoices.map(mapInvoice);
    },
    staleTime: 60_000,
    retry: (failureCount, error) => {
      if (error instanceof Error && error.message.includes("404")) return false;
      return failureCount < 2;
    },
  });
}

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { BackendSubscriptionSchema } from "@valueos/shared";

import type { PlanTier, Subscription, SubscriptionStatus } from "../types";

import { apiClient } from "@/api/client/unified-api-client";


// ---------------------------------------------------------------------------
// Shape translation
// ---------------------------------------------------------------------------

// The backend uses 'standard' where the frontend type uses 'pro'.
export function mapPlanTier(backendTier: "free" | "standard" | "enterprise"): PlanTier {
  if (backendTier === "standard") return "pro";
  return backendTier;
}

// Map the full backend status set to the UI-facing SubscriptionStatus union.
// Unknown values fall back to "active" so the UI never shows a blank state,
// but rawStatus preserves the original value for display or logic that needs it.
const UI_STATUS_MAP: Record<string, SubscriptionStatus> = {
  active: "active",
  trialing: "trialing",
  past_due: "past_due",
  canceled: "canceled",
  // Non-UI statuses coerced to the closest meaningful UI state:
  unpaid: "past_due",
  incomplete: "active",
  incomplete_expired: "canceled",
};

export function mapSubscriptionStatus(raw: string): SubscriptionStatus {
  return UI_STATUS_MAP[raw] ?? "active";
}

export function mapSubscription(
  raw: ReturnType<typeof BackendSubscriptionSchema.parse>,
): Subscription {
  return {
    id: raw.id,
    // Backend does not expose userId directly; organization_id is the
    // tenant-level identity used for display purposes.
    userId: raw.organization_id,
    planTier: mapPlanTier(raw.plan_tier),
    status: mapSubscriptionStatus(raw.status),
    rawStatus: raw.status,
    currentPeriodStart: raw.current_period_start,
    currentPeriodEnd: raw.current_period_end,
    cancelAtPeriodEnd: raw.cancel_at_period_end,
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useSubscription() {
  const queryClient = useQueryClient();

  const query = useQuery<Subscription | null>({
    queryKey: ["billing", "subscription"],
    queryFn: async () => {
      const res = await apiClient.get<unknown>("/api/billing/subscription");
      if (!res.success) {
        // 404 means no active subscription — not an error state for the UI.
        if (res.error?.code === "404" || res.error?.message?.includes("404")) return null;
        throw new Error(res.error?.message ?? "Failed to fetch subscription");
      }
      if (!res.data) return null;
      const parsed = BackendSubscriptionSchema.parse(res.data);
      return mapSubscription(parsed);
    },
    staleTime: 60_000,
    retry: (failureCount, error) => {
      if (error instanceof Error && error.message.includes("404")) return false;
      return failureCount < 2;
    },
  });

  const changePlanMutation = useMutation<void, Error, PlanTier>({
    mutationFn: async (planTier) => {
      // Map frontend 'pro' back to backend 'standard'.
      const backendTier = planTier === "pro" ? "standard" : planTier;
      const res = await apiClient.post("/api/billing/plan-change/submit", {
        new_plan_tier: backendTier,
      });
      if (!res.success) throw new Error(res.error?.message ?? "Plan change failed");
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["billing", "subscription"] });
    },
  });

  const cancelMutation = useMutation<void, Error, void>({
    mutationFn: async () => {
      const res = await apiClient.delete("/api/billing/subscription");
      if (!res.success) throw new Error(res.error?.message ?? "Cancellation failed");
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["billing", "subscription"] });
    },
  });

  return {
    subscription: query.data ?? null,
    isLoading: query.isLoading,
    error: query.error,
    changePlan: changePlanMutation.mutateAsync,
    cancelSubscription: cancelMutation.mutateAsync,
  };
}

import { useQuery } from "@tanstack/react-query";
import { BillingSummaryResponseSchema } from "@valueos/shared";

import type { UsageMetric } from "../types";

import { apiClient } from "@/api/client/unified-api-client";


// ---------------------------------------------------------------------------
// Extended type — adds metricKey for threshold logic and React list keying
// ---------------------------------------------------------------------------

export type BillingMetricKey =
  | "llm_tokens"
  | "agent_executions"
  | "api_calls"
  | "storage_gb"
  | "user_seats";

export interface UsageMetricWithMeta extends UsageMetric {
  metricKey: BillingMetricKey;
}

export interface UsageSummaryResult {
  metrics: UsageMetricWithMeta[];
  /** True when any metric is at or above 80% of its quota. */
  thresholdBreached: boolean;
  /** True when any metric is at or above 100% of its quota. */
  hardLimitReached: boolean;
  periodStart: string;
  periodEnd: string;
}

// ---------------------------------------------------------------------------
// Shape translation
// ---------------------------------------------------------------------------

const METRIC_LABELS: Record<BillingMetricKey, string> = {
  llm_tokens: "LLM Tokens",
  agent_executions: "Agent Runs",
  api_calls: "API Calls",
  storage_gb: "Storage",
  user_seats: "Seats",
};

export function mapUsageSummary(raw: {
  tenant_id: string;
  period_start: string;
  period_end: string;
  usage: Partial<Record<BillingMetricKey, number>>;
  quotas: Partial<Record<BillingMetricKey, number>>;
  percentages: Partial<Record<BillingMetricKey, number>>;
  overages: Partial<Record<BillingMetricKey, number>>;
}): UsageSummaryResult {
  const metrics = (Object.keys(raw.usage) as BillingMetricKey[]).map((key) => ({
    metric: METRIC_LABELS[key] ?? key,
    metricKey: key,
    used: raw.usage[key] ?? 0,
    limit: raw.quotas[key] ?? 0,
    percentage: raw.percentages[key] ?? 0,
  }));

  return {
    metrics,
    thresholdBreached: metrics.some((m) => m.percentage >= 80),
    hardLimitReached: metrics.some((m) => m.percentage >= 100),
    periodStart: raw.period_start,
    periodEnd: raw.period_end,
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useUsageSummary() {
  return useQuery<UsageSummaryResult | null>({
    queryKey: ["billing", "usage-summary"],
    queryFn: async () => {
      const res = await apiClient.get<unknown>("/api/billing/summary");
      if (!res.success) {
        if (res.error?.code === "404" || res.error?.message?.includes("404")) return null;
        throw new Error(res.error?.message ?? "Failed to fetch usage summary");
      }
      if (!res.data) return null;
      const usage = (res.data as { usage?: unknown }).usage;
      if (!usage) return null;
      const parsedUsage = BillingSummaryResponseSchema.shape.usage.parse(usage);
      return mapUsageSummary(parsedUsage);
    },
    staleTime: 30_000,
    retry: (failureCount, error) => {
      if (error instanceof Error && error.message.includes("404")) return false;
      return failureCount < 2;
    },
  });
}

