import { useDataBindings as useDataBinding } from "@sdui/useDataBinding";
import { Maximize, ZoomIn, ZoomOut } from "lucide-react";
import { useCallback, useState } from "react";
import { Treemap } from "recharts";

import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";

// Example data structure for a value tree node
export interface ValueTreeNode {
  id: string;
  label: string;
  value?: number;
  confidence?: number; // 0-1
  children?: ValueTreeNode[];
}

export interface ValueTreeChartProps {
  data: ValueTreeNode;
}

// Helper to find path from root to a node by id
function findPathToNode(root: ValueTreeNode, targetId: string, path: ValueTreeNode[] = []): ValueTreeNode[] | null {
  if (root.id === targetId) return [...path, root];
  if (!root.children) return null;
  for (const child of root.children) {
    const result = findPathToNode(child, targetId, [...path, root]);
    if (result) return result;
  }
  return null;
}



export function ValueTreeChart({ data }: ValueTreeChartProps) {
  // Real-time data binding for value tree data
  const { value: boundData, loading } = useDataBinding(data as unknown as Parameters<typeof useDataBinding>[0], {
    resolver: {
      resolve: async (binding: unknown) => ({ success: true, value: binding as ValueTreeNode, cached: false, timestamp: new Date().toISOString(), source: "static" as const }),
    },
    context: { organizationId: "default", projectId: "default" },
    enableRefresh: true,
  });

  const [zoom, setZoom] = useState(1);
  const [offset, setOffset] = useState({ x: 0, y: 0 });
  const [hoveredNodeId, setHoveredNodeId] = useState<string | null>(null);
  const [hoverPath, setHoverPath] = useState<ValueTreeNode[] | null>(null);

  const handleZoomIn = () => setZoom((prev) => Math.min(prev + 0.2, 2));
  const handleZoomOut = () => setZoom((prev) => Math.max(prev - 0.2, 0.5));
  const resetZoom = () => {
    setZoom(1);
    setOffset({ x: 0, y: 0 });
  };

  // When hovering a node, find the path from root to that node
  const handleNodeMouseEnter = useCallback((nodeId: string) => {
    setHoveredNodeId(nodeId);
    setHoverPath(findPathToNode(boundData as ValueTreeNode, nodeId));
  }, [boundData]);
  const handleNodeMouseLeave = useCallback(() => {
    setHoveredNodeId(null);
    setHoverPath(null);
  }, []);

  // Render a node with hover trail effect
  const renderNode = useCallback((props: {
    x: number; y: number; width: number; height: number;
    node?: ValueTreeNode;
    children?: Array<{ x: number; y: number; node?: ValueTreeNode }>;
  }) => {
    const { x, y, node, children } = props;
    if (!node) return null;

    const isInTrail = hoverPath?.some((n) => n.id === node.id);

    return (
      <g>
        {/* Render links to children before the node itself so they appear behind */}
        {children && children.length > 0 && children.map((child) => {
          if (!child.node) return null;

          const isChildInTrail = hoverPath?.some((n) => n.id === child.node.id);
          const isLinkHighlighted = isInTrail && isChildInTrail;

          // Parent node center
          const startX = x + 60; // 120 / 2
          const startY = y + 20; // 40 / 2

          // Child node center
          const endX = child.x + 60;
          const endY = child.y + 20;

          return (
            <line
              key={`link-${node.id}-${child.node.id}`}
              x1={startX}
              y1={startY}
              x2={endX}
              y2={endY}
              stroke={isLinkHighlighted ? "#6366f1" : "#cbd5e1"}
              strokeWidth={isLinkHighlighted ? 2 : 1}
              style={{
                transition: "stroke 0.2s, stroke-width 0.2s",
                filter: isLinkHighlighted ? "drop-shadow(0 0 4px #818cf8)" : undefined,
                pointerEvents: "none", // Prevent links from interfering with node hover
              }}
            />
          );
        })}

        <g
          transform={`translate(${x},${y})`}
          onMouseEnter={() => handleNodeMouseEnter(node.id)}
          onMouseLeave={handleNodeMouseLeave}
          style={{ cursor: "pointer" }}
        >
          <rect
            width={120}
            height={40}
            rx={8}
            fill={isInTrail ? "#6366f1" : "#0FBF9B"}
            opacity={isInTrail ? 0.7 : 1}
            style={{
              filter: isInTrail ? "drop-shadow(0 0 8px #818cf8)" : undefined,
              transition: "fill 0.2s, filter 0.2s, opacity 0.2s",
            }}
          />
          <text x={60} y={20} textAnchor="middle" fill="#fff" fontSize={14} fontWeight={600}>
            {node.label}
          </text>
          {typeof node.value === "number" && (
            <text x={60} y={35} textAnchor="middle" fill="#E6EEF3" fontSize={12}>
              {node.value}
            </text>
          )}
          {typeof node.confidence === "number" && (
            <TooltipProvider>
              <Tooltip>
                <TooltipTrigger asChild>
                  <circle cx={110} cy={10} r={8} fill="#16A34A" />
                </TooltipTrigger>
                <TooltipContent>
                  <p>Confidence: ${(node.confidence * 100).toFixed(0)}%</p>
                </TooltipContent>
              </Tooltip>
            </TooltipProvider>
          )}
        </g>
      </g>
    );
  }, [hoverPath, handleNodeMouseEnter, handleNodeMouseLeave]);

  if (loading) {
    return <div className="h-96 flex items-center justify-center animate-pulse text-muted-foreground">Loading value tree...</div>;
  }

  return (
    <Card className="p-4 relative overflow-hidden group">
      <div className="flex justify-between items-center mb-4">
        <Label className="block">Value Tree</Label>
        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          <Button size="xs" variant="outline" onClick={handleZoomOut}>
            <ZoomOut className="h-3 w-3" />
          </Button>
          <Button size="xs" variant="outline" onClick={handleZoomIn}>
            <ZoomIn className="h-3 w-3" />
          </Button>
          <Button size="xs" variant="outline" onClick={resetZoom}>
            <Maximize className="h-3 w-3" />
          </Button>
        </div>
      </div>

      <div
        className="cursor-grab active:cursor-grabbing"
        style={{
          width: "100%",
          height: 400,
          transform: `scale(${zoom}) translate(${offset.x}px, ${offset.y}px)`,
          transformOrigin: "center center",
          transition: "transform 0.2s ease-out",
        }}
      >
        <Treemap
          width={600}
          height={400}
          data={Array.isArray(boundData) ? boundData : [boundData]}
          content={renderNode as Parameters<typeof Treemap>[0]["content"]}
        />
      </div>
      <div className="absolute bottom-4 right-4 text-[10px] text-muted-foreground bg-white/80 px-2 py-1 rounded border">
        Zoom: {(zoom * 100).toFixed(0)}%
      </div>

    </Card>
  );
}

import { useCallback, useState } from "react";

import { apiClient } from "../../../api/client/unified-api-client";
import { logger } from "@/lib/logger";
import type { Canvas, CanvasEdge, CanvasNode, CanvasViewport } from "../types";

export function useCanvas(_canvasId?: string) {
  const [canvas, setCanvas] = useState<Canvas | null>(null);
  const [selectedNodes, setSelectedNodes] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const loadCanvas = useCallback(async (id: string) => {
    setIsLoading(true);
    try {
      const response = await apiClient.get<Canvas>(`/api/canvas/${id}`);
      if (response.success && response.data) {
        setCanvas(response.data);
      }
    } catch (error) {
      logger.error("Failed to load canvas", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const addNode = useCallback((node: Omit<CanvasNode, "id">) => {
    const newNode: CanvasNode = {
      ...node,
      id: `node_${Date.now()}`,
    };
    setCanvas((prev) =>
      prev ? { ...prev, nodes: [...prev.nodes, newNode], updatedAt: new Date().toISOString() } : null
    );
    return newNode;
  }, []);

  const updateNode = useCallback((nodeId: string, updates: Partial<CanvasNode>) => {
    setCanvas((prev) =>
      prev
        ? {
            ...prev,
            nodes: prev.nodes.map((n) => (n.id === nodeId ? { ...n, ...updates } : n)),
            updatedAt: new Date().toISOString(),
          }
        : null
    );
  }, []);

  const deleteNode = useCallback((nodeId: string) => {
    setCanvas((prev) =>
      prev
        ? {
            ...prev,
            nodes: prev.nodes.filter((n) => n.id !== nodeId),
            edges: prev.edges.filter((e) => e.source !== nodeId && e.target !== nodeId),
            updatedAt: new Date().toISOString(),
          }
        : null
    );
    setSelectedNodes((prev) => prev.filter((id) => id !== nodeId));
  }, []);

  const addEdge = useCallback((edge: Omit<CanvasEdge, "id">) => {
    const newEdge: CanvasEdge = {
      ...edge,
      id: `edge_${Date.now()}`,
    };
    setCanvas((prev) =>
      prev ? { ...prev, edges: [...prev.edges, newEdge], updatedAt: new Date().toISOString() } : null
    );
    return newEdge;
  }, []);

  const deleteEdge = useCallback((edgeId: string) => {
    setCanvas((prev) =>
      prev
        ? {
            ...prev,
            edges: prev.edges.filter((e) => e.id !== edgeId),
            updatedAt: new Date().toISOString(),
          }
        : null
    );
  }, []);

  const setViewport = useCallback((viewport: CanvasViewport) => {
    setCanvas((prev) => (prev ? { ...prev, viewport } : null));
  }, []);

  const selectNode = useCallback((nodeId: string, multi = false) => {
    setSelectedNodes((prev) => (multi ? [...prev, nodeId] : [nodeId]));
  }, []);

  const clearSelection = useCallback(() => {
    setSelectedNodes([]);
  }, []);

  return {
    canvas,
    selectedNodes,
    isLoading,
    loadCanvas,
    addNode,
    updateNode,
    deleteNode,
    addEdge,
    deleteEdge,
    setViewport,
    selectNode,
    clearSelection,
  };
}

import { createMCPServer } from "../../../mcp-ground-truth";
import type { ClaimSeverity, CompanySize, ESOIndustry } from "../../../types/eso";
import { logger } from "@/lib/logger";

// ============================================================================
// Response Types
// ============================================================================

export interface GroundTruthMetric {
  metricId: string;
  name: string;
  value: number;
  unit: string;
  confidence: number;
  source: string;
  benchmarks: {
    p25: number;
    p50: number;
    p75: number;
    worldClass?: number;
  };
}

export interface ValidationResult {
  valid: boolean;
  percentile: string;
  severity: ClaimSeverity;
  detail: string;
  warning?: string;
  benchmark: { p25: number; p50: number; p75: number };
}

export interface FeasibilityResult {
  feasible: boolean;
  score: number;
  percentileJump: number;
  estimatedMonths: number;
  riskLevel: string;
  rationale: string;
}

export interface CompositeHealthResult {
  overallScore: number;
  grade: string;
  entries: Array<{
    metricId: string;
    name: string;
    score: number;
    severity: ClaimSeverity;
    gap: number;
  }>;
  strongestKPIs: string[];
  weakestKPIs: string[];
  improvementPriority: string[];
}

// ============================================================================
// Cache
// ============================================================================

interface CacheEntry<T> {
  value: T;
  expiresAt: number;
}

const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes
const MAX_CACHE_ENTRIES = 200;

// ============================================================================
// Service
// ============================================================================

export class GroundTruthService {
  private static instance: GroundTruthService;

  private mcpServer: {
    executeTool: (name: string, args: Record<string, unknown>) => Promise<unknown>;
  } | null = null;
  private cache = new Map<string, CacheEntry<unknown>>();

  private constructor() {}

  public static getInstance(): GroundTruthService {
    if (!GroundTruthService.instance) {
      GroundTruthService.instance = new GroundTruthService();
    }
    return GroundTruthService.instance;
  }

  public async initialize(): Promise<void> {
    if (this.mcpServer) return;

    this.mcpServer = (await createMCPServer({
      industryBenchmark: {
        enableStaticData: true,
      },
    })) as { executeTool: (name: string, args: Record<string, unknown>) => Promise<unknown> };
  }

  // --------------------------------------------------------------------------
  // Cache helpers
  // --------------------------------------------------------------------------

  private getCached<T>(key: string): T | undefined {
    const entry = this.cache.get(key) as CacheEntry<T> | undefined;
    if (!entry) return undefined;
    if (Date.now() > entry.expiresAt) {
      this.cache.delete(key);
      return undefined;
    }
    return entry.value;
  }

  private setCached<T>(key: string, value: T): void {
    // Evict oldest entries when at capacity
    if (this.cache.size >= MAX_CACHE_ENTRIES) {
      const firstKey = this.cache.keys().next().value;
      if (firstKey !== undefined) this.cache.delete(firstKey);
    }
    this.cache.set(key, { value, expiresAt: Date.now() + CACHE_TTL_MS });
  }

  public clearCache(): void {
    this.cache.clear();
  }

  // --------------------------------------------------------------------------
  // Single metric benchmark
  // --------------------------------------------------------------------------

  public async getMetricBenchmark(
    metricId: string,
    industry?: ESOIndustry,
    companySize?: CompanySize
  ): Promise<GroundTruthMetric | null> {
    const cacheKey = `metric:${metricId}:${industry ?? ""}:${companySize ?? ""}`;
    const cached = this.getCached<GroundTruthMetric>(cacheKey);
    if (cached) return cached;

    await this.initialize();

    try {
      const result = await this.mcpServer!.executeTool("eso_get_metric_value", {
        metricId,
        industry,
        companySize,
      });

      if (result?.success && result.data) {
        const d = result.data;
        const metric: GroundTruthMetric = {
          metricId: d.metricId as string,
          name: d.name as string,
          value: d.value as number,
          unit: d.unit as string,
          confidence: (d.confidence as number) ?? 0.85,
          source: d.source as string,
          benchmarks: d.benchmarks as GroundTruthMetric["benchmarks"],
        };
        this.setCached(cacheKey, metric);
        return metric;
      }
    } catch (error) {
      logger.error(`Failed to fetch ground truth for metric ${metricId}`, error);
    }

    return null;
  }

  // --------------------------------------------------------------------------
  // Batch metric fetch
  // --------------------------------------------------------------------------

  public async getMetricBenchmarks(
    metricIds: string[],
    industry?: ESOIndustry,
    companySize?: CompanySize
  ): Promise<Map<string, GroundTruthMetric>> {
    const results = new Map<string, GroundTruthMetric>();
    const promises = metricIds.map(async (id) => {
      const metric = await this.getMetricBenchmark(id, industry, companySize);
      if (metric) results.set(id, metric);
    });
    await Promise.all(promises);
    return results;
  }

  // --------------------------------------------------------------------------
  // Claim validation with severity
  // --------------------------------------------------------------------------

  public async validateClaim(
    metricId: string,
    claimedValue: number
  ): Promise<ValidationResult | null> {
    await this.initialize();

    try {
      const result = await this.mcpServer!.executeTool("eso_classify_severity", {
        metricId,
        claimedValue,
      });
      if (result) return result as unknown as ValidationResult;
    } catch (error) {
      logger.error(`Failed to validate claim for ${metricId}`, error);
    }
    return null;
  }

  // --------------------------------------------------------------------------
  // Feasibility assessment
  // --------------------------------------------------------------------------

  public async assessFeasibility(
    metricId: string,
    currentValue: number,
    targetValue: number
  ): Promise<FeasibilityResult | null> {
    await this.initialize();

    try {
      const result = await this.mcpServer!.executeTool("eso_assess_feasibility", {
        metricId,
        currentValue,
        targetValue,
      });
      if (result) return result as unknown as FeasibilityResult;
    } catch (error) {
      logger.error(`Failed to assess feasibility for ${metricId}`, error);
    }
    return null;
  }

  // --------------------------------------------------------------------------
  // Composite health scoring
  // --------------------------------------------------------------------------

  public async scoreCompositeHealth(
    metrics: Array<{ metricId: string; value: number }>
  ): Promise<CompositeHealthResult | null> {
    await this.initialize();

    try {
      const result = await this.mcpServer!.executeTool("eso_composite_health", { metrics });
      if (result) return result as unknown as CompositeHealthResult;
    } catch (error) {
      logger.error("Failed to compute composite health", error);
    }
    return null;
  }
}

import { useCallback, useState } from "react";

import { api } from "../../../api/client/unified-api-client";
import type { ChatMessage } from "../types";

export function useChat(_sessionId?: string) {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isStreaming, setIsStreaming] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const sendMessage = useCallback(async (content: string) => {
    const userMessage: ChatMessage = {
      id: `msg_${Date.now()}`,
      role: "user",
      content,
      timestamp: new Date().toISOString(),
    };

    setMessages((prev) => [...prev, userMessage]);
    setIsStreaming(true);
    setError(null);

    try {
      const response = await api.chat({
        prompt: content,
        model: "mistralai/Mixtral-8x7B-Instruct-v0.1",
      });

      if (!response.success) {
        throw new Error(response.error?.message || "Network request failed");
      }

      if (response.data && !response.data.success) {
        throw new Error(
          response.data.error || response.data.message || "Request failed"
        );
      }

      const result = response.data?.data;

      if (!result) {
        throw new Error("Invalid response format");
      }

      const assistantMessage: ChatMessage = {
        id: `msg_${Date.now() + 1}`,
        role: "assistant",
        content: result.content,
        timestamp: new Date().toISOString(),
        metadata: {
          model: result.model,
          tokens: result.usage?.totalTokens,
        },
      };

      setMessages((prev) => [...prev, assistantMessage]);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to send message");
    } finally {
      setIsStreaming(false);
    }
  }, []);

  const clearMessages = useCallback(() => {
    setMessages([]);
  }, []);

  return {
    messages,
    isStreaming,
    error,
    sendMessage,
    clearMessages,
  };
}

/**
 * WorkflowTimeline Component - Horizontal timeline showing phase transitions
 */

import { useWorkflowState } from '../../hooks/useWorkflowState';
import { WorkflowState } from '../../types/workflow.types';

export function WorkflowTimeline() {
  const { phaseHistory, phase } = useWorkflowState();

  const allPhases: WorkflowState[] = ['INITIATED', 'DRAFTING', 'VALIDATING', 'COMPOSING', 'REFINING', 'FINALIZED'];
  const currentPhaseIndex = allPhases.indexOf(phase);

  return (
    <div className="p-4">
      <h4 className="text-xs font-semibold text-neutral-500 uppercase mb-3">Workflow Timeline</h4>
      <div className="flex items-center gap-1">
        {allPhases.map((state, index) => {
          const historyEntry = phaseHistory.find(p => p.state === state);
          const isCurrent = state === phase;
          const isPast = index < currentPhaseIndex;
          const isFuture = index > currentPhaseIndex;

          return (
            <div key={state} className="flex items-center">
              <PhaseNode
                state={state}
                isCurrent={isCurrent}
                isPast={isPast}
                isFuture={isFuture}
                timestamp={historyEntry?.enteredAt}
                actor={historyEntry?.actor}
              />
              {index < allPhases.length - 1 && (
                <div className={`w-8 h-0.5 ${isPast ? 'bg-blue-500' : 'bg-neutral-200'}`} />
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

interface PhaseNodeProps {
  state: WorkflowState;
  isCurrent: boolean;
  isPast: boolean;
  isFuture: boolean;
  timestamp?: string;
  actor?: string;
}

function PhaseNode({ state, isCurrent, isPast, isFuture, timestamp, actor }: PhaseNodeProps) {
  const colorClass = isCurrent
    ? 'bg-blue-500 text-white'
    : isPast
    ? 'bg-green-500 text-white'
    : 'bg-neutral-200 text-neutral-500';

  return (
    <div className="relative group">
      <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-medium ${colorClass}`}>
        {state[0]}
      </div>
      {/* Tooltip */}
      <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-neutral-800 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none z-10">
        {state}
        {timestamp && (
          <div className="text-neutral-400">
            {new Date(timestamp).toLocaleDateString()} by {actor}
          </div>
        )}
      </div>
    </div>
  );
}

