/**
 * useGraphData Hook
 *
 * Fetches value tree nodes from /api/v1/cases/:caseId/value-tree and
 * transforms the flat node list into the Graph shape the canvas expects.
 * Falls back to an empty graph when the case has no tree yet.
 */

import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';

import type { Graph, ValueEdge, ValueNode } from '../types/graph.types';

import { apiClient } from '@/api/client/unified-api-client';


// ---------------------------------------------------------------------------
// Backend row shape (mirrors ValueTreeNodeRow from the repository)
// ---------------------------------------------------------------------------

interface ValueTreeNodeRow {
  id: string;
  case_id: string;
  organization_id: string;
  parent_id: string | null;
  node_key: string | null;
  label: string;
  description: string | null;
  driver_type: string | null;
  impact_estimate: number | null;
  confidence: number | null;
  sort_order: number;
  source_agent: string | null;
  metadata: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

// ---------------------------------------------------------------------------
// Transform flat node list -> Graph
// ---------------------------------------------------------------------------

function driverTypeToNodeType(dt: string | null): ValueNode['type'] {
  switch (dt) {
    case 'revenue': return 'output';
    case 'cost':
    case 'efficiency': return 'driver';
    case 'risk': return 'metric';
    default: return 'input';
  }
}

export function transformToGraph(caseId: string, rows: ValueTreeNodeRow[]): Graph {
  if (rows.length === 0) return emptyGraph(caseId);

  const nodes: Record<string, ValueNode> = {};
  const edges: Record<string, ValueEdge> = {};
  let totalImpact = 0;
  let confidenceSum = 0;
  let confidenceCount = 0;

  for (const row of rows) {
    const confidence = row.confidence ?? 0;
    if (confidence > 0) {
      confidenceSum += confidence;
      confidenceCount += 1;
    }
    totalImpact += row.impact_estimate ?? 0;

    nodes[row.id] = {
      id: row.id,
      type: driverTypeToNodeType(row.driver_type),
      label: row.label,
      value: row.impact_estimate ?? undefined,
      unit: (row.metadata?.unit as string | undefined) ?? 'USD',
      confidence: row.confidence ?? undefined,
      inputs: [],
      outputs: [],
      metadata: {
        description: row.description ?? undefined,
        owner: (row.metadata?.owner as string | undefined),
        lastModified: row.updated_at,
        version: 1,
      },
    };
  }

  let edgeIdx = 0;
  for (const row of rows) {
    if (row.parent_id && nodes[row.parent_id] && nodes[row.id]) {
      const edgeId = `edge-${edgeIdx++}`;
      edges[edgeId] = { id: edgeId, source: row.id, target: row.parent_id, type: 'input' };
      const child = nodes[row.id];
      const parent = nodes[row.parent_id];
      child.outputs.push(row.parent_id);
      parent.inputs.push(row.id);
    }
  }

  const avgConf = confidenceCount > 0
    ? confidenceSum / confidenceCount
    : 0;

  return {
    id: `graph-${caseId}`,
    versionId: null,
    scenarioId: `scenario-${caseId}`,
    nodes,
    edges,
    computedAt: new Date().toISOString(),
    globalMetrics: {
      npv: totalImpact,
      // roi and paybackMonths are omitted until the financial model snapshot is loaded.
      // The graph metrics panel should gate display on these being defined.
      roi: undefined,
      paybackMonths: undefined,
      confidence: avgConf,
      defensibilityScore: avgConf * 0.9,
    },
    evidenceCoverage: avgConf,
  };
}

function emptyGraph(caseId: string): Graph {
  return {
    id: `graph-${caseId}`,
    versionId: null,
    scenarioId: `scenario-${caseId}`,
    nodes: {},
    edges: {},
    computedAt: null,
    globalMetrics: { npv: 0, confidence: 0, defensibilityScore: 0 },
    evidenceCoverage: 0,
  };
}

async function fetchGraph(caseId: string): Promise<Graph> {
  const res = await apiClient.get<{ data: ValueTreeNodeRow[] }>(
    `/api/v1/cases/${caseId}/value-tree`
  );

  // NOT_FOUND means the case exists but has no tree yet — treat as empty, not an error.
  if (!res.success && res.error?.code === 'NOT_FOUND') return emptyGraph(caseId);

  // Any other failure should surface so React Query can populate `error`.
  if (!res.success || !res.data) {
    throw new Error(res.error?.message ?? `Failed to fetch value tree for case ${caseId}`);
  }

  return transformToGraph(caseId, res.data.data ?? []);
}

export function useGraphData(caseId?: string) {
  // Memoize so emptyGraph isn't called (and new objects allocated) on every render.
  const placeholder = useMemo(
    () => (caseId ? emptyGraph(caseId) : undefined),
    [caseId]
  );

  const { data, isLoading, error, refetch } = useQuery({
    queryKey: ['graph', caseId],
    queryFn: () => fetchGraph(caseId!),
    enabled: !!caseId,
    staleTime: 30_000,
    placeholderData: placeholder,
  });

  return { graph: data, isLoading, error, refetch };
}

/**
 * useWorkflowState Hook - Access workflow state and actions
 */

import { useWorkflowStore } from '../store/workflow-store';
import {
  WorkflowState,
  WorkflowStep,
} from '../types/workflow.types';

export function useWorkflowState() {
  const {
    phase,
    steps,
    currentStep,
    phaseHistory,
    blockingIssues,
    advancePhase,
    completeStep,
    blockStep,
    unblockStep,
    getGatingRules,
    canTransitionTo,
    setBlockingIssues,
    clearBlockingIssues,
  } = useWorkflowStore();

  const isStepComplete = (step: WorkflowStep) =>
    steps.find((s) => s.step === step)?.status === 'complete';

  const isStepBlocked = (step: WorkflowStep) =>
    steps.find((s) => s.step === step)?.status === 'blocked';

  const isStepActive = (step: WorkflowStep) =>
    steps.find((s) => s.step === step)?.status === 'active';

  const getStepStatus = (step: WorkflowStep) =>
    steps.find((s) => s.step === step)?.status || 'not_started';

  const getBlockingReason = (step: WorkflowStep) =>
    steps.find((s) => s.step === step)?.blockingReason;

  return {
    // State
    phase,
    steps,
    currentStep,
    phaseHistory,
    blockingIssues,

    // Queries
    isStepComplete,
    isStepBlocked,
    isStepActive,
    getStepStatus,
    getBlockingReason,
    canTransitionTo,
    getGatingRules,

    // Actions
    advancePhase,
    completeStep,
    blockStep,
    unblockStep,
    setBlockingIssues,
    clearBlockingIssues,
  };
}

/**
 * Defensibility Store - Zustand store for CFO-defensibility metrics
 */

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

import { DefensibilityIssue, DefensibilityScore, NodeDefensibility } from '../types/defensibility.types';
import { Evidence, Graph, ValueNode } from '../types/graph.types';

interface DefensibilityStore {
  // Global metrics
  globalScore: number;
  coverageByNode: Record<string, number>;
  totalBackedValue: number;
  totalValue: number;

  // Issues and warnings
  issues: DefensibilityIssue[];
  nodeDefensibility: Record<string, NodeDefensibility>;

  // Actions
  calculateScore: (graph: Graph) => void;
  getNodeCoverage: (nodeId: string) => number;
  isAboveThreshold: (threshold?: number) => boolean;
  getIssuesForNode: (nodeId: string) => DefensibilityIssue[];
  addIssue: (issue: DefensibilityIssue) => void;
  clearIssues: () => void;
}

export const useDefensibilityStore = create<DefensibilityStore>()(
  persist(
    (set, get) => ({
      globalScore: 0,
      coverageByNode: {},
      totalBackedValue: 0,
      totalValue: 0,
      issues: [],
      nodeDefensibility: {},

      calculateScore: (graph) => {
        let totalValue = 0;
        let backedValue = 0;
        const coverageByNode: Record<string, number> = {};
        const nodeDefensibility: Record<string, NodeDefensibility> = {};

        for (const node of Object.values(graph.nodes)) {
          const nodeValue = node.value || 0;
          const coverage = calculateNodeEvidenceCoverage(node);
          const defensibility = calculateNodeDefensibility(node, coverage);

          totalValue += nodeValue;
          backedValue += nodeValue * coverage;
          coverageByNode[node.id] = coverage;
          nodeDefensibility[node.id] = defensibility;
        }

        const globalScore = totalValue > 0 ? backedValue / totalValue : 0;

        set({
          globalScore,
          coverageByNode,
          totalBackedValue: backedValue,
          totalValue,
          nodeDefensibility,
        });
      },

      getNodeCoverage: (nodeId) => {
        return get().coverageByNode[nodeId] || 0;
      },

      isAboveThreshold: (threshold = 0.7) => {
        return get().globalScore >= threshold;
      },

      getIssuesForNode: (nodeId) => {
        return get().issues.filter((i) => i.nodeId === nodeId);
      },

      addIssue: (issue) => {
        set({ issues: [...get().issues, issue] });
      },

      clearIssues: () => {
        set({ issues: [] });
      },
    }),
    {
      name: 'defensibility-store',
      partialize: (state) => ({
        globalScore: state.globalScore,
        coverageByNode: state.coverageByNode,
        totalBackedValue: state.totalBackedValue,
        totalValue: state.totalValue,
      }),
    }
  )
);

// Helper functions
function calculateNodeEvidenceCoverage(node: ValueNode): number {
  if (!node.evidence || node.evidence.length === 0) {
    return 0;
  }

  const evidence = node.evidence;
  const totalWeight = evidence.reduce((sum, e) => sum + (e.weight || 1), 0);
  const validWeight = evidence
    .filter((e) => isEvidenceValid(e))
    .reduce((sum, e) => sum + (e.weight || 1), 0);

  return totalWeight > 0 ? validWeight / totalWeight : 0;
}

function isEvidenceValid(evidence: Evidence): boolean {
  return (
    evidence.confidence >= 0.7 &&
    !evidence.isStale &&
    evidence.hasAttribution !== false
  );
}

function calculateNodeDefensibility(node: ValueNode, coverage: number): NodeDefensibility {
  const evidence = node.evidence || [];
  const uniqueSources = new Set(evidence.map((e) => e.source)).size;

  return {
    nodeId: node.id,
    evidenceCoverage: coverage,
    sourceIndependence: uniqueSources,
    auditTrailComplete: node.metadata?.lastModified !== undefined,
    valueContribution: node.value || 0,
    threshold: 0.8,
    warnings: generateWarnings(node, coverage, uniqueSources),
  };
}

function generateWarnings(
  node: ValueNode,
  coverage: number,
  uniqueSources: number
): import('../types/defensibility.types').DefensibilityWarning[] {
  const warnings: import('../types/defensibility.types').DefensibilityWarning[] = [];

  if (coverage < 0.5) {
    warnings.push({
      type: 'low_coverage',
      severity: 'critical',
      message: 'Evidence coverage below 50%',
      remediation: 'Add high-confidence evidence sources',
    });
  } else if (coverage < 0.8) {
    warnings.push({
      type: 'low_coverage',
      severity: 'warning',
      message: 'Evidence coverage below 80%',
      remediation: 'Add additional evidence sources',
    });
  }

  if (uniqueSources === 1) {
    warnings.push({
      type: 'single_source',
      severity: 'warning',
      message: 'Only one evidence source',
      remediation: 'Add independent corroborating sources',
    });
  }

  const staleEvidence = node.evidence?.filter((e) => e.isStale) || [];
  if (staleEvidence.length > 0) {
    warnings.push({
      type: 'stale_evidence',
      severity: 'warning',
      message: `${staleEvidence.length} stale citations need refresh`,
      remediation: 'Update with latest data',
    });
  }

  return warnings;
}

/**
 * Workflow Store - Zustand store for workflow state management
 */

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

import {
  GatingRules,
  INITIAL_WORKFLOW_STEPS,
  ValidationIssue,
  WorkflowState,
  WorkflowStep,
  WorkflowStepState,
} from '../types/workflow.types';
import { GATING_MATRIX } from '../utils/state-gating';
import { logger } from '@/lib/logger';

interface WorkflowStore {
  // Current orchestration phase
  phase: WorkflowState;

  // 7-step loop progress
  steps: WorkflowStepState[];
  currentStep: WorkflowStep;

  // Phase history for timeline
  phaseHistory: { state: WorkflowState; enteredAt: string; actor: string }[];

  // Actions
  initializeWorkflow: () => void;
  advancePhase: (to: WorkflowState, reason: string, actor?: string) => boolean;
  completeStep: (step: WorkflowStep) => void;
  blockStep: (step: WorkflowStep, reason: string) => void;
  unblockStep: (step: WorkflowStep) => void;
  getGatingRules: () => GatingRules;
  canTransitionTo: (to: WorkflowState) => boolean;

  // Validation
  blockingIssues: ValidationIssue[];
  setBlockingIssues: (issues: ValidationIssue[]) => void;
  clearBlockingIssues: () => void;
}

const VALID_TRANSITIONS: Record<WorkflowState, WorkflowState[]> = {
  INITIATED: ['DRAFTING'],
  DRAFTING: ['VALIDATING', 'INITIATED'],
  VALIDATING: ['COMPOSING', 'DRAFTING', 'REFINING'],
  COMPOSING: ['REFINING', 'VALIDATING'],
  REFINING: ['FINALIZED', 'VALIDATING', 'DRAFTING'],
  FINALIZED: ['REFINING'], // Override only
};

export const useWorkflowStore = create<WorkflowStore>()(
  persist(
    (set, get) => ({
      phase: 'INITIATED',
      steps: INITIAL_WORKFLOW_STEPS,
      currentStep: 'hypothesis',
      phaseHistory: [{ state: 'INITIATED', enteredAt: new Date().toISOString(), actor: 'system' }],
      blockingIssues: [],

      initializeWorkflow: () => {
        set({
          phase: 'INITIATED',
          steps: INITIAL_WORKFLOW_STEPS,
          currentStep: 'hypothesis',
          phaseHistory: [{ state: 'INITIATED', enteredAt: new Date().toISOString(), actor: 'system' }],
          blockingIssues: [],
        });
      },

      advancePhase: (to, reason, actor = 'user') => {
        const current = get().phase;

        // Check if transition is valid
        if (!VALID_TRANSITIONS[current].includes(to)) {
          logger.warn(`Invalid transition from ${current} to ${to}`);
          return false;
        }

        // Check for blocking issues when moving forward
        if (get().blockingIssues.some(i => i.severity === 'blocking')) {
          logger.warn('Cannot advance: blocking issues exist');
          return false;
        }

        set({
          phase: to,
          phaseHistory: [
            ...get().phaseHistory,
            { state: to, enteredAt: new Date().toISOString(), actor },
          ],
        });

        return true;
      },

      completeStep: (step) => {
        const steps = get().steps.map((s) =>
          s.step === step
            ? { ...s, status: 'complete' as const, completedAt: new Date().toISOString() }
            : s
        );

        // Find next incomplete step
        const nextStep = steps.find((s) => s.status === 'not_started');
        const currentStep = steps.find((s) => s.status === 'active')?.step ||
          nextStep?.step ||
          get().currentStep;

        // Update current step to next if current is now complete
        if (get().currentStep === step && nextStep) {
          steps.forEach((s) => {
            if (s.step === nextStep.step) {
              s.status = 'active';
              s.startedAt = new Date().toISOString();
            }
          });
        }

        set({ steps, currentStep });
      },

      blockStep: (step, reason) => {
        const steps = get().steps.map((s) =>
          s.step === step ? { ...s, status: 'blocked' as const, blockingReason: reason } : s
        );
        set({ steps });
      },

      unblockStep: (step) => {
        const steps = get().steps.map((s) =>
          s.step === step
            ? { ...s, status: 'not_started' as const, blockingReason: undefined }
            : s
        );
        set({ steps });
      },

      getGatingRules: () => {
        return GATING_MATRIX[get().phase];
      },

      canTransitionTo: (to) => {
        return VALID_TRANSITIONS[get().phase].includes(to);
      },

      setBlockingIssues: (issues) => {
        set({ blockingIssues: issues });
      },

      clearBlockingIssues: () => {
        set({ blockingIssues: [] });
      },
    }),
    {
      name: 'workflow-store',
      partialize: (state) => ({
        phase: state.phase,
        steps: state.steps,
        currentStep: state.currentStep,
        phaseHistory: state.phaseHistory,
      }),
    }
  )
);

/**
 * Defensibility Calculation Utilities
 */

import { DefensibilityIssue, DefensibilityScore } from '../types/defensibility.types';
import { Evidence, ValueNode } from '../types/graph.types';

/**
 * Calculate global defensibility score for a set of nodes
 */
export function calculateDefensibilityScore(nodes: ValueNode[]): DefensibilityScore {
  let totalValue = 0;
  let backedValue = 0;

  for (const node of nodes) {
    const nodeValue = node.value || 0;
    const coverage = calculateNodeCoverage(node);

    totalValue += nodeValue;
    backedValue += nodeValue * coverage;
  }

  const globalScore = totalValue > 0 ? backedValue / totalValue : 0;
  const threshold = 0.7;

  return {
    global: globalScore,
    breakdown: {
      backedByEvidence: backedValue,
      totalValue,
      coveragePercent: globalScore * 100,
    },
    threshold,
    isBlocking: globalScore < threshold,
  };
}

/**
 * Calculate evidence coverage for a single node
 */
export function calculateNodeCoverage(node: ValueNode): number {
  if (!node.evidence || node.evidence.length === 0) {
    return 0;
  }

  const evidence = node.evidence;
  const totalWeight = evidence.reduce((sum, e) => sum + (e.weight || 1), 0);
  const validWeight = evidence
    .filter((e) => isEvidenceValid(e))
    .reduce((sum, e) => sum + (e.weight || 1), 0);

  return totalWeight > 0 ? validWeight / totalWeight : 0;
}

/**
 * Check if evidence meets validity criteria
 */
export function isEvidenceValid(evidence: Evidence): boolean {
  return (
    evidence.confidence >= 0.7 &&
    !evidence.isStale &&
    evidence.hasAttribution !== false
  );
}

/**
 * Generate defensibility issues for a node
 */
export function generateDefensibilityIssues(
  node: ValueNode,
  allNodes: ValueNode[]
): DefensibilityIssue[] {
  const issues: DefensibilityIssue[] = [];
  const coverage = calculateNodeCoverage(node);

  // Low coverage issue
  if (coverage < 0.5) {
    issues.push({
      id: `issue-${node.id}-coverage`,
      nodeId: node.id,
      nodeName: node.label,
      type: 'evidence_gap',
      severity: 'critical',
      valueAtRisk: (node.value || 0) * (1 - coverage),
      suggestedAction: 'Add high-confidence evidence sources',
    });
  }

  // Stale evidence issue
  const staleEvidence = node.evidence?.filter((e) => e.isStale) || [];
  if (staleEvidence.length > 0) {
    issues.push({
      id: `issue-${node.id}-stale`,
      nodeId: node.id,
      nodeName: node.label,
      type: 'stale_citation',
      severity: 'warning',
      valueAtRisk: (node.value || 0) * 0.1, // Partial risk
      suggestedAction: 'Refresh stale citations',
    });
  }

  return issues;
}

/**
 * Format defensibility score as percentage
 */
export function formatDefensibilityScore(score: number): string {
  return `${Math.round(score * 100)}%`;
}

/**
 * Get color code for defensibility score
 */
export function getDefensibilityColor(score: number): 'green' | 'amber' | 'red' {
  if (score >= 0.9) return 'green';
  if (score >= 0.7) return 'amber';
  return 'red';
}

/**
 * State Gating Utilities - Workflow state-based action permissions
 */

import { GatingRules, WorkflowState } from '../types/workflow.types';

/**
 * Matrix defining which actions are allowed in each workflow state
 */
export const GATING_MATRIX: Record<WorkflowState, GatingRules> = {
  INITIATED: {
    allowEdit: true,
    allowRedTeam: false,
    allowApproval: false,
    reason: 'Complete hypothesis generation first',
  },
  DRAFTING: {
    allowEdit: true,
    allowRedTeam: true,
    allowApproval: false,
    reason: 'Validate model before approval',
  },
  VALIDATING: {
    allowEdit: true,
    allowRedTeam: true,
    allowApproval: true,
  },
  COMPOSING: {
    allowEdit: false,
    allowRedTeam: false,
    allowApproval: true,
    reason: 'Narrative generation in progress',
  },
  REFINING: {
    allowEdit: true,
    allowRedTeam: true,
    allowApproval: true,
  },
  FINALIZED: {
    allowEdit: false,
    allowRedTeam: false,
    allowApproval: false,
    reason: 'Version is locked. Request override to edit.',
  },
};

/**
 * Get gating rules for a specific workflow state
 */
export function getGatingRules(phase: WorkflowState): GatingRules {
  return GATING_MATRIX[phase];
}

/**
 * Check if editing is allowed in the given state
 */
export function canEdit(phase: WorkflowState): boolean {
  return GATING_MATRIX[phase].allowEdit;
}

/**
 * Check if red team actions are allowed in the given state
 */
export function canRedTeam(phase: WorkflowState): boolean {
  return GATING_MATRIX[phase].allowRedTeam;
}

/**
 * Check if approval is allowed in the given state
 */
export function canApprove(phase: WorkflowState): boolean {
  return GATING_MATRIX[phase].allowApproval;
}

/**
 * Get the reason why an action is disabled
 */
export function getDisabledReason(phase: WorkflowState): string | undefined {
  return GATING_MATRIX[phase].reason;
}

/**
 * Validate if a state transition is allowed
 */
export function isValidTransition(from: WorkflowState, to: WorkflowState): boolean {
  const validTransitions: Record<WorkflowState, WorkflowState[]> = {
    INITIATED: ['DRAFTING'],
    DRAFTING: ['VALIDATING', 'INITIATED'],
    VALIDATING: ['COMPOSING', 'DRAFTING', 'REFINING'],
    COMPOSING: ['REFINING', 'VALIDATING'],
    REFINING: ['FINALIZED', 'VALIDATING', 'DRAFTING'],
    FINALIZED: ['REFINING'], // Override only
  };

  return validTransitions[from].includes(to);
}

/**
 * Get list of valid next states from current state
 */
export function getValidNextStates(from: WorkflowState): WorkflowState[] {
  const validTransitions: Record<WorkflowState, WorkflowState[]> = {
    INITIATED: ['DRAFTING'],
    DRAFTING: ['VALIDATING', 'INITIATED'],
    VALIDATING: ['COMPOSING', 'DRAFTING', 'REFINING'],
    COMPOSING: ['REFINING', 'VALIDATING'],
    REFINING: ['FINALIZED', 'VALIDATING', 'DRAFTING'],
    FINALIZED: ['REFINING'],
  };

  return validTransitions[from];
}

/**
 * OnboardingWizard — orchestrates full onboarding flow:
 *   Phase A: Org + role setup (delegates to SetupWizard)
 *   Phase B: Invite team members
 *   Phase C: Create first value case (optional, skippable)
 */

import { ChevronRight, Loader2, Mail, Plus, X } from "lucide-react";
import { useState } from "react";

import { type SetupData, SetupWizard } from "./SetupWizard";

import { apiClient } from "@/api/client/unified-api-client";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";

export interface OnboardingWizardProps {
  onComplete?: () => void;
  onSkip?: () => void;
}

type Phase = "setup" | "invite" | "first-case";

export function OnboardingWizard({ onComplete, onSkip }: OnboardingWizardProps) {
  const [phase, setPhase] = useState<Phase>("setup");
  const [setupData, setSetupData] = useState<SetupData | null>(null);
  const [inviteEmails, setInviteEmails] = useState<string[]>([]);
  const [emailInput, setEmailInput] = useState("");
  const [caseName, setCaseName] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSetupComplete = (data: SetupData) => {
    setSetupData(data);
    setPhase("invite");
  };

  const addEmail = () => {
    const trimmed = emailInput.trim();
    if (trimmed && !inviteEmails.includes(trimmed)) {
      setInviteEmails((prev) => [...prev, trimmed]);
    }
    setEmailInput("");
  };

  const removeEmail = (email: string) => {
    setInviteEmails((prev) => prev.filter((e) => e !== email));
  };

  const handleInviteSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (inviteEmails.length > 0) {
        await Promise.allSettled(
          inviteEmails.map((email) =>
            apiClient.post("/api/teams/current/invites", { email, role: "member" }),
          ),
        );
      }
    } finally {
      setIsSubmitting(false);
      setPhase("first-case");
    }
  };

  const handleCreateCase = async () => {
    if (!caseName.trim()) {
      onComplete?.();
      return;
    }
    setIsSubmitting(true);
    try {
      await apiClient.post("/api/cases", {
        name: caseName.trim(),
        company: setupData?.companyName,
      });
    } finally {
      setIsSubmitting(false);
      onComplete?.();
    }
  };

  if (phase === "setup") {
    return <SetupWizard onComplete={handleSetupComplete} />;
  }

  if (phase === "invite") {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-background">
        <Card className="w-full max-w-xl">
          <CardContent className="p-8 space-y-6">
            <div className="space-y-2">
              <p className="text-sm text-muted-foreground">Invite your team</p>
              <h1 className="text-2xl font-semibold">Who should join you?</h1>
              <p className="text-sm text-muted-foreground">
                Add teammates by email. They'll get an invite to your workspace.
              </p>
            </div>

            <div className="flex gap-2">
              <Input
                value={emailInput}
                onChange={(e) => setEmailInput(e.target.value)}
                placeholder="colleague@company.com"
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    addEmail();
                  }
                }}
              />
              <Button variant="outline" size="sm" onClick={addEmail} disabled={!emailInput.trim()}>
                <Plus className="h-4 w-4" />
              </Button>
            </div>

            {inviteEmails.length > 0 && (
              <div className="space-y-2">
                {inviteEmails.map((email) => (
                  <div
                    key={email}
                    className="flex items-center justify-between px-3 py-2 bg-muted/50 rounded-md text-sm"
                  >
                    <span className="flex items-center gap-2">
                      <Mail className="h-3.5 w-3.5 text-muted-foreground" />
                      {email}
                    </span>
                    <button onClick={() => removeEmail(email)} className="text-muted-foreground hover:text-foreground">
                      <X className="h-3.5 w-3.5" />
                    </button>
                  </div>
                ))}
              </div>
            )}

            <div className="flex items-center justify-end gap-3">
              <Button variant="ghost" onClick={() => setPhase("first-case")}>
                Skip
              </Button>
              <Button onClick={handleInviteSubmit} disabled={isSubmitting}>
                {isSubmitting && <Loader2 className="h-4 w-4 mr-1 animate-spin" />}
                {inviteEmails.length > 0 ? "Send Invites" : "Continue"}
                <ChevronRight className="h-4 w-4 ml-1" />
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-background">
      <Card className="w-full max-w-xl">
        <CardContent className="p-8 space-y-6">
          <div className="space-y-2">
            <p className="text-sm text-muted-foreground">Almost done</p>
            <h1 className="text-2xl font-semibold">Create your first Value Case</h1>
            <p className="text-sm text-muted-foreground">
              Give it a name to get started, or skip and create one later.
            </p>
          </div>

          <Input
            value={caseName}
            onChange={(e) => setCaseName(e.target.value)}
            placeholder="e.g. Enterprise License Expansion – Acme Corp"
            autoFocus
          />

          <div className="flex items-center justify-end gap-3">
            <Button variant="ghost" onClick={onSkip ?? onComplete}>
              Skip
            </Button>
            <Button onClick={handleCreateCase} disabled={isSubmitting}>
              {isSubmitting && <Loader2 className="h-4 w-4 mr-1 animate-spin" />}
              {caseName.trim() ? "Create & Continue" : "Finish Setup"}
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { Briefcase, ChevronLeft, ChevronRight, Target, TrendingUp } from "lucide-react";
import { useState } from "react";

import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";

export interface SetupData {
  companyName: string;
  role: "build-cases" | "close-deals" | "prove-value" | null;
}

interface SetupWizardProps {
  onComplete: (data: SetupData) => void;
  initialData?: Partial<SetupData>;
}

const TOTAL_STEPS = 3;

const ROLE_OPTIONS = [
  {
    id: "build-cases" as const,
    icon: Briefcase,
    title: "Build Cases",
    description: "Pre-sales, consulting",
  },
  {
    id: "close-deals" as const,
    icon: Target,
    title: "Close Deals",
    description: "Account executive",
  },
  {
    id: "prove-value" as const,
    icon: TrendingUp,
    title: "Prove Value",
    description: "Customer success",
  },
];

export function SetupWizard({ onComplete, initialData }: SetupWizardProps) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState<SetupData>({
    companyName: initialData?.companyName ?? "",
    role: initialData?.role ?? null,
  });

  const canContinue = () => {
    switch (step) {
      case 1:
        return data.companyName.trim().length > 0;
      case 2:
        return data.role !== null;
      case 3:
        return true;
      default:
        return false;
    }
  };

  const handleContinue = () => {
    if (step < TOTAL_STEPS) {
      setStep(step + 1);
    } else {
      onComplete(data);
    }
  };

  const handleBack = () => {
    if (step > 1) {
      setStep(step - 1);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-background">
      <Card className="w-full max-w-xl">
        <CardContent className="p-8">
          {step === 1 && (
            <Step1Organization
              companyName={data.companyName}
              onChange={(name) => setData({ ...data, companyName: name })}
            />
          )}

          {step === 2 && (
            <Step2Role
              selectedRole={data.role}
              onChange={(role) => setData({ ...data, role })}
            />
          )}

          {step === 3 && (
            <Step3Confirmation data={data} />
          )}

          {/* Navigation */}
          <div className="flex items-center justify-end gap-3 mt-8">
            {step > 1 && (
              <Button variant="ghost" onClick={handleBack}>
                <ChevronLeft className="h-4 w-4 mr-1" />
                Back
              </Button>
            )}
            <Button onClick={handleContinue} disabled={!canContinue()}>
              {step === TOTAL_STEPS ? "Get Started" : "Continue"}
              {step < TOTAL_STEPS && <ChevronRight className="h-4 w-4 ml-1" />}
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Step indicators */}
      <div className="flex items-center gap-2 mt-6">
        {Array.from({ length: TOTAL_STEPS }).map((_, i) => (
          <div
            key={i}
            className={cn(
              "w-2 h-2 rounded-full transition-colors",
              i + 1 === step ? "bg-primary" : "bg-muted-foreground/30"
            )}
          />
        ))}
      </div>
    </div>
  );
}

interface Step1Props {
  companyName: string;
  onChange: (name: string) => void;
}

function Step1Organization({ companyName, onChange }: Step1Props) {
  return (
    <div className="space-y-6">
      <div className="space-y-2">
        <p className="text-sm text-muted-foreground">Step 1 of 3</p>
        <h1 className="text-2xl font-semibold">What's your company name?</h1>
      </div>

      <Input
        value={companyName}
        onChange={(e) => onChange(e.target.value)}
        placeholder="Acme Corporation"
        inputSize="lg"
        autoFocus
      />

      <p className="text-sm text-muted-foreground">
        This helps us personalize your experience and organize your team's work.
      </p>
    </div>
  );
}

interface Step2Props {
  selectedRole: SetupData["role"];
  onChange: (role: SetupData["role"]) => void;
}

function Step2Role({ selectedRole, onChange }: Step2Props) {
  return (
    <div className="space-y-6">
      <div className="space-y-2">
        <p className="text-sm text-muted-foreground">Step 2 of 3</p>
        <h1 className="text-2xl font-semibold">What's your primary role?</h1>
      </div>

      <div className="grid grid-cols-3 gap-4">
        {ROLE_OPTIONS.map((option) => {
          const Icon = option.icon;
          const isSelected = selectedRole === option.id;

          return (
            <button
              key={option.id}
              onClick={() => onChange(option.id)}
              className={cn(
                "flex flex-col items-center p-4 rounded-lg border-2 transition-all text-center",
                "hover:border-primary/50 hover:bg-primary/5",
                isSelected
                  ? "border-primary bg-primary/10"
                  : "border-border bg-background"
              )}
            >
              <div
                className={cn(
                  "w-12 h-12 rounded-full flex items-center justify-center mb-3",
                  isSelected ? "bg-primary text-primary-foreground" : "bg-muted"
                )}
              >
                <Icon className="h-6 w-6" />
              </div>
              <p className="font-medium text-sm">{option.title}</p>
              <p className="text-xs text-muted-foreground mt-1">
                {option.description}
              </p>
            </button>
          );
        })}
      </div>
    </div>
  );
}

interface Step3Props {
  data: SetupData;
}

function Step3Confirmation({ data }: Step3Props) {
  const roleLabel = ROLE_OPTIONS.find((r) => r.id === data.role)?.title ?? "";

  return (
    <div className="space-y-6">
      <div className="space-y-2">
        <p className="text-sm text-muted-foreground">Step 3 of 3</p>
        <h1 className="text-2xl font-semibold">You're all set!</h1>
      </div>

      <div className="space-y-4 p-4 bg-muted/50 rounded-lg">
        <div>
          <p className="text-sm text-muted-foreground">Company</p>
          <p className="font-medium">{data.companyName}</p>
        </div>
        <div>
          <p className="text-sm text-muted-foreground">Role</p>
          <p className="font-medium">{roleLabel}</p>
        </div>
      </div>

      <p className="text-sm text-muted-foreground">
        We'll customize your workspace based on your role. You can change these settings anytime.
      </p>
    </div>
  );
}

