  loading?: boolean;
  variant?: 'default' | 'primary' | 'accent';
}

function ToolbarButton({
  icon: Icon,
  label,
  onClick,
  disabled = false,
  loading = false,
  variant = 'default',
}: ToolbarButtonProps) {
  const variants = {
    default: 'text-slate-400 hover:text-white hover:bg-slate-700/50',
