          : "bg-white border-slate-200 hover:border-slate-300"
      )}
    >
      <Icon className={cn("w-5 h-5 mb-2", selected ? "text-primary" : "text-slate-400")} />
      <div className={cn("text-sm font-medium", selected ? "text-primary" : "text-slate-700")}>
