// Helpers
function getExpirationLabel(option: ExpirationOption): string {
  switch (option) {
    case '24h':
      return 'in 24 hours';
    case '7d':
      return 'in 7 days';
    case '30d':
      return 'in 30 days';
  }
}

function getExpirationDays(option: ExpirationOption): number {
  switch (option) {
    case '24h':
      return 1;
    case '7d':
      return 7;
    case '30d':
      return 30;
  }
}

function getPermissionPreset(level: PermissionLevel): GuestPermissions {
  switch (level) {
    case 'edit':
      return {
        can_view: true,
        can_comment: true,
        can_edit: true,
      };
    case 'comment':
      return {
        can_view: true,
        can_comment: true,
        can_edit: false,
      };
    case 'view':
    default:
      return {
        can_view: true,
        can_comment: false,
        can_edit: false,
      };
  }
}

