/**
 * FE-022: Clarify State UI
 *
 * Displays the agent's clarification question with selectable options
 * and optional freeform input. Supports keyboard navigation.
 */

import { HelpCircle, Send, X } from "lucide-react";
import { useEffect, useRef, useState } from "react";

import type { ClarifyOption } from "../../agent/types";

import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { cn } from "@/lib/utils";


interface ClarifyPanelProps {
  question: string;
  options: ClarifyOption[];
  defaultOption?: string;
  allowFreeform: boolean;
  onSelectOption: (optionId: string) => void;
  onSubmitFreeform: (text: string) => void;
  onCancel: () => void;
}

export function ClarifyPanel({
  question,
  options,
  defaultOption,
  allowFreeform,
  onSelectOption,
  onSubmitFreeform,
  onCancel,
}: ClarifyPanelProps) {
  const [selectedId, setSelectedId] = useState<string | null>(defaultOption ?? null);
  const [freeformText, setFreeformText] = useState("");
  const [showFreeform, setShowFreeform] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (showFreeform) inputRef.current?.focus();
  }, [showFreeform]);

  const handleSubmit = () => {
    if (showFreeform && freeformText.trim()) {
      onSubmitFreeform(freeformText.trim());
    } else if (selectedId) {
      onSelectOption(selectedId);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && (selectedId || freeformText.trim())) {
      handleSubmit();
    }
  };

  return (
    <Card className="border-blue-200 bg-white shadow-sm overflow-hidden">
      {/* Header */}
      <div className="px-4 py-3 bg-blue-50/50 border-b border-blue-100 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <HelpCircle size={16} className="text-blue-600" />
          <span className="text-xs font-semibold text-blue-700 uppercase tracking-wide">
            Clarification Needed
          </span>
        </div>
        <button
          onClick={onCancel}
          className="p-1 text-slate-400 hover:text-slate-600 rounded"
          aria-label="Cancel"
        >
          <X size={14} />
        </button>
      </div>

      {/* Question */}
      <div className="p-4">
        <p className="text-sm text-slate-700 leading-relaxed">{question}</p>
      </div>

      {/* Options */}
      {options.length > 0 && (
        <div className="px-4 pb-3 space-y-2" onKeyDown={handleKeyDown}>
          {options.map((option) => (
            <button
              key={option.id}
              onClick={() => {
                setSelectedId(option.id);
                setShowFreeform(false);
                onSelectOption(option.id);
              }}
              className={cn(
                "w-full text-left px-3 py-2.5 rounded-lg border transition-all",
                "hover:border-blue-300 hover:bg-blue-50/50",
                selectedId === option.id
                  ? "border-blue-400 bg-blue-50 ring-1 ring-blue-200"
                  : "border-slate-200 bg-white"
              )}
            >
              <div className="flex items-start gap-2">
                <div
                  className={cn(
                    "w-4 h-4 rounded-full border-2 mt-0.5 shrink-0 transition-colors",
                    selectedId === option.id
                      ? "border-blue-500 bg-blue-500"
                      : "border-slate-300"
                  )}
                >
                  {selectedId === option.id && (
                    <div className="w-full h-full flex items-center justify-center">
                      <div className="w-1.5 h-1.5 rounded-full bg-white" />
                    </div>
                  )}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-slate-800">{option.label}</p>
                  {option.description && (
                    <p className="text-xs text-slate-500 mt-0.5">{option.description}</p>
                  )}
                </div>
              </div>
            </button>
          ))}
        </div>
      )}

      {/* Freeform input */}
      {allowFreeform && (
        <div className="px-4 pb-3">
          {!showFreeform ? (
            <button
              onClick={() => {
                setShowFreeform(true);
                setSelectedId(null);
              }}
              className="text-xs text-blue-600 hover:text-blue-700 font-medium"
            >
              Or type your own answer...
            </button>
          ) : (
            <div className="flex items-center gap-2">
              <input
                ref={inputRef}
                type="text"
                value={freeformText}
                onChange={(e) => setFreeformText(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter" && freeformText.trim()) {
                    onSubmitFreeform(freeformText.trim());
                  }
                }}
                placeholder="Type your answer..."
                className="flex-1 text-sm border border-slate-200 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300"
              />
              <Button
                size="sm"
                disabled={!freeformText.trim()}
                onClick={() => onSubmitFreeform(freeformText.trim())}
              >
                <Send size={14} />
              </Button>
            </div>
          )}
        </div>
      )}
    </Card>
  );
}

/**
 * FE-028: Error Recovery Modal
 *
 * Overlay modal for the error state. Shows error details,
 * recovery suggestions, and retry/dismiss actions.
 * Recoverable errors allow retrying from the previous state.
 */

import {
  AlertTriangle,
  ArrowLeft,
  ChevronDown,
  Copy,
  RefreshCw,
} from "lucide-react";
import { useEffect, useRef, useState } from "react";

import type { AgentPhase } from "../../agent/types";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

interface ErrorRecoveryModalProps {
  code: string;
  message: string;
  recoverable: boolean;
  suggestions?: string[];
  previousPhase: AgentPhase | null;
  onRetry: () => void;
  onDismiss: () => void;
  /** API request ID for support correlation. Shown in the error details panel. */
  requestId?: string;
}

const PHASE_LABELS: Record<AgentPhase, string> = {
  idle: "Ready",
  plan: "Planning",
  execute: "Execution",
  clarify: "Clarification",
  review: "Review",
  finalize: "Finalization",
  error: "Error",
  resume: "Resume",
};

export function ErrorRecoveryModal({
  code,
  message,
  recoverable,
  suggestions,
  previousPhase,
  onRetry,
  onDismiss,
  requestId,
}: ErrorRecoveryModalProps) {
  const [showDetails, setShowDetails] = useState(false);
  const [copied, setCopied] = useState(false);
  const copiedTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Clear any pending reset timer on unmount to avoid state updates on an
  // unmounted component (e.g. modal dismissed while "Copied" is showing).
  useEffect(() => {
    return () => {
      if (copiedTimerRef.current !== null) {
        clearTimeout(copiedTimerRef.current);
      }
    };
  }, []);

  const handleCopyError = () => {
    const lines = [`Error: ${code}`, message];
    if (requestId) lines.push(`Request ID: ${requestId}`);
    const text = lines.join("\n");

    if (typeof navigator === "undefined" || !navigator.clipboard) {
      window.prompt("Copy this error details:", text);
      return;
    }

    navigator.clipboard.writeText(text).then(
      () => {
        setCopied(true);
        if (copiedTimerRef.current !== null) clearTimeout(copiedTimerRef.current);
        copiedTimerRef.current = setTimeout(() => {
          copiedTimerRef.current = null;
          setCopied(false);
        }, 2000);
      },
      () => {
        // Clipboard permission denied — surface via prompt so user can copy manually.
        window.prompt("Copy this error details:", text);
      },
    );
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/40 backdrop-blur-sm"
        onClick={onDismiss}
      />

      {/* Modal */}
      <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-md mx-4 overflow-hidden">
        {/* Red accent bar */}
        <div className="h-1 bg-red-500" />

        {/* Content */}
        <div className="p-6">
          {/* Icon + title */}
          <div className="flex items-start gap-4 mb-4">
            <div className="w-10 h-10 rounded-full bg-red-100 flex items-center justify-center shrink-0">
              <AlertTriangle size={20} className="text-red-600" />
            </div>
            <div className="flex-1 min-w-0">
              <h3 className="text-base font-semibold text-slate-900">
                {recoverable ? "Something went wrong" : "Operation failed"}
              </h3>
              <p className="text-sm text-slate-600 mt-1 leading-relaxed">
                {message}
              </p>
            </div>
          </div>

          {/* Context: where the error occurred */}
          {previousPhase && previousPhase !== "idle" && (
            <div className="mb-4 px-3 py-2 bg-slate-50 rounded-lg text-xs text-slate-500">
              Error occurred during{" "}
              <span className="font-medium text-slate-700">
                {PHASE_LABELS[previousPhase]}
              </span>{" "}
              phase
            </div>
          )}

          {/* Suggestions */}
          {suggestions && suggestions.length > 0 && (
            <div className="mb-4">
              <p className="text-xs font-medium text-slate-500 mb-2">
                Suggested actions:
              </p>
              <ul className="space-y-1.5">
                {suggestions.map((suggestion, i) => (
                  <li
                    key={i}
                    className="flex items-start gap-2 text-sm text-slate-600"
                  >
                    <span className="text-slate-400 mt-0.5">•</span>
                    {suggestion}
                  </li>
                ))}
              </ul>
            </div>
          )}

          {/* Error details (collapsible) */}
          <button
            onClick={() => setShowDetails(!showDetails)}
            className="flex items-center gap-1 text-xs text-slate-400 hover:text-slate-600 mb-4"
          >
            <ChevronDown
              size={12}
              className={cn("transition-transform", showDetails && "rotate-180")}
            />
            Technical details
          </button>

          {showDetails && (
            <div className="mb-4 bg-slate-900 rounded-lg p-3 relative">
              <pre className="text-xs text-slate-300 font-mono whitespace-pre-wrap break-all">
                {`Code: ${code}\n${message}`}
              </pre>
              {requestId && (
                <div className="mt-2 pt-2 border-t border-slate-700">
                  <p className="text-[10px] text-slate-500 mb-1">Request ID</p>
                  <code className="text-xs text-slate-300 font-mono select-all break-all">
                    {requestId}
                  </code>
                  <p className="text-[10px] text-slate-500 mt-1">
                    Include this ID when contacting support.
                  </p>
                </div>
              )}
              <button
                onClick={handleCopyError}
                className="absolute top-2 right-2 p-1 text-slate-500 hover:text-slate-300 rounded"
                aria-label="Copy error details"
              >
                <Copy size={12} />
              </button>
              {copied && (
                <span className="absolute top-2 right-8 text-[10px] text-emerald-400">
                  Copied
                </span>
              )}
            </div>
          )}
        </div>

        {/* Actions */}
        <div className="px-6 py-4 border-t border-slate-100 flex gap-3">
          <Button
            variant="outline"
            onClick={onDismiss}
            className="flex-1"
          >
            <ArrowLeft size={14} className="mr-1.5" />
            {recoverable ? "Go Back" : "Dismiss"}
          </Button>
          {recoverable && (
            <Button
              onClick={onRetry}
              className="flex-1"
            >
              <RefreshCw size={14} className="mr-1.5" />
              Retry
            </Button>
          )}
        </div>
      </div>
    </div>
  );
}

/**
 * FE-019: Plan State UI — Approval Gate
 *
 * Displays the agent's proposed execution plan with numbered steps,
 * editable assumptions, estimated duration, and approve/reject actions.
 */

import {
  CheckCircle2,
  ChevronDown,
  ChevronUp,
  Circle,
  Clock,
  Edit3,
  ShieldCheck,
} from "lucide-react";
import { useState } from "react";

import type { PlanAssumption, WorkflowStepState } from "../../agent/types";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";


interface PlanApprovalGateProps {
  steps: WorkflowStepState[];
  assumptions: PlanAssumption[];
  estimatedDuration?: number;
  onApprove: () => void;
  onReject: () => void;
  onUpdateAssumption: (id: string, value: string | number) => void;
}

export function PlanApprovalGate({
  steps,
  assumptions,
  estimatedDuration,
  onApprove,
  onReject,
  onUpdateAssumption,
}: PlanApprovalGateProps) {
  const [showAssumptions, setShowAssumptions] = useState(assumptions.length > 0);
  const [editingId, setEditingId] = useState<string | null>(null);

  const formatDuration = (ms: number) => {
    if (ms < 60_000) return `~${Math.ceil(ms / 1000)}s`;
    return `~${Math.ceil(ms / 60_000)} min`;
  };

  return (
    <Card className="border-amber-200 bg-white shadow-sm overflow-hidden">
      {/* Header */}
      <div className="px-4 py-3 bg-amber-50/50 border-b border-amber-100 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <ShieldCheck size={16} className="text-amber-600" />
          <span className="text-xs font-semibold text-amber-700 uppercase tracking-wide">
            Proposed Plan
          </span>
        </div>
        <div className="flex items-center gap-2">
          {estimatedDuration && (
            <Badge variant="outline" className="text-xs text-slate-500 border-slate-200">
              <Clock size={12} className="mr-1" />
              {formatDuration(estimatedDuration)}
            </Badge>
          )}
          <Badge className="bg-amber-100 text-amber-700 border-amber-200 text-xs">
            Awaiting Approval
          </Badge>
        </div>
      </div>

      {/* Steps */}
      <div className="p-4">
        <div className="space-y-1">
          {steps.map((step, index) => (
            <div
              key={step.id}
              className="flex items-start gap-3 py-2 group"
            >
              {/* Step number / connector */}
              <div className="flex flex-col items-center">
                <div className="w-6 h-6 rounded-full bg-slate-100 border border-slate-200 flex items-center justify-center text-xs font-medium text-slate-600">
                  {index + 1}
                </div>
                {index < steps.length - 1 && (
                  <div className="w-px h-4 bg-slate-200 mt-1" />
                )}
              </div>

              {/* Step content */}
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-slate-800">{step.label}</p>
                {step.error && (
                  <p className="text-xs text-red-500 mt-0.5">{step.error}</p>
                )}
              </div>

              {/* Step status icon */}
              <div className="w-5 flex justify-center pt-0.5">
                {step.status === "completed" ? (
                  <CheckCircle2 size={14} className="text-emerald-500" />
                ) : (
                  <Circle size={14} className="text-slate-300" />
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Assumptions (collapsible) */}
      {assumptions.length > 0 && (
        <div className="border-t border-slate-100">
          <button
            onClick={() => setShowAssumptions(!showAssumptions)}
            className="w-full px-4 py-2.5 flex items-center justify-between text-xs font-medium text-slate-500 hover:bg-slate-50 transition-colors"
          >
            <span>Assumptions ({assumptions.length})</span>
            {showAssumptions ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
          </button>

          {showAssumptions && (
            <div className="px-4 pb-3 space-y-2">
              {assumptions.map((asm) => (
                <div
                  key={asm.id}
                  className="flex items-center justify-between py-1.5 px-2 rounded-md hover:bg-slate-50 group/asm"
                >
                  <span className="text-sm text-slate-600">{asm.label}</span>
                  <div className="flex items-center gap-1.5">
                    {editingId === asm.id && asm.editable ? (
                      <input
                        type="text"
                        defaultValue={String(asm.value)}
                        autoFocus
                        onBlur={(e) => {
                          const val = e.target.value;
                          const num = Number(val);
                          onUpdateAssumption(asm.id, isNaN(num) ? val : num);
                          setEditingId(null);
                        }}
                        onKeyDown={(e) => {
                          if (e.key === "Enter") (e.target as HTMLInputElement).blur();
                          if (e.key === "Escape") setEditingId(null);
                        }}
                        className="w-24 text-right text-sm font-medium text-slate-800 border border-primary/30 rounded px-1.5 py-0.5 focus:outline-none focus:ring-1 focus:ring-primary"
                      />
                    ) : (
                      <>
                        <span className="text-sm font-medium text-slate-800">
                          {asm.value}
                        </span>
                        {asm.editable && (
                          <button
                            onClick={() => setEditingId(asm.id)}
                            className="opacity-0 group-hover/asm:opacity-100 p-0.5 text-slate-400 hover:text-primary transition-opacity"
                            aria-label={`Edit ${asm.label}`}
                          >
                            <Edit3 size={12} />
                          </button>
                        )}
                      </>
                    )}
                    {asm.source && (
                      <span className="text-[10px] text-slate-400 ml-1">{asm.source}</span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Actions */}
      <div className="px-4 py-3 border-t border-slate-100 flex gap-2">
        <Button
          variant="outline"
          size="sm"
          onClick={onReject}
          className="flex-1"
        >
          Reject
        </Button>
        <Button
          size="sm"
          onClick={onApprove}
          className="flex-1 bg-emerald-600 hover:bg-emerald-700"
        >
          Approve & Execute
        </Button>
      </div>
    </Card>
  );
}

/**
 * FE-026: Review State UI — Diff View
 *
 * Presents proposed artifacts for user review with approve/reject per artifact.
 * Shows a summary of changes and tracks review progress.
 */

import {
  BarChart3,
  BookOpen,
  CheckCircle2,
  ChevronRight,
  Eye,
  FileText,
  Table2,
  XCircle,
} from "lucide-react";
import { useState } from "react";

import type { Artifact, ArtifactType } from "../../agent/types";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { cn } from "@/lib/utils";


interface ReviewDiffPanelProps {
  artifacts: Artifact[];
  activeArtifactId: string | null;
  onSelectArtifact: (id: string) => void;
  onApproveArtifact: (id: string) => void;
  onRejectArtifact: (id: string) => void;
  onApproveAll: () => void;
  onCancel: () => void;
}

const ARTIFACT_ICONS: Partial<Record<ArtifactType, React.ReactNode>> = {
  value_model: <BarChart3 size={14} />,
  financial_projection: <BarChart3 size={14} />,
  executive_summary: <BookOpen size={14} />,
  table: <Table2 size={14} />,
  narrative: <BookOpen size={14} />,
  chart: <BarChart3 size={14} />,
};

const STATUS_CONFIG = {
  proposed: { label: "Pending", className: "bg-amber-100 text-amber-700 border-amber-200" },
  draft: { label: "Draft", className: "bg-slate-100 text-slate-600 border-slate-200" },
  approved: { label: "Approved", className: "bg-emerald-100 text-emerald-700 border-emerald-200" },
  rejected: { label: "Rejected", className: "bg-red-100 text-red-700 border-red-200" },
  superseded: { label: "Superseded", className: "bg-slate-100 text-slate-500 border-slate-200" },
} as const;

export function ReviewDiffPanel({
  artifacts,
  activeArtifactId,
  onSelectArtifact,
  onApproveArtifact,
  onRejectArtifact,
  onApproveAll,
  onCancel,
}: ReviewDiffPanelProps) {
  const reviewable = artifacts.filter((a) => a.status === "proposed" || a.status === "draft");
  const reviewed = artifacts.filter((a) => a.status === "approved" || a.status === "rejected");
  const allReviewed = reviewable.length === 0 && reviewed.length > 0;
  const approvedCount = artifacts.filter((a) => a.status === "approved").length;

  return (
    <Card className="border-emerald-200 bg-white shadow-sm overflow-hidden">
      {/* Header */}
      <div className="px-4 py-3 bg-emerald-50/50 border-b border-emerald-100 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Eye size={16} className="text-emerald-600" />
          <span className="text-xs font-semibold text-emerald-700 uppercase tracking-wide">
            Review Artifacts
          </span>
        </div>
        <span className="text-xs text-slate-500">
          {approvedCount}/{artifacts.length} approved
        </span>
      </div>

      {/* Progress bar */}
      <div className="w-full h-1 bg-emerald-100">
        <div
          className="h-full bg-emerald-500 transition-all duration-500"
          style={{ width: `${artifacts.length > 0 ? (reviewed.length / artifacts.length) * 100 : 0}%` }}
        />
      </div>

      {/* Artifact list */}
      <div className="p-2">
        {artifacts.map((artifact) => {
          const statusConfig = STATUS_CONFIG[artifact.status];
          const isActive = artifact.id === activeArtifactId;
          const isPending = artifact.status === "proposed" || artifact.status === "draft";

          return (
            <div
              key={artifact.id}
              className={cn(
                "rounded-lg border transition-all mb-1",
                isActive
                  ? "border-emerald-300 bg-emerald-50/50 shadow-sm"
                  : "border-transparent hover:bg-slate-50"
              )}
            >
              {/* Artifact row */}
              <button
                onClick={() => onSelectArtifact(artifact.id)}
                className="w-full px-3 py-2.5 flex items-center gap-3 text-left"
              >
                <div className="w-8 h-8 rounded-lg bg-slate-100 flex items-center justify-center text-slate-500 shrink-0">
                  {ARTIFACT_ICONS[artifact.type] ?? <FileText size={14} />}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-slate-800 truncate">
                    {artifact.title}
                  </p>
                  <p className="text-[10px] text-slate-400 capitalize">
                    {artifact.type.replace(/_/g, " ")}
                  </p>
                </div>
                <Badge className={cn("text-[10px] shrink-0", statusConfig.className)}>
                  {statusConfig.label}
                </Badge>
                <ChevronRight size={14} className="text-slate-300 shrink-0" />
              </button>

              {/* Inline approve/reject for active pending artifact */}
              {isActive && isPending && (
                <div className="px-3 pb-2.5 flex gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => onRejectArtifact(artifact.id)}
                    className="flex-1 text-red-600 border-red-200 hover:bg-red-50"
                  >
                    <XCircle size={14} className="mr-1" />
                    Reject
                  </Button>
                  <Button
                    size="sm"
                    onClick={() => onApproveArtifact(artifact.id)}
                    className="flex-1 bg-emerald-600 hover:bg-emerald-700"
                  >
                    <CheckCircle2 size={14} className="mr-1" />
                    Approve
                  </Button>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Footer actions */}
      <div className="px-4 py-3 border-t border-slate-100 flex gap-2">
        <Button variant="outline" size="sm" onClick={onCancel} className="flex-1">
          Cancel
        </Button>
        {reviewable.length > 0 ? (
          <Button
            size="sm"
            onClick={onApproveAll}
            className="flex-1 bg-emerald-600 hover:bg-emerald-700"
          >
            Approve All ({reviewable.length})
          </Button>
        ) : allReviewed ? (
          <Button
            size="sm"
            onClick={onApproveAll}
            className="flex-1 bg-emerald-600 hover:bg-emerald-700"
          >
            Finalize
          </Button>
        ) : null}
      </div>
    </Card>
  );
}

/**
 * PDF Export Service
 * 
 * Generates professional PDF proposals from artifacts.
 * Uses browser print API for simplicity and quality.
 */

