/**
 * Guest Permissions System
 *
 * Manages permission checks and access control for guest users
 */

import { logger } from "./lib/logger";

import { GuestPermissions } from "@/GuestAccessService";

// Permission action types
export enum PermissionAction {
  VIEW = "view",
  COMMENT = "comment",
  EDIT = "edit",
  EXPORT = "export",
  SHARE = "share",
}

// Resource types
export enum ResourceType {
  VALUE_CASE = "value_case",
  CANVAS_ELEMENT = "canvas_element",
  METRIC = "metric",
  COMMENT = "comment",
  BENCHMARK = "benchmark",
}

// Permission check result
export interface PermissionCheckResult {
  allowed: boolean;
  reason?: string;
}

class GuestPermissionManager {
  /**
   * Check if guest has permission for an action
   */
  public checkPermission(
    permissions: GuestPermissions,
    action: PermissionAction,
    resource: ResourceType
  ): PermissionCheckResult {
    // View permission
    if (action === PermissionAction.VIEW) {
      if (!permissions.can_view) {
        return {
          allowed: false,
          reason: "Guest does not have view permission",
        };
      }
      return { allowed: true };
    }

    // Comment permission
    if (action === PermissionAction.COMMENT) {
      if (!permissions.can_view) {
        return {
          allowed: false,
          reason: "Guest must have view permission to comment",
        };
      }
      if (!permissions.can_comment) {
        return {
          allowed: false,
          reason: "Guest does not have comment permission",
        };
      }
      return { allowed: true };
    }

    // Edit permission
    if (action === PermissionAction.EDIT) {
      if (!permissions.can_view) {
        return {
          allowed: false,
          reason: "Guest must have view permission to edit",
        };
      }
      if (!permissions.can_edit) {
        return {
          allowed: false,
          reason: "Guest does not have edit permission",
        };
      }
      return { allowed: true };
    }

    // Export permission (requires view)
    if (action === PermissionAction.EXPORT) {
      if (!permissions.can_view) {
        return {
          allowed: false,
          reason: "Guest must have view permission to export",
        };
      }
      return { allowed: true };
    }

    // Share permission (requires view)
    if (action === PermissionAction.SHARE) {
      if (!permissions.can_view) {
        return {
          allowed: false,
          reason: "Guest must have view permission to share",
        };
      }
      return { allowed: true };
    }

    return {
      allowed: false,
      reason: "Unknown permission action",
    };
  }

  /**
   * Check multiple permissions at once
   */
  public checkMultiplePermissions(
    permissions: GuestPermissions,
    checks: Array<{ action: PermissionAction; resource: ResourceType }>
  ): Record<string, PermissionCheckResult> {
    const results: Record<string, PermissionCheckResult> = {};

    checks.forEach(({ action, resource }) => {
      const key = `${action}:${resource}`;
      results[key] = this.checkPermission(permissions, action, resource);
    });

    return results;
  }

  /**
   * Get allowed actions for guest
   */
  public getAllowedActions(permissions: GuestPermissions): PermissionAction[] {
    const allowed: PermissionAction[] = [];

    if (permissions.can_view) {
      allowed.push(PermissionAction.VIEW);
      allowed.push(PermissionAction.EXPORT);
      allowed.push(PermissionAction.SHARE);
    }

    if (permissions.can_comment) {
      allowed.push(PermissionAction.COMMENT);
    }

    if (permissions.can_edit) {
      allowed.push(PermissionAction.EDIT);
    }

    return allowed;
  }

  /**
   * Get permission summary
   */
  public getPermissionSummary(permissions: GuestPermissions): {
    level: "view-only" | "comment" | "edit";
    description: string;
    actions: string[];
  } {
    if (permissions.can_edit) {
      return {
        level: "edit",
        description: "Can view, comment, and edit",
        actions: [
          "View all content",
          "Add comments",
          "Edit elements",
          "Export reports",
          "Share via email",
        ],
      };
    }

    if (permissions.can_comment) {
      return {
        level: "comment",
        description: "Can view and comment",
        actions: ["View all content", "Add comments", "Export reports", "Share via email"],
      };
    }

    return {
      level: "view-only",
      description: "Can only view",
      actions: ["View all content", "Export reports", "Share via email"],
    };
  }

  /**
   * Create permission preset
   */
  public createPermissionPreset(preset: "view-only" | "comment" | "edit"): GuestPermissions {
    switch (preset) {
      case "view-only":
        return {
          can_view: true,
          can_comment: false,
          can_edit: false,
        };

      case "comment":
        return {
          can_view: true,
          can_comment: true,
          can_edit: false,
        };

      case "edit":
        return {
          can_view: true,
          can_comment: true,
          can_edit: true,
        };

      default:
        return {
          can_view: true,
          can_comment: false,
          can_edit: false,
        };
    }
  }

  /**
   * Validate permissions object
   */
  public validatePermissions(permissions: unknown): permissions is GuestPermissions {
    if (typeof permissions !== "object" || permissions === null) {
      return false;
    }

    if (typeof permissions.can_view !== "boolean") {
      return false;
    }

    if (typeof permissions.can_comment !== "boolean") {
      return false;
    }

    if (typeof permissions.can_edit !== "boolean") {
      return false;
    }

    // Logical validation: can't comment or edit without view
    if (!permissions.can_view && (permissions.can_comment || permissions.can_edit)) {
      return false;
    }

    return true;
  }

  /**
   * Log permission check
   */
  public logPermissionCheck(
    guestUserId: string,
    action: PermissionAction,
    resource: ResourceType,
    result: PermissionCheckResult
  ): void {
    logger.debug("Guest permission check", {
      guestUserId,
      action,
      resource,
      allowed: result.allowed,
      reason: result.reason,
    });
  }
}

// Singleton instance
let permissionManagerInstance: GuestPermissionManager | null = null;

/**
 * Get permission manager instance
 */
export function getGuestPermissionManager(): GuestPermissionManager {
  if (!permissionManagerInstance) {
    permissionManagerInstance = new GuestPermissionManager();
  }
  return permissionManagerInstance;
}

/**
 * Helper function to check permission
 */
export function checkGuestPermission(
  permissions: GuestPermissions,
  action: PermissionAction,
  resource: ResourceType
): PermissionCheckResult {
  return getGuestPermissionManager().checkPermission(permissions, action, resource);
}

/**
 * Helper function to get allowed actions
 */
export function getGuestAllowedActions(permissions: GuestPermissions): PermissionAction[] {
  return getGuestPermissionManager().getAllowedActions(permissions);
}

/**
 * Helper function to create permission preset
 */
export function createGuestPermissionPreset(
  preset: "view-only" | "comment" | "edit"
): GuestPermissions {
  return getGuestPermissionManager().createPermissionPreset(preset);
}

// Export singleton instance getter
export default getGuestPermissionManager;

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";

import type {
  CompanyCapability,
  CompanyClaimGovernance,
  CompanyCompetitor,
  CompanyContext,
  CompanyPersona,
  CompanyProduct,
  CompanyValueContext,
  CompanyValuePattern,
  OnboardingPhase1Input,
  OnboardingPhase2Input,
  OnboardingPhase3Input,
  OnboardingPhase4Input,
} from "./types";

import { supabase } from "@/lib/supabase";

const QUERY_KEY = "company-context";

function getClient() {
  if (!supabase) throw new Error("Supabase client not initialized");
  return supabase;
}

// ---- Queries ----

export function useCompanyContext(tenantId: string | undefined) {
  return useQuery<CompanyValueContext | null>({
    queryKey: [QUERY_KEY, tenantId],
    enabled: !!tenantId,
    queryFn: async () => {
      const sb = getClient();

      // Fetch the root context
      const { data: context, error: ctxErr } = await sb
        .from("company_contexts")
        .select("*")
        .eq("tenant_id", tenantId!)
        .is("deleted_at", null)
        .maybeSingle();

      if (ctxErr) throw ctxErr;
      if (!context) return null;

      // Fetch all related data in parallel
      const [products, capabilities, competitors, personas, valuePatterns, claimGovernance] =
        await Promise.all([
          sb.from("company_products").select("*").eq("context_id", context.id).then((r) => r.data ?? []),
          sb.from("company_capabilities").select("*").eq("tenant_id", tenantId!).then((r) => r.data ?? []),
          sb.from("company_competitors").select("*").eq("context_id", context.id).then((r) => r.data ?? []),
          sb.from("company_personas").select("*").eq("context_id", context.id).then((r) => r.data ?? []),
          sb.from("company_value_patterns").select("*").eq("context_id", context.id).then((r) => r.data ?? []),
          sb.from("company_claim_governance").select("*").eq("context_id", context.id).then((r) => r.data ?? []),
        ]);

      return {
        context: context as CompanyContext,
        products: products as CompanyProduct[],
        capabilities: capabilities as CompanyCapability[],
        competitors: competitors as CompanyCompetitor[],
        personas: personas as CompanyPersona[],
        valuePatterns: valuePatterns as CompanyValuePattern[],
        claimGovernance: claimGovernance as CompanyClaimGovernance[],
      };
    },
  });
}

export function useOnboardingStatus(tenantId: string | undefined) {
  return useQuery<CompanyContext["onboarding_status"] | "none">({
    queryKey: [QUERY_KEY, "status", tenantId],
    enabled: !!tenantId,
    queryFn: async () => {
      const sb = getClient();
      const { data, error } = await sb
        .from("company_contexts")
        .select("onboarding_status")
        .eq("tenant_id", tenantId!)
        .is("deleted_at", null)
        .maybeSingle();

      if (error) throw error;
      if (!data) return "none";
      return data.onboarding_status as CompanyContext["onboarding_status"];
    },
  });
}

// ---- Mutations ----

export function useCreateCompanyContext(tenantId: string) {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: OnboardingPhase1Input) => {
      const sb = getClient();

      // Create root context
      const { data: context, error: ctxErr } = await sb
        .from("company_contexts")
        .insert({
          tenant_id: tenantId,
          company_name: input.company_name,
          website_url: input.website_url,
          industry: input.industry,
          company_size: input.company_size,
          sales_motion: input.sales_motion,
          onboarding_status: "in_progress",
        })
        .select()
        .single();

      if (ctxErr) throw ctxErr;

      // Create products
      if (input.products.length > 0) {
        const { error: prodErr } = await sb.from("company_products").insert(
          input.products.map((p) => ({
            tenant_id: tenantId,
            context_id: context.id,
            name: p.name,
            description: p.description,
            product_type: p.product_type,
          }))
        );
        if (prodErr) throw prodErr;
      }

      return context as CompanyContext;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [QUERY_KEY, tenantId] });
    },
  });
}

