export function useCompleteOnboarding(tenantId: string, contextId: string) {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async () => {
      const sb = getClient();

      // Fetch the full hydrated context for the snapshot
      const { data: context } = await sb
        .from("company_contexts")
        .select("*")
        .eq("id", contextId)
        .single();

      if (!context) throw new Error("Context not found");

      const [products, competitors, personas, claimGovernance, suggestions] = await Promise.all([
        sb.from("company_products").select("*").eq("context_id", contextId).then((r) => r.data ?? []),
        sb.from("company_competitors").select("*").eq("context_id", contextId).then((r) => r.data ?? []),
        sb.from("company_personas").select("*").eq("context_id", contextId).then((r) => r.data ?? []),
        sb.from("company_claim_governance").select("*").eq("context_id", contextId).then((r) => r.data ?? []),
        sb.from("company_research_suggestions").select("*").eq("context_id", contextId).eq("status", "accepted").then((r) => r.data ?? []),
      ]);

      const snapshot = {
        context,
        products,
        competitors,
        personas,
        claimGovernance,
        research_provenance: suggestions.map(s => ({
          entity_type: s.entity_type,
          entity_id: s.id, // suggestion id
          job_id: s.job_id,
          confidence_score: s.confidence_score,
          payload_hash: s.entity_hash
        }))
      };

      // Create version record
      await sb.from("company_context_versions").insert({
        context_id: contextId,
        tenant_id: tenantId,
        version: (context.version ?? 0) + 1,
        snapshot,
        change_reason: "Initial onboarding completed",
      });

      // Mark as completed
      const { error } = await sb
        .from("company_contexts")
        .update({
          onboarding_status: "completed",
          onboarding_completed_at: new Date().toISOString(),
          version: (context.version ?? 0) + 1,
        })
        .eq("id", contextId);

      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [QUERY_KEY, tenantId] });
    },
  });
}

/**
 * Research Job Hooks
 *
 * React Query hooks for the onboarding research job lifecycle.
 * All mutations go through the backend API (POST /api/onboarding/...)
 * so the BullMQ worker pipeline is triggered. Read queries still use
 * Supabase directly for real-time polling efficiency.
 */

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";

import type { ResearchJob, ResearchSuggestion, SuggestionEntityType } from "./types";

import { apiClient } from "@/api/client/unified-api-client";
import { supabase } from "@/lib/supabase";

const RESEARCH_KEY = "research-job";
const SUGGESTIONS_KEY = "research-suggestions";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function getClient() {
  if (!supabase) throw new Error("Supabase client not initialized");
  return supabase;
}

/**
 * Typed API wrapper for endpoints returning { data }.
 */
async function apiRequest<T>(path: string, init?: { method?: "GET" | "POST" | "PUT" | "DELETE" | "PATCH"; body?: unknown }): Promise<T> {
  const response = await apiClient.request<{ data: T }>({
    method: init?.method ?? "GET",
    url: path,
    data: init?.body,
  });

  if (!response.success) {
    throw new Error(response.error?.message ?? "Request failed");
  }

  if (!response.data) {
    throw new Error("No data returned from API");
  }

  return response.data.data;
}

// ---------------------------------------------------------------------------
// Create Research Job — goes through the backend API so BullMQ picks it up
// ---------------------------------------------------------------------------

export function useCreateResearchJob(tenantId: string) {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: {
      contextId: string;
      website: string;
      industry?: string;
      companySize?: string;
      salesMotion?: string;
    }) => {
      return apiRequest<ResearchJob>("/api/onboarding/research", {
        method: "POST",
        body: input,
      });
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [RESEARCH_KEY] });
    },
  });
}

// ---------------------------------------------------------------------------
// Poll Job Status — reads directly from Supabase for low-latency polling
// ---------------------------------------------------------------------------

export function useResearchJobStatus(jobId: string | null) {
  return useQuery<ResearchJob | null>({
    queryKey: [RESEARCH_KEY, jobId],
    enabled: !!jobId,
    refetchInterval: (query) => {
      const data = query.state.data;
      if (data && (data.status === "completed" || data.status === "failed")) {
        return false;
      }
      return 2000;
    },
    queryFn: async () => {
      const sb = getClient();

      const { data, error } = await sb
        .from("company_research_jobs")
        .select("*")
        .eq("id", jobId!)
        .single();

      if (error) throw error;
      return data as ResearchJob;
    },
  });
}

// ---------------------------------------------------------------------------
// List Suggestions
// ---------------------------------------------------------------------------

export function useResearchSuggestions(
  jobId: string | null,
  entityType?: SuggestionEntityType,
) {
  return useQuery<ResearchSuggestion[]>({
    queryKey: [SUGGESTIONS_KEY, jobId, entityType],
    enabled: !!jobId,
    queryFn: async () => {
      const sb = getClient();

      let query = sb
        .from("company_research_suggestions")
        .select("*")
        .eq("job_id", jobId!)
        .order("confidence_score", { ascending: false });

      if (entityType) {
        query = query.eq("entity_type", entityType);
      }

      const { data, error } = await query;
      if (error) throw error;
      return (data ?? []) as ResearchSuggestion[];
    },
  });
}

// ---------------------------------------------------------------------------
// Accept Suggestion — goes through backend API for transactional writes
// ---------------------------------------------------------------------------

export function useAcceptSuggestion(_tenantId: string) {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: {
      suggestionId: string;
      contextId: string;
      entityType: string;
      payload: Record<string, unknown>;
    }) => {
      return apiRequest<ResearchSuggestion>(`/api/onboarding/suggestions/${input.suggestionId}`, {
        method: "PATCH",
        body: { status: "accepted" },
      });
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [SUGGESTIONS_KEY] });
      qc.invalidateQueries({ queryKey: ["company-context"] });
    },
  });
}

// ---------------------------------------------------------------------------
// Reject Suggestion
// ---------------------------------------------------------------------------

export function useRejectSuggestion(_tenantId: string) {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (suggestionId: string) => {
      return apiRequest<ResearchSuggestion>(`/api/onboarding/suggestions/${suggestionId}`, {
        method: "PATCH",
        body: { status: "rejected" },
      });
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [SUGGESTIONS_KEY] });
    },
  });
}

// ---------------------------------------------------------------------------
// Bulk Accept
// ---------------------------------------------------------------------------

export function useBulkAcceptSuggestions(_tenantId: string) {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (
      suggestions: Array<{
        id: string;
        contextId: string;
        entityType: string;
        payload: Record<string, unknown>;
      }>,
    ) => {
      const ids = suggestions.map((s) => s.id);
      return apiRequest<{ results: Array<{ id: string; success: boolean }>; accepted: number; total: number }>(
        "/api/onboarding/suggestions/bulk-accept",
        { method: "POST", body: { ids } },
      );
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [SUGGESTIONS_KEY] });
      qc.invalidateQueries({ queryKey: ["company-context"] });
    },
  });
}

/**
 * Admin Permissions Hook
 *
 * Maps the current user's TenantRole to fine-grained AdminPermission set.
 * Used by AdminLayout and navigation to gate section visibility.
 *
 * See: docs/architecture/admin-settings-ia.md (Role Model Gap section)
 */

import { useMemo } from 'react';

import type { AdminPermission } from '../lib/adminNavigation';

type TenantRole = 'owner' | 'admin' | 'member' | 'viewer';

/**
 * Permission sets per role.
 *
 * This is the bridge between the coarse TenantRole system and the
 * fine-grained AdminPermission model required by the IA.
 *
 * When dedicated admin roles (Security Admin, Billing Admin, etc.)
 * are implemented, this mapping should be replaced with a
 * database-driven permission set per user.
 */
export const ROLE_PERMISSIONS: Record<TenantRole, AdminPermission[]> = {
  owner: [
    'governance.read', 'governance.write',
    'identity.read', 'identity.write',
    'security.read', 'security.write',
    'agents.read', 'agents.write',
    'data.read', 'data.write',
    'compliance.read', 'compliance.write',
    'billing.read', 'billing.write',
  ],
  admin: [
    'governance.read', 'governance.write',
    'identity.read', 'identity.write',
    'security.read',
    'agents.read', 'agents.write',
    'data.read', 'data.write',
    'compliance.read',
    'billing.read',
  ],
  member: [
    'governance.read',
    'identity.read',
    'agents.read',
    'billing.read',
  ],
  viewer: [
    'governance.read',
    'billing.read',
  ],
};

/**
 * Platform super admin gets all permissions including platform scope.
 */
const PLATFORM_ADMIN_PERMISSIONS: AdminPermission[] = [
  ...ROLE_PERMISSIONS.owner,
  'platform.read', 'platform.write',
];

interface UseAdminPermissionsResult {
  permissions: Set<AdminPermission>;
  hasPermission: (permission: AdminPermission) => boolean;
  canWrite: (section: string) => boolean;
  isPlatformAdmin: boolean;
}

export function resolveTenantRole(roles: string[] | undefined): TenantRole {
  if (!roles || roles.length === 0) return 'viewer';

  const normalizedRoles = roles.map((role) => role.toLowerCase());
  if (normalizedRoles.includes('owner')) return 'owner';
  if (normalizedRoles.includes('admin')) return 'admin';
  if (normalizedRoles.includes('member')) return 'member';
  return 'viewer';
}

/**
 * Returns the admin permission set for the current user.
 *
 * @param role - The user's TenantRole
 * @param isPlatformAdmin - Whether the user is a platform super admin
 */
export function useAdminPermissions(
  role: TenantRole = 'viewer',
  isPlatformAdmin = false
): UseAdminPermissionsResult {
  const permissions = useMemo(() => {
    const perms = isPlatformAdmin
      ? PLATFORM_ADMIN_PERMISSIONS
      : (ROLE_PERMISSIONS[role] ?? ROLE_PERMISSIONS.viewer);
    return new Set(perms);
  }, [role, isPlatformAdmin]);

  const hasPermission = useMemo(
    () => (permission: AdminPermission) => permissions.has(permission),
    [permissions]
  );

  const canWrite = useMemo(
    () => (section: string) => permissions.has(`${section}.write` as AdminPermission),
    [permissions]
  );

  return {
    permissions,
    hasPermission,
    canWrite,
    isPlatformAdmin,
  };
}

/**
 * useAgentMetrics
 *
 * Fetches per-agent model card info from /api/agents/:agentId/info.
 * Falls back to static metadata when the backend is unavailable.
 */

import { useQuery } from "@tanstack/react-query";

import { apiClient } from "@/api/client/unified-api-client";

export interface AgentInfo {
  id: string;
  name: string;
  type: string;
  version: string;
  active: boolean;
  description: string;
  // From model card (populated when backend responds)
  modelVersion?: string;
  trainingCutoff?: string;
  safetyConstraints?: string[];
  knownLimitations?: string[];
  // Metrics (populated from usage ledger when available)
  successRate?: number;
  runsLast7d?: number;
  costLast7d?: string;
}

// Static agent registry — source of truth for display metadata.
// Model card fields are merged in from the backend when available.
export const AGENT_REGISTRY: AgentInfo[] = [
  {
    id: "opportunity",
    name: "Opportunity Agent",
    type: "discovery",
    version: "v2.3",
    active: true,
    description: "Identifies and analyzes business opportunities from EDGAR filings, news, and market data",
  },
  {
    id: "target",
    name: "Target Agent",
    type: "modeling",
    version: "v1.8",
    active: true,
    description: "Builds value trees and quantifies target outcomes for opportunities",
  },
  {
    id: "financial-modeling",
    name: "Financial Modeling Agent",
    type: "analysis",
    version: "v3.1",
    active: true,
    description: "Generates ROI projections, business cases, and financial models",
  },
  {
    id: "integrity",
    name: "Integrity Agent",
    type: "verification",
    version: "v2.0",
    active: true,
    description: "Verifies claims against ground truth sources (EDGAR, XBRL, market data)",
  },
  {
    id: "narrative",
    name: "Narrative Agent",
    type: "content",
    version: "v1.1",
    active: true,
    description: "Generates executive summaries and presentation narratives",
  },
  {
    id: "realization",
    name: "Realization Agent",
    type: "tracking",
    version: "v1.2",
    active: true,
    description: "Tracks value delivery against targets and milestones",
  },
  {
    id: "expansion",
    name: "Expansion Agent",
    type: "growth",
    version: "v1.0",
    active: true,
    description: "Identifies upsell and cross-sell opportunities from realized value",
  },
  {
    id: "compliance-auditor",
    name: "Compliance Auditor",
    type: "verification",
    version: "v1.0",
    active: true,
    description: "Audits control coverage and generates compliance summaries",
  },
];

interface ModelCardResponse {
  agent_id: string;
  model_card: {
    model_version: string;
    training_cutoff: string;
    safety_constraints: string[];
    known_limitations: string[];
  };
}

async function fetchAgentInfo(agentId: string): Promise<Partial<AgentInfo>> {
  const res = await apiClient.get<{ data: ModelCardResponse }>(`/api/agents/${agentId}/info`);
  if (!res.success || !res.data?.data) return {};
  const mc = res.data.data.model_card;
  return {
    modelVersion: mc.model_version,
    trainingCutoff: mc.training_cutoff,
    safetyConstraints: mc.safety_constraints,
    knownLimitations: mc.known_limitations,
  };
}

/** Fetch model card for a single agent. */
export function useAgentInfo(agentId: string) {
  const base = AGENT_REGISTRY.find((a) => a.id === agentId);

  const { data: extra } = useQuery({
    queryKey: ["agent-info", agentId],
    queryFn: () => fetchAgentInfo(agentId),
    // Only fetch if the agent exists in the registry — avoids a guaranteed 404
    // for unknown IDs and prevents wasted requests when base is undefined.
    enabled: !!base,
    staleTime: 5 * 60_000,
    retry: false,
  });

  if (!base) return null;
  return { ...base, ...extra };
}

/** Return the full agent list, enriched with model card data where available. */
export function useAgentList() {
  return useQuery({
    queryKey: ["agent-list"],
    queryFn: async () => {
      const enriched = await Promise.allSettled(
        AGENT_REGISTRY.map(async (agent) => {
          try {
            const extra = await fetchAgentInfo(agent.id);
            return { ...agent, ...extra };
          } catch {
            return agent;
          }
        })
      );
      return enriched.map((r, i) =>
        r.status === "fulfilled" ? r.value : AGENT_REGISTRY[i]!
      );
    },
    staleTime: 5 * 60_000,
    // On failure, fall back to static registry
    placeholderData: AGENT_REGISTRY,
  });
}

