/**
 * Orchestration Layer: useAgentOrchestrator
 *
 * Manages the agent lifecycle by consuming real backend events:
 *   IDLE → PLANNING → EXECUTING → IDLE (or ERROR)
 *
 * State transitions are driven exclusively by SSE payloads from
 * /api/agents/jobs/:jobId/stream — no mock timers or hardcoded steps.
 */

import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { apiClient } from "@/api/client/unified-api-client";

import type { AgentProgressEvent, ChatMessage } from "./useAgentStream";
import { useAgentStream } from "./useAgentStream";

export type AgentState = "IDLE" | "PLANNING" | "EXECUTING" | "ERROR";

export interface ThoughtEvent {
  id: string;
  type: "thought" | "action" | "observation" | "result";
  content: string;
  timestamp: string;
  metadata?: Record<string, unknown>;
}

export interface AgentContext {
  currentStep: string;
  activeWorkers: string[];
  planSteps: string[];
  completedSteps: string[];
}

interface UseAgentOrchestratorOptions {
  agentId?: string;
  onThought?: (event: ThoughtEvent) => void;
  onStateChange?: (state: AgentState) => void;
  onError?: (error: Error) => void;
}

interface UseAgentOrchestratorReturn {
  state: AgentState;
  context: AgentContext;
  thoughts: ThoughtEvent[];
  isProcessing: boolean;
  submitQuery: (query: string) => Promise<void>;
  cancel: () => void;
  reset: () => void;
}

const initialContext: AgentContext = {
  currentStep: "",
  activeWorkers: [],
  planSteps: [],
  completedSteps: [],
};

export function useAgentOrchestrator(
  options: UseAgentOrchestratorOptions = {}
): UseAgentOrchestratorReturn {
  const { agentId = "opportunity", onThought, onStateChange, onError } = options;

  const [state, setState] = useState<AgentState>("IDLE");
  const [context, setContext] = useState<AgentContext>(initialContext);
  const [thoughts, setThoughts] = useState<ThoughtEvent[]>([]);

  // Tracks the in-flight POST so cancel() can abort it
  const invokeAbortRef = useRef<AbortController | null>(null);

  const isProcessing = state === "PLANNING" || state === "EXECUTING";

  // Notify caller on state change
  useEffect(() => {
    onStateChange?.(state);
  }, [state, onStateChange]);

  const addThought = useCallback(
    (event: ThoughtEvent) => {
      setThoughts((prev) => [...prev, event]);
      onThought?.(event);
    },
    [onThought],
  );

  // Stable refs for callbacks — avoids recreating the options object on every
  // render, which would cause useAgentStream's useCallback deps to fire and
  // trigger an infinite re-render loop.
  const addThoughtRef = useRef(addThought);
  addThoughtRef.current = addThought;
  const onErrorRef = useRef(onError);
  onErrorRef.current = onError;

  const streamOptions = useMemo(
    () => ({
      context: { sessionId: "", agentId, messages: [] as ChatMessage[], isStreaming: false },

      onProgress(event: AgentProgressEvent) {
        // processing heartbeat → EXECUTING state + update current step
        setState("EXECUTING");
        setContext((prev) => ({
          ...prev,
          currentStep: event.subTask ?? event.agentId ?? "Processing\u2026",
          activeWorkers: event.agentId ? [event.agentId] : prev.activeWorkers,
        }));
        addThoughtRef.current({
          id: crypto.randomUUID(),
          type: "action",
          content: event.subTask ?? event.agentId ?? "Processing\u2026",
          timestamp: new Date().toISOString(),
        });
      },

      onMessage(message: ChatMessage) {
        // completed event — result arrives as an assistant message
        addThoughtRef.current({
          id: crypto.randomUUID(),
          type: "result",
          content: message.content,
          timestamp: message.timestamp,
          metadata: message.metadata,
        });
        setState("IDLE");
        setContext(initialContext);
      },

      onError(error: Error) {
        setState("ERROR");
        setContext(initialContext);
        onErrorRef.current?.(error);
      },
    }),
    // Intentional dependency omission: addThoughtRef and onErrorRef are stable
    // refs that always point to the latest callbacks. Including them would cause
    // unnecessary re-creation of stream options on every render. Only agentId
    // changes should trigger recreation.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [agentId],
  );

  // SSE stream — wired to drive state transitions
  const { openStream, closeStream } = useAgentStream(streamOptions);

  const submitQuery = useCallback(
    async (query: string) => {
      if (isProcessing) return;

      // Cancel any previous in-flight request
      invokeAbortRef.current?.abort();
      invokeAbortRef.current = new AbortController();

      setState("PLANNING");
      addThought({
        id: crypto.randomUUID(),
        type: "thought",
        content: `Analyzing request: "${query}"`,
        timestamp: new Date().toISOString(),
      });

      try {
        const res = await apiClient.post<{ data: { jobId?: string; result?: unknown; mode?: string } }>(
          `/api/agents/${agentId}/invoke`,
          { query, sessionId: "", context: {} },
        );

        if (!res.success) {
          throw new Error(res.error?.message ?? "Agent invocation failed");
        }

        const payload = res.data?.data;

        if (!payload?.jobId) {
          // Direct-mode — result already available, no stream needed
          addThought({
            id: crypto.randomUUID(),
            type: "result",
            content:
              typeof payload?.result === "string"
                ? payload.result
                : JSON.stringify(payload?.result ?? "Done."),
            timestamp: new Date().toISOString(),
          });
          setState("IDLE");
          setContext(initialContext);
          return;
        }

        // Async mode — open SSE stream; state transitions driven by events
        openStream(payload.jobId);
      } catch (error) {
        if (invokeAbortRef.current?.signal.aborted) {
          // User cancelled — already handled by cancel()
          return;
        }
        setState("ERROR");
        setContext(initialContext);
        onError?.(error instanceof Error ? error : new Error(String(error)));
      }
    },
    [isProcessing, agentId, addThought, openStream, onError],
  );

  const cancel = useCallback(() => {
    invokeAbortRef.current?.abort();
    invokeAbortRef.current = null;
    closeStream();
    setState("IDLE");
    setContext(initialContext);
  }, [closeStream]);

  const reset = useCallback(() => {
    cancel();
    setThoughts([]);
  }, [cancel]);

  return {
    state,
    context,
    thoughts,
    isProcessing,
    submitQuery,
    cancel,
    reset,
  };
}

export default useAgentOrchestrator;

/**
 * React Query hooks for Billing operations.
 *
 * Covers: billing summary, plan management, usage tracking, invoice viewing, approval workflows.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §4.6
 */

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";

import { api } from "@/api/client/unified-api-client";
import { useTenant } from "@/contexts/TenantContext";

// ============================================================================
// Types
// ============================================================================

export type SubscriptionStatus = "active" | "past_due" | "canceled" | "trialing" | "paused";
export type ApprovalStatus = "pending" | "approved" | "rejected";
export type ApprovalDecision = "approve" | "reject";

export interface BillingSummary {
  subscription: {
    id: string;
    status: SubscriptionStatus;
    currentPlan: string;
    currentPlanId: string;
    mrr: number;
    billingPeriod: {
      start: string;
      end: string;
    };
    renewalDate: string;
  };
  usage: {
    aiTokens: {
      used: number;
      cap: number;
      percentage: number;
    };
    apiCalls: {
      used: number;
      cap: number;
      percentage: number;
    };
  };
  recentInvoice?: {
    id: string;
    period: string;
    amount: number;
    status: "paid" | "open" | "overdue";
    dueDate: string;
  };
}

export interface Plan {
  id: string;
  name: string;
  description: string;
  price: number;
  interval: "month" | "year";
  features: string[];
  limits: {
    aiTokens: number;
    apiCalls: number;
    seats: number;
  };
  isCurrent: boolean;
}

export interface PlanChangePreview {
  currentPlan: string;
  newPlan: string;
  deltaMrr: number;
  prorationAmount: number;
  effectiveDate: string;
  requiresApproval: boolean;
  approvalThreshold?: number;
}

export interface Invoice {
  id: string;
  number: string;
  period: {
    start: string;
    end: string;
  };
  amount: number;
  status: "paid" | "open" | "overdue" | "draft";
  dueDate: string;
  paidAt?: string;
  pdfUrl?: string;
  lineItems: Array<{
    description: string;
    quantity: number;
    unitPrice: number;
    amount: number;
  }>;
}

export interface UsageData {
  period: {
    start: string;
    end: string;
  };
  meters: Array<{
    key: string;
    name: string;
    used: number;
    cap: number;
    unit: string;
    trend: "up" | "down" | "flat";
    trendPercentage: number;
  }>;
  dailyBreakdown: Array<{
    date: string;
    aiTokens: number;
    apiCalls: number;
  }>;
}

export interface ApprovalRequest {
  id: string;
  requester: {
    id: string;
    name: string;
    email: string;
  };
  action: string;
  details: string;
  deltaMrr: number;
  status: ApprovalStatus;
  requestedAt: string;
  decidedAt?: string;
  decidedBy?: string;
}

export interface PlanChangeInput {
  newPlanId: string;
  effectiveDate?: string;
}

// ============================================================================
// Billing Summary Hooks
// ============================================================================

/**
 * Fetch billing summary for the current tenant.
 * GET /billing/summary
 */
export function useBillingSummary() {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id;

  return useQuery<BillingSummary>({
    queryKey: ["billingSummary", tenantId],
    queryFn: async () => {
      const response = await api.getBillingSummary();
      if (!response.success || !response.data) {
        throw new Error(response.error?.message || "Failed to fetch billing summary");
      }
      return response.data as BillingSummary;
    },
    enabled: !!tenantId,
    staleTime: 30_000,
  });
}

// ============================================================================
// Plan Management Hooks
// ============================================================================

/**
 * Fetch available plans.
 * GET /billing/plans
 */
export function usePlans() {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id;

  return useQuery<Plan[]>({
    queryKey: ["plans", tenantId],
    queryFn: async () => {
      const response = await api.getPlans();
      if (!response.success || !response.data) {
        throw new Error(response.error?.message || "Failed to fetch plans");
      }
      return response.data as Plan[];
    },
    enabled: !!tenantId,
    staleTime: 60_000, // Plans rarely change
  });
}

/**
 * Preview a plan change before committing.
 * POST /billing/plan-change/preview
 */
export function usePlanChangePreview() {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id;

  return useMutation({
    mutationFn: async (input: PlanChangeInput) => {
      const response = await api.previewPlanChange(input);
      if (!response.success) {
        throw new Error(response.error?.message || "Failed to preview plan change");
      }
      return response.data as PlanChangePreview;
    },
  });
}

/**
 * Submit a plan change.
 * POST /billing/plan-change/submit
 */
export function useSubmitPlanChange() {
  const queryClient = useQueryClient();
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id;

  return useMutation({
    mutationFn: async (input: PlanChangeInput) => {
      const response = await api.submitPlanChange(input);
      if (!response.success) {
        throw new Error(response.error?.message || "Failed to submit plan change");
      }
      return response.data;
    },
    onSuccess: () => {
      // Invalidate billing data to reflect new plan
      queryClient.invalidateQueries({ queryKey: ["billingSummary", tenantId] });
      queryClient.invalidateQueries({ queryKey: ["plans", tenantId] });
      queryClient.invalidateQueries({ queryKey: ["approvals", tenantId] });
    },
  });
}

// ============================================================================
// Invoice Hooks
// ============================================================================

/**
 * Fetch invoices for the current tenant.
 * GET /billing/invoices
 */
export function useInvoices() {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id;

  return useQuery<Invoice[]>({
    queryKey: ["invoices", tenantId],
    queryFn: async () => {
      const response = await api.getInvoices();
      if (!response.success || !response.data) {
        throw new Error(response.error?.message || "Failed to fetch invoices");
      }
      return response.data as Invoice[];
    },
    enabled: !!tenantId,
    staleTime: 60_000,
  });
}

// ============================================================================
// Usage Hooks
// ============================================================================

/**
 * Fetch usage data for the current tenant.
 * GET /billing/usage
 */
export function useUsage() {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id;

  return useQuery<UsageData>({
    queryKey: ["usage", tenantId],
    queryFn: async () => {
      const response = await api.getUsage();
      if (!response.success || !response.data) {
        throw new Error(response.error?.message || "Failed to fetch usage");
      }
      return response.data as UsageData;
    },
    enabled: !!tenantId,
    staleTime: 30_000,
  });
}

// ============================================================================
// Approval Workflow Hooks
// ============================================================================

/**
 * Fetch pending approval requests.
 * GET /billing/approvals
 */
export function useApprovals() {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id;

  return useQuery<ApprovalRequest[]>({
    queryKey: ["approvals", tenantId],
    queryFn: async () => {
      const response = await api.getApprovals();
      if (!response.success || !response.data) {
        throw new Error(response.error?.message || "Failed to fetch approvals");
      }
      return response.data as ApprovalRequest[];
    },
    enabled: !!tenantId,
    staleTime: 30_000,
  });
}

/**
 * Approve or reject a billing approval request.
 * POST /billing/approvals/:id/decide
 */
export function useDecideApproval() {
  const queryClient = useQueryClient();
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id;

  return useMutation({
    mutationFn: async ({ approvalId, decision }: { approvalId: string; decision: ApprovalDecision }) => {
      const response = await api.decideApproval(approvalId, decision);
      if (!response.success) {
        throw new Error(response.error?.message || "Failed to process approval decision");
      }
      return response.data;
    },
    onSuccess: () => {
      // Invalidate approvals and billing data
      queryClient.invalidateQueries({ queryKey: ["approvals", tenantId] });
      queryClient.invalidateQueries({ queryKey: ["billingSummary", tenantId] });
    },
  });
}

/**
 * ESO (Economic Statistics Organizations) Hook
 *
 * React hook for accessing real-time economic data from SEC, BLS, and Census.
 * Provides integration with ValueOS deterministic B2B value orchestration.
 */

import { useCallback, useEffect } from "react";

import { useESOStore } from "../stores/esoStore";

export interface ESOConfig {
  sec: {
    baseUrl: string;
    rateLimit?: number;
    enableCache?: boolean;
    cacheTTL?: number;
  };
  bls: {
    baseUrl: string;
    apiKey?: string;
    rateLimit?: number;
    enableCache?: boolean;
    cacheTTL?: number;
  };
  census: {
    baseUrl: string;
    apiKey?: string;
    rateLimit?: number;
    enableCache?: boolean;
    cacheTTL?: number;
  };
  enableRealtime: boolean;
  websocketUrl?: string;
}

export const useESO = (config?: ESOConfig) => {
  const {
    data,
    isConnected,
    isStreaming,
    error,
    lastUpdate,
    initializeESO,
    startStreaming,
    stopStreaming,
    fetchData,
    clearData,
    setError,
  } = useESOStore();

  // Initialize ESO service when config is provided
  useEffect(() => {
    if (config && !isConnected) {
      initializeESO(config);
    }
  }, [config, isConnected, initializeESO]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (isStreaming) {
        stopStreaming();
      }
    };
  }, [isStreaming, stopStreaming]);

  const fetchSECData = useCallback(
    (params?: { cik?: string; type?: string }) => {
      return fetchData("SEC", params);
    },
    [fetchData]
  );

  const fetchBLSData = useCallback(
    (params: { seriesId: string; startYear?: string; endYear?: string }) => {
      return fetchData("BLS", params);
    },
    [fetchData]
  );

  const fetchCensusData = useCallback(
    (params: { dataset: string; variables: string[]; geography?: string }) => {
      return fetchData("Census", params);
    },
    [fetchData]
  );

  const getDataBySource = useCallback(
    (source: "SEC" | "BLS" | "Census") => {
      return data[source] || null;
    },
    [data]
  );

  const getLatestData = useCallback(() => {
    return Object.entries(data).map(([source, sourceData]) => ({
      source: source as "SEC" | "BLS" | "Census",
      ...sourceData,
    }));
  }, [data]);

  const clearError = useCallback(() => {
    setError(null);
  }, [setError]);

  return {
    // State
    data,
    isConnected,
    isStreaming,
    error,
    lastUpdate,

    // Actions
    startStreaming,
    stopStreaming,
    fetchSECData,
    fetchBLSData,
    fetchCensusData,
    clearData,
    clearError,

    // Computed
    getDataBySource,
    getLatestData,
    hasData: Object.keys(data).length > 0,
    isStale: lastUpdate > 0 && Date.now() - lastUpdate > 300000, // 5 minutes
  };
};

/**
 * useIntegrity
 *
 * Fetches the latest integrity result for a value case and provides
 * a mutation to invoke the IntegrityAgent.
 *
 * Also includes V1 surface hooks for readiness, evidence gaps, and plausibility.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §4.3
 */

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";

import { api, apiClient } from "@/api/client/unified-api-client";
import { useTenant } from "@/contexts/TenantContext";

// ---------------------------------------------------------------------------
// Legacy Types
// ---------------------------------------------------------------------------

export interface ClaimValidation {
  claim_id: string;
  claim_text: string;
  verdict: "supported" | "partially_supported" | "unsupported" | "insufficient_evidence";
  confidence: number;
  evidence_assessment: string;
  issues: Array<{ type: string; severity: string; description: string }>;
  suggested_fix?: string;
}

export interface IntegrityResult {
  id: string;
  organization_id: string;
  value_case_id: string;
  session_id: string | null;
  claims: ClaimValidation[];
  veto_decision: "pass" | "veto" | "re_refine" | null;
  overall_score: number | null;
  data_quality_score: number | null;
  logic_score: number | null;
  evidence_score: number | null;
  hallucination_check: boolean | null;
  source_agent: string;
  created_at: string;
  updated_at: string;
}

export interface AgentRunResponse {
  jobId: string;
  agentId: string;
  status: string;
  result?: Record<string, unknown>;
  confidence?: string;
  duration_ms?: number;
}

// ---------------------------------------------------------------------------
// V1 Surface Types
// ---------------------------------------------------------------------------

export interface ReadinessComponent {
  name: string;
  score: number;
  weight: number;
}

export interface ReadinessData {
  compositeScore: number;
  status: "presentation-ready" | "draft" | "blocked";
  blockers: string[];
  components: {
    validationRate: ReadinessComponent;
    grounding: ReadinessComponent;
    benchmarkCoverage: ReadinessComponent;
    unsupportedCount: ReadinessComponent;
  };
  confidenceDistribution: {
    high: number; // >= 0.8
    medium: number; // >= 0.5
    low: number; // < 0.5
  };
}

export interface EvidenceGap {
  id: string;
  claimId: string;
  field: string;
  currentTier: "tier1" | "tier2" | "tier3" | "none";
  requiredTier: "tier1" | "tier2" | "tier3";
  suggestedAction: string;
  impact: "high" | "medium" | "low";
}

export interface PlausibilityFlag {
