import { useCallback, useEffect, useMemo, useState } from "react";

const PERSONALIZATION_STORAGE_KEY = "valynt_personalization_v1";
const MAX_RECENT_SEARCHES = 5;

interface PersonalizationState {
  routeUsage: Record<string, number>;
  featureUsage: Record<string, number>;
  recentSearches: string[];
}

const DEFAULT_STATE: PersonalizationState = {
  routeUsage: {},
  featureUsage: {},
  recentSearches: [],
};

const PERSONALIZATION_UPDATED_EVENT = "valynt:personalization:updated";

function loadPersonalizationState(): PersonalizationState {
  try {
    const raw = localStorage.getItem(PERSONALIZATION_STORAGE_KEY);
    if (!raw) return DEFAULT_STATE;

    const parsed = JSON.parse(raw) as Partial<PersonalizationState>;
    return {
      routeUsage: parsed.routeUsage ?? {},
      featureUsage: parsed.featureUsage ?? {},
      recentSearches: Array.isArray(parsed.recentSearches) ? parsed.recentSearches : [],
    };
  } catch {
    return DEFAULT_STATE;
  }
}

function persistPersonalizationState(state: PersonalizationState) {
  try {
    localStorage.setItem(PERSONALIZATION_STORAGE_KEY, JSON.stringify(state));
    window.dispatchEvent(new CustomEvent(PERSONALIZATION_UPDATED_EVENT));
  } catch {
    // Best-effort persistence
  }
}

export function useNavigationPersonalization() {
  const [state, setState] = useState<PersonalizationState>(() => loadPersonalizationState());

  useEffect(() => {
    const syncState = () => {
      setState(loadPersonalizationState());
    };

    const handleStorage = (event: StorageEvent) => {
      if (event.key && event.key !== PERSONALIZATION_STORAGE_KEY) return;
      syncState();
    };

    window.addEventListener("storage", handleStorage);
    window.addEventListener(PERSONALIZATION_UPDATED_EVENT, syncState);

    return () => {
      window.removeEventListener("storage", handleStorage);
      window.removeEventListener(PERSONALIZATION_UPDATED_EVENT, syncState);
    };
  }, []);

  const trackRouteVisit = useCallback((path: string) => {
    if (!path) return;

    setState((prev) => {
      const next: PersonalizationState = {
        ...prev,
        routeUsage: {
          ...prev.routeUsage,
          [path]: (prev.routeUsage[path] ?? 0) + 1,
        },
      };

      persistPersonalizationState(next);
      return next;
    });
  }, []);

  const trackFeatureUsage = useCallback((feature: string) => {
    const normalized = feature.trim();
    if (!normalized) return;

    setState((prev) => {
      const next: PersonalizationState = {
        ...prev,
        featureUsage: {
          ...prev.featureUsage,
          [normalized]: (prev.featureUsage[normalized] ?? 0) + 1,
        },
      };

      persistPersonalizationState(next);
      return next;
    });
  }, []);

  const trackSearch = useCallback((query: string) => {
    const normalized = query.trim();
    if (!normalized) return;

    setState((prev) => {
      const deduped = prev.recentSearches.filter(
        (entry) => entry.toLocaleLowerCase() !== normalized.toLocaleLowerCase()
      );

      const next: PersonalizationState = {
        ...prev,
        recentSearches: [normalized, ...deduped].slice(0, MAX_RECENT_SEARCHES),
      };

      persistPersonalizationState(next);
      return next;
    });
  }, []);

  const getUsageCount = useCallback(
    (path: string) => {
      return state.routeUsage[path] ?? 0;
    },
    [state.routeUsage]
  );

  const getFeatureUsageCount = useCallback(
    (feature: string) => {
      return state.featureUsage[feature] ?? 0;
    },
    [state.featureUsage]
  );

  const frequentRouteSet = useMemo(() => {
    const sorted = Object.entries(state.routeUsage)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3)
      .filter(([, count]) => count > 0)
      .map(([path]) => path);

    return new Set(sorted);
  }, [state.routeUsage]);

  return {
    routeUsage: state.routeUsage,
    featureUsage: state.featureUsage,
    recentSearches: state.recentSearches,
    trackRouteVisit,
    trackFeatureUsage,
    trackSearch,
    getUsageCount,
    getFeatureUsageCount,
    frequentRouteSet,
  };
}

/**
 * useValueCaseStream
 *
 * Real-time SSE connection to the HypothesisLoop backend.
 * Receives enriched LoopProgress events and maintains pipeline state
 * for the PipelineStepper and AgentInsightCard components.
 */

import { useCallback, useEffect, useRef, useState } from "react";
import type { RuntimeFailureDetails } from "@shared/domain/RuntimeFailureTaxonomy";

import { getApiBaseUrl } from "@/lib/env";

// ---------------------------------------------------------------------------
// Types — mirrors backend LoopProgress
// ---------------------------------------------------------------------------

export type PipelineStepStatus = "pending" | "running" | "completed" | "failed";

export interface PipelineStepState {
  step: number;
  stepName: string;
  status: PipelineStepStatus;
  message?: string;
  agentName?: string;
  confidence?: number;
  durationMs?: number;
  partialResult?: {
    itemCount?: number;
    totalValue?: number;
    highlights?: string[];
  };
}

export interface PipelineState {
  /** All 7 steps with their current status. */
  steps: PipelineStepState[];
  /** Current revision cycle (0 = first pass). */
  revisionCycle: number;
  /** Max allowed revision cycles. */
  maxRevisionCycles: number;
  /** Whether the pipeline is actively running. */
  isRunning: boolean;
  /** Whether the pipeline completed successfully. */
  isComplete: boolean;
  /** Error message if the pipeline failed. */
  error: string | null;
  /** Structured remediation details from runtime failure emission. */
  runtimeFailure: RuntimeFailureDetails | null;
  /** Timestamp of the last received event. */
  lastEventAt: string | null;
}

const STEP_NAMES = [
  "Hypothesis",
  "Model",
  "Evidence",
  "Narrative",
  "Objection",
  "Revision",
  "Approval",
] as const;

function buildInitialSteps(): PipelineStepState[] {
  return STEP_NAMES.map((name, i) => ({
    step: i + 1,
    stepName: name,
    status: "pending" as const,
  }));
}

const INITIAL_STATE: PipelineState = {
  steps: buildInitialSteps(),
  revisionCycle: 0,
  maxRevisionCycles: 3,
  isRunning: false,
  isComplete: false,
  error: null,
  runtimeFailure: null,
  lastEventAt: null,
};

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

interface UseValueCaseStreamOptions {
  /** Callback fired on each progress event. */
  onProgress?: (step: PipelineStepState) => void;
  /** Callback fired when the pipeline completes. */
  onComplete?: () => void;
  /** Callback fired on error. */
  onError?: (error: string) => void;
}

export interface UseValueCaseStreamReturn {
  pipeline: PipelineState;
  /** Start streaming for a given job ID. */
  connect: (jobId: string) => void;
  /** Stop the SSE connection. */
  disconnect: () => void;
  /** Reset pipeline to initial state. */
  reset: () => void;
  /** The currently active step (first running step, or last completed). */
  activeStep: PipelineStepState | null;
  /** Overall progress as a 0–1 fraction. */
  progress: number;
}

export function useValueCaseStream(
  options: UseValueCaseStreamOptions = {},
): UseValueCaseStreamReturn {
  const { onProgress, onComplete, onError } = options;

  const [pipeline, setPipeline] = useState<PipelineState>(INITIAL_STATE);
  const eventSourceRef = useRef<EventSource | null>(null);
  const optionsRef = useRef(options);
  optionsRef.current = options;

  const disconnect = useCallback(() => {
    if (eventSourceRef.current) {
      eventSourceRef.current.close();
      eventSourceRef.current = null;
    }
  }, []);

  const reset = useCallback(() => {
    disconnect();
    setPipeline(INITIAL_STATE);
  }, [disconnect]);

  const connect = useCallback(
    (jobId: string) => {
      disconnect();

      const baseUrl = getApiBaseUrl();
      const url = `${baseUrl}/agents/jobs/${encodeURIComponent(jobId)}/stream`;

      setPipeline((prev) => ({
        ...prev,
        steps: buildInitialSteps(),
        isRunning: true,
        isComplete: false,
        error: null,
        runtimeFailure: null,
      }));

      const source = new EventSource(url, { withCredentials: true });
      eventSourceRef.current = source;

      source.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data) as Record<string, unknown>;

          const runtimeFailure = (data.runtime_failure ?? data.failure) as RuntimeFailureDetails | undefined;

          // Handle progress events from the HypothesisLoop
          if (typeof data.step === "number" && typeof data.stepName === "string") {
            const stepUpdate: PipelineStepState = {
              step: data.step as number,
              stepName: data.stepName as string,
              status: (data.status as PipelineStepStatus) ?? "running",
              message: data.message as string | undefined,
              agentName: data.agentName as string | undefined,
              confidence: data.confidence as number | undefined,
              durationMs: data.durationMs as number | undefined,
              partialResult: data.partialResult as PipelineStepState["partialResult"],
            };

            setPipeline((prev) => {
              const newSteps = prev.steps.map((s) =>
                s.step === stepUpdate.step ? { ...s, ...stepUpdate } : s,
              );

              const isComplete =
                stepUpdate.step === 7 && stepUpdate.status === "completed";

              return {
                ...prev,
                steps: newSteps,
                revisionCycle: (data.revisionCycle as number) ?? prev.revisionCycle,
                maxRevisionCycles:
                  (data.maxRevisionCycles as number) ?? prev.maxRevisionCycles,
                isRunning: !isComplete,
                isComplete,
                runtimeFailure: runtimeFailure ?? prev.runtimeFailure,
                lastEventAt: data.timestamp as string,
              };
            });

            optionsRef.current.onProgress?.(stepUpdate);

            if (stepUpdate.step === 7 && stepUpdate.status === "completed") {
              optionsRef.current.onComplete?.();
              source.close();
            }
          }

          // Handle terminal status events from the job stream
          if (data.status === "completed" || data.status === "error") {
            if (data.status === "error") {
              const errorMsg =
                (data.message as string) ?? "Pipeline failed unexpectedly";
              setPipeline((prev) => ({
                ...prev,
                isRunning: false,
                error: errorMsg,
                runtimeFailure: runtimeFailure ?? prev.runtimeFailure,
              }));
              optionsRef.current.onError?.(errorMsg);
            }
            source.close();
          }
        } catch {
          // Ignore malformed events
        }
      };

      source.onerror = () => {
        setPipeline((prev) => {
          // If already complete, this is just the connection closing
          if (prev.isComplete) return prev;
          return {
            ...prev,
            isRunning: false,
            error: "Connection lost. The pipeline may still be running.",
            runtimeFailure: prev.runtimeFailure,
          };
        });
        source.close();
      };
    },
    [disconnect],
  );

  // Clean up on unmount
  useEffect(() => {
    return () => {
      eventSourceRef.current?.close();
    };
  }, []);

  // Derived state
  const activeStep =
    pipeline.steps.find((s) => s.status === "running") ??
    [...pipeline.steps].reverse().find((s) => s.status === "completed") ??
    null;

  const completedCount = pipeline.steps.filter(
    (s) => s.status === "completed",
  ).length;
  const progress = completedCount / 7;

  return {
    pipeline,
    connect,
    disconnect,
    reset,
    activeStep,
    progress,
  };
}


import React, { createContext, useCallback, useContext, useEffect, useMemo, useState } from "react";

import { DEFAULT_LOCALE, type LocaleCode, localeMetadata } from "./config";

import { loadMessages, resolveLocale } from "./index";

type Messages = Record<string, string>;
const LOCALE_STORAGE_KEY = "valueos.locale";

type I18nContextValue = {
  locale: LocaleCode;
  direction: "ltr" | "rtl";
  setLocale: (nextLocale: LocaleCode) => Promise<void>;
  t: (translationKey: string, fallbackText?: string) => string;
  loading: boolean;
};

const I18nContext = createContext<I18nContextValue | undefined>(undefined);

function getInitialLocale(): LocaleCode {
  if (typeof window === "undefined") return DEFAULT_LOCALE;

  const stored = localStorage.getItem(LOCALE_STORAGE_KEY);
  if (stored) {
    return resolveLocale(stored);
  }

  return resolveLocale(navigator.language);
}

export function I18nProvider({ children }: { children: React.ReactNode }) {
  const [locale, setLocaleState] = useState<LocaleCode>(() => getInitialLocale());
  const [messages, setMessages] = useState<Messages>({});
  const [loading, setLoading] = useState(true);

  const setLocale = useCallback(async (nextLocale: LocaleCode) => {
    const resolved = resolveLocale(nextLocale);
    setLoading(true);
    const loadedMessages = await loadMessages(resolved);
    setLocaleState(resolved);
    setMessages(loadedMessages);
    localStorage.setItem(LOCALE_STORAGE_KEY, resolved);
    setLoading(false);
  }, []);

  useEffect(() => {
    let active = true;

    loadMessages(locale)
      .then((loadedMessages) => {
        if (!active) return;
        setMessages(loadedMessages);
      })
      .finally(() => {
        if (active) setLoading(false);
      });

    return () => {
      active = false;
    };
  }, [locale]);

  useEffect(() => {
    document.documentElement.lang = locale;
    document.documentElement.dir = localeMetadata[locale].direction;
  }, [locale]);

  const value = useMemo<I18nContextValue>(
    () => ({
      locale,
      direction: localeMetadata[locale].direction,
      setLocale,
      t: (translationKey, fallbackText) => messages[translationKey] ?? fallbackText ?? translationKey,
      loading,
    }),
    [locale, loading, messages, setLocale],
  );

  return <I18nContext.Provider value={value}>{children}</I18nContext.Provider>;
}

export function useI18n() {
  const context = useContext(I18nContext);
  if (!context) {
    throw new Error("useI18n must be used within I18nProvider");
  }

  return context;
}

import { describe, expect, it } from "vitest";

import { DEFAULT_LOCALE, localeMetadata, SUPPORTED_LOCALES } from "../config";
import { getMessage, loadMessages, resolveLocale } from "../index";

describe("i18n locale fallback behavior", () => {
  it("resolves unsupported locales to the default locale", () => {
    expect(resolveLocale("fr")).toBe(DEFAULT_LOCALE);
    expect(resolveLocale("pt-BR")).toBe(DEFAULT_LOCALE);
  });

  it("resolves region variants to supported base locales", () => {
    expect(resolveLocale("en-US")).toBe("en");
    expect(resolveLocale("es-MX")).toBe("es");
  });

  it("falls back to default locale message when a key is missing", async () => {
    const translated = await getMessage("navigation.dashboard", "es");
    const fallback = await getMessage("nonexistent.translation.key", "es");

    expect(translated).toBe("Panel");
    expect(fallback).toBe("nonexistent.translation.key");
  });

  it("loads locale bundles for every configured locale", async () => {
    const bundles = await Promise.all(SUPPORTED_LOCALES.map((locale) => loadMessages(locale)));

    for (const [index, messages] of bundles.entries()) {
      expect(Object.keys(messages).length).toBeGreaterThan(0);
      expect(localeMetadata[SUPPORTED_LOCALES[index]]).toBeDefined();
    }
  });
});

import { DEFAULT_LOCALE, type LocaleCode, localeMetadata, SUPPORTED_LOCALES } from "./config";

type Messages = Record<string, string>;

type MessageLoader = () => Promise<Messages>;

const loaders: Record<LocaleCode, MessageLoader> = {
  en: () => import("./locales/en/common.json").then((module) => module.default as Messages),
  es: () => import("./locales/es/common.json").then((module) => module.default as Messages),
};

const messageCache = new Map<LocaleCode, Messages>();

export function resolveLocale(requested?: string): LocaleCode {
  if (!requested) {
    return DEFAULT_LOCALE;
  }

  const normalized = requested.split("-")[0];
  const matched = SUPPORTED_LOCALES.find((locale) => locale === normalized);

  return matched ?? DEFAULT_LOCALE;
}

export async function loadMessages(requested?: string): Promise<Messages> {
  const locale = resolveLocale(requested);
  const cached = messageCache.get(locale);
  if (cached) {
    return cached;
  }

  const loader = loaders[locale] ?? loaders[DEFAULT_LOCALE];
  const messages = await loader();
  messageCache.set(locale, messages);
  return messages;
}

export async function getMessage(key: string, requested?: string): Promise<string> {
  const locale = resolveLocale(requested);
  const messages = await loadMessages(locale);

  if (messages[key]) {
    return messages[key];
  }

  const fallbackMessages = await loadMessages(DEFAULT_LOCALE);
  return fallbackMessages[key] ?? key;
}

export function getSupportedLocales() {
  return SUPPORTED_LOCALES.map((code) => ({
    code,
    ...localeMetadata[code],
  }));
}

export const i18n = {
  resolveLocale,
  loadMessages,
  getMessage,
  getSupportedLocales,
  supported: SUPPORTED_LOCALES,
  defaultLocale: DEFAULT_LOCALE,
};

import { PSEUDO_LOCALE_CODE, type PseudoLocaleCode } from "./config";

export type Messages = Record<string, string>;

const TOKEN_PATTERN = /(\{\{[^}]+\}\}|\{[^}]+\}|%\{[^}]+\}|%s|%d)/g;
const TOKEN_SEGMENT_PATTERN = /^(\{\{[^}]+\}\}|\{[^}]+\}|%\{[^}]+\}|%s|%d)$/;
const ACCENT_MAP: Record<string, string> = {
  a: "à",
  b: "ƀ",
  c: "ç",
  d: "đ",
  e: "ë",
  f: "ƒ",
  g: "ğ",
  h: "ħ",
  i: "ï",
  j: "ĵ",
  k: "ķ",
  l: "ľ",
  m: "m",
  n: "ñ",
  o: "ô",
  p: "þ",
  q: "q",
  r: "ř",
  s: "ş",
  t: "ŧ",
  u: "ü",
  v: "ṽ",
  w: "ŵ",
  x: "ẋ",
  y: "ÿ",
  z: "ž",
  A: "Â",
  B: "ß",
  C: "Č",
  D: "Ď",
  E: "Ë",
  F: "Ƒ",
  G: "Ğ",
  H: "Ħ",
  I: "Ï",
  J: "Ĵ",
  K: "Ķ",
  L: "Ľ",
  M: "M",
  N: "Ń",
  O: "Ö",
  P: "Þ",
  Q: "Q",
  R: "Ř",
  S: "Š",
  T: "Ŧ",
  U: "Û",
  V: "Ṽ",
  W: "Ŵ",
  X: "Ẍ",
  Y: "Ŷ",
  Z: "Ž",
};

export function pseudoLocalizeString(input: string): string {
  const segments = input.split(TOKEN_PATTERN);

  return segments
    .map((segment) => {
      if (!segment) {
        return segment;
      }

      if (TOKEN_SEGMENT_PATTERN.test(segment)) {
        return segment;
      }

      const accented = [...segment].map((ch) => ACCENT_MAP[ch] ?? ch).join("");
      const padLength = Math.max(2, Math.ceil(accented.length * 0.35));
      return `${accented}${"~".repeat(padLength)}`;
    })
    .join("");
}

export function buildPseudoLocaleMessages(sourceMessages: Messages): Messages {
  return Object.fromEntries(
    Object.entries(sourceMessages).map(([key, value]) => [key, pseudoLocalizeString(value)])
  );
}

export function getPseudoLocaleCode(): PseudoLocaleCode {
  return PSEUDO_LOCALE_CODE;
}

