/**
 * ExecutiveLayout Component
 *
 * Three-panel layout with:
 * - Left: Compact icon navigation (80px)
 * - Center: Main content area (flexible)
 * - Right: AI chat sidebar (380px)
 *
 * Used for executive summary, value case workspace, and dashboard views.
 */

import { useState } from 'react';
import { Outlet, Link, useLocation, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';

import { useAuth } from '@/contexts/AuthContext';
import { useTenant } from '@/contexts/TenantContext';
import { MaterialIcon } from '@/components/ui/MaterialIcon';
import { AIChatPanel } from '@/components/ui/AIChatPanel';
import { aiSidebarReveal, slideInUp } from '@/lib/animations';
import { cn } from '@/lib/utils';
import type { ChatMessage } from '@/components/ui/AIChatPanel';

// Navigation items
const navItems = [
  { id: 'dashboard', icon: 'dashboard', label: 'Dashboard', path: '/dashboard' },
  { id: 'opportunities', icon: 'psychology', label: 'Intelligence', path: '/opportunities' },
  { id: 'models', icon: 'calculate', label: 'Models', path: '/models' },
  { id: 'integrations', icon: 'settings_input_component', label: 'Integrations', path: '/integrations' },
];

const bottomNavItems = [
  { id: 'help', icon: 'help', label: 'Help', path: '/help' },
  { id: 'profile', icon: 'account_circle', label: 'Profile', path: '/settings' },
];

export function ExecutiveLayout() {
  const [aiPanelOpen, setAiPanelOpen] = useState(true);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const { user, logout } = useAuth();
  const { currentTenant } = useTenant();
  const location = useLocation();
  const navigate = useNavigate();

  const currentPath = location.pathname;

  const isActiveRoute = (path: string) => {
    if (path === '/dashboard') {
      return currentPath === '/dashboard' || currentPath === '/';
    }
    return currentPath.startsWith(path);
  };

  const handleSendMessage = async (message: string) => {
    // Add user message
    const userMsg = {
      id: Date.now().toString(),
      role: 'user' as const,
      content: message,
      timestamp: new Date(),
    };

    setChatMessages(prev => [...prev, userMsg]);
    setChatInput('');
    setIsAiLoading(true);

    const aiMsg = {
      id: (Date.now() + 1).toString(),
      role: 'assistant' as const,
      content:
        'Agent chat is unavailable: no backend orchestration endpoint is wired for ExecutiveLayout yet. Configure a real chat integration to continue.',
      timestamp: new Date(),
      metadata: {
        agentId: 'integration-missing',
      },
    };
    setChatMessages(prev => [...prev, aiMsg]);
    setIsAiLoading(false);
  };

  return (
    <div className="h-screen flex overflow-hidden bg-md-surface">
      {/* Left Navigation */}
      <aside className="w-20 flex-shrink-0 bg-md-surface-container-lowest border-r border-md-outline-variant flex flex-col py-6">
        {/* Logo */}
        <div className="px-4 mb-8 flex justify-center">
          <div className="w-12 h-12 bg-md-primary-container rounded-xl flex items-center justify-center text-white shadow-lg">
            <MaterialIcon icon="auto_awesome" filled className="text-xl" />
          </div>
        </div>

        {/* Main Navigation */}
        <nav className="flex-1 flex flex-col gap-1 px-2">
          {navItems.map((item) => {
            const isActive = isActiveRoute(item.path);
            return (
              <Link
                key={item.id}
                to={item.path}
                className={cn(
                  'flex items-center justify-center py-3 rounded-xl transition-all duration-200 group',
                  isActive
                    ? 'bg-md-surface-container-high text-md-tertiary-container'
                    : 'text-md-on-surface-variant hover:bg-md-surface-container-high hover:text-md-on-surface'
                )}
                title={item.label}
              >
                <MaterialIcon
                  icon={item.icon}
                  size="lg"
                  filled={isActive}
                  className={cn(
                    'transition-transform duration-200',
                    !isActive && 'group-hover:scale-110'
                  )}
                />
              </Link>
            );
          })}
        </nav>

        {/* Bottom Navigation */}
        <div className="mt-auto pt-6 flex flex-col gap-1 px-2 border-t border-md-outline-variant/50">
          {bottomNavItems.map((item) => (
            <Link
              key={item.id}
              to={item.path}
              className={cn(
                'flex items-center justify-center py-3 rounded-xl transition-all duration-200',
                isActiveRoute(item.path)
                  ? 'bg-md-surface-container-high text-md-tertiary-container'
                  : 'text-md-on-surface-variant hover:bg-md-surface-container-high hover:text-md-on-surface'
              )}
              title={item.label}
            >
              <MaterialIcon icon={item.icon} size="lg" />
            </Link>
          ))}

          {/* User Avatar */}
          {user && (
            <button
              type="button"
              onClick={() => navigate('/settings')}
              className="flex items-center justify-center py-3 mt-2"
              title="Profile"
            >
              <div className="w-10 h-10 rounded-full bg-md-secondary-container flex items-center justify-center text-white text-sm font-bold">
                {user.email?.charAt(0).toUpperCase() || 'U'}
              </div>
            </button>
          )}
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Top App Bar */}
        <header className="h-16 bg-md-surface-container-lowest border-b border-md-outline-variant flex items-center justify-between px-6 flex-shrink-0">
          <div className="flex items-center gap-4">
            <h1 className="text-lg font-bold text-md-on-surface">
              {currentTenant?.name || 'Dashboard'}
            </h1>

            {/* Search */}
            <div className="hidden md:flex items-center gap-2 px-3 py-1.5 bg-md-surface-container-high rounded-lg border border-md-outline-variant/50">
              <MaterialIcon icon="search" size="sm" className="text-md-outline" />
              <input
                type="text"
                placeholder="Search analytics..."
                className="bg-transparent border-none text-sm focus:ring-0 p-0 w-48 text-md-on-surface placeholder:text-md-outline"
              />
            </div>
          </div>

          <div className="flex items-center gap-3">
            {/* AI Toggle Button */}
            <button
              type="button"
              onClick={() => setAiPanelOpen(!aiPanelOpen)}
              className={cn(
                'p-2 rounded-full transition-colors relative',
                aiPanelOpen
                  ? 'bg-md-tertiary-container/10 text-md-tertiary-container'
                  : 'text-md-on-surface-variant hover:bg-md-surface-container-high'
              )}
              title={aiPanelOpen ? 'Close AI Panel' : 'Open AI Panel'}
            >
              <MaterialIcon icon="smart_toy" size="lg" />
              {!aiPanelOpen && (
                <span className="absolute top-1 right-1 w-2 h-2 bg-emerald-500 rounded-full animate-pulse" />
              )}
            </button>

            {/* Notifications */}
            <button
              type="button"
              className="p-2 text-md-on-surface-variant hover:bg-md-surface-container-high rounded-full transition-colors"
              title="Notifications"
            >
              <MaterialIcon icon="notifications" size="lg" />
            </button>

            {/* Settings */}
            <button
              type="button"
              onClick={() => navigate('/settings')}
              className="p-2 text-md-on-surface-variant hover:bg-md-surface-container-high rounded-full transition-colors"
              title="Settings"
            >
              <MaterialIcon icon="settings" size="lg" />
            </button>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 flex overflow-hidden">
          {/* Main Content */}
          <div className="flex-1 overflow-y-auto">
            <motion.div
              key={currentPath}
              initial="hidden"
              animate="visible"
              exit="exit"
              variants={slideInUp}
              className="p-8"
            >
              <Outlet />
            </motion.div>
          </div>

          {/* AI Sidebar */}
          <AnimatePresence mode="wait">
            {aiPanelOpen && (
              <motion.div
                initial="hidden"
                animate="visible"
                exit="exit"
                variants={aiSidebarReveal}
                className="flex-shrink-0"
              >
                <AIChatPanel
                  messages={chatMessages}
                  inputValue={chatInput}
                  onInputChange={setChatInput}
                  onSendMessage={handleSendMessage}
                  isLoading={isAiLoading}
                  isOnline={true}
                  onClose={() => setAiPanelOpen(false)}
                  quickActions={[
                    { label: 'History', icon: 'history', action: () => undefined },
                    { label: 'Export', icon: 'download', action: () => undefined },
                  ]}
                />
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </main>
    </div>
  );
}

import { Bell, Menu, Search, Sparkles } from "lucide-react";
import { KeyboardEvent, useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";

import { TenantSwitcher } from "@/components/tenant/TenantSwitcher";
import { useAuth } from "@/contexts/AuthContext";
import { useCompanyValueContext } from "@/contexts/CompanyContextProvider";
import { useTenant } from "@/contexts/TenantContext";
import { useNavigationPersonalization } from "@/hooks/useNavigationPersonalization";
import { cn } from "@/lib/utils";

interface TopBarProps {
  onMenuClick?: () => void;
  onAgentOpen?: () => void;
}

const DEFAULT_SEARCH_PLACEHOLDER = "Search opportunities, models, agents...";



function getInitials(name: string): string {
  const chunks = name
    .split(" ")
    .map((part) => part.trim())
    .filter(Boolean)
    .slice(0, 2);

  if (chunks.length === 0) return "VO";
  return chunks.map((part) => part[0]?.toUpperCase() ?? "").join("");
}

export function TopBar({ onMenuClick, onAgentOpen }: TopBarProps) {
  const [searchFocused, setSearchFocused] = useState(false);
  const [query, setQuery] = useState("");
  const searchRef = useRef<HTMLInputElement>(null);
  const navigate = useNavigate();

  const { user } = useAuth();
  const { currentTenant } = useTenant();
  const { companyContext } = useCompanyValueContext();
  const { recentSearches, trackSearch, trackFeatureUsage } = useNavigationPersonalization();

  const orgName = useMemo(() => {
    const authMeta = user?.user_metadata as Record<string, unknown> | undefined;

    const candidates = [
      companyContext?.context.company_name,
      currentTenant?.name,
      typeof authMeta?.organization_name === "string" ? authMeta.organization_name : null,
      typeof authMeta?.org_name === "string" ? authMeta.org_name : null,
      typeof authMeta?.company_name === "string" ? authMeta.company_name : null,
    ];

    return candidates.find((entry) => typeof entry === "string" && entry.trim().length > 0)?.trim() ?? "Value Org";
  }, [companyContext?.context.company_name, currentTenant?.name, user?.user_metadata]);

  // orgInitials and planLabel removed — TenantSwitcher handles its own initials and plan display

  const personalizedPlaceholder = useMemo(() => {
    const recent = recentSearches[0];
    if (recent) return `Continue with "${recent}"`;

    if (companyContext?.context.industry) {
      return `Search ${companyContext.context.industry} opportunities, models, agents...`;
    }

    if (orgName !== "Value Org") {
      return `Search in ${orgName} workspace...`;
    }

    return DEFAULT_SEARCH_PLACEHOLDER;
  }, [companyContext?.context.industry, orgName, recentSearches]);

  const recentSuggestions = useMemo(() => {
    return recentSearches.slice(0, 3);
  }, [recentSearches]);

  const submitSearch = useCallback(() => {
    const trimmed = query.trim();
    if (!trimmed) return;

    trackSearch(trimmed);
    trackFeatureUsage("search");
    navigate(`/app/cases?q=${encodeURIComponent(trimmed)}`);
  }, [query, trackSearch, trackFeatureUsage, navigate]);

  const handleSearchKeyDown = (event: KeyboardEvent<HTMLInputElement>) => {
    if (event.key === "Enter") {
      submitSearch();
    } else if (event.key === "Escape") {
      searchRef.current?.blur();
    }
  };

  // Focus search on `/` keypress (when not already in an input)
  useEffect(() => {
    const handleGlobalKeyDown = (event: globalThis.KeyboardEvent) => {
      if (
        event.key === "/" &&
        document.activeElement?.tagName !== "INPUT" &&
        document.activeElement?.tagName !== "TEXTAREA" &&
        !(document.activeElement as HTMLElement)?.isContentEditable
      ) {
        event.preventDefault();
        searchRef.current?.focus();
      }
    };
    document.addEventListener("keydown", handleGlobalKeyDown);
    return () => document.removeEventListener("keydown", handleGlobalKeyDown);
  }, []);

  return (
    <header className="h-14 border-b border-border bg-background/95 backdrop-blur-sm flex items-center justify-between px-3 sm:px-4 lg:px-6 gap-2 sm:gap-4 flex-shrink-0 overflow-x-clip">
      {/* Left: mobile menu + org/tenant switcher */}
      <div className="flex items-center gap-2 sm:gap-3 min-w-0">
        {onMenuClick && (
          <button
            onClick={onMenuClick}
            aria-label="Open navigation menu"
            className="lg:hidden min-h-11 min-w-11 p-2.5 rounded-xl hover:bg-white/8 transition-colors inline-flex items-center justify-center flex-shrink-0"
          >
            <Menu className="w-5 h-5 text-muted-foreground" />
          </button>
        )}

        {/* Org / Tenant switcher */}
        <TenantSwitcher />

        {/* Tenant badge */}
        {currentTenant && (
          <div className="hidden sm:flex items-center gap-1.5 px-2.5 py-1 rounded-full border border-border bg-white/5 text-[11px] text-muted-foreground font-medium">
            <span
              className="w-1.5 h-1.5 rounded-full flex-shrink-0"
              style={{ backgroundColor: currentTenant.color || "#08A0A0" }}
            />
            <span className="truncate max-w-[6rem]">{currentTenant.name}</span>
          </div>
        )}
      </div>

      {/* Center: search */}
      <div className="hidden md:block flex-1 max-w-md mx-2 lg:mx-4 min-w-0">
        <div
          className={cn(
            "flex items-center gap-2 px-3 min-h-9 rounded-lg border transition-colors duration-150",
            searchFocused
              ? "border-primary/60 bg-background ring-2 ring-primary/10"
              : "border-border bg-muted/40 hover:bg-muted/60 hover:border-border"
          )}
        >
          <Search className={cn("w-4 h-4 flex-shrink-0 transition-colors", searchFocused ? "text-primary" : "text-muted-foreground")} />
          <input
            ref={searchRef}
            type="text"
            placeholder={personalizedPlaceholder}
            value={query}
            className="flex-1 bg-transparent text-[13px] text-foreground placeholder:text-muted-foreground outline-none"
            onFocus={() => setSearchFocused(true)}
            onBlur={() => setSearchFocused(false)}
            onChange={(event) => setQuery(event.target.value)}
            onKeyDown={handleSearchKeyDown}
          />
          {!searchFocused && (
            <kbd className="hidden sm:inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded border border-border bg-background text-[10px] text-muted-foreground font-mono">
              /
            </kbd>
          )}
        </div>

        {recentSuggestions.length > 0 && (
          <div className="hidden sm:flex items-center gap-2 mt-1 text-[11px] text-muted-foreground overflow-hidden">
            <span>Recent:</span>
            {recentSuggestions.map((suggestion) => (
              <button
                key={suggestion}
                type="button"
                className="px-2 py-0.5 rounded-full bg-white/8 hover:bg-white/12 text-muted-foreground truncate max-w-[8rem]"
                onMouseDown={(event) => event.preventDefault()}
                onClick={() => {
                  setQuery(suggestion);
                  trackSearch(suggestion);
                  trackFeatureUsage("search");
                }}
              >
                {suggestion}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Right: actions */}
      <div className="flex items-center gap-2 sm:gap-3 flex-shrink-0">
        {/* Notifications */}
        <button
          aria-label="Open notifications"
          onClick={() => trackFeatureUsage("notifications")}
          className="relative min-h-9 min-w-9 p-2 rounded-xl hover:bg-white/8 transition-colors inline-flex items-center justify-center"
        >
          <Bell className="w-[17px] h-[17px] text-muted-foreground" />
          <span className="absolute top-1.5 right-1.5 w-1.5 h-1.5 bg-destructive rounded-full" />
        </button>

        {/* Agent quick action */}
        <button
          type="button"
          onClick={() => {
            trackFeatureUsage("ask_agent");
            onAgentOpen?.();
          }}
          className="flex items-center justify-center gap-2 px-3 sm:px-4 h-9 bg-primary text-primary-foreground rounded-xl text-[13px] font-medium hover:bg-primary/90 active:scale-[0.98] transition-all duration-150 whitespace-nowrap"
        >
          <Sparkles className="w-3.5 h-3.5" />
          <span className="hidden sm:inline">Ask Agent</span>
        </button>
      </div>
    </header>
  );
}

import { logger } from "../../utils/logger";

import type { LLMProvider, LLMProviderConfig } from "./LLMGateway";

export interface SafetyPolicy {
  maxTokensPerRequest?: number;
  maxRequestsPerMinute?: number;
  allowedModels?: string[];
  blockPII?: boolean;
}

export interface FabricConfig {
  costs: {
    budget: Record<string, number>; // env -> budget amount
    currentSpend: Record<string, number>; // env -> current spend
    alerts: { threshold: number; email: string }[];
  };
  safety: {
    global: SafetyPolicy;
    perAgent: Record<string, SafetyPolicy>;
  };
  providers: {
    enabled: LLMProvider[];
    fallbackOrder: LLMProvider[];
    configs: Record<LLMProvider, LLMProviderConfig>;
  };
}

export class ConfigurationManager {
  private static instance: ConfigurationManager;
  private config: FabricConfig;

  private constructor() {
    this.config = this.getDefaultConfig();
  }

  public static getInstance(): ConfigurationManager {
    if (!ConfigurationManager.instance) {
      ConfigurationManager.instance = new ConfigurationManager();
    }
    return ConfigurationManager.instance;
  }

  public getConfig(): FabricConfig {
    return this.config;
  }

  public updateConfig(partialConfig: Partial<FabricConfig>): void {
    this.config = {
      ...this.config,
      ...partialConfig,
      costs: partialConfig.costs ? { ...this.config.costs, ...partialConfig.costs } : this.config.costs,
      safety: partialConfig.safety ? { ...this.config.safety, ...partialConfig.safety } : this.config.safety,
      providers: partialConfig.providers ? { ...this.config.providers, ...partialConfig.providers } : this.config.providers,
    };
    logger.info("Configuration updated");
  }

  public reset(): void {
    this.config = this.getDefaultConfig();
  }

  public checkSafety(agentId: string, request: unknown): { safe: boolean; reason?: string } {
    const globalPolicy = this.config.safety.global;
    const agentPolicy = this.config.safety.perAgent[agentId] || {};
    const effectivePolicy = { ...globalPolicy, ...agentPolicy };

    if (
      effectivePolicy.maxTokensPerRequest &&
      request.maxTokens &&
      request.maxTokens > effectivePolicy.maxTokensPerRequest
    ) {
      return {
        safe: false,
        reason: `Max tokens per request exceeded: ${request.maxTokens} > ${effectivePolicy.maxTokensPerRequest}`,
      };
    }
    return { safe: true };
  }

  public trackCost(env: string, cost: number): void {
    if (!this.config.costs.currentSpend[env]) {
      this.config.costs.currentSpend[env] = 0;
    }
    this.config.costs.currentSpend[env] += cost;

    const budget = this.config.costs.budget[env];
    if (budget) {
      const spend = this.config.costs.currentSpend[env];
      const percentage = (spend / budget) * 100;
      this.config.costs.alerts.forEach((alert) => {
        if (percentage >= alert.threshold) {
          logger.warn(`Budget alert: ${percentage.toFixed(1)}% used`, { env, spend, budget });
        }
      });
    }
  }

  private getDefaultConfig(): FabricConfig {
    return {
      costs: {
        budget: { development: 100, staging: 500, production: 1000 },
        currentSpend: {},
        alerts: [{ threshold: 80, email: "admin@example.com" }],
      },
      safety: {
        global: { maxTokensPerRequest: 4000, blockPII: true },
        perAgent: {},
      },
      providers: {
        enabled: ["openai"],
        fallbackOrder: ["openai"],
        configs: {} as Record<LLMProvider, LLMProviderConfig>,
      },
    };
  }
}

/**
 * AgentStateMachine — P1 transition tests
 *
 * Covers:
 * - All 11 valid transitions succeed from the correct from-state
 * - Invalid transitions return false and leave state unchanged
 * - Each successful transition appends an AgentEvent to history
 * - Subscribers are notified with the new state and event
 * - reset() returns state to idle and clears history
 * - createAgentStateMachine() factory produces a fresh idle machine
 */

import { describe, expect, it, vi } from "vitest";

import { AgentStateMachine, createAgentStateMachine } from "../stateMachine";

// ---------------------------------------------------------------------------
// Valid transitions (mirrors the validTransitions array in stateMachine.ts)
// ---------------------------------------------------------------------------

const VALID_TRANSITIONS = [
  { from: "idle", event: "START", to: "planning" },
  { from: "planning", event: "PLAN_APPROVED", to: "executing" },
  { from: "planning", event: "NEED_INPUT", to: "waiting" },
  { from: "planning", event: "ERROR", to: "error" },
  { from: "executing", event: "DONE", to: "completed" },
  { from: "executing", event: "NEED_INPUT", to: "waiting" },
  { from: "executing", event: "ERROR", to: "error" },
  { from: "waiting", event: "INPUT_RECEIVED", to: "planning" },
  { from: "waiting", event: "CONTINUE", to: "executing" },
  { from: "error", event: "RESET", to: "idle" },
  { from: "completed", event: "RESET", to: "idle" },
] as const;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/**
 * Drive the machine from idle to the given state by replaying the shortest
 * known path through VALID_TRANSITIONS.
 */
function driveToState(machine: AgentStateMachine, target: string): void {
  const paths: Record<string, string[]> = {
    idle: [],
    planning: ["START"],
    executing: ["START", "PLAN_APPROVED"],
    waiting: ["START", "NEED_INPUT"],
    completed: ["START", "PLAN_APPROVED", "DONE"],
    error: ["START", "ERROR"],
  };
  const events = paths[target];
  if (!events) throw new Error(`No known path to state: ${target}`);
  for (const event of events) {
    machine.transition(event);
  }
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("AgentStateMachine — valid transitions", () => {
  it.each(VALID_TRANSITIONS)(
    "transitions from $from on $event to $to",
    ({ from, event, to }) => {
      const machine = new AgentStateMachine();
      driveToState(machine, from);

      const result = machine.transition(event);

      expect(result).toBe(true);
      expect(machine.getState()).toBe(to);
    },
  );
});

describe("AgentStateMachine — invalid transition rejection", () => {
  it("returns false for an event that has no transition from the current state", () => {
    const machine = new AgentStateMachine();
    // idle → DONE is not a valid transition
    const result = machine.transition("DONE");

    expect(result).toBe(false);
    expect(machine.getState()).toBe("idle");
  });

  it("does not change state on an invalid transition", () => {
    const machine = new AgentStateMachine();
    machine.transition("START"); // → planning

    // DONE is only valid from executing, not planning
    machine.transition("DONE");

    expect(machine.getState()).toBe("planning");
  });

  it("returns false for an unknown event name", () => {
    const machine = new AgentStateMachine();
    const result = machine.transition("NONEXISTENT_EVENT");

    expect(result).toBe(false);
    expect(machine.getState()).toBe("idle");
  });

  it("returns false when trying to START from completed", () => {
    const machine = new AgentStateMachine();
    driveToState(machine, "completed");

    const result = machine.transition("START");

    expect(result).toBe(false);
    expect(machine.getState()).toBe("completed");
  });
});

describe("AgentStateMachine — history recording", () => {
  it("starts with an empty history", () => {
    const machine = new AgentStateMachine();
    expect(machine.getHistory()).toHaveLength(0);
  });

  it("appends one AgentEvent per successful transition", () => {
    const machine = new AgentStateMachine();
    machine.transition("START");
    machine.transition("PLAN_APPROVED");

    const history = machine.getHistory();
    expect(history).toHaveLength(2);
  });

  it("does not append to history on invalid transitions", () => {
    const machine = new AgentStateMachine();
    machine.transition("DONE"); // invalid from idle

    expect(machine.getHistory()).toHaveLength(0);
  });

  it("each history entry has type state_change with from/to/event data", () => {
    const machine = new AgentStateMachine();
    machine.transition("START");

    const [entry] = machine.getHistory();
    expect(entry.type).toBe("state_change");
    expect(entry.timestamp).toBeTruthy();
    expect((entry.data as Record<string, unknown>).from).toBe("idle");
    expect((entry.data as Record<string, unknown>).to).toBe("planning");
    expect((entry.data as Record<string, unknown>).event).toBe("START");
  });

  it("getHistory returns a copy — mutations do not affect internal state", () => {
    const machine = new AgentStateMachine();
    machine.transition("START");

    const history = machine.getHistory();
    history.pop(); // mutate the returned array

    expect(machine.getHistory()).toHaveLength(1);
  });
});

describe("AgentStateMachine — subscriber notification", () => {
  it("calls subscriber with new state and event on each transition", () => {
    const machine = new AgentStateMachine();
    const listener = vi.fn();
    machine.subscribe(listener);

    machine.transition("START");

    expect(listener).toHaveBeenCalledOnce();
    expect(listener).toHaveBeenCalledWith(
      "planning",
      expect.objectContaining({ type: "state_change" }),
    );
  });

  it("calls multiple subscribers", () => {
    const machine = new AgentStateMachine();
    const listenerA = vi.fn();
    const listenerB = vi.fn();
    machine.subscribe(listenerA);
    machine.subscribe(listenerB);

    machine.transition("START");

    expect(listenerA).toHaveBeenCalledOnce();
    expect(listenerB).toHaveBeenCalledOnce();
  });

  it("does not call subscriber on invalid transitions", () => {
    const machine = new AgentStateMachine();
    const listener = vi.fn();
    machine.subscribe(listener);

    machine.transition("DONE"); // invalid from idle

    expect(listener).not.toHaveBeenCalled();
  });

  it("unsubscribe stops future notifications", () => {
    const machine = new AgentStateMachine();
    const listener = vi.fn();
    const unsubscribe = machine.subscribe(listener);

    unsubscribe();
    machine.transition("START");

    expect(listener).not.toHaveBeenCalled();
  });
});

describe("AgentStateMachine — reset", () => {
  it("returns state to idle after reset from completed", () => {
    const machine = new AgentStateMachine();
    driveToState(machine, "completed");

    machine.reset();

    expect(machine.getState()).toBe("idle");
  });

  it("clears history on reset", () => {
    const machine = new AgentStateMachine();
    machine.transition("START");
    machine.transition("PLAN_APPROVED");

    machine.reset();

    expect(machine.getHistory()).toHaveLength(0);
  });

  it("allows transitions from idle after reset", () => {
    const machine = new AgentStateMachine();
    driveToState(machine, "error");
    machine.transition("RESET"); // → idle via valid transition
    machine.reset(); // explicit reset

    const result = machine.transition("START");
    expect(result).toBe(true);
    expect(machine.getState()).toBe("planning");
  });
});

describe("createAgentStateMachine factory", () => {
  it("creates a machine in idle state", () => {
    const machine = createAgentStateMachine();
    expect(machine.getState()).toBe("idle");
  });

  it("creates independent instances", () => {
    const a = createAgentStateMachine();
    const b = createAgentStateMachine();

    a.transition("START");

    expect(a.getState()).toBe("planning");
    expect(b.getState()).toBe("idle");
  });
});

/**
 * Agent health check via backend API.
 *
 * Replaces the direct AgentInitializer service call. The frontend has no
 * business instantiating agents — it checks their health through the API.
 */

export interface AgentHealthStatus {
  agent: string;
  available: boolean;
  responseTime?: number;
}

export interface SystemHealth {
  healthy: boolean;
  agents: AgentHealthStatus[];
  totalAgents: number;
  availableAgents: number;
  unavailableAgents: number;
  averageResponseTime: number;
}

export interface AgentInitOptions {
  healthCheckTimeout?: number;
  failFast?: boolean;
  retryAttempts?: number;
  retryDelay?: number;
  onProgress?: (status: AgentHealthStatus) => void;
  onComplete?: (health: SystemHealth) => void;
  onError?: (error: Error, health: SystemHealth) => void;
}

const FALLBACK_HEALTH: SystemHealth = {
  healthy: false,
  agents: [],
  totalAgents: 0,
  availableAgents: 0,
  unavailableAgents: 0,
  averageResponseTime: 0,
};

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export async function initializeAgents(options: AgentInitOptions = {}): Promise<SystemHealth> {
  const {
    healthCheckTimeout = 5000,
    retryAttempts = 3,
    retryDelay = 1000,
  } = options;

  for (let attempt = 0; attempt <= retryAttempts; attempt++) {
    if (attempt > 0) {
      await sleep(retryDelay);
    }

    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), healthCheckTimeout);

    try {

    // eslint-disable-next-line no-restricted-globals
      const res = await fetch("/health/dependencies", { signal: controller.signal });
      clearTimeout(timer);

      if (!res.ok) {
        clearTimeout(timer);
        continue;
      }

      // Backend health endpoint returns service statuses; map to SystemHealth shape.
      const data = (await res.json()) as Record<string, unknown>;
      const agentStatus = data["agents"] as { available?: boolean } | undefined;
      const available = agentStatus?.available !== false;

      const health: SystemHealth = {
        healthy: available,
        agents: [],
        totalAgents: 1,
        availableAgents: available ? 1 : 0,
        unavailableAgents: available ? 0 : 1,
        averageResponseTime: 0,
      };

      options.onComplete?.(health);
      return health;
    } catch {
      clearTimeout(timer);
      // Retry on network/abort errors up to retryAttempts.
    }
  }

  options.onError?.(new Error("Agent health check failed"), FALLBACK_HEALTH);
  return FALLBACK_HEALTH;
}


/**
 * Security Audit Logger
 * Comprehensive audit logging for compliance and security monitoring
 */

import { apiClient } from "@/api/client/unified-api-client";

export interface AuditEvent {
  id: string;
  timestamp: number;
  userId?: string;
  email?: string;
  sessionId?: string;
  ipAddress?: string;
  userAgent?: string;
  action: string;
  resource: string;
  result: "success" | "failure" | "error";
  details: Record<string, unknown>;
  severity: "low" | "medium" | "high" | "critical";
  category: "authentication" | "authorization" | "data_access" | "configuration" | "security";
  source: "frontend" | "backend";
  compliance: boolean; // Whether this is a compliance-relevant event
}

export interface AuditFilter {
  startDate?: Date;
  endDate?: Date;
  userId?: string;
  action?: string;
  resource?: string;
  severity?: AuditEvent["severity"];
  category?: AuditEvent["category"];
  result?: AuditEvent["result"];
  compliance?: boolean;
}

export interface AuditSummary {
  totalEvents: number;
  eventsByCategory: Record<string, number>;
  eventsBySeverity: Record<string, number>;
  eventsByResult: Record<string, number>;
  complianceEvents: number;
  criticalEvents: number;
  timeRange: { start: Date; end: Date };
}

class AuditLogger {
  private static instance: AuditLogger;
  private events: AuditEvent[] = [];
  private readonly maxEvents = 10000; // Keep last 10k events
  private readonly batchSize = 100; // Send in batches
  private sendTimer: NodeJS.Timeout | null = null;
  private pendingEvents: AuditEvent[] = [];

  private constructor() {
    this.setupBatchSending();
  }

  static getInstance(): AuditLogger {
    if (!AuditLogger.instance) {
      AuditLogger.instance = new AuditLogger();
    }
    return AuditLogger.instance;
  }

  /**
   * Log an audit event
   */
  logEvent(event: Omit<AuditEvent, "id" | "timestamp" | "source">): void {
    const auditEvent: AuditEvent = {
      ...event,
      id: this.generateEventId(),
      timestamp: Date.now(),
      source: "frontend",
    };

    // Add to in-memory storage
    this.events.push(auditEvent);
    if (this.events.length > this.maxEvents) {
      this.events.shift();
    }

    // Add to pending batch
    this.pendingEvents.push(auditEvent);

    // Log to console in development
    if (process.env.NODE_ENV === "development") {
      this.logToConsole(auditEvent);
    }

    // Trigger batch send if needed
    if (this.pendingEvents.length >= this.batchSize) {
      this.sendBatch();
    }
  }

  /**
   * Log authentication events
   */
  logAuthentication(
    action: string,
    result: "success" | "failure",
    details: Record<string, unknown>,
    userId?: string,
    email?: string
  ): void {
    this.logEvent({
      action: `auth.${action}`,
      resource: "authentication",
      result,
      details,
      severity: result === "failure" ? "medium" : "low",
      category: "authentication",
      compliance: true,
      userId,
      email,
    });
  }

  /**
   * Log authorization events
   */
  logAuthorization(
    action: string,
    resource: string,
    result: "success" | "failure",
    details: Record<string, unknown>,
    userId?: string
  ): void {
    this.logEvent({
      action: `authz.${action}`,
      resource,
      result,
      details,
      severity: result === "failure" ? "high" : "low",
      category: "authorization",
      compliance: true,
      userId,
    });
  }

  /**
   * Log data access events
   */
  logDataAccess(
    action: string,
    resource: string,
    result: "success" | "failure",
    details: Record<string, unknown>,
    userId?: string
  ): void {
    this.logEvent({
      action: `data.${action}`,
      resource,
      result,
      details,
      severity: "low",
      category: "data_access",
      compliance: true,
      userId,
    });
  }

  /**
   * Log configuration changes
   */
  logConfiguration(
    action: string,
    resource: string,
    result: "success" | "failure",
    details: Record<string, unknown>,
    userId?: string
  ): void {
    this.logEvent({
      action: `config.${action}`,
      resource,
      result,
      details,
      severity: "medium",
      category: "configuration",
      compliance: true,
      userId,
    });
  }

  /**
   * Log security events
   */
  logSecurity(
    action: string,
    resource: string,
    result: "success" | "failure",
    details: Record<string, unknown>,
    severity: "medium" | "high" | "critical" = "medium",
    userId?: string
  ): void {
    this.logEvent({
      action: `security.${action}`,
      resource,
      result,
      details,
      severity,
      category: "security",
      compliance: true,
      userId,
    });
  }

  /**
   * Get audit events with filtering
   */
  getEvents(filter?: AuditFilter): AuditEvent[] {
    let filtered = [...this.events];

    if (filter) {
      if (filter.startDate) {
        filtered = filtered.filter((event) => event.timestamp >= filter.startDate?.getTime?.());
      }

      if (filter.endDate) {
        filtered = filtered.filter((event) => event.timestamp <= filter.endDate?.getTime?.());
      }

      if (filter.userId) {
        filtered = filtered.filter((event) => event.userId === filter.userId);
      }

      if (filter.action) {
        filtered = filtered.filter((event) => event.action.includes(filter.action!));
      }

      if (filter.resource) {
        filtered = filtered.filter((event) => event.resource.includes(filter.resource!));
      }

      if (filter.severity) {
        filtered = filtered.filter((event) => event.severity === filter.severity);
      }

      if (filter.category) {
        filtered = filtered.filter((event) => event.category === filter.category);
      }

      if (filter.result) {
        filtered = filtered.filter((event) => event.result === filter.result);
      }

      if (filter.compliance !== undefined) {
        filtered = filtered.filter((event) => event.compliance === filter.compliance);
      }
    }

    return filtered.sort((a, b) => b.timestamp - a.timestamp);
  }

  /**
   * Get audit summary
   */
  getSummary(filter?: AuditFilter): AuditSummary {
    const events = this.getEvents(filter);

    const summary: AuditSummary = {
      totalEvents: events.length,
      eventsByCategory: {},
      eventsBySeverity: {},
      eventsByResult: {},
      complianceEvents: 0,
      criticalEvents: 0,
      timeRange: {
        start: new Date(Math.min(...events.map((e) => e.timestamp))),
        end: new Date(Math.max(...events.map((e) => e.timestamp))),
      },
    };

    events.forEach((event) => {
      // Category breakdown
      summary.eventsByCategory[event.category] =
        (summary.eventsByCategory[event.category] || 0) + 1;

      // Severity breakdown
      summary.eventsBySeverity[event.severity] =
        (summary.eventsBySeverity[event.severity] || 0) + 1;

      // Result breakdown
      summary.eventsByResult[event.result] = (summary.eventsByResult[event.result] || 0) + 1;

      // Compliance events
      if (event.compliance) {
        summary.complianceEvents++;
      }

      // Critical events
      if (event.severity === "critical") {
        summary.criticalEvents++;
      }
    });

    return summary;
  }

  /**
   * Get compliance report
   */
  getComplianceReport(
    startDate: Date,
    endDate: Date
  ): {
    totalEvents: number;
    complianceEvents: number;
    complianceRate: number;
    violations: Array<{
      timestamp: Date;
      action: string;
      details: Record<string, unknown>;
      severity: string;
    }>;
    recommendations: string[];
  } {
    const filter: AuditFilter = {
      startDate,
      endDate,
      compliance: true,
    };

    const events = this.getEvents(filter);
    const violations = events.filter(
      (event) => event.result === "failure" || event.severity === "critical"
    );

    const recommendations = this.generateComplianceRecommendations(violations);

    return {
      totalEvents: events.length,
      complianceEvents: events.length,
      complianceRate:
        events.length > 0
          ? (events.filter((e) => e.result === "success").length / events.length) * 100
          : 100,
      violations: violations.map((event) => ({
        timestamp: new Date(event.timestamp),
        action: event.action,
        details: event.details,
        severity: event.severity,
      })),
      recommendations,
    };
  }

  /**
   * Export audit data
   */
  exportData(filter?: AuditFilter, format: "json" | "csv" = "json"): string {
    const events = this.getEvents(filter);

    if (format === "csv") {
      return this.exportToCSV(events);
    }

    return JSON.stringify(
      {
        exportDate: new Date().toISOString(),
        filter,
        events,
        summary: this.getSummary(filter),
      },
      null,
      2
    );
  }

  /**
   * Clear audit events
   */
  clear(): void {
    this.events = [];
    this.pendingEvents = [];
  }

  /**
   * Generate unique event ID
   */
  private generateEventId(): string {
    return `audit_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  /**
   * Setup batch sending
   */
  private setupBatchSending(): void {
    // Skip in test environments — the interval keeps the Node process alive
    // after all tests finish, causing the suite to hang.
    if (process.env.NODE_ENV === "test" || process.env.TEST_MODE === "true") {
      return;
    }
    // Send batch every 30 seconds
    this.sendTimer = setInterval(() => {
      if (this.pendingEvents.length > 0) {
        this.sendBatch();
      }
    }, 30000);
    // Allow the process to exit even if this timer is still pending.
    if (this.sendTimer && typeof (this.sendTimer as NodeJS.Timeout).unref === "function") {
      (this.sendTimer as NodeJS.Timeout).unref();
    }
  }

  /**
   * Send batch of events to server
   */
  private async sendBatch(): Promise<void> {
    if (this.pendingEvents.length === 0) return;

    const batch = [...this.pendingEvents];
    this.pendingEvents = [];

    try {
      if (process.env.NODE_ENV === "production") {
        await apiClient.post("/api/audit/events", {
          events: batch,
          clientTimestamp: Date.now(),
        });
      }
    } catch (error) {
      console.error("Failed to send audit batch:", error);
      // Re-add events to pending for retry
      this.pendingEvents.unshift(...batch);
    }
  }

  /**
   * Log to console in development
   */
  private logToConsole(event: AuditEvent): void {
    const logMethod = this.getConsoleMethod(event.severity);
    logMethod(`[AUDIT] ${event.action.toUpperCase()} - ${event.result.toUpperCase()}`, {
      id: event.id,
      userId: event.userId,
      resource: event.resource,
      category: event.category,
      compliance: event.compliance,
      timestamp: new Date(event.timestamp).toISOString(),
      details: event.details,
    });
  }

  /**
   * Get appropriate console method for severity
   */
  private getConsoleMethod(severity: AuditEvent["severity"]): typeof console.log {
    switch (severity) {
      case "critical":
        return console.error;
      case "high":
        // eslint-disable-next-line no-console
        return console.warn;
      case "medium":
        // eslint-disable-next-line no-console
        return console.warn;
      case "low":

        // eslint-disable-next-line no-console
        return console.info;
      default:

        // eslint-disable-next-line no-console
        return console.log;
    }
  }

  /**
   * Export events to CSV format
   */
  private exportToCSV(events: AuditEvent[]): string {
    const headers = [
      "ID",
      "Timestamp",
      "User ID",
      "Email",
      "Session ID",
      "IP Address",
      "User Agent",
      "Action",
      "Resource",
      "Result",
      "Severity",
      "Category",
      "Compliance",
      "Details",
    ];

    const rows = events.map((event) => [
      event.id,
      new Date(event.timestamp).toISOString(),
      event.userId || "",
      event.email || "",
      event.sessionId || "",
      event.ipAddress || "",
      event.userAgent || "",
      event.action,
      event.resource,
      event.result,
      event.severity,
      event.category,
      event.compliance,
      JSON.stringify(event.details),
    ]);

    return [headers, ...rows].map((row) => row.map((cell) => `"${cell}"`).join(",")).join("\n");
  }

  /**
   * Generate compliance recommendations
   */
  private generateComplianceRecommendations(violations: AuditEvent[]): string[] {
    const recommendations: string[] = [];
    const violationTypes = new Set(violations.map((v) => v.action));

    // Authentication violations
    if (violationTypes.has("auth.login_failure")) {
      recommendations.push("Consider implementing additional authentication security measures");
    }

    // Authorization violations
    if (violationTypes.has("authz.access_denied")) {
      recommendations.push("Review and update access control policies");
    }

    // Security violations
    if (violations.some((v) => v.category === "security")) {
      recommendations.push("Investigate security violations and implement preventive measures");
    }

    // High failure rate
    const failureRate = violations.length / this.events.length;
    if (failureRate > 0.1) {
      // 10% failure rate
      recommendations.push(
        "High failure rate detected - review system reliability and user experience"
      );
    }

    // Critical events
    if (violations.some((v) => v.severity === "critical")) {
      recommendations.push("Critical security events detected - immediate investigation required");
    }

    return recommendations;
  }

  /**
   * Cleanup on page unload
   */
  cleanup(): void {
    if (this.sendTimer) {
      clearInterval(this.sendTimer);
      this.sendTimer = null;
    }

    // Send any remaining events
    if (this.pendingEvents.length > 0) {
      this.sendBatch();
    }
  }
}

