export function sanitizeForLogging(data: unknown): unknown {
  if (data === null || data === undefined) return data;
  if (typeof data !== "object") return data;
  const result: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(data as Record<string, unknown>)) {
    result[key] = PII_KEYS.has(key.toLowerCase()) ? "[REDACTED]" : value;
  }
  return result;
}

export function sanitizeUser(user: Record<string, unknown>): Record<string, unknown> {
  const { password: _p, token: _t, secret: _s, ...safe } = user;
  return safe;
}

/**
 * Rate Limiter for Authentication Attempts
 * Prevents brute force attacks by limiting authentication attempts.
 *
 * IMPORTANT: Browser-side counters are UX-only hints. They are easy to clear
 * and must never be treated as authoritative security enforcement.
 *
 * Authoritative lockout and retry policy MUST come from backend responses
 * (for example HTTP 429 plus retry metadata).
 */

import { logger } from "@/lib/logger";

interface RateLimitEntry {
  attempts: number;
  firstAttempt: number;
  lastAttempt: number;
  isLocked: boolean;
  lockUntil?: number;
}

/**
 * API contract for backend-provided lockout metadata.
 *
 * This is the authoritative source for lockout messaging/state in UI flows.
 * LocalStorage-based values are only a fallback when backend metadata is absent.
 */
export interface AuthLockoutMetadata {
  locked: boolean;
  retryAfterSeconds?: number;
  remainingAttempts?: number;
}

export class AuthRateLimitError extends Error {
  readonly status?: number;
  readonly lockout: AuthLockoutMetadata;

  constructor(message: string, lockout: AuthLockoutMetadata, status?: number) {
    super(message);
    this.name = "AuthRateLimitError";
    this.lockout = lockout;
    this.status = status;
  }
}

const isRecord = (value: unknown): value is Record<string, unknown> =>
  typeof value === "object" && value !== null;

const asOptionalNumber = (value: unknown): number | undefined =>
  typeof value === "number" && Number.isFinite(value) ? value : undefined;

const asOptionalBoolean = (value: unknown): boolean | undefined =>
  typeof value === "boolean" ? value : undefined;

/**
 * Extracts lockout metadata from backend error-like objects.
 *
 * Supports either top-level fields or nested `{ lockout: { ... } }`.
 */
export const parseAuthLockoutMetadata = (
  value: unknown,
): AuthLockoutMetadata | undefined => {
  if (!isRecord(value)) {
    return undefined;
  }

  const candidate = isRecord(value.lockout) ? value.lockout : value;
  const locked = asOptionalBoolean(candidate.locked);
  if (typeof locked !== "boolean") {
    return undefined;
  }

  return {
    locked,
    retryAfterSeconds: asOptionalNumber(candidate.retryAfterSeconds),
    remainingAttempts: asOptionalNumber(candidate.remainingAttempts),
  };
};

class AuthRateLimiter {
  private readonly storageKey = "auth_rate_limit";
  private readonly maxAttempts = 5; // Maximum failed attempts
  private readonly lockoutDuration = 15 * 60 * 1000; // 15 minutes
  private readonly windowDuration = 5 * 60 * 1000; // 5 minutes window

  /**
   * Get rate limit data for an identifier (email/IP)
   *
   * NOTE: data is local and mutable by the user; this is not an enforcement source.
   */
  private getRateLimitData(identifier: string): RateLimitEntry {
    try {
      const data = localStorage.getItem(`${this.storageKey}_${identifier}`);
      return data
        ? JSON.parse(data)
        : {
            attempts: 0,
            firstAttempt: Date.now(),
            lastAttempt: Date.now(),
            isLocked: false,
          };
    } catch (error) {
      return {
        attempts: 0,
        firstAttempt: Date.now(),
        lastAttempt: Date.now(),
        isLocked: false,
      };
    }
  }

  /**
   * Save rate limit data for an identifier
   *
   * NOTE: writes to localStorage can fail and are not security guarantees.
   */
  private setRateLimitData(identifier: string, data: RateLimitEntry): void {
    try {
      localStorage.setItem(`${this.storageKey}_${identifier}`, JSON.stringify(data));
    } catch (error) {
      logger.error("Failed to save rate limit data", error);
    }
  }

  /**
   * Check if authentication is allowed for an identifier
   *
   * NOTE: this should only be used for non-authoritative UX guidance.
   */
  canAttemptAuth(identifier: string): {
    allowed: boolean;
    remainingAttempts: number;
    lockoutRemaining?: number;
  } {
    const data = this.getRateLimitData(identifier);
    const now = Date.now();

    // Check if currently locked out
    if (data.isLocked && data.lockUntil && data.lockUntil > now) {
      return {
        allowed: false,
        remainingAttempts: 0,
        lockoutRemaining: Math.ceil((data.lockUntil - now) / 1000 / 60), // minutes
      };
    }

    // Reset if window has expired
    if (now - data.firstAttempt > this.windowDuration) {
      this.setRateLimitData(identifier, {
        attempts: 0,
        firstAttempt: now,
        lastAttempt: now,
        isLocked: false,
      });
      return { allowed: true, remainingAttempts: this.maxAttempts };
    }

    const remainingAttempts = Math.max(0, this.maxAttempts - data.attempts);

    return {
      allowed: remainingAttempts > 0,
      remainingAttempts,
    };
  }

  /**
   * Record a failed authentication attempt
   *
   * NOTE: local tracking is a fallback for messaging only.
   */
  recordFailedAttempt(identifier: string): { isLocked: boolean; lockoutRemaining?: number } {
    const data = this.getRateLimitData(identifier);
    const now = Date.now();

    // Reset if window has expired
    if (now - data.firstAttempt > this.windowDuration) {
      data.attempts = 0;
      data.firstAttempt = now;
    }

    data.attempts += 1;
    data.lastAttempt = now;

    // Check if should lock out
    if (data.attempts >= this.maxAttempts) {
      data.isLocked = true;
      data.lockUntil = now + this.lockoutDuration;
    }

    this.setRateLimitData(identifier, data);

    if (data.isLocked && data.lockUntil) {
      return {
        isLocked: true,
        lockoutRemaining: Math.ceil((data.lockUntil - now) / 1000 / 60),
      };
    }

    return { isLocked: false };
  }

  /**
   * Record a successful authentication attempt (reset counter)
   *
   * NOTE: clearing local data does not override backend lockout state.
   */
  recordSuccessfulAttempt(identifier: string): void {
    try {
      localStorage.removeItem(`${this.storageKey}_${identifier}`);
    } catch (error) {
      logger.error("Failed to clear rate limit data", error);
    }
  }

  /**
   * Get rate limit status for UI display
   *
   * NOTE: do not treat this as security state; backend state is authoritative.
   */
  getRateLimitStatus(identifier: string): {
    attempts: number;
    maxAttempts: number;
    isLocked: boolean;
    lockoutRemaining?: number;
  } {
    const data = this.getRateLimitData(identifier);
    const now = Date.now();

    let lockoutRemaining;
    if (data.isLocked && data.lockUntil && data.lockUntil > now) {
      lockoutRemaining = Math.ceil((data.lockUntil - now) / 1000 / 60);
    }

    return {
      attempts: data.attempts,
      maxAttempts: this.maxAttempts,
      isLocked: data.isLocked && (!data.lockUntil || data.lockUntil > now),
      lockoutRemaining,
    };
  }

  /**
   * Clear all rate limit data (for testing/admin)
   */
  clearAllData(): void {
    try {
      const keys = Object.keys(localStorage);
      keys.forEach((key) => {
        if (key.startsWith(this.storageKey)) {
          localStorage.removeItem(key);
        }
      });
    } catch (error) {
      logger.error("Failed to clear rate limit data", error);
    }
  }
}

// Export singleton instance
export const authRateLimiter = new AuthRateLimiter();

// /workspaces/ValueOS/src/lib/safeExpressionEvaluator.ts
/**
 * Safe Mathematical Expression Evaluator
 *
 * This module provides a secure way to evaluate mathematical expressions
 * without using eval() or new Function(), preventing code injection attacks.
 */

// Allowed mathematical functions and constants
const ALLOWED_FUNCTIONS = new Set([
  "abs",
  "acos",
  "acosh",
  "asin",
  "asinh",
  "atan",
  "atanh",
  "atan2",
  "cbrt",
  "ceil",
  "cos",
  "cosh",
  "exp",
  "expm1",
  "floor",
  "fround",
  "hypot",
  "log",
  "log10",
  "log1p",
  "log2",
  "max",
  "min",
  "pow",
  "round",
  "sign",
  "sin",
  "sinh",
  "sqrt",
  "tan",
  "tanh",
  "trunc",
]);

const ALLOWED_CONSTANTS = new Set([
  "E",
  "PI",
  "SQRT2",
  "SQRT1_2",
  "LN2",
  "LN10",
  "LOG2E",
  "LOG10E",
]);

/**
 * Tokenizes a mathematical expression
 */
function tokenizeExpression(expression: string): string[] {
  const tokens: string[] = [];
  let current = "";

  for (let i = 0; i < expression.length; i++) {
    const char = expression[i];
    const nextChar = expression[i + 1];

    if (/\s/.test(char)) {
      if (current) tokens.push(current);
      current = "";
      continue;
    }

    if (/[+\-*/()^,]/.test(char)) {
      if (current) tokens.push(current);
      tokens.push(char);
      current = "";
      continue;
    }

    if (/[<>=!&|]/.test(char)) {
      if (current) tokens.push(current);

      if ((char === "&" && nextChar === "&") || (char === "|" && nextChar === "|")) {
        tokens.push(`${char}${nextChar}`);
        i++;
        current = "";
        continue;
      }

      if ((char === "<" || char === ">" || char === "=" || char === "!") && nextChar === "=") {
        tokens.push(`${char}${nextChar}`);
        i++;
        current = "";
        continue;
      }

      tokens.push(char);
      current = "";
      continue;
    }

    if (/[a-zA-Z_]/.test(char)) {
      current += char;
    } else if (/[0-9.]/.test(char)) {
      current += char;
    } else {
      throw new Error(`Invalid character in expression: ${char}`);
    }
  }

  if (current) tokens.push(current);
  return tokens;
}

// ---------------------------------------------------------------------------
// AST node types for the expression parser
// ---------------------------------------------------------------------------

interface NumberNode   { type: "number";   value: number }
interface ConstantNode { type: "constant"; name: string }
interface VariableNode { type: "variable"; name: string }
interface UnaryNode    { type: "unary";    operator: string; argument: ASTNode }
interface BinaryNode   { type: "binary";   operator: string; left: ASTNode; right: ASTNode }
interface FunctionNode { type: "function"; name: string; args: ASTNode[] }

type ASTNode = NumberNode | ConstantNode | VariableNode | UnaryNode | BinaryNode | FunctionNode;

/**
 * Parses tokens into an Abstract Syntax Tree (AST)
 */
function parseTokens(tokens: string[]): ASTNode {
  let index = 0;

  function parseExpression(): ASTNode {
    return parseBinaryExpression(0);
  }

  function parseBinaryExpression(minPrecedence: number): ASTNode {
    let left = parseUnaryExpression();

    while (index < tokens.length) {
      const operator = tokens[index];
      if (!operator) break;

      const precedence = getOperatorPrecedence(operator);

      if (precedence < minPrecedence) break;

      index++;
      const right = parseBinaryExpression(precedence + 1);
      left = { type: "binary", operator, left, right };
    }

    return left;
  }

  function parseUnaryExpression(): ASTNode {
    const token = tokens[index];
    if (!token) throw new Error("Unexpected end of expression");

    if (token === "+" || token === "-" || token === "!") {
      index++;
      const argument = parseUnaryExpression();
      return { type: "unary", operator: token, argument };
    }

    return parsePrimaryExpression();
  }

  function parsePrimaryExpression(): ASTNode {
    const token = tokens[index];
    if (!token) throw new Error("Unexpected end of expression");


    // eslint-disable-next-line security/detect-possible-timing-attacks
    if (token === "(") {
      index++;
      const expression = parseExpression();
      if (index >= tokens.length || tokens[index] !== ")") {
        throw new Error("Missing closing parenthesis");
      }
      index++;
      return expression;
    }

    if (/^\d+(\.\d+)?$/.test(token)) {
      index++;
      return { type: "number", value: parseFloat(token) };
    }

    if (ALLOWED_CONSTANTS.has(token)) {
      index++;
      return { type: "constant", name: token };
    }

    if (ALLOWED_FUNCTIONS.has(token)) {
      index++;
      if (index >= tokens.length || tokens[index] !== "(") {
        throw new Error(`Expected '(' after function ${token}`);
      }
      index++;

      const args: ASTNode[] = [];
      if (index < tokens.length && tokens[index] !== ")") {
        args.push(parseExpression());
        while (index < tokens.length && tokens[index] === ",") {
          index++;
          args.push(parseExpression());
        }
      }

      if (index >= tokens.length || tokens[index] !== ")") {
        throw new Error("Missing closing parenthesis in function call");
      }
      index++;

      return { type: "function", name: token, args };
    }

    // Variable reference
    if (/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(token)) {
      index++;
      return { type: "variable", name: token };
    }

    throw new Error(`Unexpected token: ${token}`);
  }

  const result = parseExpression();
  if (index !== tokens.length) {
    throw new Error("Unexpected tokens after expression");
  }

  return result;
}

function getOperatorPrecedence(operator: string): number {
  switch (operator) {
    case "||":
      return 1;
    case "&&":
      return 2;
    case "==":
    case "!=":
      return 3;
    case "<":
    case "<=":
    case ">":
    case ">=":
      return 4;
    case "+":
    case "-":
      return 5;
    case "*":
    case "/":
      return 6;
    case "^":
      return 7;
    default:
      return 0;
  }
}

/**
 * Evaluates an AST node with the given variables
 */
function evaluateAST(node: ASTNode, vars: Record<string, number>): number {
  switch (node.type) {
    case "number":
      return node.value;

    case "constant":
      return (Math as Record<string, unknown>)[node.name] as number;

    case "variable":
      if (Object.prototype.hasOwnProperty.call(vars, node.name)) {
        return vars[node.name] as number;
      }
      throw new Error(`Unknown variable: ${node.name}`);

    case "unary": {
      const arg = evaluateAST(node.argument, vars);
      if (node.operator === "!") {
        return arg ? 0 : 1;
      }
      return node.operator === "-" ? -arg : arg;
    }

    case "binary": {
      const left = evaluateAST(node.left, vars);
      const right = evaluateAST(node.right, vars);

      switch (node.operator) {
        case "+":  return left + right;
        case "-":  return left - right;
        case "*":  return left * right;
        case "/":
          if (right === 0) throw new Error("Division by zero");
          return left / right;
        case "^":  return Math.pow(left, right);
        case "==": return left === right ? 1 : 0;
        case "!=": return left !== right ? 1 : 0;
        case "<":  return left < right ? 1 : 0;
        case "<=": return left <= right ? 1 : 0;
        case ">":  return left > right ? 1 : 0;
        case ">=": return left >= right ? 1 : 0;
        case "&&": return left && right ? 1 : 0;
        case "||": return left || right ? 1 : 0;
        default:   throw new Error(`Unknown operator: ${node.operator}`);
      }
    }

    case "function": {
      const func = (Math as Record<string, unknown>)[node.name];
      if (typeof func !== "function") {
        throw new Error(`Unknown function: ${node.name}`);
      }
      const evaluatedArgs = node.args.map((arg) => evaluateAST(arg, vars));
      const result = (func as (...a: number[]) => number)(...evaluatedArgs);
      if (typeof result !== "number" || isNaN(result)) {
        throw new Error(`Function ${node.name} returned invalid result`);
      }
      return result;
    }

    default:
      throw new Error(`Unknown node type: ${(node as ASTNode).type}`);
  }
}

/**
 * Creates a safe expression evaluator function
 */
export function createSafeEvaluator() {
  return function evaluate(expression: string, vars: Record<string, number> = {}): number {
    // Validate and parse the expression
    const tokens = tokenizeExpression(expression);
    const ast = parseTokens(tokens);

    // Evaluate the AST
    return evaluateAST(ast, vars);
  };
}

/**
 * Validates if an expression is safe to evaluate
 */
export function validateExpression(expression: string): { valid: boolean; error?: string } {
  try {
    const tokens = tokenizeExpression(expression);
    parseTokens(tokens);
    return { valid: true };
  } catch (error) {
    return {
      valid: false,
      error: error instanceof Error ? error.message : "Unknown error",
    };
  }
}

/**
 * Security Logger for Authentication Events
 * Provides comprehensive logging for security monitoring and audit trails
 */

export interface SecurityEvent {
  type:
    | "auth_success"
    | "auth_failure"
    | "auth_attempt"
    | "token_issued"
    | "token_refreshed"
    | "token_expired"
    | "session_expired"
    | "rate_limit_exceeded"
    | "csrf_failure"
    | "suspicious_activity"
    | "security_violation";
  severity: "low" | "medium" | "high" | "critical";
  userId?: string;
  email?: string;
  ip?: string;
  userAgent?: string;
  timestamp: number;
  details: Record<string, unknown>;
  sessionId?: string;
  source: "frontend" | "backend";
}

export interface SecurityMetrics {
  totalAuthAttempts: number;
  successfulAuths: number;
  failedAuths: number;
  rateLimitHits: number;
  suspiciousActivities: number;
  uniqueUsers: number;
  averageSessionDuration: number;
  tokenRefreshes: number;
  securityViolations: number;
}

class SecurityLogger {
  private static instance: SecurityLogger;
  private events: SecurityEvent[] = [];
  private metrics: SecurityMetrics = {
    totalAuthAttempts: 0,
    successfulAuths: 0,
    failedAuths: 0,
    rateLimitHits: 0,
    suspiciousActivities: 0,
    uniqueUsers: 0,
    averageSessionDuration: 0,
    tokenRefreshes: 0,
    securityViolations: 0,
  };
  private uniqueUserIds = new Set<string>();
  private sessionDurations: number[] = [];
  private readonly maxEvents = 1000; // Keep last 1000 events in memory

  private constructor() {}

  static getInstance(): SecurityLogger {
    if (!SecurityLogger.instance) {
      SecurityLogger.instance = new SecurityLogger();
    }
    return SecurityLogger.instance;
  }

  /**
   * Log a security event
   */
  logEvent(event: Omit<SecurityEvent, "timestamp" | "source">): void {
    const securityEvent: SecurityEvent = {
      ...event,
      timestamp: Date.now(),
      source: "frontend",
    };

    // Add to events array (keep only last maxEvents)
    this.events.push(securityEvent);
    if (this.events.length > this.maxEvents) {
      this.events.shift();
    }

    // Update metrics
    this.updateMetrics(securityEvent);

    // Log to console in development
    if (process.env.NODE_ENV === "development") {
      this.logToConsole(securityEvent);
    }

    // In production, send to monitoring service
    if (process.env.NODE_ENV === "production") {
      this.sendToMonitoringService(securityEvent);
    }
  }

  /**
   * Log authentication attempt
   */
  logAuthAttempt(email: string, ip?: string, userAgent?: string): void {
    this.logEvent({
      type: "auth_attempt",
      severity: "low",
      email,
      ...(ip && { ip }),
      ...(userAgent && { userAgent }),
      details: { action: "login_attempt" },
    });
  }

  /**
   * Log successful authentication
   */
  logAuthSuccess(userId: string, email: string, ip?: string, userAgent?: string): void {
    this.logEvent({
      type: "auth_success",
      severity: "low",
      userId,
      email,
      ...(ip && { ip }),
      ...(userAgent && { userAgent }),
      details: { action: "login_success" },
    });
  }

  /**
   * Log failed authentication
   */
  logAuthFailure(email: string, reason: string, ip?: string, userAgent?: string): void {
    this.logEvent({
      type: "auth_failure",
      severity: "medium",
      email,
      ...(ip && { ip }),
      ...(userAgent && { userAgent }),
      details: { reason, action: "login_failure" },
    });
  }

  /**
   * Log token issuance
   */
  logTokenIssued(userId: string, tokenType: "access" | "refresh", expiresAt: number): void {
    this.logEvent({
      type: "token_issued",
      severity: "low",
      userId,
      details: {
        tokenType,
        expiresAt,
        expiresIn: expiresAt - Date.now(),
      },
    });
  }

  /**
   * Log token refresh
   */
  logTokenRefreshed(userId: string, oldTokenExpiry: number, newTokenExpiry: number): void {
    this.logEvent({
      type: "token_refreshed",
      severity: "low",
      userId,
      details: {
        oldTokenExpiry,
        newTokenExpiry,
        extensionTime: newTokenExpiry - oldTokenExpiry,
      },
    });
  }

  /**
   * Log token expiration
   */
  logTokenExpired(userId: string, tokenType: "access" | "refresh", expiredAt: number): void {
    this.logEvent({
      type: "token_expired",
      severity: "medium",
      userId,
      details: { tokenType, expiredAt },
    });
  }

  /**
   * Log session expiration
   */
  logSessionExpired(userId: string, sessionId: string, duration: number): void {
    this.sessionDurations.push(duration);
    this.logEvent({
      type: "session_expired",
      severity: "medium",
      userId,
      sessionId,
      details: { sessionDuration: duration },
    });
  }

  /**
   * Log rate limit exceeded
   */
  logRateLimitExceeded(
    email: string,
    attempts: number,
    lockoutDuration: number,
    ip?: string
  ): void {
    this.logEvent({
      type: "rate_limit_exceeded",
      severity: "high",
      email,
      ...(ip && { ip }),
      details: {
        attempts,
        lockoutDuration,
        action: "rate_limit_triggered",
      },
    });
  }

  /**
   * Log CSRF failure
   */
  logCsrfFailure(ip?: string, userAgent?: string, endpoint?: string): void {
    this.logEvent({
      type: "csrf_failure",
      severity: "high",
      ...(ip && { ip }),
      ...(userAgent && { userAgent }),
      details: { endpoint, action: "csrf_validation_failed" },
    });
  }

  /**
   * Log suspicious activity
   */
  logSuspiciousActivity(
    type: string,
    severity: "medium" | "high" | "critical",
    details: Record<string, unknown>
  ): void {
    this.logEvent({
      type: "suspicious_activity",
      severity,
      details: { activityType: type, ...details },
    });
  }

  /**
   * Log security violation
   */
  logSecurityViolation(violation: string, details: Record<string, unknown>, userId?: string): void {
    this.logEvent({
      type: "security_violation",
      severity: "critical",
      ...(userId && { userId }),
      details: { violation, ...details },
    });
  }

  /**
   * Get current security metrics
   */
  getMetrics(): SecurityMetrics {
    // Calculate average session duration
    const avgDuration =
      this.sessionDurations.length > 0
        ? this.sessionDurations.reduce((a, b) => a + b, 0) / this.sessionDurations.length
        : 0;

    return {
      ...this.metrics,
      uniqueUsers: this.uniqueUserIds.size,
      averageSessionDuration: Math.round(avgDuration),
    };
  }

  /**
   * Get recent events
   */
  getRecentEvents(limit: number = 50): SecurityEvent[] {
    return this.events.slice(-limit);
  }

  /**
   * Get events by type
   */
  getEventsByType(type: SecurityEvent["type"], limit?: number): SecurityEvent[] {
    const filtered = this.events.filter((event) => event.type === type);
    return limit ? filtered.slice(-limit) : filtered;
  }

  /**
   * Get events by severity
   */
  getEventsBySeverity(severity: SecurityEvent["severity"], limit?: number): SecurityEvent[] {
    const filtered = this.events.filter((event) => event.severity === severity);
    return limit ? filtered.slice(-limit) : filtered;
  }

  /**
   * Get events for a specific user
   */
  getUserEvents(userId: string, limit?: number): SecurityEvent[] {
    const filtered = this.events.filter((event) => event.userId === userId);
    return limit ? filtered.slice(-limit) : filtered;
  }

  /**
   * Get security summary for dashboard
   */
  getSecuritySummary(): {
    metrics: SecurityMetrics;
    recentCriticalEvents: SecurityEvent[];
    recentSuspiciousActivities: SecurityEvent[];
    topFailedEmails: Array<{ email: string; count: number }>;
  } {
    const recentCriticalEvents = this.getEventsBySeverity("critical", 10);
    const recentSuspiciousActivities = this.getEventsByType("suspicious_activity", 10);

    // Get top failed emails
    const failedAuths = this.getEventsByType("auth_failure");
    const emailCounts = new Map<string, number>();

    failedAuths.forEach((event) => {
      if (event.email) {
        emailCounts.set(event.email, (emailCounts.get(event.email) || 0) + 1);
      }
    });

    const topFailedEmails = Array.from(emailCounts.entries())
      .map(([email, count]) => ({ email, count }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 10);

    return {
      metrics: this.getMetrics(),
      recentCriticalEvents,
      recentSuspiciousActivities,
      topFailedEmails,
    };
  }

  /**
   * Clear all events and reset metrics
   */
  clear(): void {
    this.events = [];
    this.metrics = {
      totalAuthAttempts: 0,
      successfulAuths: 0,
      failedAuths: 0,
      rateLimitHits: 0,
      suspiciousActivities: 0,
      uniqueUsers: 0,
      averageSessionDuration: 0,
      tokenRefreshes: 0,
      securityViolations: 0,
    };
    this.uniqueUserIds.clear();
    this.sessionDurations = [];
  }

  /**
   * Update metrics based on event
   */
  private updateMetrics(event: SecurityEvent): void {
    switch (event.type) {
      case "auth_attempt":
        this.metrics.totalAuthAttempts++;
        break;
      case "auth_success":
        this.metrics.successfulAuths++;
        if (event.userId) {
          this.uniqueUserIds.add(event.userId);
        }
        break;
      case "auth_failure":
        this.metrics.failedAuths++;
        break;
      case "rate_limit_exceeded":
        this.metrics.rateLimitHits++;
        break;
      case "suspicious_activity":
        this.metrics.suspiciousActivities++;
        break;
      case "token_refreshed":
        this.metrics.tokenRefreshes++;
        break;
      case "security_violation":
        this.metrics.securityViolations++;
        break;
    }
  }

  /**
   * Log to console in development
   */
  private logToConsole(event: SecurityEvent): void {
    const logMethod = this.getConsoleMethod(event.severity);
    logMethod(`[Security Event] ${event.type.toUpperCase()} - ${event.severity.toUpperCase()}`, {
      userId: event.userId,
      email: event.email,
      timestamp: new Date(event.timestamp).toISOString(),
      details: event.details,
    });
  }

  /**
   * Get appropriate console method for severity
   */
  private getConsoleMethod(severity: SecurityEvent["severity"]): typeof console.log {
    switch (severity) {
      case "critical":
        return console.error;
      case "high":
        // eslint-disable-next-line no-console
        return console.warn;
      case "medium":
        // eslint-disable-next-line no-console
        return console.warn;
      case "low":

        // eslint-disable-next-line no-console
        return console.info;
      default:

        // eslint-disable-next-line no-console
        return console.log;
    }
  }

  /**
   * Send event to monitoring service (in production)
   */
  private sendToMonitoringService(_event: SecurityEvent): void {
    // In production, this would send to your monitoring service
    // Examples: DataDog, New Relic, OpenTelemetry, etc.
    try {
      // Example for custom endpoint:
      // fetch('/api/security/events', {
      //   method: 'POST',
      //   headers: { 'Content-Type': 'application/json' },
      //   body: JSON.stringify(event),
      // });
    } catch (error) {
      console.error("Failed to send security event to monitoring service:", error);
    }
  }
}

