export type ShutdownHandler = (reason: string) => Promise<void> | void;

interface RegisteredHandler {
  name: string;
  handler: ShutdownHandler;
}

interface ShutdownRuntime {
  timeoutMs: number;
  exit: (code: number) => never | void;
  log: (level: "info" | "warn" | "error", message: string, meta?: Record<string, unknown>) => void;
}

const DEFAULT_SHUTDOWN_TIMEOUT_MS = 120_000;

const handlers: RegisteredHandler[] = [];
const wiredSignals = new Set<string>();

let shutdownInFlight: Promise<void> | null = null;
let shuttingDown = false;

const runtime: ShutdownRuntime = {
  timeoutMs: DEFAULT_SHUTDOWN_TIMEOUT_MS,
  exit: (code) => process.exit(code),
  log: (level, message, meta) => {
    const payload = meta ? ` ${JSON.stringify(meta)}` : "";


    // eslint-disable-next-line no-console
    console[level](`[shutdown] ${message}${payload}`);
  },
};

export function configureGracefulShutdown(config: Partial<ShutdownRuntime> & { timeoutMs?: number }): void {
  if (typeof config.timeoutMs === "number") {
    runtime.timeoutMs = config.timeoutMs;
  }
  if (config.exit) {
    runtime.exit = config.exit;
  }
  if (config.log) {
    runtime.log = config.log;
  }
}

export function registerShutdownHandler(name: string, handler: ShutdownHandler): void {
  handlers.push({ name, handler });
}

export function wireProcessShutdownSignals(signals: readonly NodeJS.Signals[] = ["SIGTERM", "SIGINT"]): void {
  for (const signal of signals) {
    if (wiredSignals.has(signal)) {
      continue;
    }

    process.on(signal, () => {
      void initiateGracefulShutdown(signal);
    });

    wiredSignals.add(signal);
  }
}

export async function initiateGracefulShutdown(reason: string): Promise<void> {
  if (shutdownInFlight) {
    runtime.log("warn", "Shutdown already in progress; reusing existing flow", { reason });
    return shutdownInFlight;
  }

  shuttingDown = true;
  runtime.log("info", "Starting graceful shutdown", { reason, handlerCount: handlers.length });

  shutdownInFlight = (async () => {
    const drain = (async () => {
      for (const { name, handler } of handlers) {
        runtime.log("info", "Running shutdown handler", { name, reason });
        await handler(reason);
      }
    })();

    const timeout = new Promise<never>((_, reject) => {
      setTimeout(() => {
        reject(new Error(`Graceful shutdown timed out after ${runtime.timeoutMs}ms`));
      }, runtime.timeoutMs);
    });

    try {
      await Promise.race([drain, timeout]);
      runtime.log("info", "Graceful shutdown completed", { reason });
      runtime.exit(0);
    } catch (error) {
      runtime.log("error", "Graceful shutdown failed or timed out", {
        reason,
        message: error instanceof Error ? error.message : String(error),
      });
      runtime.exit(1);
    }
  })();

  return shutdownInFlight;
}

export function isShuttingDown(): boolean {
  return shuttingDown;
}

export function __resetGracefulShutdownForTests(): void {
  handlers.splice(0, handlers.length);
  wiredSignals.clear();
  shutdownInFlight = null;
  shuttingDown = false;
  runtime.timeoutMs = DEFAULT_SHUTDOWN_TIMEOUT_MS;
  runtime.exit = (code) => process.exit(code);
  runtime.log = (level, message, meta) => {
    const payload = meta ? ` ${JSON.stringify(meta)}` : "";


    // eslint-disable-next-line no-console
    console[level](`[shutdown] ${message}${payload}`);
  };
}

/**
 * SDUIStateProvider
 *
 * Zustand-based state management for SDUI widgets.
 * Supports per-case state storage, undo/redo via useCanvasState integration,
 * and sessionStorage persistence for crash recovery.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §2
 */

import { createContext, ReactNode, useContext, useMemo } from "react";
import { create } from "zustand";
import { createJSONStorage, persist } from "zustand/middleware";
import { immer } from "zustand/middleware/immer";

// ============================================================================
// Types
// ============================================================================

export interface WidgetState {
  data: Record<string, unknown>;
  dirty: boolean;
  lastModified: string;
}

export interface CaseState {
  caseId: string;
  widgets: Record<string, WidgetState>;
  undoStack: string[];
  redoStack: string[];
  snapshots: Record<string, Record<string, WidgetState>>;
}

interface SDUIStateStore {
  cases: Record<string, CaseState>;

  setWidgetState: (caseId: string, widgetId: string, data: Record<string, unknown>) => void;
  resetWidgetState: (caseId: string, widgetId: string) => void;
  resetCaseState: (caseId: string) => void;

  undo: (caseId: string) => void;
  redo: (caseId: string) => void;
  canUndo: (caseId: string) => boolean;
  canRedo: (caseId: string) => boolean;

  createSnapshot: (caseId: string) => string;
  restoreSnapshot: (caseId: string, snapshotId: string) => void;

  getWidgetState: (caseId: string, widgetId: string) => WidgetState | undefined;
  isDirty: (caseId: string) => boolean;
}

function generateSnapshotId(): string {
  return `snap_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
}

function createEmptyCaseState(caseId: string): CaseState {
  return {
    caseId,
    widgets: {},
    undoStack: [],
    redoStack: [],
    snapshots: {},
  };
}

export const useSDUIStore = create<SDUIStateStore>()(
  immer(
    persist(
      (set, get) => ({
        cases: {},

        setWidgetState: (caseId, widgetId, data) => {
          set((state) => {
            if (!state.cases[caseId]) {
              state.cases[caseId] = createEmptyCaseState(caseId);
            }
            const caseState = state.cases[caseId];
            if (!caseState.widgets[widgetId]?.dirty) {
              const snapshotId = generateSnapshotId();
              caseState.undoStack.push(snapshotId);
              caseState.redoStack = [];
            }
            if (caseState.undoStack.length > 50) {
              caseState.undoStack.shift();
            }
            caseState.widgets[widgetId] = {
              data: { ...data },
              dirty: true,
              lastModified: new Date().toISOString(),
            };
          });
        },

        resetWidgetState: (caseId, widgetId) => {
          set((state) => {
            if (state.cases[caseId]?.widgets[widgetId]) {
              delete state.cases[caseId].widgets[widgetId];
            }
          });
        },

        resetCaseState: (caseId) => {
          set((state) => {
            delete state.cases[caseId];
          });
        },

        undo: (caseId) => {
          set((state) => {
            const caseState = state.cases[caseId];
            if (!caseState || caseState.undoStack.length === 0) return;
            const snapshotId = caseState.undoStack.pop();
            if (snapshotId) {
              caseState.redoStack.push(snapshotId);
            }
            Object.values(caseState.widgets).forEach((widget) => {
              (widget as WidgetState).dirty = false;
            });
          });
        },

        redo: (caseId) => {
          set((state) => {
            const caseState = state.cases[caseId];
            if (!caseState || caseState.redoStack.length === 0) return;
            const snapshotId = caseState.redoStack.pop();
            if (snapshotId) {
              caseState.undoStack.push(snapshotId);
            }
          });
        },

        canUndo: (caseId) => {
          const caseState = get().cases[caseId];
          return caseState ? caseState.undoStack.length > 0 : false;
        },

        canRedo: (caseId) => {
          const caseState = get().cases[caseId];
          return caseState ? caseState.redoStack.length > 0 : false;
        },

        createSnapshot: (caseId) => {
          const snapshotId = generateSnapshotId();
          set((state) => {
            if (!state.cases[caseId]) {
              state.cases[caseId] = createEmptyCaseState(caseId);
            }
            const caseState = state.cases[caseId];
            // Deep-copy current widget state into the snapshot store
            caseState.snapshots[snapshotId] = JSON.parse(
              JSON.stringify(caseState.widgets)
            ) as Record<string, WidgetState>;
            caseState.undoStack.push(snapshotId);
          });
          return snapshotId;
        },

        restoreSnapshot: (caseId, snapshotId) => {
          set((state) => {
            const caseState = state.cases[caseId];
            if (!caseState) return;
            const saved = caseState.snapshots[snapshotId];
            if (!saved) return;
            caseState.widgets = JSON.parse(
              JSON.stringify(saved)
            ) as Record<string, WidgetState>;
          });
        },

        getWidgetState: (caseId, widgetId) => {
          return get().cases[caseId]?.widgets[widgetId];
        },

        isDirty: (caseId) => {
          const caseState = get().cases[caseId];
          if (!caseState) return false;
          return Object.values(caseState.widgets).some((w) => w.dirty);
        },
      }),
      {
        name: "sdui-state-storage",
        storage: createJSONStorage(() => sessionStorage),
        partialize: (state) => ({
          cases: Object.fromEntries(
            Object.entries(state.cases).map(([id, c]) => [
              id,
              {
                caseId: c.caseId,
                widgets: c.widgets,
                undoStack: c.undoStack,
                redoStack: c.redoStack,
                snapshots: c.snapshots,
              },
            ])
          ),
        }),
      }
    )
  )
);

interface SDUIStateContextValue {
  store: typeof useSDUIStore;
  useStore: typeof useSDUIStore;
}

const SDUIStateContext = createContext<SDUIStateContextValue | undefined>(undefined);

export function SDUIStateProvider({ children, _supabase }: { children: ReactNode; _supabase?: unknown }) {
  const value = useMemo(
    () => ({
      store: useSDUIStore,
      useStore: useSDUIStore,
    }),
    []
  );

  return <SDUIStateContext.Provider value={value}>{children}</SDUIStateContext.Provider>;
}

export function useSDUIState() {
  const context = useContext(SDUIStateContext);
  if (!context) {
    return { store: useSDUIStore, useStore: useSDUIStore };
  }
  return context;
}

export function useWidgetState(caseId: string, widgetId: string) {
  const store = useSDUIStore();

  return {
    state: store.getWidgetState(caseId, widgetId),
    setState: (data: Record<string, unknown>) => store.setWidgetState(caseId, widgetId, data),
    reset: () => store.resetWidgetState(caseId, widgetId),
  };
}

export function useCaseUndoRedo(caseId: string) {
  const store = useSDUIStore();

  return {
    canUndo: store.canUndo(caseId),
    canRedo: store.canRedo(caseId),
    undo: () => store.undo(caseId),
    redo: () => store.redo(caseId),
    isDirty: store.isDirty(caseId),
  };
}

/**
 * @jest-environment jsdom
 */

import { act, renderHook } from "@testing-library/react";
import { beforeEach, describe, expect, it, vi } from "vitest";


import { useCaseUndoRedo, useSDUIStore, useWidgetState } from "../SDUIStateProvider";

describe("SDUIStateProvider", () => {
  const caseId = "test-case-123";
  const widgetId = "test-widget";

  beforeEach(() => {
    // Clear the store before each test
    const store = useSDUIStore.getState();
    store.resetCaseState(caseId);
  });

  describe("setWidgetState", () => {
    it("stores widget state per case", () => {
      const { result } = renderHook(() => useWidgetState(caseId, widgetId));

      act(() => {
        result.current.setState({ value: 100, name: "test" });
      });

      expect(result.current.state?.data).toEqual({ value: 100, name: "test" });
      expect(result.current.state?.dirty).toBe(true);
    });

    it("marks widget as dirty when state changes", () => {
      const { result } = renderHook(() => useWidgetState(caseId, widgetId));

      act(() => {
        result.current.setState({ value: 1 });
      });

      expect(result.current.state?.dirty).toBe(true);
    });
  });

  describe("undo/redo", () => {
    it("can undo widget state changes", () => {
      const { result: widgetResult } = renderHook(() => useWidgetState(caseId, widgetId));
      const { result: undoRedoResult } = renderHook(() => useCaseUndoRedo(caseId));

      act(() => {
        widgetResult.current.setState({ value: 1 });
      });

      act(() => {
        widgetResult.current.setState({ value: 2 });
      });

      // Undo should revert dirty state
      act(() => {
        undoRedoResult.current.undo();
      });

      expect(undoRedoResult.current.canUndo).toBe(false);
    });

    it("can redo after undo", () => {
      const { result: undoRedoResult } = renderHook(() => useCaseUndoRedo(caseId));

      act(() => {
        undoRedoResult.current.undo();
      });

      // Initially can't redo because nothing was undone
      expect(undoRedoResult.current.canRedo).toBe(false);
    });
  });

  describe("reset", () => {
    it("resets widget state", () => {
      const { result } = renderHook(() => useWidgetState(caseId, widgetId));

      act(() => {
        result.current.setState({ value: 100 });
      });

      act(() => {
        result.current.reset();
      });

      expect(result.current.state).toBeUndefined();
    });
  });

  describe("isDirty", () => {
    it("returns false when no widgets are dirty", () => {
      const { result } = renderHook(() => useCaseUndoRedo(caseId));
      expect(result.current.isDirty).toBe(false);
    });

    it("returns true when at least one widget is dirty", () => {
      const { result: widgetResult } = renderHook(() => useWidgetState(caseId, widgetId));
      const { result: undoRedoResult } = renderHook(() => useCaseUndoRedo(caseId));

      act(() => {
        widgetResult.current.setState({ value: 100 });
      });

      expect(undoRedoResult.current.isDirty).toBe(true);
    });
  });

  describe("sessionStorage persistence", () => {
    it("persists state to sessionStorage", () => {
      const store = useSDUIStore;

      act(() => {
        store.getState().setWidgetState(caseId, widgetId, { test: "data" });
      });

      // Verify the store has the data
      const widgetState = store.getState().getWidgetState(caseId, widgetId);
      expect(widgetState?.data).toEqual({ test: "data" });
    });
  });
});

import { createClient } from "@supabase/supabase-js";

import { logger } from "./logger";

const logPrefix = "[Supabase]";
const isBrowser = typeof window !== "undefined";

const getServerEnv = (key: string): string | undefined => {
  if (typeof process !== "undefined" && process.env?.[key]) {
    return process.env[key];
  }

  return undefined;
};

const supabaseUrl =
  getServerEnv("VITE_SUPABASE_URL") ||
  getServerEnv("SUPABASE_PUBLIC_URL") ||
  getServerEnv("SUPABASE_URL") ||
  getServerEnv("SUPABASE_INTERNAL_URL");
const supabaseAnonKey =
  getServerEnv("VITE_SUPABASE_ANON_KEY") || getServerEnv("SUPABASE_ANON_KEY");

let serviceRoleClient: ReturnType<typeof createClient> | null = null;

export const createServerSupabaseClient = () => {
  if (isBrowser) {
    throw new Error("createServerSupabaseClient() is only available in Node/server runtime.");
  }

  const supabaseServiceRoleKey = getServerEnv("SUPABASE_SERVICE_ROLE_KEY");

  if (!supabaseUrl || !supabaseServiceRoleKey) {
    const diagnostics = [
      `${logPrefix} Missing server Supabase credentials for privileged access.`,
      `${logPrefix}   VITE_SUPABASE_URL: ${supabaseUrl ? "SET" : "MISSING"}`,
      `${logPrefix}   SUPABASE_SERVICE_ROLE_KEY: ${supabaseServiceRoleKey ? "SET" : "MISSING"}`,
      `${logPrefix} Privileged paths cannot start without service-role credentials.`,
    ].join("\n");

    logger.error(diagnostics);
    throw new Error(diagnostics);
  }

  if (!serviceRoleClient) {
    serviceRoleClient = createClient(supabaseUrl, supabaseServiceRoleKey, {
      auth: {
        autoRefreshToken: false,
        persistSession: false,
      },
    });
    logger.info(`${logPrefix} ✅ Service-role server client initialized`);
  }

  return serviceRoleClient;
};

export const createRequestSupabaseClient = (accessToken: string) => {
  if (isBrowser) {
    throw new Error("createRequestSupabaseClient() is only available in Node/server runtime.");
  }

  if (!supabaseUrl || !supabaseAnonKey) {
    throw new Error(
      "Missing Supabase request-scoped credentials. Expected VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY.",
    );
  }

  if (!accessToken) {
    throw new Error("createRequestSupabaseClient requires a bearer access token.");
  }

  return createClient(supabaseUrl, supabaseAnonKey, {
    global: {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    },
    auth: {
      autoRefreshToken: false,
      persistSession: false,
    },
  });
};

import { createClient } from "@supabase/supabase-js";

import { logger } from "./logger";

const logPrefix = "[Supabase]";
const isBrowser = typeof window !== "undefined";

const getBrowserEnv = (key: "VITE_SUPABASE_URL" | "VITE_SUPABASE_ANON_KEY") => {
  const viteEnv = (import.meta as ImportMeta & { env?: Record<string, string | undefined> }).env;
  return viteEnv?.[key];
};

const supabaseUrl = getBrowserEnv("VITE_SUPABASE_URL");
const supabaseAnonKey = getBrowserEnv("VITE_SUPABASE_ANON_KEY");

logger.info(`${logPrefix} Initializing browser client...`);
logger.info(`${logPrefix} Runtime: ${isBrowser ? "browser" : "node"}`);
logger.info(`${logPrefix} URL configured: ${supabaseUrl ? "YES" : "NO"}`);
logger.info(`${logPrefix} Anon key configured: ${supabaseAnonKey ? "YES" : "NO"}`);

let browserClient: ReturnType<typeof createClient> | null = null;

export const createBrowserSupabaseClient = () => {
  if (!isBrowser) {
    throw new Error(
      "createBrowserSupabaseClient() can only be used in the browser runtime.",
    );
  }

  if (!supabaseUrl || !supabaseAnonKey) {
    throw new Error(
      "Missing Supabase browser credentials. Expected VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY.",
    );
  }

  if (!browserClient) {
