// ============================================================================
// Configuration Validation
// ============================================================================

export class ConfigurationValidator {
  /**
   * Validate base MCP configuration
   */
  static validateBase(config: unknown): MCPBaseConfig {
    const errors: string[] = [];

    if (
      !config ||
      typeof config !== "object" ||
      config === null
    ) {
      throw new Error("Invalid configuration object");
    }

    const configObj = config as Record<string, unknown>;

    if (
      !configObj.environment ||
      typeof configObj.environment !== "string" ||
      !["development", "staging", "production"].includes(configObj.environment)
    ) {
      errors.push("Invalid environment. Must be: development, staging, production");
    }

    if (typeof configObj.debug !== "boolean") {
      errors.push("debug must be a boolean");
    }

    if (
      !configObj.logLevel ||
      typeof configObj.logLevel !== "string" ||
      !["error", "warn", "info", "debug"].includes(configObj.logLevel)
    ) {
      errors.push("Invalid logLevel. Must be: error, warn, info, debug");
    }

    if (
      !configObj.timeout ||
      typeof configObj.timeout !== "object" ||
      configObj.timeout === null
    ) {
      errors.push("timeout configuration is required");
    } else {
      const timeout = configObj.timeout as Record<string, unknown>;

      if (typeof timeout.default !== "number" || timeout.default <= 0) {
        errors.push("timeout.default must be a positive number");
      }
      if (typeof timeout.external !== "number" || timeout.external <= 0) {
        errors.push("timeout.external must be a positive number");
      }
      if (typeof timeout.database !== "number" || timeout.database <= 0) {
        errors.push("timeout.database must be a positive number");
      }
    }

    if (errors.length > 0) {
      throw new Error(`Configuration validation failed:\n${errors.join("\n")}`);
    }

    return config as MCPBaseConfig;
  }

  /**
   * Validate CRM configuration
   */
  static validateCRM(config: unknown): MCPCRMServerConfig {
    const baseConfig = this.validateBase(config);

    const configObj = config as Record<string, unknown>;

    if (!configObj.crm || typeof configObj.crm !== "object" || configObj.crm === null) {
      throw new Error("CRM configuration is required");
    }

    const crm = configObj.crm as Record<string, unknown>;

    if (!Array.isArray(crm.providers) || crm.providers.length === 0) {
      throw new Error("At least one CRM provider must be configured");
    }

    // Validate each provider
    crm.providers.forEach((provider: unknown, index: number) => {
      const providerErrors: string[] = [];

      if (
        !provider ||
        typeof provider !== "object" ||
        provider === null
      ) {
        providerErrors.push(`Invalid provider object at index ${index}`);
      } else {
        const p = provider as Record<string, unknown>;

        if (!p.provider || typeof p.provider !== "string" || !["hubspot", "salesforce", "dynamics"].includes(p.provider)) {
          providerErrors.push(`Invalid provider at index ${index}`);
        }

        if (typeof p.enabled !== "boolean") {
          providerErrors.push(`enabled must be boolean for provider at index ${index}`);
        }

        if (!p.fieldMappings || typeof p.fieldMappings !== "object" || p.fieldMappings === null) {
          providerErrors.push(`fieldMappings is required for provider at index ${index}`);
        }
      }

      if (providerErrors.length > 0) {
        throw new Error(`Provider validation failed:\n${providerErrors.join("\n")}`);
      }
    });

    return config as MCPCRMServerConfig;
  }

  /**
   * Validate Financial server configuration
   */
  static validateFinancial(config: unknown): MCPFinancialServerConfig {
    const baseConfig = this.validateBase(config);

    const configObj = config as Record<string, unknown>;

    if (!configObj.financial || typeof configObj.financial !== "object" || configObj.financial === null) {
      throw new Error("Financial configuration is required");
    }

    const financial = configObj.financial as Record<string, unknown>;

    // Validate modules
    const requiredModules = ["edgar", "xbrl", "marketData", "privateCompany", "industryBenchmark"];
    if (!financial.modules || typeof financial.modules !== "object" || financial.modules === null) {
      throw new Error("financial.modules configuration is required");
    }
    const modules = financial.modules as Record<string, unknown>;
    requiredModules.forEach((module) => {
      if (!modules[module]) {
        throw new Error(`${module} module configuration is required`);
      }
    });

    return config as MCPFinancialServerConfig;
  }
}

// ============================================================================
// Configuration Manager
// ============================================================================

export class ConfigurationManager {
  private static instance: ConfigurationManager;
  private configCache: Map<string, MCPServerConfig> = new Map();
  private fileWatchers: Map<string, boolean> = new Map();
  private configDir: string;

  private constructor(configDir?: string) {
    this.configDir = configDir || resolve(process.cwd(), "config");
  }

  static getInstance(configDir?: string): ConfigurationManager {
    if (!ConfigurationManager.instance) {
      ConfigurationManager.instance = new ConfigurationManager(configDir);
    }
    return ConfigurationManager.instance;
  }

  /**
   * Load configuration for a specific server type
   */
  async loadConfig<T extends MCPServerConfig>(
    serverType: "crm" | "financial" | "integrated",
    environment?: string
  ): Promise<T> {
    const cacheKey = `${serverType}-${environment || process.env.NODE_ENV || "development"}`;

    // Return cached config if available
    if (this.configCache.has(cacheKey)) {
      return this.configCache.get(cacheKey) as T;
    }

    // Determine config file path
    const env = environment || process.env.NODE_ENV || "development";
    const configPath = this.getConfigPath(serverType, env);

    if (!existsSync(configPath)) {
      throw new Error(`Configuration file not found: ${configPath}`);
    }

    try {
      // Load and parse configuration
      const rawConfig = this.loadConfigFile(configPath);

      // Validate configuration
      let validatedConfig: T;
      switch (serverType) {
        case "crm":
          validatedConfig = ConfigurationValidator.validateCRM(rawConfig) as T;
          break;
        case "financial":
          validatedConfig = ConfigurationValidator.validateFinancial(rawConfig) as T;
          break;
        case "integrated":
          validatedConfig = ConfigurationValidator.validateBase(rawConfig) as T;
          break;
        default:
          throw new Error(`Unknown server type: ${serverType}`);
      }

      // Cache the configuration
      this.configCache.set(cacheKey, validatedConfig);

      // Set up file watching for hot reload in development
      if (validatedConfig.debug && !this.fileWatchers.has(cacheKey)) {
        this.setupFileWatcher(configPath, cacheKey, serverType, env);
      }

      logger.info(`Configuration loaded successfully`, {
        serverType,
        environment: env,
        configPath,
      });

      return validatedConfig;
    } catch (error: unknown) {
      logger.error(`Failed to load configuration`, {
        serverType,
        environment: env,
        configPath,
        error: error instanceof Error ? error.message : "Unknown error",
      });
      throw error;
    }
  }

  /**
   * Get configuration file path
   */
  private getConfigPath(serverType: string, environment: string): string {
    const filename = `${serverType}-${environment}.json`;
    return join(this.configDir, filename);
  }

  /**
   * Load configuration file
   */
  private loadConfigFile(configPath: string): unknown {
    try {
      const content = readFileSync(configPath, "utf-8");
      return JSON.parse(content) as unknown;
    } catch (error: unknown) {
      if (error instanceof SyntaxError) {
        throw new Error(`Invalid JSON in configuration file: ${configPath}`);
      }
      throw error;
    }
  }

  /**
   * Set up file watcher for hot reload
   */
  private setupFileWatcher(
    configPath: string,
    cacheKey: string,
    serverType: "crm" | "financial" | "integrated",
    environment: string
  ): void {
    this.fileWatchers.set(cacheKey, true);

    watchFile(configPath, async () => {
      try {
        logger.info(`Configuration file changed, reloading...`, {
          serverType,
          environment,
          configPath,
        });

        // Clear cache
        this.configCache.delete(cacheKey);

        // Reload configuration
        await this.loadConfig(serverType, environment);

        logger.info(`Configuration reloaded successfully`, {
          serverType,
          environment,
        });
      } catch (error: unknown) {
        logger.error(`Failed to reload configuration`, {
          serverType,
          environment,
          error: error instanceof Error ? error.message : "Unknown error",
        });
      }
    });
  }

  /**
   * Clear configuration cache
   */
  clearCache(serverType?: string, environment?: string): void {
    if (serverType && environment) {
      const cacheKey = `${serverType}-${environment}`;
      this.configCache.delete(cacheKey);
    } else {
      this.configCache.clear();
    }
  }

  /**
   * Get cached configuration
   */
  getCachedConfig<T extends MCPServerConfig>(
    serverType: string,
    environment?: string
  ): T | undefined {
    const env = environment || process.env.NODE_ENV || "development";
    const cacheKey = `${serverType}-${env}`;
    return this.configCache.get(cacheKey) as T | undefined;
  }

  /**
   * Validate configuration without loading
   */
  validateConfig(serverType: "crm" | "financial" | "integrated", config: unknown): boolean {
    try {
      switch (serverType) {
        case "crm":
          ConfigurationValidator.validateCRM(config);
          break;
        case "financial":
          ConfigurationValidator.validateFinancial(config);
          break;
        case "integrated":
          ConfigurationValidator.validateBase(config);
          break;
        default:
          return false;
      }
      return true;
    } catch {
      return false;
    }
  }

  /**
   * Cleanup file watchers
   */
  cleanup(): void {
    for (const [cacheKey] of this.fileWatchers) {
      const [serverType, environment] = cacheKey.split("-");
      const configPath = this.getConfigPath(serverType, environment);
      unwatchFile(configPath);
    }
    this.fileWatchers.clear();
  }
}

/**
 * MCP Rate Limiter
 *
 * Provides centralized rate limiting for all MCP servers with provider-specific
 * configurations, circuit breaker patterns, and adaptive throttling.
 */

import { EventEmitter } from "events";

import { logger } from "../../lib/logger";

// ============================================================================
// Rate Limiting Types
// ============================================================================

export interface MCPRateLimitConfig {
  provider: string;
  requestsPerSecond: number;
  burstCapacity: number;
  windowMs: number;
  retryAfterBase: number;
  maxRetries: number;
  backoffMultiplier: number;
  adaptiveThrottling: boolean;
  circuitBreaker: {
    enabled: boolean;
    failureThreshold: number;
    recoveryTimeout: number;
    monitoringPeriod: number;
  };
}

export interface MCPRateLimitResult {
  allowed: boolean;
  remaining: number;
  resetTime: number;
  retryAfter?: number;
  circuitBreakerOpen?: boolean;
  adaptiveDelay?: number;
}

export interface MCPRateLimitState {
  provider: string;
  currentRequests: number;
  totalRequests: number;
  failedRequests: number;
  successRate: number;
  averageResponseTime: number;
  circuitBreakerState: "closed" | "open" | "half-open";
  lastFailureTime?: number;
  nextRetryTime?: number;
}

// ============================================================================
// Circuit Breaker Implementation
// ============================================================================

class CircuitBreaker {
  private state: "closed" | "open" | "half-open" = "closed";
  private failureCount = 0;
  private lastFailureTime = 0;
  private nextRetryTime = 0;

  constructor(
    private config: MCPRateLimitConfig["circuitBreaker"],
    private provider: string
  ) {}

  check(): { allowed: boolean; state: string } {
    const now = Date.now();

    switch (this.state) {
      case "closed":
        return { allowed: true, state: "closed" };

      case "open":
        if (now >= this.nextRetryTime) {
          this.state = "half-open";
          logger.info(`Circuit breaker transitioning to half-open for provider: ${this.provider}`);
          return { allowed: true, state: "half-open" };
        }
        return { allowed: false, state: "open" };

      case "half-open":
        return { allowed: true, state: "half-open" };

      default:
        return { allowed: false, state: "unknown" };
    }
  }

  onSuccess(): void {
    if (this.state === "half-open") {
      this.reset();
    }
  }

  onFailure(): void {
    this.failureCount++;
    this.lastFailureTime = Date.now();

    if (this.state === "closed" && this.failureCount >= this.config.failureThreshold) {
      this.trip();
    } else if (this.state === "half-open") {
      this.trip();
    }
  }

  private trip(): void {
    this.state = "open";
    this.nextRetryTime = Date.now() + this.config.recoveryTimeout;
    logger.warn(`Circuit breaker tripped for provider: ${this.provider}`, {
      failureCount: this.failureCount,
      nextRetryTime: new Date(this.nextRetryTime),
    });
  }

  private reset(): void {
    this.state = "closed";
    this.failureCount = 0;
    this.lastFailureTime = 0;
    this.nextRetryTime = 0;
    logger.info(`Circuit breaker reset for provider: ${this.provider}`);
  }

  getState(): MCPRateLimitState["circuitBreakerState"] {
    return this.state;
  }

  getFailureCount(): number {
    return this.failureCount;
  }
}

// ============================================================================
// Adaptive Throttling
// ============================================================================

class AdaptiveThrottler {
  private responseTimes: number[] = [];
  private maxHistorySize = 100;
  private currentDelay = 0;

  constructor(private targetResponseTime: number) {}

  recordResponseTime(responseTime: number): void {
    this.responseTimes.push(responseTime);

    if (this.responseTimes.length > this.maxHistorySize) {
      this.responseTimes.shift();
    }

    this.adjustDelay();
  }

  private adjustDelay(): void {
    if (this.responseTimes.length < 10) return;

    const avgResponseTime =
      this.responseTimes.reduce((a, b) => a + b, 0) / this.responseTimes.length;
    const variance = this.calculateVariance();

    // Increase delay if response times are high or volatile
    if (avgResponseTime > this.targetResponseTime * 1.5 || variance > this.targetResponseTime) {
      this.currentDelay = Math.min(this.currentDelay + 100, 2000); // Max 2 second delay
    } else if (
      avgResponseTime < this.targetResponseTime * 0.8 &&
      variance < this.targetResponseTime * 0.5
    ) {
      this.currentDelay = Math.max(this.currentDelay - 50, 0); // Reduce delay but not below 0
    }

    if (this.currentDelay > 0) {
      logger.debug(`Adaptive throttling applied`, {
        avgResponseTime,
        variance,
        currentDelay: this.currentDelay,
      });
    }
  }

  private calculateVariance(): number {
    const mean = this.responseTimes.reduce((a, b) => a + b, 0) / this.responseTimes.length;
    const squaredDiffs = this.responseTimes.map((x) => Math.pow(x - mean, 2));
    return squaredDiffs.reduce((a, b) => a + b, 0) / this.responseTimes.length;
  }

  getCurrentDelay(): number {
    return this.currentDelay;
  }

  reset(): void {
    this.responseTimes = [];
    this.currentDelay = 0;
  }
}

// ============================================================================
// MCP Rate Limiter
// ============================================================================

export class MCPRateLimiter extends EventEmitter {
  private static instance: MCPRateLimiter;
  private providers: Map<string, MCPRateLimitConfig> = new Map();
  private requestWindows: Map<string, number[]> = new Map();
  private circuitBreakers: Map<string, CircuitBreaker> = new Map();
  private adaptiveThrottlers: Map<string, AdaptiveThrottler> = new Map();
  private stats: Map<string, MCPRateLimitState> = new Map();
  private cleanupInterval: NodeJS.Timeout | null = null;

  private constructor() {
    super();

    // Skip in test environments — the interval keeps the Node process alive.
    if (process.env.NODE_ENV === "test" || process.env.TEST_MODE === "true") {
      return;
    }
    // Clean up old request data every 5 minutes
    this.cleanupInterval = setInterval(
      () => {
        this.cleanup();
      },
      5 * 60 * 1000
    );
    if (this.cleanupInterval && typeof (this.cleanupInterval as NodeJS.Timeout).unref === "function") {
      (this.cleanupInterval as NodeJS.Timeout).unref();
    }
  }

  static getInstance(): MCPRateLimiter {
    if (!MCPRateLimiter.instance) {
      MCPRateLimiter.instance = new MCPRateLimiter();
    }
    return MCPRateLimiter.instance;
  }

  /**
   * Register a provider with rate limiting configuration
   */
  registerProvider(config: MCPRateLimitConfig): void {
    this.providers.set(config.provider, config);

    // Initialize circuit breaker if enabled
    if (config.circuitBreaker.enabled) {
      this.circuitBreakers.set(
        config.provider,
        new CircuitBreaker(config.circuitBreaker, config.provider)
      );
    }

    // Initialize adaptive throttler if enabled
    if (config.adaptiveThrottling) {
      this.adaptiveThrottlers.set(config.provider, new AdaptiveThrottler(1000)); // 1 second target
    }

    // Initialize stats
    this.stats.set(config.provider, {
      provider: config.provider,
      currentRequests: 0,
      totalRequests: 0,
      failedRequests: 0,
      successRate: 1.0,
      averageResponseTime: 0,
      circuitBreakerState: "closed",
    });

    logger.info(`Rate limiter registered for provider: ${config.provider}`, {
      requestsPerSecond: config.requestsPerSecond,
      burstCapacity: config.burstCapacity,
      circuitBreakerEnabled: config.circuitBreaker.enabled,
      adaptiveThrottling: config.adaptiveThrottling,
    });
  }

  /**
   * Check if a request should be allowed
   */
  async checkLimit(provider: string): Promise<MCPRateLimitResult> {
    const config = this.providers.get(provider);
    if (!config) {
      throw new Error(`Provider ${provider} not registered with rate limiter`);
    }

    const now = Date.now();
    const windowStart = now - config.windowMs;

    // Check circuit breaker
    const circuitBreaker = this.circuitBreakers.get(provider);
    if (circuitBreaker) {
      const cbResult = circuitBreaker.check();
      if (!cbResult.allowed) {
        this.updateStats(provider, { circuitBreakerOpen: true });
        return {
          allowed: false,
          remaining: 0,
          resetTime: circuitBreaker["nextRetryTime"] || now + config.circuitBreaker.recoveryTimeout,
          circuitBreakerOpen: true,
        };
      }
    }

    // Get or initialize request window
    if (!this.requestWindows.has(provider)) {
      this.requestWindows.set(provider, []);
    }

    const requests = this.requestWindows.get(provider)!;
    const validRequests = requests.filter((timestamp) => timestamp > windowStart);
    this.requestWindows.set(provider, validRequests);

    // Check rate limit
    const currentRequests = validRequests.length;
    const remaining = Math.max(0, config.burstCapacity - currentRequests);

    if (currentRequests >= config.burstCapacity) {
      const oldestRequest = Math.min(...validRequests);
      const resetTime = oldestRequest + config.windowMs;

      logger.warn(`Rate limit exceeded for provider: ${provider}`, {
        currentRequests,
        burstCapacity: config.burstCapacity,
        windowMs: config.windowMs,
      });

      return {
        allowed: false,
        remaining: 0,
        resetTime,
        retryAfter: Math.ceil((resetTime - now) / 1000),
      };
    }

    // Check adaptive throttling
    let adaptiveDelay = 0;
    const throttler = this.adaptiveThrottlers.get(provider);
    if (throttler) {
      adaptiveDelay = throttler.getCurrentDelay();
    }

    // Allow request
    validRequests.push(now);
    this.requestWindows.set(provider, validRequests);

    this.updateStats(provider, {
      currentRequests: currentRequests + 1,
      totalRequests: 1,
    });

    return {
      allowed: true,
      remaining: remaining - 1,
      resetTime: now + config.windowMs,
      adaptiveDelay,
    };
  }

  /**
   * Record successful request completion
   */
  recordSuccess(provider: string, responseTime: number): void {
    const circuitBreaker = this.circuitBreakers.get(provider);
    if (circuitBreaker) {
      circuitBreaker.onSuccess();
    }

    const throttler = this.adaptiveThrottlers.get(provider);
    if (throttler) {
      throttler.recordResponseTime(responseTime);
    }

    this.updateStats(provider, {
      successRate: 1.0,
      averageResponseTime: responseTime,
    });

    this.emit("success", { provider, responseTime });
  }

  /**
   * Record failed request
   */
  recordFailure(provider: string, error?: Error): void {
    const circuitBreaker = this.circuitBreakers.get(provider);
    if (circuitBreaker) {
      circuitBreaker.onFailure();
    }

    this.updateStats(provider, {
      failedRequests: 1,
      successRate: 0.0,
    });

    this.emit("failure", { provider, error });
  }

  /**
   * Get rate limit statistics for a provider
   */
  getStats(provider: string): MCPRateLimitState | null {
    return this.stats.get(provider) || null;
  }

  /**
   * Get all provider statistics
   */
  getAllStats(): MCPRateLimitState[] {
    return Array.from(this.stats.values());
  }

  /**
   * Reset rate limit for a provider
   */
  resetProvider(provider: string): void {
    this.requestWindows.delete(provider);
    this.circuitBreakers.delete(provider);
    this.adaptiveThrottlers.delete(provider);

    const stats = this.stats.get(provider);
    if (stats) {
      stats.currentRequests = 0;
      stats.totalRequests = 0;
      stats.failedRequests = 0;
      stats.successRate = 1.0;
      stats.averageResponseTime = 0;
      stats.circuitBreakerState = "closed";
    }

    logger.info(`Rate limiter reset for provider: ${provider}`);
  }

  /**
   * Update provider statistics
   */
  private updateStats(provider: string, updates: Partial<MCPRateLimitState>): void {
    const stats = this.stats.get(provider);
    if (!stats) return;

    if (updates.currentRequests !== undefined) {
      stats.currentRequests = updates.currentRequests;
    }

    if (updates.totalRequests !== undefined) {
      stats.totalRequests += updates.totalRequests;
    }

    if (updates.failedRequests !== undefined) {
      stats.failedRequests += updates.failedRequests;
    }

    if (updates.successRate !== undefined) {
      const totalAttempts = stats.totalRequests;
      const failures = stats.failedRequests;
      stats.successRate = totalAttempts > 0 ? (totalAttempts - failures) / totalAttempts : 1.0;
    }

    if (updates.averageResponseTime !== undefined) {
      // Simple exponential moving average
      const alpha = 0.1;
      stats.averageResponseTime =
        stats.averageResponseTime === 0
          ? updates.averageResponseTime
          : alpha * updates.averageResponseTime + (1 - alpha) * stats.averageResponseTime;
    }

    // Update circuit breaker state
    const circuitBreaker = this.circuitBreakers.get(provider);
    if (circuitBreaker) {
      stats.circuitBreakerState = circuitBreaker.getState();
      stats.lastFailureTime = circuitBreaker["lastFailureTime"];
      stats.nextRetryTime = circuitBreaker["nextRetryTime"];
    }
  }

  /**
   * Clean up old request data
   */
  private cleanup(): void {
    const now = Date.now();
    const maxAge = 24 * 60 * 60 * 1000; // 24 hours

    for (const [provider, requests] of this.requestWindows.entries()) {
      const validRequests = requests.filter((timestamp) => now - timestamp < maxAge);

      if (validRequests.length === 0) {
        this.requestWindows.delete(provider);
      } else {
        this.requestWindows.set(provider, validRequests);
      }
    }

    logger.debug("Rate limiter cleanup completed", {
      providersRemaining: this.requestWindows.size,
    });
  }

  /**
   * Destroy the rate limiter (cleanup)
   */
  destroy(): void {
    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
      this.cleanupInterval = null;
    }

    this.providers.clear();
    this.requestWindows.clear();
    this.circuitBreakers.clear();
    this.adaptiveThrottlers.clear();
    this.stats.clear();

    this.removeAllListeners();
  }
}

// Export singleton instance
export const mcpRateLimiter = MCPRateLimiter.getInstance();

/**
 * MCP Standardized Response Types
 *
 * Provides unified response format across all MCP servers with consistent
 * structure for success, error, and metadata handling.
 */

import { createErrorResponse, MCPBaseError } from "../errors/MCPBaseError";

// ============================================================================
// Base Response Interface
// ============================================================================

export interface MCPResponseMetadata {
  requestId?: string;
  timestamp: string;
  duration?: number; // Response time in milliseconds
  provider?: string;
  tool?: string;
  tier?: string;
  cacheHit?: boolean;
  rateLimitRemaining?: number;
  warnings?: string[];
  debug?: {
    executionPath?: string[];
    performanceMetrics?: Record<string, number>;
    dependencies?: string[];
  };
}

export interface MCPBaseResponse<T = unknown> {
  success: boolean;
  data?: T;
  error?: {
    code: string;
    message: string;
    category: string;
    metadata: Record<string, unknown>;
    details?: unknown;
  };
  metadata: MCPResponseMetadata;
}

// ============================================================================
// Success Response Types
// ============================================================================

export interface MCPSuccessResponse<T = unknown> extends MCPBaseResponse<T> {
  success: true;
  data: T;
  error?: never;
}

export interface MCPErrorResponse extends MCPBaseResponse<never> {
  success: false;
  data?: never;
  error: {
    code: string;
    message: string;
    category: string;
    metadata: Record<string, unknown>;
    details?: unknown;
  };
}

// ============================================================================
// Tool-Specific Response Types
// ============================================================================

export interface MCPToolResponse<T = unknown> extends MCPSuccessResponse<T> {
  metadata: MCPResponseMetadata & {
    tool: string;
    provider?: string;
    tier?: string;
  };
}

export interface MCPFinancialToolResponse<T = unknown> extends MCPToolResponse<T> {
  metadata: MCPResponseMetadata & {
    tool: string;
    provider: "edgar" | "xbrl" | "marketdata" | "private" | "benchmark";
    tier: "tier1" | "tier2" | "tier3";
    audit: {
      traceId: string;
      verificationHash?: string;
      provenance: {
        source: string;
        filingType?: string;
        accessionNumber?: string;
        extractionMethod: string;
      };
    };
  };
}

export interface MCPCRMToolResponse<T = unknown> extends MCPToolResponse<T> {
  metadata: MCPResponseMetadata & {
    tool: string;
    provider: "hubspot" | "salesforce" | "dynamics";
    tenantId: string;
    connectionStatus: "connected" | "degraded" | "disconnected";
  };
}

// ============================================================================
// Response Builder Classes
// ============================================================================

export class MCPResponseBuilder {
  private metadata: MCPResponseMetadata;

  constructor(
    private tool?: string,
    private provider?: string,
    private requestId?: string
  ) {
    this.metadata = {
      timestamp: new Date().toISOString(),
      ...(tool && { tool }),
      ...(provider && { provider }),
      ...(requestId && { requestId }),
    };
  }

  /**
   * Get current metadata (for utility functions)
   */
  getMetadata(): MCPResponseMetadata {
    return { ...this.metadata };
  }

  /**
   * Set request ID
   */
  withRequestId(requestId: string): MCPResponseBuilder {
    this.metadata.requestId = requestId;
    return this;
  }

  /**
   * Set provider
   */
  withProvider(provider: string): MCPResponseBuilder {
    this.metadata.provider = provider;
    return this;
  }

  /**
   * Set tier (for financial responses)
   */
  withTier(tier: string): MCPResponseBuilder {
    this.metadata.tier = tier;
    return this;
  }

  /**
   * Set cache hit status
   */
  withCacheHit(cacheHit: boolean): MCPResponseBuilder {
    this.metadata.cacheHit = cacheHit;
    return this;
  }

  /**
   * Set rate limit remaining
   */
  withRateLimitRemaining(remaining: number): MCPResponseBuilder {
    this.metadata.rateLimitRemaining = remaining;
    return this;
  }

  /**
   * Add warning
   */
  withWarning(warning: string): MCPResponseBuilder {
    if (!this.metadata.warnings) {
      this.metadata.warnings = [];
    }
    this.metadata.warnings.push(warning);
    return this;
  }

  /**
   * Set duration
   */
  withDuration(duration: number): MCPResponseBuilder {
    this.metadata.duration = duration;
    return this;
  }

  /**
   * Add debug information
   */
  withDebug(debug: {
    executionPath?: string[];
    performanceMetrics?: Record<string, number>;
    dependencies?: string[];
  }): MCPResponseBuilder {
    this.metadata.debug = debug;
    return this;
  }

  /**
   * Create success response
   */
  success<T>(data: T): MCPSuccessResponse<T> {
    return {
      success: true,
      data,
      metadata: this.metadata,
    };
  }

  /**
   * Create error response
   */
  error(error: Error | MCPBaseError, requestId?: string): MCPErrorResponse {
    if (error instanceof MCPBaseError) {
      return {
        success: false,
        error: error.toJSON().error,
        metadata: {
          ...this.metadata,
          ...(requestId && { requestId }),
        },
      };
    }

    return {
      success: false,
      error: createErrorResponse(error, requestId || this.metadata.requestId).error,
      metadata: this.metadata,
    };
  }

  /**
   * Create financial tool response with audit metadata
   */
  financialSuccess<T>(
    data: T,
    audit: {
      traceId: string;
      verificationHash?: string;
      provenance: {
        source: string;
        filingType?: string;
        accessionNumber?: string;
        extractionMethod: string;
      };
    }
  ): MCPFinancialToolResponse<T> {
    return {
      success: true,
      data,
      metadata: {
        ...this.metadata,
        tool: this.tool || "unknown",
        provider: (this.provider as
          | "edgar"
          | "xbrl"
          | "marketdata"
          | "private"
          | "benchmark") || "unknown",
        tier: (this.metadata.tier as "tier1" | "tier2" | "tier3") || "unknown",
        audit,
      } as MCPFinancialToolResponse<T>["metadata"],
    };
  }

  /**
   * Create CRM tool response with connection metadata
   */
  crmSuccess<T>(
    data: T,
    tenantId: string,
    connectionStatus: "connected" | "degraded" | "disconnected" = "connected"
  ): MCPCRMToolResponse<T> {
    return {
      success: true,
      data,
      metadata: {
        ...this.metadata,
        tool: this.tool || "unknown",
        provider: (this.provider as "hubspot" | "salesforce" | "dynamics") || "unknown",
        tenantId,
        connectionStatus,
      } as MCPCRMToolResponse<T>["metadata"],
    };
  }
}

// ============================================================================
// Utility Functions
// ============================================================================

/**
 * Create a response builder for tool responses
 */
export function createResponseBuilder(
  tool?: string,
  provider?: string,
  requestId?: string
): MCPResponseBuilder {
  return new MCPResponseBuilder(tool, provider, requestId);
}

/**
 * Create simple success response
 */
export function createSuccessResponse<T>(
  data: T,
  metadata?: Partial<MCPResponseMetadata>
): MCPSuccessResponse<T> {
  return {
    success: true,
    data,
    metadata: {
      timestamp: new Date().toISOString(),
      ...metadata,
    },
  };
}

/**
 * Create simple error response
 */
export function createErrorResponseFromError(
  error: Error | MCPBaseError,
  metadata?: Partial<MCPResponseMetadata>
): MCPErrorResponse {
  const builder = new MCPResponseBuilder();
  if (metadata) {
    // Use builder methods to set metadata instead of direct access
    if (metadata.requestId) builder.withRequestId(metadata.requestId);
    if (metadata.provider) builder.withProvider(metadata.provider);
    if (metadata.tier) builder.withTier(metadata.tier);
    if (metadata.cacheHit !== undefined) builder.withCacheHit(metadata.cacheHit);
    if (metadata.rateLimitRemaining !== undefined)
      builder.withRateLimitRemaining(metadata.rateLimitRemaining);
    if (metadata.warnings) metadata.warnings.forEach((w) => builder.withWarning(w));
    if (metadata.duration !== undefined) builder.withDuration(metadata.duration);
    if (metadata.debug) builder.withDebug(metadata.debug);
  }
  return builder.error(error);
}

/**
 * Check if response is successful
 */
export function isSuccessResponse<T>(
  response: MCPBaseResponse<T>
): response is MCPSuccessResponse<T> {
  return response.success === true;
}

/**
 * Check if response is an error
 */
export function isErrorResponse(response: MCPBaseResponse): response is MCPErrorResponse {
  return response.success === false;
}

/**
 * Extract data from response with type safety
 */
export function getResponseData<T>(response: MCPSuccessResponse<T>): T;
export function getResponseData<T>(response: MCPErrorResponse): undefined;
export function getResponseData<T>(response: MCPBaseResponse<T>): T | undefined;
export function getResponseData<T>(response: MCPBaseResponse<T>): T | undefined {
  if (isSuccessResponse(response)) {
    return response.data;
  }
  return undefined;
}

/**
 * Extract error from response with type safety
 */
export function getResponseError(response: MCPErrorResponse): MCPErrorResponse["error"];
export function getResponseError(response: MCPSuccessResponse): undefined;
export function getResponseError(response: MCPBaseResponse): MCPErrorResponse["error"] | undefined;
export function getResponseError(response: MCPBaseResponse): MCPErrorResponse["error"] | undefined {
  if (isErrorResponse(response)) {
    return response.error;
  }
  return undefined;
}

/**
 * CRM Configuration Manager
 *
 * Extends the base configuration manager with CRM-specific functionality
 * and provides easy access to provider configurations and field mappings.
 */

import { logger } from "../../lib/logger";
import { ConfigurationManager, CRMProviderConfig, MCPCRMServerConfig } from "../../mcp-common";

export class CRMConfigManager {
  private static instance: CRMConfigManager;
  private baseConfigManager: ConfigurationManager;
  private config: MCPCRMServerConfig | null = null;

  private constructor() {
    this.baseConfigManager = ConfigurationManager.getInstance();
  }

  static getInstance(): CRMConfigManager {
    if (!CRMConfigManager.instance) {
      CRMConfigManager.instance = new CRMConfigManager();
    }
    return CRMConfigManager.instance;
  }

  /**
   * Load CRM configuration
   */
  async loadConfig(environment?: string): Promise<MCPCRMServerConfig> {
    try {
      this.config = await this.baseConfigManager.loadConfig<MCPCRMServerConfig>("crm", environment);
      logger.info("CRM configuration loaded successfully", {
        environment: environment || process.env.NODE_ENV || "development",
        providers: this.config.crm.providers.map((p) => p.provider).filter((p) => p.enabled),
      });
      return this.config;
    } catch (error) {
      logger.error("Failed to load CRM configuration", {
        error: error instanceof Error ? error.message : "Unknown error",
        environment: environment || process.env.NODE_ENV || "development",
      });
      throw error;
    }
  }

  /**
   * Get current configuration
   */
  getConfig(): MCPCRMServerConfig {
    if (!this.config) {
      throw new Error("CRM configuration not loaded. Call loadConfig() first.");
    }
    return this.config;
  }

  /**
   * Get provider configuration
   */
  getProviderConfig(provider: "hubspot" | "salesforce" | "dynamics"): CRMProviderConfig | null {
    const config = this.getConfig();
    return config.crm.providers.find((p) => p.provider === provider && p.enabled) || null;
  }

  /**
   * Get default provider configuration
   */
  getDefaultProviderConfig(): CRMProviderConfig | null {
    const config = this.getConfig();
    const defaultProvider = config.crm.defaultProvider;
    return this.getProviderConfig(defaultProvider);
  }

  /**
   * Get field mappings for a provider
   */
  getFieldMappings(provider: "hubspot" | "salesforce" | "dynamics"): Record<string, string> {
    const providerConfig = this.getProviderConfig(provider);
    if (!providerConfig) {
      throw new Error(`Provider ${provider} not found or not enabled`);
    }
    return providerConfig.fieldMappings;
  }

  /**
   * Get custom fields for a provider
   */
  getCustomFields(provider: "hubspot" | "salesforce" | "dynamics") {
    const providerConfig = this.getProviderConfig(provider);
    if (!providerConfig) {
      throw new Error(`Provider ${provider} not found or not enabled`);
    }
    return providerConfig.customFields;
  }

  /**
   * Get rate limit configuration for a provider
   */
  getRateLimitConfig(provider: "hubspot" | "salesforce" | "dynamics") {
    const providerConfig = this.getProviderConfig(provider);
    if (!providerConfig) {
      throw new Error(`Provider ${provider} not found or not enabled`);
    }
    return providerConfig.rateLimit;
  }

  /**
   * Get API endpoint for a provider
   */
  getApiEndpoint(provider: "hubspot" | "salesforce" | "dynamics"): string {
    const providerConfig = this.getProviderConfig(provider);
    if (!providerConfig) {
      throw new Error(`Provider ${provider} not found or not enabled`);
    }
    return providerConfig.apiEndpoint || this.getDefaultApiEndpoint(provider);
  }

  /**
   * Get default API endpoint for a provider
   */
  private getDefaultApiEndpoint(provider: string): string {
    switch (provider) {
      case "hubspot":
        return "https://api.hubapi.com";
      case "salesforce":
        return "https://login.salesforce.com";
      case "dynamics":
        return "https://api.dynamics.com";
      default:
        throw new Error(`Unknown provider: ${provider}`);
    }
  }

  /**
   * Get OAuth scopes for a provider
   */
  getOAuthScopes(provider: "hubspot" | "salesforce" | "dynamics"): string[] {
    const providerConfig = this.getProviderConfig(provider);
    if (!providerConfig) {
      throw new Error(`Provider ${provider} not found or not enabled`);
    }
    return providerConfig.oauth.scopes;
  }

  /**
   * Get token refresh threshold for a provider
   */
  getTokenRefreshThreshold(provider: "hubspot" | "salesforce" | "dynamics"): number {
    const providerConfig = this.getProviderConfig(provider);
    if (!providerConfig) {
      throw new Error(`Provider ${provider} not found or not enabled`);
    }
    return providerConfig.oauth.tokenRefreshThreshold;
  }

  /**
   * Get sync configuration
   */
  getSyncConfig() {
    const config = this.getConfig();
    return config.crm.sync;
  }

  /**
   * Get cache configuration
   */
  getCacheConfig() {
    const config = this.getConfig();
    return config.cache;
  }

  /**
   * Get timeout configuration
   */
  getTimeoutConfig() {
    const config = this.getConfig();
    return config.timeout;
  }

  /**
   * Check if a provider is enabled
   */
  isProviderEnabled(provider: "hubspot" | "salesforce" | "dynamics"): boolean {
    const providerConfig = this.getProviderConfig(provider);
    return providerConfig !== null;
  }

  /**
   * Get all enabled providers
   */
  getEnabledProviders(): ("hubspot" | "salesforce" | "dynamics")[] {
    const config = this.getConfig();
    return config.crm.providers
      .filter((p) => p.enabled)
      .map((p) => p.provider as "hubspot" | "salesforce" | "dynamics");
  }

  /**
   * Validate field mapping exists
   */
  validateFieldMapping(provider: "hubspot" | "salesforce" | "dynamics", field: string): boolean {
    try {
      const mappings = this.getFieldMappings(provider);
      return field in mappings;
    } catch {
      return false;
    }
  }

  /**
   * Get mapped field name
   */
  getMappedFieldName(
    provider: "hubspot" | "salesforce" | "dynamics",
    field: string
  ): string | null {
    try {
      const mappings = this.getFieldMappings(provider);
      return mappings[field] || null;
    } catch {
      return null;
    }
  }

  /**
   * Reload configuration
   */
  async reloadConfig(environment?: string): Promise<MCPCRMServerConfig> {
    this.baseConfigManager.clearCache("crm", environment);
    return this.loadConfig(environment);
  }

  /**
   * Get configuration for environment variables
   */
  getEnvironmentConfig() {
    const config = this.getConfig();
    return {
      NODE_ENV: config.environment,
      DEBUG: config.debug,
      LOG_LEVEL: config.logLevel,
      CRM_DEFAULT_PROVIDER: config.crm.defaultProvider,
    };
  }
}

