/**
 * HubSpot CRM Module
 * 
 * Implements CRM operations for HubSpot via their REST API.
 * Uses OAuth tokens stored at tenant level.
 */

import { logger } from '../../lib/logger';
import {
  CRMActivity,
  CRMCompany,
  CRMConnection,
  CRMContact,
  CRMDeal,
  CRMModule,
  DealSearchParams,
  DealSearchResult,
} from '../types';

// ============================================================================
// HubSpot API Types
// ============================================================================

interface HubSpotDeal {
  id: string;
  properties: {
    dealname: string;
    amount?: string;
    dealstage: string;
    closedate?: string;
    hubspot_owner_id?: string;
    hs_lastmodifieddate?: string;
    createdate?: string;
    [key: string]: string | undefined;
  };
  associations?: {
    contacts?: { results: Array<{ id: string }> };
    companies?: { results: Array<{ id: string }> };
  };
}

interface HubSpotContact {
  id: string;
  properties: {
    firstname?: string;
    lastname?: string;
    email?: string;
    phone?: string;
    jobtitle?: string;
    company?: string;
    [key: string]: string | undefined;
  };
}

interface HubSpotCompany {
  id: string;
  properties: {
    name?: string;
    domain?: string;
    industry?: string;
    numberofemployees?: string;
    annualrevenue?: string;
    [key: string]: string | undefined;
  };
}

interface HubSpotEngagement {
  id: string;
  properties: {
    hs_timestamp?: string;
    hs_engagement_type?: string;
    hs_body_preview?: string;
    hs_call_duration?: string;
    [key: string]: string | undefined;
  };
}

// ============================================================================
// HubSpot Module Implementation
// ============================================================================

export class HubSpotModule implements CRMModule {
  readonly provider = 'hubspot' as const;
  private connection: CRMConnection | null = null;
  private baseUrl = 'https://api.hubapi.com';

  constructor(connection?: CRMConnection) {
    if (connection) {
      this.setConnection(connection);
    }
  }

  setConnection(connection: CRMConnection): void {
    if (connection.provider !== 'hubspot') {
      throw new Error('Invalid connection provider for HubSpot module');
    }
    this.connection = connection;
  }

  isConnected(): boolean {
    return this.connection !== null && this.connection.status === 'active';
  }

  async testConnection(): Promise<boolean> {
    try {
      const response = await this.apiRequest('/crm/v3/objects/deals?limit=1');
      return response.ok;
    } catch {
      return false;
    }
  }

  // ==========================================================================
  // Deals
  // ==========================================================================

  async searchDeals(params: DealSearchParams): Promise<DealSearchResult> {
    const limit = params.limit || 10;

    // Build HubSpot search request
    const filterGroups: Array<{ filters: Array<{ propertyName: string; operator: string; value: string }> }> = [];

    if (params.companyName) {
      // Search by associated company name requires a different approach
      // For now, we'll use deal name search
      filterGroups.push({
        filters: [{
          propertyName: 'dealname',
          operator: 'CONTAINS_TOKEN',
          value: params.companyName,
        }],
      });
    }

    if (params.stage && params.stage.length > 0) {
      filterGroups.push({
        filters: params.stage.map(s => ({
          propertyName: 'dealstage',
          operator: 'EQ',
          value: s,
        })),
      });
    }

    if (params.minAmount) {
      filterGroups.push({
        filters: [{
          propertyName: 'amount',
          operator: 'GTE',
          value: params.minAmount.toString(),
        }],
      });
    }

    const searchBody = {
      filterGroups: filterGroups.length > 0 ? filterGroups : undefined,
      query: params.query,
      limit,
      properties: [
        'dealname', 'amount', 'dealstage', 'closedate',
        'hubspot_owner_id', 'createdate', 'hs_lastmodifieddate',
      ],
    };

    try {
      const response = await this.apiRequest('/crm/v3/objects/deals/search', {
        method: 'POST',
        body: JSON.stringify(searchBody),
      });

      if (!response.ok) {
        throw new Error(`HubSpot search failed: ${response.status}`);
      }

      const data = await response.json();
      const deals: CRMDeal[] = data.results.map((d: HubSpotDeal) => this.mapDeal(d));

      return {
        deals,
        total: data.total || deals.length,
        hasMore: data.paging?.next !== undefined,
      };
    } catch (error) {
      logger.error('HubSpot searchDeals failed', error instanceof Error ? error : undefined);
      return { deals: [], total: 0, hasMore: false };
    }
  }

  async getDeal(dealId: string): Promise<CRMDeal | null> {
    try {
      const response = await this.apiRequest(
        `/crm/v3/objects/deals/${dealId}?properties=dealname,amount,dealstage,closedate,hubspot_owner_id,createdate,hs_lastmodifieddate&associations=contacts,companies`
      );

      if (!response.ok) {
        if (response.status === 404) return null;
        throw new Error(`HubSpot getDeal failed: ${response.status}`);
      }

      const data: HubSpotDeal = await response.json();
      return this.mapDeal(data);
    } catch (error) {
      logger.error('HubSpot getDeal failed', error instanceof Error ? error : undefined);
      return null;
    }
  }

  async getDealContacts(dealId: string): Promise<CRMContact[]> {
    try {
      // Get associated contacts
      const response = await this.apiRequest(
        `/crm/v3/objects/deals/${dealId}/associations/contacts`
      );

      if (!response.ok) {
        return [];
      }

      const { results } = await response.json();
      const contactIds = results.map((r: { id: string }) => r.id);

      if (contactIds.length === 0) return [];

      // Batch get contact details
      const batchResponse = await this.apiRequest('/crm/v3/objects/contacts/batch/read', {
        method: 'POST',
        body: JSON.stringify({
          inputs: contactIds.map((id: string) => ({ id })),
          properties: ['firstname', 'lastname', 'email', 'phone', 'jobtitle', 'company'],
        }),
      });

      if (!batchResponse.ok) {
        return [];
      }

      const batchData = await batchResponse.json();
      return batchData.results.map((c: HubSpotContact) => this.mapContact(c));
    } catch (error) {
      logger.error('HubSpot getDealContacts failed', error instanceof Error ? error : undefined);
      return [];
    }
  }

  async getDealActivities(dealId: string, limit = 20): Promise<CRMActivity[]> {
    try {
      // Get engagements associated with deal
      const response = await this.apiRequest(
        `/crm/v3/objects/deals/${dealId}/associations/engagements`
      );

      if (!response.ok) {
        return [];
      }

      const { results } = await response.json();
      const engagementIds = results.slice(0, limit).map((r: { id: string }) => r.id);

      if (engagementIds.length === 0) return [];

      // Batch get engagement details
      const batchResponse = await this.apiRequest('/crm/v3/objects/engagements/batch/read', {
        method: 'POST',
        body: JSON.stringify({
          inputs: engagementIds.map((id: string) => ({ id })),
          properties: ['hs_timestamp', 'hs_engagement_type', 'hs_body_preview', 'hs_call_duration'],
        }),
      });

      if (!batchResponse.ok) {
        return [];
      }

      const batchData = await batchResponse.json();
      return batchData.results.map((e: HubSpotEngagement) => this.mapActivity(e));
    } catch (error) {
      logger.error('HubSpot getDealActivities failed', error instanceof Error ? error : undefined);
      return [];
    }
  }

  // ==========================================================================
  // Companies
  // ==========================================================================

  async getCompany(companyId: string): Promise<CRMCompany | null> {
    try {
      const response = await this.apiRequest(
        `/crm/v3/objects/companies/${companyId}?properties=name,domain,industry,numberofemployees,annualrevenue`
      );

      if (!response.ok) {
        if (response.status === 404) return null;
        throw new Error(`HubSpot getCompany failed: ${response.status}`);
      }

      const data: HubSpotCompany = await response.json();
      return this.mapCompany(data);
    } catch (error) {
      logger.error('HubSpot getCompany failed', error instanceof Error ? error : undefined);
      return null;
    }
  }

  async searchCompanies(query: string, limit = 10): Promise<CRMCompany[]> {
    try {
      const response = await this.apiRequest('/crm/v3/objects/companies/search', {
        method: 'POST',
        body: JSON.stringify({
          query,
          limit,
          properties: ['name', 'domain', 'industry', 'numberofemployees', 'annualrevenue'],
        }),
      });

      if (!response.ok) {
        return [];
      }

      const data = await response.json();
      return data.results.map((c: HubSpotCompany) => this.mapCompany(c));
    } catch (error) {
      logger.error('HubSpot searchCompanies failed', error instanceof Error ? error : undefined);
      return [];
    }
  }

  // ==========================================================================
  // Sync Operations
  // ==========================================================================

  async updateDealProperties(dealId: string, properties: Record<string, unknown>): Promise<boolean> {
    try {
      const response = await this.apiRequest(`/crm/v3/objects/deals/${dealId}`, {
        method: 'PATCH',
        body: JSON.stringify({ properties }),
      });

      return response.ok;
    } catch (error) {
      logger.error('HubSpot updateDealProperties failed', error instanceof Error ? error : undefined);
      return false;
    }
  }

  async addDealNote(dealId: string, note: string): Promise<boolean> {
    try {
      // Create a note engagement
      const response = await this.apiRequest('/crm/v3/objects/notes', {
        method: 'POST',
        body: JSON.stringify({
          properties: {
            hs_note_body: note,
            hs_timestamp: new Date().toISOString(),
          },
          associations: [{
            to: { id: dealId },
            types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 214 }],
          }],
        }),
      });

      return response.ok;
    } catch (error) {
      logger.error('HubSpot addDealNote failed', error instanceof Error ? error : undefined);
      return false;
    }
  }

  // ==========================================================================
  // Private Helpers
  // ==========================================================================

  private async apiRequest(path: string, options: RequestInit = {}): Promise<Response> {
    if (!this.connection?.accessToken) {
      throw new Error('HubSpot not connected');
    }

    // legitimate-exception: MCP CRM module makes authenticated calls to HubSpot API directly
    return fetch(`${this.baseUrl}${path}`, {
      ...options,
      headers: {
        'Authorization': `Bearer ${this.connection.accessToken}`,
        'Content-Type': 'application/json',
        ...options.headers,
      },
    });
  }

  private mapDeal(d: HubSpotDeal): CRMDeal {
    return {
      id: d.id,
      externalId: d.id,
      provider: 'hubspot',
      name: d.properties.dealname || 'Untitled Deal',
      amount: d.properties.amount ? parseFloat(d.properties.amount) : undefined,
      stage: d.properties.dealstage || 'unknown',
      closeDate: d.properties.closedate ? new Date(d.properties.closedate) : undefined,
      createdAt: new Date(d.properties.createdate || Date.now()),
      updatedAt: new Date(d.properties.hs_lastmodifieddate || Date.now()),
      ownerId: d.properties.hubspot_owner_id,
      companyId: d.associations?.companies?.results[0]?.id,
      properties: d.properties,
    };
  }

  private mapContact(c: HubSpotContact): CRMContact {
    return {
      id: c.id,
      externalId: c.id,
      provider: 'hubspot',
      firstName: c.properties.firstname,
      lastName: c.properties.lastname,
      email: c.properties.email,
      phone: c.properties.phone,
      title: c.properties.jobtitle,
      companyName: c.properties.company,
      properties: c.properties,
    };
  }

  private mapCompany(c: HubSpotCompany): CRMCompany {
    return {
      id: c.id,
      externalId: c.id,
      provider: 'hubspot',
      name: c.properties.name || 'Unknown Company',
      domain: c.properties.domain,
      industry: c.properties.industry,
      size: c.properties.numberofemployees,
      revenue: c.properties.annualrevenue ? parseFloat(c.properties.annualrevenue) : undefined,
      properties: c.properties,
    };
  }

  private mapActivity(e: HubSpotEngagement): CRMActivity {
    const typeMap: Record<string, CRMActivity['type']> = {
      EMAIL: 'email',
      CALL: 'call',
      MEETING: 'meeting',
      TASK: 'task',
      NOTE: 'note',
    };

    return {
      id: e.id,
      externalId: e.id,
      provider: 'hubspot',
      type: typeMap[e.properties.hs_engagement_type || ''] || 'note',
      body: e.properties.hs_body_preview,
      occurredAt: new Date(e.properties.hs_timestamp || Date.now()),
      durationMinutes: e.properties.hs_call_duration
        ? parseInt(e.properties.hs_call_duration) / 60000
        : undefined,
      properties: e.properties,
    };
  }
}

/**
 * Salesforce CRM Module
 * 
 * Implements CRM operations for Salesforce via their REST API.
 * Uses OAuth tokens stored at tenant level.
 */

import { logger } from '../../lib/logger';
import {
  CRMActivity,
  CRMCompany,
  CRMConnection,
  CRMContact,
  CRMDeal,
  CRMModule,
  DealSearchParams,
  DealSearchResult,
} from '../types';

// ============================================================================
// Salesforce API Types
// ============================================================================

interface SalesforceOpportunity {
  Id: string;
  Name: string;
  Amount?: number;
  StageName: string;
  CloseDate?: string;
  Probability?: number;
  OwnerId?: string;
  Owner?: { Name: string };
  AccountId?: string;
  Account?: { Name: string };
  CreatedDate: string;
  LastModifiedDate: string;
  Description?: string;
  [key: string]: unknown;
}

interface SalesforceContact {
  Id: string;
  FirstName?: string;
  LastName?: string;
  Email?: string;
  Phone?: string;
  Title?: string;
  AccountId?: string;
  Account?: { Name: string };
  [key: string]: unknown;
}

interface SalesforceAccount {
  Id: string;
  Name: string;
  Website?: string;
  Industry?: string;
  NumberOfEmployees?: number;
  AnnualRevenue?: number;
  [key: string]: unknown;
}

interface SalesforceTask {
  Id: string;
  Subject?: string;
  Description?: string;
  ActivityDate?: string;
  Status: string;
  Type?: string;
  WhatId?: string;
  WhoId?: string;
  OwnerId?: string;
  CreatedDate: string;
  [key: string]: unknown;
}

interface SalesforceEvent {
  Id: string;
  Subject?: string;
  Description?: string;
  StartDateTime?: string;
  EndDateTime?: string;
  DurationInMinutes?: number;
  WhatId?: string;
  WhoId?: string;
  OwnerId?: string;
  CreatedDate: string;
  [key: string]: unknown;
}

interface SalesforceQueryResult<T> {
  totalSize: number;
  done: boolean;
  records: T[];
  nextRecordsUrl?: string;
}

// ============================================================================
// Salesforce Module Implementation
// ============================================================================

export class SalesforceModule implements CRMModule {
  readonly provider = 'salesforce' as const;
  private connection: CRMConnection | null = null;

  constructor(connection?: CRMConnection) {
    if (connection) {
      this.setConnection(connection);
    }
  }

  setConnection(connection: CRMConnection): void {
    if (connection.provider !== 'salesforce') {
      throw new Error('Invalid connection provider for Salesforce module');
    }
    if (!connection.instanceUrl) {
      throw new Error('Salesforce connection requires instanceUrl');
    }
    this.connection = connection;
  }

  isConnected(): boolean {
    return this.connection !== null && this.connection.status === 'active';
  }

  async testConnection(): Promise<boolean> {
    try {
      const response = await this.apiRequest('/services/data/v59.0/limits');
      return response.ok;
    } catch {
      return false;
    }
  }

  // ==========================================================================
  // Deals (Opportunities)
  // ==========================================================================

  async searchDeals(params: DealSearchParams): Promise<DealSearchResult> {
    const limit = params.limit || 10;
    const conditions: string[] = [];

    if (params.query) {
      // SOSL search for free text
      conditions.push(`Name LIKE '%${this.escapeSOQL(params.query)}%'`);
    }

    if (params.companyName) {
      conditions.push(`Account.Name LIKE '%${this.escapeSOQL(params.companyName)}%'`);
    }

    if (params.stage && params.stage.length > 0) {
      const stages = params.stage.map(s => `'${this.escapeSOQL(s)}'`).join(',');
      conditions.push(`StageName IN (${stages})`);
    }

    if (params.minAmount) {
      conditions.push(`Amount >= ${params.minAmount}`);
    }

    if (params.maxAmount) {
      conditions.push(`Amount <= ${params.maxAmount}`);
    }

    if (params.closeDateAfter) {
      conditions.push(`CloseDate >= ${params.closeDateAfter.toISOString().split('T')[0]}`);
    }

    if (params.closeDateBefore) {
      conditions.push(`CloseDate <= ${params.closeDateBefore.toISOString().split('T')[0]}`);
    }

    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

    const query = `
      SELECT Id, Name, Amount, StageName, CloseDate, Probability,
             OwnerId, Owner.Name, AccountId, Account.Name,
             CreatedDate, LastModifiedDate
      FROM Opportunity
      ${whereClause}
      ORDER BY LastModifiedDate DESC
      LIMIT ${limit}
    `;

    try {
      const result = await this.soqlQuery<SalesforceOpportunity>(query);

      return {
        deals: result.records.map(opp => this.mapOpportunity(opp)),
        total: result.totalSize,
        hasMore: !result.done,
      };
    } catch (error) {
      logger.error('Salesforce searchDeals failed', error instanceof Error ? error : undefined);
      return { deals: [], total: 0, hasMore: false };
    }
  }

  async getDeal(dealId: string): Promise<CRMDeal | null> {
    const query = `
      SELECT Id, Name, Amount, StageName, CloseDate, Probability,
             OwnerId, Owner.Name, AccountId, Account.Name,
             CreatedDate, LastModifiedDate, Description
      FROM Opportunity
      WHERE Id = '${this.escapeSOQL(dealId)}'
    `;

    try {
      const result = await this.soqlQuery<SalesforceOpportunity>(query);
      if (result.records.length === 0) return null;
      return this.mapOpportunity(result.records[0]);
    } catch (error) {
      logger.error('Salesforce getDeal failed', error instanceof Error ? error : undefined);
      return null;
    }
  }

  async getDealContacts(dealId: string): Promise<CRMContact[]> {
    // Get contacts via OpportunityContactRole
    const query = `
      SELECT ContactId, Contact.Id, Contact.FirstName, Contact.LastName,
             Contact.Email, Contact.Phone, Contact.Title,
             Contact.AccountId, Contact.Account.Name, Role
      FROM OpportunityContactRole
      WHERE OpportunityId = '${this.escapeSOQL(dealId)}'
    `;

    try {
      const result = await this.soqlQuery<{
        ContactId: string;
        Contact: SalesforceContact;
        Role?: string;
      }>(query);

      return result.records.map(ocr => ({
        ...this.mapContact(ocr.Contact),
        role: ocr.Role,
      }));
    } catch (error) {
      logger.error('Salesforce getDealContacts failed', error instanceof Error ? error : undefined);
      return [];
    }
  }

  async getDealActivities(dealId: string, limit = 20): Promise<CRMActivity[]> {
    const activities: CRMActivity[] = [];

    // Get Tasks
    const taskQuery = `
      SELECT Id, Subject, Description, ActivityDate, Status, Type, CreatedDate
      FROM Task
      WHERE WhatId = '${this.escapeSOQL(dealId)}'
      ORDER BY CreatedDate DESC
      LIMIT ${Math.floor(limit / 2)}
    `;

    // Get Events
    const eventQuery = `
      SELECT Id, Subject, Description, StartDateTime, EndDateTime, DurationInMinutes, CreatedDate
      FROM Event
      WHERE WhatId = '${this.escapeSOQL(dealId)}'
      ORDER BY CreatedDate DESC
      LIMIT ${Math.floor(limit / 2)}
    `;

    try {
      const [taskResult, eventResult] = await Promise.all([
        this.soqlQuery<SalesforceTask>(taskQuery),
        this.soqlQuery<SalesforceEvent>(eventQuery),
      ]);

      activities.push(...taskResult.records.map(t => this.mapTask(t)));
      activities.push(...eventResult.records.map(e => this.mapEvent(e)));

      // Sort by date
      activities.sort((a, b) => b.occurredAt.getTime() - a.occurredAt.getTime());

      return activities.slice(0, limit);
    } catch (error) {
      logger.error('Salesforce getDealActivities failed', error instanceof Error ? error : undefined);
      return [];
    }
  }

  // ==========================================================================
  // Companies (Accounts)
  // ==========================================================================

  async getCompany(companyId: string): Promise<CRMCompany | null> {
    const query = `
      SELECT Id, Name, Website, Industry, NumberOfEmployees, AnnualRevenue
      FROM Account
      WHERE Id = '${this.escapeSOQL(companyId)}'
    `;

    try {
      const result = await this.soqlQuery<SalesforceAccount>(query);
      if (result.records.length === 0) return null;
      return this.mapAccount(result.records[0]);
    } catch (error) {
      logger.error('Salesforce getCompany failed', error instanceof Error ? error : undefined);
      return null;
    }
  }

  async searchCompanies(searchQuery: string, limit = 10): Promise<CRMCompany[]> {
    const query = `
      SELECT Id, Name, Website, Industry, NumberOfEmployees, AnnualRevenue
      FROM Account
      WHERE Name LIKE '%${this.escapeSOQL(searchQuery)}%'
      ORDER BY LastModifiedDate DESC
      LIMIT ${limit}
    `;

    try {
      const result = await this.soqlQuery<SalesforceAccount>(query);
      return result.records.map(a => this.mapAccount(a));
    } catch (error) {
      logger.error('Salesforce searchCompanies failed', error instanceof Error ? error : undefined);
      return [];
    }
  }

  // ==========================================================================
  // Sync Operations
  // ==========================================================================

  async updateDealProperties(dealId: string, properties: Record<string, unknown>): Promise<boolean> {
    try {
      const response = await this.apiRequest(
        `/services/data/v59.0/sobjects/Opportunity/${dealId}`,
        {
          method: 'PATCH',
          body: JSON.stringify(properties),
        }
      );

      return response.ok || response.status === 204;
    } catch (error) {
      logger.error('Salesforce updateDealProperties failed', error instanceof Error ? error : undefined);
      return false;
    }
  }

  async addDealNote(dealId: string, note: string): Promise<boolean> {
    try {
      // Create a Note (ContentNote) and link to Opportunity
      const noteResponse = await this.apiRequest(
        '/services/data/v59.0/sobjects/ContentNote',
        {
          method: 'POST',
          body: JSON.stringify({
            Title: 'ValueCanvas Insight',
            Content: Buffer.from(note).toString('base64'),
          }),
        }
      );

      if (!noteResponse.ok) {
        // Fallback to Task
        const taskResponse = await this.apiRequest(
          '/services/data/v59.0/sobjects/Task',
          {
            method: 'POST',
            body: JSON.stringify({
              Subject: 'ValueCanvas Insight',
              Description: note,
              WhatId: dealId,
              Status: 'Completed',
              Priority: 'Normal',
            }),
          }
        );
        return taskResponse.ok;
      }

      const noteData = await noteResponse.json();

      // Link note to opportunity
      await this.apiRequest(
        '/services/data/v59.0/sobjects/ContentDocumentLink',
        {
          method: 'POST',
          body: JSON.stringify({
            ContentDocumentId: noteData.id,
            LinkedEntityId: dealId,
            ShareType: 'V',
          }),
        }
      );

      return true;
    } catch (error) {
      logger.error('Salesforce addDealNote failed', error instanceof Error ? error : undefined);
      return false;
    }
  }

  // ==========================================================================
  // Private Helpers
  // ==========================================================================

  private async apiRequest(path: string, options: RequestInit = {}): Promise<Response> {
    if (!this.connection?.accessToken || !this.connection?.instanceUrl) {
      throw new Error('Salesforce not connected');
    }

    const url = `${this.connection.instanceUrl}${path}`;


    // eslint-disable-next-line no-restricted-globals
    return fetch(url, {
      ...options,
      headers: {
        'Authorization': `Bearer ${this.connection.accessToken}`,
        'Content-Type': 'application/json',
        ...options.headers,
      },
    });
  }

  private async soqlQuery<T>(query: string): Promise<SalesforceQueryResult<T>> {
    const encodedQuery = encodeURIComponent(query.trim().replace(/\s+/g, ' '));
    const response = await this.apiRequest(`/services/data/v59.0/query?q=${encodedQuery}`);

    if (!response.ok) {
      const error = await response.text();
      throw new Error(`SOQL query failed: ${error}`);
    }

    return response.json();
  }

  private escapeSOQL(value: string): string {
    // Escape special SOQL characters
    return value
      .replace(/\\/g, '\\\\')
      .replace(/'/g, "\\'")
      .replace(/"/g, '\\"');
  }

  private mapOpportunity(opp: SalesforceOpportunity): CRMDeal {
    return {
      id: opp.Id,
      externalId: opp.Id,
      provider: 'salesforce',
      name: opp.Name,
      amount: opp.Amount,
      stage: opp.StageName,
      probability: opp.Probability,
      closeDate: opp.CloseDate ? new Date(opp.CloseDate) : undefined,
      createdAt: new Date(opp.CreatedDate),
      updatedAt: new Date(opp.LastModifiedDate),
      ownerId: opp.OwnerId,
      ownerName: opp.Owner?.Name,
      companyId: opp.AccountId,
      companyName: opp.Account?.Name,
      properties: opp,
    };
  }

  private mapContact(c: SalesforceContact): CRMContact {
    return {
      id: c.Id,
      externalId: c.Id,
      provider: 'salesforce',
      firstName: c.FirstName,
      lastName: c.LastName,
      email: c.Email,
      phone: c.Phone,
      title: c.Title,
      companyId: c.AccountId,
      companyName: c.Account?.Name,
      properties: c,
    };
  }

  private mapAccount(a: SalesforceAccount): CRMCompany {
    return {
      id: a.Id,
      externalId: a.Id,
      provider: 'salesforce',
      name: a.Name,
      domain: a.Website,
      industry: a.Industry,
      size: a.NumberOfEmployees?.toString(),
      revenue: a.AnnualRevenue,
      properties: a,
    };
  }

  private mapTask(t: SalesforceTask): CRMActivity {
    const typeMap: Record<string, CRMActivity['type']> = {
      Call: 'call',
      Email: 'email',
      Meeting: 'meeting',
    };

    return {
      id: t.Id,
      externalId: t.Id,
      provider: 'salesforce',
      type: typeMap[t.Type || ''] || 'task',
      subject: t.Subject,
      body: t.Description,
      occurredAt: new Date(t.ActivityDate || t.CreatedDate),
      dealId: t.WhatId,
      properties: t,
    };
  }

  private mapEvent(e: SalesforceEvent): CRMActivity {
    return {
      id: e.Id,
      externalId: e.Id,
      provider: 'salesforce',
      type: 'meeting',
      subject: e.Subject,
      body: e.Description,
      occurredAt: new Date(e.StartDateTime || e.CreatedDate),
      durationMinutes: e.DurationInMinutes,
      dealId: e.WhatId,
      properties: e,
    };
  }
}

import React, { lazy, Suspense } from 'react';
import { Navigate, Route, Routes } from 'react-router-dom';

import { ErrorBoundary } from '@/components/common/ErrorBoundary';

import { AdminLayout } from './AdminLayout';

const AdminDashboard = lazy(() => import('./AdminDashboard'));
const UsersPage = lazy(() => import('./UsersPage'));
const SecurityDashboard = lazy(() => import('./SecurityDashboard').then((m) => ({ default: m.SecurityDashboard })));
const AuditLogsPage = lazy(() => import('./compliance/AuditLogsPage').then((m) => ({ default: m.AuditLogsPage })));
const PolicyHistoryPage = lazy(() => import('./compliance/PolicyHistoryPage').then((m) => ({ default: m.PolicyHistoryPage })));
const RetentionPage = lazy(() => import('./compliance/RetentionPage').then((m) => ({ default: m.RetentionPage })));
const DsrPage = lazy(() => import('./compliance/DsrPage').then((m) => ({ default: m.DsrPage })));
const ComplianceModePage = lazy(() => import('./compliance/ComplianceModePage').then((m) => ({ default: m.ComplianceModePage })));

const LoadingFallback = () => <div className="flex items-center justify-center h-32"><div className="text-sm text-gray-400">Loading...</div></div>;

export const AdminRouter: React.FC = () => {
  return (
    <ErrorBoundary>
      <Suspense fallback={<LoadingFallback />}>
        <Routes>
        <Route element={<AdminLayout />}>
          <Route index element={<Navigate to="dashboard" replace />} />

          <Route path="dashboard" element={<AdminDashboard />} />
          <Route path="identity/users" element={<UsersPage />} />
          <Route path="security-dashboard" element={<SecurityDashboard />} />

          <Route path="compliance/audit-logs" element={<AuditLogsPage />} />
