export function CasesPage() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  // Seed from ?q= once on mount; lazy initializer avoids overwriting user edits on re-renders
  const [searchQuery, setSearchQuery] = useState(() => searchParams.get("q") ?? "");
  const [statusFilter, setStatusFilter] = useState("all");
  const [sortBy, setSortBy] = useState("updated");
  const [viewMode, setViewMode] = useState<ViewMode>("grid");

  const { data: rawCases, isLoading, error, refetch } = useCasesList();
  const { data: portfolio } = usePortfolioValue();

  const cases = (rawCases ?? []).map(toCaseView);

  const filteredCases = cases.filter((c) => {
    const matchesSearch =
      c.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      c.company.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === "all" || c.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const sortedCases = [...filteredCases].sort((a, b) => {
    switch (sortBy) {
      case "name":
        return a.name.localeCompare(b.name);
      case "value":
        return parseValue(b.value) - parseValue(a.value);
      default:
        return 0;
    }
  });

  const stats = {
    total: cases.length,
    inProgress: cases.filter((c) => c.status === "in-progress" || c.status === "review").length,
    committed: cases.filter((c) => c.status === "committed" || c.status === "published").length,
    totalValue: portfolio?.totalValue ?? 0,
  };

  return (
    <div className="p-8 max-w-7xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Cases</h1>
          <p className="text-muted-foreground mt-1">
            {stats.total} cases • {stats.inProgress} in progress
            {stats.totalValue > 0 &&
              ` • $${(stats.totalValue / 1_000_000).toFixed(1)}M total value`}
          </p>
        </div>
        <Button onClick={() => navigate("/app/cases/new")}>
          <Plus className="h-4 w-4 mr-2" />
          New Case
        </Button>
      </div>

      {/* Filters Bar */}
      <div className="flex items-center gap-3 mb-6">
        {/* Search */}
        <div className="flex-1 max-w-sm">
          <SearchInput
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onClear={() => setSearchQuery("")}
            placeholder="Search cases..."
          />
        </div>

        {/* Status Filter */}
        <SimpleSelect
          value={statusFilter}
          onValueChange={setStatusFilter}
          options={STATUS_OPTIONS}
        />

        {/* Sort */}
        <div className="flex items-center gap-2">
          <ArrowUpDown className="h-4 w-4 text-muted-foreground" />
          <SimpleSelect
            value={sortBy}
            onValueChange={setSortBy}
            options={SORT_OPTIONS}
          />
        </div>

        {/* Spacer */}
        <div className="flex-1" />

        {/* View Toggle */}
        <div className="flex items-center border border-border rounded-lg overflow-hidden" role="group" aria-label="View mode">
          <button
            onClick={() => setViewMode("grid")}
            aria-label="Grid view"
            aria-pressed={viewMode === "grid"}
            className={cn(
              "p-2 transition-colors",
              viewMode === "grid"
                ? "bg-primary text-primary-foreground"
                : "text-muted-foreground hover:bg-muted"
            )}
          >
            <Grid className="h-4 w-4" aria-hidden="true" />
          </button>
          <button
            onClick={() => setViewMode("list")}
            aria-label="List view"
            aria-pressed={viewMode === "list"}
            className={cn(
              "p-2 transition-colors",
              viewMode === "list"
                ? "bg-primary text-primary-foreground"
                : "text-muted-foreground hover:bg-muted"
            )}
          >
            <List className="h-4 w-4" aria-hidden="true" />
          </button>
        </div>
      </div>

      {/* Loading State */}
      {isLoading && <CaseListSkeleton />}

      {/* Error State */}
      {error && !isLoading && (
        <ErrorState error={error as Error} onRetry={() => refetch()} />
      )}

      {/* Cases Grid/List */}
      {!isLoading && !error && (
        <>
          {viewMode === "grid" ? (
            <div className="grid grid-cols-3 gap-4">
              {sortedCases.map((caseItem) => (
                <CaseCard
                  key={caseItem.id}
                  caseData={caseItem}
                  onClick={() => navigate(`/app/cases/${caseItem.id}`)}
                />
              ))}
            </div>
          ) : (
            <Card className="overflow-hidden">
              {/* Table Header */}
              <div className="grid grid-cols-12 gap-4 px-6 py-3 bg-muted/50 border-b text-xs font-medium text-muted-foreground uppercase tracking-wider">
                <div className="col-span-4">Case</div>
                <div className="col-span-2">Value</div>
                <div className="col-span-2">Status</div>
                <div className="col-span-2">Owner</div>
                <div className="col-span-2">Updated</div>
              </div>

              {/* Table Body */}
              <div className="divide-y">
                {sortedCases.map((caseItem) => (
                  <CaseRow
                    key={caseItem.id}
                    caseData={caseItem}
                    onClick={() => navigate(`/app/cases/${caseItem.id}`)}
                  />
                ))}
              </div>
            </Card>
          )}

          {/* Empty State */}
          {sortedCases.length === 0 && (
            <div className="flex flex-col items-center justify-center py-20 text-center">
              <div className="w-12 h-12 rounded-xl bg-muted flex items-center justify-center mb-4">
                <Briefcase className="h-5 w-5 text-muted-foreground" />
              </div>
              <h3 className="text-sm font-medium text-foreground mb-1">No cases found</h3>
              <p className="text-sm text-muted-foreground mb-5 max-w-xs">
                {searchQuery || statusFilter !== "all"
                  ? "Try adjusting your search or filters."
                  : "Create your first value case to get started."}
              </p>
              {searchQuery || statusFilter !== "all" ? (
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => {
                    setSearchQuery("");
                    setStatusFilter("all");
                  }}
                >
                  Clear filters
                </Button>
              ) : (
                <Button size="sm" onClick={() => navigate("/app/cases/new")}>
                  <Plus className="h-4 w-4 mr-1.5" />
                  New Case
                </Button>
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
}

interface CaseCardProps {
  caseData: CaseView;
  onClick: () => void;
}

function CaseCard({ caseData, onClick }: CaseCardProps) {
  const statusConfig = STATUS_CONFIG[caseData.status] ?? STATUS_CONFIG.draft;

  return (
    <Card
      className="p-4 hover:border-primary/50 hover:shadow-sm transition-all cursor-pointer"
      onClick={onClick}
    >
      <div className="flex items-start justify-between mb-3">
        <div className="w-10 h-10 rounded-full bg-muted flex items-center justify-center text-sm font-medium text-muted-foreground border border-border">
          {caseData.initials}
