/**
 * TemplatesPage
 * 
 * Manage value case templates - view, create, edit, delete.
 */

import {
  BarChart3,
  Check,
  Copy,
  DollarSign,
  Edit2,
  Filter,
  MoreVertical,
  Plus,
  Search,
  Shield,
  Star,
  Trash2,
  TrendingUp,
  Zap,
} from 'lucide-react';
import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';

import { DEFAULT_TEMPLATES } from '@/features/templates/defaultTemplates';
import type { TemplateCategory, ValueCaseTemplate } from '@/features/templates/types';
import { cn } from '@/lib/utils';

const CATEGORY_CONFIG: Record<TemplateCategory, { label: string; icon: React.ComponentType<{ className?: string }>; color: string }> = {
  general: { label: 'General', icon: BarChart3, color: 'bg-slate-100 text-slate-600' },
  saas: { label: 'SaaS', icon: Zap, color: 'bg-purple-100 text-purple-600' },
  infrastructure: { label: 'Infrastructure', icon: DollarSign, color: 'bg-blue-100 text-blue-600' },
  security: { label: 'Security', icon: Shield, color: 'bg-amber-100 text-amber-600' },
  productivity: { label: 'Productivity', icon: TrendingUp, color: 'bg-emerald-100 text-emerald-600' },
  custom: { label: 'Custom', icon: Star, color: 'bg-pink-100 text-pink-600' },
};

export function TemplatesPage() {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<TemplateCategory | 'all'>('all');
  const [templates, setTemplates] = useState<ValueCaseTemplate[]>(DEFAULT_TEMPLATES);

  // Filter templates
  const filteredTemplates = useMemo(() => {
    return templates.filter(template => {
      const matchesSearch = 
        template.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        template.description.toLowerCase().includes(searchQuery.toLowerCase());

      const matchesCategory = 
        selectedCategory === 'all' || template.category === selectedCategory;

      return matchesSearch && matchesCategory;
    });
  }, [templates, searchQuery, selectedCategory]);

  // Group by category
  const groupedTemplates = useMemo(() => {
    const groups: Record<string, ValueCaseTemplate[]> = {};

    filteredTemplates.forEach(template => {
      const category = template.category;
      if (!groups[category]) {
        groups[category] = [];
      }
      groups[category].push(template);
    });

    return groups;
  }, [filteredTemplates]);

  const handleUseTemplate = (templateId: string) => {
    navigate(`/app/cases/new?template=${templateId}`);
  };

  const handleDuplicateTemplate = (template: ValueCaseTemplate) => {
    const newTemplate: ValueCaseTemplate = {
      ...template,
      id: `custom_${Date.now()}`,
      name: `${template.name} (Copy)`,
      isDefault: false,
      isCustom: true,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };
    setTemplates([...templates, newTemplate]);
  };

  const handleDeleteTemplate = (templateId: string) => {
    setTemplates(templates.filter(t => t.id !== templateId));
  };

  return (
    <div className="flex flex-col h-full">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-8 py-4">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-900">Case Templates</h1>
            <p className="text-sm text-slate-500 mt-1">
              Pre-built value case structures for common scenarios
            </p>
          </div>
          <button
            onClick={() => navigate('/app/templates/new')}
            className="flex items-center gap-2 px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 transition-colors"
          >
            <Plus size={18} />
            Create Template
          </button>
        </div>

        {/* Search and Filter */}
        <div className="flex items-center gap-4">
          <div className="flex-1 max-w-md relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search templates..."
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent"
            />
          </div>

          <div className="flex items-center gap-2">
            <Filter className="w-4 h-4 text-slate-400" />
            <select
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value as TemplateCategory | 'all')}
              className="px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary"
            >
              <option value="all">All Categories</option>
              {Object.entries(CATEGORY_CONFIG).map(([key, config]) => (
                <option key={key} value={key}>{config.label}</option>
              ))}
            </select>
          </div>
        </div>
      </header>

      {/* Content */}
      <main className="flex-1 overflow-y-auto p-6">
        {Object.entries(groupedTemplates).length === 0 ? (
          <div className="text-center py-12">
            <BarChart3 className="w-12 h-12 text-slate-300 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-slate-700 mb-2">No templates found</h3>
            <p className="text-sm text-slate-500">
              Try adjusting your search or filter criteria
            </p>
          </div>
        ) : (
          <div className="space-y-8">
            {Object.entries(groupedTemplates).map(([category, categoryTemplates]) => {
              const config = CATEGORY_CONFIG[category as TemplateCategory];
              const Icon = config?.icon || BarChart3;

              return (
                <section key={category}>
                  <div className="flex items-center gap-2 mb-4">
                    <div className={cn("p-1.5 rounded-lg", config?.color || 'bg-slate-100')}>
                      <Icon className="w-4 h-4" />
                    </div>
                    <h2 className="text-lg font-semibold text-slate-800">
                      {config?.label || category}
                    </h2>
                    <span className="text-sm text-slate-400">
                      ({categoryTemplates.length})
                    </span>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {categoryTemplates.map((template) => (
                      <TemplateCard
                        key={template.id}
                        template={template}
                        onUse={() => handleUseTemplate(template.id)}
                        onDuplicate={() => handleDuplicateTemplate(template)}
                        onDelete={() => handleDeleteTemplate(template.id)}
                      />
                    ))}
                  </div>
                </section>
              );
            })}
          </div>
        )}
      </main>
    </div>
  );
}

// Template Card Component
interface TemplateCardProps {
  template: ValueCaseTemplate;
  onUse: () => void;
  onDuplicate: () => void;
  onDelete: () => void;
}

function TemplateCard({ template, onUse, onDuplicate, onDelete }: TemplateCardProps) {
  const [showMenu, setShowMenu] = useState(false);

  return (
    <div className="bg-white rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-slate-100">
        <div className="flex items-start justify-between">
          <div className="flex-1">
            <div className="flex items-center gap-2">
              <h3 className="font-semibold text-slate-900">{template.name}</h3>
              {template.isDefault && (
                <span className="px-1.5 py-0.5 text-[10px] font-medium bg-primary/10 text-primary rounded">
                  DEFAULT
                </span>
              )}
            </div>
            <p className="text-sm text-slate-500 mt-1 line-clamp-2">
              {template.description}
            </p>
          </div>

          <div className="relative">
            <button
              onClick={() => setShowMenu(!showMenu)}
              className="p-1 hover:bg-slate-100 rounded transition-colors"
            >
              <MoreVertical size={16} className="text-slate-400" />
            </button>

            {showMenu && (
              <>
                <div 
                  className="fixed inset-0 z-10" 
                  onClick={() => setShowMenu(false)} 
                />
                <div className="absolute right-0 top-8 z-20 w-40 bg-white rounded-lg shadow-lg border border-slate-200 py-1">
                  <button
                    onClick={() => { onDuplicate(); setShowMenu(false); }}
                    className="w-full px-3 py-2 text-left text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                  >
                    <Copy size={14} />
                    Duplicate
                  </button>
                  {template.isCustom && (
                    <>
                      <button
                        onClick={() => setShowMenu(false)}
                        className="w-full px-3 py-2 text-left text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                      >
                        <Edit2 size={14} />
                        Edit
                      </button>
                      <button
                        onClick={() => { onDelete(); setShowMenu(false); }}
                        className="w-full px-3 py-2 text-left text-sm text-red-600 hover:bg-red-50 flex items-center gap-2"
                      >
                        <Trash2 size={14} />
                        Delete
                      </button>
                    </>
                  )}
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      {/* Metrics Preview */}
      <div className="p-4 bg-slate-50">
        <div className="text-xs font-medium text-slate-500 mb-2">KEY METRICS</div>
        <div className="flex flex-wrap gap-1.5">
          {template.primaryMetrics.slice(0, 4).map((metricId) => {
            const metric = template.metrics.find(m => m.id === metricId);
            if (!metric) return null;

            return (
              <span
                key={metricId}
                className="px-2 py-1 text-xs font-medium bg-white border border-slate-200 rounded-md text-slate-600"
              >
                {metric.name}
              </span>
            );
          })}
          {template.primaryMetrics.length > 4 && (
            <span className="px-2 py-1 text-xs text-slate-400">
              +{template.primaryMetrics.length - 4} more
            </span>
          )}
        </div>
      </div>

      {/* Footer */}
      <div className="p-4 flex items-center justify-between">
        <div className="text-xs text-slate-400">
          {template.metrics.length} metrics · {template.valueDrivers.length} drivers
        </div>
        <button
          onClick={onUse}
          className="flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium text-primary hover:bg-primary/5 rounded-lg transition-colors"
        >
          <Check size={14} />
          Use Template
        </button>
      </div>
    </div>
  );
}

export default TemplatesPage;

/**
 * ValueDriverLibrary - Admin command center for value drivers
 * 
 * Create, edit, publish, and manage strategic value drivers.
 */

import {
  Archive,
  BarChart3,
  Edit,
  Eye,
  Plus,
  Sparkles,
  Target,
  TrendingUp,
} from "lucide-react";
import { useEffect, useState } from "react";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { SearchInput } from "@/components/ui/input";
import { SimpleSelect } from "@/components/ui/select";
import { ValueDriverEditor } from "@/components/value-drivers/ValueDriverEditor";
import { cn } from "@/lib/utils";
import {
  DriverStatus,
  PERSONA_TAG_LABELS,
  useValueDrivers,
  VALUE_DRIVER_TYPE_LABELS,
  ValueDriver,
  ValueDriverType,
} from "@/types/valueDriver";

const TYPE_COLORS: Record<ValueDriverType, string> = {
  "cost-savings": "bg-emerald-100 text-emerald-700 border-emerald-200",
  "revenue-lift": "bg-blue-100 text-blue-700 border-blue-200",
  "productivity-gain": "bg-purple-100 text-purple-700 border-purple-200",
  "risk-mitigation": "bg-amber-100 text-amber-700 border-amber-200",
};

const STATUS_COLORS: Record<DriverStatus, string> = {
  draft: "bg-slate-100 text-slate-600",
  published: "bg-emerald-100 text-emerald-700",
  archived: "bg-red-100 text-red-600",
};

const TYPE_OPTIONS = [
  { value: "all", label: "All Types" },
  { value: "cost-savings", label: "Cost Savings" },
  { value: "revenue-lift", label: "Revenue Lift" },
  { value: "productivity-gain", label: "Productivity Gain" },
  { value: "risk-mitigation", label: "Risk Mitigation" },
];

const STATUS_OPTIONS = [
  { value: "all", label: "All Statuses" },
  { value: "published", label: "Published" },
  { value: "draft", label: "Draft" },
  { value: "archived", label: "Archived" },
];

export function ValueDriverLibrary() {
  const { drivers: fetchedDrivers, loading: driversLoading } = useValueDrivers();
  const [drivers, setDrivers] = useState<ValueDriver[]>([]);
  const [searchQuery, setSearchQuery] = useState("");

  // Sync fetched drivers into local state so edits/creates can be applied optimistically
  useEffect(() => {
    setDrivers(fetchedDrivers);
  }, [fetchedDrivers]);
  const [typeFilter, setTypeFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("all");
  const [selectedDriver, setSelectedDriver] = useState<ValueDriver | null>(null);
  const [isEditorOpen, setIsEditorOpen] = useState(false);

  const filteredDrivers = drivers.filter((d) => {
    const matchesSearch =
      d.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      d.description.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesType = typeFilter === "all" || d.type === typeFilter;
    const matchesStatus = statusFilter === "all" || d.status === statusFilter;
    return matchesSearch && matchesType && matchesStatus;
  });

  const stats = {
    total: drivers.length,
    published: drivers.filter((d) => d.status === "published").length,
    totalUsage: drivers.reduce((sum, d) => sum + d.usageCount, 0),
    avgWinRate: drivers
      .filter((d) => d.winRateCorrelation)
      .reduce((sum, d, _, arr) => sum + (d.winRateCorrelation || 0) / arr.length, 0),
  };

  const handleCreateNew = () => {
    setSelectedDriver(null);
    setIsEditorOpen(true);
  };

  const handleEdit = (driver: ValueDriver) => {
    setSelectedDriver(driver);
    setIsEditorOpen(true);
  };

  const handleToggleStatus = (driver: ValueDriver) => {
    const newStatus: DriverStatus = driver.status === "published" ? "archived" : "published";
    setDrivers((prev) =>
      prev.map((d) => (d.id === driver.id ? { ...d, status: newStatus } : d))
    );
  };

  const handleSave = (driver: ValueDriver) => {
    if (selectedDriver) {
      setDrivers((prev) =>
        prev.map((d) => (d.id === driver.id ? driver : d))
      );
    } else {
      setDrivers((prev) => [...prev, { ...driver, id: `vd-${Date.now()}` }]);
    }
    setIsEditorOpen(false);
  };

  return (
    <div className="flex flex-col h-full">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-8 py-4">
        <div className="flex items-start justify-between mb-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-900">Value Drivers</h1>
            <p className="text-slate-500 mt-1">
              Strategic value propositions for consistent, high-impact messaging
            </p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline">
              <Sparkles className="h-4 w-4 mr-2" />
              AI Suggest
            </Button>
            <Button onClick={handleCreateNew}>
              <Plus className="h-4 w-4 mr-2" />
              New Driver
            </Button>
          </div>
        </div>
      </header>

      <div className="flex-1 overflow-auto p-8 bg-slate-50">

      {/* Stats Cards */}
      <div className="grid grid-cols-4 gap-4 mb-6">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Total Drivers</p>
                <p className="text-2xl font-bold">{stats.total}</p>
              </div>
              <Target className="h-8 w-8 text-muted-foreground/30" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Published</p>
                <p className="text-2xl font-bold text-emerald-600">{stats.published}</p>
              </div>
              <Eye className="h-8 w-8 text-emerald-500/30" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Total Usage</p>
                <p className="text-2xl font-bold">{stats.totalUsage}</p>
              </div>
              <BarChart3 className="h-8 w-8 text-muted-foreground/30" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Avg Win Rate</p>
                <p className="text-2xl font-bold text-blue-600">
                  {(stats.avgWinRate * 100).toFixed(0)}%
                </p>
              </div>
              <TrendingUp className="h-8 w-8 text-blue-500/30" />
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Filters */}
      <Card className="mb-6">
        <CardContent className="p-4">
          <div className="flex items-center gap-4">
            <div className="flex-1 max-w-sm">
              <SearchInput
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onClear={() => setSearchQuery("")}
                placeholder="Search drivers..."
              />
            </div>
            <SimpleSelect
              value={typeFilter}
              onValueChange={setTypeFilter}
              options={TYPE_OPTIONS}
            />
            <SimpleSelect
              value={statusFilter}
              onValueChange={setStatusFilter}
              options={STATUS_OPTIONS}
            />
          </div>
        </CardContent>
      </Card>

      {/* Drivers Table */}
      <Card>
        <div className="overflow-hidden">
          {/* Table Header */}
          <div className="grid grid-cols-12 gap-4 px-6 py-3 bg-muted/50 border-b text-xs font-medium text-muted-foreground uppercase tracking-wider">
            <div className="col-span-4">Driver</div>
            <div className="col-span-2">Type</div>
            <div className="col-span-2">Personas</div>
            <div className="col-span-1">Usage</div>
            <div className="col-span-1">Win Rate</div>
            <div className="col-span-1">Status</div>
            <div className="col-span-1"></div>
          </div>

          {/* Table Body */}
          <div className="divide-y">
            {driversLoading && (
              <div className="px-6 py-8 text-center text-sm text-muted-foreground">
                Loading value drivers…
              </div>
            )}
            {!driversLoading && filteredDrivers.length === 0 && (
              <div className="px-6 py-8 text-center text-sm text-muted-foreground">
                No value drivers found.
              </div>
            )}
            {filteredDrivers.map((driver) => (
              <div
                key={driver.id}
                className="grid grid-cols-12 gap-4 px-6 py-4 items-center hover:bg-muted/30 transition-colors"
              >
                {/* Name & Description */}
                <div className="col-span-4">
                  <p className="font-medium text-slate-900">{driver.name}</p>
                  <p className="text-sm text-muted-foreground line-clamp-1">
                    {driver.description}
                  </p>
                </div>

                {/* Type */}
                <div className="col-span-2">
                  <Badge className={cn("text-xs", TYPE_COLORS[driver.type])}>
                    {VALUE_DRIVER_TYPE_LABELS[driver.type]}
                  </Badge>
                </div>

                {/* Personas */}
                <div className="col-span-2 flex flex-wrap gap-1">
                  {driver.personaTags.slice(0, 2).map((tag) => (
                    <Badge key={tag} variant="outline" className="text-xs">
                      {PERSONA_TAG_LABELS[tag]}
                    </Badge>
                  ))}
                  {driver.personaTags.length > 2 && (
                    <Badge variant="outline" className="text-xs">
                      +{driver.personaTags.length - 2}
                    </Badge>
                  )}
                </div>

                {/* Usage */}
                <div className="col-span-1">
                  <span className="text-sm font-medium">{driver.usageCount}</span>
                </div>

                {/* Win Rate */}
                <div className="col-span-1">
                  {driver.winRateCorrelation ? (
                    <span className="text-sm font-medium text-emerald-600">
                      {(driver.winRateCorrelation * 100).toFixed(0)}%
                    </span>
                  ) : (
                    <span className="text-sm text-muted-foreground">—</span>
                  )}
                </div>

                {/* Status */}
                <div className="col-span-1">
                  <Badge className={cn("text-xs capitalize", STATUS_COLORS[driver.status])}>
                    {driver.status}
                  </Badge>
                </div>

                {/* Actions */}
                <div className="col-span-1 flex items-center justify-end gap-1">
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-8 w-8 p-0"
                    onClick={() => handleEdit(driver)}
                  >
                    <Edit className="h-4 w-4" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-8 w-8 p-0"
                    onClick={() => handleToggleStatus(driver)}
                  >
                    {driver.status === "published" ? (
                      <Archive className="h-4 w-4" />
                    ) : (
                      <Eye className="h-4 w-4" />
                    )}
                  </Button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </Card>

      {/* Empty State */}
      {filteredDrivers.length === 0 && (
        <div className="text-center py-12">
          <Target className="h-12 w-12 mx-auto text-muted-foreground/30 mb-4" />
          <p className="text-muted-foreground">No value drivers found</p>
          <Button variant="outline" className="mt-4" onClick={handleCreateNew}>
            Create your first driver
          </Button>
        </div>
      )}

      {/* Editor Modal */}
      {isEditorOpen && (
        <ValueDriverEditor
          driver={selectedDriver}
          onSave={handleSave}
          onClose={() => setIsEditorOpen(false)}
        />
      )}
      </div>
    </div>
  );
}

export default ValueDriverLibrary;

