    });

    renderAtPath("/app/cases/abc-123");
    await user.click(screen.getByRole("button", { name: /retry/i }));

    expect(mockRefetch).toHaveBeenCalledOnce();
  });

  it("renders case name and status when fetch succeeds", () => {
