/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */
interface ValueCase {
  id: string;
  name: string;
  company: string;
  projectedValue: string;
  confidence: number;
  daysInStage: number;
  domainPack: string;
  alert?: string;
  drift?: string;
}

interface MaturityColumn {
