export default function ValueMaturityBoard() {
  // Removed useMaturityCards to clean up useWireframeData.ts dependency
  // Use useMemo to avoid recreating this empty object on every render
  const liveCards: Record<string, any[]> = React.useMemo(() => ({}), []);

  // Merge live cards into the static column structure.
  // Live cards replace mock cases in their respective columns when available.
  const mergedInitial: MaturityColumn[] = initialColumns.map((col) => {
    const live = liveCards[col.id];
    if (!live || live.length === 0) return col;
    return {
      ...col,
      cases: live.map((c) => ({
        id: c.id,
        name: c.title,
        company: c.company,
        projectedValue: c.value,
        confidence: c.confidence,
        daysInStage: c.daysInStage,
        domainPack: "Enterprise IT",
        alert: c.blocked ? "Blocked" : undefined,
      })),
    };
  });

  const [cols, setCols] = useState<MaturityColumn[]>(mergedInitial);
  // Track columns the user has modified via drag-and-drop so live data
  // updates don't overwrite their local reordering.
  const userModifiedCols = useRef<Set<string>>(new Set());

  // Sync live data into cols whenever the API response arrives or updates.
  // Columns the user has already dragged cards into/out of are left untouched.
  useEffect(() => {
    setCols((prev) =>
      prev.map((col) => {
        if (userModifiedCols.current.has(col.id)) return col;
        const live = liveCards[col.id];
        if (!live || live.length === 0) return col;
        return {
          ...col,
          cases: live.map((c) => ({
            id: c.id,
            name: c.title,
            company: c.company,
            projectedValue: c.value,
            confidence: c.confidence,
            daysInStage: c.daysInStage,
            domainPack: "Enterprise IT",
            alert: c.blocked ? "Blocked" : undefined,
          })),
        };
      })
    );
  }, [liveCards]);

  const [draggedCase, setDraggedCase] = useState<ValueCase | null>(null);
  const [draggedFromCol, setDraggedFromCol] = useState<string | null>(null);
  const [toasts, setToasts] = useState<GateToast[]>([]);
  const [dropFeedback, setDropFeedback] = useState<Record<string, "accept" | "reject" | "warning" | null>>({});
  const toastCounter = useRef(0);

  const handleDragStart = useCallback((c: ValueCase, colId: string) => {
    setDraggedCase(c);
    setDraggedFromCol(colId);
  }, []);

  const addToast = useCallback((result: PolicyResult, caseName: string, fromCol: string, toCol: string) => {
    const id = `toast-${++toastCounter.current}`;
    const fromLabel = cols.find((c) => c.id === fromCol)?.shortLabel || fromCol;
    const toLabel = cols.find((c) => c.id === toCol)?.shortLabel || toCol;
    setToasts((prev) => [...prev.slice(-4), { id, result, caseName, fromCol: fromLabel, toCol: toLabel }]);
    // Auto-dismiss after 6 seconds
    setTimeout(() => {
      setToasts((prev) => prev.filter((t) => t.id !== id));
    }, 6000);
  }, [cols]);

  const handleDrop = useCallback(
    (targetColId: string) => {
      if (!draggedCase || !draggedFromCol || targetColId === draggedFromCol) {
        setDraggedCase(null);
        setDraggedFromCol(null);
        return;
      }

      const result = evaluatePolicyGate(draggedCase, draggedFromCol, targetColId);

      if (result.allowed) {
        // Mark both affected columns as user-modified so live data won't overwrite them.
        userModifiedCols.current.add(draggedFromCol);
        userModifiedCols.current.add(targetColId);

        // Move the card
        setCols((prev) =>
          prev.map((col) => {
            if (col.id === draggedFromCol) {
              return { ...col, cases: col.cases.filter((c) => c.id !== draggedCase!.id) };
            }
            if (col.id === targetColId) {
              return { ...col, cases: [...col.cases, { ...draggedCase!, daysInStage: 0 }] };
            }
            return col;
          })
        );

        // Flash feedback
        const feedbackType = result.severity === "warning" ? "warning" : "accept";
        setDropFeedback((prev) => ({ ...prev, [targetColId]: feedbackType }));
        setTimeout(() => setDropFeedback((prev) => ({ ...prev, [targetColId]: null })), 800);
      } else {
        // Rejection animation — flash the target column red
        setDropFeedback((prev) => ({ ...prev, [targetColId]: "reject" }));
        setTimeout(() => setDropFeedback((prev) => ({ ...prev, [targetColId]: null })), 800);
      }

      addToast(result, draggedCase.name, draggedFromCol, targetColId);
      setDraggedCase(null);
      setDraggedFromCol(null);
    },
    [draggedCase, draggedFromCol, addToast]
  );

  const dismissToast = useCallback((id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  return (
    <ResponsivePageLayout activeHref="/maturity">
      {/* Header */}
      <header className="h-12 border-b border-border flex items-center px-4 shrink-0">
        <h1 className="text-sm font-semibold">Value Maturity Board</h1>
        <span className="text-[9px] font-mono px-1.5 py-0.5 rounded bg-muted text-muted-foreground ml-3 hidden sm:inline">Decision Readiness View</span>
        <div className="ml-auto flex items-center gap-2">
          <span className="text-[9px] font-mono text-muted-foreground hidden md:inline">Drag cards to test policy gates</span>
          <GripVertical className="w-3.5 h-3.5 text-muted-foreground/50 hidden md:block" />
        </div>
      </header>

      {/* Summary */}
      <AnnotatedSection annotation={ANNOTATIONS.maturityBoard} position="top-right">
        <SummaryBar cols={cols} />
      </AnnotatedSection>

      {/* Desktop Kanban — horizontal scroll with drag-and-drop */}
      <div className="hidden md:flex flex-1 overflow-x-auto overflow-y-hidden relative">
        <div className="flex h-full min-w-max">
          {cols.map((col, ci) => (
            <DropColumn
              key={col.id}
              col={col}
              colIndex={ci}
              draggedCase={draggedCase}
              draggedFromCol={draggedFromCol}
              onDragStart={handleDragStart}
              onDrop={handleDrop}
              dropFeedback={dropFeedback[col.id] || null}
            />
          ))}
        </div>
      </div>

      {/* Mobile Accordion — vertical stacked (no drag-and-drop) */}
      <div className="md:hidden flex-1 overflow-y-auto">
        {cols.map((col, ci) => (
          <MobileColumn key={col.id} col={col} defaultOpen={ci < 3} />
        ))}
      </div>

      {/* Policy Gate Legend */}
      <PolicyGateLegend />

      {/* Toast overlay */}
      <GateToastOverlay toasts={toasts} onDismiss={dismissToast} />
    </ResponsivePageLayout>
  );
}

/**
 * Workflow State Repository
 *
 * CRITICAL FIX: Provides database-backed state persistence
 * Replaces singleton in-memory state to enable concurrent request isolation
 *
 * Pattern: Repository pattern for clean separation of concerns
 */

import { SupabaseClient } from "@supabase/supabase-js";
import { z } from "zod";

import { logger } from "../lib/logger";
import { WorkflowStatus } from "../types";

export type JsonPrimitive = string | number | boolean | null;
export type JsonValue = JsonPrimitive | JsonValue[] | { [key: string]: JsonValue };
export type JsonObject = { [key: string]: JsonValue };

const jsonValueSchema: z.ZodType<JsonValue> = z.lazy(() =>
  z.union([z.string(), z.number(), z.boolean(), z.null(), z.array(jsonValueSchema), z.record(z.string(), jsonValueSchema)])
);

const workflowMetadataSchema = z
  .object({
    startedAt: z.string().datetime().optional(),
    lastUpdatedAt: z.string().datetime().optional(),
    errorCount: z.number().int().nonnegative().optional(),
    retryCount: z.number().int().nonnegative().optional(),
  })
  .optional();

const workflowStateSchema = z.object({
  currentStage: z.string().min(1),
  status: z.custom<WorkflowStatus>((value): value is WorkflowStatus => {
    return ["pending", "running", "completed", "failed", "cancelled"].includes(String(value));
  }, "Invalid workflow status"),
  completedStages: z.array(z.string()),
  context: z.record(z.string(), jsonValueSchema),
  metadata: workflowMetadataSchema,
});

const sessionDataSchema = z.object({
  id: z.string().min(1),
  tenant_id: z.string().optional(),
  user_id: z.string().min(1),
  workflow_state: workflowStateSchema,
  status: z.enum(["active", "completed", "error", "abandoned"]),
  created_at: z.string().datetime(),
  updated_at: z.string().datetime(),
});

/**
 * Workflow state stored in database
 */
export interface WorkflowState {
  currentStage: string;
  status: WorkflowStatus;
  completedStages: string[];
  context: JsonObject;
  metadata?: {
    startedAt?: string;
    lastUpdatedAt?: string;
    errorCount?: number;
    retryCount?: number;
  };
}

/**
 * Session data from database
 */
export interface SessionData {
  id: string;
  tenant_id?: string;
  user_id: string;
  workflow_state: WorkflowState;
  status: "active" | "completed" | "error" | "abandoned";
  created_at: string;
  updated_at: string;
}

/**
 * Repository for managing workflow state persistence
 */
export class WorkflowStateRepository {
  constructor(private supabase: SupabaseClient) {}

  private requireTenantId(tenantId: string): string {
    if (!tenantId) {
      throw new Error("Tenant ID is required for workflow state access");
    }
    return tenantId;
  }

  private parseWorkflowState(payload: unknown, context: Record<string, string>): WorkflowState | null {
    const parsed = workflowStateSchema.safeParse(payload);

    if (!parsed.success) {
      logger.error("Invalid workflow state payload", {
        issues: parsed.error.issues,
        ...context,
      });
      return null;
    }

    return parsed.data;
  }

  private parseSessionData(payload: unknown, context: Record<string, string>): SessionData | null {
    const parsed = sessionDataSchema.safeParse(payload);

    if (!parsed.success) {
      logger.error("Invalid session payload", {
        issues: parsed.error.issues,
        ...context,
      });
      return null;
    }

    return parsed.data;
  }

  /**
   * Get workflow state for a session
   *
   * @param sessionId Session identifier
   * @returns Workflow state or null if not found
   */
  async getState(sessionId: string, tenantId: string): Promise<WorkflowState | null> {
    try {
      const resolvedTenantId = this.requireTenantId(tenantId);
      const { data, error } = await this.supabase
        .from("agent_sessions")
        .select("workflow_state")
        .eq("id", sessionId)
        .eq("tenant_id", resolvedTenantId)
        .single();

      if (error) {
        logger.error("Failed to get workflow state", { error, sessionId });
        return null;
      }

      if (!data || !data.workflow_state) {
        logger.warn("No workflow state found", { sessionId });
        return null;
      }

      return this.parseWorkflowState(data.workflow_state, { sessionId, tenantId: resolvedTenantId });
    } catch (error) {
      logger.error("Error getting workflow state", {
        error: error instanceof Error ? error : undefined,
        sessionId,
      });
      return null;
    }
  }

  /**
   * Save workflow state for a session
   *
   * @param sessionId Session identifier
   * @param state Workflow state to save
   */
  async saveState(sessionId: string, state: WorkflowState, tenantId: string): Promise<void> {
    try {
      const resolvedTenantId = this.requireTenantId(tenantId);
      const validatedState = workflowStateSchema.parse(state);

      // Add metadata
      const stateWithMetadata: WorkflowState = {
        ...validatedState,
        metadata: {
          ...validatedState.metadata,
          lastUpdatedAt: new Date().toISOString(),
        },
      };

      const { error } = await this.supabase
        .from("agent_sessions")
        .update({
          workflow_state: stateWithMetadata,
          updated_at: new Date().toISOString(),
        })
        .eq("id", sessionId)
        .eq("tenant_id", resolvedTenantId);

      if (error) {
        logger.error("Failed to save workflow state", { error, sessionId });
        throw error;
      }

      logger.debug("Workflow state saved", {
        sessionId,
        stage: state.currentStage,
        status: state.status,
      });
    } catch (error) {
      logger.error("Error saving workflow state", {
        error: error instanceof Error ? error : undefined,
        sessionId,
      });
      throw error;
    }
  }

  /**
   * Create a new session with initial workflow state
   *
   * @param userId User identifier
   * @param initialState Initial workflow state
   * @returns Session ID
   */
  async createSession(
    userId: string,
    initialState: WorkflowState,
    tenantId: string
  ): Promise<string> {
    try {
      const resolvedTenantId = this.requireTenantId(tenantId);
      const validatedInitialState = workflowStateSchema.parse(initialState);

      // Add metadata
      const stateWithMetadata: WorkflowState = {
        ...validatedInitialState,
        metadata: {
          startedAt: new Date().toISOString(),
          lastUpdatedAt: new Date().toISOString(),
          errorCount: 0,
          retryCount: 0,
        },
      };

      const { data, error } = await this.supabase
        .from("agent_sessions")
        .insert({
          user_id: userId,
          tenant_id: resolvedTenantId,
          workflow_state: stateWithMetadata,
          status: "active",
        })
        .select("id")
        .single();

      if (error || !data) {
        logger.error("Failed to create session", { error, userId });
        throw error || new Error("No session ID returned");
      }

      logger.info("Session created", {
        sessionId: data.id,
        userId,
        initialStage: initialState.currentStage,
      });

      return data.id;
    } catch (error) {
      logger.error("Error creating session", {
        error: error instanceof Error ? error : undefined,
        userId,
      });
      throw error;
    }
  }

  /**
   * Get full session data
   *
   * @param sessionId Session identifier
   * @returns Session data or null if not found
   */
  async getSession(sessionId: string, tenantId: string): Promise<SessionData | null> {
    try {
      const resolvedTenantId = this.requireTenantId(tenantId);
      const { data, error } = await this.supabase
        .from("agent_sessions")
        .select("*")
        .eq("id", sessionId)
        .eq("tenant_id", resolvedTenantId)
        .single();

      if (error) {
        logger.error("Failed to get session", { error, sessionId });
        return null;
      }

      return this.parseSessionData(data, { sessionId, tenantId: resolvedTenantId });
    } catch (error) {
      logger.error("Error getting session", {
        error: error instanceof Error ? error : undefined,
        sessionId,
      });
      return null;
    }
  }

  /**
   * Update session status
   *
   * @param sessionId Session identifier
   * @param status New status
   */
  async updateSessionStatus(
    sessionId: string,
    status: "active" | "completed" | "error" | "abandoned",
    tenantId: string
  ): Promise<void> {
    try {
      const resolvedTenantId = this.requireTenantId(tenantId);
      const { error } = await this.supabase
        .from("agent_sessions")
        .update({
          status,
          updated_at: new Date().toISOString(),
        })
        .eq("id", sessionId)
        .eq("tenant_id", resolvedTenantId);

      if (error) {
        logger.error("Failed to update session status", { error, sessionId, status });
        throw error;
      }

      logger.debug("Session status updated", { sessionId, status });
    } catch (error) {
      logger.error("Error updating session status", {
        error: error instanceof Error ? error : undefined,
        sessionId,
        status,
      });
      throw error;
    }
  }

  /**
   * Increment error count for a session
   *
   * @param sessionId Session identifier
   */
  async incrementErrorCount(sessionId: string, tenantId: string): Promise<void> {
    try {
      const state = await this.getState(sessionId, tenantId);
      if (!state) {
        throw new Error("Session not found");
      }

      const updatedState: WorkflowState = {
        ...state,
        metadata: {
          ...state.metadata,
          errorCount: (state.metadata?.errorCount || 0) + 1,
          lastUpdatedAt: new Date().toISOString(),
        },
      };

      await this.saveState(sessionId, updatedState, tenantId);
    } catch (error) {
      logger.error("Error incrementing error count", {
        error: error instanceof Error ? error : undefined,
        sessionId,
      });
      throw error;
    }
  }

  /**
   * Get active sessions for a user
   *
   * @param userId User identifier
   * @param limit Maximum number of sessions to return
   * @returns Array of session data
   */
  async getActiveSessions(
    userId: string,
    tenantId: string,
    limit: number = 10
  ): Promise<SessionData[]> {
    try {
      const resolvedTenantId = this.requireTenantId(tenantId);
      const { data, error } = await this.supabase
        .from("agent_sessions")
        .select("*")
        .eq("user_id", userId)
        .eq("tenant_id", resolvedTenantId)
        .eq("status", "active")
        .order("updated_at", { ascending: false })
        .limit(limit);

      if (error) {
        logger.error("Failed to get active sessions", { error, userId });
        return [];
      }

      return (data ?? []).flatMap((session) => {
        const parsed = this.parseSessionData(session, { userId, tenantId: resolvedTenantId });
        return parsed ? [parsed] : [];
      });
    } catch (error) {
      logger.error("Error getting active sessions", {
        error: error instanceof Error ? error : undefined,
        userId,
      });
      return [];
    }
  }

  /**
   * Clean up old sessions
   *
   * @param olderThanDays Delete sessions older than this many days
   * @returns Number of sessions deleted
   */
  async cleanupOldSessions(olderThanDays: number = 30, tenantId: string): Promise<number> {
    try {
      const resolvedTenantId = this.requireTenantId(tenantId);
      const cutoffDate = new Date();
      cutoffDate.setDate(cutoffDate.getDate() - olderThanDays);

      const { data, error } = await this.supabase
        .from("agent_sessions")
        .delete()
        .lt("updated_at", cutoffDate.toISOString())
        .eq("tenant_id", resolvedTenantId)
        .neq("status", "active")
        .select("id");

      if (error) {
        logger.error("Failed to cleanup old sessions", { error, olderThanDays });
        return 0;
      }

      const count = data?.length || 0;
      logger.info("Old sessions cleaned up", { count, olderThanDays });
      return count;
    } catch (error) {
      logger.error("Error cleaning up old sessions", {
        error: error instanceof Error ? error : undefined,
        olderThanDays,
      });
      return 0;
    }
  }

  /**
   * Atomic state update with optimistic locking
   *
   * Prevents race conditions by checking updated_at timestamp
   *
   * @param sessionId Session identifier
   * @param expectedUpdatedAt Expected last update timestamp
   * @param newState New workflow state
   * @param tenantId Tenant identifier
   * @returns True if update succeeded, false if conflict detected
   */
  async atomicStateUpdate(
    sessionId: string,
    expectedUpdatedAt: string,
    newState: WorkflowState,
    tenantId: string
  ): Promise<boolean> {
    try {
      const resolvedTenantId = this.requireTenantId(tenantId);
      const validatedState = workflowStateSchema.parse(newState);
      const stateWithMetadata: WorkflowState = {
        ...validatedState,
        metadata: {
          ...validatedState.metadata,
          lastUpdatedAt: new Date().toISOString(),
        },
      };

      const { data, error } = await this.supabase
        .from("agent_sessions")
        .update({
          workflow_state: stateWithMetadata,
          updated_at: new Date().toISOString(),
        })
        .eq("id", sessionId)
        .eq("tenant_id", resolvedTenantId)
        .eq("updated_at", expectedUpdatedAt)
        .select("id");

      if (error) {
        logger.error("Failed atomic state update", { error, sessionId });
        return false;
      }

      if (!data || data.length === 0) {
        logger.warn("Atomic state update conflict detected", {
          sessionId,
          expectedUpdatedAt,
        });
        return false;
      }

      logger.debug("Atomic state update succeeded", { sessionId });
      return true;
    } catch (error) {
      logger.error("Error in atomic state update", {
        error: error instanceof Error ? error : undefined,
        sessionId,
      });
      return false;
    }
  }
}

/**
 * CORS Validator
 *
 * Validates CORS configuration to prevent security misconfigurations
 *
 * API-001: CORS hardening to prevent cross-origin attacks
 *
 * Security Rules:
 * 1. Cannot use wildcard (*) origin with credentials enabled
 * 2. All origins must be valid URLs (except '*')
 * 3. Origins are matched exactly (no pattern matching for security)
 */

import { logger } from "../lib/logger";

export interface CORSConfig {
  enabled: boolean;
  origins: string[];
  methods: string[];
  allowedHeaders: string[];
  exposedHeaders: string[];
  credentials: boolean;
  maxAge: number;
}

/**
 * Validate CORS configuration for security issues
 */
export function validateCORSConfig(config: CORSConfig): void {
  // CRITICAL: Prevent wildcard with credentials (CSRF vulnerability)
  if (config.credentials && config.origins.includes("*")) {
    throw new Error(
      "SECURITY ERROR: Cannot use wildcard (*) origin with credentials enabled. " +
        "This allows any site to make authenticated requests, enabling CSRF attacks."
    );
  }

  // Validate each origin
  config.origins.forEach((origin) => {
    if (origin === "*") {
      logger.warn("CORS: Using wildcard origin - credentials will be disabled");
      return;
    }

    if (!isValidOrigin(origin)) {
      throw new Error(
        `Invalid CORS origin: "${origin}". ` +
          'Origins must be valid URLs (e.g., https://app.example.com) or "*"'
      );
    }
  });

  // Warn if credentials disabled (may be intentional)
  if (
    !config.credentials &&
    config.origins.length > 0 &&
    !config.origins.includes("*")
  ) {
    logger.info(
      "CORS: Credentials disabled - cookies will not be sent cross-origin"
    );
  }

  logger.info("CORS configuration validated", {
    origins: config.origins.length,
    credentials: config.credentials,
    methods: config.methods.join(", "),
  });
}

/**
 * Check if origin is a valid URL
 */
export function isValidOrigin(origin: string): boolean {
  try {
    const url = new URL(origin);

    // Must use HTTPS in production (except localhost for dev)
    if (import.meta.env?.PROD) {
      if (url.protocol !== "https:") {
        logger.warn(`Non-HTTPS origin in production: ${origin}`);
        return false;
      }
    }

    // No trailing slashes
    if (origin.endsWith("/")) {
      logger.warn(`Origin has trailing slash: ${origin}`);
      return false;
    }

    return true;
  } catch (error) {
    return false;
  }
}

/**
 * Get CORS origins from environment variable
 * Format: Comma-separated list of origins
 * Example: "https://app.valueos.com,https://staging.valueos.com"
 */
export function getEnvCORSOrigins(): string[] {
  // Use import.meta.env directly for Vite compatibility in the browser
  const envOrigins = (import.meta.env?.VITE_CORS_ORIGINS as string) || "";

  if (!envOrigins) {
    // Default origins for development
    if (import.meta.env?.DEV) {
      return [
        "http://localhost:5173", // Vite dev server
        "http://localhost:3000", // Alternative port
        "http://127.0.0.1:5173",
      ];
    }

    // Production should always have explicit origins
    logger.error("CORS_ORIGINS not configured for production!");
    return [];
  }

  // Parse and validate
  const origins = envOrigins
    .split(",")
    .map((origin) => origin.trim())
    .filter((origin) => origin.length > 0);

  logger.info("CORS origins loaded from environment", {
    count: origins.length,
  });
  return origins;
}

/**
 * Check if request origin is allowed
 */
export function isOriginAllowed(
  requestOrigin: string | undefined,
  allowedOrigins: string[]
): boolean {
  if (!requestOrigin) {
    return false;
  }

  // Wildcard allows all
  if (allowedOrigins.includes("*")) {
    return true;
  }

  // Exact match only (no subdomain wildcards for security)
  return allowedOrigins.includes(requestOrigin);
}

/**
 * Get CORS headers for response
 */
export function getCORSHeaders(
  requestOrigin: string | undefined,
  config: CORSConfig
): Record<string, string> {
  const headers: Record<string, string> = {};

  if (!config.enabled) {
    return headers;
  }

  // Check if origin is allowed
  if (isOriginAllowed(requestOrigin, config.origins)) {
    // Use specific origin (not wildcard) when credentials enabled
    if (config.credentials && requestOrigin) {
      headers["Access-Control-Allow-Origin"] = requestOrigin;
      headers["Access-Control-Allow-Credentials"] = "true";
    } else if (config.origins.includes("*")) {
      headers["Access-Control-Allow-Origin"] = "*";
    } else if (requestOrigin) {
      headers["Access-Control-Allow-Origin"] = requestOrigin;
    }

    // Other headers
    headers["Access-Control-Allow-Methods"] = config.methods.join(", ");
    headers["Access-Control-Allow-Headers"] = config.allowedHeaders.join(", ");

    if (config.exposedHeaders.length > 0) {
      headers["Access-Control-Expose-Headers"] =
        config.exposedHeaders.join(", ");
    }

    if (config.maxAge > 0) {
      headers["Access-Control-Max-Age"] = config.maxAge.toString();
    }

    // Vary header to prevent caching issues
    headers["Vary"] = "Origin";
  }

  return headers;
}

/**
 * CSRF Protection
 *
 * Implements Cross-Site Request Forgery protection using the Synchronizer Token Pattern.
 * Generates and validates CSRF tokens for state-changing operations.
 */

import * as React from "react";

import { getConfig } from "../config/environment";
import { logger } from "../lib/logger";

import { getSecurityConfig } from "./SecurityConfig";

/**
 * Constant-time string comparison to prevent timing attacks.
 *
 * SECURITY AUDIT (2026-03-18): Added to replace direct === comparison
 * on CSRF tokens, which leaks token content via response time differences.
 *
 * Always iterates over max(a.length, b.length) characters. Out-of-bounds
 * indices return 0 via (charCodeAt || 0), avoiding modulo/NaN issues and
 * ensuring the loop duration depends only on the longer input -- not on
 * which argument is the stored token vs. attacker-supplied value.
 */
function constantTimeEqual(a: string, b: string): boolean {
  const len = Math.max(a.length, b.length);
  let result = a.length ^ b.length; // non-zero when lengths differ
  for (let i = 0; i < len; i++) {
    result |= (a.charCodeAt(i) || 0) ^ (b.charCodeAt(i) || 0);
  }
  return result === 0;
}

/**
 * CSRF token configuration
 */
export interface CSRFTokenConfig {
  tokenLength: number;
  tokenLifetime: number; // milliseconds
  headerName: string;
  cookieName: string;
  paramName: string;
}

/**
 * CSRF token
 */
export interface CSRFToken {
  token: string;
  createdAt: number;
  expiresAt: number;
}

/**
 * Default CSRF configuration
 */
const DEFAULT_CSRF_CONFIG: CSRFTokenConfig = {
  tokenLength: 32,
  tokenLifetime: 3600000, // 1 hour
  headerName: "X-CSRF-Token",
  cookieName: "csrf_token",
  paramName: "_csrf",
};

/**
 * CSRF token storage
 */
class CSRFTokenStore {
  private tokens: Map<string, CSRFToken> = new Map();

  /**
   * Store a token
   */
  set(key: string, token: CSRFToken): void {
    this.tokens.set(key, token);
    this.cleanup();
  }

  /**
   * Get a token
   */
  get(key: string): CSRFToken | undefined {
    const token = this.tokens.get(key);
    if (token && token.expiresAt > Date.now()) {
      return token;
    }
    if (token) {
      this.tokens.delete(key);
    }
    return undefined;
  }

  /**
   * Delete a token
   */
  delete(key: string): void {
    this.tokens.delete(key);
  }

  /**
   * Clean up expired tokens
   */
  private cleanup(): void {
    const now = Date.now();
    for (const [key, token] of this.tokens.entries()) {
      if (token.expiresAt <= now) {
        this.tokens.delete(key);
      }
    }
  }

  /**
   * Clear all tokens
   */
  clear(): void {
    this.tokens.clear();
  }
}

/**
 * Global token store
 */
const tokenStore = new CSRFTokenStore();

/**
 * Generate a random token
 */
function generateRandomToken(length: number): string {
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  return Array.from(array, (byte) => byte.toString(16).padStart(2, "0")).join("");
}

/**
 * Generate a CSRF token
 */
export function generateCSRFToken(
  sessionId?: string,
  config: Partial<CSRFTokenConfig> = {}
): CSRFToken {
  const cfg = { ...DEFAULT_CSRF_CONFIG, ...config };
  const token = generateRandomToken(cfg.tokenLength);
  const createdAt = Date.now();
  const expiresAt = createdAt + cfg.tokenLifetime;

  const csrfToken: CSRFToken = {
    token,
    createdAt,
    expiresAt,
  };

  // Store token
  const key = sessionId || "default";
  tokenStore.set(key, csrfToken);

  return csrfToken;
}

/**
 * Validate a CSRF token
 */
export function validateCSRFToken(
  token: string,
  sessionId?: string,
  config: Partial<CSRFTokenConfig> = {}
): boolean {
  if (!token) {
    return false;
  }

  const key = sessionId || "default";
  const storedToken = tokenStore.get(key);

  if (!storedToken) {
    return false;
  }

  // SECURITY AUDIT (2026-03-18): Use constant-time comparison to prevent
  // timing attacks that could allow character-by-character token guessing.
  if (!constantTimeEqual(storedToken.token, token)) {
    return false;
  }

  // Check if token is expired
  if (storedToken.expiresAt <= Date.now()) {
    tokenStore.delete(key);
    return false;
  }

  return true;
}

/**
 * Refresh a CSRF token
 */
export function refreshCSRFToken(
  sessionId?: string,
  config: Partial<CSRFTokenConfig> = {}
): CSRFToken {
  const key = sessionId || "default";
  tokenStore.delete(key);
  return generateCSRFToken(sessionId, config);
}

/**
 * Get current CSRF token
 */
export function getCSRFToken(sessionId?: string): CSRFToken | undefined {
  const key = sessionId || "default";
  return tokenStore.get(key);
}

/**
 * Delete CSRF token
 */
export function deleteCSRFToken(sessionId?: string): void {
  const key = sessionId || "default";
  tokenStore.delete(key);
}

/**
 * Clear all CSRF tokens
 */
export function clearAllCSRFTokens(): void {
  tokenStore.clear();
}

/**
 * Set CSRF token in cookie
 */
export function setCSRFCookie(token: string, config: Partial<CSRFTokenConfig> = {}): void {
  const cfg = { ...DEFAULT_CSRF_CONFIG, ...config };
  const securityConfig = getSecurityConfig();

  const cookieOptions = [
    `${cfg.cookieName}=${token}`,
    `Path=/`,
    `Max-Age=${cfg.tokenLifetime / 1000}`,
    `SameSite=${securityConfig.session.sameSite}`,
  ];

  if (securityConfig.session.secure) {
    cookieOptions.push("Secure");
  }

  document.cookie = cookieOptions.join("; ");
}

/**
 * Get CSRF token from cookie
 */
export function getCSRFCookie(config: Partial<CSRFTokenConfig> = {}): string | null {
  const cfg = { ...DEFAULT_CSRF_CONFIG, ...config };
  const cookies = document.cookie.split(";");

  for (const cookie of cookies) {
    const [name, value] = cookie.trim().split("=");
    if (name === cfg.cookieName) {
      return value;
    }
  }

  return null;
}

/**
 * Delete CSRF cookie
 */
export function deleteCSRFCookie(config: Partial<CSRFTokenConfig> = {}): void {
  const cfg = { ...DEFAULT_CSRF_CONFIG, ...config };
  document.cookie = `${cfg.cookieName}=; Path=/; Max-Age=0`;
}

/**
 * Add CSRF token to request headers
 */
export function addCSRFHeader(
  headers: Headers | Record<string, string>,
  token?: string,
  config: Partial<CSRFTokenConfig> = {}
): Headers | Record<string, string> {
  const cfg = { ...DEFAULT_CSRF_CONFIG, ...config };
  const csrfToken = token || getCSRFCookie(cfg);

  if (!csrfToken) {
    logger.warn("No CSRF token available");
    return headers;
  }

  if (headers instanceof Headers) {
    headers.set(cfg.headerName, csrfToken);
  } else {
    headers[cfg.headerName] = csrfToken;
  }

  return headers;
}

/**
 * Add CSRF token to form data
 */
export function addCSRFToFormData(
  formData: FormData,
  token?: string,
  config: Partial<CSRFTokenConfig> = {}
): FormData {
  const cfg = { ...DEFAULT_CSRF_CONFIG, ...config };
  const csrfToken = token || getCSRFCookie(cfg);

  if (!csrfToken) {
    logger.warn("No CSRF token available");
    return formData;
  }

  formData.append(cfg.paramName, csrfToken);
  return formData;
}

/**
 * Add CSRF token to URL parameters
 */
export function addCSRFToURL(
  url: string,
  token?: string,
  config: Partial<CSRFTokenConfig> = {}
): string {
  const cfg = { ...DEFAULT_CSRF_CONFIG, ...config };
  const csrfToken = token || getCSRFCookie(cfg);

  if (!csrfToken) {
    logger.warn("No CSRF token available");
    return url;
  }

  const urlObj = new URL(url, window.location.origin);
  urlObj.searchParams.set(cfg.paramName, csrfToken);
  return urlObj.toString();
}

/**
 * Fetch wrapper with CSRF protection
 */
export async function fetchWithCSRF(
  url: string,
  options: RequestInit = {},
  config: Partial<CSRFTokenConfig> = {},

  // eslint-disable-next-line no-restricted-globals
  fetchImpl: typeof fetch = fetch
): Promise<Response> {
  const cfg = { ...DEFAULT_CSRF_CONFIG, ...config };

  // Only add CSRF token for state-changing methods
  const method = (options.method || "GET").toUpperCase();
  const requiresCSRF = ["POST", "PUT", "PATCH", "DELETE"].includes(method);

  if (requiresCSRF) {
    // Get or generate token
    let token = getCSRFCookie(cfg);
    if (!token) {
      const csrfToken = generateCSRFToken(undefined, cfg);
      token = csrfToken.token;
      setCSRFCookie(token, cfg);
    }

    // Add token to headers
    const headers = new Headers(options.headers);
    addCSRFHeader(headers, token, cfg);
    options.headers = headers;
  }

  return fetchImpl(url, options);
}

/**
 * Initialize CSRF protection
 */
export function initializeCSRFProtection(
  sessionId?: string,
  config: Partial<CSRFTokenConfig> = {}
): CSRFToken {
  const envConfig = getConfig();

  if (!envConfig.security.csrfEnabled) {
    logger.warn("CSRF protection is disabled");
  }

  // Generate initial token
  const token = generateCSRFToken(sessionId, config);

  // Set cookie
  setCSRFCookie(token.token, config);

  // Add meta tag for easy access
  let metaTag = document.querySelector('meta[name="csrf-token"]') as HTMLMetaElement;
  if (!metaTag) {
    metaTag = document.createElement("meta");
    metaTag.name = "csrf-token";
    document.head.appendChild(metaTag);
  }
  metaTag.content = token.token;

  return token;
}

/**
 * Get CSRF token from meta tag
 */
export function getCSRFTokenFromMeta(): string | null {
  const metaTag = document.querySelector('meta[name="csrf-token"]') as HTMLMetaElement;
  return metaTag ? metaTag.content : null;
}

/**
 * React hook for CSRF protection
 */
export function useCSRFToken(sessionId?: string): {
  token: string | null;
  refresh: () => void;
  addToHeaders: (headers: Headers | Record<string, string>) => Headers | Record<string, string>;
  addToFormData: (formData: FormData) => FormData;
} {
  const [token, setToken] = React.useState<string | null>(null);

  React.useEffect(() => {
    // Get or generate token
    let csrfToken = getCSRFCookie();
    if (!csrfToken) {
      const generated = generateCSRFToken(sessionId);
      csrfToken = generated.token;
      setCSRFCookie(csrfToken);
    }
    setToken(csrfToken);
  }, [sessionId]);

  const refresh = React.useCallback(() => {
    const newToken = refreshCSRFToken(sessionId);
    setCSRFCookie(newToken.token);
    setToken(newToken.token);
  }, [sessionId]);

  const addToHeaders = React.useCallback(
    (headers: Headers | Record<string, string>) => {
      return addCSRFHeader(headers, token || undefined);
    },
    [token]
  );

  const addToFormData = React.useCallback(
    (formData: FormData) => {
      return addCSRFToFormData(formData, token || undefined);
    },
    [token]
  );

  return {
    token,
    refresh,
    addToHeaders,
    addToFormData,
  };
}

let csrfFetchInterceptorInstalled = false;
let originalFetch: typeof fetch | null = null;

/**
 * Attach a global fetch interceptor that automatically injects CSRF tokens
 * on state-changing requests.
 */
export function attachCSRFFetchInterceptor(config: Partial<CSRFTokenConfig> = {}): void {
  if (csrfFetchInterceptorInstalled || typeof fetch === "undefined") {
    return;
  }

  originalFetch = fetch.bind(globalThis);
  csrfFetchInterceptorInstalled = true;

  const baseFetch = originalFetch;

  globalThis.fetch = (async (input: RequestInfo | URL, init?: RequestInit) => {
    const options = init || {};
    const requestMethod = input instanceof Request ? input.method : undefined;
    const method = (options.method || requestMethod || "GET").toUpperCase();

    if (["POST", "PUT", "PATCH", "DELETE"].includes(method)) {
      const requestOptions: RequestInit = { ...options, method };

      return fetchWithCSRF(
        typeof input === "string" || input instanceof URL ? input.toString() : input.url,
        requestOptions,
        config,
        baseFetch
      );
    }

    return baseFetch(input, options);
  }) as typeof fetch;
}

/**
 * Input Sanitizer
 * 
 * Implements input validation and sanitization to prevent injection attacks.
 * Protects against XSS, SQL injection, command injection, and other threats.
 */

import DOMPurify from 'isomorphic-dompurify';

import { getSecurityConfig } from './SecurityConfig';

/**
 * Sanitization options
 */
export interface SanitizeOptions {
  allowHtml?: boolean;
  allowedTags?: string[];
  allowedAttributes?: Record<string, string[]>;
  maxLength?: number;
  stripScripts?: boolean;
  encodeHtml?: boolean;
}

/**
 * Validation result
 */
export interface ValidationResult {
  valid: boolean;
  sanitized: string;
  errors: string[];
  warnings: string[];
}

/**
 * HTML entities map
 */
const HTML_ENTITIES: Record<string, string> = {
  '&': '&amp;',
  '<': '&lt;',
  '>': '&gt;',
  '"': '&quot;',
  "'": '&#x27;',
};

/**
 * SQL injection patterns
 */
const SQL_INJECTION_PATTERNS = [
  /(\b(SELECT|INSERT|UPDATE|DELETE|DROP|CREATE|ALTER|EXEC|EXECUTE)\b)/gi,
  /(--|\#|\/\*|\*\/)/g,
  /(\bOR\b.*=.*)/gi,
  /(\bAND\b.*=.*)/gi,
  /('|"|;|\||&)/g,
];

/**
 * Command injection patterns
 */
const COMMAND_INJECTION_PATTERNS = [
  /[;&|`$(){}[\]<>]/g,
  /\.\.\//g,
  /~\//g,
];

/**
 * Path traversal patterns
 */
const PATH_TRAVERSAL_PATTERNS = [
  /\.\.\//g,
  /\.\.\\/g,
  /%2e%2e%2f/gi,
  /%2e%2e\\/gi,
];

/**
 * Encode HTML entities
 */
export function encodeHtml(text: string): string {
  return text.replace(/[&<>"']/g, (char) => HTML_ENTITIES[char] || char);
}

/**
 * Decode HTML entities
 */
export function decodeHtml(text: string): string {
  return text.replace(/&(#x?[0-9a-fA-F]+|[a-zA-Z]+);/g, (match, entity) => {
    if (typeof entity !== 'string') {
      return match;
    }

    if (entity.startsWith('#x') || entity.startsWith('#X')) {
      const codePoint = Number.parseInt(entity.slice(2), 16);
      return Number.isNaN(codePoint) ? match : String.fromCodePoint(codePoint);
    }

    if (entity.startsWith('#')) {
      const codePoint = Number.parseInt(entity.slice(1), 10);
      return Number.isNaN(codePoint) ? match : String.fromCodePoint(codePoint);
    }

    switch (entity) {
      case 'amp':
        return '&';
      case 'lt':
        return '<';
      case 'gt':
        return '>';
      case 'quot':
        return '"';
      case 'apos':
        return "'";
      default:
        return match;
    }
  });
}

/**
 * Sanitize HTML content
 */
export function sanitizeHtml(
  html: string,
  options: SanitizeOptions = {}
): string {
  const config = getSecurityConfig().inputValidation;
  const {
    allowHtml = false,
    allowedTags = [],
    allowedAttributes = {},
    maxLength = config.maxStringLength,
  } = options;

  let sanitized = html;

  // Truncate if too long
  if (sanitized.length > maxLength) {
    sanitized = sanitized.substring(0, maxLength);
  }

  // If HTML is not allowed: first strip dangerous elements, then encode remaining HTML
  if (!allowHtml) {
    // Remove scripts and event handlers but keep the raw tag text for encoding
    const stripped = sanitized
      .replace(/<script[\s\S]*?<\/script>/gi, '')
      .replace(/<!--[\s\S]*?-->/g, '')
      .replace(/\s*on\w+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]*)/gi, '');
    // Encode all remaining HTML characters including /
    return stripped.replace(/[&<>"'/]/g, (char) => ({
      '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#x27;', '/': '&#x2F;',
    }[char] ?? char));
  }

  // Prepare DOMPurify config
  const purifyConfig: DOMPurify.Config = {};

  if (allowedTags.length > 0) {
    purifyConfig.ALLOWED_TAGS = allowedTags;
  } else {
    // Default safe configuration if no tags specified
    purifyConfig.USE_PROFILES = { html: true };
    purifyConfig.ADD_ATTR = ['target']; // Allow target attribute (often used for links)
  }

  if (Object.keys(allowedAttributes).length > 0) {
    // Flatten allowed attributes as DOMPurify applies them globally
    const allAllowedAttrs = new Set<string>();
    Object.values(allowedAttributes).forEach(attrs => {
      attrs.forEach(attr => allAllowedAttrs.add(attr));
    });
    purifyConfig.ALLOWED_ATTR = Array.from(allAllowedAttrs);

    // When explicit attributes are provided, disable profile defaults to ensure strict whitelist
    delete purifyConfig.USE_PROFILES;
    delete purifyConfig.ADD_ATTR;
  }

  // Sanitize using DOMPurify
  return DOMPurify.sanitize(sanitized, purifyConfig) as string;
}

/**
 * Validate and sanitize string input
 */
export function sanitizeString(
  input: string,
  options: SanitizeOptions = {}
): ValidationResult {
  const config = getSecurityConfig().inputValidation;
  const errors: string[] = [];
  const warnings: string[] = [];
  const maxLength = options.maxLength ?? config.maxStringLength;

  // Check length
  if (input.length > maxLength) {
    warnings.push(`Input truncated to ${maxLength} characters`);
  }

  // Sanitize
  const sanitized = sanitizeHtml(input, options);

  // Check for SQL injection attempts
  for (const pattern of SQL_INJECTION_PATTERNS) {
    if (pattern.test(input)) {
      errors.push('Input contains potentially dangerous SQL patterns');
      break;
    }
  }

  // Check for command injection attempts
  for (const pattern of COMMAND_INJECTION_PATTERNS) {
    if (pattern.test(input)) {
      errors.push('Input contains potentially dangerous command patterns');
      break;
    }
  }

  return {
    valid: errors.length === 0,
    sanitized,
    errors,
    warnings,
  };
}

export function sanitizeInput(input: string, options: SanitizeOptions = {}): string {
  return sanitizeString(input, options).sanitized;
}

/**
 * Validate and sanitize URL
 */
export function sanitizeUrl(url: string): ValidationResult {
  const errors: string[] = [];
  const warnings: string[] = [];

  try {
    const parsed = new URL(url);

    // Check protocol
    if (!['http:', 'https:'].includes(parsed.protocol)) {
      errors.push('URL must use HTTP or HTTPS protocol');
    }

    // Check for javascript: protocol
    if (parsed.protocol === 'javascript:') {
      errors.push('JavaScript URLs are not allowed');
    }

    // Check for data: protocol
    if (parsed.protocol === 'data:') {
      warnings.push('Data URLs should be used with caution');
    }

    // Sanitize by reconstructing
    const sanitized = `${parsed.protocol}//${parsed.host}${parsed.pathname}${parsed.search}${parsed.hash}`;

    return {
      valid: errors.length === 0,
      sanitized,
      errors,
      warnings,
    };
  } catch (_error: unknown) {
    return {
      valid: false,
      sanitized: '',
      errors: ['Invalid URL format'],
      warnings: [],
    };
  }
}

/**
 * Validate and sanitize file path
 */
export function sanitizeFilePath(path: string): ValidationResult {
  const errors: string[] = [];
  const warnings: string[] = [];

  // Check for path traversal
  for (const pattern of PATH_TRAVERSAL_PATTERNS) {
    if (pattern.test(path)) {
      errors.push('Path contains directory traversal patterns');
      break;
    }
  }

  // Check for absolute paths
  if (path.startsWith('/') || /^[a-zA-Z]:/.test(path)) {
    warnings.push('Absolute paths should be avoided');
  }

  // Remove dangerous characters and path traversal sequences
  const sanitized = path
    .replace(/\.\.\//g, '')
    .replace(/\.\.\\/g, '')
    .replace(/%2e%2e%2f/gi, '')
    .replace(/%2e%2e\\/gi, '')
    .replace(/[<>:"|?*]/g, '');

  return {
    valid: errors.length === 0,
    sanitized,
    errors,
    warnings,
  };
}

/**
 * Validate email address
 */
export function validateEmail(email: string): ValidationResult {
  const errors: string[] = [];
  const warnings: string[] = [];

  // Basic email regex (RFC 5322 simplified)
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;

  if (!emailRegex.test(email)) {
    errors.push('Invalid email format');
  }

  // Check length
  if (email.length > 254) {
    errors.push('Email address is too long');
  }

  // Check for suspicious patterns
  if (email.includes('..')) {
    warnings.push('Email contains consecutive dots');
  }

  const sanitized = email.toLowerCase().trim();

  return {
    valid: errors.length === 0,
    sanitized,
    errors,
    warnings,
  };
}

/**
 * Validate phone number
 */
export function validatePhoneNumber(phone: string): ValidationResult {
  const errors: string[] = [];
  const warnings: string[] = [];

  // Remove common formatting characters
  const cleaned = phone.replace(/[\s\-\(\)\.]/g, '');

  // Check if it contains only digits and optional + prefix
  if (!/^\+?\d{10,15}$/.test(cleaned)) {
    errors.push('Invalid phone number format');
  }

  return {
    valid: errors.length === 0,
    sanitized: cleaned,
    errors,
    warnings,
  };
}

/**
 * Sanitize JSON input
 */
export function sanitizeJson(json: string): ValidationResult {
  const config = getSecurityConfig().inputValidation;
  const errors: string[] = [];
  const warnings: string[] = [];

  try {
    // Parse JSON
    const parsed: unknown = JSON.parse(json);

    // Check depth
    const depth = getObjectDepth(parsed);
    if (depth > config.maxObjectDepth) {
      errors.push(`JSON object depth exceeds maximum of ${config.maxObjectDepth}`);
    }

    // Check array lengths
    const hasLongArray = checkArrayLengths(parsed, config.maxArrayLength);
    if (hasLongArray) {
      errors.push(`JSON contains arrays exceeding maximum length of ${config.maxArrayLength}`);
    }

    // Sanitize string values
    const sanitized = sanitizeJsonValues(parsed);

    return {
      valid: errors.length === 0,
      sanitized: JSON.stringify(sanitized),
      errors,
      warnings,
    };
  } catch (_error: unknown) {
    return {
      valid: false,
      sanitized: '',
      errors: ['Invalid JSON format'],
      warnings: [],
    };
  }
}

/**
 * Get object depth
 */
function getObjectDepth(obj: unknown, currentDepth: number = 0): number {
  if (obj === null || typeof obj !== 'object') {
    return currentDepth;
  }

  let maxDepth = currentDepth;
  for (const key in obj as Record<string, unknown>) {
    if (Object.prototype.hasOwnProperty.call(obj, key)) {
      const depth = getObjectDepth((obj as Record<string, unknown>)[key], currentDepth + 1);
      maxDepth = Math.max(maxDepth, depth);
    }
  }

  return maxDepth;
}

/**
 * Check array lengths recursively
 */
function checkArrayLengths(obj: unknown, maxLength: number): boolean {
  if (Array.isArray(obj)) {
    if (obj.length > maxLength) {
      return true;
    }
    for (const item of obj) {
      if (checkArrayLengths(item, maxLength)) {
        return true;
      }
    }
  } else if (obj !== null && typeof obj === 'object') {
    for (const key in obj as Record<string, unknown>) {
      if (Object.prototype.hasOwnProperty.call(obj, key)) {
        if (checkArrayLengths((obj as Record<string, unknown>)[key], maxLength)) {
          return true;
        }
      }
    }
  }

  return false;
}

/**
 * Sanitize JSON values recursively
 */
function sanitizeJsonValues(obj: unknown): unknown {
  if (typeof obj === 'string') {
    return sanitizeHtml(obj, { allowHtml: false });
  } else if (Array.isArray(obj)) {
    return obj.map(item => sanitizeJsonValues(item));
  } else if (obj !== null && typeof obj === 'object') {
    const sanitized: Record<string, unknown> = {};
    for (const key in obj as Record<string, unknown>) {
      if (Object.prototype.hasOwnProperty.call(obj, key)) {
        sanitized[key] = sanitizeJsonValues((obj as Record<string, unknown>)[key]);
      }
    }
    return sanitized;
  }

  return obj;
}

/**
 * Validate file upload
 */
export function validateFileUpload(
  file: File,
  allowedTypes?: string[],
  maxSize?: number
): ValidationResult {
  const config = getSecurityConfig().inputValidation;
  const errors: string[] = [];
  const warnings: string[] = [];

  const types = allowedTypes ?? config.allowedFileTypes;
  const size = maxSize ?? config.maxFileSize;

  // Check file type
  if (!types.includes(file.type)) {
    errors.push(`File type ${file.type} is not allowed`);
  }

  // Check file size
  if (file.size > size) {
    errors.push(`File size ${file.size} exceeds maximum of ${size} bytes`);
  }

  // Check file name
  const fileNameResult = sanitizeFilePath(file.name);
  if (!fileNameResult.valid) {
    errors.push(...fileNameResult.errors);
  }

  return {
    valid: errors.length === 0,
    sanitized: fileNameResult.sanitized,
    errors,
    warnings,
  };
}

/**
 * Sanitize object recursively
 */
export function sanitizeObject(obj: unknown, options: SanitizeOptions = {}): unknown {
  if (typeof obj === 'string') {
    return sanitizeString(obj, options).sanitized;
  } else if (Array.isArray(obj)) {
    return obj.map(item => sanitizeObject(item, options));
  } else if (obj !== null && typeof obj === 'object') {
    const sanitized: Record<string, unknown> = {};
    for (const key in obj as Record<string, unknown>) {
      if (Object.prototype.hasOwnProperty.call(obj, key)) {
        sanitized[key] = sanitizeObject((obj as Record<string, unknown>)[key], options);
      }
    }
    return sanitized;
  }

  return obj;
}

/** Remove all HTML tags from a string. */
export function stripHtmlTags(input: string): string {
  return input.replace(/<[^>]*>/g, "");
}

/** Remove dangerous HTML attributes (event handlers, javascript: hrefs). */
export function stripDangerousAttributes(input: string): string {
  return input
    .replace(/\s+on\w+\s*=\s*["'][^"']*["']/gi, "")
    .replace(/\s+on\w+\s*=\s*[^\s>]*/gi, "")
    .replace(/href\s*=\s*["']javascript:[^"']*["']/gi, 'href="#"');
}

/**
 * Password Validator
 * 
 * Implements OWASP password validation guidelines.
 * Validates password strength, prevents common passwords, and enforces policy.
 */

import { logger } from '../lib/logger';

import { getSecurityConfig } from './SecurityConfig';

/**
 * Password validation result
 */
export interface PasswordValidationResult {
  valid: boolean;
  errors: string[];
  warnings: string[];
  strength: 'weak' | 'fair' | 'good' | 'strong' | 'very-strong';
  score: number; // 0-100
}

/**
 * Common passwords list (top 100 most common)
 */
const COMMON_PASSWORDS = new Set([
  'password', '123456', '123456789', '12345678', '12345', '1234567', 'password1',
  'password123!', 'password123', 'p@ssword123', 'p@ssw0rd',
  'qwerty', 'abc123', '111111', '123123', 'admin', 'letmein', 'welcome', 'monkey',
  'dragon', 'master', 'sunshine', 'princess', 'football', 'shadow', 'michael',
  'jennifer', 'computer', 'baseball', 'jordan', 'superman', 'iloveyou', 'trustno1',
  'starwars', 'whatever', 'batman', 'passw0rd', 'zaq1zaq1', 'qwertyuiop', 'login',
  'access', 'solo', 'killer', 'charlie', 'freedom', 'ranger', 'buster', 'thomas',
  'robert', 'soccer', 'hockey', 'maverick', 'cookie', 'summer', 'pepper', 'maggie',
  'ginger', 'hunter', 'secret', 'harley', 'phoenix', 'bailey', 'jessica', 'ashley',
  'nicole', 'amanda', 'melissa', 'michelle', 'daniel', 'matthew', 'joshua', 'andrew',
  'anthony', 'william', 'joseph', 'david', 'richard', 'charles', 'thomas', 'donald',
  'george', 'kenneth', 'steven', 'edward', 'brian', 'ronald', 'kevin', 'jason',
  'jeff', 'gary', 'timothy', 'jose', 'larry', 'frank', 'scott', 'eric', 'stephen',
  'raymond', 'gregory', 'joshua', 'jerry', 'dennis', 'walter', 'patrick', 'peter',
]);

/**
 * Keyboard patterns to detect
 */
const KEYBOARD_PATTERNS = [
  'qwerty', 'asdfgh', 'zxcvbn', '1qaz2wsx', 'qazwsx', 'qwertyuiop',
  'asdfghjkl', 'zxcvbnm', '1234567890', '0987654321',
];

/**
 * Sequential patterns
 */
const SEQUENTIAL_PATTERNS = [
  'abcdefgh', 'bcdefghi', 'cdefghij', 'defghijk',
  '12345678', '23456789', '34567890',
];

/**
 * Validate password against policy
 */
export function validatePassword(
  password: string,
  userInfo?: {
    email?: string;
    username?: string;
    firstName?: string;
    lastName?: string;
  }
): PasswordValidationResult {
  const config = getSecurityConfig().passwordPolicy;
  const errors: string[] = [];
  const warnings: string[] = [];
  let score = 0;

  // Check minimum length
  if (password.length < config.minLength) {
    errors.push(`Password must be at least ${config.minLength} characters long`);
  } else {
    score += 10;
  }

  // Check maximum length
  if (password.length > config.maxLength) {
    errors.push(`Password must not exceed ${config.maxLength} characters`);
  }

  // Check for uppercase letters
  if (config.requireUppercase && !/[A-Z]/.test(password)) {
    errors.push('Password must contain at least one uppercase letter');
  } else if (/[A-Z]/.test(password)) {
    score += 10;
  }

  // Check for lowercase letters
  if (config.requireLowercase && !/[a-z]/.test(password)) {
    errors.push('Password must contain at least one lowercase letter');
  } else if (/[a-z]/.test(password)) {
    score += 10;
  }

  // Check for numbers
  if (config.requireNumbers && !/\d/.test(password)) {
    errors.push('Password must contain at least one number');
  } else if (/\d/.test(password)) {
    score += 10;
  }

  // Check for special characters
  if (config.requireSpecialChars) {
    // Escape regex metacharacters and ensure '-' is at the end to avoid range interpretation
    const escaped = config.specialChars
      .replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
      .replace(/-/g, '\\-');

    // eslint-disable-next-line security/detect-non-literal-regexp
    const specialCharsRegex = new RegExp(`[${escaped}]`);
    if (!specialCharsRegex.test(password)) {
      errors.push(`Password must contain at least one special character (${config.specialChars})`);
    } else {
      score += 15;
    }
  }

  // Check for common passwords
  if (config.preventCommonPasswords) {
    const lowerPassword = password.toLowerCase();
    if (COMMON_PASSWORDS.has(lowerPassword)) {
      errors.push('Password is too common. Please choose a more unique password');
    } else {
      score += 10;
    }
  }

  // Check for keyboard patterns
  const lowerPassword = password.toLowerCase();
  for (const pattern of KEYBOARD_PATTERNS) {
    if (lowerPassword.includes(pattern)) {
      warnings.push('Password contains a keyboard pattern. Consider using a more random password');
      score -= 5;
      break;
    }
  }

  // Check for sequential patterns
  for (const pattern of SEQUENTIAL_PATTERNS) {
    if (lowerPassword.includes(pattern)) {
      warnings.push('Password contains a sequential pattern. Consider using a more random password');
      score -= 5;
      break;
    }
  }

  // Check for repeated characters
  if (/(.)\1{2,}/.test(password)) {
    warnings.push('Password contains repeated characters. Consider using more variety');
    score -= 5;
  }

  // Check for user information
  if (config.preventUserInfo && userInfo) {
    const userInfoValues = [
      userInfo.email?.split('@')[0],
      userInfo.username,
      userInfo.firstName,
      userInfo.lastName,
    ].filter(Boolean);

    for (const value of userInfoValues) {
      if (value && lowerPassword.includes(value.toLowerCase())) {
        errors.push('Password must not contain your personal information');
        break;
      }
    }
  }

  // Bonus points for length
  if (password.length >= 16) {
    score += 15;
  } else if (password.length >= 14) {
    score += 10;
  } else if (password.length >= 12) {
    score += 5;
  }

  // Bonus points for character variety
  const uniqueChars = new Set(password).size;
  if (uniqueChars >= password.length * 0.8) {
    score += 10;
  } else if (uniqueChars >= password.length * 0.6) {
    score += 5;
  }

  // Ensure score is within bounds
  score = Math.max(0, Math.min(100, score));

  // Determine strength
  let strength: PasswordValidationResult['strength'];
  if (score >= 80) {
    strength = 'very-strong';
  } else if (score >= 60) {
    strength = 'strong';
  } else if (score >= 40) {
    strength = 'good';
  } else if (score >= 20) {
    strength = 'fair';
  } else {
    strength = 'weak';
  }

  return {
    valid: errors.length === 0,
    errors,
    warnings,
    strength,
    score,
  };
}

/**
 * Check if password has been compromised (using Have I Been Pwned API)
 * This is an async check that should be done separately
 */
export type PasswordBreachStatus = 'breached' | 'not_breached' | 'unknown';

export interface PasswordBreachResult {
  status: PasswordBreachStatus;
  count?: number;
  reason?: string;
}

// Simple front-end HIBP check returning conservative results
export async function checkPasswordBreach(password: string): Promise<PasswordBreachResult> {
  const timeoutMs = Number(process.env.VUE_APP_HIBP_TIMEOUT_MS) || 2000;

  try {
    const encoder = new TextEncoder();
    const data = encoder.encode(password);
    const hashBuffer = await crypto.subtle.digest('SHA-1', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('').toUpperCase();

    const prefix = hashHex.substring(0, 5);
    const suffix = hashHex.substring(5);

    const controller = new AbortController();
    const to = setTimeout(() => controller.abort(), timeoutMs);
    // legitimate-exception: HIBP breach check calls external API directly; apiClient is browser-auth-scoped
    const res = await fetch(`https://api.pwnedpasswords.com/range/${prefix}`, { signal: controller.signal, headers: { Accept: 'text/plain', 'User-Agent': 'valyntapp/1.0' } });
    clearTimeout(to);

    if (!res.ok) {
      logger.warn('HIBP returned non-ok status');
      return { status: 'unknown', reason: `status_${res.status}` };
    }

    const text = await res.text();
    const lines = text.split('\n');
    for (const line of lines) {
      const [hashSuffix, countStr] = line.split(':');
      if (hashSuffix === suffix) {
        const count = Number((countStr || '').trim()) || undefined;
        return { status: 'breached', count };
      }
    }

    return { status: 'not_breached' };
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    logger.warn('HIBP check failed', { reason: message });
    return { status: 'unknown', reason: message };
  }
}

/**
 * Return a cryptographically random integer in [0, max).
 */
function cryptoRandInt(max: number): number {
  // Rejection-sampling to avoid modulo bias.
  const limit = Math.floor(0x100000000 / max) * max;
  const buf = new Uint32Array(1);
  let value: number;
  do {
    crypto.getRandomValues(buf);
    value = buf[0]!;
  } while (value >= limit);
  return value % max;
}

/**
 * Generate a strong random password using the Web Crypto API.
 */
export function generateStrongPassword(length: number = 16): string {
  const config = getSecurityConfig().passwordPolicy;

  const uppercase = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  const lowercase = 'abcdefghijklmnopqrstuvwxyz';
  const numbers = '0123456789';
  const special = config.specialChars;

  let charset = '';
  const required: string[] = [];

  if (config.requireUppercase) {
    required.push(uppercase[cryptoRandInt(uppercase.length)]!);
    charset += uppercase;
  }
  if (config.requireLowercase) {
    required.push(lowercase[cryptoRandInt(lowercase.length)]!);
    charset += lowercase;
  }
  if (config.requireNumbers) {
    required.push(numbers[cryptoRandInt(numbers.length)]!);
    charset += numbers;
  }
  if (config.requireSpecialChars) {
    required.push(special[cryptoRandInt(special.length)]!);
    charset += special;
  }

  // Fill remaining positions
  const chars = [...required];
  for (let i = chars.length; i < length; i++) {
    chars.push(charset[cryptoRandInt(charset.length)]!);
  }

  // Fisher-Yates shuffle using crypto random indices
  for (let i = chars.length - 1; i > 0; i--) {
    const j = cryptoRandInt(i + 1);
    [chars[i], chars[j]] = [chars[j]!, chars[i]!];
  }

  return chars.join('');
}

/**
 * Hash password using bcrypt-compatible algorithm
 * Note: In production, use a proper bcrypt library on the server side
 */
export async function hashPassword(password: string): Promise<string> {
  const config = getSecurityConfig().encryption;

  // Generate salt
  const salt = crypto.getRandomValues(new Uint8Array(16));

  // Import password as key material
  const encoder = new TextEncoder();
  const passwordData = encoder.encode(password + (config.pepper || ''));

  const keyMaterial = await crypto.subtle.importKey(
    'raw',
    passwordData,
    'PBKDF2',
    false,
    ['deriveBits']
  );

  // Derive key using PBKDF2
  const derivedBits = await crypto.subtle.deriveBits(
    {
      name: 'PBKDF2',
      salt: salt,
      iterations: Math.pow(2, config.saltRounds),
      hash: 'SHA-256',
    },
    keyMaterial,
    256
  );

  // Combine salt and hash
  const hashArray = new Uint8Array(derivedBits);
  const combined = new Uint8Array(salt.length + hashArray.length);
  combined.set(salt);
  combined.set(hashArray, salt.length);

  // Convert to base64
  return btoa(String.fromCharCode(...combined));
}

/**
 * Verify password against hash
 */
export async function verifyPassword(password: string, hash: string): Promise<boolean> {
  try {
    const config = getSecurityConfig().encryption;

    // Decode hash
    const combined = Uint8Array.from(atob(hash), c => c.charCodeAt(0));
    const salt = combined.slice(0, 16);
    const storedHash = combined.slice(16);

    // Hash the provided password with the same salt
    const encoder = new TextEncoder();
    const passwordData = encoder.encode(password + (config.pepper || ''));

    const keyMaterial = await crypto.subtle.importKey(
      'raw',
      passwordData,
      'PBKDF2',
      false,
      ['deriveBits']
    );

    const derivedBits = await crypto.subtle.deriveBits(
      {
        name: 'PBKDF2',
        salt: salt,
        iterations: Math.pow(2, config.saltRounds),
        hash: 'SHA-256',
      },
      keyMaterial,
      256
    );

    const computedHash = new Uint8Array(derivedBits);

    // Compare hashes
    if (computedHash.length !== storedHash.length) {
      return false;
    }

    let match = true;
    for (let i = 0; i < computedHash.length; i++) {
      if (computedHash[i] !== storedHash[i]) {
        match = false;
      }
    }

    return match;
  } catch (error) {
    logger.error('Error verifying password:', error);
    return false;
  }
}

/**
 * Calculate password entropy (bits)
 */
export function calculatePasswordEntropy(password: string): number {
  let charsetSize = 0;

  if (/[a-z]/.test(password)) charsetSize += 26;
  if (/[A-Z]/.test(password)) charsetSize += 26;
  if (/\d/.test(password)) charsetSize += 10;
  if (/[^a-zA-Z0-9]/.test(password)) charsetSize += 32; // Approximate special chars

  return Math.log2(Math.pow(charsetSize, password.length));
}

/**
 * Estimate time to crack password
 */
export function estimateCrackTime(password: string): string {
  const entropy = calculatePasswordEntropy(password);
  const guessesPerSecond = 1e10; // 10 billion guesses per second (modern GPU)
  const possibleCombinations = Math.pow(2, entropy);
  const secondsToCrack = possibleCombinations / (2 * guessesPerSecond); // Average case

  if (secondsToCrack < 1) return 'Instant';
  if (secondsToCrack < 60) return `${Math.round(secondsToCrack)} seconds`;
  if (secondsToCrack < 3600) return `${Math.round(secondsToCrack / 60)} minutes`;
  if (secondsToCrack < 86400) return `${Math.round(secondsToCrack / 3600)} hours`;
  if (secondsToCrack < 31536000) return `${Math.round(secondsToCrack / 86400)} days`;
  if (secondsToCrack < 3153600000) return `${Math.round(secondsToCrack / 31536000)} years`;
  return 'Centuries';
}

/**
 * Rate Limiter
 *
 * Implements rate limiting using the sliding window algorithm.
 * Protects against brute force attacks and API abuse.
 *
 * SECURITY AUDIT (2026-03-18): WARNING - This rate limiter uses an in-memory
 * Map and window.setInterval, making it client-side only. It can be trivially
 * bypassed by disabling JavaScript or calling APIs directly. A server-side
 * rate limiter (e.g., Redis-backed) MUST be used for actual protection.
 * This client-side implementation should only serve as a UX convenience.
 */

import * as React from "react";

import { getSecurityConfig } from "./SecurityConfig";

/**
 * Rate limit entry
 */
interface RateLimitEntry {
  count: number;
  resetAt: number;
  requests: number[];
}

/**
 * Rate limit result
 */
export interface RateLimitResult {
  allowed: boolean;
  remaining: number;
  resetAt: number;
  retryAfter?: number;
}

/**
 * Rate limit exceeded error
 */
export class RateLimitExceededError extends Error {
  constructor(
    public retryAfter: number,
    public limit: number,
    public window: number
  ) {
    super(`Rate limit exceeded. Try again in ${retryAfter}ms`);
    this.name = "RateLimitExceededError";
  }
}

/**
 * Rate limiter class
 */
export class RateLimiter {
  private store: Map<string, RateLimitEntry> = new Map();
  private cleanupInterval: number | null = null;

  constructor(
    private maxRequests: number,
    private windowMs: number,
    private keyPrefix: string = "ratelimit"
  ) {
    // Start cleanup interval
    this.startCleanup();
  }

  /**
   * Check if request is allowed
   */
  check(key: string): RateLimitResult {
    const fullKey = `${this.keyPrefix}:${key}`;
    const now = Date.now();
    const windowStart = now - this.windowMs;

    // Get or create entry
    let entry = this.store.get(fullKey);
    if (!entry) {
      entry = {
        count: 0,
        resetAt: now + this.windowMs,
        requests: [],
      };
      this.store.set(fullKey, entry);
    }

    // Remove old requests outside the window
    entry.requests = entry.requests.filter((timestamp) => timestamp > windowStart);
    entry.count = entry.requests.length;

    // Check if limit exceeded
    if (entry.count >= this.maxRequests) {
      const oldestRequest = entry.requests[0];
      const retryAfter = oldestRequest + this.windowMs - now;

      return {
        allowed: false,
        remaining: 0,
        resetAt: oldestRequest + this.windowMs,
        retryAfter: Math.max(0, retryAfter),
      };
    }

    // Add current request
    entry.requests.push(now);
    entry.count++;
    entry.resetAt = now + this.windowMs;

    return {
      allowed: true,
      remaining: this.maxRequests - entry.count,
      resetAt: entry.resetAt,
    };
  }

  /**
   * Consume a request (throws if limit exceeded)
   */
  consume(key: string): RateLimitResult {
    const result = this.check(key);

    if (!result.allowed) {
      throw new RateLimitExceededError(result.retryAfter || 0, this.maxRequests, this.windowMs);
    }

    return result;
  }

  /**
   * Reset rate limit for a key
   */
  reset(key: string): void {
    const fullKey = `${this.keyPrefix}:${key}`;
    this.store.delete(fullKey);
  }

  /**
   * Get current count for a key
   */
  getCount(key: string): number {
    const fullKey = `${this.keyPrefix}:${key}`;
    const entry = this.store.get(fullKey);
    return entry ? entry.count : 0;
  }

  /**
   * Start cleanup interval
   */
  private startCleanup(): void {
    if (this.cleanupInterval) {
      return;
    }

    this.cleanupInterval = window.setInterval(() => {
      this.cleanup();
    }, this.windowMs);
  }

  /**
   * Stop cleanup interval
   */
  stopCleanup(): void {
    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
      this.cleanupInterval = null;
    }
  }

  /**
   * Clean up expired entries
   */
  private cleanup(): void {
    const now = Date.now();
    for (const [key, entry] of this.store.entries()) {
      if (entry.resetAt <= now) {
        this.store.delete(key);
      }
    }
  }

  /**
   * Clear all entries
   */
  clear(): void {
    this.store.clear();
  }

  /**
   * Destroy the rate limiter
   */
  destroy(): void {
    this.stopCleanup();
    this.clear();
  }
}

/**
 * Global rate limiters
 */
const rateLimiters = new Map<string, RateLimiter>();

/**
 * Get or create a rate limiter
 */
function getRateLimiter(name: string, maxRequests: number, windowMs: number): RateLimiter {
  const key = `${name}:${maxRequests}:${windowMs}`;

  if (!rateLimiters.has(key)) {
    rateLimiters.set(key, new RateLimiter(maxRequests, windowMs, name));
  }

  return rateLimiters.get(key)!;
}

/**
 * Check global rate limit
 */
export function checkGlobalRateLimit(key: string): RateLimitResult {
  const config = getSecurityConfig().rateLimit.global;
  const limiter = getRateLimiter("global", config.maxRequests, config.windowMs);
  return limiter.check(key);
}

/**
 * Check per-user rate limit
 */
export function checkUserRateLimit(userId: string): RateLimitResult {
  const config = getSecurityConfig().rateLimit.perUser;
  const limiter = getRateLimiter("user", config.maxRequests, config.windowMs);
  return limiter.check(userId);
}

/**
 * Check per-organization rate limit
 */
export function checkOrgRateLimit(orgId: string): RateLimitResult {
  const config = getSecurityConfig().rateLimit.perOrg;
  const limiter = getRateLimiter("org", config.maxRequests, config.windowMs);
  return limiter.check(orgId);
}

/**
 * Check authentication rate limit
 */
export function checkAuthRateLimit(identifier: string): RateLimitResult {
  const config = getSecurityConfig().rateLimit.auth;
  const limiter = getRateLimiter("auth", config.maxRequests, config.windowMs);
  return limiter.check(identifier);
}

/**
 * Consume global rate limit
 */
export function consumeGlobalRateLimit(key: string): RateLimitResult {
  const config = getSecurityConfig().rateLimit.global;
  const limiter = getRateLimiter("global", config.maxRequests, config.windowMs);
  return limiter.consume(key);
}

/**
 * Consume user rate limit
 */
export function consumeUserRateLimit(userId: string): RateLimitResult {
  const config = getSecurityConfig().rateLimit.perUser;
  const limiter = getRateLimiter("user", config.maxRequests, config.windowMs);
  return limiter.consume(userId);
}

/**
 * Consume organization rate limit
 */
export function consumeOrgRateLimit(orgId: string): RateLimitResult {
  const config = getSecurityConfig().rateLimit.perOrg;
  const limiter = getRateLimiter("org", config.maxRequests, config.windowMs);
  return limiter.consume(orgId);
}

/**
 * Consume authentication rate limit
 */
export function consumeAuthRateLimit(identifier: string): RateLimitResult {
  const config = getSecurityConfig().rateLimit.auth;
  const limiter = getRateLimiter("auth", config.maxRequests, config.windowMs);
  return limiter.consume(identifier);
}

/**
 * Reset rate limit
 */
export function resetRateLimit(type: "global" | "user" | "org" | "auth", key: string): void {
  const config =
    getSecurityConfig().rateLimit[
      type === "global"
        ? "global"
        : type === "user"
          ? "perUser"
          : type === "org"
            ? "perOrg"
            : "auth"
    ];
  const limiter = getRateLimiter(type, config.maxRequests, config.windowMs);
  limiter.reset(key);
}

/**
 * Fetch wrapper with rate limiting
 */
export async function fetchWithRateLimit(
  url: string,
  options: RequestInit = {},
  rateLimitKey?: string
): Promise<Response> {
  // Check rate limit
  const key = rateLimitKey || url;
  const result = checkGlobalRateLimit(key);

  if (!result.allowed) {
    throw new RateLimitExceededError(
      result.retryAfter || 0,
      getSecurityConfig().rateLimit.global.maxRequests,
      getSecurityConfig().rateLimit.global.windowMs
    );
  }

  // Make request

  // eslint-disable-next-line no-restricted-globals
  const response = await fetch(url, options);

  // Add rate limit headers to response
  const headers = new Headers(response.headers);
  headers.set("X-RateLimit-Limit", String(getSecurityConfig().rateLimit.global.maxRequests));
  headers.set("X-RateLimit-Remaining", String(result.remaining));
  headers.set("X-RateLimit-Reset", String(result.resetAt));

  return new Response(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers,
  });
}

/**
 * React hook for rate limiting
 */
export function useRateLimit(
  type: "global" | "user" | "org" | "auth",
  key: string
): {
  allowed: boolean;
  remaining: number;
  resetAt: number;
  retryAfter?: number;
  check: () => RateLimitResult;
  consume: () => RateLimitResult;
  reset: () => void;
} {
  const [state, setState] = React.useState<RateLimitResult>({
    allowed: true,
    remaining: 0,
    resetAt: 0,
  });

  const check = React.useCallback(() => {
    let result: RateLimitResult;

    switch (type) {
      case "global":
        result = checkGlobalRateLimit(key);
        break;
      case "user":
        result = checkUserRateLimit(key);
        break;
      case "org":
        result = checkOrgRateLimit(key);
        break;
      case "auth":
        result = checkAuthRateLimit(key);
        break;
    }

    setState(result);
    return result;
  }, [type, key]);

  const consume = React.useCallback(() => {
    let result: RateLimitResult;

    switch (type) {
      case "global":
        result = consumeGlobalRateLimit(key);
        break;
      case "user":
        result = consumeUserRateLimit(key);
        break;
      case "org":
        result = consumeOrgRateLimit(key);
        break;
      case "auth":
        result = consumeAuthRateLimit(key);
        break;
    }

    setState(result);
    return result;
  }, [type, key]);

  const reset = React.useCallback(() => {
    resetRateLimit(type, key);
    check();
  }, [type, key, check]);

  React.useEffect(() => {
    check();
  }, [check]);

  return {
    ...state,
    check,
    consume,
    reset,
  };
}

/**
 * Cleanup all rate limiters
 */
export function cleanupRateLimiters(): void {
  for (const limiter of rateLimiters.values()) {
    limiter.destroy();
  }
  rateLimiters.clear();
}

