// ============================================================================
// Types
// ============================================================================

export interface AsyncState<T> {
  data: T | null;
  loading: boolean;
  error: string | null;
  lastUpdated: Date | null;
}

export interface UseAsyncStateOptions<T> {
  initialData?: T | null;
  onSuccess?: (data: T) => void;
  onError?: (error: string) => void;
  retryAttempts?: number;
  retryDelay?: number;
  cacheTime?: number;
}

export interface AsyncActions<T> {
  execute: (...args: unknown[]) => Promise<T>;
  reset: () => void;
  retry: () => void;
  setData: (data: T) => void;
}

// ============================================================================
// Hook Implementation
// ============================================================================

export function useAsyncState<T>(
  asyncFunction: (...args: unknown[]) => Promise<T>,
  options: UseAsyncStateOptions<T> = {}
): [AsyncState<T>, AsyncActions<T>] {
  const {
    initialData = null,
    onSuccess,
    onError,
    retryAttempts = 3,
    retryDelay = 1000,
  } = options;

  // State management
  const [state, setState] = useState<AsyncState<T>>({
    data: initialData,
    loading: false,
    error: null,
    lastUpdated: null,
  });

  // Refs for tracking
  const mountedRef = useRef(true);
  const abortControllerRef = useRef<AbortController | null>(null);
  const retryCountRef = useRef(0);
  const lastArgsRef = useRef<unknown[] | null>(null);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      mountedRef.current = false;
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, []);

  // Execute async function
  const execute = useCallback(
    async (...args: unknown[]): Promise<T> => {
      // Cancel previous request if still running
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }

      // Create new abort controller
      const abortController = new AbortController();
      abortControllerRef.current = abortController;

      // Store args for retry
      lastArgsRef.current = args;

      // Reset state
      setState((prev) => ({
        ...prev,
        loading: true,
        error: null,
      }));

      try {
        const result = await asyncFunction(...args);

        // Check if component is still mounted and request wasn't aborted
        if (!mountedRef.current || abortController.signal.aborted) {
          throw new Error("Request aborted");
        }

        // Update state with success
        setState({
          data: result,
          loading: false,
          error: null,
          lastUpdated: new Date(),
        });

        // Reset retry count
        retryCountRef.current = 0;

        // Call success callback
        if (onSuccess) {
          onSuccess(result);
        }

        return result;
      } catch (error) {
        // Check if component is still mounted
        if (!mountedRef.current) {
          throw error;
        }

        const errorMessage = error instanceof Error ? error.message : "Unknown error occurred";

        // Update state with error
        setState((prev) => ({
          ...prev,
          loading: false,
          error: errorMessage,
        }));

        // Call error callback
        if (onError) {
          onError(errorMessage);
        }

        throw error;
      }
    },
    [asyncFunction, onSuccess, onError]
  );

  // Retry last failed request
  const retry = useCallback(async (): Promise<void> => {
    if (retryCountRef.current >= retryAttempts) {
      return;
    }

    retryCountRef.current += 1;

    // Wait before retry
    if (retryDelay > 0) {
      await new Promise((resolve) => setTimeout(resolve, retryDelay));
    }

    // Retry with last args if available
    if (lastArgsRef.current) {
      try {
        await execute(...lastArgsRef.current);
      } catch (_error) {
        // Error is already handled in execute
      }
    }
  }, [execute, retryAttempts, retryDelay]);

  // Reset state
  const reset = useCallback((): void => {
    setState({
      data: initialData,
      loading: false,
      error: null,
      lastUpdated: null,
    });
    retryCountRef.current = 0;
    lastArgsRef.current = null;
  }, [initialData]);

  // Set data directly
  const setData = useCallback((data: T): void => {
    setState({
      data,
      loading: false,
      error: null,
      lastUpdated: new Date(),
    });
  }, []);

  return [state, { execute, reset, retry, setData }];
}

// ============================================================================
// Specialized Hooks
// ============================================================================

/**
 * Hook for API calls with automatic loading and error states
 */
export function useApiCall<T>(
  apiFunction: (...args: unknown[]) => Promise<T>,
  options?: UseAsyncStateOptions<T>
) {
  return useAsyncState(apiFunction, options);
}

/**
 * Hook for cached data with automatic refresh
 */
export function useCachedData<T>(
  key: string,
  fetchFunction: () => Promise<T>,
  options: UseAsyncStateOptions<T> & { refreshInterval?: number } = {}
) {
  const { refreshInterval, ...asyncOptions } = options;
  const [state, actions] = useAsyncState(fetchFunction, asyncOptions);

  // Auto-refresh effect
  useEffect(() => {
    if (!refreshInterval) return;

    const interval = setInterval(() => {
      actions.execute();
    }, refreshInterval);

    return () => clearInterval(interval);
  }, [refreshInterval, actions]);

  // Check cache on mount
  useEffect(() => {
    const cached = localStorage.getItem(`cache_${key}`);
    if (cached && !state.data) {
      try {
        const parsed = JSON.parse(cached);
        const now = Date.now();

        // Check if cache is still valid
        if (now - parsed.timestamp < (options.cacheTime || 300000)) {
          actions.setData(parsed.data);
        } else {
          // Cache expired, fetch fresh data
          actions.execute();
        }
      } catch (_error) {
        // Invalid cache, fetch fresh data
        actions.execute();
      }
    } else if (!state.data && !state.loading) {
      // No cache, fetch data
      actions.execute();
    }
  }, [key, options.cacheTime, actions, state.data, state.loading]);

  // Update cache when data changes
  useEffect(() => {
    if (state.data && state.lastUpdated) {
      const payload = JSON.stringify({
        data: state.data,
        timestamp: state.lastUpdated.getTime(),
      });
      // Skip caching payloads that are likely to exceed the ~5 MB localStorage quota.
      // 4 MB leaves headroom for other stored keys.
      const MAX_CACHE_BYTES = 4 * 1024 * 1024;
      const payloadBytes = new TextEncoder().encode(payload).length;
      if (payloadBytes > MAX_CACHE_BYTES) {
        logger.warn(
          `[useCachedData] Skipping cache write for key "${key}": payload size ${payloadBytes} bytes exceeds limit.`
        );
        return;
      }
      try {
        localStorage.setItem(`cache_${key}`, payload);
      } catch (error) {
        if (error instanceof DOMException && error.name === "QuotaExceededError") {
          logger.warn(
            `[useCachedData] localStorage quota exceeded for key "${key}". Cache write skipped.`,
            error
          );
        } else {
          // Unexpected storage errors: log and notify, but do not throw from inside useEffect.
          logger.error(
            `[useCachedData] Unexpected localStorage error while writing cache for key "${key}". Cache write skipped.`,
            error
          );
          if (options.onError) {
            options.onError(
              `Unexpected localStorage error while caching data for key "${key}".`
            );
          }
        }
      }
    }
  }, [key, state.data, state.lastUpdated, options.onError]);

  return [state, actions] as const;
}

/**
 * Hook for paginated data
 */
export function usePaginatedData<T>(
  fetchFunction: (page: number, limit: number) => Promise<{ data: T[]; total: number }>,
  options: UseAsyncStateOptions<{ data: T[]; total: number }> & { defaultLimit?: number } = {}
) {
  const { defaultLimit = 20, ...asyncOptions } = options;
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(defaultLimit);

  const [state, actions] = useAsyncState(
    (pageNum: number, pageLimit: number) => fetchFunction(pageNum, pageLimit),
    asyncOptions
  );

  const loadPage = useCallback(
    (newPage: number, newLimit?: number) => {
      const limitToUse = newLimit || limit;
      setPage(newPage);
      if (newLimit) setLimit(newLimit);
      return actions.execute(newPage, limitToUse);
    },
    [actions, limit]
  );

  const nextPage = useCallback(() => {
    if (state.data && page * limit < state.data.total) {
      return loadPage(page + 1);
    }
  }, [page, limit, state.data, loadPage]);

  const prevPage = useCallback(() => {
    if (page > 1) {
      return loadPage(page - 1);
    }
  }, [page, loadPage]);

  const refresh = useCallback(() => {
    return loadPage(page, limit);
  }, [loadPage, page, limit]);

  return {
    ...state,
    page,
    limit,
    totalPages: state.data ? Math.ceil(state.data.total / limit) : 0,
    hasNextPage: state.data ? page * limit < state.data.total : false,
    hasPrevPage: page > 1,
    loadPage,
    nextPage,
    prevPage,
    refresh,
    setLimit,
  };
}

// ============================================================================
// Utility Functions
// ============================================================================

/**
 * Create a debounced version of an async function
 */
export function useDebouncedAsync<T>(
  asyncFunction: (...args: unknown[]) => Promise<T>,
  delay: number = 300
) {
  const debouncedRef = useRef<NodeJS.Timeout | null>(null);

  return useCallback(
    (...args: unknown[]) => {
      return new Promise<T>((resolve, reject) => {
        // Clear previous timeout
        if (debouncedRef.current) {
          clearTimeout(debouncedRef.current);
        }

        // Set new timeout
        debouncedRef.current = setTimeout(async () => {
          try {
            const result = await asyncFunction(...args);
            resolve(result);
          } catch (error) {
            reject(error);
          }
        }, delay);
      });
    },
    [asyncFunction, delay]
  );
}

/**
 * Create a throttled version of an async function
 */
export function useThrottledAsync<T>(
  asyncFunction: (...args: unknown[]) => Promise<T>,
  limit: number = 1000
) {
  const lastExecutionRef = useRef<number>(0);

  return useCallback(
    (...args: unknown[]) => {
      return new Promise<T>((resolve, reject) => {
        const now = Date.now();
        const timeSinceLastExecution = now - lastExecutionRef.current;

        if (timeSinceLastExecution >= limit) {
          lastExecutionRef.current = now;

          asyncFunction(...args)
            .then(resolve)
            .catch(reject);
        } else {
          const delay = limit - timeSinceLastExecution;

          setTimeout(() => {
            lastExecutionRef.current = Date.now();

            asyncFunction(...args)
              .then(resolve)
              .catch(reject);
          }, delay);
        }
      });
    },
    [asyncFunction, limit]
  );
}

/**
 * ValueCanvas Store
 *
 * Zustand store for Value Driver Configuration Canvas state management.
 * Manages nodes, edges, driver values, and UI state for real-time calculations.
 */

import { addEdge, Connection, Edge, Node } from "@xyflow/react";
import { zundo } from "zundo";
import { create } from "zustand";
import { devtools } from "zustand/middleware";

// Types for the store
export interface ValueDriverNode {
  id: string;
  type: "input" | "calculated";
  label: string;
  formula?: string;
  value: number;
  format: "currency" | "percentage" | "number";
  position: { x: number; y: number };
}

export interface ValueDriverEdge {
  id: string;
  source: string;
  target: string;
  sourceHandle?: string;
  targetHandle?: string;
}

export interface DriverValues {
  [nodeId: string]: number;
}

export interface DriverDefinitions {
  [nodeId: string]: {
    formula: string;
    format: "currency" | "percentage" | "number";
    label: string;
  };
}

// Store slices
interface GraphSlice {
  nodes: Node[];
  edges: Edge[];
  addNode: (node: Node) => void;
  updateNode: (nodeId: string, updates: Partial<Node>) => void;
  removeNode: (nodeId: string) => void;
  addEdge: (edge: Edge) => void;
  removeEdge: (edgeId: string) => void;
  onConnect: (connection: Connection) => void;
  setNodes: (nodes: Node[]) => void;
  setEdges: (edges: Edge[]) => void;
}

interface ModelSlice {
  driverDefinitions: DriverDefinitions;
  driverValues: DriverValues;
  updateDriverDefinition: (nodeId: string, definition: Partial<DriverDefinitions[string]>) => void;
  updateDriverValue: (nodeId: string, value: number) => void;
  batchUpdateValues: (updates: { [nodeId: string]: number }) => void;
  setDriverDefinitions: (definitions: DriverDefinitions) => void;
  setDriverValues: (values: DriverValues) => void;
}

interface UiSlice {
  selectedNodeId: string | null;
  isEditorOpen: boolean;
  isLibraryOpen: boolean;
  isSaving: boolean;
  lastSaved: Date | null;
  error: string | null;
  setSelectedNodeId: (nodeId: string | null) => void;
  setIsEditorOpen: (open: boolean) => void;
  setIsLibraryOpen: (open: boolean) => void;
  setIsSaving: (saving: boolean) => void;
  setLastSaved: (date: Date | null) => void;
  setError: (error: string | null) => void;
}

// Combined store interface
interface ValueCanvasStore extends GraphSlice, ModelSlice, UiSlice {
  // Actions that coordinate across slices
  addDriverNode: (node: ValueDriverNode) => void;
  updateDriverFormula: (nodeId: string, formula: string) => void;
  deleteDriverNode: (nodeId: string) => void;
  loadCanvas: (data: {
    nodes: Node[];
    edges: Edge[];
    driverDefinitions: DriverDefinitions;
    driverValues: DriverValues;
  }) => void;
  reset: () => void;
}

// Initial state
const initialState = {
  // Graph slice
  nodes: [],
  edges: [],

  // Model slice
  driverDefinitions: {},
  driverValues: {},

  // UI slice
  selectedNodeId: null,
  isEditorOpen: false,
  isLibraryOpen: false,
  isSaving: false,
  lastSaved: null,
  error: null,
};

// Create the store with undo/redo middleware
const useValueCanvasStore = create<ValueCanvasStore>()(
  zundo(
    devtools(
      (set, get) => ({
        ...initialState,

        // Graph slice actions
        addNode: (node: Node) =>
          set(
            (state) => ({
              nodes: [...state.nodes, node],
            }),
            false,
            "addNode"
          ),

        updateNode: (nodeId: string, updates: Partial<Node>) =>
          set(
            (state) => ({
              nodes: state.nodes.map((node) =>
                node.id === nodeId ? { ...node, ...updates } : node
              ),
            }),
            false,
            "updateNode"
          ),

        removeNode: (nodeId: string) =>
          set(
            (state) => ({
              nodes: state.nodes.filter((node) => node.id !== nodeId),
              edges: state.edges.filter((edge) => edge.source !== nodeId && edge.target !== nodeId),
            }),
            false,
            "removeNode"
          ),

        addEdge: (edge: Edge) =>
          set(
            (state) => ({
              edges: addEdge(edge, state.edges),
            }),
            false,
            "addEdge"
          ),

        removeEdge: (edgeId: string) =>
          set(
            (state) => ({
              edges: state.edges.filter((edge) => edge.id !== edgeId),
            }),
            false,
            "removeEdge"
          ),

        onConnect: (connection: Connection) => {
          const edge = {
            ...connection,
            id: `edge-${connection.source}-${connection.target}`,
            type: "default",
          };
          (get() as ValueCanvasStore).addEdge(edge);
        },

        setNodes: (nodes: Node[]) => set({ nodes }, false, "setNodes"),
        setEdges: (edges: Edge[]) => set({ edges }, false, "setEdges"),

        // Model slice actions
        updateDriverDefinition: (nodeId: string, definition: Partial<DriverDefinitions[string]>) =>
          set(
            (state) => ({
              driverDefinitions: {
                ...state.driverDefinitions,
                [nodeId]: {
                  ...state.driverDefinitions[nodeId],
                  ...definition,
                },
              },
            }),
            false,
            "updateDriverDefinition"
          ),

        updateDriverValue: (nodeId: string, value: number) =>
          set(
            (state) => ({
              driverValues: {
                ...state.driverValues,
                [nodeId]: value,
              },
            }),
            false,
            "updateDriverValue"
          ),

        batchUpdateValues: (updates: { [nodeId: string]: number }) =>
          set(
            (state) => ({
              driverValues: {
                ...state.driverValues,
                ...updates,
              },
            }),
            false,
            "batchUpdateValues"
          ),

        setDriverDefinitions: (definitions: DriverDefinitions) =>
          set({ driverDefinitions: definitions }, false, "setDriverDefinitions"),
        setDriverValues: (values: DriverValues) =>
          set({ driverValues: values }, false, "setDriverValues"),

        // UI slice actions
        setSelectedNodeId: (nodeId: string | null) =>
          set({ selectedNodeId: nodeId }, false, "setSelectedNodeId"),
        setIsEditorOpen: (open: boolean) => set({ isEditorOpen: open }, false, "setIsEditorOpen"),
        setIsLibraryOpen: (open: boolean) =>
          set({ isLibraryOpen: open }, false, "setIsLibraryOpen"),
        setIsSaving: (saving: boolean) => set({ isSaving: saving }, false, "setIsSaving"),
        setLastSaved: (date: Date | null) => set({ lastSaved: date }, false, "setLastSaved"),
        setError: (error: string | null) => set({ error }, false, "setError"),

        // Coordinated actions
        addDriverNode: (driverNode: ValueDriverNode) => {
          const node: Node = {
            id: driverNode.id,
            type: driverNode.type === "input" ? "inputNode" : "calculatedNode",
            position: driverNode.position,
            data: {
              label: driverNode.label,
              value: driverNode.value,
              format: driverNode.format,
              formula: driverNode.formula,
            },
          };

          (get() as ValueCanvasStore).addNode(node);
          (get() as ValueCanvasStore).updateDriverDefinition(driverNode.id, {
            formula: driverNode.formula || "",
            format: driverNode.format,
            label: driverNode.label,
          });
          (get() as ValueCanvasStore).updateDriverValue(driverNode.id, driverNode.value);
        },

        updateDriverFormula: (nodeId: string, formula: string) => {
          (get() as ValueCanvasStore).updateDriverDefinition(nodeId, { formula });
          // Trigger recalculation will be handled by CalculationEngine
        },

        deleteDriverNode: (nodeId: string) => {
          (get() as ValueCanvasStore).removeNode(nodeId);
          set(
            (state) => {
              const { [nodeId]: _, ...driverDefinitions } = state.driverDefinitions;
              const { [nodeId]: __, ...driverValues } = state.driverValues;
              return { driverDefinitions, driverValues };
            },
            false,
            "deleteDriverNode"
          );
        },

        loadCanvas: (data: {
          nodes: Node[];
          edges: Edge[];
          driverDefinitions: DriverDefinitions;
          driverValues: DriverValues;
        }) =>
          set(
            {
              nodes: data.nodes,
              edges: data.edges,
              driverDefinitions: data.driverDefinitions,
              driverValues: data.driverValues,
            },
            false,
            "loadCanvas"
          ),

        reset: () => set(initialState, false, "reset"),
      }),
      { name: "value-canvas-store" }
    ),
    {
      // zundo options
      handleSet: (handleSet: (payload: unknown, replace?: boolean) => void) => (payload: unknown, replace?: boolean) => {
        // Only include actions that should be undoable
        const undoableActions = [
          "addNode",
          "updateNode",
          "removeNode",
          "addEdge",
          "removeEdge",
          "updateDriverDefinition",
          "updateDriverValue",
          "batchUpdateValues",
          "addDriverNode",
          "updateDriverFormula",
          "deleteDriverNode",
        ];

        if (undoableActions.includes(payload?.type)) {
          handleSet(payload, replace);
        } else {
          // For non-undoable actions, just set without history
          payload?.type && handleSet({ ...payload, type: undefined }, replace);
        }
      },
    }
  )
);

// Export hooks for undo/redo
export const useTemporalStore = () => {
  const store = (useValueCanvasStore as unknown as { temporal: { undo: () => void; redo: () => void; clear: () => void; pastStates: unknown[]; futureStates: unknown[] } }).temporal;
  return {
    undo: store.undo,
    redo: store.redo,
    clear: store.clear,
    pastStates: store.pastStates,
    futureStates: store.futureStates,
  };
};

export default useValueCanvasStore;

