/**
 * Performance Monitoring and Optimization Utilities
 */

import * as React from "react";

import { logger } from "../lib/logger";

export interface PerformanceMetric {
  name: string;
  value: number;
  unit: "ms" | "bytes" | "count";
  timestamp: number;
  metadata?: Record<string, unknown>;
}

export interface PerformanceBenchmark {
  target: number;
  warning: number;
  critical: number;
}

export const PERFORMANCE_BENCHMARKS: Record<string, PerformanceBenchmark> = {
  "settings.panel.load": { target: 200, warning: 300, critical: 500 },
  "settings.section.load": { target: 100, warning: 150, critical: 250 },
  "settings.search": { target: 50, warning: 100, critical: 200 },
  "settings.save": { target: 300, warning: 500, critical: 1000 },
  "web-vitals.inp": { target: 200, warning: 300, critical: 500 },
  "web-vitals.tbt": { target: 200, warning: 400, critical: 600 },
  "web-vitals.fcp": { target: 1800, warning: 2500, critical: 3000 },
  "web-vitals.lcp": { target: 2500, warning: 3500, critical: 4000 },
};

class PerformanceMonitor {
  private metrics: PerformanceMetric[] = [];
  private observers: Map<string, PerformanceObserver> = new Map();

  /**
   * Start measuring performance
   */
  startMeasure(name: string): () => number {
    const startTime = performance.now();
    performance.mark(`${name}-start`);

    return () => {
      const endTime = performance.now();
      performance.mark(`${name}-end`);

      try {
        performance.measure(name, `${name}-start`, `${name}-end`);
      } catch (error) {
        logger.warn("Performance measure failed:", error);
      }

      const duration = endTime - startTime;
      this.recordMetric({
        name,
        value: duration,
        unit: "ms",
        timestamp: Date.now(),
      });

      return duration;
    };
  }

  /**
   * Record a performance metric
   */
  recordMetric(metric: PerformanceMetric): void {
    this.metrics.push(metric);

    // Keep only last 1000 metrics
    if (this.metrics.length > 1000) {
      this.metrics = this.metrics.slice(-1000);
    }

    // Check against benchmarks
    const benchmark = PERFORMANCE_BENCHMARKS[metric.name];
    if (benchmark && metric.unit === "ms") {
      if (metric.value > benchmark.critical) {
        logger.error("Performance critical: ${metric.name} took ${metric.value}ms");
        this.reportPerformanceIssue(metric, "critical");
      } else if (metric.value > benchmark.warning) {
        logger.warn("Performance warning: ${metric.name} took ${metric.value}ms");
        this.reportPerformanceIssue(metric, "warning");
      }
    }
  }

  /**
   * Get metrics for a specific measurement
   */
  getMetrics(name: string): PerformanceMetric[] {
    return this.metrics.filter((m) => m.name === name);
  }

  /**
   * Get average value for a metric
   */
  getAverage(name: string): number {
    const metrics = this.getMetrics(name);
    if (metrics.length === 0) return 0;

    const sum = metrics.reduce((acc, m) => acc + m.value, 0);
    return sum / metrics.length;
  }

  /**
   * Get percentile value
   */
  getPercentile(name: string, percentile: number): number {
    const metrics = this.getMetrics(name).sort((a, b) => a.value - b.value);
    if (metrics.length === 0) return 0;

    const index = Math.ceil((percentile / 100) * metrics.length) - 1;
    return metrics[index]?.value || 0;
  }

  /**
   * Observe Core Web Vitals
   */
  observeWebVitals(): void {
    if (typeof window === "undefined" || !("PerformanceObserver" in window)) {
      return;
    }

    // Largest Contentful Paint (LCP)
    try {
      const lcpObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries();
        const lastEntry = entries[entries.length - 1] as PerformanceEntry & { renderTime?: number; loadTime?: number };

        this.recordMetric({
          name: "web-vitals.lcp",
          value: lastEntry.renderTime ?? lastEntry.loadTime ?? 0,
          unit: "ms",
          timestamp: Date.now(),
        });
      });

      lcpObserver.observe({ type: "largest-contentful-paint", buffered: true });
      this.observers.set("lcp", lcpObserver);
    } catch (error) {
      logger.warn("LCP observation failed:", error);
    }

    // First Input Delay (FID)
    try {
      const fidObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries();
        entries.forEach((entry) => {
          const e = entry as PerformanceEntry & { processingStart: number };
          this.recordMetric({
            name: "web-vitals.fid",
            value: e.processingStart - e.startTime,
            unit: "ms",
            timestamp: Date.now(),
          });
        });
      });

      fidObserver.observe({ type: "first-input", buffered: true });
      this.observers.set("fid", fidObserver);
    } catch (error) {
      logger.warn("FID observation failed:", error);
    }

    // Cumulative Layout Shift (CLS)
    try {
      let clsValue = 0;
      const clsObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries();
        entries.forEach((entry) => {
          const e = entry as PerformanceEntry & { hadRecentInput?: boolean; value?: number };
          if (!e.hadRecentInput) {
            clsValue += e.value ?? 0;
          }
        });

        this.recordMetric({
          name: "web-vitals.cls",
          value: clsValue,
          unit: "count",
          timestamp: Date.now(),
        });
      });

      clsObserver.observe({ type: "layout-shift", buffered: true });
      this.observers.set("cls", clsObserver);
    } catch (error) {
      logger.warn("CLS observation failed:", error);
    }

    // Interaction to Next Paint (INP) - replaces FID
    this.observeINP();

    // First Contentful Paint (FCP)
    this.observeFCP();

    // Total Blocking Time (TBT)
    this.observeTBT();
  }

  /**
   * Observe Interaction to Next Paint (INP)
   * Measures responsiveness throughout the page lifecycle
   */
  private observeINP(): void {
    if (typeof window === "undefined" || !("PerformanceObserver" in window)) {
      return;
    }

    try {
      const inpObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries();
        entries.forEach((entry) => {
          const e = entry as PerformanceEntry & { processingEnd: number; target?: unknown };
          const duration = e.processingEnd - e.startTime;

          this.recordMetric({
            name: "web-vitals.inp",
            value: duration,
            unit: "ms",
            timestamp: Date.now(),
            metadata: {
              interactionType: e.name,
              target: e.target,
            },
          });
        });
      });

      inpObserver.observe({ type: "event", buffered: true, durationThreshold: 16 });
      this.observers.set("inp", inpObserver);
    } catch (error) {
      logger.warn("INP observation failed:", error);
    }
  }

  /**
   * Observe First Contentful Paint (FCP)
   */
  private observeFCP(): void {
    if (typeof window === "undefined" || !("PerformanceObserver" in window)) {
      return;
    }

    try {
      const fcpObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries();
        entries.forEach((entry) => {
          this.recordMetric({
            name: "web-vitals.fcp",
            value: entry.startTime,
            unit: "ms",
            timestamp: Date.now(),
          });
        });
      });

      fcpObserver.observe({ type: "paint", buffered: true });
      this.observers.set("fcp", fcpObserver);
    } catch (error) {
      logger.warn("FCP observation failed:", error);
    }
  }

  /**
   * Measure Total Blocking Time (TBT)
   * Tracks long tasks that block the main thread
   */
  private observeTBT(): void {
    if (typeof window === "undefined" || !("PerformanceObserver" in window)) {
      return;
    }

    try {
      let tbtValue = 0;
      const tbtObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries();
        entries.forEach((entry) => {
          if (entry.duration > 50) {
            tbtValue += entry.duration - 50;
          }
        });

        this.recordMetric({
          name: "web-vitals.tbt",
          value: tbtValue,
          unit: "ms",
          timestamp: Date.now(),
        });
      });

      tbtObserver.observe({ type: "longtask", buffered: true });
      this.observers.set("tbt", tbtObserver);
    } catch (error) {
      logger.warn("TBT observation failed:", error);
    }
  }

  /**
   * Report performance issue
   */
  private reportPerformanceIssue(
    metric: PerformanceMetric,
    severity: "warning" | "critical"
  ): void {
    if (typeof window === "undefined") return;
    const analytics = (window as Record<string, unknown>)["analytics"];
    if (analytics && typeof analytics === "object" && "track" in analytics) {
      (analytics as { track: (event: string, props: Record<string, unknown>) => void }).track(
        "Performance Issue",
        { metric: metric.name, value: metric.value, unit: metric.unit, severity, timestamp: metric.timestamp }
      );
    }
  }

  /**
   * Generate performance report
   */
  generateReport(): {
    summary: Record<string, { avg: number; p50: number; p95: number; p99: number }>;
    issues: Array<{ name: string; severity: string; value: number }>;
  } {
    const metricNames = [...new Set(this.metrics.map((m) => m.name))];

    const summary: Record<string, { avg: number; p50: number; p95: number; p99: number }> = {};
    const issues: Array<{ name: string; severity: string; value: number }> = [];

    metricNames.forEach((name) => {
      summary[name] = {
        avg: Math.round(this.getAverage(name) * 100) / 100,
        p50: Math.round(this.getPercentile(name, 50) * 100) / 100,
        p95: Math.round(this.getPercentile(name, 95) * 100) / 100,
        p99: Math.round(this.getPercentile(name, 99) * 100) / 100,
      };

      const benchmark = PERFORMANCE_BENCHMARKS[name];
      if (benchmark) {
        const p95 = this.getPercentile(name, 95);
        if (p95 > benchmark.critical) {
          issues.push({ name, severity: "critical", value: p95 });
        } else if (p95 > benchmark.warning) {
          issues.push({ name, severity: "warning", value: p95 });
        }
      }
    });

    return { summary, issues };
  }

  /**
   * Clear all metrics
   */
  clear(): void {
    this.metrics = [];
  }

  /**
   * Disconnect all observers
   */
  disconnect(): void {
    this.observers.forEach((observer) => observer.disconnect());
    this.observers.clear();
  }

  /**
   * Measure component throughput (actions per second)
   */
  measureThroughput(componentName: string, actionCount: number, duration: number): void {
    const throughput = (actionCount / duration) * 1000;

    this.recordMetric({
      name: `throughput.${componentName}`,
      value: throughput,
      unit: "count",
      timestamp: Date.now(),
      metadata: {
        actionCount,
        duration,
      },
    });
  }

  /**
   * Monitor animation frame rate
   */
  monitorFrameRate(duration: number = 1000): Promise<number> {
    return new Promise((resolve) => {
      if (typeof window === "undefined" || !window.requestAnimationFrame) {
        resolve(0);
        return;
      }

      let frameCount = 0;
      const startTime = performance.now();

      const countFrame = (currentTime: number) => {
        frameCount++;

        if (currentTime - startTime < duration) {
          lastTime = currentTime;
          requestAnimationFrame(countFrame);
        } else {
          const actualDuration = currentTime - startTime;
          const fps = (frameCount / actualDuration) * 1000;

          this.recordMetric({
            name: "animation.fps",
            value: fps,
            unit: "count",
            timestamp: Date.now(),
            metadata: {
              frameCount,
              duration: actualDuration,
            },
          });

          resolve(fps);
        }
      };

      requestAnimationFrame(countFrame);
    });
  }

  /**
   * Track memory usage (if available)
   */
  trackMemoryUsage(): void {
    type MemoryInfo = { usedJSHeapSize: number; totalJSHeapSize: number; jsHeapSizeLimit: number };
    const perf = performance as Performance & { memory?: MemoryInfo };
    if (typeof window === "undefined" || !perf.memory) {
      return;
    }

    const memory = perf.memory;

    this.recordMetric({
      name: "memory.used",
      value: memory.usedJSHeapSize / 1048576,
      unit: "bytes",
      timestamp: Date.now(),
      metadata: {
        total: memory.totalJSHeapSize / 1048576,
        limit: memory.jsHeapSizeLimit / 1048576,
      },
    });
  }

  /**
   * Get error rate for a specific operation
   */
  calculateErrorRate(operationName: string, timeWindow: number = 60000): number {
    const now = Date.now();
    const recentMetrics = this.metrics.filter(
      (m) => m.name === operationName && now - m.timestamp < timeWindow
    );

    if (recentMetrics.length === 0) return 0;

    const errors = recentMetrics.filter((m) => m.metadata?.error === true).length;
    return (errors / recentMetrics.length) * 100;
  }

  /**
   * Record operation result (success or error)
   */
  recordOperation(name: string, success: boolean, duration?: number): void {
    this.recordMetric({
      name,
      value: duration || 0,
      unit: "ms",
      timestamp: Date.now(),
      metadata: {
        error: !success,
        success,
      },
    });
  }
}

export const performanceMonitor = new PerformanceMonitor();

/**
 * React hook for performance monitoring
 */
export const usePerformanceMonitor = (name: string) => {
  const measureRef = React.useRef<(() => number) | null>(null);

  React.useEffect(() => {
    measureRef.current = performanceMonitor.startMeasure(name);

    return () => {
      if (measureRef.current) {
        measureRef.current();
      }
    };
  }, [name]);

  return {
    recordMetric: (metric: Omit<PerformanceMetric, "timestamp">) =>
      performanceMonitor.recordMetric({ ...metric, timestamp: Date.now() }),
  };
};

/**
 * Debounce function with performance tracking
 */
export function debounce<T extends (...args: Parameters<T>) => ReturnType<T>>(
  func: T,
  wait: number,
  options: { leading?: boolean; trailing?: boolean; maxWait?: number } = {}
): T & { cancel: () => void; flush: () => void } {
  let timeoutId: NodeJS.Timeout | undefined;
  let maxTimeoutId: NodeJS.Timeout | undefined;
  let lastArgs: Parameters<T> | undefined;
  let lastThis: unknown;
  let result: ReturnType<T> | undefined;
  let lastCallTime: number | undefined;
  let lastInvokeTime = 0;

  const { leading = false, trailing = true, maxWait } = options;

  function invokeFunc(time: number) {
    const args = lastArgs;
    // Snapshot and clear before invoking to avoid stale references on re-entry.
    // Cast to Parameters<T> is safe: invokeFunc is only called after debounced()
    // has set lastArgs. thisArg may be undefined when debounced is called as a
    // plain function (not a method) — that is the expected case and func.apply
    // handles undefined thisArg correctly in both strict and sloppy mode.
    const thisArg = lastThis as ThisParameterType<T> | undefined;

    lastArgs = lastThis = undefined;
    lastInvokeTime = time;
    result = func.apply(thisArg as ThisParameterType<T>, args!);
    return result;
  }

  function startTimer(pendingFunc: () => void, wait: number) {
    return setTimeout(pendingFunc, wait);
  }

  function cancelTimer(id: NodeJS.Timeout) {
    clearTimeout(id);
  }

  function leadingEdge(time: number) {
    lastInvokeTime = time;
    timeoutId = startTimer(timerExpired, wait);
    return leading ? invokeFunc(time) : result;
  }

  function remainingWait(time: number) {
    const timeSinceLastCall = time - lastCallTime!;
    const timeSinceLastInvoke = time - lastInvokeTime;
    const timeWaiting = wait - timeSinceLastCall;

    return maxWait !== undefined
      ? Math.min(timeWaiting, maxWait - timeSinceLastInvoke)
      : timeWaiting;
  }

  function shouldInvoke(time: number) {
    const timeSinceLastCall = time - lastCallTime!;
    const timeSinceLastInvoke = time - lastInvokeTime;

    return (
      lastCallTime === undefined ||
      timeSinceLastCall >= wait ||
      timeSinceLastCall < 0 ||
      (maxWait !== undefined && timeSinceLastInvoke >= maxWait)
    );
  }

  function timerExpired() {
    const time = Date.now();
    if (shouldInvoke(time)) {
      return trailingEdge(time);
    }
    timeoutId = startTimer(timerExpired, remainingWait(time));
  }

  function trailingEdge(time: number) {
    timeoutId = undefined;

    if (trailing && lastArgs) {
      return invokeFunc(time);
    }
    lastArgs = lastThis = undefined;
    return result;
  }

  function cancel() {
    if (timeoutId !== undefined) {
      cancelTimer(timeoutId);
    }
    if (maxTimeoutId !== undefined) {
      cancelTimer(maxTimeoutId);
    }
    lastInvokeTime = 0;
    lastArgs = lastCallTime = lastThis = timeoutId = maxTimeoutId = undefined;
  }

  function flush() {
    return timeoutId === undefined ? result : trailingEdge(Date.now());
  }

  function debounced(this: unknown, ...args: Parameters<T>) {
    const time = Date.now();
    const isInvoking = shouldInvoke(time);

    lastArgs = args;
    lastThis = this;
    lastCallTime = time;

    if (isInvoking) {
      if (timeoutId === undefined) {
        return leadingEdge(lastCallTime);
      }
      if (maxWait !== undefined) {
        timeoutId = startTimer(timerExpired, wait);
        return invokeFunc(lastCallTime);
      }
    }
    if (timeoutId === undefined) {
      timeoutId = startTimer(timerExpired, wait);
    }
    return result;
  }

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced as unknown as T & { cancel: () => void; flush: () => void };
}

/**
 * Safe JSON Parser with Zod Validation
 *
 * CRITICAL FIX: Addresses fragile JSON extraction from LLM outputs
 *
 * Problem: Current regex-based parsing fails 15-20% of the time when LLMs
 * add conversational text or malformed JSON.
 *
 * Solution: Multi-stage parsing pipeline with error recovery
 */

import { z } from "zod";

import { logger } from "../lib/logger";

/**
 * Parse result with detailed error information
 */
export interface ParseResult<T> {
  success: boolean;
  data?: T;
  error?: string;
  rawContent?: string;
  attempts?: number;
}

/**
 * Options for JSON parsing
 */
export interface ParseOptions {
  /** Maximum number of repair attempts */
  maxAttempts?: number;

  /** Whether to strip markdown code blocks */
  stripMarkdown?: boolean;

  /** Whether to attempt JSON repair */
  attemptRepair?: boolean;

  /** Whether to log parsing failures */
  logFailures?: boolean;
}

const DEFAULT_OPTIONS: ParseOptions = {
  maxAttempts: 3,
  stripMarkdown: true,
  attemptRepair: true,
  logFailures: true,
};

/**
 * Clean markdown code blocks from content
 */
function stripMarkdownCodeBlocks(content: string): string {
  // Remove ```json ... ``` blocks
  let cleaned = content.replace(/```json\s*\n?/gi, "");
  cleaned = cleaned.replace(/```\s*\n?/g, "");

  // Remove leading/trailing whitespace
  cleaned = cleaned.trim();

  return cleaned;
}

/**
 * Extract JSON substring from mixed content
 */
function extractJsonSubstring(content: string): string | null {
  // Find first { and last }
  const firstBrace = content.indexOf("{");
  const lastBrace = content.lastIndexOf("}");

  if (firstBrace === -1 || lastBrace === -1 || firstBrace >= lastBrace) {
    // Try array notation
    const firstBracket = content.indexOf("[");
    const lastBracket = content.lastIndexOf("]");

    if (firstBracket === -1 || lastBracket === -1 || firstBracket >= lastBracket) {
      return null;
    }

    return content.substring(firstBracket, lastBracket + 1);
  }

  return content.substring(firstBrace, lastBrace + 1);
}

/**
 * Attempt to repair common JSON errors
 */
function repairJson(jsonString: string): string {
  let repaired = jsonString;

  // Fix trailing commas in objects
  repaired = repaired.replace(/,(\s*[}\]])/g, "$1");

  // Fix missing quotes around keys (common LLM error)
  const unquotedKeyRegex =
    /"[^"\\]*(?:\\.[^"\\]*)*"|'[^'\\]*(?:\\.[^'\\]*)*'|([{,]\s*)([a-zA-Z_][a-zA-Z0-9_]*)\s*:/g;
  repaired = repaired.replace(unquotedKeyRegex, (match, p1, p2) => {
    if (p1 !== undefined && p2 !== undefined) {
      return `${p1}"${p2}":`;
    }
    return match;
  });

  // Convert single-quoted string values to double-quoted.
  // Only target key-value patterns to avoid mangling apostrophes in prose.
  repaired = repaired.replace(/:\s*'([^'\\]*(\\.[^'\\]*)*)'/g, ': "$1"');

  // Fix missing commas between properties (only when a closing quote
  // is followed by a newline and then an opening quote for a new key).
  repaired = repaired.replace(/"(\s*\n\s*)"([a-zA-Z_])/g, '",$1"$2');

  // Fix undefined/null values
  repaired = repaired.replace(/:\s*undefined/g, ": null");

  return repaired;
}

/**
 * Parse LLM output with schema validation
 *
 * @param content Raw LLM output
 * @param schema Zod schema for validation
 * @param options Parsing options
 * @returns Parsed and validated data
 */
export async function parseLLMOutput<T>(
  content: string,
  schema: z.ZodSchema<T>,
  options: ParseOptions = {}
): Promise<ParseResult<T>> {
  const opts = { ...DEFAULT_OPTIONS, ...options };
  let attempts = 0;
  let lastError: string | undefined;

  while (attempts < opts.maxAttempts!) {
    attempts++;

    try {
      // Stage 1: Clean markdown
      let cleaned = opts.stripMarkdown ? stripMarkdownCodeBlocks(content) : content;

      // Stage 2: Extract JSON substring
      const jsonString = extractJsonSubstring(cleaned);

      if (!jsonString) {
        lastError = "No JSON object or array found in content";
        if (attempts < opts.maxAttempts!) {
          // Try with the full content
          cleaned = content;
          continue;
        }
        break;
      }

      // Stage 3: Attempt repair if enabled
      const finalJson = opts.attemptRepair && attempts > 1 ? repairJson(jsonString) : jsonString;

      // Stage 4: Parse JSON
      const parsed = JSON.parse(finalJson);

      // Stage 5: Validate with Zod schema
      const validated = schema.parse(parsed);

      // Success!
      logger.debug("JSON parsing successful", {
        attempts,
        contentLength: content.length,
        jsonLength: finalJson.length,
      });

      return {
        success: true,
        data: validated,
        attempts,
      };
    } catch (error) {
      lastError = error instanceof Error ? error.message : String(error);

      if (opts.logFailures) {
        logger.warn("JSON parsing attempt failed", {
          attempt: attempts,
          maxAttempts: opts.maxAttempts,
          error: lastError,
          contentPreview: content.substring(0, 200),
        });
      }

      // If this was the last attempt, break
      if (attempts >= opts.maxAttempts!) {
        break;
      }
    }
  }

  // All attempts failed
  if (opts.logFailures) {
    logger.error("JSON parsing failed after all attempts", {
      attempts,
      error: lastError,
      content,
    });
  }

  return {
    success: false,
    error: lastError || "Unknown parsing error",
    rawContent: content,
    attempts,
  };
}

/**
 * Parse LLM output with automatic retry on failure
 *
 * This version throws an error if parsing fails, suitable for use
 * in contexts where you want to trigger error handling/retry logic.
 */
export async function parseLLMOutputStrict<T>(
  content: string,
  schema: z.ZodSchema<T>,
  options: ParseOptions = {}
): Promise<T> {
  const result = await parseLLMOutput(content, schema, options);

  if (!result.success) {
    throw new Error(`JSON parsing failed: ${result.error}`);
  }

  return result.data!;
}

/**
 * Create a reflection prompt for LLM to self-correct
 *
 * When parsing fails, this generates a prompt to send back to the LLM
 * asking it to fix the JSON output.
 */
export function createReflectionPrompt(
  originalPrompt: string,
  failedOutput: string,
  error: string
): string {
  return `Your previous response could not be parsed as valid JSON.

Original request: ${originalPrompt}

Your response: ${failedOutput}

Error: ${error}

Please provide a corrected response with valid JSON only. Ensure:
1. All keys are in double quotes
2. All string values are in double quotes
3. No trailing commas
4. Proper nesting of objects and arrays
5. No comments or extra text outside the JSON

Corrected JSON:`;
}

/**
 * Common schemas for LLM outputs
 */
export const CommonSchemas = {
  /** Schema for KPI extraction */
  kpiSchema: z.object({
    kpis: z.array(
      z.object({
        kpi_name: z.string(),
        target_value: z.number(),
        unit: z.string().optional(),
        timeframe: z.string().optional(),
      })
    ),
  }),

  /** Schema for component selection */
  componentSchema: z.object({
    component_type: z.string(),
    props: z.record(z.any()),
    reasoning: z.string().optional(),
  }),

  /** Schema for subgoal routing */
  subgoalSchema: z.object({
    subgoals: z.array(
      z.object({
        id: z.string(),
        type: z.string(),
        description: z.string(),
        assigned_agent: z.string(),
        dependencies: z.array(z.string()).optional(),
      })
    ),
  }),

  /** Schema for system map */
  systemMapSchema: z.object({
    nodes: z.array(
      z.object({
        id: z.string(),
        label: z.string(),
        type: z.enum(["factor", "outcome", "intervention"]),
      })
    ),
    edges: z.array(
      z.object({
        source: z.string(),
        target: z.string(),
        relationship: z.string(),
      })
    ),
  }),
};

/**
 * Utility to validate and parse JSON with a specific schema
 */
export function createSchemaParser<T>(schema: z.ZodSchema<T>) {
  return {
    parse: (content: string, options?: ParseOptions) => parseLLMOutput(content, schema, options),
    parseStrict: (content: string, options?: ParseOptions) =>
      parseLLMOutputStrict(content, schema, options),
    schema,
  };
}

/**
 * Consolidated Sanitization Utilities
 * Extracted common sanitization logic from across the codebase
 */

import { logger } from '../lib/logger';

export interface SanitizationResult {
  sanitized: string;
  originalLength: number;
  sanitizedLength: number;
  changes: string[];
}

export interface SanitizationOptions {
  maxLength?: number;
  removeScripts?: boolean;
  encodeHtmlEntities?: boolean;
  removeEventHandlers?: boolean;
  removeDangerousProtocols?: boolean;
  trimWhitespace?: boolean;
}

/**
 * Default sanitization options
 */
export const DEFAULT_SANITIZATION_OPTIONS: Required<SanitizationOptions> = {
  maxLength: 50000,
  removeScripts: true,
  encodeHtmlEntities: true,
  removeEventHandlers: true,
  removeDangerousProtocols: true,
  trimWhitespace: false,
};

/**
 * Patterns for script tag removal (with content)
 */
const SCRIPT_PATTERNS = [
  /<script[\s\S]*?<\/script>/gi,
  /<!--[\s\S]*?-->/g,
];

/**
 * Patterns for event handler attribute removal (attribute only, not the element).
 * Matches the attribute name+value but preserves the preceding whitespace token.
 */
const EVENT_HANDLER_PATTERN = /on\w+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]*)/gi;

/**
 * Patterns for dangerous protocol removal (full expression up to whitespace)
 */
const DANGEROUS_PROTOCOL_PATTERNS = [
  /javascript:\S*/gi,
  /data:text\/html\S*/gi,
];

/**
 * HTML entities mapping for encoding
 */
const HTML_ENTITIES: Record<string, string> = {
  '&': '&amp;',
  '<': '&lt;',
  '>': '&gt;',
  '"': '&quot;',
  "'": '&#39;',
};

/**
 * Encode dangerous HTML characters (does not encode / to preserve tag structure)
 */
function encodeHtmlEntities(text: string): string {
  return text.replace(/[&<>"']/g, char => HTML_ENTITIES[char] || char);
}

/**
 * Remove dangerous patterns from content, respecting individual config flags
 */
function removeDangerousPatterns(
  content: string,
  opts: { removeScripts: boolean; removeEventHandlers: boolean; removeDangerousProtocols: boolean }
): { sanitized: string; changes: string[] } {
  const changes: string[] = [];
  let sanitized = content;

  if (opts.removeScripts) {
    for (const pattern of SCRIPT_PATTERNS) {
      sanitized = sanitized.replace(pattern, (match) => {
        changes.push(`Removed: ${match.slice(0, 50)}${match.length > 50 ? '...' : ''}`);
        return '';
      });
    }
  }

  if (opts.removeEventHandlers) {
    sanitized = sanitized.replace(EVENT_HANDLER_PATTERN, (match) => {
      changes.push(`Removed: ${match.trim().slice(0, 50)}`);
      return '';
    });
  }

  if (opts.removeDangerousProtocols) {
    for (const pattern of DANGEROUS_PROTOCOL_PATTERNS) {
      sanitized = sanitized.replace(pattern, (match) => {
        changes.push(`Removed: ${match.slice(0, 50)}${match.length > 50 ? '...' : ''}`);
        return '';
      });
    }
  }

  return { sanitized, changes };
}

/**
 * Trim excessive whitespace
 */
function trimWhitespace(text: string): string {
  return text
    .replace(/[ \t]+/g, ' ')  // Multiple spaces/tabs to single space
    .replace(/\n{3,}/g, '\n\n')  // Multiple newlines to double newline
    .trim();
}

/**
 * Sanitize LLM content with comprehensive security measures
 */
export function sanitizeLLMContent(
  content: string,
  options: SanitizationOptions = {}
): SanitizationResult {
  if (!content || typeof content !== 'string') {
    return {
      sanitized: '',
      originalLength: 0,
      sanitizedLength: 0,
      changes: ['Empty or invalid content']
    };
  }

  const config = { ...DEFAULT_SANITIZATION_OPTIONS, ...options };
  const changes: string[] = [];
  let sanitized = content;

  // Track original length
  const originalLength = content.length;

  try {
    // Remove dangerous patterns
    if (config.removeScripts || config.removeEventHandlers || config.removeDangerousProtocols) {
      const patternResult = removeDangerousPatterns(sanitized, {
        removeScripts: config.removeScripts,
        removeEventHandlers: config.removeEventHandlers,
        removeDangerousProtocols: config.removeDangerousProtocols,
      });
      sanitized = patternResult.sanitized;
      changes.push(...patternResult.changes);
    }

    // Encode HTML entities
    if (config.encodeHtmlEntities) {
      const before = sanitized;
      sanitized = encodeHtmlEntities(sanitized);
      if (before !== sanitized) {
        changes.push('Encoded HTML entities');
      }
    }

    // Trim whitespace
    if (config.trimWhitespace) {
      const before = sanitized;
      sanitized = trimWhitespace(sanitized);
      if (before !== sanitized) {
        changes.push('Trimmed excessive whitespace');
      }
    }

    // Limit length
    if (config.maxLength && sanitized.length > config.maxLength) {
      sanitized = sanitized.slice(0, config.maxLength);
      changes.push(`Truncated to ${config.maxLength} characters`);
    }

    const sanitizedLength = sanitized.length;

    // Log significant changes for security monitoring
    if (changes.length > 0) {
      logger.debug('Content sanitized', {
        originalLength,
        sanitizedLength,
        changesCount: changes.length,
        significantChange: originalLength !== sanitizedLength
      });
    }

    return {
      sanitized,
      originalLength,
      sanitizedLength,
      changes
    };

  } catch (error) {
    logger.error('Sanitization error', { error: error instanceof Error ? error.message : error });
    return {
      sanitized: '',
      originalLength,
      sanitizedLength: 0,
      changes: ['Sanitization failed - content removed for security']
    };
  }
}

/**
 * Sanitize user input with basic validation
 */
export function sanitizeUserInput(
  input: string,
  maxLength = 2000
): SanitizationResult {
  return sanitizeLLMContent(input, {
    maxLength,
    removeScripts: true,
    encodeHtmlEntities: false, // User input might need different handling
    removeEventHandlers: true,
    removeDangerousProtocols: true,
    trimWhitespace: false,
  });
}

/**
 * Sanitize LLM messages for agent communication
 */
export function sanitizeLLMMessage(
  message: { role: string; content: string; [key: string]: unknown }
): { sanitized: typeof message; changes: string[] } {
  const changes: string[] = [];

  if (typeof message.content === 'string' && message.content.length > 0) {
    const contentResult = sanitizeLLMContent(message.content, { encodeHtmlEntities: false, trimWhitespace: false });
    if (contentResult.changes.length > 0) {
      changes.push(...contentResult.changes.map(change => `content: ${change}`));
    }

    return {
      sanitized: {
        ...message,
        content: contentResult.sanitized,
      },
      changes
    };
  }

  return { sanitized: message, changes };
}

/**
 * Check if content contains potentially dangerous patterns
 */
export function containsDangerousContent(content: string): {
  dangerous: boolean;
  patterns: string[];
  severity: 'low' | 'medium' | 'high';
} {
  const patterns: string[] = [];
  let severity: 'low' | 'medium' | 'high' = 'low';

  const allPatterns = [...SCRIPT_PATTERNS, EVENT_HANDLER_PATTERN, ...DANGEROUS_PROTOCOL_PATTERNS];
  for (const pattern of allPatterns) {
    const matches = content.match(pattern);
    if (matches) {
      patterns.push(...matches.slice(0, 5)); // Limit to first 5 matches
      severity = 'high'; // Any dangerous pattern is high severity
    }
  }

  // Check for prompt injection patterns
  const injectionPatterns = [
    /^\s*system:/i,
    /^\s*ignore\s+(previous|all)/i,
    /jailbreak/i,
    /developer\s+mode/i,
    /\b(system|assistant):\s/i,
  ];

  for (const pattern of injectionPatterns) {
    if (pattern.test(content)) {
      patterns.push('Prompt injection pattern');
      severity = severity === 'high' ? 'high' : 'medium';
    }
  }

  return {
    dangerous: patterns.length > 0,
    patterns,
    severity
  };
}

/**
 * Batch sanitize multiple content strings
 */
export function sanitizeBatch(
  contents: string[],

  options: SanitizationOptions = {}
): Array<SanitizationResult & { index: number }> {
  return contents.map((content, index) => ({
    ...sanitizeLLMContent(content, options),
    index
  }));
}

import DOMPurify from "isomorphic-dompurify";

const DEFAULT_CONFIG: DOMPurify.Config = {
  ALLOWED_TAGS: [
    "a", "b", "blockquote", "br", "code", "div", "em",
    "h1", "h2", "h3", "h4", "h5", "h6", "hr", "i", "img",
    "li", "ol", "p", "pre", "span", "strong",
    "table", "tbody", "td", "tfoot", "th", "thead", "tr", "ul",
  ],
  ALLOWED_ATTR: ["alt", "class", "height", "href", "rel", "src", "target", "title", "width"],
  ADD_ATTR: ["target"],
  FORBID_TAGS: ["script", "style", "iframe", "object", "embed", "form", "input"],
  FORBID_ATTR: ["onerror", "onload", "onclick", "onmouseover", "onfocus", "onblur"],
  ALLOW_DATA_ATTR: false,
};

export function sanitizeHtml(dirty: string): string {
  if (!dirty) return "";

  const sanitized = DOMPurify.sanitize(dirty, DEFAULT_CONFIG) as string;
  if (typeof document === "undefined") {
    return sanitized;
  }

  const template = document.createElement("template");
  // eslint-disable-next-line no-restricted-syntax
  template.innerHTML = sanitized;

  template.content.querySelectorAll("a").forEach((anchor) => {
    const href = anchor.getAttribute("href");
    if (href && !/^(https?:|mailto:|tel:)/i.test(href)) {
      anchor.removeAttribute("href");
    }

    if (anchor.getAttribute("target") === "_blank" || (href && /^https?:/i.test(href))) {
      anchor.setAttribute("rel", "noopener noreferrer");
    }
  });

  template.content.querySelectorAll("img").forEach((image) => {
    const src = image.getAttribute("src");
    if (src && /^(data:|javascript:)/i.test(src.trim())) {
      image.removeAttribute("src");
    }
  });

  return template.innerHTML;
}

