/**
 * Template Security Hardening Utilities
 * Provides XSS prevention, input validation, and CSRF protection for UI templates
 */

import { logger } from "@/lib/logger";
import * as DOMPurify from "isomorphic-dompurify";
import React from "react";

// ============================================================================
// XSS Prevention
// ============================================================================

/**
 * Sanitizes HTML content to prevent XSS attacks
 * Uses DOMPurify with strict configuration
 */
export const sanitizeHTML = (input: string): string => {
  if (!input || typeof input !== "string") return "";

  return DOMPurify.sanitize(input, {
    ALLOWED_TAGS: [], // No HTML tags allowed by default
    ALLOWED_ATTR: [], // No attributes allowed
    FORBID_TAGS: ["script", "iframe", "object", "embed", "link", "style"],
    FORBID_ATTR: [
      "onerror",
      "onload",
      "onclick",
      "onmouseover",
      "onmouseout",
      "onfocus",
      "onblur",
    ],
    KEEP_CONTENT: false,
    RETURN_DOM: false,
    RETURN_DOM_FRAGMENT: false,
  });
};

/**
 * Sanitizes user input for display in templates
 * Removes dangerous content while preserving text
 */
export const sanitizeUserInput = (input: unknown): string => {
  if (input === null || input === undefined) return "";
  if (typeof input !== "string") return String(input);

  // Remove script tags and dangerous patterns
  let sanitized = input
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, "")
    .replace(/javascript:/gi, "")
    .replace(/on\w+\s*=\s*["'][^"']*["']/gi, "")
    .replace(/<[^>]*>/g, ""); // Remove all HTML tags

  return sanitizeHTML(sanitized);
};

/**
 * Sanitizes complex data objects (arrays, nested objects)
 */
export const sanitizeDataObject = <T,>(data: T): T => {
  if (data === null || data === undefined) return data;

  if (Array.isArray(data)) {
    return data.map((item) => sanitizeDataObject(item)) as unknown as T;
  }

  if (typeof data === "object" && data !== null) {
    const sanitized: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(data)) {
      if (typeof value === "string") {
        sanitized[key] = sanitizeUserInput(value);
      } else if (typeof value === "object" && value !== null) {
        sanitized[key] = sanitizeDataObject(value);
      } else {
        sanitized[key] = value;
      }
    }
    return sanitized as unknown as T;
  }

  if (typeof data === "string") {
    return sanitizeUserInput(data) as unknown as T;
  }

  return data;
};

// ============================================================================
// Input Validation
// ============================================================================

/**
 * Validates and sanitizes numeric inputs
 */
export const validateNumber = (
  input: unknown,
  min?: number,
  max?: number
): number => {
  const num = Number(input);
  if (isNaN(num)) return 0;

  if (min !== undefined && num < min) return min;
  if (max !== undefined && num > max) return max;

  return num;
};

/**
 * Validates string inputs with length limits
 */
export const validateString = (
  input: unknown,
  maxLength: number = 1000
): string => {
  if (input === null || input === undefined) return "";

  const str = String(input);
  const sanitized = sanitizeUserInput(str);

  return sanitized.slice(0, maxLength);
};

/**
 * Validates email format
 */
export const validateEmail = (email: string): boolean => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

/**
 * Validates URL format
 */
export const validateURL = (url: string): boolean => {
  try {
    const parsed = new URL(url);
    return ["http:", "https:"].includes(parsed.protocol);
  } catch {
    return false;
  }
};

/**
 * Validates array inputs
 */
export const validateArray = <T,>(input: unknown, maxLength: number = 100): T[] => {
  if (!Array.isArray(input)) return [];
  return input.slice(0, maxLength) as T[];
};

// ============================================================================
// CSRF Protection
// ============================================================================

/**
 * Generates CSRF token
 */
export const generateCSRFToken = (): string => {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return Array.from(array, (byte) => byte.toString(16).padStart(2, "0")).join(
    ""
  );
};

/**
 * Validates CSRF token
 */
export const validateCSRFToken = (token: string): boolean => {
  if (!token || typeof token !== "string") return false;
  return token.length === 64 && /^[0-9a-f]+$/.test(token);
};

/**
 * Stores CSRF token in secure manner
 */
export const storeCSRFToken = (token: string): void => {
  if (validateCSRFToken(token)) {
    sessionStorage.setItem("csrf_token", token);
  }
};

/**
 * Retrieves and validates CSRF token
 */
export const getCSRFToken = (): string | null => {
  const token = sessionStorage.getItem("csrf_token");
  return token && validateCSRFToken(token) ? token : null;
};

// ============================================================================
// Content Security Policy
// ============================================================================

/**
 * Validates content source
 */
export const validateContentSource = (source: string): boolean => {
  const allowedSources = [
    "https://",
    "http://localhost",
    "data:image/",
    "blob:",
  ];

  return allowedSources.some((allowed) => source.startsWith(allowed));
};

/**
 * Sanitizes image sources
 */
export const sanitizeImageSource = (src: string): string => {
  if (!validateContentSource(src)) {
    return "about:blank";
  }
  return src;
};

// ============================================================================
// Data Masking
// ============================================================================

/**
 * Masks sensitive data (e.g., credit cards, SSN)
 */
export const maskSensitiveData = (
  data: string,
  visibleChars: number = 4
): string => {
  if (!data || typeof data !== "string") return "";

  if (data.length <= visibleChars) return "*".repeat(data.length);

  const visible = data.slice(-visibleChars);
  return "*".repeat(data.length - visibleChars) + visible;
};

/**
 * Masks email address
 */
export const maskEmail = (email: string): string => {
  if (!validateEmail(email)) return "";

  const [local, domain] = email.split("@");
  const maskedLocal =
    local.length > 2
      ? local[0] + "*".repeat(local.length - 2) + local[local.length - 1]
      : "*".repeat(local.length);

  return `${maskedLocal}@${domain}`;
};

// ============================================================================
// Template-Specific Validators
// ============================================================================

/**
 * Validates ROI calculator inputs
 */
export const validateROIInputs = (inputs: {
  engHeadcount: number;
  engSalary: number;
  buildCost: number;
  efficiencyTarget: number;
}): {
  engHeadcount: number;
  engSalary: number;
  buildCost: number;
  efficiencyTarget: number;
} => {
  return {
    engHeadcount: validateNumber(inputs.engHeadcount, 1, 1000),
    engSalary: validateNumber(inputs.engSalary, 10, 500),
    buildCost: validateNumber(inputs.buildCost, 1, 10000),
    efficiencyTarget: validateNumber(inputs.efficiencyTarget, 1, 100),
  };
};

/**
 * Validates scenario data
 */
export const validateScenarioData = (scenario: {
  id: string;
  title: string;
  description: string;
  category?: string;
}): {
  id: string;
  title: string;
  description: string;
  category?: string;
} => {
  return {
    id: validateString(scenario.id, 50),
    title: validateString(scenario.title, 200),
    description: validateString(scenario.description, 1000),
    category: scenario.category
      ? validateString(scenario.category, 50)
      : undefined,
  };
};

/**
 * Validates persona analysis data
 */
export const validatePersonaAnalysis = (analysis: {
  id: string;
  persona: string;
  title: string;
  summary: string;
  confidence: number;
}): {
  id: string;
  persona: string;
  title: string;
  summary: string;
  confidence: number;
} => {
  return {
    id: validateString(analysis.id, 50),
    persona: validateString(analysis.persona, 20),
    title: validateString(analysis.title, 200),
    summary: validateString(analysis.summary, 1000),
    confidence: validateNumber(analysis.confidence, 0, 100),
  };
};

// ============================================================================
// Security Headers
// ============================================================================

/**
 * Returns security headers for template responses
 */
export const getSecurityHeaders = (): Record<string, string> => ({
  "X-Content-Type-Options": "nosniff",
  "X-Frame-Options": "DENY",
  "X-XSS-Protection": "1; mode=block",
  "Strict-Transport-Security": "max-age=31536000; includeSubDomains",
  "Referrer-Policy": "strict-origin-when-cross-origin",
  "Permissions-Policy": "geolocation=(), microphone=(), camera=()",
});

// ============================================================================
// Safe JSON Parsing
// ============================================================================

/**
 * Safely parses JSON with validation
 */
export const safeJSONParse = <T,>(
  jsonString: string,
  defaultValue: T | null = null
): T | null => {
  try {
    const parsed = JSON.parse(jsonString);
    return sanitizeDataObject(parsed);
  } catch {
    return defaultValue;
  }
};

/**
 * Safely stringifies data with validation
 */
export const safeJSONStringify = <T,>(data: T): string | null => {
  try {
    // Remove circular references
    const seen = new WeakSet<object>();
    const safeData = JSON.parse(
      JSON.stringify(data, (_key, value) => {
        if (typeof value === "object" && value !== null) {
          if (seen.has(value)) return "[Circular]";
          seen.add(value);
        }
        return value;
      })
    );

    return JSON.stringify(sanitizeDataObject(safeData));
  } catch {
    return null;
  }
};

// ============================================================================
// Rate Limiting
// ============================================================================

interface RateLimitConfig {
  maxRequests: number;
  windowMs: number;
}

const rateLimitStore = new Map<string, { count: number; resetTime: number }>();

/**
 * Checks rate limit for a given identifier
 */
export const checkRateLimit = (
  identifier: string,
  config: RateLimitConfig = { maxRequests: 100, windowMs: 60000 }
): boolean => {
  const now = Date.now();
  const existing = rateLimitStore.get(identifier);

  if (!existing || now > existing.resetTime) {
    rateLimitStore.set(identifier, {
      count: 1,
      resetTime: now + config.windowMs,
    });
    return true;
  }

  if (existing.count >= config.maxRequests) {
    return false;
  }

  existing.count++;
  return true;
};

/**
 * Clears rate limit for identifier
 */
export const clearRateLimit = (identifier: string): void => {
  rateLimitStore.delete(identifier);
};

// ============================================================================
// Input Sanitization Pipeline
// ============================================================================

/**
 * Complete sanitization pipeline for template inputs
 */
export const sanitizeTemplateInput = <T,>(
  input: T,
  schema?: Record<string, (value: unknown) => unknown>
): T => {
  if (!input) return input;

  // Step 1: Sanitize data structure
  const sanitized = sanitizeDataObject(input);

  // Step 2: Validate against schema if provided
  if (schema) {
    const validated: Record<string, unknown> = {};
    for (const [key, validator] of Object.entries(schema)) {
      if (Object.prototype.hasOwnProperty.call(sanitized, key)) {
        validated[key] = validator(sanitized[key]);
      }
    }
    return validated as T;
  }

  return sanitized;
};

// ============================================================================
// Security Event Logging
// ============================================================================

export interface SecurityEvent {
  type: "xss_attempt" | "csrf_violation" | "rate_limit" | "invalid_input";
  timestamp: number;
  source: string;
  details: unknown;
}

const securityEvents: SecurityEvent[] = [];

/**
 * Logs security events for monitoring
 */
export const logSecurityEvent = (
  event: Omit<SecurityEvent, "timestamp">
): void => {
  const fullEvent: SecurityEvent = {
    ...event,
    timestamp: Date.now(),
  };

  securityEvents.push(fullEvent);

  // Keep only last 1000 events
  if (securityEvents.length > 1000) {
    securityEvents.shift();
  }

  // In production, send to security monitoring service
  if (process.env.NODE_ENV === "production") {
    logger.warn("SECURITY_EVENT:", { event: fullEvent });
  }
};

/**
 * Retrieves recent security events
 */
export const getSecurityEvents = (limit: number = 100): SecurityEvent[] => {
  return securityEvents.slice(-limit);
};

// ============================================================================
// Template Security Wrapper
// ============================================================================

/**
 * Wraps template component with security measures
 */
export const withSecurity = <P extends object>(
  Component: React.ComponentType<P>,
  securityConfig: {
    sanitizeProps?: boolean;
    validateInputs?: boolean;
    requireCSRF?: boolean;
  } = {}
) => {
  const WrappedComponent = (props: P) => {
    const {
      sanitizeProps = true,
      validateInputs = false,
      requireCSRF = false,
    } = securityConfig;

    let sanitizedProps = { ...props };

    // Sanitize props if enabled
    if (sanitizeProps) {
      sanitizedProps = sanitizeDataObject(props) as P;
    }

    // Validate inputs if enabled
    if (validateInputs) {
      // Add validation logic here based on component type
    }

    // Check CSRF if required
    if (requireCSRF) {
      const token = getCSRFToken();
      if (!token) {
        logSecurityEvent({
          type: "csrf_violation",
          source: "withSecurity",
          details: { component: Component.name },
        });
        return null; // Or render error state
      }
    }

    return <Component {...sanitizedProps} />;
  };

  WrappedComponent.displayName = `withSecurity(${Component.displayName || Component.name})`;
  return WrappedComponent;
};

// ============================================================================
// Export all utilities
// ============================================================================

export default {
  // XSS Prevention
  sanitizeHTML,
  sanitizeUserInput,
  sanitizeDataObject,

  // Input Validation
  validateNumber,
  validateString,
  validateEmail,
  validateURL,
  validateArray,

  // CSRF Protection
  generateCSRFToken,
  validateCSRFToken,
  storeCSRFToken,
  getCSRFToken,

  // Content Security
  validateContentSource,
  sanitizeImageSource,

  // Data Masking
  maskSensitiveData,
  maskEmail,

  // Template Validators
  validateROIInputs,
  validateScenarioData,
  validatePersonaAnalysis,

  // Security Headers
  getSecurityHeaders,

  // Safe JSON
  safeJSONParse,
  safeJSONStringify,

  // Rate Limiting
  checkRateLimit,
  clearRateLimit,

  // Pipeline
  sanitizeTemplateInput,

  // Logging
  logSecurityEvent,
  getSecurityEvents,

  // Wrapper
  withSecurity,
};

/**
 * Documentation CMS (Content Management System)
 *
 * Admin interface for managing documentation pages:
 * - Create/edit/delete pages
 * - Version history
 * - Draft/published states
 * - Category management
 * - Media uploads
 */

import {
  AlertCircle,
  CheckCircle,
  Clock,
  Edit,
  FileText,
  Plus,
  Save,
  Search,
  Trash2,
  X,
} from "lucide-react";
import React, { useEffect, useState } from "react";

import { useOrganization } from "../../hooks/useOrganization";
import { supabase } from "../../lib/supabase";

interface DocPage {
  id: string;
  slug: string;
  title: string;
  description: string;
  content: string;
  category_id: string;
  status: "draft" | "published" | "archived";
  version: string;
  featured: boolean;
  tags: string[];
  created_at: string;
  updated_at: string;
}

interface DocCategory {
  id: string;
  slug: string;
  name: string;
  description: string;
  icon: string;
}

export const DocumentationCMS: React.FC = () => {
  const { organizationId } = useOrganization();
  const [pages, setPages] = useState<DocPage[]>([]);
  const [categories, setCategories] = useState<DocCategory[]>([]);
  const [selectedPage, setSelectedPage] = useState<DocPage | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [filterStatus, setFilterStatus] = useState<string>("all");
  const [loading, setLoading] = useState(true);
  const [confirmDeletePageId, setConfirmDeletePageId] = useState<string | null>(null);

  useEffect(() => {
    if (!organizationId) return;
    loadPages();
    loadCategories();
  }, [filterStatus, searchQuery, organizationId]);

  const loadPages = async () => {
    if (!organizationId) return;
    setLoading(true);
    let query = supabase.from("doc_pages")
      .select("*")
      .eq("organization_id", organizationId)
      .order("updated_at", { ascending: false });
    if (filterStatus !== "all") {
      query = query.eq("status", filterStatus);
    }
    if (searchQuery) {
      query = query.or(
        `title.ilike.%${searchQuery}%,description.ilike.%${searchQuery}%`
      );
    }
    const { data, error } = await query;
    if (data && !error) {
      setPages(data);
    }
    setLoading(false);
  };

  const loadCategories = async () => {
    if (!organizationId) return;
    const { data } = await supabase.from("doc_categories")
      .select("*")
      .eq("organization_id", organizationId)
      .order("display_order");
    if (data) {
      setCategories(data);
    }
  };

  const createNewPage = () => {
    const newPage: DocPage = {
      id: "",
      slug: "",
      title: "",
      description: "",
      content: "",
      category_id: categories[0]?.id || "",
      status: "draft",
      version: "1.0.0",
      featured: false,
      tags: [],
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
    };
    setSelectedPage(newPage);
    setIsEditing(true);
  };

  const savePage = async () => {
    if (!selectedPage || !organizationId) return;
    // Generate slug from title if empty
    if (!selectedPage.slug) {
      selectedPage.slug = selectedPage.title
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, "-")
        .replace(/^-|-$/g, "");
    }
    const pageData = {
      ...selectedPage,
      organization_id: organizationId,
      updated_at: new Date().toISOString(),
    };
    if (selectedPage.id) {
      // Update existing page — scope to both id and organization_id
      const { error } = await supabase.from("doc_pages")
        .update(pageData)
        .eq("id", selectedPage.id)
        .eq("organization_id", organizationId);
      if (!error) {
        // Create version history entry scoped to the organization
        await supabase.from("doc_versions").insert({
          page_id: selectedPage.id,
          organization_id: organizationId,
          version: selectedPage.version,
          title: selectedPage.title,
          content: selectedPage.content,
          content_type: "markdown",
          change_summary: "Updated via CMS",
        });
      }
    } else {
      // Create new page
      const { data, error } = await supabase.from("doc_pages")
        .insert(pageData)
        .select()
        .single();
      if (data && !error) {
        setSelectedPage(data);
      }
    }
    loadPages();
    setIsEditing(false);
  };

  const deletePage = (pageId: string) => {
    setConfirmDeletePageId(pageId);
  };

  const handleConfirmDeletePage = async () => {
    if (!confirmDeletePageId || !organizationId) return;
    await supabase.from("doc_pages")
      .delete()
      .eq("id", confirmDeletePageId)
      .eq("organization_id", organizationId);
    loadPages();
    setSelectedPage(null);
    setConfirmDeletePageId(null);
  };

  const publishPage = async (pageId: string) => {
    if (!organizationId) return;
    await supabase.from("doc_pages")
      .update({
        status: "published",
        published_at: new Date().toISOString(),
      })
      .eq("id", pageId)
      .eq("organization_id", organizationId);
    loadPages();
  };

  const unpublishPage = async (pageId: string) => {
    if (!organizationId) return;
    await supabase.from("doc_pages")
      .update({ status: "draft" })
      .eq("id", pageId)
      .eq("organization_id", organizationId);
    loadPages();
  };

  return (
    <>
      {/* ...existing UI code for the CMS goes here... */}
