/**
 * Reset Password Page
 * Request password reset email
 */

import { AlertCircle, CheckCircle, Mail } from 'lucide-react';
import React, { useState } from 'react';
import { Link } from 'react-router-dom';

import { useAuth } from '../../contexts/AuthContext';
import { logger } from '@/lib/logger';

export function ResetPasswordPage() {
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);

  const { resetPassword } = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess(false);
    setLoading(true);

    try {
      await resetPassword(email);
      setSuccess(true);
    } catch (err: unknown) {
      logger.error('Password reset error:', { error: err });
      setError((err instanceof Error ? err.message : null) || 'Failed to send reset email. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 to-indigo-100 px-4">
      <div className="max-w-md w-full">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-gray-900 mb-2">Reset Password</h1>
          <p className="text-gray-600">Enter your email to receive a reset link</p>
        </div>

        {/* Reset Form */}
        <div className="bg-white rounded-lg shadow-xl p-8">
          {success ? (
            // Success Message
            <div className="text-center">
              <div className="mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4">
                <CheckCircle className="w-10 h-10 text-green-600" />
              </div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">Check Your Email</h3>
              <p className="text-gray-600 mb-6">
                We've sent a password reset link to <strong>{email}</strong>
              </p>
              <p className="text-sm text-gray-500 mb-6">
                Click the link in the email to reset your password. The link will expire in 1 hour.
              </p>
              <Link
                to="/login"
                className="inline-block w-full py-3 px-4 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 transition-colors"
              >
                Back to Login
              </Link>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Error Alert */}
              {error && (
                <div className="bg-red-50 border border-red-200 rounded-lg p-4 flex items-start">
                  <AlertCircle className="w-5 h-5 text-red-600 mr-3 mt-0.5 flex-shrink-0" />
                  <div className="text-sm text-red-800">{error}</div>
                </div>
              )}

              {/* Email */}
              <div>
                <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-2">
                  Email Address
                </label>
                <div className="relative">
                  <Mail className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    id="email"
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    placeholder="you@example.com"
                    disabled={loading}
                  />
                </div>
              </div>

              {/* Submit Button */}
              <button
                type="submit"
                disabled={loading}
                className={`
                  w-full py-3 px-4 rounded-lg font-semibold text-white
                  ${loading
                    ? 'bg-gray-400 cursor-not-allowed'
                    : 'bg-blue-600 hover:bg-blue-700 active:bg-blue-800'
                  }
                  transition-colors duration-200
                `}
              >
                {loading ? 'Sending...' : 'Send Reset Link'}
              </button>

              {/* Back to Login */}
              <div className="text-center">
                <Link to="/login" className="text-sm text-blue-600 hover:text-blue-700 font-medium">
                  ← Back to Login
                </Link>
              </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

export default ResetPasswordPage;

import { fireEvent, render, screen, waitFor } from "@testing-library/react";
import { MemoryRouter } from "react-router-dom";
import { beforeEach, describe, expect, it, vi } from "vitest";

import { AuthRateLimitError, authRateLimiter } from "@/lib/rateLimiter";

import { ModernLoginPage } from "../ModernLoginPage";

const mockLogin = vi.fn();

vi.mock("../../../contexts/AuthContext", () => ({
  useAuth: () => ({
    login: mockLogin,
    signup: vi.fn(),
    resendVerificationEmail: vi.fn(),
    signInWithProvider: vi.fn(),
  }),
}));

vi.mock("../../../i18n", () => ({
  getSupportedLocales: () => [{ code: "en", label: "English" }],
}));

vi.mock("../../../i18n/I18nProvider", () => ({
  useI18n: () => ({
    locale: "en",
    setLocale: vi.fn(),
    t: (_key: string, fallback: string) => fallback,
  }),
}));

vi.mock("../../../lib/logger", () => ({
  logger: {
    info: vi.fn(),
    error: vi.fn(),
  },
}));

const submitLoginForm = async () => {
  fireEvent.change(screen.getByLabelText(/corporate email/i), {
    target: { value: "locked@example.com" },
  });
  fireEvent.change(screen.getByLabelText(/security key/i), {
    target: { value: "password123" },
  });
  fireEvent.click(screen.getByRole("button", { name: /resume value model/i }));
};

describe("ModernLoginPage lockout handling", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    authRateLimiter.clearAllData();
    localStorage.clear();
  });

  it("does not unlock when localStorage is cleared if backend still reports locked", async () => {
    for (let index = 0; index < 5; index += 1) {
      authRateLimiter.recordFailedAttempt("locked@example.com");
    }
    localStorage.clear();

    mockLogin.mockRejectedValueOnce(
      new AuthRateLimitError("Too many login attempts", {
        locked: true,
        retryAfterSeconds: 300,
        remainingAttempts: 0,
      }, 429),
    );

    render(
      <MemoryRouter>
        <ModernLoginPage />
      </MemoryRouter>,
    );

    await submitLoginForm();

    await waitFor(() => {
      expect(mockLogin).toHaveBeenCalledTimes(1);
      expect(
        screen.getByText("Too many login attempts. Try again in about 5 minutes."),
      ).toBeInTheDocument();
    });
  });

  it("uses server retry window in lockout message when backend provides metadata", async () => {
    for (let index = 0; index < 5; index += 1) {
      authRateLimiter.recordFailedAttempt("locked@example.com");
    }

    mockLogin.mockRejectedValueOnce(
      new AuthRateLimitError("Locked", { locked: true, retryAfterSeconds: 120 }, 429),
    );

    render(
      <MemoryRouter>
        <ModernLoginPage />
      </MemoryRouter>,
    );

    await submitLoginForm();

    await waitFor(() => {
      expect(
        screen.getByText("Too many login attempts. Try again in about 2 minutes."),
      ).toBeInTheDocument();
    });
  });

  it("falls back to local limiter only when server lockout metadata is absent", async () => {
    for (let index = 0; index < 4; index += 1) {
      authRateLimiter.recordFailedAttempt("locked@example.com");
    }

    mockLogin.mockRejectedValueOnce(new Error("Invalid credentials"));

    render(
      <MemoryRouter>
        <ModernLoginPage />
      </MemoryRouter>,
    );

    await submitLoginForm();

    await waitFor(() => {
      expect(
        screen.getByText("Too many login attempts. Please try again in about 15 minutes."),
      ).toBeInTheDocument();
    });
  });
});

