type FilterTab = "all" | CaseStatus;

const filterTabs: { key: FilterTab; label: string }[] = [
  { key: "all", label: "All" },
  { key: "needs-input", label: "Needs Input" },
  { key: "running", label: "Running" },
  { key: "review", label: "In Review" },
  { key: "paused", label: "Paused" },
  { key: "complete", label: "Complete" },
];

export function Opportunities() {
  const [search, setSearch] = useState("");
  const [activeFilter, setActiveFilter] = useState<FilterTab>("all");
  const [viewMode, setViewMode] = useState<"grid" | "list">("grid");

  const { data: cases, isLoading } = useCasesList();
  const allCases = (cases ?? []).filter((c) => c.status !== "archived");

  const filtered = allCases.filter((c) => {
    const status = deriveStatus(c);
    const matchesFilter = activeFilter === "all" || status === activeFilter;
    const displayName = (c.company_profiles?.company_name ?? c.name).toLowerCase();
    const matchesSearch =
      !search ||
      displayName.includes(search.toLowerCase()) ||
      c.name.toLowerCase().includes(search.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  return (
    <div className="p-6 lg:p-10 max-w-[1200px] mx-auto space-y-5">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black text-zinc-950 tracking-[-0.05em]">Value Cases</h1>
          <p className="text-[13px] text-zinc-400 mt-0.5">
            {isLoading ? (
              <span className="inline-block h-3 w-32 bg-zinc-200 rounded animate-pulse" />
            ) : (
              <>
                {allCases.length} {allCases.length === 1 ? "case" : "cases"}
                {allCases.filter((c) => deriveStatus(c) === "needs-input").length > 0 && (
                  <> &middot; <span className="text-amber-600 font-medium">{allCases.filter((c) => deriveStatus(c) === "needs-input").length} need your input</span></>
                )}
              </>
            )}
          </p>
        </div>
      </div>

      <InlineQuickStart />

      {!isLoading && allCases.length > 0 && <StatBar cases={allCases} />}

      <div className="flex items-center gap-3">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search cases, companies…"
            className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400 transition-colors"
          />
        </div>

        <div className="flex items-center gap-0.5 p-0.5 bg-zinc-100 rounded-xl">
          {filterTabs.map((tab) => {
            const count = tab.key === "all"
              ? allCases.length
              : allCases.filter((c) => deriveStatus(c) === tab.key).length;
            if (count === 0 && tab.key !== "all") return null;
            return (
              <button
                key={tab.key}
                onClick={() => setActiveFilter(tab.key)}
                className={cn(
                  "px-3 py-1.5 rounded-lg text-[12px] font-medium transition-colors flex items-center gap-1.5",
                  activeFilter === tab.key ? "bg-white text-zinc-900 shadow-sm" : "text-zinc-500 hover:text-zinc-700"
                )}
              >
                {tab.label}
                <span className={cn(
                  "text-[10px] font-bold min-w-[18px] h-[18px] flex items-center justify-center rounded-full",
                  activeFilter === tab.key ? "bg-zinc-900 text-white" : "bg-zinc-200 text-zinc-500"
                )}>
                  {count}
                </span>
              </button>
            );
          })}
        </div>

        <div className="flex items-center gap-0.5 p-0.5 bg-zinc-100 rounded-lg ml-auto">
          <button
            onClick={() => setViewMode("grid")}
            className={cn("p-1.5 rounded-md transition-colors", viewMode === "grid" ? "bg-white shadow-sm text-zinc-900" : "text-zinc-400 hover:text-zinc-600")}
          >
            <LayoutGrid className="w-4 h-4" />
          </button>
          <button
            onClick={() => setViewMode("list")}
            className={cn("p-1.5 rounded-md transition-colors", viewMode === "list" ? "bg-white shadow-sm text-zinc-900" : "text-zinc-400 hover:text-zinc-600")}
          >
            <List className="w-4 h-4" />
          </button>
        </div>
      </div>

      {isLoading ? (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
          <CardSkeleton /><CardSkeleton /><CardSkeleton /><CardSkeleton />
        </div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-16">
          <div className="w-12 h-12 bg-zinc-100 rounded-2xl flex items-center justify-center mx-auto mb-3">
            <Search className="w-5 h-5 text-zinc-400" />
          </div>
          <p className="text-[14px] font-medium text-zinc-600">
            {allCases.length === 0 ? "No cases yet" : "No cases match your filters"}
          </p>
          <p className="text-[12px] text-zinc-400 mt-1">
            {allCases.length === 0 ? "Start your first value case above." : "Try adjusting your search or filter."}
          </p>
        </div>
      ) : viewMode === "grid" ? (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
          {filtered.map((c) => <DealCard key={c.id} c={c} />)}
        </div>
      ) : (
        <div className="bg-white border border-zinc-200 rounded-2xl overflow-hidden">
          <div className="grid grid-cols-[minmax(0,1fr)_auto_auto_minmax(0,1fr)_auto] gap-3 px-5 py-2.5 border-b border-zinc-100 bg-zinc-50">
            <span className="text-[10px] font-semibold uppercase tracking-[0.15em] text-zinc-400">Deal</span>
            <span className="text-[10px] font-semibold uppercase tracking-[0.15em] text-zinc-400">Stage / Status</span>
            <span className="hidden md:block text-[10px] font-semibold uppercase tracking-[0.15em] text-zinc-400 w-20">Conf.</span>
            <span className="hidden lg:block text-[10px] font-semibold uppercase tracking-[0.15em] text-zinc-400">Next Action</span>
            <span className="text-[10px] font-semibold uppercase tracking-[0.15em] text-zinc-400 text-right">Value</span>
          </div>
          {filtered.map((c) => <DealRow key={c.id} c={c} />)}
        </div>
      )}
    </div>
  );
}

/**
 * Projects view — lists projects within the current workspace.
 *
 * Uses useProjects + useWorkspace from features/workspace.
 */

import { FolderOpen, Loader2, Plus } from "lucide-react";
import { useState } from "react";

import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { useProjects } from "@/features/workspace/hooks/useProjects";
import { useWorkspace } from "@/features/workspace/hooks/useWorkspace";
import type { ProjectStatus } from "@/features/workspace/types";

export interface ProjectsProps {
  organizationId?: string;
}

const STATUS_COLORS: Record<ProjectStatus, string> = {
  active: "bg-green-100 text-green-800",
  completed: "bg-blue-100 text-blue-800",
  archived: "bg-gray-100 text-gray-600",
};

export function Projects(_props: ProjectsProps) {
  const { workspace, isLoading: wsLoading } = useWorkspace();
  const { projects, isLoading, error, createProject } = useProjects(workspace?.id);
  const [showCreate, setShowCreate] = useState(false);
  const [newName, setNewName] = useState("");
  const [newDesc, setNewDesc] = useState("");

  const handleCreate = async () => {
    if (!newName.trim()) return;
    await createProject({ name: newName.trim(), description: newDesc.trim() || undefined });
    setNewName("");
    setNewDesc("");
    setShowCreate(false);
  };

  if (wsLoading || isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-6">
        <p className="text-destructive">{error}</p>
      </div>
    );
  }

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-semibold">Projects</h1>
        <Button size="sm" onClick={() => setShowCreate(true)}>
          <Plus className="h-4 w-4 mr-1" /> New Project
        </Button>
      </div>

      {showCreate && (
        <Card className="p-4 space-y-3">
          <input
            className="w-full border rounded px-3 py-2 text-sm"
            placeholder="Project name"
            value={newName}
            onChange={(e) => setNewName(e.target.value)}
            autoFocus
          />
          <input
            className="w-full border rounded px-3 py-2 text-sm"
            placeholder="Description (optional)"
            value={newDesc}
            onChange={(e) => setNewDesc(e.target.value)}
          />
          <div className="flex gap-2">
            <Button size="sm" onClick={handleCreate} disabled={!newName.trim()}>
              Create
            </Button>
            <Button size="sm" variant="ghost" onClick={() => setShowCreate(false)}>
              Cancel
            </Button>
          </div>
        </Card>
      )}

      {projects.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-48 text-muted-foreground">
          <FolderOpen className="h-10 w-10 mb-2" />
          <p>No projects yet. Create your first project to get started.</p>
        </div>
      ) : (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {projects.map((project) => (
            <Card key={project.id} className="p-4 hover:shadow-md transition-shadow">
              <div className="flex items-start justify-between">
                <h3 className="font-medium truncate">{project.name}</h3>
                <span
                  className={`text-xs px-2 py-0.5 rounded-full ${STATUS_COLORS[project.status]}`}
                >
                  {project.status}
                </span>
              </div>
              {project.description && (
                <p className="text-sm text-muted-foreground mt-1 line-clamp-2">
                  {project.description}
                </p>
              )}
              <p className="text-xs text-muted-foreground mt-3">
                Created {new Date(project.createdAt).toLocaleDateString()}
              </p>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

/**
 * Quantum View Template (Multi-Persona)
 * VOS-UI-005: Displays different perspectives/analyses from multiple AI personas
 * Features: Persona switching, parallel analysis views, consensus indicators
 */

import { 
  Activity, 
  AlertTriangle, 
  Brain, 
  CheckCircle, 
  Shield,
  TrendingUp,
  UserCheck,
  Users,
} from 'lucide-react';
import React, { useMemo, useState } from 'react';

import AgentBadge from '../components/Agents/AgentBadge';
import ConfidenceIndicator from '../components/Agents/ConfidenceIndicator';

// ============================================================================
// Types
// ============================================================================

export type PersonaType = 'financial' | 'technical' | 'strategic' | 'risk' | 'operational';

export interface PersonaAnalysis {
  id: string;
  persona: PersonaType;
  title: string;
  summary: string;
  confidence: number;
  keyMetrics: Array<{
    label: string;
    value: string | number;
    unit?: string;
    trend?: 'up' | 'down' | 'neutral';
  }>;
  recommendations: string[];
  risks: string[];
  consensus?: boolean;
  aiGenerated?: boolean;
}

export interface QuantumViewProps {
  title?: string;
  subtitle?: string;
  analyses: PersonaAnalysis[];
  showConsensus?: boolean;
  onPersonaSelect?: (persona: PersonaType) => void;
  onAnalysisClick?: (analysis: PersonaAnalysis) => void;
  autoSync?: boolean;
}

// ============================================================================
// Persona Configuration
// ============================================================================

const PERSONA_CONFIG: Record<PersonaType, { icon: React.ElementType; color: string; label: string }> = {
  financial: { icon: TrendingUp, color: 'text-green-600', label: 'Financial Analyst' },
  technical: { icon: Brain, color: 'text-blue-600', label: 'Technical Architect' },
  strategic: { icon: Users, color: 'text-purple-600', label: 'Strategic Advisor' },
  risk: { icon: Shield, color: 'text-red-600', label: 'Risk Analyst' },
  operational: { icon: Activity, color: 'text-orange-600', label: 'Operations Lead' },
};

// ============================================================================
// Components
// ============================================================================

const PersonaCard: React.FC<{
  analysis: PersonaAnalysis;
  selected: boolean;
  onClick: () => void;
  showConsensus?: boolean;
}> = ({ analysis, selected, onClick, showConsensus }) => {
  const config = PERSONA_CONFIG[analysis.persona];
  if (!config) return null;
  const Icon = config.icon;

  return (
    <div
      onClick={onClick}
      className={`
        relative p-4 rounded-xl border cursor-pointer transition-all
        ${selected 
          ? 'bg-primary/5 border-primary shadow-lg shadow-primary/20' 
          : 'bg-card border-border hover:border-primary/50 hover:bg-primary/5'
        }
      `}
      role="button"
      tabIndex={0}
      aria-pressed={selected}
      data-testid={`persona-card-${analysis.persona}`}
    >
      {/* Header */}
      <div className="flex items-start justify-between mb-3">
        <div className="flex items-center gap-3">
          <div className={`p-2 rounded-lg bg-primary/10 ${config.color}`}>
            <Icon className="w-5 h-5" />
          </div>
          <div>
            <h3 className="font-semibold text-foreground">{analysis.title}</h3>
            <p className="text-xs text-muted-foreground">{config.label}</p>
          </div>
        </div>

        {showConsensus && analysis.consensus && (
          <div className="flex items-center gap-1 text-green-600 text-xs font-medium">
            <CheckCircle className="w-3 h-3" />
            Consensus
          </div>
        )}
      </div>

      {/* Summary */}
      <p className="text-sm text-muted-foreground mb-3 line-clamp-2">
        {analysis.summary}
      </p>

      {/* Key Metrics */}
      <div className="flex flex-wrap gap-2 mb-3">
        {(analysis.keyMetrics ?? []).slice(0, 2).map((metric, idx) => (
          <div key={idx} className="px-2 py-1 bg-secondary rounded text-xs">
            <span className="font-medium">{metric.value}</span>
            {metric.unit && <span className="text-muted-foreground ml-1">{metric.unit}</span>}
            {metric.trend && (
              <span className={`ml-1 ${metric.trend === 'up' ? 'text-green-600' : metric.trend === 'down' ? 'text-red-600' : 'text-muted-foreground'}`}>
                {metric.trend === 'up' ? '↑' : metric.trend === 'down' ? '↓' : '→'}
              </span>
            )}
          </div>
        ))}
      </div>

      {/* Confidence */}
      <div className="flex items-center justify-between">
        <ConfidenceIndicator
          value={analysis.confidence}
          confidence={analysis.confidence}
          label="Confidence"
          size="sm"
        />
        {analysis.aiGenerated && (
          <span className="text-[10px] px-1.5 py-0.5 bg-primary/20 text-primary rounded">
            AI
          </span>
        )}
      </div>
    </div>
  );
};

const AnalysisDetail: React.FC<{
  analysis: PersonaAnalysis;
  onBack: () => void;
}> = ({ analysis, onBack }) => {
  const config = PERSONA_CONFIG[analysis.persona];
  if (!config) return null;
  const Icon = config.icon;

  return (
    <div className="space-y-6" data-testid={`analysis-detail-${analysis.persona}`}>
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className={`p-3 rounded-lg bg-primary/10 ${config.color}`}>
            <Icon className="w-6 h-6" />
          </div>
          <div>
            <h2 className="text-xl font-bold text-foreground">{analysis.title}</h2>
            <p className="text-sm text-muted-foreground">{config.label}</p>
          </div>
        </div>
        <button
          onClick={onBack}
          className="px-3 py-1.5 text-sm border border-border rounded hover:bg-secondary"
        >
          Back to Overview
        </button>
      </div>

      {/* Summary & Confidence */}
      <div className="p-4 bg-card border border-border rounded-lg">
        <div className="flex items-start justify-between mb-3">
          <p className="text-foreground">{analysis.summary}</p>
          <ConfidenceIndicator
            value={analysis.confidence}
            confidence={analysis.confidence}
            label="Confidence"
            size="lg"
          />
        </div>
      </div>

      {/* Key Metrics */}
      <div>
        <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider mb-3">
          Key Metrics
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          {(analysis.keyMetrics ?? []).map((metric, idx) => (
            <div key={idx} className="p-3 bg-secondary rounded-lg">
              <div className="text-xs text-muted-foreground mb-1">{metric.label}</div>
              <div className="text-lg font-bold text-foreground">
                {metric.value}
                {metric.unit && <span className="text-muted-foreground ml-1">{metric.unit}</span>}
              </div>
              {metric.trend && (
                <div className={`text-xs mt-1 ${
                  metric.trend === 'up' ? 'text-green-600' : 
                  metric.trend === 'down' ? 'text-red-600' : 'text-muted-foreground'
                }`}>
                  {metric.trend === 'up' ? '↑ Improving' : 
                   metric.trend === 'down' ? '↓ Declining' : '→ Stable'}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Recommendations */}
      <div>
        <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider mb-3">
          Recommendations
        </h3>
        <ul className="space-y-2">
          {(analysis.recommendations ?? []).map((rec, idx) => (
            <li key={idx} className="flex items-start gap-2 text-sm">
              <CheckCircle className="w-4 h-4 text-green-600 mt-0.5 flex-shrink-0" />
              <span className="text-foreground">{rec}</span>
            </li>
          ))}
        </ul>
      </div>

      {/* Risks */}
      {(analysis.risks ?? []).length > 0 && (
        <div>
          <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider mb-3">
            Risks & Considerations
          </h3>
          <ul className="space-y-2">
            {(analysis.risks ?? []).map((risk, idx) => (
              <li key={idx} className="flex items-start gap-2 text-sm">
                <AlertTriangle className="w-4 h-4 text-amber-600 mt-0.5 flex-shrink-0" />
                <span className="text-foreground">{risk}</span>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
};

const ConsensusView: React.FC<{
  analyses: PersonaAnalysis[];
}> = ({ analyses }) => {
  const consensusAnalyses = analyses.filter(a => a.consensus);

  if (consensusAnalyses.length === 0) {
    return (
      <div className="p-6 text-center text-muted-foreground">
        <Users className="w-12 h-12 mx-auto mb-3 opacity-50" />
        <p>No consensus reached among personas</p>
      </div>
    );
  }

  // Calculate consensus metrics
  const avgConfidence = consensusAnalyses.reduce((sum, a) => sum + a.confidence, 0) / consensusAnalyses.length;

  // Find common recommendations
  const allRecommendations = consensusAnalyses.flatMap(a => a.recommendations ?? []);
  const recommendationCounts = allRecommendations.reduce((acc, rec) => {
    acc[rec] = (acc[rec] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const commonRecommendations = Object.entries(recommendationCounts)
    .filter(([_, count]) => count >= 2)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3);

  return (
    <div className="space-y-4" data-testid="consensus-view">
      {/* Header */}
      <div className="flex items-center justify-between p-4 bg-primary/5 border border-primary/20 rounded-lg">
        <div className="flex items-center gap-2">
          <UserCheck className="w-5 h-5 text-primary" />
          <h3 className="font-semibold text-primary">Consensus View</h3>
        </div>
        <div className="text-sm text-muted-foreground">
          {consensusAnalyses.length} of {analyses.length} personas agree
        </div>
      </div>

      {/* Agreement Score */}
      <div className="p-4 bg-card border border-border rounded-lg">
        <div className="flex justify-between items-center mb-2">
          <span className="text-sm text-muted-foreground">Overall Agreement</span>
          <span className="text-2xl font-bold text-primary">{Math.round(avgConfidence)}%</span>
        </div>
        <div className="w-full bg-secondary rounded-full h-2">
          <div 
            className="bg-primary h-2 rounded-full transition-all"
            style={{ width: `${avgConfidence}%` }}
          />
        </div>
      </div>

      {/* Common Recommendations */}
      {commonRecommendations.length > 0 && (
        <div className="p-4 bg-card border border-border rounded-lg">
          <h4 className="text-sm font-semibold mb-3">Top Consensus Recommendations</h4>
          <ul className="space-y-2">
            {commonRecommendations.map(([rec, count], idx) => (
              <li key={idx} className="flex items-center gap-2 text-sm">
                <div className="w-5 h-5 rounded-full bg-primary/20 text-primary flex items-center justify-center text-xs font-bold">
                  {count}
                </div>
                <span className="text-foreground">{rec}</span>
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Persona Agreement List */}
      <div className="space-y-2">
        {consensusAnalyses.map(analysis => {
          const config = PERSONA_CONFIG[analysis.persona];
          const Icon = config.icon;
          return (
            <div key={analysis.id} className="flex items-center justify-between p-3 bg-secondary rounded-lg">
              <div className="flex items-center gap-2">
                <Icon className={`w-4 h-4 ${config.color}`} />
                <span className="text-sm font-medium">{analysis.title}</span>
              </div>
              <span className="text-xs text-green-600 font-medium">Agrees</span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// ============================================================================
// Main Component
// ============================================================================

export const QuantumView: React.FC<QuantumViewProps> = ({
  title = 'Quantum View',
  subtitle = 'Multi-Persona Analysis',
  analyses,
  showConsensus = true,
  onPersonaSelect,
  onAnalysisClick,
  autoSync = false,
}) => {
  const [selectedPersona, setSelectedPersona] = useState<PersonaType | null>(null);
  const [viewMode, setViewMode] = useState<'overview' | 'detail' | 'consensus'>('overview');

  // Derive selected analysis
  const selectedAnalysis = useMemo(() => {
    if (!selectedPersona) return null;
    return analyses.find(a => a.persona === selectedPersona) || null;
  }, [analyses, selectedPersona]);

  // Calculate consensus status
  const consensusCount = useMemo(() => {
    return analyses.filter(a => a.consensus).length;
  }, [analyses]);

  // Handle persona selection
  const handlePersonaSelect = (persona: PersonaType) => {
    setSelectedPersona(persona);
    setViewMode('detail');
    onPersonaSelect?.(persona);

    const analysis = analyses.find(a => a.persona === persona);
    if (analysis) {
      onAnalysisClick?.(analysis);
    }
  };

  // Handle consensus view
  const handleConsensusView = () => {
    setViewMode('consensus');
  };

  // Handle back to overview
  const handleBack = () => {
    setViewMode('overview');
    setSelectedPersona(null);
  };

  // Auto-sync effect
  React.useEffect(() => {
    if (autoSync && analyses.length > 0) {
      // Auto-select first persona with highest confidence
      const highestConfidence = analyses.reduce((max, a) => 
        a.confidence > max.confidence ? a : max
      , analyses[0]);

      setSelectedPersona(highestConfidence.persona);
      setViewMode('detail');
    }
  }, [autoSync, analyses]);

  if (analyses.length === 0) {
    return (
      <div className="p-8 text-center text-muted-foreground">
        <Users className="w-16 h-16 mx-auto mb-4 opacity-50" />
        <p>No persona analyses available</p>
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col overflow-hidden bg-background">
      {/* Header */}
      <div className="h-14 border-b border-border px-6 flex items-center justify-between bg-card">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <Brain className="w-5 h-5 text-primary" />
            <h1 className="text-lg font-semibold text-foreground">{title}</h1>
          </div>
          {subtitle && (
            <span className="text-sm text-muted-foreground">{subtitle}</span>
          )}
        </div>

        <div className="flex items-center gap-2">
          {showConsensus && (
            <button
              onClick={handleConsensusView}
              className={`
                px-3 py-1.5 text-sm rounded border transition-all
                ${viewMode === 'consensus'
                  ? 'bg-primary text-primary-foreground border-primary'
                  : 'bg-card border-border hover:bg-secondary'
                }
              `}
            >
              <UserCheck className="w-4 h-4 inline mr-1" />
              Consensus {consensusCount > 0 && `(${consensusCount})`}
            </button>
          )}
          <AgentBadge agentId="multi-persona" size="sm" />
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-auto p-6">
        {viewMode === 'overview' && (
          <div className="space-y-6">
            {/* Persona Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {analyses.map(analysis => (
                <PersonaCard
                  key={analysis.id}
                  analysis={analysis}
                  selected={selectedPersona === analysis.persona}
                  onClick={() => handlePersonaSelect(analysis.persona)}
                  showConsensus={showConsensus}
                />
              ))}
            </div>

            {/* Quick Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="p-4 bg-card border border-border rounded-lg">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm text-muted-foreground">Total Personas</span>
                  <Users className="w-4 h-4 text-muted-foreground" />
                </div>
                <div className="text-2xl font-bold text-foreground">{analyses.length}</div>
              </div>

              <div className="p-4 bg-card border border-border rounded-lg">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm text-muted-foreground">Consensus</span>
                  <UserCheck className="w-4 h-4 text-green-600" />
                </div>
                <div className="text-2xl font-bold text-green-600">{consensusCount}</div>
              </div>

              <div className="p-4 bg-card border border-border rounded-lg">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm text-muted-foreground">Avg Confidence</span>
                  <Activity className="w-4 h-4 text-blue-600" />
                </div>
                <div className="text-2xl font-bold text-blue-600">
                  {Math.round(analyses.reduce((sum, a) => sum + a.confidence, 0) / analyses.length)}%
                </div>
              </div>
            </div>
          </div>
        )}

        {viewMode === 'detail' && selectedAnalysis && (
          <AnalysisDetail
            analysis={selectedAnalysis}
            onBack={handleBack}
          />
        )}

        {viewMode === 'consensus' && (
          <ConsensusView analyses={analyses} />
        )}
      </div>
    </div>
  );
};

export default QuantumView;

/**
 * RealizationTracker
 *
 * Page view for post-sale realization: KPI targets, checkpoint timeline, handoff notes.
 * Reference: openspec/changes/frontend-v1-surfaces/tasks.md §5.5
 */

import { AlertCircle, Calendar, FileText, Target } from "lucide-react";
import React from "react";
import { useParams } from "react-router-dom";

import { CanvasHost, SDUIWidget } from "@/components/canvas/CanvasHost";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Skeleton } from "@/components/ui/skeleton";
import { useBaseline, useCheckpoints } from "@/hooks/useRealization";

export function RealizationTracker() {
  const { caseId } = useParams<{ caseId: string }>();

  const { data: baseline, isLoading: baselineLoading, error: baselineError } = useBaseline(caseId);
  const { data: checkpoints, isLoading: checkpointsLoading, error: checkpointsError } = useCheckpoints(caseId);

  const isLoading = baselineLoading || checkpointsLoading;
  const error = baselineError || checkpointsError;

  if (isLoading) {
    return (
      <div className="p-6 space-y-4">
        <Skeleton className="h-8 w-1/3" />
        <Skeleton className="h-32 w-full" />
        <Skeleton className="h-48 w-full" />
      </div>
    );
  }

  if (error) {
    return (
      <Alert variant="destructive" className="m-6">
        <AlertCircle className="h-4 w-4" />
        <AlertTitle>Failed to load realization data</AlertTitle>
        <AlertDescription>{error?.message || "Unknown error occurred"}</AlertDescription>
      </Alert>
    );
  }

  const kpiWidget: SDUIWidget = {
    id: "kpi-targets",
    componentType: "kpi-target-card",
    props: { targets: baseline?.kpiTargets ?? [] },
  };

  const checkpointWidget: SDUIWidget = {
    id: "checkpoint-timeline",
    componentType: "checkpoint-timeline",
    props: {
      checkpoints: checkpoints ?? [],
      metricName: "Value Realization",
      unit: "$",
    },
  };

  return (
    <div className="h-full flex flex-col">
      <div className="px-6 py-4 border-b bg-card">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-xl font-semibold">Realization Tracker</h1>
            <p className="text-sm text-muted-foreground mt-1">
              Track post-sale value delivery and outcomes
            </p>
          </div>
          {baseline && (
            <div className="text-right">
              <p className="text-sm text-muted-foreground">Baseline Scenario</p>
              <p className="font-semibold">{baseline.scenarioName}</p>
              <p className="text-xs text-muted-foreground">
                Approved {baseline.approvalDate ? new Date(baseline.approvalDate).toLocaleDateString() : "N/A"}
              </p>
            </div>
          )}
        </div>
      </div>

      <div className="flex-1 p-6 overflow-y-auto">
        <div className="max-w-6xl mx-auto space-y-6">
          {/* KPI Targets */}
          <div className="rounded-xl border bg-card p-6">
            <div className="flex items-center gap-3 mb-4">
              <div className="p-2 bg-primary/10 rounded-lg">
                <Target className="w-5 h-5 text-primary" />
              </div>
              <h2 className="font-semibold text-lg">KPI Targets</h2>
            </div>
            <CanvasHost widgets={[kpiWidget]} />
          </div>

          {/* Checkpoint Timeline */}
          <div className="rounded-xl border bg-card p-6">
            <div className="flex items-center gap-3 mb-4">
              <div className="p-2 bg-primary/10 rounded-lg">
                <Calendar className="w-5 h-5 text-primary" />
              </div>
              <h2 className="font-semibold text-lg">Checkpoint Timeline</h2>
            </div>
            <CanvasHost widgets={[checkpointWidget]} />
          </div>

          {/* Assumptions (read-only) */}
          {baseline?.assumptions && baseline.assumptions.length > 0 && (
            <div className="rounded-xl border bg-card p-6">
              <div className="flex items-center gap-3 mb-4">
                <div className="p-2 bg-primary/10 rounded-lg">
                  <FileText className="w-5 h-5 text-primary" />
                </div>
                <h2 className="font-semibold text-lg">Baseline Assumptions</h2>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {baseline.assumptions.map((assumption) => (
                  <div key={assumption.id} className="p-4 border rounded-lg bg-muted/30">
                    <p className="font-medium text-sm">{assumption.name}</p>
                    <p className="text-lg font-semibold mt-1">
                      {assumption.value} {assumption.unit}
                    </p>
                    <p className="text-xs text-muted-foreground mt-1">
                      Source: {assumption.source}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Handoff Notes */}
          {baseline?.handoffNotes && (
            <div className="rounded-xl border bg-card p-6">
              <div className="flex items-center gap-3 mb-4">
                <div className="p-2 bg-primary/10 rounded-lg">
                  <FileText className="w-5 h-5 text-primary" />
                </div>
                <h2 className="font-semibold text-lg">Handoff Notes</h2>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="p-4 border rounded-lg">
                  <h3 className="font-medium text-sm text-muted-foreground mb-2">Deal Context</h3>
                  <p className="text-sm">{baseline.handoffNotes.dealContext || "N/A"}</p>
                </div>
                <div className="p-4 border rounded-lg">
                  <h3 className="font-medium text-sm text-muted-foreground mb-2">
                    Buyer Priorities
                  </h3>
                  <p className="text-sm">{baseline.handoffNotes.buyerPriorities || "N/A"}</p>
                </div>
                <div className="p-4 border rounded-lg">
                  <h3 className="font-medium text-sm text-muted-foreground mb-2">
                    Implementation Assumptions
                  </h3>
                  <p className="text-sm">
                    {baseline.handoffNotes.implementationAssumptions || "N/A"}
                  </p>
                </div>
                <div className="p-4 border rounded-lg">
                  <h3 className="font-medium text-sm text-muted-foreground mb-2">Key Risks</h3>
                  <p className="text-sm">{baseline.handoffNotes.keyRisks || "N/A"}</p>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default RealizationTracker;

