/**
 * Billing Dashboard
 * Main billing page with usage, plans, and invoices
 */

import { AlertCircle, CreditCard, FileText, TrendingUp } from "lucide-react";
import React, { useEffect, useState } from "react";

import { logger } from "@/lib/logger";
import { apiClient } from "../../api/client/unified-api-client";
import { InvoiceList } from "../../components/Billing/InvoiceList";
import { PlanSelector } from "../../components/Billing/PlanSelector";
import { UsageMeter } from "../../components/Billing/UsageMeter";
import { BillingMetric, PlanTier } from "../../config/billing";
import { Invoice, Subscription, UsageSummary } from "../../types/billing";

export const BillingDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<"usage" | "plans" | "invoices">(
    "usage"
  );
  const [subscription, setSubscription] = useState<Subscription | null>(null);
  const [usage, setUsage] = useState<UsageSummary | null>(null);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchBillingData();
  }, []);

  const fetchBillingData = async () => {
    setLoading(true);
    try {
      const [subRes, usageRes, invoicesRes] = await Promise.allSettled([
        apiClient.get<Subscription>("/api/billing/subscription"),
        apiClient.get<UsageSummary>("/api/billing/usage"),
        apiClient.get<{ invoices?: Invoice[] }>("/api/billing/invoices"),
      ]);
      if (subRes.status === "fulfilled") setSubscription(subRes.value.data ?? null);
      if (usageRes.status === "fulfilled") setUsage(usageRes.value.data ?? null);
      if (invoicesRes.status === "fulfilled") setInvoices(invoicesRes.value.data?.invoices ?? []);
    } catch (error) {
      logger.error("Failed to fetch billing data:", { error });
    } finally {
      setLoading(false);
    }
  };

  const handlePlanChange = async (newPlan: PlanTier) => {
    const res = await apiClient.put("/api/billing/subscription", { planTier: newPlan });
    if (!res.success) {
      logger.error("Failed to update plan:", { message: res.error?.message });
      setError("Failed to update plan");
      return;
    }
    await fetchBillingData();
    setActiveTab("usage");
  };

  const handleDownloadInvoice = async (invoiceId: string) => {
    const res = await apiClient.get<{ pdfUrl: string }>(`/api/billing/invoices/${invoiceId}/pdf`);
    if (!res.success) {
      logger.error("Failed to download invoice:", { message: res.error?.message });
      return;
    }
    if (res.data?.pdfUrl) window.open(res.data.pdfUrl, "_blank", "noopener,noreferrer");
  };

  const handleViewInvoice = (invoiceId: string) => {
    const invoice = invoices.find((inv) => inv.id === invoiceId);
    if (invoice?.hosted_invoice_url) {
      window.open(invoice.hosted_invoice_url, "_blank", "noopener,noreferrer");
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900">Billing & Usage</h1>
        <p className="text-gray-600 mt-2">
          Manage your subscription, monitor usage, and view invoices
        </p>
      </div>

      {error && (
        <div className="mb-4 p-4 bg-red-50 border border-red-200 rounded-lg">
          <div className="flex items-center">
            <AlertCircle className="h-5 w-5 text-red-500 mr-2" />
            <span className="text-red-700">{error}</span>
          </div>
        </div>
      )}

      {/* Current Plan Card */}
      {subscription && (
        <div className="bg-gradient-to-r from-blue-500 to-purple-600 rounded-lg p-6 text-white mb-8">
          <div className="flex items-center justify-between">
            <div>
              <div className="text-sm opacity-90">Current Plan</div>
              <div className="text-3xl font-bold mt-1">
                {subscription.plan_tier.charAt(0).toUpperCase() +
                  subscription.plan_tier.slice(1)}
              </div>
              <div className="text-sm opacity-90 mt-2">
                ${subscription.amount}/month • {subscription.status}
              </div>
            </div>
            <CreditCard className="w-16 h-16 opacity-50" />
          </div>
        </div>
      )}

      {/* Tabs */}
      <div className="border-b border-gray-200 mb-6">
        <nav className="flex space-x-8">
          <button
            onClick={() => setActiveTab("usage")}
            className={`
              py-4 px-1 border-b-2 font-medium text-sm transition-colors
              ${activeTab === "usage"
                ? "border-blue-500 text-blue-600"
                : "border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300"
              }
            `}
          >
            <div className="flex items-center space-x-2">
              <TrendingUp className="w-5 h-5" />
              <span>Usage</span>
            </div>
          </button>

          <button
            onClick={() => setActiveTab("plans")}
            className={`
              py-4 px-1 border-b-2 font-medium text-sm transition-colors
              ${activeTab === "plans"
                ? "border-blue-500 text-blue-600"
                : "border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300"
              }
            `}
          >
            <div className="flex items-center space-x-2">
              <CreditCard className="w-5 h-5" />
              <span>Plans</span>
            </div>
          </button>

          <button
            onClick={() => setActiveTab("invoices")}
            className={`
              py-4 px-1 border-b-2 font-medium text-sm transition-colors
              ${activeTab === "invoices"
                ? "border-blue-500 text-blue-600"
                : "border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300"
              }
            `}
          >
            <div className="flex items-center space-x-2">
              <FileText className="w-5 h-5" />
              <span>Invoices</span>
            </div>
          </button>
        </nav>
      </div>

      {/* Tab Content */}
      <div className="mt-6">
        {activeTab === "usage" && (
          <div>
            {loading ? (
              <div className="text-center py-12">Loading usage data...</div>
            ) : usage ? (
              <div className="space-y-6">
                {/* Usage Meters */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {Object.entries(usage.usage).map(([metric, amount]) => (
                    <div
                      key={metric}
                      className="bg-white p-6 rounded-lg shadow"
                    >
                      <UsageMeter
                        metric={metric as BillingMetric}
                        usage={amount}
                        quota={usage.quotas[metric as BillingMetric]}
                      />
                    </div>
                  ))}
                </div>

                {/* Upcoming Invoice Preview */}
                <div className="bg-white p-6 rounded-lg shadow">
                  <h3 className="text-lg font-semibold mb-4">
                    Projected Invoice
                  </h3>
                  <div className="flex justify-between items-center">
                    <span className="text-gray-600">Base Plan</span>
                    <span className="font-semibold">${usage.costs.base}</span>
                  </div>
                  <div className="flex justify-between items-center mt-2">
                    <span className="text-gray-600">Overage Charges</span>
                    <span className="font-semibold">
                      $
                      {Object.values(usage.costs.overage)
                        .reduce((sum, cost) => sum + cost, 0)
                        .toFixed(2)}
                    </span>
                  </div>
                  <div className="flex justify-between items-center mt-4 pt-4 border-t">
                    <span className="text-lg font-bold">Total</span>
                    <span className="text-2xl font-bold text-blue-600">
                      ${usage.costs.total.toFixed(2)}
                    </span>
                  </div>
                </div>

                {/* Usage Alerts */}
                {Object.entries(usage.percentages).some(
                  ([_, pct]) => pct >= 80
                ) && (
                    <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
                      <div className="flex items-start">
                        <AlertCircle className="w-5 h-5 text-yellow-600 mr-3 mt-0.5" />
                        <div>
                          <h4 className="font-semibold text-yellow-900">
                            Usage Alert
                          </h4>
                          <p className="text-sm text-yellow-800 mt-1">
                            You're approaching your quota limits on some metrics.
                            Consider upgrading your plan.
                          </p>
                        </div>
                      </div>
                    </div>
                  )}
              </div>
            ) : (
              <div className="text-center py-12 text-gray-600">
                No usage data available
              </div>
            )}
          </div>
        )}

        {activeTab === "plans" && (
          <div>
            <PlanSelector
              currentPlan={subscription?.plan_tier}
              onSelectPlan={handlePlanChange}
              loading={loading}
            />
          </div>
        )}

        {activeTab === "invoices" && (
          <div>
            <InvoiceList
              invoices={invoices}
              loading={loading}
              onDownload={handleDownloadInvoice}
              onView={handleViewInvoice}
            />
          </div>
        )}
      </div>
    </div>
  );
};

/**
 * Enhanced Billing Dashboard
 * Phase 3: End-User Experience & System Observability
 * 
 * Features:
 * - Color-coded usage metrics (>75% yellow, >90% red)
 * - Real-time usage monitoring
 * - Async feedback for all operations
 * - Comprehensive error handling
 */

import { Calendar, CreditCard, Download, TrendingUp } from 'lucide-react';
import React from 'react';

import { apiClient } from '../../api/client/unified-api-client';
import {
  UsageMetricsGrid,
  UsageSummaryBanner,
  useUsageMetrics,
} from '../../components/Billing/UsageMetrics';
import {
  AsyncFeedbackBanner,
  SettingsErrorBoundary,
  useAsyncState,
} from '../../components/Settings/SettingsAsyncFeedback';
import { FullPageLoading } from '../../components/Settings/SettingsLoadingState';
import { PlanConfig, PLANS, PlanTier } from '../../config/billing';
import { Subscription } from '../../types/billing';

interface BillingPlan {
  name: string;
  price: number;
  billingCycle: 'monthly' | 'annual';
  features: string[];
  limits: {
    users: number;
    storage: number;
    apiCalls: number;
  };
}

interface EnhancedBillingDashboardProps {
  organizationId: string;
}

export const EnhancedBillingDashboard: React.FC<EnhancedBillingDashboardProps> = ({
  organizationId,
}) => {
  const [currentSubscription, setCurrentSubscription] = React.useState<Subscription | null>(null);
  const [subscriptionLoading, setSubscriptionLoading] = React.useState(true);
  const [subscriptionError, setSubscriptionError] = React.useState<Error | null>(null);

  // Fetch usage metrics with color-coded warnings
  const { metrics, loading: usageLoading, error: usageError, hasWarnings, hasCritical } = useUsageMetrics(organizationId);

  // Async state for plan changes
  const { state: upgradeState, execute: executeUpgrade, reset: resetUpgrade } = useAsyncState();

  // Fetch subscription details on mount
  React.useEffect(() => {
    const fetchSubscription = async () => {
      setSubscriptionLoading(true);
      const res = await apiClient.get<Subscription>('/api/billing/subscription');
      if (res.success) {
        setCurrentSubscription(res.data ?? null);
      } else {
        const msg = res.error?.message ?? '';
        // 404 means no subscription yet — default to free tier
        if (msg.includes('404') || msg.includes('Not Found')) {
          setCurrentSubscription({ plan_tier: 'free' } as unknown as Subscription);
        } else {
          setSubscriptionError(new Error(msg || 'Failed to load subscription'));
        }
      }
      setSubscriptionLoading(false);
    };

    fetchSubscription();
  }, [organizationId]);

  // Derive current plan from subscription
  const planConfig: PlanConfig = React.useMemo(() => {
    const tier: PlanTier = currentSubscription?.plan_tier || 'free';
    return PLANS[tier];
  }, [currentSubscription]);

  const currentPlan: BillingPlan = {
    name: planConfig.name,
    price: planConfig.price,
    billingCycle: planConfig.billingPeriod === 'yearly' ? 'annual' : 'monthly',
    features: planConfig.features,
    limits: {
      users: planConfig.quotas.user_seats,
      storage: planConfig.quotas.storage_gb,
      apiCalls: planConfig.quotas.api_calls,
    },
  };

  const DEFAULT_DAYS_UNTIL_BILLING = 30;
  const MS_PER_DAY = 86400000;

  const nextBillingDate = currentSubscription?.current_period_end
    ? new Date(currentSubscription.current_period_end)
    : new Date(Date.now() + DEFAULT_DAYS_UNTIL_BILLING * MS_PER_DAY); // Default to 30 days from now

  // Handle plan upgrade
  const handleUpgrade = async () => {
    await executeUpgrade(async () => {
      // Determine next plan tier
      const currentTier = currentSubscription?.plan_tier || 'free';
      let nextTier: PlanTier;

      if (currentTier === 'free') {
        nextTier = 'standard';
      } else if (currentTier === 'standard') {
        nextTier = 'enterprise';
      } else {
        // Already at top tier or unknown
        throw new Error('You are already on the highest plan. Contact sales for custom needs.');
      }

      const putRes = await apiClient.put('/api/billing/subscription', { planTier: nextTier });
      if (!putRes.success) throw new Error(putRes.error?.message ?? 'Failed to upgrade plan');

      // Refresh subscription data
      const subRes = await apiClient.get<Subscription>('/api/billing/subscription');
      if (!subRes.success) throw new Error(subRes.error?.message ?? 'Failed to reload subscription');
      setCurrentSubscription(subRes.data ?? null);
    });
  };

  const loading = usageLoading || subscriptionLoading;
  const error = usageError || subscriptionError;

  // Loading state
  if (loading) {
    return <FullPageLoading message="Loading billing information..." />;
  }

  // Error state
  if (error) {
    return (
      <div className="p-6">
        <AsyncFeedbackBanner
          state="error"
          errorMessage={`Failed to load billing information: ${error.message}`}
        />
      </div>
    );
  }

  return (
    <SettingsErrorBoundary>
      <div className="space-y-6">
        {/* Page Header */}
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Billing & Usage</h2>
          <p className="text-gray-600 mt-1">
            Manage your subscription and monitor usage
          </p>
        </div>

        {/* Upgrade Feedback */}
        <AsyncFeedbackBanner
          state={upgradeState}
          successMessage="Plan upgraded successfully!"
          errorMessage="Failed to upgrade plan. Please try again."
          onDismiss={resetUpgrade}
        />

        {/* Usage Summary Banner (shows if warnings/critical) */}
        <UsageSummaryBanner metrics={metrics} />

        {/* Current Plan Card */}
        <div className="bg-white border border-gray-200 rounded-lg p-6">
          <div className="flex items-start justify-between mb-4">
            <div>
              <h3 className="text-lg font-semibold text-gray-900">Current Plan</h3>
              <p className="text-sm text-gray-600 mt-1">
                {currentPlan.name} - ${currentPlan.price}/{currentPlan.billingCycle === 'monthly' ? 'mo' : 'yr'}
              </p>
            </div>
            <button
              onClick={handleUpgrade}
              disabled={upgradeState === 'loading'}
              className={`
                px-4 py-2 rounded-lg font-medium transition-colors
                ${
                  hasCritical
                    ? 'bg-red-600 text-white hover:bg-red-700'
                    : hasWarnings
                    ? 'bg-yellow-600 text-white hover:bg-yellow-700'
                    : 'bg-blue-600 text-white hover:bg-blue-700'
                }
                disabled:opacity-50 disabled:cursor-not-allowed
              `}
            >
              {upgradeState === 'loading' ? 'Upgrading...' : 'Upgrade Plan'}
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Features */}
            <div>
              <h4 className="font-medium text-gray-900 mb-2">Included Features</h4>
              <ul className="space-y-1">
                {currentPlan.features.map((feature, index) => (
                  <li key={index} className="text-sm text-gray-600 flex items-center">
                    <span className="text-green-600 mr-2">✓</span>
                    {feature}
                  </li>
                ))}
              </ul>
            </div>

            {/* Billing Info */}
            <div className="space-y-3">
              <div className="flex items-center text-sm">
                <Calendar className="h-4 w-4 text-gray-400 mr-2" />
                <span className="text-gray-600">
                  Next billing date:{' '}
                  <span className="font-medium text-gray-900">
                    {nextBillingDate.toLocaleDateString()}
                  </span>
                </span>
              </div>
              <div className="flex items-center text-sm">
                <CreditCard className="h-4 w-4 text-gray-400 mr-2" />
                <span className="text-gray-600">
                  Payment method:{' '}
                  <span className="font-medium text-gray-900">•••• 4242</span>
                </span>
              </div>
              <button className="text-sm text-blue-600 hover:text-blue-700 font-medium">
                Update payment method →
              </button>
            </div>
          </div>
        </div>

        {/* Usage Metrics with Color-Coded Warnings */}
        <div>
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-gray-900">Usage This Month</h3>
            <button className="text-sm text-blue-600 hover:text-blue-700 font-medium flex items-center">
              <TrendingUp className="h-4 w-4 mr-1" />
              View detailed analytics
            </button>
          </div>
          <UsageMetricsGrid metrics={metrics} />
        </div>

        {/* Billing History */}
        <div className="bg-white border border-gray-200 rounded-lg p-6">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-gray-900">Billing History</h3>
            <button className="text-sm text-blue-600 hover:text-blue-700 font-medium flex items-center">
              <Download className="h-4 w-4 mr-1" />
              Download all invoices
            </button>
          </div>

          <div className="space-y-3">
            {[
              { date: '2026-01-01', amount: 99, status: 'paid' },
              { date: '2025-12-01', amount: 99, status: 'paid' },
              { date: '2025-11-01', amount: 99, status: 'paid' },
            ].map((invoice, index) => (
              <div
                key={index}
                className="flex items-center justify-between py-3 border-b border-gray-100 last:border-0"
              >
                <div className="flex items-center space-x-4">
                  <div className="text-sm">
                    <p className="font-medium text-gray-900">
                      {new Date(invoice.date).toLocaleDateString('en-US', {
                        month: 'long',
                        year: 'numeric',
                      })}
                    </p>
                    <p className="text-gray-600">${invoice.amount}.00</p>
                  </div>
                </div>
                <div className="flex items-center space-x-3">
                  <span className="px-2 py-1 text-xs font-medium text-green-700 bg-green-100 rounded">
                    {invoice.status.toUpperCase()}
                  </span>
                  <button className="text-sm text-blue-600 hover:text-blue-700">
                    Download
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Usage Alerts Info */}
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
          <h4 className="font-medium text-blue-900 mb-2">Usage Alerts</h4>
          <p className="text-sm text-blue-800">
            You'll receive email notifications when your usage reaches:
          </p>
          <ul className="text-sm text-blue-800 mt-2 space-y-1">
            <li>• <strong>75%</strong> of your plan limits (warning)</li>
            <li>• <strong>90%</strong> of your plan limits (critical)</li>
            <li>• <strong>100%</strong> of your plan limits (limit exceeded)</li>
          </ul>
        </div>
      </div>
    </SettingsErrorBoundary>
  );
};

import { Building2, Loader2, Palette, Upload, X } from "lucide-react";
import React, { useEffect, useRef, useState } from "react";

import { SettingsSection } from "../../components/settings";
import {
  applyBrandTheme,
  VALYNT_BRAND_PRIMARY,
  VALYNT_BRAND_SECONDARY,
} from "../../styles/brandTheme";

import { ValidatedInput } from "@/components/ui/validated-input";
import type { CustomBrandingConfig } from "@/config/settingsMatrix";

interface OrganizationGeneralProps {
  initialBranding?: CustomBrandingConfig;
  initialOrganizationName?: string;
  initialDomain?: string;
}

const BRANDING_PREVIEW_TEXT_COLOR = "#f8fafc";

export const OrganizationGeneral: React.FC<OrganizationGeneralProps> = ({
  initialBranding,
  initialOrganizationName = "Acme Corporation",
  initialDomain = "acme.com",
}) => {
  const [orgName, setOrgName] = useState(initialOrganizationName);
  const [domain, setDomain] = useState(initialDomain);
  const [industry, setIndustry] = useState("technology");
  const [orgSize, setOrgSize] = useState("51-200");
  const [primaryColor, _setPrimaryColor] = useState(
    initialBranding?.primaryColor ?? VALYNT_BRAND_PRIMARY
  );
  const [secondaryColor, _setSecondaryColor] = useState(
    initialBranding?.secondaryColor ?? VALYNT_BRAND_SECONDARY
  );
  const [logo, setLogo] = useState<string | null>(initialBranding?.logoUrl ?? null);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [saving, setSaving] = useState(false);
  const [isDirty, setIsDirty] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const validateOrgName = (name: string): string | null => {
    if (!name.trim()) return "Organization name is required";
    if (name.length < 2) return "Name must be at least 2 characters";
    return null;
  };

  const validateDomain = (domain: string): string | null => {
    if (!domain.trim()) return "Domain is required";
    const domainRegex = /^[a-zA-Z0-9][a-zA-Z0-9-]{0,61}[a-zA-Z0-9]?\.[a-zA-Z]{2,}$/;
    if (!domainRegex.test(domain)) return "Invalid domain format";
    return null;
  };

  const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith("image/")) {
      setErrors((prev) => ({ ...prev, logo: "Please upload an image file" }));
      return;
    }

    if (file.size > 5 * 1024 * 1024) {
      setErrors((prev) => ({ ...prev, logo: "Image must be smaller than 5MB" }));
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setLogo(reader.result as string);
      setIsDirty(true);
      setErrors((prev) => ({ ...prev, logo: "" }));
    };
    reader.readAsDataURL(file);
  };

  const handleSave = async () => {
    const nameError = validateOrgName(orgName);
    const domainError = validateDomain(domain);

    if (nameError || domainError) {
      setErrors({
        orgName: nameError || "",
        domain: domainError || "",
      });
      return;
    }

    setSaving(true);
    try {
      await new Promise((resolve) => setTimeout(resolve, 1500));
      applyBrandTheme({ primary: primaryColor, secondary: secondaryColor });
      setIsDirty(false);
    } finally {
      setSaving(false);
    }
  };

  useEffect(() => {
    // Only apply theme on mount to set initial defaults
    applyBrandTheme({ primary: primaryColor, secondary: secondaryColor });
    // Intentionally run once on mount only - subsequent theme changes
    // are applied via handleSave to avoid preview flickering
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const brandingPreviewEnabled = Boolean(
    initialBranding?.logoUrl && initialBranding.primaryColor && initialBranding.secondaryColor
  );

  const brandingPreviewStyle: React.CSSProperties = {
    background: `linear-gradient(135deg, ${primaryColor} 0%, ${secondaryColor} 100%)`,
    color: BRANDING_PREVIEW_TEXT_COLOR,
  };

  return (
    <div className="space-y-6">
      <SettingsSection
        title="Organization Identity"
        description="Manage your organization's basic information and branding"
      >
        <div className="space-y-6">
          <div className="flex items-start space-x-6">
            <div>
              <div className="relative group">
                {logo ? (
                  <img
                    src={logo}
                    alt="Organization logo"
                    className="w-24 h-24 rounded-lg object-cover border-2 border-border"
                  />
                ) : (
                  <div className="w-24 h-24 bg-card rounded-lg flex items-center justify-center border-2 border-border">
                    <Building2 className="h-12 w-12 text-primary" />
                  </div>
                )}
                {logo && (
                  <button
                    onClick={() => {
                      setLogo(null);
                      setIsDirty(true);
                    }}
                    className="absolute -top-2 -right-2 p-1.5 bg-error text-error-foreground rounded-full hover:bg-error/80 transition-colors"
                  >
                    <X className="h-4 w-4" />
                  </button>
                )}
              </div>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleLogoChange}
                className="hidden"
              />
              <button
                onClick={() => fileInputRef.current?.click()}
