import {
  AlertCircle, Check, Clock, Globe, Key, Lock, Plus, Shield, Trash2, Users
} from 'lucide-react';
import React, { useEffect, useState } from 'react';
import { SettingsSection } from '../../components/settings';
/* eslint-enable import/order */

interface AllowedDomain {
  id: string;
  domain: string;
  createdAt: string;
}

interface AuthPolicy {
  id: string;
  ssoEnforced: boolean;
  mfaRequired: boolean;
  passwordMinLength: number;
  passwordRequireUppercase: boolean;
  passwordRequireNumbers: boolean;
  passwordRequireSymbols: boolean;
  passwordExpiryDays: number;
  sessionTimeoutMinutes: number;
  idleTimeoutMinutes: number;
  maxConcurrentSessions: number;
}
import { useDebouncedState } from '../../hooks/useDebounce';
import { analyticsClient } from '../../lib/analyticsClient';

export const OrganizationSecurity: React.FC = () => {
  const [policy, setPolicy] = useState<AuthPolicy>({
    id: '1',
    ssoEnforced: false,
    mfaRequired: true,
    passwordMinLength: 12,
    passwordRequireUppercase: true,
    passwordRequireNumbers: true,
    passwordRequireSymbols: true,
    passwordExpiryDays: 90,
    sessionTimeoutMinutes: 60,
    idleTimeoutMinutes: 30,
    maxConcurrentSessions: 3,
  });

  // Debounced numeric inputs to reduce API pressure
  // Updates UI immediately but delays API calls by 500ms
  const [passwordMinLength, debouncedPasswordMinLength, setPasswordMinLength] = useDebouncedState(
    policy.passwordMinLength,
    500
  );
  const [passwordExpiryDays, debouncedPasswordExpiryDays, setPasswordExpiryDays] = useDebouncedState(
    policy.passwordExpiryDays,
    500
  );
  const [sessionTimeoutMinutes, debouncedSessionTimeoutMinutes, setSessionTimeoutMinutes] = useDebouncedState(
    policy.sessionTimeoutMinutes,
    500
  );
  const [idleTimeoutMinutes, debouncedIdleTimeoutMinutes, setIdleTimeoutMinutes] = useDebouncedState(
    policy.idleTimeoutMinutes,
    500
  );
  const [maxConcurrentSessions, debouncedMaxConcurrentSessions, setMaxConcurrentSessions] = useDebouncedState(
    policy.maxConcurrentSessions,
    500
  );

  // Update policy when debounced values change (for API calls)
  useEffect(() => {
    setPolicy(prev => ({
      ...prev,
      passwordMinLength: debouncedPasswordMinLength,
      passwordExpiryDays: debouncedPasswordExpiryDays,
      sessionTimeoutMinutes: debouncedSessionTimeoutMinutes,
      idleTimeoutMinutes: debouncedIdleTimeoutMinutes,
      maxConcurrentSessions: debouncedMaxConcurrentSessions,
    }));
  }, [
    debouncedPasswordMinLength,
    debouncedPasswordExpiryDays,
    debouncedSessionTimeoutMinutes,
    debouncedIdleTimeoutMinutes,
    debouncedMaxConcurrentSessions,
  ]);

  const [domains, setDomains] = useState<AllowedDomain[]>([
    {
      id: '1',
      domain: 'example.com',
      type: 'whitelist',
      autoProvision: true,
      createdAt: '2024-01-01',
    },
  ]);

  const [newDomain, setNewDomain] = useState('');
  const [saving, setSaving] = useState(false);
  const [apiKeys, setApiKeys] = useState<Array<{ id: string; label: string; key: string; createdAt: string; lastUsed?: string }>>([
    {
      id: 'key-1',
      label: 'Primary Server Key',
      key: 'vc_demo_primary_key',
      createdAt: '2024-11-01',
      lastUsed: '2024-12-15',
    },
  ]);
  const [lastGeneratedKey, setLastGeneratedKey] = useState<string | null>(null);

  const handleSavePolicy = async () => {
    setSaving(true);
    await new Promise(resolve => setTimeout(resolve, 1000));
    setSaving(false);
  };

  const handleAddDomain = () => {
    if (!newDomain) return;

    setDomains([
      ...domains,
      {
        id: `${domains.length + 1}`,
        domain: newDomain,
        type: 'whitelist',
        autoProvision: false,
        createdAt: new Date().toISOString(),
      },
    ]);
    setNewDomain('');
  };

  const handleRemoveDomain = (id: string) => {
    setDomains(domains.filter(d => d.id !== id));
  };

  const generateApiKey = () => {
    const rawKey = `vc_${Math.random().toString(36).slice(2, 10)}${Math.random().toString(36).slice(2, 8)}`;
    const newKey = {
      id: `key-${apiKeys.length + 1}`,
      label: `Key ${apiKeys.length + 1}`,
      key: rawKey,
      createdAt: new Date().toISOString(),
      lastUsed: 'Never',
    };

    setApiKeys([...apiKeys, newKey]);
    setLastGeneratedKey(rawKey);
    analyticsClient.trackWorkflowEvent('api_key_generated', 'api_access', {
      key_id: newKey.id,
      label: newKey.label,
      last4: rawKey.slice(-4),
    });
  };

  const maskKey = (key: string) => `${key.slice(0, 4)}••••${key.slice(-4)}`;

  return (
    <div className="space-y-6">
      <SettingsSection title="Authentication Policy" description="Configure security requirements for user authentication">
        <div className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex items-start justify-between p-4 border border-gray-200 rounded-lg">
              <div className="flex items-start space-x-3">
                <Shield className="h-5 w-5 text-gray-600 mt-0.5" />
                <div>
                  <p className="font-medium text-gray-900">Enforce SSO</p>
                  <p className="text-sm text-gray-600 mt-1">
                    Require Single Sign-On for all users
                  </p>
                </div>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input
                  type="checkbox"
                  className="sr-only peer"
                  checked={policy.ssoEnforced}
                  onChange={(e) => setPolicy({ ...policy, ssoEnforced: e.target.checked })}
                />
                <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-blue-300 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
              </label>
            </div>

            <div className="flex items-start justify-between p-4 border border-gray-200 rounded-lg">
              <div className="flex items-start space-x-3">
                <Key className="h-5 w-5 text-gray-600 mt-0.5" />
                <div>
                  <p className="font-medium text-gray-900">Require MFA</p>
                  <p className="text-sm text-gray-600 mt-1">
                    Multi-factor authentication required
                  </p>
                </div>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input
                  type="checkbox"
                  className="sr-only peer"
                  checked={policy.mfaRequired}
                  onChange={(e) => setPolicy({ ...policy, mfaRequired: e.target.checked })}
                />
                <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-blue-300 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
              </label>
            </div>
          </div>

          <div className="border-t border-gray-200 pt-6">
            <h4 className="text-sm font-medium text-gray-900 mb-4">Password Requirements</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Minimum Length</label>
                <input
                  type="number"
                  value={passwordMinLength}
                  onChange={(e) => setPasswordMinLength(parseInt(e.target.value) || 8)}
                  min="8"
                  max="32"
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Password Expiry (days)</label>
                <input
                  type="number"
                  value={passwordExpiryDays}
                  onChange={(e) => setPasswordExpiryDays(parseInt(e.target.value) || 0)}
                  min="0"
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
                <p className="text-xs text-gray-500 mt-1">0 = never expires</p>
              </div>
            </div>

            <div className="mt-4 space-y-2">
              <label className="flex items-center space-x-2 text-sm">
                <input
                  type="checkbox"
                  checked={policy.passwordRequireUppercase}
                  onChange={(e) => setPolicy({ ...policy, passwordRequireUppercase: e.target.checked })}
                  className="rounded border-gray-300 focus:ring-blue-500"
                />
                <span>Require uppercase letters</span>
              </label>
              <label className="flex items-center space-x-2 text-sm">
                <input
                  type="checkbox"
                  checked={policy.passwordRequireNumbers}
                  onChange={(e) => setPolicy({ ...policy, passwordRequireNumbers: e.target.checked })}
                  className="rounded border-gray-300 focus:ring-blue-500"
                />
                <span>Require numbers</span>
              </label>
              <label className="flex items-center space-x-2 text-sm">
                <input
                  type="checkbox"
                  checked={policy.passwordRequireSymbols}
                  onChange={(e) => setPolicy({ ...policy, passwordRequireSymbols: e.target.checked })}
                  className="rounded border-gray-300 focus:ring-blue-500"
                />
                <span>Require special characters</span>
              </label>
            </div>
          </div>
        </div>
      </SettingsSection>

      <SettingsSection title="Session Management" description="Configure session timeout and concurrent session limits">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 max-w-3xl">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              <Clock className="inline h-4 w-4 mr-1" />
              Session Timeout
            </label>
            <div className="flex items-center space-x-2">
              <input
                type="number"
                value={sessionTimeoutMinutes}
                onChange={(e) => setSessionTimeoutMinutes(parseInt(e.target.value) || 15)}
                min="15"
                className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
              <span className="text-sm text-gray-600">min</span>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              <Clock className="inline h-4 w-4 mr-1" />
              Idle Timeout
            </label>
            <div className="flex items-center space-x-2">
              <input
                type="number"
                value={idleTimeoutMinutes}
                onChange={(e) => setIdleTimeoutMinutes(parseInt(e.target.value) || 5)}
                min="5"
                className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
              <span className="text-sm text-gray-600">min</span>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              <Users className="inline h-4 w-4 mr-1" />
              Max Sessions
            </label>
            <input
              type="number"
              value={maxConcurrentSessions}
              onChange={(e) => setMaxConcurrentSessions(parseInt(e.target.value) || 1)}
              min="1"
              max="10"
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>
      </SettingsSection>

      <SettingsSection title="Allowed Email Domains" description="Manage email domains for auto-provisioning and access control">
        <div className="space-y-4">
          <div className="flex space-x-2">
            <input
              type="text"
              value={newDomain}
              onChange={(e) => setNewDomain(e.target.value)}
              placeholder="example.com"
              className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            <button
              onClick={handleAddDomain}
              disabled={!newDomain}
              className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <Plus className="h-4 w-4 mr-2" />
              Add Domain
            </button>
          </div>

          <div className="space-y-2">
            {domains.map((domain) => (
              <div
                key={domain.id}
                className="flex items-center justify-between p-3 border border-gray-200 rounded-lg"
              >
                <div className="flex items-center space-x-3">
                  <Globe className="h-5 w-5 text-gray-600" />
                  <div>
                    <p className="font-medium text-gray-900">{domain.domain}</p>
                    <p className="text-xs text-gray-500">
                      {domain.type === 'whitelist' ? 'Whitelist' : 'Blacklist'}
                      {domain.autoProvision && ' • Auto-provision enabled'}
                    </p>
                  </div>
                </div>
                <button
                  onClick={() => handleRemoveDomain(domain.id)}
                  className="p-2 text-red-600 hover:bg-red-50 rounded transition-colors"
                >
                  <Trash2 className="h-4 w-4" />
                </button>
              </div>
            ))}
          </div>

          {domains.length === 0 && (
            <div className="text-center py-8 border border-gray-200 rounded-lg">
              <Globe className="h-12 w-12 text-gray-300 mx-auto mb-3" />
              <p className="text-gray-600">No domains configured</p>
              <p className="text-sm text-gray-500 mt-1">Add a domain to control user access</p>
            </div>
          )}
        </div>
      </SettingsSection>

      <SettingsSection
        title="API Access & Keys"
        description="Generate and rotate API keys for integrations"
        actions={
          <button
            onClick={generateApiKey}
            className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            <Key className="h-4 w-4 mr-2" />
            Generate Key
          </button>
        }
      >
        <div className="space-y-4">
          {lastGeneratedKey && (
            <div className="p-3 bg-green-50 border border-green-200 rounded-lg text-sm text-green-800">
              <p className="font-semibold">New key generated</p>
              <p className="break-all text-gray-800">{lastGeneratedKey}</p>
              <p className="text-xs text-gray-600">Copy and store it now — we only show it once.</p>
            </div>
          )}

          <div className="space-y-2">
            {apiKeys.map((apiKey) => (
              <div key={apiKey.id} className="flex items-center justify-between p-3 border border-gray-200 rounded-lg">
                <div>
                  <p className="font-medium text-gray-900">{apiKey.label}</p>
                  <p className="text-sm text-gray-600">{maskKey(apiKey.key)}</p>
                  <p className="text-xs text-gray-500">Created {new Date(apiKey.createdAt).toLocaleDateString()} • Last used {apiKey.lastUsed}</p>
                </div>
                <button
                  onClick={() => {
                    navigator.clipboard?.writeText(apiKey.key);
                    analyticsClient.track('api_key_copied', {
                      key_id: apiKey.id,
                      workflow: 'api_access',
                    });
                  }}
                  className="px-3 py-1 text-sm border border-gray-300 rounded-lg hover:bg-gray-50"
                >
                  Copy
                </button>
              </div>
            ))}
          </div>
        </div>
      </SettingsSection>

      <div className="flex justify-end">
        <button
          onClick={handleSavePolicy}
          disabled={saving}
          className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50"
        >
          {saving ? 'Saving...' : 'Save Security Settings'}
        </button>
      </div>
    </div>
  );
};

import {
  Ban,
  CheckCircle,
  ChevronLeft,
  ChevronRight,
  Clock,
  Download,
  Mail,
  MoreVertical,
  Search,
  UserPlus,
  XCircle,
} from "lucide-react";
import React, { useEffect, useMemo, useState } from "react";

import { apiClient } from "../../api/client/unified-api-client";
import { ConfirmationModal } from "../../components/common/ConfirmationModal";
import { useToast } from "../../components/common/Toast";
import { SettingsSection } from "../../components/settings";
import { useAuth } from "../../contexts/AuthContext";
import { analyticsClient } from "../../lib/analyticsClient";

interface OrganizationUser {
  userUuid: string;
  tenantId: string;
  email: string;
  emailVerified: boolean;
  displayName: string;
  role: string;
  status: string;
  lastLoginAt: string | null;
  creationSource: string;
  mfaEnrolled: boolean;
  deviceCount: number;
  deviceListReference: string;
  department?: string;
}

const PAGE_SIZE = 10;
const ROLE_OPTIONS = [
  { value: "owner", label: "Owner" },
  { value: "admin", label: "Admin" },
  { value: "member", label: "User" },
  { value: "viewer", label: "Viewer" },
] as const;

type TenantRoleValue = (typeof ROLE_OPTIONS)[number]["value"];

export const OrganizationUsers: React.FC = () => {
  const { success, error: showErrorToast } = useToast();
  const [users, setUsers] = useState<OrganizationUser[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [deletingUserId, setDeletingUserId] = useState<string | null>(null);
  const [userPendingRemoval, setUserPendingRemoval] = useState<OrganizationUser | null>(null);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("all");
  const [deptFilter, _setDeptFilter] = useState("all");
  const [selectedUsers, setSelectedUsers] = useState<Set<string>>(new Set());
  const [sortColumn, setSortColumn] = useState<keyof OrganizationUser>("displayName");
  const [sortDirection, setSortDirection] = useState<"asc" | "desc">("asc");
  const [currentPage, setCurrentPage] = useState(1);
  const [isInviteModalOpen, setInviteModalOpen] = useState(false);
  const [inviteEmail, setInviteEmail] = useState("");
  const [inviteRole, setInviteRole] = useState<TenantRoleValue>("member");
  const [inviteStatus, setInviteStatus] = useState<string | null>(null);
  const { session } = useAuth();

  useEffect(() => {
    const fetchUsers = async () => {
      if (!session?.access_token) {
        setIsLoading(false);
        return;
      }

      setIsLoading(true);
      setLoadError(null);

      try {
        const response = await apiClient.get<{ users: OrganizationUser[] }>("/api/admin/users");
        if (!response.success) {
          throw new Error(response.error?.message || "Failed to load users");
        }
        setUsers(response.data?.users ?? []);
      } catch (error) {
        setLoadError(error instanceof Error ? error.message : "Failed to load users");
      } finally {
        setIsLoading(false);
      }
    };

    fetchUsers();
  }, [session?.access_token]);

  const filteredAndSortedUsers = useMemo(() => {
    const result = users.filter((user) => {
      const matchesSearch =
        !searchQuery ||
        user.displayName.toLowerCase().includes(searchQuery.toLowerCase()) ||
        user.email.toLowerCase().includes(searchQuery.toLowerCase());

      const matchesRole = roleFilter === "all" || user.role === roleFilter;
      const matchesStatus = statusFilter === "all" || user.status === statusFilter;
      const matchesDept = deptFilter === "all" || user.department === deptFilter;

      return matchesSearch && matchesRole && matchesStatus && matchesDept;
    });

    result.sort((a, b) => {
      const aVal = a[sortColumn];
      const bVal = b[sortColumn];
      if (aVal === undefined) return 1;
      if (bVal === undefined) return -1;

      const comparison = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
      return sortDirection === "asc" ? comparison : -comparison;
    });

    return result;
  }, [users, searchQuery, roleFilter, statusFilter, deptFilter, sortColumn, sortDirection]);

  const paginatedUsers = useMemo(() => {
    const start = (currentPage - 1) * PAGE_SIZE;
    return filteredAndSortedUsers.slice(start, start + PAGE_SIZE);
  }, [filteredAndSortedUsers, currentPage]);

  const totalPages = Math.ceil(filteredAndSortedUsers.length / PAGE_SIZE);

  const handleSort = (column: keyof OrganizationUser) => {
    if (sortColumn === column) {
      setSortDirection(sortDirection === "asc" ? "desc" : "asc");
    } else {
      setSortColumn(column);
      setSortDirection("asc");
    }
  };

  const handleSelectUser = (userId: string) => {
    const newSelected = new Set(selectedUsers);
    if (newSelected.has(userId)) {
      newSelected.delete(userId);
    } else {
      newSelected.add(userId);
    }
    setSelectedUsers(newSelected);
  };

  const handleSelectAll = () => {
    if (selectedUsers.size === paginatedUsers.length) {
      setSelectedUsers(new Set());
    } else {
      setSelectedUsers(new Set(paginatedUsers.map((u) => u.userUuid)));
    }
  };

  const handleInviteSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    if (!inviteEmail) return;

    try {
      const response = await apiClient.post<{ user: OrganizationUser }>("/api/admin/users/invite", {
        email: inviteEmail,
        role: inviteRole,
      });

      if (!response.success) {
        throw new Error(response.error?.message || "Invite failed");
      }

      if (response.data?.user) {
        setUsers((current) => [response.data!.user, ...current]);
      }
      setInviteStatus(`Invitation sent to ${inviteEmail}`);
      analyticsClient.trackWorkflowEvent("teammate_invited", "team_invite", {
        email: inviteEmail,
        role: inviteRole,
      });
      setInviteModalOpen(false);
      setInviteEmail("");
    } catch (error) {
      setInviteStatus(error instanceof Error ? error.message : "Failed to send invite");
    }
  };

  const handleRoleChange = async (userId: string, role: TenantRoleValue) => {
    try {
      const response = await apiClient.patch(`/api/admin/users/${userId}/role`, { role });
      if (!response.success) {
        throw new Error(response.error?.message || "Role update failed");
      }
      setUsers((current) =>
        current.map((user) => (user.userUuid === userId ? { ...user, role } : user))
      );
    } catch (error) {
      setLoadError(error instanceof Error ? error.message : "Failed to update role");
    }
  };

  const handleRemoveUser = async (userId: string) => {
    setDeletingUserId(userId);
    try {
      const response = await apiClient.delete(`/api/admin/users/${userId}`);
      if (!response.success) {
        throw new Error(response.error?.message || "Removal failed");
      }
      setUsers((current) => current.filter((user) => user.userUuid !== userId));
      success("User removed successfully.");
    } catch (error) {
      const message = error instanceof Error ? error.message : "Failed to remove user";
      setLoadError(message);
      showErrorToast(message);
    } finally {
      setDeletingUserId(null);
    }
  };

  const getStatusIcon = (status: OrganizationUser["status"]) => {
    switch (status) {
      case "active":
        return <CheckCircle className="h-4 w-4 text-green-600" />;
      case "invited":
        return <Mail className="h-4 w-4 text-blue-600" />;
      case "suspended":
        return <Clock className="h-4 w-4 text-yellow-600" />;
      case "deactivated":
        return <Ban className="h-4 w-4 text-red-600" />;
      default:
        return <Clock className="h-4 w-4 text-gray-500" />;
    }
  };

  const getStatusColor = (status: OrganizationUser["status"]) => {
    switch (status) {
      case "active":
        return "bg-green-100 text-green-800";
      case "invited":
        return "bg-blue-100 text-blue-800";
      case "suspended":
        return "bg-yellow-100 text-yellow-800";
      case "deactivated":
        return "bg-red-100 text-red-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  return (
    <div className="space-y-6">
      <SettingsSection
        title="User Directory"
        description="Manage all users across your organization"
        actions={
          <div className="flex space-x-2">
            <button className="flex items-center px-3 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors">
              <Download className="h-4 w-4 mr-2" />
              Export
            </button>
            <button
              className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
              onClick={() => {
                setInviteModalOpen(true);
                setInviteStatus(null);
                analyticsClient.trackWorkflowEvent("teammate_invite_opened", "team_invite", {});
              }}
            >
              <UserPlus className="h-4 w-4 mr-2" />
              Invite User
            </button>
          </div>
        }
      >
        <div className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
            <div className="relative md:col-span-2">
              <Search className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
              <input
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search by name or email..."
                aria-label="Search users by name or email"
                className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <select
              value={roleFilter}
              onChange={(e) => setRoleFilter(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="all">All Roles</option>
              {ROLE_OPTIONS.map((role) => (
                <option key={role.value} value={role.value}>
                  {role.label}
                </option>
              ))}
            </select>

            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="all">All Status</option>
              <option value="active">Active</option>
              <option value="invited">Invited</option>
              <option value="suspended">Suspended</option>
              <option value="deactivated">Deactivated</option>
            </select>
          </div>

          {loadError && (
            <div className="flex items-center justify-between p-3 bg-red-50 border border-red-200 rounded-lg text-sm text-red-700">
              {loadError}
            </div>
          )}

          {isLoading && (
