            </div>
            <p className="text-sm text-gray-600 mb-4">
              Invites are auto-tagged with <span className="font-semibold">beta_cohort</span> for
              priority support.
            </p>
            <form className="space-y-4" onSubmit={handleInviteSubmit}>
              <div>
                <label
