    stageKeys: ["hypothesis"],
  },
  {
    key: "analyze",
    label: "Analyze",
    description: "Quantify value architecture and map drivers to measurable outcomes.",
    stageKeys: ["model", "value-graph"],
  },
  {
    key: "validate",
    label: "Validate",
    description: "Pressure-test assumptions and compile evidence-backed narrative outputs.",
    stageKeys: ["integrity", "narrative"],
  },
  {
    key: "decide",
    label: "Decide",
    description: "Align realization execution and expansion plans for operational decisions.",
    stageKeys: ["realization", "expansion"],
  },
];

function getStageState(
  stageKey: string,
  workflowExecution: WorkflowExecutionMetadata
): ExecutionState {
  const stage = workflowExecution.stages?.[stageKey];
  if (stage?.status) return stage.status;
  if (stage?.is_complete) return "complete";
  if (workflowExecution.blocked_stage === stageKey) return "blocked";
  if (workflowExecution.in_progress_stage === stageKey || workflowExecution.active_stage === stageKey) return "in_progress";
  return "pending";
}

function getMilestoneCompletionCriteria(
  milestone: MilestoneDefinition,
  workflowExecution: WorkflowExecutionMetadata
): string[] {
  return milestone.stageKeys.flatMap((stageKey) => workflowExecution.stages?.[stageKey]?.completion_criteria ?? []);
}

function getMilestoneState(milestone: MilestoneDefinition, stageStatuses: Record<string, ExecutionState>): ExecutionState {
  const states = milestone.stageKeys.map((stageKey) => stageStatuses[stageKey] ?? "pending");

  if (states.some((state) => state === "blocked")) return "blocked";
  if (states.every((state) => state === "complete")) return "complete";
  if (states.some((state) => state === "in_progress" || state === "complete")) return "in_progress";
  return "pending";
}

function getMilestoneProgressCopy(
  milestone: MilestoneDefinition,
  milestoneState: ExecutionState,
  stageStatuses: Record<string, ExecutionState>
): string {
  if (milestoneState === "complete") {
    return `${milestone.label} is complete. ${milestone.description}`;
  }

  if (milestoneState === "blocked") {
    const blockedStage = milestone.stageKeys.find((stageKey) => stageStatuses[stageKey] === "blocked");
    const blockedStageLabel = stages.find((stage) => stage.key === blockedStage)?.label ?? "A stage";
    return `${blockedStageLabel} is blocked and must be unblocked to continue ${milestone.label}.`;
  }

  if (milestoneState === "in_progress") {
    const activeStage = milestone.stageKeys.find((stageKey) => stageStatuses[stageKey] === "in_progress");
    const activeStageLabel = stages.find((stage) => stage.key === activeStage)?.label ?? milestone.label;
    return `${milestone.label} is in progress via ${activeStageLabel}.`;
  }

  return `${milestone.label} is queued. ${milestone.description}`;
}

function normalizePrerequisiteStageKey(prerequisite: string): string | null {
  const normalized = prerequisite.trim().toLowerCase();
  if (!normalized) return null;

  const matchedStage = stages.find((stage) => {
    const stageKey = stage.key.toLowerCase();
    const stageLabel = stage.label.toLowerCase();
    return normalized === stageKey || normalized === stageLabel || normalized.includes(stageKey) || normalized.includes(stageLabel);
  });

  return matchedStage?.key ?? null;
}

export function ValueCaseCanvas() {
  const { oppId, caseId, stage: stageParam } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const [searchParams] = useSearchParams();
  const [activeStage, setActiveStage] = useState<StageKey>(() => resolveStageFromUrl(stageParam, searchParams.get("stage")));
  const [evidenceOpen, setEvidenceOpen] = useState(false);
  const [activeRunId, setActiveRunId] = useState<string | null>(null);
  const [activeDirectResult, setActiveDirectResult] = useState<AgentJobResult | null>(null);
  const [guardMessage, setGuardMessage] = useState<string | null>(null);
const handleRunStarted = (jobId: string, direct?: AgentJobResult) => {
  setActiveRunId(jobId);
  setActiveDirectResult(direct ?? null);
};

const { data: merged } = useMergedContext(caseId);
const { data: valueCase, isLoading: caseLoading } = useCase(caseId);
const { data: workflowExecutionViewModel } = useWorkflowExecutionViewModel(caseId);

const workflowStatus = workflowExecutionViewModel ?? {
  statusLabel: WORKFLOW_STATUS_PRESENTATION.never_run.label,
  statusMessage: WORKFLOW_STATUS_PRESENTATION.never_run.userMessage,
  statusIconClassName: WORKFLOW_STATUS_PRESENTATION.never_run.iconClassName,
  confidenceBarClassName: WORKFLOW_STATUS_PRESENTATION.never_run.confidenceClassName,
  confidencePercent: 0,
  confidenceLabel: "0%",
  ctaText: WORKFLOW_STATUS_PRESENTATION.never_run.ctaText,
  lastUpdatedLabel: "No execution activity yet",
  execution: { stages: {} },
};

const pptxExport = usePptxExport(caseId);
const { toast } = useToast();

  const workflowExecution = useMemo(
    () => workflowStatus.execution ?? { stages: {} },
    [workflowStatus.execution]
  );

  const stageStatuses = useMemo(
    () => Object.fromEntries(stages.map((stage) => [stage.key, getStageState(stage.key, workflowExecution)])),
    [workflowExecution]
  );

  const activeMilestone = useMemo(
    () => milestones.find((milestone) => milestone.stageKeys.includes(activeStage)) ?? milestones[0],
    [activeStage]
  );

  const activeMilestoneState = useMemo(
    () => getMilestoneState(activeMilestone, stageStatuses),
    [activeMilestone, stageStatuses]
  );

  const activeMilestoneProgressCopy = useMemo(
    () => getMilestoneProgressCopy(activeMilestone, activeMilestoneState, stageStatuses),
    [activeMilestone, activeMilestoneState, stageStatuses]
  );

  const milestoneCriteria = useMemo(
    () => Array.from(new Set(getMilestoneCompletionCriteria(activeMilestone, workflowExecution))),
    [activeMilestone, workflowExecution]
  );

  const recommendedNextAction = useMemo(() => {
    const orderedStages = stages.map((stage) => stage.key);

    for (const stageKey of orderedStages) {
      const state = stageStatuses[stageKey];
      const stageLabel = stages.find((item) => item.key === stageKey)?.label ?? stageKey;
      const stageMilestone = milestones.find((milestone) => milestone.stageKeys.includes(stageKey))?.label ?? "the journey";

      if (state === "blocked") {
        const blockedReason = workflowExecution.stages?.[stageKey]?.blocked_reason;
        return `Unblock ${stageLabel}${blockedReason ? `: ${blockedReason}` : " by satisfying prerequisites."}`;
      }
      if (state === "in_progress") {
        return `Continue ${stageLabel} to advance ${stageMilestone}.`;
      }
      if (state === "pending") {
        return `Run ${stageLabel} next to progress ${stageMilestone}.`;
      }
    }

    return "All milestones are complete. Review evidence and prepare stakeholder export.";
  }, [stageStatuses, workflowExecution.stages]);

  useEffect(() => {
    if (pptxExport.isError) {
      toast({
        title: "Export failed",
        description: pptxExport.error?.message ?? "Could not generate PPTX. Try again.",
        variant: "destructive",
      });
    }
  }, [pptxExport.isError, pptxExport.error, toast]);

  const caseTitle = caseLoading
    ? null
    : valueCase
      ? [valueCase.company_profiles?.company_name, valueCase.name].filter(Boolean).join(" — ")
      : caseId ?? "Value Case";

  const stageContent: Record<string, React.ReactNode> = {
    hypothesis: <HypothesisStage onRunStarted={handleRunStarted} />,
    model: <ModelStage />,
    integrity: <IntegrityStage caseId={caseId} />,
    narrative: <NarrativeStage caseId={caseId} opportunityId={oppId} />,
    realization: <RealizationStage caseId={caseId} />,
    expansion: <ExpansionStage caseId={caseId} />,
    "value-graph": <ValueGraphStage opportunityId={oppId} />,
  };

  const currentStage = stages.find((s) => s.key === activeStage);

  const canvasBasePath = useMemo(() => {
    const marker = `/opportunities/${oppId}/cases/${caseId}`;
    const markerIndex = location.pathname.indexOf(marker);
    if (markerIndex === -1) {
      return location.pathname;
    }

    return location.pathname.slice(0, markerIndex + marker.length);
  }, [caseId, location.pathname, oppId]);

  useEffect(() => {
    const stageFromUrl = resolveStageFromUrl(stageParam, searchParams.get("stage"));
    if (stageFromUrl !== activeStage) {
      setActiveStage(stageFromUrl);
    }

    const stageParamProvided = typeof stageParam === "string";
    const stageQueryProvided = searchParams.get("stage") !== null;
    const stageParamKnown = isKnownStage(stageParam);
    const stageQueryKnown = isKnownStage(searchParams.get("stage"));

    if ((stageParamProvided && !stageParamKnown) || (!stageParamProvided && stageQueryProvided && !stageQueryKnown)) {
      const nextSearchParams = new URLSearchParams(searchParams);
      nextSearchParams.delete("stage");
      const nextSearch = nextSearchParams.toString();

      navigate(
        { pathname: `${canvasBasePath}/${stageFromUrl}`, search: nextSearch ? `?${nextSearch}` : "" },
        { replace: true }
      );
    }
  }, [activeStage, canvasBasePath, navigate, searchParams, stageParam]);

  const persistStageToUrl = (targetStage: StageKey) => {
    const nextSearchParams = new URLSearchParams(searchParams);
    nextSearchParams.delete("stage");
    const nextSearch = nextSearchParams.toString();

    navigate(
      { pathname: `${canvasBasePath}/${targetStage}`, search: nextSearch ? `?${nextSearch}` : "" },
      { replace: false }
    );
  };

  const tryEnterStage = (targetStage: StageDefinition) => {
    const stageStatus = stageStatuses[targetStage.key];
    const stageMetadata = workflowExecution.stages?.[targetStage.key];
    const prerequisites = stageMetadata?.prerequisites ?? [];

    const unmetPrerequisites = prerequisites.filter((prerequisite) => {
      const prerequisiteStageKey = normalizePrerequisiteStageKey(prerequisite);
      if (!prerequisiteStageKey) return false;
      return stageStatuses[prerequisiteStageKey] !== "complete";
    });

    if (stageStatus !== "blocked" && unmetPrerequisites.length === 0) {
      setGuardMessage(null);
      setActiveStage(targetStage.key);
      persistStageToUrl(targetStage.key);
      return;
    }

    const blockedReason = stageMetadata?.blocked_reason
      ?? (unmetPrerequisites.length > 0
        ? "Required prerequisites are not complete yet."
        : "Required upstream work is incomplete.");
    const prerequisiteSummary = prerequisites.length > 0
      ? `Prerequisites: ${prerequisites.join(", ")}.`
      : "No explicit prerequisites were provided by execution metadata.";
    const unmetSummary = unmetPrerequisites.length > 0
      ? `Unmet prerequisites: ${unmetPrerequisites.join(", ")}.`
      : "";

    setGuardMessage(`${targetStage.label} is currently blocked. ${blockedReason} ${prerequisiteSummary} ${unmetSummary}`.trim());
  };

  return (
    <div className="h-full flex flex-col">
      <div className="px-6 py-4 border-b border-zinc-200 bg-white flex items-center gap-4 flex-shrink-0">
        <Link to={`/opportunities/${oppId}`} className="p-1.5 rounded-lg hover:bg-zinc-100">
          <ArrowLeft className="w-4 h-4 text-zinc-400" />
        </Link>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <h2 className="text-[15px] font-black text-zinc-950 tracking-tight truncate">
              {caseTitle ?? <span className="inline-block w-48 h-4 bg-zinc-100 rounded animate-pulse" />}
            </h2>
            <span
              className={cn(
                "px-2 py-0.5 rounded-full text-[10px] font-semibold flex-shrink-0 text-white",
                workflowStatus.statusIconClassName
              )}
            >
              {workflowStatus.statusLabel}
            </span>
            {merged?.pack && (
              <span className="flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-semibold bg-violet-50 text-violet-700 flex-shrink-0">
                <Layers className="w-2.5 h-2.5" />
                {merged.pack.name}
              </span>
            )}
          </div>
          <p className="text-[11px] text-zinc-400">{caseId || "VC-1024"}</p>
        </div>

        <div className="flex items-center gap-2 flex-shrink-0">
          <span className="text-[11px] text-zinc-400">Confidence</span>
          <div className="w-20 h-2 bg-zinc-100 rounded-full overflow-hidden">
            <div
              className={cn("h-full rounded-full", workflowStatus.confidenceBarClassName)}
              style={{ width: `${workflowStatus.confidencePercent}%` }}
            />
          </div>
          <span className="text-[12px] font-semibold text-zinc-700">{workflowStatus.confidenceLabel}</span>
        </div>

        <button className="flex items-center gap-1.5 px-3 py-2 border border-zinc-200 rounded-xl text-[12px] font-medium text-zinc-700 hover:bg-zinc-50">
          <Clock className="w-3.5 h-3.5" />
          v12
        </button>

        <button
          onClick={() => setEvidenceOpen(!evidenceOpen)}
          className="flex items-center gap-1.5 px-3 py-2 border border-zinc-200 rounded-xl text-[12px] font-medium text-zinc-700 hover:bg-zinc-50"
        >
          <Shield className="w-3.5 h-3.5" />
          Evidence
        </button>

        <button
          onClick={() => pptxExport.mutate({ title: caseTitle ?? undefined })}
          disabled={pptxExport.isPending}
          className="flex items-center gap-1.5 px-3 py-2 border border-zinc-200 rounded-xl text-[12px] font-medium text-zinc-700 hover:bg-zinc-50 disabled:opacity-50 disabled:cursor-not-allowed"
          title="Export as PowerPoint"
        >
          <Download className="w-3.5 h-3.5" />
          {pptxExport.isPending ? "Exporting…" : "Export"}
        </button>

        <button className="flex items-center gap-1.5 px-3 py-2 bg-zinc-950 text-white rounded-xl text-[12px] font-medium hover:bg-zinc-800">
          <Play className="w-3.5 h-3.5" />
          {workflowStatus.ctaText}
        </button>
      </div>

      <div className="px-6 py-3 border-b border-zinc-100 bg-white flex items-center gap-1 flex-shrink-0">
        {stages.map((s) => {
          const status = stageStatuses[s.key];
          return (
            <button
              key={s.key}
              onClick={() => tryEnterStage(s)}
              className={cn(
                "flex items-center gap-2 px-4 py-2 rounded-xl text-[12px] font-medium transition-colors",
                activeStage === s.key
                  ? "bg-zinc-950 text-white"
                  : "text-zinc-500 hover:bg-zinc-100 hover:text-zinc-700",
                status === "blocked" ? "opacity-70" : ""
              )}
            >
              <div className={cn("w-2 h-2 rounded-full", s.color)} />
              {s.label}
            </button>
          );
        })}

        <div className="ml-auto flex items-center gap-1.5 text-[11px] text-zinc-400">
          <RotateCcw className="w-3 h-3" />
          <span>Iterate anytime</span>
        </div>
      </div>

      <div className="px-6 py-3 border-b border-zinc-100 bg-zinc-50 flex items-start justify-between gap-4">
        <div>
          <p className="text-[11px] uppercase tracking-wide text-zinc-500 font-semibold">Journey milestone</p>
          <p className="text-[14px] font-semibold text-zinc-900">
            {activeMilestone.label}
          </p>
          <p className="text-[12px] text-zinc-600">{activeMilestoneProgressCopy}</p>
          <p className="text-[12px] text-zinc-700 mt-2" data-testid="guided-next-action">
            Recommended next action: {recommendedNextAction}
          </p>
          {guardMessage && (
            <p className="text-[12px] text-amber-700 mt-2" role="alert">
              {guardMessage}
            </p>
          )}
        </div>

        <div className="min-w-[280px]">
          <p className="text-[11px] uppercase tracking-wide text-zinc-500 font-semibold">Completion criteria</p>
          {milestoneCriteria.length > 0 ? (
            <ul className="mt-1 space-y-1">
              {milestoneCriteria.map((criteria, index) => (
                <li key={`${criteria}-${index}`} className="text-[12px] text-zinc-700 flex items-start gap-1.5">
                  <CheckCircle2 className="w-3.5 h-3.5 text-emerald-600 mt-0.5" />
                  <span>{criteria}</span>
                </li>
              ))}
            </ul>
          ) : (
            <p className="text-[12px] text-zinc-500">No completion criteria reported by workflow execution metadata yet.</p>
          )}
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className="flex-1 overflow-y-auto p-6">
          <div className="flex items-center gap-3 mb-5">
            <div className={cn("w-3 h-3 rounded-full", currentStage?.color)} />
            <h3 className="text-[15px] font-black text-zinc-950 tracking-tight">
              {currentStage?.label}
            </h3>
            <span className="text-[11px] text-zinc-400">{workflowStatus.statusMessage}</span>
            <span className="text-[11px] text-zinc-300 ml-auto">{workflowStatus.lastUpdatedLabel}</span>
          </div>
          {stageContent[activeStage]}
          <div className="mt-6">
            <HandoffTimelineCards runId={activeRunId} stageId={activeStage} />
          </div>
        </div>

        <div className="w-[340px] border-l border-zinc-200 bg-white p-5 overflow-y-auto flex-shrink-0 hidden xl:block">
          <AgentThread runId={activeRunId} directResult={activeDirectResult} />
        </div>
      </div>

      <EvidenceDrawer open={evidenceOpen} onClose={() => setEvidenceOpen(false)} caseId={caseId} />
    </div>
  );
}

/**
 * ValueCaseWorkspace
 *
 * Sprint 5 integration: connects SDUI CanvasHost, useCanvasState (artifact
 * persistence), and useAgentOrchestrator into a single routable view.
 *
 * Widget layout is driven by an SDUIWidget[] descriptor so the backend can
 * push new layouts without a frontend deploy.
 *
 * Enhanced with PipelineStepper, PipelineProgressBar, and AgentInsightCard
 * for real-time 7-step pipeline visualization driven by SSE LoopProgress events.
 */

import { useCallback, useEffect, useMemo, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";

import { CanvasHost, type SDUIWidget } from "@/components/canvas";
import { AgentInsightCard } from "@/components/orchestration/AgentInsightCard";
import { AgentStatusIndicator } from "@/components/orchestration/AgentStatusIndicator";
import { DegradedStatusBanner } from "@/components/orchestration/DegradedStatusBanner";
import { PipelineCompletionSummary } from "@/components/orchestration/PipelineCompletionSummary";
import { PipelineProgressBar } from "@/components/orchestration/PipelineProgressBar";
import { PipelineStepper } from "@/components/orchestration/PipelineStepper";
import { RemediationActionPanel } from "@/components/orchestration/RemediationActionPanel";
import { useTenant } from "@/contexts/TenantContext";
import { useAgentOrchestrator } from "@/hooks/useAgentOrchestrator";
import { useCanvasState } from "@/hooks/useCanvasState";
import { useValueCaseStream } from "@/hooks/useValueCaseStream";

/**
 * Default widget layout when no server-driven layout is available.
 * Each entry maps to a registered CanvasHost widget type.
 */
function buildDefaultWidgets(
  isProcessing: boolean,
  currentStep: string,
): SDUIWidget[] {
  return [
    {
      id: "ws-agent-response",
      componentType: "agent-response",
      props: {
        agentName: "Value Intelligence Agent",
        status: isProcessing ? currentStep : "Awaiting input",
        summary:
          "Submit a query to begin value analysis for this case.",
        valueDrivers: [],
      },
    },
    {
      id: "ws-chat-input",
      componentType: "chat-input",
      props: {
        placeholder: "Describe the value scenario to analyze...",
        disabled: isProcessing,
      },
    },
  ];
}

export function ValueCaseWorkspace() {
  const { caseId } = useParams<{ caseId: string }>();
  const navigate = useNavigate();
  const { currentTenant } = useTenant();

  // Canvas state (artifact persistence + undo/redo)
  const {
    assumptions,
    isDirty,
    calculateMetrics,
    commit,
  } = useCanvasState();

  // Agent orchestration
  const {
    state: agentState,
    context: agentContext,
    thoughts,
    isProcessing,
    submitQuery,
  } = useAgentOrchestrator({
    onStateChange: () => {
      // Recalculate metrics when agent finishes
      calculateMetrics();
    },
  });

  // Real-time pipeline stream (SSE)
  const {
    pipeline,
    connect: connectStream,
    progress,
    activeStep,
  } = useValueCaseStream({
    onComplete: () => calculateMetrics(),
  });
  const runtimeFailure = pipeline.runtimeFailure;

  const hasPipelineActivity = pipeline.steps.some((s) => s.status !== "pending");

  // Recalculate on assumption changes
  useEffect(() => {
    calculateMetrics();
  }, [assumptions, calculateMetrics]);

  // Server-driven widget layout (future: fetch from API)
  const [serverWidgets, setServerWidgets] = useState<SDUIWidget[] | null>(null);

  const widgets = useMemo(() => {
    if (serverWidgets) return serverWidgets;
    return buildDefaultWidgets(isProcessing, agentContext.currentStep);
  }, [serverWidgets, isProcessing, agentContext.currentStep]);

  // Handle widget actions (chat submit, button clicks, etc.)
  const handleWidgetAction = useCallback(
    (widgetId: string, action: string, payload?: unknown) => {
      if (widgetId === "ws-chat-input" && action === "submit") {
        const msg = (payload as { message?: string })?.message;
        if (msg) {
          submitQuery(msg);
        }
      }
    },
    [submitQuery],
  );

  // Auto-commit when dirty and agent finishes
  useEffect(() => {
    if (isDirty && agentState === "IDLE") {
      commit();
    }
  }, [isDirty, agentState, commit]);

  return (
    <div className="flex flex-col h-full">
      {/* ── Pipeline progress header ── */}
      {(isProcessing || hasPipelineActivity) && (
        <div className="border-b border-zinc-200 bg-white">
          {/* Compact progress bar at the very top */}
          {pipeline.isRunning && (
            <PipelineProgressBar
              progress={progress}
              isRunning={pipeline.isRunning}
              label={activeStep?.message}
              className="px-6 pt-3 pb-1"
            />
          )}

          {/* 7-step pipeline stepper */}
          <div className="px-6 py-4 overflow-x-auto">
            <PipelineStepper
              steps={pipeline.steps}
              revisionCycle={pipeline.revisionCycle}
              maxRevisionCycles={pipeline.maxRevisionCycles}
            />
          </div>

          {/* Error banner */}
          {pipeline.error && (
            <div className="mx-6 mb-3 rounded-lg border border-red-200 bg-red-50 px-4 py-2.5 text-sm text-red-700">
              {pipeline.error}
            </div>
          )}

          {runtimeFailure && (
            <div className="mx-6 mb-3">
              <DegradedStatusBanner runtimeFailure={runtimeFailure} />
            </div>
          )}
        </div>
      )}

      {/* ── Fallback: legacy agent status pill ── */}
      {isProcessing && !hasPipelineActivity && (
        <div className="border-b border-zinc-200 bg-zinc-50 px-6 py-2">
          <AgentStatusIndicator
            state={agentState}
            currentStep={agentContext.currentStep}
          />
        </div>
      )}

      {/* ── Thought stream ── */}
      {thoughts.length > 0 && (
        <div className="border-b border-zinc-200 bg-zinc-50/50 px-6 py-3">
          <p className="text-[11px] font-medium text-zinc-400 uppercase tracking-wide mb-1">
            Agent Thoughts
          </p>
          <div className="space-y-0.5 font-mono text-xs text-zinc-500 max-h-24 overflow-y-auto">
            {thoughts.slice(-5).map((t) => (
              <div key={t.id} className="flex items-start gap-2">
                <span className="text-zinc-900 font-medium">[{t.type}]</span>
                <span>{t.content}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── Main content ── */}
      <div className="flex-1 overflow-y-auto p-6">
        <div className="mx-auto max-w-4xl space-y-6">
          {/* Pipeline completion summary */}
          {pipeline.isComplete && (
            <PipelineCompletionSummary pipeline={pipeline} />
          )}

          {/* Agent insight cards — one per completed/running step */}
          {hasPipelineActivity && (
            <div className="space-y-2">
              {pipeline.steps
                .filter((s) => s.status !== "pending")
                .map((s) => (
                  <AgentInsightCard key={`${s.step}-${pipeline.revisionCycle}`} step={s} />
                ))}
            </div>
          )}

          {runtimeFailure && (
            <RemediationActionPanel
              runtimeFailure={runtimeFailure}
              onOpenApprovalInbox={() => navigate("/billing?tab=approvals")}
            />
          )}

          {/* SDUI Canvas */}
          {caseId ? (
            <CanvasHost
              widgets={widgets}
              onWidgetAction={handleWidgetAction}
            />
          ) : (
            <div className="flex h-full items-center justify-center text-zinc-400 text-sm">
              Select or create a value case to begin.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default ValueCaseWorkspace;

