import {
  AlertTriangle,
  ArrowUp,
  CheckCircle2,
  Clock,
  Loader2,
  RefreshCw,
  Shield,
  XCircle,
} from "lucide-react";
import { useMemo, useState } from "react";
import { useParams } from "react-router-dom";

import { useAgentJob } from "@/hooks/useAgentJob";
import {
  useCheckpointReview,
  useCheckpointReviewDecision,
} from "@/hooks/useCheckpointReview";
import type { AgentJobResult } from "@/hooks/useAgentJob";
import { logger } from "@/lib/logger";
import { cn } from "@/lib/utils";

interface AgentThreadProps {
  runId?: string | null;
  directResult?: AgentJobResult | null;
  currentSubTask?: string | null;
  stageId?: string;
  riskLevel?: "low" | "medium" | "high";
}

export function AgentThread({
  runId,
  directResult,
  currentSubTask,
  stageId = "hypothesis",
  riskLevel = "medium",
}: AgentThreadProps) {
  const { caseId } = useParams<{ caseId: string }>();

  const { data: job, isLoading, retryRun, resumePolling } =
    useAgentJob(runId ?? null, directResult);

  const { data: review } = useCheckpointReview(
    caseId,
    runId ?? null,
    stageId
  );

  const reviewDecision = useCheckpointReviewDecision();

  const [message, setMessage] = useState("");
  const [rationale, setRationale] = useState("");
  const [validationError, setValidationError] = useState<string | null>(null);

  const currentStatus = review?.status ?? "pending";
  const isApproved = currentStatus === "approved";
  const isChangesRequested = currentStatus === "changes_requested";

  const requireApproveRationale = riskLevel === "high";

  const isDegraded =
    job?.status === "failed" ||
    job?.status === "error" ||
    job?.status === "unavailable";

  const retryBackoffLabel = useMemo(() => {
    if (!job?.nextRetryAt) return null;
    const nextRetryDate = new Date(job.nextRetryAt);
    if (Number.isNaN(nextRetryDate.getTime())) return null;

    const deltaMs = Math.max(0, nextRetryDate.getTime() - Date.now());
    const seconds = Math.ceil(deltaMs / 1000);
    return seconds > 0
      ? `Next automatic attempt in ~${seconds}s`
      : `Next automatic attempt at ${nextRetryDate.toLocaleTimeString()}`;
  }, [job?.nextRetryAt]);

  const retryAttemptLabel = useMemo(() => {
    if (job?.attemptsMade == null) return null;
    const attemptNumber = Math.max(1, job.attemptsMade);
    return `Attempt ${attemptNumber}`;
  }, [job?.attemptsMade]);

  const statusIcon = () => {
    if (!runId) return null;
    if (isLoading)
      return <Loader2 className="w-3.5 h-3.5 text-blue-500 animate-spin" />;
    switch (job?.status) {
      case "completed":
        return <CheckCircle2 className="w-3.5 h-3.5 text-emerald-600" />;
      case "failed":
      case "error":
        return <XCircle className="w-3.5 h-3.5 text-red-500" />;
      case "unavailable":
        return <AlertTriangle className="w-3.5 h-3.5 text-amber-500" />;
      case "retrying":
        return <RefreshCw className="w-3.5 h-3.5 text-orange-500 animate-spin" />;
      default:
        return <Loader2 className="w-3.5 h-3.5 text-blue-500 animate-spin" />;
    }
  };

  const statusLabel = () => {
    if (!runId) return "No active run";
    if (isLoading) return "Connecting…";

    const modeTag =
      job?.mode === "direct"
        ? " · direct"
        : job?.mode === "kafka"
          ? " · async"
          : "";

    switch (job?.status) {
      case "queued":
        return "Queued";
      case "processing":
        return currentSubTask
          ? currentSubTask
          : `Running${job.agentId ? ` · ${job.agentId}` : ""}`;
      case "retrying":
        return `Retrying${job.attemptsMade != null ? ` (attempt ${job.attemptsMade})` : ""
          }`;
      case "completed":
        return `Completed${modeTag}`;
      case "failed":
      case "error":
        return `Failed${modeTag}`;
      case "unavailable":
        return "Infrastructure unavailable";
      default:
        return "Unknown";
    }
  };

  const statusBg = () => {
    switch (job?.status) {
      case "completed":
        return "bg-emerald-50";
      case "error":
      case "failed":
        return "bg-red-50";
      case "unavailable":
        return "bg-amber-50";
      case "retrying":
        return "bg-orange-50";
      default:
        return "bg-blue-50";
    }
  };

  const iconBg = () => {
    switch (job?.status) {
      case "completed":
        return "bg-emerald-100";
      case "error":
      case "failed":
        return "bg-red-100";
      case "unavailable":
        return "bg-amber-100";
      case "retrying":
        return "bg-orange-100";
      default:
        return "bg-blue-100";
    }
  };

  const handleViewArtifact = () => {
    if (!job?.lastKnownGoodOutput) return;
    const artifact =
      typeof job.lastKnownGoodOutput === "string"
        ? job.lastKnownGoodOutput
        : JSON.stringify(job.lastKnownGoodOutput, null, 2);

    navigator.clipboard.writeText(artifact).catch((err) => {
      logger.warn("Failed to copy artifact to clipboard:", { error: err });
    });
  };

  const reviewBanner = useMemo(() => {
    if (isApproved) return "Approved";
    if (isChangesRequested) return "Changes Requested";
    return "Pending Review";
  }, [isApproved, isChangesRequested]);

  const formattedDecisionTime = useMemo(() => {
    if (!review?.decidedAt) return null;
    const parsed = new Date(review.decidedAt);
    if (Number.isNaN(parsed.getTime())) return null;
    return parsed.toLocaleString();
  }, [review?.decidedAt]);

  const canApprove = !isChangesRequested && !reviewDecision.isPending;
  const canRequestChanges = !isApproved && !reviewDecision.isPending;

  const submitDecision = (decision: "approved" | "changes_requested") => {
    if (!caseId || !runId) return;

    const trimmed = rationale.trim();

    const mustProvide =
      decision === "changes_requested" ||
      (decision === "approved" && requireApproveRationale);

    if (mustProvide && !trimmed) {
      setValidationError(
        decision === "changes_requested"
          ? "Rationale is required when requesting changes."
          : "Rationale is required for approvals in high-risk stages."
      );
      return;
    }

    setValidationError(null);

    reviewDecision.mutate({
      caseId,
      runId,
      stageId,
      decision,
      rationale: trimmed || undefined,
      riskLevel,
    });
  };

  return (
    <div className="space-y-3">
      <h4 className="text-[11px] font-semibold uppercase tracking-[0.2em] text-zinc-400">
        Agent Workflow
      </h4>

      {!runId && (
        <div className="flex items-center gap-3 p-4 rounded-xl bg-zinc-50 border border-dashed border-zinc-200">
          <Clock className="w-4 h-4 text-zinc-300 flex-shrink-0" />
          <p className="text-[12px] text-zinc-400">
            Click "Run Stage" in the Hypothesis panel to start the agent.
          </p>
        </div>
      )}

      {runId && (
        <div className="space-y-2">
          <div
            className={cn("flex items-center gap-3 p-3 rounded-xl", statusBg())}
          >
            <div
              className={cn(
                "w-6 h-6 rounded-full flex items-center justify-center",
                iconBg()
              )}
            >
              {statusIcon()}
            </div>

            <div className="flex-1">
              <p className="text-[12px] font-medium text-zinc-800">
                {statusLabel()}
              </p>

              {job?.message && (
                <p className="text-[11px] text-zinc-500">{job.message}</p>
              )}

              {retryBackoffLabel && (
                <p className="text-[11px] text-zinc-500">
                  {retryBackoffLabel}
                </p>
              )}
            </div>
          </div>

          {isDegraded && (
            <div className="space-y-2 rounded-xl border border-zinc-200 bg-zinc-50 p-3">
              <p className="text-[11px] font-medium text-zinc-700">
                Recovery Actions
              </p>

              <div className="flex flex-wrap gap-2">
                <button
                  onClick={() => retryRun.mutate()}
                  disabled={retryRun.isPending}
                  className="rounded-md border border-zinc-300 bg-white px-2.5 py-1 text-[11px] text-zinc-700 disabled:cursor-not-allowed disabled:opacity-60"
                >
                Retry run
              </button>

                <button
                  onClick={() => resumePolling.mutate()}
                  disabled={resumePolling.isPending}
                  className="rounded-md border border-zinc-300 bg-white px-2.5 py-1 text-[11px] text-zinc-700 disabled:cursor-not-allowed disabled:opacity-60"
                >
                Resume polling
              </button>

                <button
                  onClick={handleViewArtifact}
                  disabled={!job?.lastKnownGoodOutput}
                  className="rounded-md border border-zinc-300 bg-white px-2.5 py-1 text-[11px] text-zinc-700 disabled:cursor-not-allowed disabled:opacity-60"
                >
                  View last successful artifact
              </button>
            </div>

              {(retryAttemptLabel || retryBackoffLabel) && (
                <p className="text-[11px] text-zinc-500">
                  {[retryAttemptLabel, retryBackoffLabel].filter(Boolean).join(" · ")}
                </p>
              )}

              {job?.lastKnownGoodOutput && (
                <div className="rounded-lg border border-emerald-200 bg-emerald-50 p-2">
                  <p className="text-[11px] font-medium text-emerald-700">
                    Last known good output
                  </p>
                  <p className="text-[10px] text-emerald-700/80">
                    {job.lastKnownGoodAt
                      ? `Captured ${new Date(job.lastKnownGoodAt).toLocaleString()}`
                      : "Captured from the previous successful run"}
                  </p>
                  <pre className="mt-1 max-h-28 overflow-auto rounded bg-white/80 p-2 text-[10px] text-zinc-700">
                    {typeof job.lastKnownGoodOutput === "string"
                      ? job.lastKnownGoodOutput
                      : JSON.stringify(job.lastKnownGoodOutput, null, 2)}
                  </pre>
                </div>
              )}
            </div>
          )}

          <p className="text-[10px] text-zinc-300 font-mono">
            run: {runId}
          </p>
        </div>
      )}

{job?.status === "completed" && (
  <div className="p-4 border-2 border-amber-300 bg-amber-50 space-y-3">
    <div className="flex justify-between">
      <span>Review Required</span>
      <span>{reviewBanner}</span>
    </div>

    <textarea
      value={rationale}
      onChange={(e) => setRationale(e.target.value)}
      placeholder="Add rationale..."
    />

    {validationError && <p>{validationError}</p>}

    {review?.actorId && formattedDecisionTime && (
      <p className="text-[11px] text-zinc-600">
        Last decision by {review.actorId} at {formattedDecisionTime}
      </p>
    )}

    <div className="flex gap-2">
      <button
        onClick={() => submitDecision("approved")}
        disabled={!canApprove}
      >
        Approve
      </button>
      <button
        onClick={() => submitDecision("changes_requested")}
        disabled={!canRequestChanges}
      >
        Request Changes
      </button>
    </div>
  </div>
)}

<div className="flex gap-2">
  <textarea
    value={message}
    onChange={(e) => setMessage(e.target.value)}
    placeholder="Ask the agent..."
  />
  <button disabled={!message.trim()}>
    <ArrowUp />
  </button>
</div>
    </div>
  );
}

import {
  AlertTriangle,
  ArrowRight,
  Check,
  Edit3,
  FileSearch,
  Layers,
  Lightbulb,
  Loader2,
  Minus,
  Package,
  Play,
  Plus,
  Sparkles,
  Swords,
  TrendingDown,
  TrendingUp,
  Users,
  X,
} from "lucide-react";
import { useRef, useState } from "react";
import { useParams } from "react-router-dom";

import { useCompanyValueContext } from "@/contexts/CompanyContextProvider";
import { useHardenAllKPIs, useHardenKPI, useMergedContext } from "@/hooks/useDomainPacks";
import { useHypothesisOutput, useRunHypothesisAgent } from "@/hooks/useHypothesis";
import type { NormalizedHypothesis } from "@/hooks/useHypothesis";
import { cn } from "@/lib/utils";

// Inline-editable text field
function EditableField({
  value,
  onSave,
  className,
}: {
  value: string;
  onSave: (v: string) => void;
  className?: string;
}) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value);

  if (editing) {
    return (
      <div className="flex items-center gap-1">
        <input
          autoFocus
          value={draft}
          onChange={(e) => setDraft(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter") { onSave(draft); setEditing(false); }
            if (e.key === "Escape") { setDraft(value); setEditing(false); }
          }}
          className={cn("bg-white border border-zinc-300 rounded-lg px-2 py-1 text-[13px] outline-none focus:border-zinc-500", className)}
        />
        <button onClick={() => { onSave(draft); setEditing(false); }} className="p-1 rounded hover:bg-zinc-100">
          <Check className="w-3 h-3 text-emerald-600" />
        </button>
        <button onClick={() => { setDraft(value); setEditing(false); }} className="p-1 rounded hover:bg-zinc-100">
          <X className="w-3 h-3 text-zinc-400" />
        </button>
      </div>
    );
  }

  return (
    <span
      onClick={() => setEditing(true)}
      className={cn("cursor-pointer hover:bg-zinc-100 rounded px-1 -mx-1 transition-colors group/edit inline-flex items-center gap-1", className)}
    >
      {value}
      <Edit3 className="w-3 h-3 text-zinc-300 opacity-0 group-hover/edit:opacity-100 transition-opacity" />
    </span>
  );
}

// Confidence badge
function ConfidenceBadge({ value, source }: { value: number; source: string }) {
  return (
    <div className="flex items-center gap-1.5">
      <div className="w-10 h-1.5 bg-zinc-100 rounded-full overflow-hidden">
        <div
          className={cn(
            "h-full rounded-full",
            value >= 90 ? "bg-emerald-500" : value >= 75 ? "bg-blue-500" : value >= 50 ? "bg-amber-500" : "bg-red-400"
          )}
          style={{ width: `${value}%` }}
        />
      </div>
      <span className="text-[10px] font-medium text-zinc-500">{value}%</span>
      <span className="text-[10px] text-zinc-300">·</span>
      <span className="text-[10px] text-zinc-400">{source}</span>
    </div>
  );
}

// Direction icon for KPI
function DirectionIcon({ direction }: { direction: "up" | "down" | "neutral" }) {
  if (direction === "up") return <TrendingUp className="w-3 h-3 text-emerald-500" />;
  if (direction === "down") return <TrendingDown className="w-3 h-3 text-blue-500" />;
  return <Minus className="w-3 h-3 text-zinc-400" />;
}

// Ghost KPI card — suggested by domain pack, not yet in the case
function GhostKPICard({
  kpi,
  onAccept,
  isAccepting,
}: {
  kpi: MergedKPI;
  onAccept: () => void;
  isAccepting: boolean;
}) {
  return (
    <div className={cn(
      "bg-white border rounded-xl p-4 transition-all",
      kpi.hardened
        ? "border-zinc-200"
        : "border-dashed border-zinc-300 bg-zinc-50/50 hover:border-zinc-400"
    )}>
      <div className="flex items-center justify-between mb-2">
        <div className="flex items-center gap-2">
          <DirectionIcon direction={kpi.direction} />
          <span className="text-[13px] font-semibold text-zinc-900">{kpi.name}</span>
          {kpi.unit && (
            <span className="text-[10px] px-1.5 py-0.5 bg-zinc-100 rounded text-zinc-500">{kpi.unit}</span>
          )}
        </div>
        <div className="flex items-center gap-2">
          {kpi.category && (
            <span className="text-[10px] px-2 py-0.5 rounded-full bg-zinc-100 text-zinc-500 font-medium">
              {kpi.category}
            </span>
          )}
          {kpi.hardened ? (
            <span className="flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full bg-emerald-50 text-emerald-700 font-semibold">
              <Check className="w-2.5 h-2.5" />
              Added
            </span>
          ) : (
            <span className="text-[10px] px-2 py-0.5 rounded-full bg-blue-50 text-blue-600 font-semibold">
              Suggested
            </span>
          )}
        </div>
      </div>

      {kpi.description && (
        <p className="text-[12px] text-zinc-500 mb-2">{kpi.description}</p>
      )}

      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          {kpi.baseline_hint && (
            <span className="text-[11px] text-zinc-400 italic">{kpi.baseline_hint}</span>
          )}
          {kpi.target_hint && !kpi.baseline_hint && (
            <span className="text-[11px] text-zinc-400 italic">{kpi.target_hint}</span>
          )}
        </div>

        {!kpi.hardened && (
          <button
            onClick={onAccept}
            disabled={isAccepting}
            className="flex items-center gap-1 px-3 py-1.5 text-[11px] font-medium text-zinc-700 border border-zinc-200 rounded-lg hover:bg-zinc-100 transition-colors disabled:opacity-50"
          >
            <Plus className="w-3 h-3" />
            Accept
          </button>
        )}
      </div>
    </div>
  );
}

// Domain Pack KPIs section
function DomainPackKPIs() {
  const { caseId } = useParams();
  const { data: merged, isLoading } = useMergedContext(caseId);
  const hardenKPI = useHardenKPI();
  const hardenAll = useHardenAllKPIs();

  if (!caseId || isLoading || !merged?.pack) return null;
  if (merged.kpis.length === 0) return null;

  const ghostCount = merged.kpis.filter(k => !k.hardened).length;

  return (
    <div className="bg-white border border-zinc-200 rounded-2xl p-5">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <Layers className="w-4 h-4 text-violet-600" />
          <h4 className="text-[13px] font-semibold text-zinc-900">
            {merged.pack.name} KPIs
          </h4>
          <span className="text-[11px] text-zinc-400">
            {merged.kpis.length} metrics · {ghostCount} suggested
          </span>
        </div>
        {ghostCount > 0 && (
          <button
            onClick={() => hardenAll.mutate({ caseId })}
            disabled={hardenAll.isPending}
            className="flex items-center gap-1.5 px-3 py-1.5 bg-zinc-950 text-white rounded-lg text-[11px] font-medium hover:bg-zinc-800 transition-colors disabled:opacity-50"
          >
            <ArrowRight className="w-3 h-3" />
            {hardenAll.isPending ? "Adding..." : `Add all ${ghostCount} KPIs`}
          </button>
        )}
      </div>

      <div className="space-y-2">
        {merged.kpis.map((kpi) => (
          <GhostKPICard
            key={kpi.kpi_key}
            kpi={kpi}
            onAccept={() => hardenKPI.mutate({ caseId, kpiKey: kpi.kpi_key })}
            isAccepting={hardenKPI.isPending}
          />
        ))}
      </div>
    </div>
  );
}

// Domain Pack Assumptions section — shows financial defaults with origin labels
function DomainPackAssumptions() {
  const { caseId } = useParams();
  const { data: merged, isLoading } = useMergedContext(caseId);

  if (!caseId || isLoading || !merged?.pack) return null;
  if (merged.assumptions.length === 0) return null;

  const originLabel = (origin: string) => {
    if (origin === "domain_pack") return { text: "Domain Default", color: "bg-violet-50 text-violet-700" };
    if (origin === "manual") return { text: "User Override", color: "bg-emerald-50 text-emerald-700" };
    return { text: "System Default", color: "bg-zinc-100 text-zinc-500" };
  };

  const formatValue = (a: typeof merged.assumptions[0]) => {
    if (a.value_type === "bool") return a.value ? "Yes" : "No";
    if (a.value_type === "number" && a.unit) return `${a.value}${a.unit}`;
    return String(a.value ?? "—");
  };

  return (
    <div className="bg-white border border-zinc-200 rounded-2xl p-5">
      <div className="flex items-center gap-2 mb-4">
        <Layers className="w-4 h-4 text-amber-600" />
        <h4 className="text-[13px] font-semibold text-zinc-900">Financial Assumptions</h4>
        <span className="text-[11px] text-zinc-400">{merged.assumptions.length} parameters</span>
      </div>

      <div className="grid grid-cols-2 gap-2">
        {merged.assumptions.map((a) => {
          const origin = originLabel(a.origin);
          return (
            <div
              key={a.assumption_key}
              className={cn(
                "p-3 rounded-xl border transition-colors",
                a.hardened ? "bg-white border-zinc-200" : "bg-zinc-50/50 border-dashed border-zinc-300"
              )}
            >
              <div className="flex items-center justify-between mb-1">
                <span className="text-[11px] text-zinc-400">{a.display_name}</span>
                <span className={cn("text-[9px] px-1.5 py-0.5 rounded-full font-semibold", origin.color)}>
                  {origin.text}
                </span>
              </div>
              <p className="text-lg font-black text-zinc-950 tracking-tight">{formatValue(a)}</p>
              {a.description && (
                <p className="text-[10px] text-zinc-400 mt-0.5">{a.description}</p>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

interface HypothesisStageProps {
  /**
   * Called when an agent run is started.
   * jobId is always provided; directResult is populated for direct-mode runs
   * so AgentThread can show the result without polling.
   */
  onRunStarted?: (jobId: string, directResult?: import("@/hooks/useAgentJob").AgentJobResult) => void;
}

export function HypothesisStage({ onRunStarted }: HypothesisStageProps) {
  const { caseId } = useParams<{ caseId: string }>();
  const { companyContext, isReady } = useCompanyValueContext();

  const { data: hypothesisOutput, isLoading, isError } = useHypothesisOutput(caseId);
  const runAgent = useRunHypothesisAgent(caseId);

  const hypotheses: NormalizedHypothesis[] = hypothesisOutput?.hypotheses ?? [];

  const confidenceToPercent = (c: number) => Math.round(c * 100);

  // Debounce guard — prevents duplicate BullMQ job enqueues from rapid clicks
  // during the brief window before runAgent.isPending becomes true.
  const isSubmittingRef = useRef(false);

  const handleRunStage = () => {
    if (isSubmittingRef.current || runAgent.isPending) return;
    isSubmittingRef.current = true;

    const companyName = companyContext?.context.company_name;
    runAgent.mutate(
      { companyName, query: companyName ? `Analyze value opportunities for ${companyName}` : undefined },
      {
        onSuccess: (data) => {
          isSubmittingRef.current = false;
          if (!data.jobId) return;
          // For direct-mode runs, pass the pre-resolved result so AgentThread
          // skips polling and shows the result immediately.
          if (data.mode === "direct") {
            onRunStarted?.(data.jobId, {
              jobId: data.jobId,
              status: data.status === "completed" ? "completed" : "failed",
              agentId: data.agentId,
              mode: "direct",
              result: data.result,
              confidence: data.confidence,
              reasoning: data.reasoning,
              warnings: data.warnings,
            });
          } else {
            onRunStarted?.(data.jobId);
          }
        },
        onError: () => {
          isSubmittingRef.current = false;
        },
      },
    );
  };

  return (
    <div className="space-y-5">
      {/* Hypothesis header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Lightbulb className="w-4 h-4 text-blue-600" />
          <h4 className="text-[13px] font-semibold text-zinc-900">Hypotheses</h4>
          {!isLoading && (
            <span className="text-[11px] text-zinc-400">{hypotheses.length} claims</span>
          )}
        </div>
        <button
          onClick={handleRunStage}
          disabled={runAgent.isPending || isLoading || isSubmittingRef.current}
          className="flex items-center gap-1.5 px-3 py-1.5 bg-zinc-950 text-white rounded-xl text-[12px] font-medium hover:bg-zinc-800 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {runAgent.isPending ? (
            <Loader2 className="w-3 h-3 animate-spin" />
          ) : (
            <Play className="w-3 h-3" />
          )}
          {runAgent.isPending ? "Running…" : hypotheses.length > 0 ? "Re-run Stage" : "Run Stage"}
        </button>
      </div>

      {/* Loading state */}
      {isLoading && (
        <div className="flex items-center justify-center py-12 text-zinc-400">
          <Loader2 className="w-5 h-5 animate-spin mr-2" />
          <span className="text-[13px]">Loading hypothesis data…</span>
        </div>
      )}

      {/* Error state */}
      {isError && !isLoading && (
        <div role="alert" className="bg-red-50 border border-red-200 rounded-2xl p-4 text-[13px] text-red-700 flex items-center justify-between">
          <span>Failed to load hypothesis data. Try running the stage again.</span>
          <button
            onClick={() => runAgent.mutate({})}
            disabled={runAgent.isPending}
            className="ml-3 px-3 py-1 bg-red-600 hover:bg-red-700 disabled:opacity-60 text-white text-[12px] font-medium rounded-lg transition-colors"
          >
            Retry
          </button>
        </div>
      )}

      {/* Agent running state */}
      {runAgent.isPending && (
        <div className="bg-blue-50 border border-blue-200 rounded-2xl p-4 flex items-center gap-3">
          <Loader2 className="w-4 h-4 text-blue-600 animate-spin flex-shrink-0" />
          <div>
            <p className="text-[13px] font-medium text-blue-900">Opportunity Agent running…</p>
            <p className="text-[11px] text-blue-600 mt-0.5">Fetching financial data and generating hypotheses</p>
          </div>
        </div>
      )}

      {/* Agent error */}
      {runAgent.isError && (
        <div role="alert" className="bg-red-50 border border-red-200 rounded-2xl p-4 text-[13px] text-red-700 flex items-center justify-between">
          <span>Agent run failed: {runAgent.error?.message ?? "Unknown error"}</span>
          <button
            onClick={() => runAgent.mutate({})}
            disabled={runAgent.isPending}
            className="ml-3 px-3 py-1 bg-red-600 hover:bg-red-700 disabled:opacity-60 text-white text-[12px] font-medium rounded-lg transition-colors"
          >
            Retry
          </button>
        </div>
      )}

      {/* Empty state — no run yet */}
      {!isLoading && !runAgent.isPending && hypotheses.length === 0 && (
        <div className="bg-zinc-50 border border-dashed border-zinc-300 rounded-2xl p-8 text-center">
          <Lightbulb className="w-8 h-8 text-zinc-300 mx-auto mb-3" />
          <p className="text-[14px] font-medium text-zinc-600">No hypotheses yet</p>
          <p className="text-[12px] text-zinc-400 mt-1">Click "Run Stage" to have the Opportunity Agent generate value hypotheses.</p>
        </div>
      )}

      {/* Hypothesis cards — live data */}
      {hypotheses.length > 0 && (
        <div className="space-y-3">
          {hypotheses.map((h, i) => {
            const confidencePct = confidenceToPercent(h.presentation.confidenceScore);
            const status = confidencePct >= 75 ? "verified" : confidencePct >= 50 ? "needs-evidence" : "draft";
            const statusConfig = {
              verified: { label: "Verified", color: "text-emerald-700", bg: "bg-emerald-50", icon: Check },
              "needs-evidence": { label: "Needs Evidence", color: "text-amber-700", bg: "bg-amber-50", icon: AlertTriangle },
              draft: { label: "Draft", color: "text-zinc-500", bg: "bg-zinc-100", icon: Edit3 },
            };
            const st = statusConfig[status];
            const StIcon = st.icon;

            return (
              <div key={h.entity.id ?? `${h.entity.description}-${i}`} className="bg-white border border-zinc-200 rounded-2xl p-5 hover:border-zinc-300 transition-colors">
                {/* Status + confidence row */}
                <div className="flex items-center justify-between mb-3">
                  <div className={cn("flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-semibold", st.color, st.bg)}>
                    <StIcon className="w-3 h-3" />
                    <span>{st.label}</span>
                  </div>
                  <ConfidenceBadge value={confidencePct} source={h.entity.category} />
                </div>

                {/* Title + description */}
                <p className="text-[14px] font-semibold text-zinc-900 mb-1">{h.presentation.title}</p>
                <p className="text-[13px] text-zinc-600 leading-relaxed mb-3">{h.entity.description}</p>

                {/* Impact range */}
                {h.entity.estimated_value && (
                  <div className="flex items-center gap-2 mb-3">
                    <span className="text-[10px] font-semibold uppercase tracking-[0.15em] text-zinc-400">Impact:</span>
                    <span className="text-[12px] font-medium text-zinc-700">
                      {h.entity.estimated_value.low}–{h.entity.estimated_value.high} {h.entity.estimated_value.unit}
                      {" "}over {h.entity.estimated_value.timeframe_months}mo
                    </span>
                  </div>
                )}

                {/* Evidence chain */}
                {h.presentation.evidence.length > 0 && (
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className="text-[10px] font-semibold uppercase tracking-[0.15em] text-zinc-400">Evidence:</span>
                    {h.presentation.evidence.map((e) => (
                      <span key={e} className="flex items-center gap-1 px-2 py-0.5 bg-zinc-50 border border-zinc-100 rounded-md text-[10px] text-zinc-600">
                        <FileSearch className="w-2.5 h-2.5" />
                        {e}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Metadata footer when output exists */}
      {hypothesisOutput && (
        <div className="text-[11px] text-zinc-400 text-right">
          Last run: {new Date(hypothesisOutput.created_at).toLocaleString()} · confidence: {hypothesisOutput.confidence ?? "—"}
        </div>
      )}

      {/* Domain Pack KPIs — ghost suggestions from the selected pack */}
      <DomainPackKPIs />

      {/* Domain Pack Assumptions — financial defaults from the selected pack */}
      <DomainPackAssumptions />

      {/* Company intelligence — from CompanyValueContext when available */}
      <div className="bg-white border border-zinc-200 rounded-2xl p-5">
        <div className="flex items-center gap-2 mb-4">
          <Sparkles className="w-4 h-4 text-zinc-500" />
          <h4 className="text-[13px] font-semibold text-zinc-900">Company Intelligence</h4>
          <span className={cn(
            "ml-auto text-[10px] px-2 py-0.5 rounded-full font-semibold",
            isReady ? "bg-emerald-50 text-emerald-700" : "bg-blue-50 text-blue-700"
          )}>
            {isReady ? "From onboarding" : "Auto-populated"}
          </span>
        </div>

        {isReady && companyContext ? (
          <>
            {/* Real data from company context */}
            <div className="grid grid-cols-2 gap-3 mb-4">
              <div className="p-3 bg-zinc-50 rounded-xl">
                <p className="text-[11px] text-zinc-400">Company</p>
                <p className="text-lg font-black text-zinc-950 tracking-tight">{companyContext.context.company_name}</p>
                <p className="text-[11px] font-medium text-zinc-500 capitalize">
                  {companyContext.context.industry || "—"} · {companyContext.context.company_size?.replace("_", " ") || "—"}
                </p>
              </div>
              <div className="p-3 bg-zinc-50 rounded-xl">
                <p className="text-[11px] text-zinc-400">Sales Motion</p>
                <p className="text-lg font-black text-zinc-950 tracking-tight capitalize">
                  {companyContext.context.sales_motion?.replace("_", " ") || "—"}
                </p>
                <p className="text-[11px] font-medium text-zinc-500">
                  {companyContext.context.annual_revenue || "Revenue not set"}
                </p>
              </div>
            </div>

            {/* Products from context */}
            {companyContext.products.length > 0 && (
              <div className="mb-4">
