import { ExternalLink, FileSearch, RotateCcw, ThumbsDown, ThumbsUp } from "lucide-react";

import { type DisplayClaim, statusConfig, tierColorMap } from "./integrityUtils";

import { cn } from "@/lib/utils";


interface ClaimCardProps {
  claim: DisplayClaim;
}

export function ClaimCard({ claim }: ClaimCardProps) {
  const st = statusConfig[claim.status];
  const StIcon = st.icon;
  const tierKey = claim.tier.split(":")[0]?.trim() ?? "Tier 3";
  const tc = tierColorMap[tierKey] ?? tierColorMap["Tier 3"]!;

  return (
    <div
      className={cn(
        "p-4 rounded-2xl border transition-colors",
        claim.status === "flagged"
          ? "border-amber-200 bg-amber-50/30"
          : claim.status === "rejected"
          ? "border-red-200 bg-red-50/30"
          : "border-zinc-200 bg-white",
      )}
    >
      {/* Status badge + tier + confidence */}
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <div
            className={cn(
              "flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-semibold",
              st.color,
              st.bg,
            )}
          >
            <StIcon className="w-3 h-3" />
            <span>{st.label}</span>
          </div>
          <span className={cn("text-[10px] px-2 py-0.5 rounded-full font-semibold", tc.color, tc.bg)}>
            {claim.tier}
          </span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className="w-12 h-1.5 bg-zinc-100 rounded-full overflow-hidden">
            <div
              className={cn(
                "h-full rounded-full",
                claim.confidence >= 90 ? "bg-emerald-500"
                  : claim.confidence >= 75 ? "bg-blue-500"
                  : claim.confidence >= 50 ? "bg-amber-500"
                  : "bg-red-400",
              )}
              style={{ width: `${claim.confidence}%` }}
            />
          </div>
          <span className="text-[11px] font-medium text-zinc-600">{claim.confidence}%</span>
        </div>
      </div>

      {/* Claim text */}
      <p className="text-[13px] text-zinc-800 font-medium mb-2">{claim.text}</p>

      {/* Evidence tier label */}
      <div className="flex items-center gap-1.5 mb-3">
        <FileSearch className="w-3 h-3 text-zinc-400" />
        <span className="text-[11px] text-zinc-500">{claim.tier}</span>
        <ExternalLink className="w-3 h-3 text-zinc-300 cursor-pointer hover:text-zinc-500" />
      </div>

      {/* Objection (flagged claims only) */}
      {claim.objection && (
        <div className="p-3 rounded-xl bg-amber-50 border border-amber-100 mb-3">
          <p className="text-[11px] font-semibold text-amber-800 mb-1">Objection</p>
          <p className="text-[12px] text-amber-700">{claim.objection}</p>
        </div>
      )}

      {/* Actions (flagged claims only) */}
      {claim.status === "flagged" && (
        <div className="flex items-center gap-2 pt-2 border-t border-zinc-100">
          <button className="flex items-center gap-1.5 px-3 py-1.5 bg-zinc-950 text-white rounded-lg text-[11px] font-medium hover:bg-zinc-800">
            <RotateCcw className="w-3 h-3" />
            Revise Claim
          </button>
          <button className="flex items-center gap-1.5 px-3 py-1.5 border border-zinc-200 rounded-lg text-[11px] font-medium text-zinc-600 hover:bg-zinc-50">
            <ThumbsUp className="w-3 h-3" />
            Override
          </button>
          <button className="flex items-center gap-1.5 px-3 py-1.5 border border-zinc-200 rounded-lg text-[11px] font-medium text-zinc-600 hover:bg-zinc-50">
            <ThumbsDown className="w-3 h-3" />
            Remove
          </button>
        </div>
      )}
    </div>
  );
}

import { Building2, Globe, Loader2, Package, Plus, Sparkles, X } from "lucide-react";
import { useState } from "react";

import type { OnboardingPhase1Input } from "@/hooks/company-context/types";
import type { ResearchJob, ResearchSuggestion } from "@/hooks/company-context/types";
import { cn } from "@/lib/utils";

interface Props {
  onNext: (
    data: OnboardingPhase1Input,
    researchJobId?: string,
    options?: { fastTrack: boolean }
  ) => void;
  researchJob?: ResearchJob | null;
  researchSuggestions?: ResearchSuggestion[];
  onStartResearch?: (
    website: string,
    industry: string,
    companySize: string | null,
    salesMotion: string | null,
    ticker?: string
  ) => void;
  isResearching?: boolean;
}

export function Phase1Company({ onNext, researchJob, researchSuggestions, onStartResearch, isResearching }: Props) {
  const [companyName, setCompanyName] = useState("");
  const [websiteUrl, setWebsiteUrl] = useState("");
  const [industry, setIndustry] = useState("");
  const [ticker, setTicker] = useState("");
  const [companySize, setCompanySize] = useState<OnboardingPhase1Input["company_size"]>(null);
  const [salesMotion, setSalesMotion] = useState<OnboardingPhase1Input["sales_motion"]>(null);
  const [fastTrackMode, setFastTrackMode] = useState(true);
  const [products, setProducts] = useState<OnboardingPhase1Input["products"]>([
    { name: "", description: "", product_type: "platform" },
  ]);

  // Pre-populate products from suggestions when research completes
  const productSuggestions = researchSuggestions?.filter(
    (s) => s.entity_type === "product" && s.status === "suggested"
  ) ?? [];

  const hasResearchCompleted = researchJob?.status === "completed";
  const hasResearchFailed = researchJob?.status === "failed";
  const isResearchRunning = researchJob?.status === "running" || researchJob?.status === "queued";

  const [hasPrePopulated, setHasPrePopulated] = useState(false);
  if (hasResearchCompleted && productSuggestions.length > 0 && !hasPrePopulated) {
    const suggestedProducts = productSuggestions.map((s) => ({
      name: (s.payload as Record<string, string>).name ?? "",
      description: (s.payload as Record<string, string>).description ?? "",
      product_type: ((s.payload as Record<string, string>).product_type ?? "platform") as OnboardingPhase1Input["products"][0]["product_type"],
    }));
    const existingFilled = products.filter((p) => p.name.trim().length > 0);
    setProducts([...existingFilled, ...suggestedProducts]);
    setHasPrePopulated(true);
  }

  const addProduct = () => setProducts([...products, { name: "", description: "", product_type: "module" }]);
  const removeProduct = (i: number) => setProducts(products.filter((_, idx) => idx !== i));
  const updateProduct = (i: number, field: string, value: string) => {
    setProducts(products.map((p, idx) => (idx === i ? { ...p, [field]: value } : p)));
  };

  const canProceed = companyName.trim().length > 0 && products.some((p) => p.name.trim().length > 0);
  const canAutoFill = websiteUrl.trim().length > 0 && websiteUrl.includes(".") && !isResearching && !isResearchRunning;

  const handleSubmit = () => {
    onNext(
      {
        company_name: companyName.trim(),
        website_url: websiteUrl.trim(),
        industry: industry.trim(),
        ticker: ticker.trim() || undefined,
        company_size: companySize,
        sales_motion: salesMotion,
        products: products.filter((p) => p.name.trim().length > 0),
      },
      researchJob?.id,
      { fastTrack: fastTrackMode },
    );
  };

  const handleAutoFill = () => {
    if (onStartResearch && canAutoFill) {
      onStartResearch(websiteUrl.trim(), industry.trim(), companySize, salesMotion, ticker.trim());
    }
  };

  const sizeOptions: Array<{ value: OnboardingPhase1Input["company_size"]; label: string }> = [
    { value: "smb", label: "SMB" },
    { value: "mid_market", label: "Mid-Market" },
    { value: "enterprise", label: "Enterprise" },
  ];

  const motionOptions: Array<{ value: OnboardingPhase1Input["sales_motion"]; label: string }> = [
    { value: "new_logo", label: "New Logo" },
    { value: "expansion", label: "Expansion" },
    { value: "land_and_expand", label: "Land & Expand" },
    { value: "renewal", label: "Renewal" },
  ];

  const entityStatus = researchJob?.entity_status ?? {};
  const entityTypes = ["product", "competitor", "persona", "claim", "capability", "value_pattern", "sec_filing"];

  return (
    <div className="space-y-6">
      <div>
        <div className="flex items-center gap-3 mb-2">
          <div className="w-10 h-10 bg-blue-50 rounded-xl flex items-center justify-center">
            <Building2 className="w-5 h-5 text-blue-600" />
          </div>
          <div>
            <h2 className="text-[16px] font-black text-zinc-950 tracking-tight">Your Company</h2>
            <p className="text-[12px] text-zinc-400">Tell us about your business so every value case starts smarter</p>
          </div>
        </div>
      </div>

      {/* Company basics */}
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-400 mb-1.5 block">
            Company Name *
          </label>
          <input
            value={companyName}
            onChange={(e) => setCompanyName(e.target.value)}
            placeholder="e.g. Acme Corp"
            className="w-full px-4 py-3 rounded-xl border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400 transition-colors"
          />
        </div>
        <div>
          <label className="text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-400 mb-1.5 block">
            Website
          </label>
          <div className="relative">
            <Globe className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400" />
            <input
              value={websiteUrl}
              onChange={(e) => setWebsiteUrl(e.target.value)}
              placeholder="https://acme.com"
              className="w-full pl-10 pr-4 py-3 rounded-xl border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400 transition-colors"
            />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-400 mb-1.5 block">
            Industry
          </label>
          <input
            value={industry}
            onChange={(e) => setIndustry(e.target.value)}
            placeholder="e.g. SaaS, FinTech"
            className="w-full px-4 py-3 rounded-xl border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400 transition-colors"
          />
        </div>
        <div>
          <label className="text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-400 mb-1.5 block">
            Ticker / CIK (optional)
          </label>
          <input
            value={ticker}
            onChange={(e) => setTicker(e.target.value)}
            placeholder="e.g. MSFT or 0000789019"
            className="w-full px-4 py-3 rounded-xl border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400 transition-colors"
          />
        </div>
      </div>

      {/* Company size */}
      <div>
        <label className="text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-400 mb-2 block">
          Company Size
        </label>
        <div className="flex gap-2">
          {sizeOptions.map((opt) => (
            <button
              key={opt.value}
              onClick={() => setCompanySize(opt.value)}
              className={cn(
                "flex-1 py-2.5 rounded-xl border text-[12px] font-medium transition-colors",
                companySize === opt.value
                  ? "border-zinc-950 bg-zinc-950 text-white"
                  : "border-zinc-200 text-zinc-600 hover:border-zinc-300"
              )}
            >
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      {/* Sales motion */}
      <div>
        <label className="text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-400 mb-2 block">
          Primary Sales Motion
        </label>
        <div className="flex gap-2">
          {motionOptions.map((opt) => (
            <button
              key={opt.value}
              onClick={() => setSalesMotion(opt.value)}
              className={cn(
                "flex-1 py-2.5 rounded-xl border text-[12px] font-medium transition-colors",
                salesMotion === opt.value
                  ? "border-zinc-950 bg-zinc-950 text-white"
                  : "border-zinc-200 text-zinc-600 hover:border-zinc-300"
              )}
            >
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      {/* Auto-fill from website */}
      {onStartResearch && (
        <div className="space-y-3">
          <div className="p-4 rounded-xl border border-zinc-200 bg-white">
            <button
              type="button"
              onClick={() => setFastTrackMode((prev) => !prev)}
              className="w-full flex items-start justify-between gap-3 text-left"
            >
              <div>
                <p className="text-[13px] font-semibold text-zinc-900">Fast-track onboarding</p>
                <p className="text-[12px] text-zinc-500 mt-1">
                  Use an AI research agent to scan your website and public signals, then preload competitors,
                  personas, and claims so you can review and launch faster.
                </p>
              </div>
              <span
                className={cn(
                  "mt-0.5 inline-flex h-6 min-w-11 items-center rounded-full p-1 transition-colors",
                  fastTrackMode ? "bg-zinc-900" : "bg-zinc-300"
                )}
                aria-label="Toggle fast-track onboarding"
              >
                <span
                  className={cn(
                    "h-4 w-4 rounded-full bg-white transition-transform",
                    fastTrackMode ? "translate-x-5" : "translate-x-0"
                  )}
                />
              </span>
            </button>
          </div>

          {!researchJob && (
            <button
              onClick={handleAutoFill}
              disabled={!canAutoFill}
              className={cn(
                "w-full flex items-center justify-center gap-2 py-3 rounded-xl border text-[12px] font-medium transition-colors",
                canAutoFill
                  ? "border-blue-200 bg-blue-50 text-blue-700 hover:bg-blue-100"
                  : "border-zinc-200 bg-zinc-50 text-zinc-400 cursor-not-allowed"
              )}
            >
              <Sparkles className="w-4 h-4" />
              {fastTrackMode ? "Run AI fast-track research" : "Auto-fill from website"}
            </button>
          )}

          {(isResearchRunning || isResearching) && (
            <div className="p-4 rounded-xl border border-blue-100 bg-blue-50/50 space-y-3">
              <div className="flex items-center gap-2">
                <Loader2 className="w-4 h-4 text-blue-500 animate-spin" />
                <span className="text-[12px] font-medium text-blue-700">Analyzing website...</span>
              </div>
              <div className="grid grid-cols-3 gap-2">
                {entityTypes.map((et) => {
                  const status = entityStatus[et] ?? "pending";
                  const statusColors: Record<string, string> = {
                    pending: "bg-zinc-100 text-zinc-400",
                    running: "bg-blue-100 text-blue-600",
                    completed: "bg-emerald-100 text-emerald-700",
                    done: "bg-emerald-100 text-emerald-700",
                    failed: "bg-red-100 text-red-600",
                  };
                  return (
                    <div
                      key={et}
                      className={cn(
                        "px-2 py-1.5 rounded-lg text-[10px] font-medium text-center capitalize",
                        statusColors[status] ?? "bg-zinc-100 text-zinc-400"
                      )}
                    >
                      {et.replace("_", " ")}
                      {status === "running" && (
                        <Loader2 className="w-3 h-3 inline ml-1 animate-spin" />
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {hasResearchCompleted && (
            <div className="p-3 rounded-xl border border-emerald-100 bg-emerald-50/50 flex items-center gap-2">
              <Sparkles className="w-4 h-4 text-emerald-600" />
              <span className="text-[12px] text-emerald-700 font-medium">
                Research complete — products pre-populated below. Suggestions for competitors, personas, and claims will appear in the next steps.
              </span>
            </div>
          )}

          {hasResearchFailed && (
            <div className="p-3 rounded-xl border border-red-100 bg-red-50/50">
              <span className="text-[12px] text-red-700">
                Research failed: {researchJob?.error_message ?? "Unknown error"}. You can continue manually.
              </span>
            </div>
          )}
        </div>
      )}

      {/* Products */}
      <div>
        <div className="flex items-center justify-between mb-2">
          <label className="text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-400">
            Products / Solutions *
          </label>
          <button
            onClick={addProduct}
            className="flex items-center gap-1 text-[11px] text-zinc-500 hover:text-zinc-700 transition-colors"
          >
            <Plus className="w-3 h-3" /> Add
          </button>
        </div>
        <div className="space-y-3">
          {products.map((p, i) => (
            <div key={i} className="flex items-start gap-3 p-4 rounded-xl border border-zinc-200 bg-zinc-50/50">
              <Package className="w-4 h-4 text-zinc-400 mt-2.5 flex-shrink-0" />
              <div className="flex-1 space-y-2">
                <input
                  value={p.name}
                  onChange={(e) => updateProduct(i, "name", e.target.value)}
                  placeholder="Product name"
                  className="w-full px-3 py-2 rounded-lg border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400"
                />
                <input
                  value={p.description}
                  onChange={(e) => updateProduct(i, "description", e.target.value)}
                  placeholder="Brief description — what does it do for customers?"
                  className="w-full px-3 py-2 rounded-lg border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400"
                />
                <select
                  value={p.product_type ?? "platform"}
                  onChange={(e) => updateProduct(i, "product_type", e.target.value)}
                  className="px-3 py-2 rounded-lg border border-zinc-200 text-[12px] bg-white text-zinc-600 outline-none"
                >
                  <option value="platform">Platform</option>
                  <option value="module">Module</option>
                  <option value="service">Service</option>
                  <option value="add_on">Add-on</option>
                </select>
              </div>
              {products.length > 1 && (
                <button onClick={() => removeProduct(i)} className="p-1 rounded hover:bg-zinc-200 mt-2">
                  <X className="w-3.5 h-3.5 text-zinc-400" />
                </button>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Next */}
      <div className="flex justify-end pt-2">
        <button
          onClick={handleSubmit}
          disabled={!canProceed}
          className={cn(
            "px-6 py-3 rounded-xl text-[13px] font-medium transition-colors",
            canProceed
              ? "bg-zinc-950 text-white hover:bg-zinc-800"
              : "bg-zinc-100 text-zinc-400 cursor-not-allowed"
          )}
        >
          Continue
        </button>
      </div>
    </div>
  );
}

import { Plus, Swords, X } from "lucide-react";
import { useState } from "react";

import { SuggestionSection } from "@/components/onboarding/SuggestionCard";
import { useTenant } from "@/contexts/TenantContext";
import type { CompanyCompetitor, OnboardingPhase2Input } from "@/hooks/company-context/types";
import { useAcceptSuggestion, useRejectSuggestion, useResearchSuggestions } from "@/hooks/company-context/useResearchJob";
import { cn } from "@/lib/utils";

interface Props {
  onNext: (data: OnboardingPhase2Input) => void;
  onBack: () => void;
  researchJobId?: string | null;
}

type Relationship = NonNullable<CompanyCompetitor["relationship"]>;

export function Phase2Competitors({ onNext, onBack, researchJobId }: Props) {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id ?? "default";
  const { data: suggestions } = useResearchSuggestions(researchJobId ?? null, "competitor");
  const acceptMutation = useAcceptSuggestion(tenantId);
  const rejectMutation = useRejectSuggestion(tenantId);

  const [competitors, setCompetitors] = useState<
    Array<{ name: string; website_url: string; relationship: Relationship }>
  >([{ name: "", website_url: "", relationship: "direct" }]);

  const add = () => setCompetitors([...competitors, { name: "", website_url: "", relationship: "direct" }]);
  const remove = (i: number) => setCompetitors(competitors.filter((_, idx) => idx !== i));
  const update = (i: number, field: string, value: string) => {
    setCompetitors(competitors.map((c, idx) => (idx === i ? { ...c, [field]: value } : c)));
  };

  const filled = competitors.filter((c) => c.name.trim().length > 0);

  const relationships: Array<{ value: Relationship; label: string }> = [
    { value: "direct", label: "Direct" },
    { value: "indirect", label: "Indirect" },
    { value: "incumbent", label: "Incumbent" },
    { value: "emerging", label: "Emerging" },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3 mb-2">
        <div className="w-10 h-10 bg-violet-50 rounded-xl flex items-center justify-center">
          <Swords className="w-5 h-5 text-violet-600" />
        </div>
        <div>
          <h2 className="text-[16px] font-black text-zinc-950 tracking-tight">Competitive Landscape</h2>
          <p className="text-[12px] text-zinc-400">Name your competitors so the system knows what to lean into and what to avoid</p>
        </div>
      </div>

      {/* AI Suggestions */}
      {suggestions && suggestions.length > 0 && (
        <SuggestionSection
          suggestions={suggestions}
          onAccept={(s) => {
            acceptMutation.mutate({
              suggestionId: s.id,
              contextId: s.context_id,
              entityType: s.entity_type,
              payload: s.payload as Record<string, unknown>,
            });
            // Also add to local list
            const p = s.payload as Record<string, string>;
            setCompetitors((prev) => [
              ...prev.filter((c) => c.name.trim().length > 0),
              { name: p.name ?? "", website_url: p.website_url ?? "", relationship: (p.relationship ?? "direct") as Relationship },
            ]);
          }}
          onReject={(s) => rejectMutation.mutate(s.id)}
          onEdit={(s, payload) => {
            acceptMutation.mutate({
              suggestionId: s.id,
              contextId: s.context_id,
              entityType: s.entity_type,
              payload,
            });
          }}
          renderPayload={(payload, _isEditing, _onChange) => {
            const p = payload as Record<string, string>;
            return (
              <div className="space-y-1">
                <p className="text-[13px] font-medium text-zinc-900">{p.name}</p>
                {p.website_url && <p className="text-[11px] text-zinc-400">{p.website_url}</p>}
                {p.relationship && (
                  <span className="text-[10px] px-2 py-0.5 rounded-full bg-violet-50 text-violet-700 border border-violet-100 capitalize">
                    {p.relationship}
                  </span>
                )}
              </div>
            );
          }}
          isProcessing={acceptMutation.isPending || rejectMutation.isPending}
        />
      )}

      <div className="space-y-3">
        {competitors.map((c, i) => (
          <div key={i} className="flex items-start gap-3 p-4 rounded-xl border border-zinc-200 bg-zinc-50/50">
            <div className="flex-1 space-y-2">
              <div className="grid grid-cols-2 gap-2">
                <input
                  value={c.name}
                  onChange={(e) => update(i, "name", e.target.value)}
                  placeholder="Competitor name"
                  className="px-3 py-2 rounded-lg border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400"
                />
                <input
                  value={c.website_url}
                  onChange={(e) => update(i, "website_url", e.target.value)}
                  placeholder="Website (optional)"
                  className="px-3 py-2 rounded-lg border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400"
                />
              </div>
              <div className="flex gap-1.5">
                {relationships.map((r) => (
                  <button
                    key={r.value}
                    onClick={() => update(i, "relationship", r.value)}
                    className={cn(
                      "px-3 py-1.5 rounded-lg text-[11px] font-medium border transition-colors",
                      c.relationship === r.value
                        ? "border-violet-300 bg-violet-50 text-violet-700"
                        : "border-zinc-200 text-zinc-500 hover:border-zinc-300"
                    )}
                  >
                    {r.label}
                  </button>
                ))}
              </div>
            </div>
            {competitors.length > 1 && (
              <button onClick={() => remove(i)} className="p-1 rounded hover:bg-zinc-200 mt-1">
                <X className="w-3.5 h-3.5 text-zinc-400" />
              </button>
            )}
          </div>
        ))}
      </div>

      <button
        onClick={add}
        className="flex items-center gap-1.5 px-3 py-2 border border-dashed border-zinc-300 rounded-xl text-[12px] text-zinc-500 hover:border-zinc-400 hover:text-zinc-700 transition-colors w-full justify-center"
      >
        <Plus className="w-3 h-3" /> Add Competitor
      </button>

      <div className="flex justify-between pt-2">
        <button onClick={onBack} className="px-5 py-3 rounded-xl text-[13px] font-medium text-zinc-500 hover:bg-zinc-100 transition-colors">
          Back
        </button>
        <div className="flex gap-2">
          <button
            onClick={() => onNext({ competitors: [] })}
            className="px-5 py-3 rounded-xl text-[13px] font-medium text-zinc-400 hover:text-zinc-600 transition-colors"
          >
            Skip
          </button>
          <button
            onClick={() => onNext({ competitors: filled })}
            disabled={filled.length === 0}
            className={cn(
              "px-6 py-3 rounded-xl text-[13px] font-medium transition-colors",
              filled.length > 0
                ? "bg-zinc-950 text-white hover:bg-zinc-800"
                : "bg-zinc-100 text-zinc-400 cursor-not-allowed"
            )}
          >
            Continue ({filled.length})
          </button>
        </div>
      </div>
    </div>
  );
}

import { Plus, Users, X } from "lucide-react";
import { useState } from "react";

import { SuggestionSection } from "@/components/onboarding/SuggestionCard";
import { useTenant } from "@/contexts/TenantContext";
import type { CompanyPersona, OnboardingPhase3Input } from "@/hooks/company-context/types";
import { useAcceptSuggestion, useRejectSuggestion, useResearchSuggestions } from "@/hooks/company-context/useResearchJob";
import { cn } from "@/lib/utils";

interface Props {
  onNext: (data: OnboardingPhase3Input) => void;
  onBack: () => void;
  researchJobId?: string | null;
}

type PersonaType = NonNullable<CompanyPersona["persona_type"]>;
type Seniority = NonNullable<CompanyPersona["seniority"]>;

interface PersonaDraft {
  title: string;
  persona_type: PersonaType;
  seniority: Seniority;
  kpis: string;
  pains: string;
}

export function Phase3Personas({ onNext, onBack, researchJobId }: Props) {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id ?? "default";
  const { data: suggestions } = useResearchSuggestions(researchJobId ?? null, "persona");
  const acceptMutation = useAcceptSuggestion(tenantId);
  const rejectMutation = useRejectSuggestion(tenantId);

  const [personas, setPersonas] = useState<PersonaDraft[]>([
    { title: "", persona_type: "decision_maker", seniority: "vp", kpis: "", pains: "" },
  ]);

  const add = () =>
    setPersonas([...personas, { title: "", persona_type: "champion", seniority: "director", kpis: "", pains: "" }]);
  const remove = (i: number) => setPersonas(personas.filter((_, idx) => idx !== i));
  const update = (i: number, field: keyof PersonaDraft, value: string) => {
    setPersonas(personas.map((p, idx) => (idx === i ? { ...p, [field]: value } : p)));
  };

  const filled = personas.filter((p) => p.title.trim().length > 0);

  const types: Array<{ value: PersonaType; label: string }> = [
    { value: "decision_maker", label: "Decision Maker" },
    { value: "champion", label: "Champion" },
    { value: "influencer", label: "Influencer" },
    { value: "end_user", label: "End User" },
    { value: "blocker", label: "Blocker" },
  ];

  const seniorities: Array<{ value: Seniority; label: string }> = [
    { value: "c_suite", label: "C-Suite" },
    { value: "vp", label: "VP" },
    { value: "director", label: "Director" },
    { value: "manager", label: "Manager" },
    { value: "individual_contributor", label: "IC" },
  ];

  const handleSubmit = () => {
    onNext({
      personas: filled.map((p) => ({
        title: p.title.trim(),
        persona_type: p.persona_type,
        seniority: p.seniority,
        typical_kpis: p.kpis
          .split(",")
          .map((s) => s.trim())
          .filter(Boolean),
        pain_points: p.pains
          .split(",")
          .map((s) => s.trim())
          .filter(Boolean),
      })),
    });
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3 mb-2">
        <div className="w-10 h-10 bg-emerald-50 rounded-xl flex items-center justify-center">
          <Users className="w-5 h-5 text-emerald-600" />
        </div>
        <div>
          <h2 className="text-[16px] font-black text-zinc-950 tracking-tight">Buyer Personas</h2>
          <p className="text-[12px] text-zinc-400">Who buys from you? This shapes how value narratives are framed</p>
        </div>
      </div>

      {/* AI Suggestions */}
      {suggestions && suggestions.length > 0 && (
        <SuggestionSection
          suggestions={suggestions}
          onAccept={(s) => {
            acceptMutation.mutate({
              suggestionId: s.id,
              contextId: s.context_id,
              entityType: s.entity_type,
              payload: s.payload as Record<string, unknown>,
            });
            const p = s.payload as Record<string, any>;
            setPersonas((prev) => [
              ...prev.filter((x) => x.title.trim().length > 0),
              {
                title: p.title ?? "",
                persona_type: p.persona_type ?? "champion",
                seniority: p.seniority ?? "director",
                kpis: Array.isArray(p.typical_kpis) ? p.typical_kpis.join(", ") : "",
                pains: Array.isArray(p.pain_points) ? p.pain_points.join(", ") : "",
              },
            ]);
          }}
          onReject={(s) => rejectMutation.mutate(s.id)}
          onEdit={(s, payload) => {
            acceptMutation.mutate({
              suggestionId: s.id,
              contextId: s.context_id,
              entityType: s.entity_type,
              payload,
            });
          }}
          renderPayload={(payload, _isEditing, _onChange) => {
            const p = payload as Record<string, any>;
            return (
              <div className="space-y-1">
                <p className="text-[13px] font-medium text-zinc-900">{p.title}</p>
                <div className="flex gap-1.5 flex-wrap">
                  {p.persona_type && (
                    <span className="text-[10px] px-2 py-0.5 rounded-full bg-emerald-50 text-emerald-700 border border-emerald-100 capitalize">
                      {String(p.persona_type).replace("_", " ")}
                    </span>
                  )}
                  {p.seniority && (
                    <span className="text-[10px] px-2 py-0.5 rounded-full bg-zinc-100 text-zinc-500 capitalize">
                      {String(p.seniority).replace("_", " ")}
                    </span>
                  )}
                </div>
                {Array.isArray(p.typical_kpis) && p.typical_kpis.length > 0 && (
                  <p className="text-[11px] text-zinc-500">KPIs: {p.typical_kpis.join(", ")}</p>
                )}
                {Array.isArray(p.pain_points) && p.pain_points.length > 0 && (
                  <p className="text-[11px] text-zinc-500">Pains: {p.pain_points.join(", ")}</p>
                )}
              </div>
            );
          }}
          isProcessing={acceptMutation.isPending || rejectMutation.isPending}
        />
      )}

      <div className="space-y-4">
        {personas.map((p, i) => (
          <div key={i} className="p-4 rounded-xl border border-zinc-200 bg-zinc-50/50 space-y-3">
            <div className="flex items-center justify-between">
              <input
                value={p.title}
                onChange={(e) => update(i, "title", e.target.value)}
                placeholder="e.g. VP of Engineering, CFO, Head of RevOps"
                className="flex-1 px-3 py-2 rounded-lg border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400"
              />
              {personas.length > 1 && (
                <button onClick={() => remove(i)} className="p-1 rounded hover:bg-zinc-200 ml-2">
                  <X className="w-3.5 h-3.5 text-zinc-400" />
                </button>
              )}
            </div>

            <div className="flex gap-1.5 flex-wrap">
              <span className="text-[10px] font-semibold uppercase tracking-[0.15em] text-zinc-400 self-center mr-1">Type:</span>
              {types.map((t) => (
                <button
                  key={t.value}
                  onClick={() => update(i, "persona_type", t.value)}
                  className={cn(
                    "px-2.5 py-1 rounded-lg text-[10px] font-medium border transition-colors",
                    p.persona_type === t.value
                      ? "border-emerald-300 bg-emerald-50 text-emerald-700"
                      : "border-zinc-200 text-zinc-500"
                  )}
                >
                  {t.label}
                </button>
              ))}
            </div>

            <div className="flex gap-1.5 flex-wrap">
              <span className="text-[10px] font-semibold uppercase tracking-[0.15em] text-zinc-400 self-center mr-1">Level:</span>
              {seniorities.map((s) => (
                <button
                  key={s.value}
                  onClick={() => update(i, "seniority", s.value)}
                  className={cn(
                    "px-2.5 py-1 rounded-lg text-[10px] font-medium border transition-colors",
                    p.seniority === s.value
                      ? "border-emerald-300 bg-emerald-50 text-emerald-700"
                      : "border-zinc-200 text-zinc-500"
                  )}
                >
                  {s.label}
                </button>
              ))}
            </div>

            <input
              value={p.kpis}
              onChange={(e) => update(i, "kpis", e.target.value)}
              placeholder="KPIs they care about (comma-separated)"
              className="w-full px-3 py-2 rounded-lg border border-zinc-200 text-[12px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400"
            />
            <input
              value={p.pains}
              onChange={(e) => update(i, "pains", e.target.value)}
              placeholder="Pain points (comma-separated)"
              className="w-full px-3 py-2 rounded-lg border border-zinc-200 text-[12px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400"
            />
          </div>
        ))}
      </div>

      <button
        onClick={add}
        className="flex items-center gap-1.5 px-3 py-2 border border-dashed border-zinc-300 rounded-xl text-[12px] text-zinc-500 hover:border-zinc-400 hover:text-zinc-700 transition-colors w-full justify-center"
      >
        <Plus className="w-3 h-3" /> Add Persona
      </button>

      <div className="flex justify-between pt-2">
        <button onClick={onBack} className="px-5 py-3 rounded-xl text-[13px] font-medium text-zinc-500 hover:bg-zinc-100 transition-colors">
          Back
        </button>
        <div className="flex gap-2">
          <button onClick={() => onNext({ personas: [] })} className="px-5 py-3 rounded-xl text-[13px] font-medium text-zinc-400 hover:text-zinc-600 transition-colors">
            Skip
          </button>
          <button
            onClick={handleSubmit}
            disabled={filled.length === 0}
            className={cn(
              "px-6 py-3 rounded-xl text-[13px] font-medium transition-colors",
              filled.length > 0 ? "bg-zinc-950 text-white hover:bg-zinc-800" : "bg-zinc-100 text-zinc-400 cursor-not-allowed"
            )}
          >
            Continue ({filled.length})
          </button>
        </div>
      </div>
    </div>
  );
}

import { Plus, Shield, X } from "lucide-react";
import { useState } from "react";

import { SuggestionSection } from "@/components/onboarding/SuggestionCard";
import { useTenant } from "@/contexts/TenantContext";
import type { CompanyClaimGovernance, OnboardingPhase4Input } from "@/hooks/company-context/types";
import { useAcceptSuggestion, useRejectSuggestion, useResearchSuggestions } from "@/hooks/company-context/useResearchJob";
import { cn } from "@/lib/utils";

interface Props {
  companyName: string;
  onNext: (data: OnboardingPhase4Input) => void;
  onBack: () => void;
  researchJobId?: string | null;
}

type RiskLevel = CompanyClaimGovernance["risk_level"];
type Category = NonNullable<CompanyClaimGovernance["category"]>;

interface ClaimDraft {
  claim_text: string;
  risk_level: RiskLevel;
  category: Category;
  rationale: string;
}

export function Phase4Claims({ companyName, onNext, onBack, researchJobId }: Props) {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id ?? "default";
  const { data: suggestions } = useResearchSuggestions(researchJobId ?? null, "claim");
  const acceptMutation = useAcceptSuggestion(tenantId);
  const rejectMutation = useRejectSuggestion(tenantId);

  const [claims, setClaims] = useState<ClaimDraft[]>([
    { claim_text: "", risk_level: "safe", category: "revenue", rationale: "" },
  ]);

  const add = () => setClaims([...claims, { claim_text: "", risk_level: "safe", category: "cost", rationale: "" }]);
  const remove = (i: number) => setClaims(claims.filter((_, idx) => idx !== i));
  const update = (i: number, field: keyof ClaimDraft, value: string) => {
    setClaims(claims.map((c, idx) => (idx === i ? { ...c, [field]: value } : c)));
  };

  const filled = claims.filter((c) => c.claim_text.trim().length > 0);

  const riskLevels: Array<{ value: RiskLevel; label: string; color: string; bg: string }> = [
    { value: "safe", label: "Safe", color: "text-emerald-700", bg: "bg-emerald-50 border-emerald-200" },
    { value: "conditional", label: "Conditional", color: "text-amber-700", bg: "bg-amber-50 border-amber-200" },
    { value: "high_risk", label: "High Risk", color: "text-red-700", bg: "bg-red-50 border-red-200" },
  ];

  const categories: Array<{ value: Category; label: string }> = [
    { value: "revenue", label: "Revenue" },
    { value: "cost", label: "Cost" },
    { value: "risk", label: "Risk" },
    { value: "productivity", label: "Productivity" },
    { value: "compliance", label: "Compliance" },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3 mb-2">
        <div className="w-10 h-10 bg-amber-50 rounded-xl flex items-center justify-center">
          <Shield className="w-5 h-5 text-amber-600" />
        </div>
        <div>
          <h2 className="text-[16px] font-black text-zinc-950 tracking-tight">Claim Governance</h2>
          <p className="text-[12px] text-zinc-400">
            What claims should {companyName} make confidently, cautiously, or avoid?
          </p>
        </div>
      </div>

      <div className="p-4 rounded-xl bg-blue-50 border border-blue-100">
        <p className="text-[12px] text-blue-700">
          These rules teach the system which value claims are safe to make, which need extra evidence,
          and which should be flagged automatically. This prevents embarrassing overstatements in front of CFOs.
        </p>
      </div>

      {/* AI Suggestions */}
      {suggestions && suggestions.length > 0 && (
        <SuggestionSection
          suggestions={suggestions.map((s) => {
            // Claims with confidence < 0.5 default to "conditional"
            if (s.confidence_score < 0.5) {
              return {
                ...s,
                payload: { ...s.payload, risk_level: "conditional" },
              };
            }
            return s;
          })}
          onAccept={(s) => {
            const payload = s.payload as Record<string, unknown>;
            // Enforce confidence-based risk defaulting
            if (s.confidence_score < 0.5) {
              payload.risk_level = "conditional";
            }
            acceptMutation.mutate({
              suggestionId: s.id,
              contextId: s.context_id,
              entityType: s.entity_type,
              payload,
            });
            const p = payload as Record<string, string>;
            setClaims((prev) => [
              ...prev.filter((c) => c.claim_text.trim().length > 0),
              {
                claim_text: p.claim_text ?? "",
                risk_level: (p.risk_level ?? "conditional") as RiskLevel,
                category: (p.category ?? "revenue") as Category,
                rationale: p.rationale ?? "",
              },
            ]);
          }}
          onReject={(s) => rejectMutation.mutate(s.id)}
          onEdit={(s, payload) => {
            if (s.confidence_score < 0.5) {
              payload.risk_level = "conditional";
            }
            acceptMutation.mutate({
              suggestionId: s.id,
              contextId: s.context_id,
              entityType: s.entity_type,
              payload,
            });
          }}
          renderPayload={(payload, _isEditing, _onChange) => {
            const p = payload as Record<string, string>;
            const riskColors: Record<string, string> = {
              safe: "bg-emerald-50 text-emerald-700 border-emerald-200",
              conditional: "bg-amber-50 text-amber-700 border-amber-200",
              high_risk: "bg-red-50 text-red-700 border-red-200",
            };
            return (
              <div className="space-y-1.5">
                <p className="text-[12px] text-zinc-700">{p.claim_text}</p>
                <div className="flex items-center gap-2">
                  {p.risk_level && (
                    <span className={cn("text-[10px] px-2 py-0.5 rounded-full font-semibold border capitalize", riskColors[p.risk_level] ?? "bg-zinc-100 text-zinc-500")}>
                      {p.risk_level.replace("_", " ")}
                    </span>
                  )}
                  {p.category && (
                    <span className="text-[10px] px-2 py-0.5 rounded-full bg-zinc-100 text-zinc-500 capitalize">
                      {p.category}
                    </span>
                  )}
                </div>
                {p.rationale && <p className="text-[11px] text-zinc-400">{p.rationale}</p>}
              </div>
            );
          }}
          isProcessing={acceptMutation.isPending || rejectMutation.isPending}
        />
      )}

      <div className="space-y-4">
        {claims.map((c, i) => (
          <div key={i} className="p-4 rounded-xl border border-zinc-200 bg-zinc-50/50 space-y-3">
            <div className="flex items-start gap-2">
              <textarea
                value={c.claim_text}
                onChange={(e) => update(i, "claim_text", e.target.value)}
                placeholder='e.g. "Our platform reduces infrastructure costs by 60%"'
                rows={2}
                className="flex-1 px-3 py-2 rounded-lg border border-zinc-200 text-[13px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400 resize-none"
              />
              {claims.length > 1 && (
                <button onClick={() => remove(i)} className="p-1 rounded hover:bg-zinc-200">
                  <X className="w-3.5 h-3.5 text-zinc-400" />
                </button>
              )}
            </div>

            <div className="flex items-center gap-4">
              <div className="flex gap-1.5">
                {riskLevels.map((r) => (
                  <button
                    key={r.value}
                    onClick={() => update(i, "risk_level", r.value)}
                    className={cn(
                      "px-3 py-1.5 rounded-lg text-[11px] font-medium border transition-colors",
                      c.risk_level === r.value ? cn(r.color, r.bg) : "border-zinc-200 text-zinc-500"
                    )}
                  >
                    {r.label}
                  </button>
                ))}
              </div>
              <select
                value={c.category}
                onChange={(e) => update(i, "category", e.target.value)}
                className="px-3 py-1.5 rounded-lg border border-zinc-200 text-[11px] bg-white text-zinc-600 outline-none"
              >
                {categories.map((cat) => (
                  <option key={cat.value} value={cat.value}>{cat.label}</option>
                ))}
              </select>
            </div>

            <input
              value={c.rationale}
              onChange={(e) => update(i, "rationale", e.target.value)}
              placeholder="Why this risk level? (optional)"
              className="w-full px-3 py-2 rounded-lg border border-zinc-200 text-[12px] bg-white placeholder:text-zinc-400 outline-none focus:border-zinc-400"
            />
          </div>
        ))}
      </div>

      <button
        onClick={add}
        className="flex items-center gap-1.5 px-3 py-2 border border-dashed border-zinc-300 rounded-xl text-[12px] text-zinc-500 hover:border-zinc-400 hover:text-zinc-700 transition-colors w-full justify-center"
      >
        <Plus className="w-3 h-3" /> Add Claim Rule
      </button>

      <div className="flex justify-between pt-2">
        <button onClick={onBack} className="px-5 py-3 rounded-xl text-[13px] font-medium text-zinc-500 hover:bg-zinc-100 transition-colors">
          Back
        </button>
        <div className="flex gap-2">
          <button onClick={() => onNext({ claim_governance: [] })} className="px-5 py-3 rounded-xl text-[13px] font-medium text-zinc-400 hover:text-zinc-600 transition-colors">
            Skip
          </button>
          <button
            onClick={() => onNext({ claim_governance: filled })}
            disabled={filled.length === 0}
            className={cn(
              "px-6 py-3 rounded-xl text-[13px] font-medium transition-colors",
              filled.length > 0 ? "bg-zinc-950 text-white hover:bg-zinc-800" : "bg-zinc-100 text-zinc-400 cursor-not-allowed"
            )}
          >
            Continue ({filled.length})
          </button>
        </div>
      </div>
    </div>
  );
}

import {
  Bot,
  Building2,
  CheckCircle2,
  ExternalLink,
  Package,
  Shield,
  Sparkles,
  Swords,
  TrendingUp,
  Users,
  Zap,
} from "lucide-react";
import { useState } from "react";

import { useTenant } from "@/contexts/TenantContext";
import type {
  OnboardingPhase1Input,
  OnboardingPhase2Input,
  OnboardingPhase3Input,
  OnboardingPhase4Input,
  ResearchSuggestion,
} from "@/hooks/company-context/types";
import { useAcceptSuggestion, useRejectSuggestion } from "@/hooks/company-context/useResearchJob";
import { cn } from "@/lib/utils";

interface Props {
  phase1: OnboardingPhase1Input;
  phase2: OnboardingPhase2Input;
  phase3: OnboardingPhase3Input;
  phase4: OnboardingPhase4Input;
  onConfirm: () => void;
  onBack: () => void;
  isSubmitting: boolean;
  researchJobId?: string | null;
  researchSuggestions?: ResearchSuggestion[];
}

function SectionCard({
  icon: Icon,
  title,
  count,
  color,
  children,
  badge,
}: {
  icon: React.ElementType;
  title: string;
  count: number;
  color: string;
  children: React.ReactNode;
  badge?: React.ReactNode;
}) {
  return (
    <div className="bg-white border border-zinc-200 rounded-2xl p-5">
      <div className="flex items-center gap-2 mb-3">
        <Icon className={cn("w-4 h-4", color)} />
        <h3 className="text-[13px] font-semibold text-zinc-900">{title}</h3>
        {badge}
        <span className="ml-auto text-[11px] px-2 py-0.5 rounded-full bg-zinc-100 text-zinc-500 font-medium">
          {count}
        </span>
      </div>
      {children}
    </div>
  );
}

function ProvenanceBadge({ suggestion }: { suggestion?: ResearchSuggestion }) {
  const [showSources, setShowSources] = useState(false);

  if (!suggestion || (suggestion.status !== "accepted" && suggestion.status !== "edited")) return null;

  return (
    <div className="inline-flex items-center gap-1 ml-2">
      <span className="inline-flex items-center gap-1 text-[9px] px-1.5 py-0.5 rounded-full bg-blue-50 text-blue-600 border border-blue-100 font-medium">
        <Bot className="w-2.5 h-2.5" />
        AI · {Math.round(suggestion.confidence_score * 100)}%
      </span>
      {suggestion.source_urls.length > 0 && (
        <button
          onClick={() => setShowSources(!showSources)}
          className="text-[9px] text-zinc-400 hover:text-zinc-600"
        >
          {suggestion.source_urls.length} source{suggestion.source_urls.length !== 1 ? "s" : ""}
        </button>
      )}
      {showSources && (
        <div className="absolute mt-6 p-2 bg-white border border-zinc-200 rounded-lg shadow-lg z-10 space-y-1">
          {suggestion.source_urls.map((url, i) => (
            <a
              key={i}
              href={url}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1 text-[10px] text-blue-500 hover:text-blue-700"
            >
              <ExternalLink className="w-3 h-3" />
              {url}
            </a>
          ))}
        </div>
      )}
    </div>
  );
}

export function Phase5Review({ phase1, phase2, phase3, phase4, onConfirm, onBack, isSubmitting, researchJobId, researchSuggestions }: Props) {
  const { currentTenant } = useTenant();
  const tenantId = currentTenant?.id ?? "default";
  const acceptMutation = useAcceptSuggestion(tenantId);
  const rejectMutation = useRejectSuggestion(tenantId);

  const acceptedSuggestions = researchSuggestions?.filter((s) => s.status === "accepted" || s.status === "edited") ?? [];
  const pendingCapabilities = researchSuggestions?.filter((s) => s.entity_type === "capability" && s.status === "suggested") ?? [];
  const pendingPatterns = researchSuggestions?.filter((s) => s.entity_type === "value_pattern" && s.status === "suggested") ?? [];

  return (
    <div className="space-y-6 pb-12">
      <div className="flex items-center gap-3 mb-2">
        <div className="w-10 h-10 bg-pink-50 rounded-xl flex items-center justify-center">
          <Sparkles className="w-5 h-5 text-pink-600" />
        </div>
        <div>
          <h2 className="text-[16px] font-black text-zinc-950 tracking-tight">Review & Activate</h2>
          <p className="text-[12px] text-zinc-400">
            Confirm your company intelligence — this becomes the foundation for every value case
          </p>
        </div>
      </div>

      {/* Research provenance summary */}
      {acceptedSuggestions.length > 0 && (
        <div className="p-4 rounded-xl border border-blue-100 bg-blue-50/30 space-y-2">
          <div className="flex items-center gap-2">
            <Bot className="w-4 h-4 text-blue-500" />
            <span className="text-[12px] font-semibold text-blue-700">
              AI-Assisted Onboarding
            </span>
          </div>
          <p className="text-[11px] text-blue-600">
            {acceptedSuggestions.length} item{acceptedSuggestions.length !== 1 ? "s" : ""} were
            suggested by AI and accepted during this onboarding.
            {researchJobId && (
              <span className="text-blue-400 ml-1">Job: {researchJobId.substring(0, 8)}...</span>
            )}
          </p>
        </div>
      )}

      {/* Company summary */}
      <SectionCard icon={Building2} title="Company" count={1} color="text-blue-600">
        <div className="grid grid-cols-2 gap-3">
          <div>
            <p className="text-[11px] text-zinc-400">Name</p>
            <p className="text-[13px] font-medium text-zinc-900">{phase1.company_name}</p>
          </div>
          <div>
            <p className="text-[11px] text-zinc-400">Industry</p>
            <p className="text-[13px] font-medium text-zinc-900">{phase1.industry || "—"}</p>
          </div>
          <div>
            <p className="text-[11px] text-zinc-400">Size</p>
            <p className="text-[13px] font-medium text-zinc-900 capitalize">
              {phase1.company_size?.replace("_", " ") || "—"}
            </p>
          </div>
          <div>
            <p className="text-[11px] text-zinc-400">Sales Motion</p>
            <p className="text-[13px] font-medium text-zinc-900 capitalize">
              {phase1.sales_motion?.replace("_", " ") || "—"}
            </p>
          </div>
        </div>
      </SectionCard>

      {/* Products */}
      <SectionCard icon={Package} title="Products" count={phase1.products.length} color="text-blue-600">
        <div className="space-y-2">
          {phase1.products.map((p, i) => {
            const matchingSuggestion = acceptedSuggestions.find(
              (s) => s.entity_type === "product" && (s.payload as Record<string, string>).name === p.name
            );
            return (
              <div key={i} className="flex items-center gap-3 p-2.5 rounded-xl bg-zinc-50 relative">
                <span className="text-[13px] font-medium text-zinc-900 flex-1">{p.name}</span>
                <span className="text-[11px] text-zinc-400 capitalize">{p.product_type?.replace("_", " ")}</span>
                <ProvenanceBadge suggestion={matchingSuggestion} />
              </div>
            );
          })}
        </div>
      </SectionCard>

      {/* Advanced AI Insights (Capabilities & Patterns) */}
      {(pendingCapabilities.length > 0 || pendingPatterns.length > 0) && (
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <Sparkles className="w-4 h-4 text-blue-500" />
            <h3 className="text-[14px] font-bold text-zinc-900">Advanced AI Insights</h3>
          </div>

          {pendingCapabilities.length > 0 && (
            <SectionCard
              icon={Zap}
              title="Suggested Capabilities"
              count={pendingCapabilities.length}
              color="text-blue-500"
              badge={<span className="text-[9px] px-1.5 py-0.5 rounded-full bg-blue-50 text-blue-600 font-bold border border-blue-100">NEW</span>}
            >
              <div className="space-y-3">
                {pendingCapabilities.map((s) => {
                  const p = s.payload as Record<string, unknown>;
                  const capability = typeof p.capability === "string" ? p.capability : "";
                  const operational_change = typeof p.operational_change === "string" ? p.operational_change : "";
                  return (
                    <div key={s.id} className="p-3 rounded-xl border border-blue-100 bg-blue-50/20 flex items-start justify-between gap-4">
                      <div className="flex-1">
                        <p className="text-[12px] font-semibold text-zinc-900">{capability}</p>
                        <p className="text-[11px] text-zinc-500 mt-1">{operational_change}</p>
                      </div>
                      <button
                        onClick={() => acceptMutation.mutate({
                          suggestionId: s.id,
                          contextId: s.context_id,
                          entityType: s.entity_type,
                          payload: s.payload as Record<string, unknown>,
                        })}
                        disabled={acceptMutation.isPending}
                        className="text-[11px] font-bold text-blue-600 hover:text-blue-700 transition-colors"
                      >
                        Accept
                      </button>
                    </div>
                  );
                })}
              </div>
            </SectionCard>
          )}

          {pendingPatterns.length > 0 && (
            <SectionCard
              icon={TrendingUp}
              title="Suggested Value Patterns"
              count={pendingPatterns.length}
              color="text-emerald-500"
              badge={<span className="text-[9px] px-1.5 py-0.5 rounded-full bg-emerald-50 text-emerald-600 font-bold border border-emerald-100">NEW</span>}
            >
              <div className="space-y-3">
                {pendingPatterns.map((s) => {
                  const p = s.payload as Record<string, unknown>;
                  const pattern_name = typeof p.pattern_name === "string" ? p.pattern_name : "";
                  const typical_kpis = Array.isArray(p.typical_kpis) ? p.typical_kpis : [];
                  return (
                    <div key={s.id} className="p-3 rounded-xl border border-emerald-100 bg-emerald-50/20 flex items-start justify-between gap-4">
                      <div className="flex-1">
                        <p className="text-[12px] font-semibold text-zinc-900">{pattern_name}</p>
                        <div className="flex gap-2 mt-1">
                          {typical_kpis.slice(0, 2).map((k: unknown, idx: number) => {
                            if (typeof k === "object" && k !== null) {
                              const kObj = k as { name?: string };
                              return kObj.name ? (
                                <span key={idx} className="text-[10px] text-emerald-600 font-medium">
                                  • {kObj.name}
                                </span>
                              ) : null;
                            }
                            return null;
                          })}
                        </div>
                      </div>
                      <button
                        onClick={() => acceptMutation.mutate({
                          suggestionId: s.id,
                          contextId: s.context_id,
                          entityType: s.entity_type,
                          payload: s.payload as Record<string, unknown>,
                        })}
                        disabled={acceptMutation.isPending}
                        className="text-[11px] font-bold text-emerald-600 hover:text-emerald-700 transition-colors"
                      >
                        Accept
                      </button>
                    </div>
                  );
                })}
              </div>
            </SectionCard>
          )}
        </div>
      )}

      {/* Competitors */}
      {phase2.competitors.length > 0 && (
        <SectionCard icon={Swords} title="Competitors" count={phase2.competitors.length} color="text-violet-600">
          <div className="flex flex-wrap gap-2">
            {phase2.competitors.map((c, i) => (
              <span key={i} className="px-3 py-1.5 rounded-lg bg-violet-50 text-[12px] font-medium text-violet-700 border border-violet-100">
                {c.name}
                <span className="text-violet-400 ml-1 capitalize"> · {c.relationship}</span>
              </span>
            ))}
          </div>
        </SectionCard>
      )}

      {/* Personas */}
      {phase3.personas.length > 0 && (
        <SectionCard icon={Users} title="Buyer Personas" count={phase3.personas.length} color="text-emerald-600">
          <div className="space-y-2">
            {phase3.personas.map((p, i) => (
              <div key={i} className="flex items-center gap-3 p-2.5 rounded-xl bg-zinc-50">
                <span className="text-[13px] font-medium text-zinc-900 flex-1">{p.title}</span>
                <span className="text-[10px] px-2 py-0.5 rounded-full bg-emerald-50 text-emerald-700 font-semibold capitalize">
                  {p.persona_type?.replace("_", " ")}
                </span>
                <span className="text-[10px] px-2 py-0.5 rounded-full bg-zinc-100 text-zinc-500 font-semibold capitalize">
                  {p.seniority?.replace("_", " ")}
                </span>
              </div>
            ))}
          </div>
        </SectionCard>
      )}

      {/* Claim governance */}
      {phase4.claim_governance.length > 0 && (
        <SectionCard icon={Shield} title="Claim Governance" count={phase4.claim_governance.length} color="text-amber-600">
          <div className="space-y-2">
            {phase4.claim_governance.map((c, i) => {
              const riskColors: Record<string, string> = {
                safe: "bg-emerald-50 text-emerald-700 border-emerald-200",
                conditional: "bg-amber-50 text-amber-700 border-amber-200",
                high_risk: "bg-red-50 text-red-700 border-red-200",
              };
              return (
                <div key={i} className="p-3 rounded-xl bg-zinc-50">
                  <div className="flex items-start gap-2">
                    <span className={cn("text-[10px] px-2 py-0.5 rounded-full font-semibold border flex-shrink-0 mt-0.5", riskColors[c.risk_level])}>
                      {c.risk_level.replace("_", " ")}
                    </span>
                    <p className="text-[12px] text-zinc-700">{c.claim_text}</p>
                  </div>
                </div>
              );
            })}
          </div>
        </SectionCard>
      )}

      {/* Confirm */}
      <div className="p-5 rounded-2xl bg-zinc-950 text-white">
        <div className="flex items-center gap-3 mb-3">
          <CheckCircle2 className="w-5 h-5 text-emerald-400" />
          <h3 className="text-[14px] font-semibold">Ready to activate</h3>
        </div>
        <p className="text-[12px] text-zinc-400 mb-4">
          Once activated, this intelligence becomes the foundation for every value case.
          You can always update it later from the Company Knowledge page.
        </p>
        <div className="flex gap-3">
          <button onClick={onBack} className="px-5 py-3 rounded-xl text-[13px] font-medium text-zinc-400 hover:text-white transition-colors">
            Back
          </button>
          <button
            onClick={onConfirm}
            disabled={isSubmitting}
            className="px-6 py-3 bg-white text-zinc-950 rounded-xl text-[13px] font-semibold hover:bg-zinc-100 transition-colors flex items-center gap-2"
          >
            {isSubmitting ? (
              <div className="w-4 h-4 border-2 border-zinc-300 border-t-zinc-900 rounded-full animate-spin" />
            ) : (
              <Sparkles className="w-4 h-4" />
            )}
            {isSubmitting ? "Activating..." : "Activate Company Intelligence"}
          </button>
        </div>
      </div>
    </div>
  );
}
